insert into platform_topic_master (subject_slug, topic_slug, page_name, sections)
values
('business', '1-1-role-of-business-enterprise', '1.1 Role of Business Enterprise', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>These are the essential terms you must know and be able to use accurately in the exam.</p>\n<ul>\n  <li><strong>Entrepreneur:</strong> An individual who takes the risk of setting up and running a business enterprise.</li>\n  <li><strong>Enterprise:</strong> Seeing an opportunity to provide a product or service that people are willing to buy — often described as ''spotting an opportunity''.</li>\n  <li><strong>Opportunity:</strong> Taking advantage of a gap in the market or a possibility to provide something customers need that is not currently being met.</li>\n  <li><strong>Characteristics (of an entrepreneur):</strong> The personal features and qualities that make someone likely to succeed — the four accepted ones are: risk-taking, determination, confidence, and creativity.</li>\n  <li><strong>Risk:</strong> The possibility of a negative outcome when starting or running a business, such as financial loss, poor health, or strained relationships.</li>\n  <li><strong>Reward:</strong> The benefit gained from taking a risk — financial (profit) or non-financial (independence, self-satisfaction).</li>\n  <li><strong>Business activity:</strong> The process by which a business produces goods or provides services to satisfy the needs of customers.</li>\n</ul>", "check": {"question": "Which of these correctly distinguishes an ''entrepreneur'' from ''enterprise''?", "options": ["An entrepreneur is the risk-taker; enterprise is spotting an opportunity", "An entrepreneur is a synonym for a manager, while enterprise means a company''s turnover", "An entrepreneur is only someone who owns a large company; enterprise is a legal structure", "An entrepreneur and enterprise mean exactly the same thing and are interchangeable"], "answer": 0, "explain": "An entrepreneur is the individual who takes the risk of setting up and running a business, while enterprise is the concept of spotting an opportunity and acting on it."}}, {"title": "What is Business Activity & Enterprise?", "html": "<p>Businesses exist to <strong>satisfy the needs and wants of customers</strong>. They provide goods and services at a price people are willing to pay — and in return, the business earns profit.</p>\n<p>There are three main purposes of business enterprise and entrepreneurship:</p>\n<ul>\n  <li><strong>Spotting an opportunity:</strong> Identifying a gap in the market, improving an existing product or service, or producing something more cheaply than competitors.</li>\n  <li><strong>Developing an idea:</strong> Designing the product or service and planning how to produce it.</li>\n  <li><strong>Satisfying customer needs:</strong> Producing the product, providing the service, and marketing it to the right customers.</li>\n</ul>\n<p><strong>Enterprise</strong> is nothing new — for as long as trade has existed, people have spotted opportunities and acted on them. For example, street sellers appear with umbrellas the moment it rains: they identified a customer need and acted fast.</p>\n<div class=\"case-study-box\">\n  <h4>Case Study: Google — Spotting an Opportunity</h4>\n  <p>Larry Page and Sergey Brin started Google by meeting in a garage. They spotted the need for a reliable search engine in the fast-growing computer market. That small idea grew into one of the world''s most valuable companies. Google is now developing drone technology to speed up deliveries — showing that enterprise means continuously spotting new opportunities.</p>\n  <p><strong>Takeaway:</strong> Enterprise is about constantly looking for unmet needs. Entrepreneurs don''t just wait — they act.</p>\n</div>", "check": {"question": "Which of the following is NOT one of the three core purposes of business enterprise?", "options": ["Maximising short-term share price", "Spotting an opportunity to sell", "Developing an idea for a product", "Satisfying customer needs directly"], "answer": 0, "explain": "The three core purposes are spotting an opportunity, developing an idea, and satisfying customer needs — maximising share price is not one of them."}}, {"title": "Characteristics of an Entrepreneur", "html": "<p>Successful entrepreneurs share a set of key characteristics. You must be able to <strong>identify, explain, and apply</strong> these in the exam — especially for 6-mark questions that ask you to link them to a specific business.</p>\n<ul>\n  <li><strong>Creativity / Innovative:</strong> The ability to think up new ideas, design new products, or solve problems in original ways. James Dyson invented the bagless vacuum cleaner — something that had never existed before.</li>\n  <li><strong>Risk-taking:</strong> Being prepared to put personal money, time, or reputation at risk in the hope of a reward. Dyson gave up his paid job and invested his own savings to fund his venture — with no guarantee of success.</li>\n  <li><strong>Determination / Perseverance:</strong> Not giving up when things get difficult. Dyson tried over 5,000 designs before finding one that worked. This is the most commonly tested characteristic in context questions.</li>\n  <li><strong>Confidence / Self-belief:</strong> Believing that their idea will succeed and being able to inspire others to believe it too. An confident entrepreneur doesn''t say ''I can''t'' — they say ''I will''.</li>\n</ul>\n<p>⚠️ <strong>Examiner Warning:</strong> Do NOT write traits like <strong>''hardworking'', ''motivated'', ''well-organised'', ''resilient'', or ''teamwork''</strong>. The mark scheme explicitly states these will NOT be awarded marks. Stick to the four official characteristics above.</p>", "check": {"question": "Which of the four officially accepted entrepreneurial characteristics describes not giving up when problems arise?", "options": ["Determination", "Confidence", "Creativity", "Risk-taking"], "answer": 0, "explain": "Determination (or perseverance) is the characteristic of continuing to work through difficulties without giving up."}}, {"title": "Rewards vs Drawbacks of Risk Taking", "html": "<p>When an entrepreneur takes a risk, they hope the <strong>rewards</strong> will outweigh the <strong>drawbacks</strong>. There are both financial and non-financial versions of each.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Rewards</div>\n    <div class=\"pro-item\"><strong>Financial (Profit):</strong> The greater the risk, the greater the potential reward. Entrepreneurs like Sir Richard Branson and Lord Sugar built personal fortunes by taking calculated risks.</div>\n    <div class=\"pro-item\"><strong>Independence:</strong> Being your own boss — making all your own decisions without answering to anyone else. The feeling of freedom can be a more powerful motivator than money for many entrepreneurs.</div>\n    <div class=\"pro-item\"><strong>Self-satisfaction:</strong> The personal pride of watching your own idea come to life and succeed. A business born from a hobby can bring deep fulfilment even when profit is modest.</div>\n    <div class=\"pro-item\"><strong>Changing customer habits:</strong> Anita Roddick founded The Body Shop on the principle that cosmetics should not be tested on animals — and changed the entire industry in doing so.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Drawbacks (Risks)</div>\n    <div class=\"con-item\"><strong>Financial loss:</strong> Life savings invested in a failing business may be lost entirely. This is the number one reason why many people never become entrepreneurs.</div>\n    <div class=\"con-item\"><strong>Failing health:</strong> The stress of running a business — whether it is struggling or booming — can cause serious mental and physical illness.</div>\n    <div class=\"con-item\"><strong>Strained relationships:</strong> Starting a business demands enormous time. Holidays are sacrificed, family time is lost, and personal relationships suffer as the business takes priority.</div>\n  </div>\n</div>", "check": {"question": "Which of the following is a NON-FINANCIAL reward of entrepreneurship?", "options": ["Independence", "Profit", "Turnover", "Wages"], "answer": 0, "explain": "Independence — being your own boss — is a non-financial reward. Profit is the financial reward, while turnover and wages are not entrepreneurial rewards."}}, {"title": "Real-World Case Studies", "html": "<div class=\"case-study-box\">\n  <h4>Case Study: James Dyson — Determination, Creativity & Risk-Taking</h4>\n  <p>Frustrated with the poor performance of his vacuum cleaner, James Dyson decided to design a better one. He gave up his paid job, used his personal savings, and spent years in his garage creating over 5,000 different prototypes before producing the world''s first bagless vacuum cleaner.</p>\n  <p>When his first partnership (with Amway) failed, he didn''t stop — he formed his own company in 1991. Dyson Ltd now employs over 12,000 people worldwide and continues to innovate with vacuum cleaners, hand dryers, hair dryers, and air purifiers.</p>\n  <p><strong>Takeaway:</strong> Dyson demonstrates all four characteristics — determination (5,000+ designs), creativity (brand new product), confidence (believed in his idea despite early failure), and risk-taking (quit his job, used his personal savings).</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Zuber & Mohsin Issa — Spotting Opportunities</h4>\n  <p>The Issa brothers started with a single petrol station in Manchester in 2001. By continuously spotting new opportunities — adding supermarkets, coffee shops, and fast-food outlets to their petrol stations — they grew to over 5,000 outlets across Europe and the USA. In October 2020, they purchased a controlling stake in Asda from Walmart for £6.8 billion.</p>\n  <p><strong>Takeaway:</strong> Enterprise is not a one-time event. The Issa brothers show that successful entrepreneurship means spotting new opportunities at every stage of growth.</p>\n</div>", "check": {"question": "When using case study evidence to explain an entrepreneur''s characteristic, what must you always do to earn the application mark?", "options": ["Link the characteristic to specific evidence about the person", "Give a dictionary definition of the characteristic itself", "List as many different characteristics as you possibly can", "Compare the entrepreneur to a completely different case study"], "answer": 0, "explain": "Application marks require linking the characteristic to specific evidence from the case study, not just defining the term."}}, {"title": "Evaluating Risk & Reward", "html": "<p>When evaluating whether it is worth taking the risk of starting a business, you must <strong>weigh up both sides</strong> using the information provided. Evaluation questions rarely have a single correct answer — it depends on context.</p>\n<p>Key points to consider when writing an evaluation:</p>\n<ul>\n  <li>Does the entrepreneur have the right <strong>characteristics</strong> to succeed?</li>\n  <li>Is there genuine <strong>customer demand</strong> for the product or service?</li>\n  <li>How significant is the <strong>competition</strong>? Are there already established businesses in the market?</li>\n  <li>What is the entrepreneur''s <strong>financial position</strong> — can they afford to lose the money invested?</li>\n  <li>What are the <strong>non-financial costs</strong> (health, time, relationships) and how might these affect the entrepreneur''s ability to run the business long-term?</li>\n</ul>\n<p><strong>Evaluation point:</strong> Just because an entrepreneur is confident, determined, and willing to take a risk does <em>not</em> guarantee success. You must use specific evidence from the case study to justify your judgement — a conclusion that just repeats earlier points scores no evaluation marks.</p>", "check": {"question": "When answering an evaluation question about whether an entrepreneur should take a risk, what should your final judgement be based on?", "options": ["Specific evidence from the case study, not repeated earlier points", "Your own personal opinion about business in general", "Whichever side of the argument has more bullet points listed", "The entrepreneur''s characteristics alone, ignoring other factors"], "answer": 0, "explain": "Evaluation marks require judgements to be justified using specific evidence from the case study — a conclusion that just repeats earlier points scores no evaluation marks."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Entrepreneur", "definition": "A person who takes the risk of setting up and running a business enterprise."}, {"term": "Enterprise", "definition": "Seeing an opportunity to provide a product or service that people are willing to buy — ''spotting an opportunity''."}, {"term": "Creativity", "definition": "An entrepreneurial characteristic — the ability to think of new ideas and design original products or solutions."}, {"term": "Determination", "definition": "An entrepreneurial characteristic — not giving up when things are difficult, and working hard to overcome problems."}, {"term": "Confidence", "definition": "An entrepreneurial characteristic — believing strongly in your own ideas and inspiring others to believe in them too."}, {"term": "Risk-taking", "definition": "An entrepreneurial characteristic — being prepared to invest personal money, time, or reputation into a business that may fail."}, {"term": "Financial reward", "definition": "The profit earned by an entrepreneur from running a successful business."}, {"term": "Independence", "definition": "A non-financial reward — being your own boss and making your own business decisions."}, {"term": "Self-satisfaction", "definition": "A non-financial reward — the personal pride an entrepreneur feels when their idea becomes a successful business."}, {"term": "Financial risk", "definition": "The possibility of losing money invested in a business if the venture fails."}, {"term": "Health risk", "definition": "The non-financial risk that the stress of running a business could lead to mental or physical illness."}, {"term": "Strained relationships", "definition": "A non-financial risk — long working hours and business pressure damaging personal and family relationships."}, {"term": "Business activity", "definition": "The process of producing goods or providing services to satisfy the needs of customers."}, {"term": "Spotting an opportunity", "definition": "Identifying a gap in the market or a customer need that existing businesses are not meeting."}, {"term": "James Dyson", "definition": "Entrepreneur who demonstrated determination (5,000+ designs), creativity (bagless vacuum cleaner), confidence, and risk-taking (quit job, used personal savings)."}, {"term": "The Issa Brothers", "definition": "Entrepreneurs who grew from one petrol station in 2001 to buying a controlling stake in Asda for £6.8bn in 2020 — a real-world example of spotting opportunities continuously."}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of the following is the correct definition of enterprise?", "options": ["The process of producing goods in a factory", "Spotting an opportunity to provide a product or service people are willing to buy", "Researching what customers want before opening a business", "The act of employing workers to grow a business"], "answer": 1, "explain": "Correct answer: Enterprise is defined as spotting an opportunity to provide a product or service that customers are willing to buy. It is about identifying a gap in the market and acting on it."}, {"question": "Two brothers are currently unemployed. They decide to set up their own window cleaning business. What is an entrepreneurial risk for the brothers?", "options": ["Cold weather", "Paying taxes", "Poor health", "Slippery ladders"], "answer": 2, "explain": "Correct answer: Poor health. Entrepreneurial risks are personal consequences of running a business, such as stress leading to illness. Cold weather and slippery ladders are working hazards. Paying taxes is a legal cost, not an entrepreneurial risk."}, {"question": "Finley and Umi create personalised pictures using shells and pebbles. What would NOT be an appropriate reason for them to have started this business?", "options": ["They developed an idea for a business by making pictures that are unique", "They satisfied the needs of customers looking for sustainable gifts", "They spotted an opportunity to earn money from a leisure activity they loved", "They wanted to test their physical and mental health by working long hours"], "answer": 3, "explain": "Correct answer: Working long hours to test physical and mental health is a drawback of entrepreneurship — not a reason to start a business. Options A, B, and C are all valid entrepreneurial motivations: developing an idea, satisfying customer needs, and spotting an opportunity."}, {"question": "A plumbing firm is struggling to keep up with customer demand. What would help the business to succeed?", "options": ["Asking regular customers with blocked toilets to ring back another day", "Giving customers unrealistic appointment times", "Ignoring customer complaints about delays in fixing water leaks", "Planning all business activity and work schedules carefully"], "answer": 3, "explain": "Correct answer: Planning business activity carefully allows the firm to manage increased demand effectively. Options A, B, and C all involve poor customer service that would drive customers to competitors and damage the business''s reputation."}, {"question": "Satisfying the needs of customers is:", "options": ["A legal requirement", "A market research task", "A purpose of business activity", "The role of the human resources function"], "answer": 2, "explain": "Correct answer: Satisfying the needs of customers is the core purpose of business activity. Businesses produce goods and services to meet customer needs and earn profit in return. It is not a legal requirement (A), not just a research task (B), and not limited to HR (D)."}, {"question": "Which of the following is a financial reward for enterprise?", "options": ["Authority", "Profit", "Success", "Wages"], "answer": 1, "explain": "Correct answer: Profit. Profit is the key financial reward of enterprise — the money remaining after all costs have been paid. Authority (A) is non-financial. Success (C) is too vague. Wages (D) are paid to employees, not earned by entrepreneurs as a reward for enterprise."}, {"question": "A wine enthusiast has spotted an opportunity to turn their interest into a business by becoming a blogger. This is called:", "options": ["Delegation", "Enterprise", "Market research", "Productivity"], "answer": 1, "explain": "Correct answer: Enterprise. Spotting an opportunity and acting on it to create a business is the definition of enterprise. Delegation (A) is passing tasks to others. Market research (C) is gathering information. Productivity (D) measures output per worker."}, {"question": "Which one of the following is NOT a risk of entrepreneurship?", "options": ["Failing health", "Loss of money", "Self-satisfaction", "Strained personal relationships"], "answer": 2, "explain": "Correct answer: Self-satisfaction. Self-satisfaction is a non-financial REWARD of entrepreneurship — the personal pride felt when an idea succeeds. Failing health (A), loss of money (B), and strained relationships (D) are all genuine risks."}, {"question": "Raj has developed an idea for a new business. This is an example of:", "options": ["Discrimination", "Enterprise", "Flexible working", "Productivity"], "answer": 1, "explain": "Correct answer: Enterprise. Developing an idea for a new business is one of the three core purposes of enterprise. Discrimination (A) means treating people unfairly. Flexible working (C) relates to employment arrangements. Productivity (D) is output per unit of input."}, {"question": "Which one of the following is UNLIKELY to be a characteristic of a successful entrepreneur?", "options": ["Being able to create opportunities", "Being confident in new situations", "Being determined to work through problems", "Being uncomfortable with taking risks"], "answer": 3, "explain": "Correct answer: A successful entrepreneur must be comfortable with taking risks — it is a core characteristic. Being uncomfortable with risk would prevent someone from starting a business. Options A, B, and C are all genuine entrepreneurial characteristics."}, {"question": "An entrepreneur needs which of the following characteristics?", "options": ["Very well dressed at all times", "Know a person in business", "Very good at accounts", "Confident"], "answer": 3, "explain": "Correct answer: Confident. Confidence is one of the four core entrepreneurial characteristics alongside creativity, determination, and risk-taking. Being well dressed (A), knowing people (B), or being good at accounts (C) are not required characteristics."}, {"question": "Which of the following is NOT a reward for risk taking when starting a business?", "options": ["Being able to invest money", "Being able to make profits for yourself", "Being independent", "Being able to see your own ideas work"], "answer": 0, "explain": "Correct answer: Investing money is something you DO when starting a business — it is an action taken (and a financial risk), not a reward received. Making profit (B), independence (C), and seeing your ideas succeed (D) are all genuine rewards of entrepreneurship."}]}, "fib": {"enabled": true, "questions": [{"text": "Businesses exist to satisfy the [needs] of customers by providing goods and services at a price people are willing to [pay]."}, {"text": "An [entrepreneur] is a person who takes the risk of setting up and running a business enterprise."}, {"text": "Enterprise is often described as [spotting] an opportunity — seeing a gap in the market that no other business is filling."}, {"text": "The four core characteristics of an entrepreneur are: creativity, risk-taking, [determination], and [confidence]."}, {"text": "The greater the [risk], the greater the potential [reward]. This is a key principle behind entrepreneurial decision-making."}, {"text": "James Dyson showed great [determination] by trying over 5,000 different designs before producing a working bagless vacuum cleaner."}, {"text": "Financial rewards of enterprise include [profit], while non-financial rewards include independence and self-[satisfaction]."}, {"text": "Non-financial risks of entrepreneurship include failing [health] due to stress, and [strained] personal relationships due to long working hours."}, {"text": "When Larry Page and Sergey Brin spotted the need for a reliable [search] engine, they developed what became Google."}, {"text": "Anita Roddick founded The Body Shop after spotting an opportunity to sell cosmetics that were not [tested] on animals, which changed consumer [attitudes]."}, {"text": "An entrepreneur who starts a business primarily to be their own boss is motivated by the reward of [independence]."}, {"text": "Virgin first started as a mail order business selling records before its founder spotted an opportunity to develop it into a business providing [air] travel."}]}, "tf": {"enabled": true, "questions": [{"statement": "Businesses exist primarily to satisfy the needs of customers.", "answer": true, "explain": "TRUE. The primary purpose of business activity is to satisfy the needs of customers by providing goods and services at a price people are willing to pay. Profit is the reward for doing this successfully."}, {"statement": "The four core characteristics of an entrepreneur include: creativity, determination, confidence, and hardworking.", "answer": false, "explain": "FALSE. The four core characteristics are creativity, determination, confidence, and risk-taking. ''Hardworking'' is NOT accepted by the OCR mark scheme — writing it in an exam will score zero marks."}, {"statement": "The financial risk of entrepreneurship includes the possibility of losing personal savings invested in the business.", "answer": true, "explain": "TRUE. One of the main financial risks is that money invested — including personal savings — could be lost entirely if the business fails. This is the primary reason many people choose not to start businesses."}, {"statement": "Self-satisfaction is a risk of entrepreneurship.", "answer": false, "explain": "FALSE. Self-satisfaction is a non-financial REWARD of entrepreneurship — the personal pride felt when an idea becomes a successful business. The risks include financial loss, failing health, and strained relationships."}, {"statement": "James Dyson demonstrated determination by trying thousands of different designs before succeeding with his bagless vacuum cleaner.", "answer": true, "explain": "TRUE. Dyson tried over 5,000 designs over several years — the classic exam example of the entrepreneurial characteristic of determination (or perseverance)."}, {"statement": "Profit is a non-financial reward of enterprise.", "answer": false, "explain": "FALSE. Profit is a FINANCIAL reward of enterprise — it is money. Non-financial rewards include independence, self-satisfaction, and changing customer attitudes."}, {"statement": "An entrepreneur who starts a business to be their own boss is primarily motivated by the reward of independence.", "answer": true, "explain": "TRUE. Independence — being your own boss and making your own decisions — is a key non-financial reward. Many entrepreneurs prioritise this over financial gain."}, {"statement": "Poor health is a financial risk of being an entrepreneur.", "answer": false, "explain": "FALSE. Poor health is a NON-FINANCIAL risk. It refers to the mental and physical strain of running a business. The financial risk is the possible loss of money invested in the business."}, {"statement": "Enterprise only applies to starting a completely new business — improving an existing product is not enterprise.", "answer": false, "explain": "FALSE. Enterprise includes improving existing products or services, or providing them more cheaply. Apple did not invent the mobile phone but spotted how to improve it — that is enterprise. Spotting any opportunity counts."}, {"statement": "The greater the risk taken by an entrepreneur, the greater the potential reward.", "answer": true, "explain": "TRUE. This is a fundamental principle of entrepreneurship — higher risk is associated with the potential for higher rewards. This is why some entrepreneurs take large financial risks in pursuit of large profits."}, {"statement": "''Motivated'' and ''well-organised'' are accepted characteristics of an entrepreneur in the OCR GCSE Business mark scheme.", "answer": false, "explain": "FALSE. The OCR mark scheme specifically states that traits like ''motivated'', ''well-organised'', ''resilient'', ''teamwork'', and ''hardworking'' are NOT accepted. Always use the four official characteristics: creativity, risk-taking, determination, and confidence."}, {"statement": "Strained personal relationships are a potential non-financial risk of running a business.", "answer": true, "explain": "TRUE. Starting and running a business is extremely time-consuming. This can mean sacrificing holidays, missing family time, and placing enormous pressure on personal relationships — all non-financial costs of entrepreneurship."}]}, "misc": {"enabled": true, "items": [{"myth": "Students write ''hardworking'', ''motivated'', ''resilient'', or ''well-organised'' as characteristics of an entrepreneur.", "truth": "The OCR mark scheme only accepts four characteristics: creativity, risk-taking, determination, and confidence. Writing other traits — no matter how sensible they seem — scores zero marks. The examiner is very specific about this.", "check": {"question": "Which of these is one of the four characteristics officially accepted by the OCR mark scheme?", "options": ["Risk-taking", "Hardworking", "Well-organised", "Resilient"], "answer": 0, "explain": "Only creativity, risk-taking, determination and confidence are accepted; traits like hardworking, well-organised and resilient score zero marks."}}, {"myth": "Students think ''paying taxes'' or ''cold weather'' are entrepreneurial risks.", "truth": "Entrepreneurial risks are personal consequences of running a business: financial loss, failing health, and strained relationships. Taxes are business costs; weather is a working hazard — neither is an entrepreneurial risk in the OCR context.", "check": {"question": "Which of these counts as a genuine ''entrepreneurial risk'' rather than a working hazard or business cost?", "options": ["Failing health due to stress", "Paying the yearly business taxes", "Cold winter weather", "Slippery wet ladders"], "answer": 0, "explain": "Entrepreneurial risks are personal consequences to the entrepreneur, such as failing health, financial loss and strained relationships — not routine costs or physical hazards of the job."}}, {"myth": "Students confuse ''risk'' and ''reward'' — writing self-satisfaction as a risk, or financial loss as a reward.", "truth": "Risks are negative outcomes (financial loss, poor health, damaged relationships). Rewards are positive outcomes (profit, independence, self-satisfaction). Self-satisfaction is always a REWARD, never a risk.", "check": {"question": "Self-satisfaction should always be classified as which of the following?", "options": ["A non-financial reward", "A non-financial risk", "A financial reward", "A financial risk"], "answer": 0, "explain": "Self-satisfaction is a positive outcome — a non-financial reward — and should never be written as a risk."}}, {"myth": "Students explain what a characteristic means instead of applying it to the business in the case study.", "truth": "For application marks, you MUST link the characteristic to the specific business. E.g. ''James Dyson showed creativity by designing a bagless vacuum cleaner that had never existed before.'' Never just define the term — always say HOW the entrepreneur showed it.", "check": {"question": "To earn an application mark when explaining a characteristic, what must a student do?", "options": ["State exactly how the entrepreneur showed the trait", "Define what the characteristic word actually means", "Name as many characteristics as you possibly can", "Repeat the same characteristic in different words"], "answer": 0, "explain": "Application marks require showing HOW the entrepreneur demonstrated the characteristic using case study evidence, not simply defining the term."}}, {"myth": "Students think that because an entrepreneur has all four characteristics, their business is guaranteed to succeed.", "truth": "Having the right characteristics increases the chance of success but does not guarantee it. Market conditions, competition, economic factors, and access to finance all affect whether a business succeeds. The examiner expects you to consider multiple factors when evaluating.", "check": {"question": "Does having all four entrepreneurial characteristics guarantee that a business will succeed?", "options": ["No — competition, market conditions and finance also matter", "Yes — the four characteristics alone guarantee full success", "No — only risk-taking ever has any effect on success", "Yes — but only if the entrepreneur also has experience"], "answer": 0, "explain": "Having the right characteristics increases the chance of success but doesn''t guarantee it; other factors such as competition and finance also matter."}}, {"myth": "Students write that wages are a financial reward for enterprise.", "truth": "Wages are paid to EMPLOYEES by the business. The financial reward for the entrepreneur is PROFIT — the money left after all costs have been paid. Entrepreneurs do not earn wages from their own business.", "check": {"question": "What is the correct financial reward earned by an entrepreneur from their own business?", "options": ["Profit", "Wages", "Salary", "Turnover"], "answer": 0, "explain": "Entrepreneurs earn profit — the money left after costs have been paid — not wages, which are paid to employees."}}, {"myth": "Students think enterprise only means starting a brand-new product that has never existed before.", "truth": "Enterprise includes spotting opportunities to improve existing products, fill gaps in existing markets, or deliver an existing service more cheaply or in a better location. Improving something that already exists is still enterprise.", "check": {"question": "Which of the following counts as ''enterprise'' according to the OCR definition?", "options": ["Improving an existing product or making it cheaper", "Only inventing a completely brand-new product", "Only opening a business in a brand-new location", "Only starting a business with no competitors at all"], "answer": 0, "explain": "Enterprise includes spotting opportunities to improve existing products or provide them more cheaply or in a better way — not just brand-new inventions."}}]}, "tips": {"enabled": true, "items": [{"title": "One Point. Full Stop. Move On.", "html": "\n      <p>A 1-mark <strong>''State'', ''Identify''</strong> or <strong>''Give''</strong> question needs exactly <strong>one correct point</strong>. No explanation. No examples. No paragraphs.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific accepted point = 1 mark ✅</li>\n        <li>A vague or generic point = 0 marks ❌</li>\n        <li>A trait not on the accepted list (e.g. ''hardworking'') = 0 marks ❌</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/><em>\"He worked very hard and was motivated.\"</em><br/>These are not accepted characteristics on the mark scheme.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/><em>\"Determination\"</em> or <em>\"Risk-taking\"</em><br/>Specific, accepted — earns the mark with one word.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> The most common correct answer in exams is ''risk taker''. Many students waste time writing full sentences when a single word earns the mark. Do not over-write on 1-mark questions.</p>\n      <p><strong>🚫 Never write:</strong> ''motivated'', ''well-organised'', ''resilient'', ''teamwork'', or ''hardworking'' for a characteristics question — the examiner explicitly will not award marks for these.</p>\n    ", "check": {"question": "How should you answer a 1-mark ''State'' or ''Identify'' question?", "options": ["Give exactly one clear, specific accepted point, no explanation", "Write a full paragraph explaining the point in a lot of detail", "Give three different points to be extra safe", "Explain the point fully using a case study example"], "answer": 0, "explain": "A 1-mark identify/state question only needs one clear, specific, accepted point — no explanation or examples are required."}}, {"title": "Point + Apply: The 2-Mark Formula", "html": "\n      <p>A 2-mark <strong>''Explain''</strong> question needs a characteristic (K) <strong>plus</strong> an application to the specific business in the case study (APP). You <em>cannot</em> score the application mark without first scoring the knowledge mark.</p>\n      <p><strong>The Formula: K (1 mark) + APP (1 mark)</strong></p>\n      <ul>\n        <li><strong>K:</strong> Name the entrepreneurial characteristic clearly.</li>\n        <li><strong>APP:</strong> Explain specifically how this characteristic applies to the business in the case study.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/><em>\"Julie and Cathy are creative. Creativity means thinking of new ideas.\"</em><br/>This just defines the word — it doesn''t apply it to the hairdressing business. Only 1 mark.</p>\n      <p><strong>✅ Good Answer (2 marks):</strong><br/><em>\"Julie and Cathy must be creative (K) so that they can offer a wide range of different styles for their customers'' hair, keeping people coming back to Sophisticutz rather than going to a competitor (APP).\"</em></p>\n      <p><strong>Useful sentence starters:</strong></p>\n      <ul>\n        <li><em>\"[Characteristic] is important because in the case of [business]...\"</em></li>\n        <li><em>\"[Business] demonstrates [characteristic] by...\"</em></li>\n      </ul>\n    ", "check": {"question": "What two elements must a 2-mark ''Explain'' answer contain to score both marks?", "options": ["A named characteristic (K) plus an application to the business (APP)", "A definition of the term followed by a second, different definition", "Two different characteristics named but neither one explained", "An opinion about the business followed by a short conclusion"], "answer": 0, "explain": "A 2-mark explain question requires Knowledge (naming the characteristic) plus Application (linking it to the specific business) — you cannot score APP without first scoring K."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n      <p>A 3-mark <strong>''Analyse''</strong> question requires three steps in a chain of reasoning. You <em>cannot</em> score application or analysis marks without scoring understanding first.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the risk or characteristic and briefly explain what it means.</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link it directly to the specific business using evidence from the case study. Use phrases like <em>\"in the case of...\"</em> or <em>\"the text states that...\"</em></li>\n        <li><strong>Step 3 — Analysis (AN):</strong> Explain the <em>impact</em> on the business — think: money, customers, survival, reputation.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/><em>\"A risk of starting a hairdressing business is financial loss. This means you could lose money.\"</em><br/>No application to Sophisticutz. No analysis of impact. Only scores 1 mark.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/><em>\"One risk of starting a hairdressing business in competition with Sophisticutz is financial loss (U). The text states there are already several established competitors occupying the best locations in town (APP). As a result, the new salon would struggle to attract customers in the early stages, meaning the entrepreneur could lose their personal savings before the business becomes profitable (AN).\"</em></p>\n      <p><strong>The ''So What?'' Rule:</strong><br/>Keep asking yourself ''So what?'' until you reach a bottom-line business impact (profit, costs, customers, survival).</p>\n    ", "check": {"question": "In a 3-mark ''Analyse'' answer, what does the final step (AN) require you to do?", "options": ["Explain the impact on the business, e.g. profit, customers, survival", "Repeat the application point again but in slightly different words", "Define the key term used earlier in the first step", "State a second characteristic shown by the entrepreneur"], "answer": 0, "explain": "The Analysis step requires explaining the impact of the point on the business — for example on money, customers, reputation or survival."}}, {"title": "Three Mini-Analyses: Apply to the Business Every Time", "html": "\n      <p>A 6-mark question asking you to ''explain three entrepreneurial characteristics'' is simply <strong>three 2-mark explain answers</strong> written one after another. For each characteristic you score: K (1 mark) + APP (1 mark).</p>\n      <p><strong>The Structure — Repeat 3 Times:</strong></p>\n      <ul>\n        <li><strong>Point 1:</strong> Name the characteristic (K) → Apply to the business using evidence from the text (APP)</li>\n        <li><strong>Point 2:</strong> Name the characteristic (K) → Apply to the business using evidence from the text (APP)</li>\n        <li><strong>Point 3:</strong> Name the characteristic (K) → Apply to the business using evidence from the text (APP)</li>\n      </ul>\n      <p><strong>⚠️ The Most Common Mistake:</strong><br/>Students write: <em>\"Creativity means thinking of new ideas.\"</em><br/>This just defines the word. You will NOT earn the application mark for explaining what a word means. You must say HOW the entrepreneur in the case study showed this characteristic — with evidence.</p>\n      <p><strong>✅ Model structure (Dyson question):</strong></p>\n      <ul>\n        <li><em>\"James Dyson showed determination (K) — he tried thousands of designs over several years without giving up (APP).\"</em></li>\n        <li><em>\"He was also creative (K) — he invented a completely new type of vacuum cleaner, the bagless design, that nobody had made before (APP).\"</em></li>\n        <li><em>\"Dyson was a risk taker (K) — he gave up his paid job and used his own savings to fund his new product, with no guarantee of success (APP).\"</em></li>\n      </ul>\n      <p><strong>Use the text!</strong> The examiner provides information about the entrepreneur specifically so you can apply it. Every application mark requires evidence from the case study.</p>\n    ", "check": {"question": "A 6-mark question asking you to ''explain three entrepreneurial characteristics'' is best answered using which structure?", "options": ["Three separate K + APP mini-answers, one for each trait", "One long paragraph covering all characteristics at once", "Three definitions of characteristics with no application", "One single characteristic explained in great depth"], "answer": 0, "explain": "The 6-mark question is simply three 2-mark explain answers in a row — each needs a named characteristic (K) plus application to the business (APP)."}}]}, "exam": {"enabled": true, "questions": [{"question": "Creativity is one characteristic of an entrepreneur. Identify one other characteristic of an entrepreneur. [1 mark]", "marks": 1, "hint": "There are three other accepted characteristics. Choose from: risk-taking, determination, or confidence. Do NOT write ''hardworking'' or ''motivated'' — these are not accepted by the mark scheme.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><ul><li><strong>1 mark</strong> for any one of the following: Risk-taking / Determination / Confidence</li></ul><p><strong>Accept:</strong> Synonyms such as ''perseverance'' for ''determination'' or ''self-assured'' for ''confidence''.</p><p><strong>Do NOT accept:</strong> ''Creativity'' (excluded by the stem of the question), or traits such as ''motivated'', ''well organised'', ''resilient'', ''teamwork'', or ''hardworking''.</p><p><strong>Examiner''s Comment:</strong> Most candidates gained the mark. The most common correct response was ''a risk taker''. Some candidates repeated ''creativity'', which was excluded by the question stem — always read the stem carefully before answering.</p></div>"}, {"question": "What is an entrepreneurial risk for the brothers?", "marks": 1, "hint": "An ''entrepreneurial risk'' is a personal consequence of running a business — not a physical hazard of the job or a legal obligation. Think about what happens to the PERSON, not the work.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: C — Poor health</strong></p><ul><li><strong>Why C is correct:</strong> Poor health is an entrepreneurial risk — the stress of running a business, especially one that may struggle, can cause serious mental and physical illness to the entrepreneur personally.</li><li><strong>Why A is wrong:</strong> Cold weather is a working condition/hazard for window cleaners — it affects the work itself, not the entrepreneur as a business owner.</li><li><strong>Why B is wrong:</strong> Paying taxes is a legal obligation for all businesses — it is a cost, not an entrepreneurial risk.</li><li><strong>Why D is wrong:</strong> Slippery ladders are a health and safety hazard specific to the work of window cleaning — not an entrepreneurial risk.</li></ul><p><strong>Examiner''s Comment:</strong> Only one third of candidates selected the correct answer. Many chose A or D (working hazards) or B (a cost). This demonstrates a lack of understanding of what ''entrepreneurial risk'' specifically means — it is about personal consequences to the entrepreneur, not the physical conditions of the work.</p><p><strong>Assessment for learning:</strong> Centres are advised not to overlook the third bullet point of Topic 1.1 — The concept of risk and reward.</p></div>"}, {"question": "What would NOT be an appropriate reason for Finley and Umi to have started this business?", "marks": 1, "hint": "You are looking for the option that is NOT a valid reason to start a business. Think about what enterprise means — and what its drawbacks are.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: D</strong></p><ul><li><strong>Why D is correct (NOT appropriate):</strong> Wanting to ''test physical and mental health by working long hours'' is actually a DRAWBACK of entrepreneurship — not a reason to start a business. No entrepreneur starts a business specifically to damage their health.</li><li><strong>Why A is wrong (it IS an appropriate reason):</strong> Developing a unique product idea is a legitimate purpose of enterprise.</li><li><strong>Why B is wrong (it IS an appropriate reason):</strong> Satisfying the needs of customers is the core purpose of business activity.</li><li><strong>Why C is wrong (it IS an appropriate reason):</strong> Spotting an opportunity to turn a leisure activity into a money-making business is a classic example of enterprise.</li></ul></div>"}, {"question": "What would help the business to succeed?", "marks": 1, "hint": "Businesses exist to satisfy customer needs. Which option actually achieves that goal?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: D</strong></p><ul><li><strong>Why D is correct:</strong> Planning business activity and work schedules carefully allows the plumbing firm to manage increased demand effectively, serving customers efficiently while maintaining quality.</li><li><strong>Why A is wrong:</strong> Turning customers away means they will simply contact a competitor — damaging customer loyalty and revenue.</li><li><strong>Why B is wrong:</strong> Making unrealistic promises leads to disappointment and damages the business''s reputation.</li><li><strong>Why C is wrong:</strong> Ignoring complaints accelerates customer loss and destroys the business''s reputation — the opposite of success.</li></ul></div>"}, {"question": "Explain three entrepreneurial characteristics that have supported James Dyson''s success. [6 marks]", "marks": 6, "hint": "For each characteristic: (1) name it clearly, then (2) explain specifically HOW Dyson showed it using evidence from the text. Do NOT just define the word — you must apply it to James Dyson.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 6 marks (AO1a: 3 marks + AO2: 3 marks)</h5><p>One mark for each entrepreneurial characteristic named (K), up to a maximum of 3.<br>One further mark for each application to James Dyson using evidence from the text (APP), up to a maximum of 3.<br><strong>No further marks can be gained without first scoring the Knowledge mark.</strong></p><table class=\"case-table\"><caption>Indicative Characteristics and Applications</caption><tr><th>Characteristic (K — 1 mark each)</th><th>Application to Dyson (APP — 1 mark each)</th></tr><tr><td>Confidence</td><td>Believed he could design a better vacuum cleaner than those on the market</td></tr><tr><td>Determination / Perseverance</td><td>Tried thousands of design ideas over several years from the late-1970s to 1984; continued after partnership with Amway failed and formed his own company</td></tr><tr><td>Creativity / Innovative / Inventive</td><td>Created a brand-new type of vacuum cleaner — the bagless design — that had not existed before</td></tr><tr><td>Willingness to take risks</td><td>Set up his own company in 1991 after the partnership with Amway failed, investing his own money and reputation</td></tr></table><p><strong>Examiner''s Comment:</strong> Generally well answered. To achieve full marks, students needed to name three characteristics and explain how each applied to Dyson using evidence from the text. Students who did less well named characteristics but then explained the meaning of the term (e.g. ''creativity means being good at design'') rather than how it applied to Dyson specifically. This did not earn the application mark.</p></div>"}, {"question": "State one characteristic of an entrepreneur. [1 mark]", "marks": 1, "hint": "Choose from: creativity, risk-taking, determination, or confidence. One word or a short phrase is all you need.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p>One mark for any accepted characteristic of an entrepreneur:</p><ul><li>Creativity / imaginative / innovative / inventive</li><li>Risk-taking</li><li>Determination</li><li>Confidence</li></ul><p><strong>Do NOT accept:</strong> ''Leadership''</p></div>"}, {"question": "Satisfying the needs of customers is:", "marks": 1, "hint": "Think about WHY businesses exist in the first place.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: C — A purpose of business activity</strong></p><ul><li><strong>Why C is correct:</strong> Satisfying the needs of customers is a core purpose of business activity — businesses produce goods and services to meet customer needs and earn profit in return.</li><li><strong>Why A is wrong:</strong> It is not a legal requirement — businesses that fail to satisfy customers lose them to competitors, but face no legal penalty.</li><li><strong>Why B is wrong:</strong> Market research is a tool used to find out what customers need — not the purpose of business activity itself.</li><li><strong>Why D is wrong:</strong> Human resources manages employees — satisfying customers is the purpose of the entire business, not just one department.</li></ul></div>"}, {"question": "Which of the following is a financial reward for enterprise?", "marks": 1, "hint": "Financial rewards involve money. Which option is a specific type of money earned by entrepreneurs?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: B — Profit</strong></p><ul><li><strong>Why B is correct:</strong> Profit is the financial reward of enterprise — the money remaining after all costs have been paid. It is what entrepreneurs aim to earn as a return for taking risks.</li><li><strong>Why A is wrong:</strong> Authority (power or control) is a non-financial benefit, not a financial reward.</li><li><strong>Why C is wrong:</strong> ''Success'' is vague and non-specific — it is not a financial reward.</li><li><strong>Why D is wrong:</strong> Wages are paid to employees — entrepreneurs do not earn wages from their own business; they earn profit.</li></ul></div>"}, {"question": "This is called:", "marks": 1, "hint": "What is it called when someone spots an opportunity and acts on it to create a business?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: B — Enterprise</strong></p><ul><li><strong>Why B is correct:</strong> Enterprise is spotting an opportunity to provide a product or service people are willing to pay for. The wine enthusiast has identified a way to turn a hobby into a business — a classic example of enterprise.</li><li><strong>Why A is wrong:</strong> Delegation is the process of passing tasks or authority to others within a business.</li><li><strong>Why C is wrong:</strong> Market research is collecting information about customers and the market — not the act of creating a business.</li><li><strong>Why D is wrong:</strong> Productivity is output per worker — it measures efficiency, not enterprise.</li></ul></div>"}, {"question": "Which one of the following is NOT a risk of entrepreneurship?", "marks": 1, "hint": "Three of these are risks. One of them is actually a REWARD. Which one?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Answer: C — Self-satisfaction</strong></p><ul><li><strong>Why C is correct (NOT a risk):</strong> Self-satisfaction is a non-financial REWARD of entrepreneurship — the personal pride and fulfilment from making a business idea succeed. This is one of the most frequently confused points in this topic.</li><li><strong>Why A is a risk:</strong> Failing health — the stress of running a business can cause serious mental and physical illness.</li><li><strong>Why B is a risk:</strong> Loss of money — personal savings invested in a failing business can be lost entirely.</li><li><strong>Why D is a risk:</strong> Strained personal relationships — long working hours and financial pressure put enormous strain on family and personal relationships.</li></ul></div>"}, {"question": "Identify one characteristic of an entrepreneur mentioned in Text 3. [1 mark]", "marks": 1, "hint": "Read the case study carefully — a characteristic is directly mentioned or strongly implied. Look for clues like ''enjoy coming up with new ideas'' or ''not knowing what the future may bring''.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO2)</h5><p>1 mark for identification of a characteristic <strong>clearly stated or implied in the text</strong>:</p><ul><li><strong>Creativity</strong> — \"enjoy coming up with new ideas\" / the unique concept of combining a restaurant with electric car charging points</li><li><strong>Risk-taking</strong> — \"not knowing what the future may bring\" (they embrace uncertainty)</li><li><strong>Decisive/Determination</strong> — \"have decided to set up\" and acted on their market opportunity</li></ul><p><strong>Note:</strong> The characteristic must be drawn from or supported by the text — generic answers not linked to the case study are not accepted for this question type.</p></div>"}, {"question": "This is an example of:", "marks": 1, "hint": "Developing an idea for a new business is one of the three purposes of what concept?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p><strong>Answer: B — Enterprise</strong></p><ul><li><strong>Why B is correct:</strong> Developing an idea for a new business is one of the three core purposes of enterprise (alongside spotting an opportunity and satisfying customer needs).</li><li><strong>Why A is wrong:</strong> Discrimination means treating someone unfairly based on protected characteristics such as race, gender, or age.</li><li><strong>Why C is wrong:</strong> Flexible working refers to arrangements where employees can vary their hours or place of work.</li><li><strong>Why D is wrong:</strong> Productivity measures output per worker — it is about efficiency in production, not starting a business.</li></ul></div>"}, {"question": "State one risk for an entrepreneur when starting a new business. [1 mark]", "marks": 1, "hint": "Think about what could go wrong personally for the entrepreneur — there are financial and non-financial risks. Either type is acceptable.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p>1 mark for any appropriate risk. Answers may include:</p><ul><li>Financial loss / loss of money / personal savings could be lost</li><li>Failing health / stress / mental or physical illness</li><li>Strained relationships with friends or family</li><li>Nobody may be interested in the business idea / insufficient demand</li><li>Strong competition (e.g. from The Works already in the same town)</li></ul></div>"}, {"question": "Which one of the following is UNLIKELY to be a characteristic of a successful entrepreneur?", "marks": 1, "hint": "All successful entrepreneurs share certain traits. One of these options is the OPPOSITE of what an entrepreneur should be.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p><strong>Answer: D — Being uncomfortable with taking risks</strong></p><ul><li><strong>Why D is correct (UNLIKELY):</strong> A successful entrepreneur must be willing and comfortable with taking risks — it is a core characteristic. Being uncomfortable with risk would prevent someone from ever starting a business.</li><li><strong>Why A is wrong (it IS a characteristic):</strong> Creating opportunities is central to enterprise — spotting and acting on gaps in the market.</li><li><strong>Why B is wrong (it IS a characteristic):</strong> Confidence in new situations is one of the four official entrepreneurial characteristics.</li><li><strong>Why C is wrong (it IS a characteristic):</strong> Determination to work through problems is one of the four official entrepreneurial characteristics.</li></ul></div>"}, {"question": "State two characteristics of an entrepreneur. [2 marks]", "marks": 2, "hint": "You need two separate accepted characteristics — each worth 1 mark. One word or a short phrase is enough for each.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a)</h5><p>1 mark for each correct characteristic, up to a maximum of 2 marks. Answers may include:</p><ul><li>Willing to take risks</li><li>Determination</li><li>Confidence</li><li>Creativity / imaginative / innovative</li><li>Passionate</li><li>Hard working</li><li>Motivated</li><li>Disciplined</li><li>Adaptable / flexible</li><li>Knowledgeable</li><li>People person</li></ul><p><strong>Note:</strong> This mark scheme is broader than some other questions (ARA — Any Reasonable Answer). Accept a wider range of traits here.</p></div>"}, {"question": "State two reasons why businesses exist. [2 marks]", "marks": 2, "hint": "Think about the fundamental purposes of business activity. What are businesses trying to achieve?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a / Knowledge)</h5><p>1 mark for each correct reason why businesses exist, up to a maximum of 2 marks. Reasons may include:</p><ul><li>To satisfy the needs of customers</li><li>To make a profit</li><li>To provide goods or services</li><li>To create employment</li></ul><p><strong>Note:</strong> Knowledge only required — no explanation needed.</p></div>"}, {"question": "Explain one characteristic Julie and Cathy might have as entrepreneurs. [2 marks]", "marks": 2, "hint": "Name a characteristic (1 mark) then explain how it applies specifically to Julie and Cathy''s hairdressing business (1 mark). You cannot score the application mark without first scoring the knowledge mark.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1b: Understanding 1 mark + AO2: Application 1 mark)</h5><p><strong>Understanding (1 mark)</strong> — acceptable characteristics:</p><ul><li>Creative</li><li>Prepared to take risks</li><li>Determined</li><li>Confident</li></ul><p><strong>Application (1 mark)</strong> — explanation relating to the hairdressing context:</p><ul><li>\"Julie and Cathy must be creative and make sure that customers are offered a range of different styles for their hair.\"</li><li>\"Julie and Cathy must be confident as there will be other hairdressers in the area, and they must demonstrate confidence so that customers will choose their salon.\"</li></ul><p><strong>Note:</strong> You cannot score the application mark without first scoring the understanding mark.</p></div>"}, {"question": "Analyse one risk to an entrepreneur in starting a new hairdressing business in competition with Sophisticutz. [3 marks]", "marks": 3, "hint": "Use the three-step formula: (1) state and explain the risk, (2) link it to the Sophisticutz case study using evidence, (3) explain the impact on the new business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1b: U 1 mark + AO2: APP 1 mark + AO3a: AN 1 mark)</h5><p><strong>Understanding (1 mark)</strong> — risk examples:</p><ul><li>Financial loss</li><li>Stress and effect on health</li><li>Pressure on relationships with friends/family</li></ul><p><strong>Application (1 mark)</strong> — linked to the Sophisticutz case study:</p><ul><li>\"There are already a lot of established hairdressers in the area.\"</li><li>\"All the best locations in town are already occupied by existing hairdressers, so a new business would have to open in a less favourable location.\"</li></ul><p><strong>Analysis (1 mark)</strong> — the effect/impact on the new business:</p><ul><li>\"Competition from Sophisticutz may mean fewer customers in the early stages, resulting in a loss of income.\"</li><li>\"This could lead to the entrepreneur losing their personal savings before the business becomes profitable.\"</li></ul><p><strong>Note:</strong> You cannot score application or analysis marks without first scoring the understanding mark.</p></div>"}, {"question": "Analyse two characteristics of an entrepreneur that helped James Dyson to succeed when starting up his business. [6 marks]", "marks": 6, "hint": "For each characteristic: state it (U), apply it to the Dyson case study using evidence from the text (APP), then explain the impact it had on his success (AN). Do this twice for two different characteristics.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 6 marks (AO1b: U 2 marks + AO2: APP 2 marks + AO3a: AN 2 marks)</h5><p>For each of two characteristics:</p><ul><li><strong>Understanding (1 mark each):</strong> Name and briefly explain the entrepreneurial characteristic.</li><li><strong>Application (1 mark each):</strong> Link to James Dyson using evidence from the text.</li><li><strong>Analysis (1 mark each):</strong> Explain the impact this characteristic had on his ability to succeed.</li></ul><p><strong>Acceptable characteristics and indicative content:</strong></p><ul><li><strong>Determination:</strong> U — not giving up when things are difficult. APP — tried over 500 designs. AN — without this he would have abandoned the project and the vacuum cleaner would never have been produced.</li><li><strong>Risk-taking:</strong> U — prepared to invest own money. APP — gave up his paid job and risked his savings. AN — this gave him the freedom and commitment to fully develop his idea without the distraction of employment.</li><li><strong>Confidence:</strong> U — believed in his own ability to succeed. APP — ''believing that, in the end, he would be successful.'' AN — this confidence kept him going through failures and convinced his wife to support them financially.</li><li><strong>Creativity:</strong> U — ability to design a new type of product. APP — created the bagless vacuum cleaner, a completely new concept. AN — this allowed him to enter a crowded market with a genuinely different product that customers wanted.</li></ul></div>"}]}}'::jsonb),
('business', '1-2-business-planning', '1.2 Business Planning', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>These are the essential terms you must be able to define accurately in the exam. Learn each one precisely — examiners expect specific language.</p>\n<ul>\n  <li><strong>Business Plan:</strong> A document which sets out details of the product or service being sold, how it will be financed, how it will be marketed, and the findings of market research.</li>\n  <li><strong>Finance:</strong> A business word used instead of money. The finance needed to start a business is the money required to buy the resources needed.</li>\n  <li><strong>Markets:</strong> Where a business sells its goods and services.</li>\n  <li><strong>Resources:</strong> The things a business needs to make it work, including finance, staff and materials.</li>\n  <li><strong>Operate:</strong> A term used to explain how a business works.</li>\n  <li><strong>Success:</strong> For a business, can take many forms, including making profit, surviving and providing a good service to customers.</li>\n  <li><strong>Aims and Objectives:</strong> Statements of what the business is trying to achieve (e.g. make a profit, expand, increase market share, survive).</li>\n  <li><strong>SMART Objectives:</strong> Objectives that are Specific, Measurable, Achievable, Realistic and Time-bound.</li>\n</ul>", "check": {"question": "What does the ''M'' in SMART objectives stand for?", "options": ["Measurable", "Marketable", "Motivational", "Manageable"], "answer": 0, "explain": "The M in SMART stands for Measurable — one of the five criteria (Specific, Measurable, Achievable, Realistic, Time-bound) listed in the Key Terms card."}}, {"title": "The Purpose of Planning Business Activity", "html": "<p>Every business — whether brand new or well established — needs to plan. Planning is a vital part of the successful start-up and development of a business. There are two core purposes:</p>\n<ul>\n  <li><strong>Reduce the risk of failure:</strong> Starting a business is risky. There may be competitors and customers might not want the product. Writing a business plan forces entrepreneurs to think through potential problems before they happen, reducing (but not eliminating) risk.</li>\n  <li><strong>Help a business to be as successful as possible:</strong> Thinking carefully about all aspects of running a business allows entrepreneurs to reflect on what they are proposing. The greater the care and thought given to this process, the greater the chance of success.</li>\n</ul>\n<p><strong>When is a business plan written?</strong> A business plan is normally written <strong>before a business starts</strong>, or when there is a major change in what the business plans to do (e.g. expanding into a new market, launching a new product).</p>\n<div class=\"case-study-box\">\n  <h4>Case Study: Electric Cars & Business Planning</h4>\n  <p>By 2030, no new petrol or diesel cars can be sold in the UK. Every car manufacturer — from Ford to Toyota — must plan carefully for this enormous change. Billions of pounds are being spent on changing production methods, and this cannot happen overnight. Careful planning ensures manufacturers meet the 2030 deadline without making costly mistakes in an intensely competitive market.</p>\n  <p><strong>Takeaway:</strong> Even large, established businesses must plan when facing major change. The scale of investment makes planning essential — getting it wrong could be catastrophic.</p>\n</div>", "check": {"question": "According to the two core purposes of business planning, besides reducing the risk of failure, what is the other main purpose?", "options": ["Satisfy a legal requirement for trading", "Help the business be as successful as possible", "Prevent competitors from entering the market", "Guarantee the business will make a profit"], "answer": 1, "explain": "The card states planning serves two purposes: reducing the risk of failure and helping the business be as successful as possible."}}, {"title": "The Contents of a Business Plan", "html": "<p>A business plan is not a standardised document — it is adapted to the specific circumstances of each business. However, most plans will cover the following key areas:</p>\n<ul>\n  <li><strong>The Business Idea:</strong> What the business will produce and sell. Is it a totally new idea or a development of an existing product/service?</li>\n  <li><strong>The People Running the Business:</strong> Details of who is involved and their relevant experience. Banks and investors are far more likely to back a plan from someone with proven experience.</li>\n  <li><strong>Market Research:</strong> Evidence that consumers want the product or service. Includes target market, pricing, how the product will be sold (online, shops, etc.) and promotional plans.</li>\n  <li><strong>Finance:</strong> How much money is needed, what it will be spent on, and where it will come from (e.g. owner''s savings, bank loan, overdraft, selling shares).</li>\n  <li><strong>Aims and Objectives:</strong> What the business wants to achieve and by when. These should be SMART.</li>\n  <li><strong>The Target Market:</strong> Who the business is selling to — age, gender, income level, etc.</li>\n  <li><strong>Competitors:</strong> Who the competitors are and how the business will differentiate itself (better quality, lower prices, unique features).</li>\n  <li><strong>Resources Needed:</strong> Equipment, premises, staff — everything required to operate the business.</li>\n</ul>\n<p>⚠️ <strong>What is NOT in a business plan:</strong> Personal hobbies of the owners, dates of birth, favourite school subjects, or titles of business textbooks.</p>", "check": {"question": "Which of the following would NOT normally be included in a business plan?", "options": ["The owners'' dates of birth", "The target market", "How the business will be financed", "Details of competitors"], "answer": 0, "explain": "The card explicitly states personal details like dates of birth are NOT included in a business plan, unlike the target market, finance and competitors."}}, {"title": "The Role of a Business Plan", "html": "<p>A business plan serves several important roles beyond simply being a written document. Understanding these roles helps you answer \"explain the purpose of…\" questions at a higher level.</p>\n<ul>\n  <li><strong>Identifying Markets:</strong> Forces the business to think clearly about who it is targeting. This shapes marketing decisions — the type of advertising, the price point, and the distribution channel all depend on the target market.</li>\n  <li><strong>Helping with Finance:</strong> Banks are more likely to lend money if they can see a detailed, well-thought-out plan. It demonstrates that the owners have considered all aspects of the business and gives lenders confidence they will be repaid.</li>\n  <li><strong>Identifying Resources:</strong> Requires owners to think about what equipment, premises, and staff they need to operate. Without this, a potential investor may view the business as too risky and refuse to invest.</li>\n  <li><strong>Achieving Aims and Objectives:</strong> Setting out aims with a timeline gives the business a clear direction. Without targets, there is no way to measure success or know when things are going wrong.</li>\n  <li><strong>Reducing Risk:</strong> Though a business plan cannot eliminate risk, it significantly reduces it by ensuring the business has thought through the key challenges in advance.</li>\n</ul>", "check": {"question": "Which role of a business plan best explains why banks are more willing to lend money to a business?", "options": ["Identifying markets, since it lists advertising slogans", "Reducing risk, since it removes all risk from trading", "Helping with finance, showing it''s carefully thought through", "Achieving aims and objectives, guaranteeing targets are met"], "answer": 2, "explain": "The ''Helping with Finance'' role explains that banks lend more readily when they see a detailed, well-thought-out plan, giving them confidence they will be repaid."}}, {"title": "Advantages & Disadvantages of a Business Plan", "html": "<p>For evaluation questions, you must be able to argue both sides. Here are the key points for and against producing a business plan:</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Reduces risk:</strong> Potential problems are identified before money is spent, giving the business a better chance of surviving.</div>\n    <div class=\"pro-item\"><strong>Secures finance:</strong> Banks and investors will rarely lend money without seeing a detailed plan — it is often essential for external funding.</div>\n    <div class=\"pro-item\"><strong>Sets clear direction:</strong> SMART objectives give the business measurable targets and a timeline, helping to keep focus and motivate staff.</div>\n    <div class=\"pro-item\"><strong>Identifies resources:</strong> Ensures the business has considered what it needs to operate, so it is not caught short once trading begins.</div>\n    <div class=\"pro-item\"><strong>Useful for evaluation:</strong> The plan can be used to monitor progress and identify when the business is falling short of its targets.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Time-consuming:</strong> Writing a thorough business plan takes significant time — time that could be spent running the business or serving customers.</div>\n    <div class=\"con-item\"><strong>Can be inaccurate:</strong> Forecasts are based on assumptions. If the market changes or competitors respond unexpectedly, the plan may quickly become outdated.</div>\n    <div class=\"con-item\"><strong>No guarantee of success:</strong> Even the best business plan cannot eliminate all risk. Unforeseen events (e.g. economic recessions, new competitors) can still cause a business to fail.</div>\n    <div class=\"con-item\"><strong>Opportunity cost:</strong> The time spent writing a plan has an opportunity cost — the owner cannot do other productive activities during that time.</div>\n  </div>\n</div>", "check": {"question": "Which of the following is a disadvantage of writing a business plan mentioned in this card?", "options": ["It guarantees business success", "It is time-consuming to produce", "It removes the need to secure finance", "It prevents competitors from copying ideas"], "answer": 1, "explain": "One disadvantage listed is that writing a thorough business plan is time-consuming, taking time that could be spent running the business."}}, {"title": "Evaluating a Business Plan", "html": "<p>In 9-mark evaluation questions, you will be asked to assess whether a specific business plan is effective or whether a business should write one. Use this framework to structure your thinking:</p>\n<ul>\n  <li><strong>What is included?</strong> Does the plan cover the core areas — market research, finance, target market, competitors, resources, objectives?</li>\n  <li><strong>What is missing?</strong> Any missing section could be a critical weakness, especially if it relates to the business''s specific situation (e.g. no competitor analysis for a business entering a crowded market).</li>\n  <li><strong>Are objectives SMART?</strong> Vague targets like \"make a profit\" or \"grow the business\" are not measurable. Look for specific figures and timelines.</li>\n  <li><strong>Is the plan relevant to the business context?</strong> A plan for a new start-up needs more detail than a plan for an established business making a minor change.</li>\n  <li><strong>Is the time cost justified?</strong> Weigh the benefit of having a plan against the opportunity cost of the time spent writing it.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Dunning Golf Club</h4>\n  <p>Dunning Golf Club produced a plan to increase its membership and profitability. The plan included: improving the golf club facilities, offering more benefits to paid-up members (e.g. subsidised lessons), using outside caterers to ensure better and cheaper catering, and more clearly stated priorities for the future and how these would be financed.</p>\n  <p><strong>Takeaway:</strong> This plan covers several important areas (finance, marketing, customer benefits, objectives) but could be criticised for not explicitly mentioning market research or a detailed competitor analysis. Are the targets SMART? They mention goals but without specific figures or deadlines.</p>\n</div>", "check": {"question": "When evaluating whether a business plan is effective, what should you check regarding its objectives?", "options": ["Whether it is longer than five pages", "Whether the objectives are SMART", "Whether it was submitted to a bank", "Whether it was written by a professional consultant"], "answer": 1, "explain": "The evaluation framework asks whether objectives are SMART — vague targets without specific figures or timelines, as seen in the Dunning Golf Club case study, are a weakness."}}, {"title": "Business Planning for Different Types of Business", "html": "<p>The importance and content of a business plan can vary significantly depending on the type of business. You may be asked to apply your knowledge to a specific business context.</p>\n<ul>\n  <li><strong>New Start-Up Business:</strong> A business plan is <em>especially</em> critical here. The business has no trading history, no existing customers, and typically needs external finance. Without a plan, a bank will not lend money and the founder has no way to judge whether the idea will work. The risk of failure is highest at the start-up stage.</li>\n  <li><strong>Large Established Business (e.g. Greggs, Ford):</strong> Planning is still vital when entering new markets, launching new products, or making major operational changes. Greggs used market data showing rising vegan numbers to plan and launch new products — this led to a 9.6% increase in sales.</li>\n  <li><strong>Expanding Business:</strong> When a successful business wants to grow (e.g. open new locations), a plan helps identify new resource needs, new competitors in the target area, and the finance required to fund expansion.</li>\n  <li><strong>Seasonal Business (e.g. Boots UK):</strong> Planning helps manage resource needs at different times of year — for example, recruiting temporary staff ahead of the Christmas period to match seasonal demand.</li>\n</ul>", "check": {"question": "Why is a business plan especially critical for a new start-up business, according to this card?", "options": ["It removes the need for market research", "It is legally required to be submitted to Companies House", "It has no trading history and usually needs external finance", "It guarantees the new business will succeed"], "answer": 2, "explain": "The card states a business plan is especially critical for a new start-up because it has no trading history and typically needs external finance, which banks won''t lend without a plan."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Business Plan", "definition": "A document setting out the product/service, how it will be financed and marketed, and market research findings."}, {"term": "Finance", "definition": "Money needed to buy the resources required to start or run a business."}, {"term": "Resources", "definition": "Everything a business needs to operate: finance, staff, materials, equipment, and premises."}, {"term": "Markets", "definition": "Where a business sells its goods and services."}, {"term": "Target Market", "definition": "The specific group of customers the business aims to sell to, defined by characteristics such as age, gender, and income."}, {"term": "Objectives", "definition": "Specific targets a business aims to achieve — ideally SMART (Specific, Measurable, Achievable, Realistic, Time-bound)."}, {"term": "Competitors", "definition": "Other businesses selling the same or similar products in the same market."}, {"term": "Market Research", "definition": "The process of gathering information about consumers and the market to inform business decisions."}, {"term": "Opportunity Cost", "definition": "The value of the next best alternative foregone when making a decision (e.g. the revenue lost while the owner writes the plan)."}, {"term": "Purpose of a Business Plan", "definition": "To reduce the risk of failure and to help the business be as successful as possible."}, {"term": "When is a Business Plan Written?", "definition": "Before a business starts trading, or when a major change to the business is planned."}, {"term": "Why do banks require a business plan?", "definition": "To show that careful thought has been given to all aspects of the business, giving them confidence the loan will be repaid."}]}, "mcq": {"enabled": true, "questions": [{"question": "A business plan would normally be written:", "options": ["Every month to keep it up to date", "A month after a business starts trading", "After a business has become established and competitors are known", "Before a business starts"], "answer": 3, "explain": "Correct: A business plan is written before a business starts (or when a major change is planned). Writing it after the business starts defeats the purpose of reducing risk and guiding early decisions."}, {"question": "A business plan will:", "options": ["Make sure the competitors know you are in business", "Identify the competitors of the business", "Put the competitors out of business", "Allow the competitors to see whether you need finance"], "answer": 1, "explain": "Correct: One key section of a business plan involves identifying who the competitors are and how the business will compete against them. It does not alert competitors to your existence or remove them from the market."}, {"question": "The purpose of identifying resources in a business plan is to:", "options": ["Make sure the required resources have been identified and where they will come from, so potential investors feel safer", "Make sure there is a list of some of the resources required", "Make sure each person involved knows what ''resources'' means", "Make sure resources required cost less than first thought"], "answer": 0, "explain": "Correct: Identifying resources in full — and explaining how they will be obtained — gives investors confidence that the owners have thought through how the business will operate. A vague list is not sufficient."}, {"question": "Which of the following is NOT in a business plan?", "options": ["The target market for the new business", "The objectives of the business", "The dates of birth of the business owners", "The known competitors of the new business"], "answer": 2, "explain": "Correct: Dates of birth of business owners are personal and irrelevant to running a business. A business plan includes the target market, objectives, and competitors — all of which are relevant to business decisions."}, {"question": "For which of the following might Sundip & Sons'' business plan be useful?", "options": ["Calculating the share of the profit due to each of the three partners", "Complying with current legislation relating to business planning", "Identifying the resources needed to expand into the new market", "Obtaining additional finance from shareholders"], "answer": 2, "explain": "Correct: A business plan helps identify the resources needed to operate. Sundip & Sons are expanding into laptop and tablet repairs, so they need to identify what new equipment, skills and premises this requires. Profit-sharing is governed by a partnership agreement, and there is no legal requirement to have a business plan."}, {"question": "Which of the following would help Radi to reduce his level of risk as a business owner?", "options": ["Becoming a sole trader", "Carefully planning all business activity", "Ignoring the needs of customers", "Making employees work long hours"], "answer": 1, "explain": "Correct: Careful planning reduces business risk by identifying potential problems before they occur and ensuring resources, finance, and markets are all considered. The other options would increase risk or cause harm."}, {"question": "Why is a business plan especially important for a new business?", "options": ["Because the owner needs something to show friends and family", "Because it guarantees the business will be successful", "Because it helps obtain finance and reduces the risk of failure before trading begins", "Because it tells competitors what the business plans to do"], "answer": 2, "explain": "Correct: A new business has no trading history, so it is especially important to plan carefully. The plan helps secure finance from banks (who will not lend without one) and reduces the risk of failure by forcing the owner to think through all aspects of the business."}, {"question": "Should information about the hobbies of the business owners be included in a business plan?", "options": ["Yes, to show the owners are well-rounded individuals", "Yes, because hobbies may be relevant to the business", "No, it is personal and irrelevant to running the business", "No, because it takes up too much space"], "answer": 2, "explain": "Correct: Hobbies are personal information and are not relevant to business decisions. A business plan should only include information that helps the business or its investors understand how the business will operate and succeed."}, {"question": "A bank is considering whether to lend money to a new business. Which of the following would most increase the bank''s confidence?", "options": ["The business owner''s personal bank statements", "A detailed and well-researched business plan", "A list of the products the business wants to sell", "A signed letter from a friend of the owner"], "answer": 1, "explain": "Correct: A detailed business plan shows the bank that the owner has carefully considered all aspects of the business — market research, competitors, finance needs, and objectives. This gives the bank confidence the loan will be repaid."}, {"question": "Which statement about a business plan is TRUE?", "options": ["Writing a business plan guarantees the business will succeed", "A business plan eliminates all risk from starting a business", "A business plan reduces risk but cannot eliminate it", "Only new businesses need to write a business plan"], "answer": 2, "explain": "Correct: A business plan reduces the risk of failure by making owners think carefully about all aspects of their business. However, it cannot eliminate risk entirely — unexpected events can still cause a business to fail even with an excellent plan."}, {"question": "SJ Salon last wrote its business plan when it opened in 2014. A national competitor is about to open nearby. What does this situation suggest about the need for a new plan?", "options": ["No new plan is needed because the original plan is still valid", "A new plan is needed because the competitive environment has significantly changed", "A new plan should only be written if the salon makes a loss", "A new plan is unnecessary because the salon has been profitable"], "answer": 1, "explain": "Correct: A business plan should be updated when there is a major change in the business environment. A new national competitor entering the local market is exactly this kind of significant change — it affects the salon''s target market, pricing, marketing, and strategic objectives."}, {"question": "Which of the following is the best definition of a ''business plan''?", "options": ["A thought or idea about what a business might do in the future", "A document detailing the product/service, how it will be financed, marketed, and evidence from market research", "A legal document required by law before starting a business", "A monthly report produced by a business showing its profits"], "answer": 1, "explain": "Correct: A business plan is specifically a document (not just a thought or idea) that details the product/service, finance sources, marketing approach, and market research findings. It is not a legal requirement and is not produced monthly."}]}, "fib": {"enabled": true, "questions": [{"text": "A business plan is normally written [before] a business starts, or when a [major] change takes place."}, {"text": "The two main purposes of a business plan are to reduce the [risk] of failure and to help a business to be as [successful] as possible."}, {"text": "A business plan must include details of who the [target] market is and who the [competitors] are."}, {"text": "The [finance] needed to start a business is the money required to buy the [resources] needed to operate."}, {"text": "Good objectives should be SMART — Specific, [Measurable], Achievable, Realistic and [Time-bound]."}, {"text": "A bank is more likely to lend money if the business can present a detailed [business] plan, as it shows the bank that careful [thought] has been given to all aspects of the business."}, {"text": "Writing a business plan [reduces] risk but does not [eliminate] it entirely."}, {"text": "The [disadvantage] of a business plan is that it takes significant time to write, which has an [opportunity] cost."}, {"text": "Market research is used to show that [consumers] will use the business and to identify the [price] at which the product will be sold."}, {"text": "A business plan is a [document], not just a thought or idea — this distinction is important for the [knowledge] mark in longer exam questions."}, {"text": "For a new business, obtaining [finance] is one of the most important uses of a business plan, as banks will rarely lend without seeing one."}, {"text": "The people section of a business plan includes details of who is [involved] and their [experience] in running a business."}]}, "tf": {"enabled": true, "questions": [{"statement": "A business plan should include information about the hobbies of the business owners.", "answer": false, "explain": "FALSE. Hobbies are personal and irrelevant to business decisions. A business plan covers business-relevant content only: the business idea, finance, marketing, market research, competitors, target market, and objectives."}, {"statement": "A business plan should include details of what marketing is planned.", "answer": true, "explain": "TRUE. Marketing is a core section of any business plan. It identifies how the business will attract customers, what price it will charge, how it will promote its products, and through which channels it will sell."}, {"statement": "Writing a business plan guarantees that a business will succeed.", "answer": false, "explain": "FALSE. A business plan reduces the risk of failure but cannot guarantee success. Unforeseen circumstances — economic downturns, unexpected competition, changing consumer tastes — can still cause a business to fail even with a thorough plan."}, {"statement": "A business plan is normally written before a business starts trading.", "answer": true, "explain": "TRUE. The business plan is typically produced before the business starts, or when a major change is planned. Writing it after trading begins means many risks may not have been considered at the critical start-up stage."}, {"statement": "A business plan should include a list of the favourite books read by the business owners.", "answer": false, "explain": "FALSE. Titles of business books (or any personal reading material) are irrelevant to the business plan. Only business-relevant information — markets, finance, competitors, resources, objectives — belongs in the plan."}, {"statement": "A good business plan is necessary if a business hopes to obtain external finance from a bank.", "answer": true, "explain": "TRUE. Banks and other external investors will rarely lend money without seeing a detailed business plan. It demonstrates that the owners have thought carefully about how the money will be used and how the loan will be repaid."}, {"statement": "A business plan should include analysis of the competitors in the market.", "answer": true, "explain": "TRUE. Identifying competitors — and explaining how the business will differentiate itself (e.g. lower prices, better quality, unique features) — is an essential part of the business plan."}, {"statement": "Once written, a business plan never needs to be updated.", "answer": false, "explain": "FALSE. A business plan should be reviewed and updated when significant changes occur — such as a new competitor entering the market, the business deciding to expand, or major changes in consumer demand."}, {"statement": "A description of the target market should be included in a business plan.", "answer": true, "explain": "TRUE. Identifying who the business is selling to (age, gender, income level, location, etc.) is fundamental to the business plan. It shapes decisions about pricing, promotion, and distribution."}, {"statement": "The information about who is running the business is irrelevant to investors and can be left out of a business plan.", "answer": false, "explain": "FALSE. Investors and banks are much more likely to fund a business run by people with relevant experience. Details of the owners'' qualifications and business experience are an important part of the plan."}, {"statement": "A business plan helps to identify the resources a business will need to operate.", "answer": true, "explain": "TRUE. One of the key roles of a business plan is to identify what resources — equipment, premises, staff — the business requires. Without this, a potential investor may feel the business has not been properly thought through."}, {"statement": "There is a legal requirement for all businesses to produce a business plan.", "answer": false, "explain": "FALSE. There is no legal requirement to produce a business plan. However, it is strongly advisable — particularly for new businesses seeking external finance — as banks will rarely lend without one."}]}, "misc": {"enabled": true, "items": [{"myth": "A business plan is a thought or process — something the owner thinks about.", "truth": "A business plan is specifically a document or written record. The Knowledge mark in long-answer questions requires you to describe it as a document, not just an idea or plan in the owner''s head.", "check": {"question": "What must a business plan be described as, to earn the Knowledge mark?", "options": ["A thought or idea in the owner''s mind", "A verbal agreement between business partners", "A mental checklist used before trading", "A document or written record"], "answer": 3, "explain": "The misconception card corrects that a business plan is specifically a document, not a thought — this distinction is required for the Knowledge mark."}}, {"myth": "Writing a business plan means the business will definitely succeed.", "truth": "A business plan reduces risk but cannot eliminate it. Always write ''reduces the risk of failure'' — never say it ''guarantees success'' or ''ensures the business will be profitable''.", "check": {"question": "Which phrase correctly describes the effect of a business plan on risk?", "options": ["Eliminates all risk of failure", "Guarantees the business will succeed", "Reduces the risk of failure", "Has no effect on the level of risk"], "answer": 2, "explain": "The card corrects the misconception that a plan guarantees success — it only reduces risk, and you should never claim it ''guarantees'' or ''ensures'' success."}}, {"myth": "A business plan has a fixed, standard format that every business follows.", "truth": "A business plan is adapted to the specific circumstances of the business. There is no single correct format — the content depends on what the business needs to consider.", "check": {"question": "Does every business plan follow the same fixed, standard format?", "options": ["It must follow an identical, standardised structure", "It is chosen randomly by each business owner", "It is set by strict government regulation", "It is closely adapted to a business''s specific needs"], "answer": 3, "explain": "The card corrects the misconception of a fixed format — a business plan is adapted to what the specific business needs to consider."}}, {"myth": "In an evaluate question about a business plan, simply listing what is in a plan gets full marks.", "truth": "Evaluation questions require you to judge whether the plan is good or whether it is missing anything. You must consider whether the objectives are SMART and whether the missing sections matter given the specific business context.", "check": {"question": "In an evaluate question, what must you do to earn full marks beyond listing the contents of a business plan?", "options": ["Copy the case study details out word for word", "Write as many sentences as possible about the plan", "Simply list every section included in the plan", "Judge whether the plan is effective and identify gaps"], "answer": 3, "explain": "The card corrects the misconception that listing contents earns full marks — evaluate questions require judging the plan''s effectiveness, including whether objectives are SMART and what might be missing."}}, {"myth": "All businesses need to write a new business plan every year.", "truth": "A business plan is written when a business starts or when a major change is planned (e.g. expansion, entering a new market). It is not an annual requirement — but it should be updated when significant changes occur.", "check": {"question": "When should a business normally produce a new business plan?", "options": ["Every single year without exception", "Only after the business has already failed once", "At start-up, or when a major change is planned", "Only when a bank specifically requests one"], "answer": 2, "explain": "The card corrects the misconception of an annual requirement — a plan is written at start-up or when a major change (like expansion) is planned, and updated when significant changes occur."}}, {"myth": "Including personal information about the owners (hobbies, birth dates, favourite books) makes the business plan more complete.", "truth": "Personal information is irrelevant and should not be included. Examiners specifically test this with true/false questions. Only business-relevant information belongs in the plan.", "check": {"question": "Should personal information about the owners, such as hobbies or dates of birth, be included in a business plan?", "options": ["No, because including it breaks the law", "Yes, it makes the plan feel more complete and personal", "No, personal information is irrelevant to the business", "Yes, but only for larger business partnerships"], "answer": 2, "explain": "The card corrects the misconception that personal details make a plan more complete — examiners specifically test with true/false questions that such information is irrelevant."}}, {"myth": "For the Application marks in a 9-mark question, you just need to mention the business name.", "truth": "Application marks require you to use specific data from the case study — particularly numerical data. For example, calculating percentages from survey results or using specific figures mentioned in the text.", "check": {"question": "What is required to earn Application marks in a 9-mark question?", "options": ["Writing the longest possible answer overall", "Repeating back the wording of the question", "Using specific numerical data from the study", "Simply mentioning the name of the business"], "answer": 2, "explain": "The card corrects the misconception that naming the business is enough — Application marks require using specific data, especially numerical calculations, from the case study."}}, {"myth": "A conclusion in a 9-mark evaluation can just repeat the points already made.", "truth": "To earn full Evaluation marks, the judgement must be explicit AND contextually justified. Simply repeating earlier points without making a clear decision earns only 1 mark out of 3. You must state your decision AND justify it using case study detail.", "check": {"question": "To earn full Evaluation marks in a 9-mark question conclusion, what must you do?", "options": ["List a few extra advantages not mentioned before", "Ask the examiner an unanswered rhetorical question", "Simply repeat the analysis points already made", "State an explicit decision, justified in context"], "answer": 3, "explain": "The card corrects the misconception that repeating points is enough — full Evaluation marks require an explicit, contextually-justified decision; repeating points without one earns only 1 of 3 marks."}}]}, "tips": {"enabled": true, "items": [{"title": "A Business Plan is a DOCUMENT — Not a Thought", "html": "<p>This is one of the most commonly missed marks on the paper. The Knowledge mark requires you to describe a business plan as a <strong>specific document or written record</strong> — not just an idea, thought, or process.</p>\n    <p><strong>❌ Bad Answer (0 marks):</strong><br/><em>\"A business plan is when a business thinks about what it wants to do.\"</em></p>\n    <p><strong>✅ Good Answer (1 mark):</strong><br/><em>\"A business plan is a document that sets out the aims, finance, market research, and marketing of a business.\"</em></p>\n    <p><strong>⚠️ Examiner''s Warning:</strong> Candidates who launched straight into pros and cons without defining what a business plan actually is frequently missed this mark. Always define key terms at the start of a long-answer question.</p>", "check": {"question": "According to this exam tip, what mistake do many candidates make in long-answer questions about business plans?", "options": ["They forget to write a conclusion", "They give far too many disadvantages", "They write too many calculations", "They skip the definition entirely"], "answer": 3, "explain": "The examiner''s warning notes candidates who jumped straight into pros and cons without first defining what a business plan is frequently missed the Knowledge mark."}}, {"title": "Point + Link to Business = 2 Marks", "html": "<p>For a 2-mark \"explain\" question, you need two things: a clear point AND a development that links it to the business or shows the impact.</p>\n    <p><strong>The Formula:</strong> State the benefit (1) → Explain how it helps the specific business (1)</p>\n    <p><strong>❌ Bad Answer (0–1 marks):</strong><br/><em>\"Planning helps Boots UK because it is organised.\"</em><br/>This is too vague — \"organised\" is not a business outcome.</p>\n    <p><strong>✅ Good Answer (2 marks):</strong><br/><em>\"Business planning helps Boots UK identify what resources (such as labour) are needed at specific times (1), so that when the store is at its busiest over Christmas, staffing levels match demand (1).\"</em></p>\n    <p><strong>🚫 Avoid:</strong> Do not confuse WHAT is planned with WHY planning is useful. The question asks for the purpose/advantage — not the contents.</p>", "check": {"question": "What is required to score full marks on a 2-mark ''explain'' question?", "options": ["A clear point linked to the business", "One long, unstructured paragraph", "A definition of the key term only", "Two completely unrelated points"], "answer": 0, "explain": "The formula for a 2-mark explain question is: state the benefit, then explain how it helps the specific business — point plus link."}}, {"title": "Use the Numbers — Don''t Just Quote Them", "html": "<p>In 9-mark questions with data, <strong>two of the nine marks are for quantitative application</strong>. This means you must <strong>calculate or process</strong> the numbers — not just copy them out.</p>\n    <p><strong>The Formula:</strong> Perform any relevant calculation using the data provided.</p>\n    <p><strong>Examples of calculations from the SJ Salon question:</strong></p>\n    <ul>\n      <li>65% of customers have used SJ Salon since 2019 (130 ÷ 200 × 100)</li>\n      <li>42% of customers would consider trying the competitor if cheaper (84 ÷ 200 × 100)</li>\n      <li>Sam last wrote a business plan 10 years ago (2024 − 2014 = 10)</li>\n      <li>Writing the plan would take 75% of a working week (30 ÷ 40 × 100)</li>\n      <li>96 customers were NOT aware of the competitor (200 − 104 = 96)</li>\n    </ul>\n    <p><strong>⚠️ Key Rule:</strong> You need two separate calculations for 2 marks. Any valid calculation counts — even simple ones like 2 + 2 = 4 employees.</p>", "check": {"question": "In a 9-mark data-response question, how many separate calculations are typically needed to earn full quantitative application marks?", "options": ["Four", "One", "Two", "None — quoting the figures is enough"], "answer": 2, "explain": "The key rule states you need two separate calculations to earn the two quantitative application marks — simply quoting numbers is not enough."}}, {"title": "One Pro AND One Con = Full Analysis Marks", "html": "<p>For the 2 analysis marks in a 9-mark question, examiners are looking for <strong>one business-facing advantage</strong> AND <strong>one business-facing disadvantage</strong> of writing a business plan.</p>\n    <p><strong>The Formula:</strong> One pro (1) + One con (1) = 2 marks</p>\n    <p><strong>✅ Good Analysis Points:</strong></p>\n    <ul>\n      <li><strong>Pros:</strong> Helps set new goals to compete → Secures finance from a bank → Identifies what resources are needed → Helps measure success against objectives</li>\n      <li><strong>Cons:</strong> Takes significant time to write → Opportunity cost (time away from customers) → May quickly become outdated → No guarantee of success</li>\n    </ul>\n    <p><strong>❌ Common Mistake:</strong> Only writing advantages, or only writing disadvantages. You need both for full marks.</p>\n    <p><strong>🚫 Avoid vague analysis:</strong> \"It helps the business\" or \"it makes things easier\" are not specific business impacts. Always say <em>what</em> improves — costs, revenue, customer numbers, market share, etc.</p>", "check": {"question": "What combination of points is needed to earn full Analysis marks in a 9-mark question about a business plan?", "options": ["Two disadvantages and no advantages", "One vague statement that ''it helps the business''", "Two advantages and no disadvantages", "One business-facing advantage and one disadvantage"], "answer": 3, "explain": "Full Analysis marks require one pro AND one con — only writing advantages or only disadvantages misses out on the full 2 marks."}}, {"title": "The Four-Paragraph Structure for Full Marks", "html": "<p>A 9-mark evaluation question is the highest-tariff question on the paper. Marks are split across <strong>Knowledge, Understanding, Application (quantitative), Analysis, and Evaluation</strong>. Structure your answer in four paragraphs:</p>\n    <p><strong>Paragraph 1 — K & U:</strong><br/>Define the key term and explain what it contains.<br/><em>\"A business plan is a document (K) that contains details of the business''s aims, target market, finance, and market research (U).\"</em></p>\n    <p><strong>Paragraph 2 — AN & APP (Advantage):</strong><br/>Give one reason FOR writing the plan, applied to the specific business with data.<br/><em>\"One advantage of writing a new plan is that it would help SJ Salon set new strategies to compete. 42% of customers (APP) would consider using the new competitor if its prices were lower — so the salon needs a clear plan to retain these customers (AN).\"</em></p>\n    <p><strong>Paragraph 3 — AN & APP (Disadvantage):</strong><br/>Give one reason AGAINST, applied to the business with data.<br/><em>\"However, writing the plan will take Sam 30 hours — 75% of a full working week (APP). This is time he will not spend serving customers, which is an opportunity cost that could cost the salon revenue (AN).\"</em></p>\n    <p><strong>Paragraph 4 — Evaluation (3 marks):</strong><br/>Make a <strong>clear, explicit decision</strong> (1) + valid justification (1) + contextual justification (1).<br/><em>\"Overall, I think Sam SHOULD write a new business plan (DECISION). The arrival of a national hairdressing chain is a significant change to SJ Salon''s competitive environment (CONTEXT), and without a plan, the partners have no clear strategy for retaining their customers and could lose a substantial proportion of their revenue (REASONING/IMPACT).\"</em></p>\n    <p><strong>⚠️ Examiner''s Warning:</strong> The most common reason for losing Evaluation marks was \"sitting on the fence\" — giving reasons for and against but never stating a final decision. You MUST make a clear choice.</p>", "check": {"question": "According to examiners, what is the most common reason students lose Evaluation marks in a 9-mark question?", "options": ["Giving reasons without ever deciding", "Quoting too much from the case study", "Writing far too short an introduction", "Using too many calculations"], "answer": 0, "explain": "The examiner''s warning states the most common reason for losing Evaluation marks was ''sitting on the fence'' — never making a clear final decision."}}, {"title": "Evaluating a Business Plan''s Effectiveness", "html": "<p>When asked to evaluate <strong>how effective a specific business plan is</strong> (e.g. Shirtz Ltd or Dunning Golf Club), use this framework:</p>\n    <ul>\n      <li><strong>What is good about it?</strong> Which sections are present and well-developed?</li>\n      <li><strong>What is missing or weak?</strong> Are any key sections absent? Is the detail sufficient?</li>\n      <li><strong>Are the objectives SMART?</strong> Vague goals like \"grow the business\" are not measurable — this is a critical weakness.</li>\n      <li><strong>Does the missing content matter for this specific business?</strong> A missing competitor analysis is especially damaging if the business is entering a competitive market.</li>\n    </ul>\n    <p><strong>✅ Example Evaluation Sentence:</strong><br/><em>\"Overall, the Shirtz Ltd business plan is only partially effective (DECISION). While it identifies the need for new finance and the target pricing strategy, it lacks the financial detail (such as cash flow forecasts) that a bank would need before agreeing to lend money (CONTEXT + IMPACT). Without this, the plan may not help Shirtz Ltd achieve its core objective of expansion (REASONING).\"</em></p>", "check": {"question": "When evaluating how effective a specific business plan is, why is a missing competitor analysis especially damaging?", "options": ["It always results in an automatic mark of zero", "If entering a competitive market, this gap matters more", "It only matters for analyse questions, not evaluate ones", "Competitor analysis is never part of a business plan"], "answer": 1, "explain": "The framework notes that missing content matters more when it is directly relevant to the business''s specific situation — e.g. a missing competitor analysis is especially damaging for a business entering a crowded market."}}]}, "exam": {"enabled": true, "questions": [{"question": "Evaluate, using the data in Text 3, whether Sam should write a new business plan. [9 marks]", "marks": 9, "hint": "You need to: (1) define a business plan as a document, (2) explain what it contains, (3) perform two calculations using the survey data, (4) give one advantage AND one disadvantage of writing the plan, and (5) make a clear final decision with a justified, contextual reason.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 9 marks total</h5><ul><li><strong>Knowledge (1 mark AO1a):</strong> Business plan is a document/record/e-file (not just a thought or process)</li><li><strong>Understanding (1 mark AO1b):</strong> Identifies one item of content found in a business plan (e.g. aims, target market, finance, competitors, market research)</li><li><strong>Quantitative Application (2 marks AO2):</strong> Two demonstrations of numerical skill using the data provided</li><li><strong>Analysis (2 marks AO3a):</strong> One business-facing advantage AND one business-facing disadvantage of writing a business plan</li><li><strong>Evaluation (3 marks AO3b):</strong> Explicit decision (1) + valid justification (1) + contextual justification using case study detail (1)</li></ul></div>\n    <div class=\"marks-section\"><h5>Valid Quantitative Calculations (any two)</h5><ul><li>65% have used SJ Salon since 2019 (130 ÷ 200 × 100)</li><li>35% / 70 customers have only recently become customers (200 − 130 = 70)</li><li>52% / 104 customers were aware of the competitor (104 ÷ 200 × 100)</li><li>42% would try the competitor if cheaper (84 ÷ 200 × 100)</li><li>58% / 116 would NOT try the competitor even if cheaper</li><li>33% consider quality more important than price (66 ÷ 200 × 100)</li><li>The plan has not been updated for 10 years (2024 − 2014)</li><li>Writing the plan = 75% of a working week (30 ÷ 40 × 100)</li><li>SJ Salon now has 4 employees (1 FT + 1 PT + 2 new PT = 4, or partners + 4 workers = 6 total)</li></ul></div>\n    <div class=\"marks-section\"><h5>Analysis Points</h5><p><strong>Pros of writing:</strong> Set/adapt goals for new competition → attract investors → develop new strategy/USP → monitor progress against targets</p><p><strong>Cons of writing:</strong> Time cost (30 hours / 75% of working week) → opportunity cost (time away from customers) → cost implications → plan may quickly become outdated</p></div>\n    <div class=\"marks-section\"><h5>Evaluation Guidance</h5><p>No right or wrong decision — marks are awarded for the quality of justification, not the choice made.</p><ul><li><strong>1 mark:</strong> A clear decision (should or should not write the plan)</li><li><strong>2 marks:</strong> Decision + valid reason (applicable to most businesses)</li><li><strong>3 marks:</strong> Decision + contextual reason using specific case study detail</li></ul><p><strong>⚠️ Common Error:</strong> \"Sitting on the fence\" — giving pros and cons without a final decision = 0 evaluation marks. The decision must be explicit.</p></div>"}, {"question": "For which of the following might Sundip & Sons'' business plan be useful?", "marks": 1, "hint": "Think about what a business plan actually helps a business to DO. Which of these options is a genuine role of a business plan?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Identifying the resources needed to expand into the new market</h5><p><strong>Why C is correct:</strong> A key role of a business plan is to identify the resources a business needs to operate. Sundip & Sons are expanding into laptop and tablet repairs, so they need to identify what new equipment, skills, and potentially premises this requires. The plan helps them plan for this expansion systematically.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (Profit share):</strong> Profit sharing between partners is governed by the partnership agreement, not the business plan. The business plan outlines how the business will operate and grow — not how profits are distributed.</li><li><strong>B (Legislation):</strong> There is no legislation requiring businesses to produce a business plan. It is not a legal requirement — it is a strategic management tool.</li><li><strong>D (Finance from shareholders):</strong> A partnership cannot have shareholders — shareholders are part of limited companies. A business plan could help obtain a bank loan, but not shareholder finance in this context.</li></ul></div>"}, {"question": "Explain the purpose of planning business activity for Greggs'' managers. [2 marks]", "marks": 2, "hint": "You need one clear purpose (1 mark) and then link it specifically to something in the Greggs case study (1 mark). Do NOT just describe what Greggs plans — explain WHY planning helps.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a + AO2)</h5><ul><li><strong>1 mark (Knowledge/Understanding):</strong> Identifies a valid purpose of planning business activity</li><li><strong>1 mark (Application):</strong> Links the purpose specifically to Greggs using case study detail</li></ul><p><strong>Note: No application mark can be gained without a knowledge/understanding mark first.</strong></p></div>\n    <div class=\"marks-section\"><h5>Valid Purposes (any one)</h5><ul><li>Reduce risk of failure</li><li>Help a business to succeed / achieve objectives</li><li>Obtain finance / investment</li><li>Identify markets to enter</li><li>Identify resources required to operate</li><li>Support evaluation of business performance</li></ul></div>\n    <div class=\"marks-section\"><h5>Valid Application Points</h5><ul><li>Market growing from £18.5bn to £23.4bn</li><li>New product development (vegan products)</li><li>20,000 employees to manage and resource</li><li>Greggs'' aim to be favourite for food-on-the-go</li><li>Growing number of vegans in the UK</li><li>One of the UK''s happiest places to work</li></ul></div>\n    <div class=\"marks-section\"><h5>⚠️ Examiner Warning</h5><p>\"To be organised\" or \"help the business flow\" are too vague and score zero. You must state the specific business purpose (e.g. reduce risk, obtain finance, identify markets). Do NOT describe WHAT is planned — explain WHY planning is useful.</p></div>"}, {"question": "Explain one way planning business activity may help Superdry to succeed. [2 marks]", "marks": 2, "hint": "Choose one specific way planning helps — then link it to a specific detail from the Superdry case study. Do NOT describe what Superdry does — explain how PLANNING helps them do it better.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b + AO2)</h5><ul><li><strong>1 mark (Understanding):</strong> Demonstrates understanding of how planning leads to success</li><li><strong>1 mark (Application):</strong> Links the point specifically to Superdry using case study detail</li></ul><p><strong>Note: No application mark without understanding first.</strong></p></div>\n    <div class=\"marks-section\"><h5>Valid Understanding Points</h5><ul><li>Helps reduce risk</li><li>Helps with resourcing (physical / IT / staffing)</li><li>Helps secure finance</li><li>Helps with decision-making</li><li>Helps the business know HOW to achieve something (not just what to do)</li></ul></div>\n    <div class=\"marks-section\"><h5>Valid Application — Superdry Details</h5><ul><li>Successful international brand</li><li>135 stores across UK and Europe</li><li>4,800 employees</li><li>Committed to high quality</li><li>Policies on discrimination / employee retention</li><li>£41.4m spent on store investment in 2017</li><li>Refitting 11 stores</li><li>Distribution through Next / own website</li></ul></div>\n    <div class=\"marks-section\"><h5>⚠️ Do NOT Award</h5><ul><li>\"Helps achieve objectives\" — this restates what the question is asking</li><li>Answers about doing market research — research is not the same as planning</li><li>Vague answers: \"more organised\", \"focused\", \"better chance of survival\"</li></ul></div>"}, {"question": "Explain one advantage to Boots UK of planning business activities. [2 marks]", "marks": 2, "hint": "One advantage (1 mark) + a development that shows the impact on Boots UK specifically (1 mark). Use the information about seasonal demand in the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b + AO2)</h5><ul><li><strong>1 mark (Understanding):</strong> States a clear advantage of planning business activities</li><li><strong>1 mark (Application):</strong> Development point applied in context of Boots UK</li></ul></div>\n    <div class=\"marks-section\"><h5>Valid Advantages</h5><ul><li>Helps reduce risk and/or increase chances of success</li><li>Helps identify markets</li><li>Helps identify what resources are required (e.g. human resources)</li><li>Helps achieve aims/objectives (e.g. increased profitability, customer satisfaction)</li><li>Helps secure additional finance</li></ul></div>\n    <div class=\"marks-section\"><h5>Model Answers</h5><p><em>\"Boots UK''s trade varies throughout the year. Business planning helps managers identify what resources (such as labour) are needed at specific times (1), so that when Boots UK is at its busiest, staffing levels match customer demand and service quality is maintained (1).\"</em></p><p><em>\"Business planning can help Boots UK to secure additional finance (1) to fund the opening of new stores or investment in existing stores (1).\"</em></p></div>"}, {"question": "Which of the following would help Radi to reduce his level of risk?", "marks": 1, "hint": "Think about which option directly addresses the problem of risk — the core purpose of a business plan.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Carefully planning all business activity</h5><p><strong>Why B is correct:</strong> The primary purpose of a business plan is to reduce risk. By carefully planning, Radi can identify potential problems before they occur, ensure resources are in place, and set clear objectives for managing growth. This directly addresses his concern about the increasing level of risk.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (Becoming a sole trader):</strong> Chimney Restore Ltd is already a limited company, which actually gives Radi the protection of limited liability. Becoming a sole trader would increase his personal financial risk (unlimited liability), not reduce it.</li><li><strong>C (Ignoring customers):</strong> Ignoring customer needs would lead to falling sales and reputation damage — this increases risk significantly, not reduces it.</li><li><strong>D (Long hours for employees):</strong> Overworking employees leads to poor morale, mistakes, high staff turnover, and potential legal issues. This increases operational and legal risk.</li></ul></div>"}, {"question": "Explain one way that preparing a business plan may be useful to Ford Motors. [2 marks]", "marks": 2, "hint": "Focus on the USE or BENEFIT of the business plan — not its contents. Then apply it to something specific about Ford Motors (e.g. types of vehicles, number of employees, investment in new designs).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b + AO2)</h5><ul><li><strong>1 mark (Understanding):</strong> Explains a valid use or benefit of preparing a business plan</li><li><strong>1 mark (Application):</strong> Links the use specifically to Ford Motors</li></ul></div>\n    <div class=\"marks-section\"><h5>Valid Uses</h5><ul><li>Secure finance/investment</li><li>Helps achieve/focus on aims and objectives</li><li>Helps identify markets</li><li>Identify resources needed</li><li>Reduce risk</li><li>Helps with scheduling tasks / managing deadlines</li><li>Helps forecast financial achievement / set budgets</li><li>Helps monitor progress against targets</li></ul></div>\n    <div class=\"marks-section\"><h5>Valid Application — Ford Details</h5><ul><li>Developing new car designs / models</li><li>Manufacturing cars, vans, trucks, buses</li><li>Different market segments (eco, family, sports, people carriers)</li><li>Primary and secondary market research</li><li>Monitoring sales against product lifecycle</li></ul></div>\n    <div class=\"marks-section\"><h5>⚠️ Examiner Warning (from examiner comments)</h5><p>Many candidates scored zero on this question because they described the CONTENTS of a business plan rather than its USE. The question asks how it may be USEFUL — not what it contains.</p><p><strong>Do NOT award:</strong> \"Helps set objectives\" on its own (too vague) | \"Communicate with employees\" | \"Being organised\" | \"Improves performance\"</p></div>"}, {"question": "Evaluate the effectiveness of Shirtz Ltd''s business plan as shown in the case study. [9 marks]", "marks": 9, "hint": "You need to judge HOW GOOD the plan is. What does it do well? What is missing or not detailed enough? Are the objectives SMART? Is there enough financial detail to secure a bank loan? Make a clear final judgement.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 9 marks (Levels of Response)</h5><ul><li><strong>Knowledge (1 mark AO1a):</strong> Purpose of a business plan (e.g. to gain finance, set objectives, identify markets, attract investors, develop strategy, manage cash flow)</li><li><strong>Understanding (1 mark AO1b):</strong> Identifies content or role of a business plan</li><li><strong>Application (2 marks AO2):</strong> Applies knowledge to Shirtz Ltd using specific case study detail (plan content, the pricing table, the expansion aims)</li><li><strong>Analysis (2 marks AO3a):</strong> Explains the effect/impact of the plan''s strengths or weaknesses on Shirtz Ltd</li><li><strong>Evaluation (3 marks AO3b):</strong> Judgement on overall effectiveness, with justification using case study context</li></ul></div>\n    <div class=\"marks-section\"><h5>Level Descriptors</h5><p><strong>Level 3 (7–9 marks):</strong> Good knowledge and understanding of business plans. Good application to Shirtz Ltd with detailed understanding of the scenario. Good analysis with logical chains of reasoning. Strong evaluation with a fully justified, contextual judgement.</p><p><strong>Level 2 (4–6 marks):</strong> Good knowledge and understanding. Good application to Shirtz Ltd. Limited analysis (some chains of cause and effect). Limited evaluation attempting a conclusion with some recognition of influencing factors.</p><p><strong>Level 1 (1–3 marks):</strong> Limited knowledge or understanding. Some use of scenario elements. Limited analysis (simple cause/consequence). No evaluation.</p></div>\n    <div class=\"marks-section\"><h5>Content Guidance</h5><p><strong>What the plan does well:</strong> Includes aims/objectives (grow, buy machinery, new location) | Identifies financial needs | Lists business/resource needs | Includes market research (pricing data table) | Covers marketing mix (4Ps) | Identifies human resource needs</p><p><strong>What the plan is missing or weak on:</strong> Objectives are not fully SMART (no specific timeline or measurable profit target) | Finance section lacks detail (how much? from where? loan? shares?) | No competitor analysis | No target market analysis | Market research is limited to pricing only | \"New finance will be required\" is too vague for a bank to act on</p></div>"}, {"question": "Explain the purpose of writing a business plan, such as that produced by Dunning Golf Club. [4 marks]", "marks": 4, "hint": "You need 2 separate reasons for writing a business plan, each applied to Dunning Golf Club. Structure: Define what a business plan is (1) → Explain what it contains (1) → Apply Reason 1 to Dunning (1) → Apply Reason 2 to Dunning (1).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 4 marks</h5><ul><li><strong>Knowledge (1 mark):</strong> Define what a business plan is</li><li><strong>Understanding (1 mark):</strong> Explain what it contains or its general purpose</li><li><strong>Application × 2 (2 marks):</strong> Two reasons applied specifically to Dunning Golf Club using the case study detail</li></ul></div>\n    <div class=\"marks-section\"><h5>Valid Purposes</h5><ul><li>Reduce the risk of failure</li><li>Help the business to be as successful as possible</li><li>Obtain external finance / investment</li><li>Set clear aims and objectives with a timeline</li><li>Identify resources needed</li><li>Identify competitors and how to beat them</li></ul></div>\n    <div class=\"marks-section\"><h5>Application to Dunning Golf Club</h5><ul><li>The plan outlines how to increase membership and profitability — clear objectives</li><li>Using outside caterers shows resource planning and cost management</li><li>Subsidised lessons for members = a strategy to attract and retain customers</li><li>Priorities for the future + how they will be financed = financial planning for investors/banks</li></ul></div>"}, {"question": "Evaluate the Dunning Golf Club business plan. [9 marks]", "marks": 9, "hint": "Judge whether the plan is good or whether it is missing anything important. Consider: Does it cover the key areas? Are the targets SMART (Specific, Measurable, Achievable, Realistic, Time-bound)? What could be improved? Make a clear final judgement.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 9 marks</h5><ul><li><strong>Knowledge (1 mark):</strong> Business plan is a document</li><li><strong>Understanding (1 mark):</strong> What it contains / its purpose</li><li><strong>Application (2 marks):</strong> Applied to Dunning Golf Club using the plan''s specific contents</li><li><strong>Analysis (2 marks):</strong> Benefits of the plan AND weaknesses/what is missing</li><li><strong>Evaluation (3 marks):</strong> Clear decision on whether the plan is good, with justification — particularly whether objectives are SMART</li></ul></div>\n    <div class=\"marks-section\"><h5>Analysis Guidance</h5><p><strong>Benefits:</strong> The plan has clear strategies (outside caterers, subsidised lessons, improved facilities) | It considers finance | It sets priorities for the future</p><p><strong>Weaknesses:</strong> Objectives are not fully SMART — no specific membership targets, no timeline, no measurable profit figure | No market research evidence | No competitor analysis | No detail on target market | Finance section says \"how these would be financed\" but gives no specific amounts</p></div>\n    <div class=\"marks-section\"><h5>Evaluation — SMART Objectives Test</h5><p>\"Increase membership and profitability\" is NOT SMART because: no specific number of new members is targeted, no profit figure is stated, no timeline is given. Examiners specifically note that candidates should assess whether targets are SMART and explain why.</p></div>"}, {"question": "Identify two elements of a business plan. [2 marks]", "marks": 2, "hint": "You simply need to name two things that would be found in any business plan. No explanation needed — this is a Knowledge question.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a — Knowledge)</h5><p>1 mark for each valid element of a business plan (up to a maximum of 2). No explanation is required.</p><p><strong>Valid Elements (any two):</strong></p><ul><li>The business idea</li><li>Market research</li><li>Objectives of the business</li><li>Target market</li><li>Competitors</li><li>Finance</li><li>Resources needed</li><li>Marketing plan / marketing mix</li><li>Details of the people running the business</li></ul></div>"}, {"question": "Evaluate which of the two identified elements would be more important in the development of Ira''s business. [7 marks]", "marks": 7, "hint": "Apply your two elements from Q10a to Ira''s specific situation. For each one, explain what the impact would be on her business. Then make a clear final decision about which is MORE important and justify it using case study detail.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks</h5><ul><li><strong>Application (2 marks AO2):</strong> Two points applying the identified elements to Ira''s specific business situation</li><li><strong>Analysis (2 marks AO3a):</strong> Explains the effect/impact of the two elements on Ira''s business</li><li><strong>Evaluation (3 marks AO3b):</strong> Judgement (1) + valid justification (1) + contextual justification using case study detail (1)</li></ul></div>\n    <div class=\"marks-section\"><h5>Application Guidance (Market Research + Competitors)</h5><p><strong>Market Research applied to Ira:</strong> Ira has not undertaken any market research for the new towns. She needs to understand whether people in those towns want Italian food, what price they will pay, and how the new restaurants should be positioned.</p><p><strong>Competitors applied to Ira:</strong> There are many competitors in the towns where she plans to open. Ira must understand who they are, what they offer, and how her home-style menu can attract customers away from established restaurants.</p></div>\n    <div class=\"marks-section\"><h5>Analysis Guidance</h5><p><strong>Market Research impact:</strong> Without market research, Ira may open restaurants that do not meet local demand → insufficient customers → unable to cover costs → business may fail in the new towns.</p><p><strong>Competitors impact:</strong> Established competitors already have loyal customers. If Ira cannot compete effectively on price or quality, she will not attract enough customers → insufficient revenue → may have to close new restaurants.</p></div>\n    <div class=\"marks-section\"><h5>Evaluation Guidance</h5><p>No right or wrong choice — marks awarded for the quality of justification.</p><ul><li><strong>1 mark:</strong> Clear decision on which element is more important</li><li><strong>2 marks:</strong> Decision + valid justification</li><li><strong>3 marks:</strong> Decision + specific contextual justification using case study detail</li></ul></div>"}]}}'::jsonb),
('business', '1-3-business-ownership', '1.3 Business Ownership', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>This unit covers the four main types of business ownership. Understanding the features, advantages, and disadvantages of each is essential for your exams.</p>\n<ul>\n<li><strong>Sole Trader:</strong> A business owned by one person. The most common form of business ownership in the UK. The owner can employ as many staff as they wish — ''sole'' refers to ownership, not working alone.</li>\n<li><strong>Partnership:</strong> A business owned by two or more people (minimum 2 partners). Common in professions such as law firms, accountancy practices, and dental practices.</li>\n<li><strong>Private Limited Company (Ltd):</strong> A company where shares can only be sold to family and friends with agreement of all existing shareholders. Has ''Ltd'' after its name.</li>\n<li><strong>Public Limited Company (plc):</strong> A large company whose shares are sold to the general public through the Stock Exchange. Has ''plc'' after its name. Requires a minimum of £50,000 share capital.</li>\n<li><strong>Limited Liability:</strong> The responsibility for the debts of a business is limited to the amount invested by a shareholder. Personal possessions are protected. A feature of private and public limited companies.</li>\n<li><strong>Unlimited Liability:</strong> The responsibility for all debts of a business rests with the owners personally. Personal possessions — including a home or car — may have to be sold to repay debts. A feature of sole traders and ordinary partnerships.</li>\n<li><strong>Deed of Partnership:</strong> A legal document setting out the operations of the partnership — the role of each partner, how profits and losses are shared, and how much capital each partner has contributed.</li>\n<li><strong>Shareholders:</strong> The owners of a private or public limited company. Each shareholder has invested money and owns a share of the business proportional to their investment.</li>\n<li><strong>Dividend:</strong> The money paid to a shareholder from the profits of a limited company. This is the reward for taking a financial risk by investing in the company.</li>\n<li><strong>Capital:</strong> Money raised to start or develop a business.</li>\n<li><strong>Sleeping Partner:</strong> A partner who invests capital into a partnership but takes no active part in running the business. Their liability is limited to the amount they contributed.</li>\n<li><strong>Limited Liability Partnership (LLP):</strong> A hybrid form where partners have limited liability for business debts, but must make their finances publicly available. Common among solicitors.</li>\n</ul>", "check": {"question": "What is distinctive about a Limited Liability Partnership (LLP)?", "options": ["It is a partnership where only one partner needs to invest capital", "It is another name for a private limited company", "Partners have limited liability but must publish finances", "Partners have unlimited liability but keep finances private"], "answer": 2, "explain": "An LLP is a hybrid form where partners get limited liability for business debts, but in exchange must make their finances publicly available, as stated in the Key Terms definitions."}}, {"title": "Sole Traders", "html": "<p>A <strong>sole trader</strong> is a business owned by one person. Despite the name, a sole trader <em>can</em> employ as many people as they wish — ''sole'' refers to sole ownership, not working alone. Sole traders are the most common form of business ownership in the UK.</p>\n<p>Common examples include plumbers, electricians, hairdressers, market traders, and freelance consultants.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages</div>\n<div class=\"pro-item\"><strong>Easy to set up:</strong> A sole trader is the easiest and cheapest form of ownership to establish. There are very few forms to complete, making it the most popular choice for start-up businesses.</div>\n<div class=\"pro-item\"><strong>Complete control:</strong> The sole trader makes all decisions without consulting anyone, allowing faster decision-making and full autonomy over the business.</div>\n<div class=\"pro-item\"><strong>Keeps all profits:</strong> Because there is only one owner, all profits belong to the sole trader alone — no obligation to share earnings.</div>\n<div class=\"pro-item\"><strong>Financial privacy:</strong> Unlike limited companies, a sole trader does not have to publish financial information. All accounts remain completely private.</div>\n<div class=\"pro-item\"><strong>Low start-up capital:</strong> A sole trader can be set up with very little money, making it accessible to entrepreneurs with limited savings.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages</div>\n<div class=\"con-item\"><strong>Unlimited liability:</strong> The sole trader is personally responsible for all business debts. If the business fails, personal possessions — including a home or car — may need to be sold to repay what is owed.</div>\n<div class=\"con-item\"><strong>Shortage of capital:</strong> With only one owner, raising money is difficult. Banks may be reluctant to lend, limiting the ability to start or expand.</div>\n<div class=\"con-item\"><strong>Long hours and stress:</strong> The sole trader must manage all aspects of the business alone, often working very long hours — especially when starting out. This can cause serious stress and illness.</div>\n<div class=\"con-item\"><strong>Skill shortage:</strong> The owner may lack specialist skills needed to run the business effectively, meaning staff with specific expertise may need to be hired at additional cost.</div>\n<div class=\"con-item\"><strong>No continuity:</strong> If the sole trader dies or becomes seriously ill, the business may cease to exist entirely or struggle to continue operating.</div>\n</div>\n</div>", "check": {"question": "According to the ''no continuity'' disadvantage, what typically happens if a sole trader dies or becomes seriously ill?", "options": ["The business automatically passes to the nearest employee", "Shares are transferred to another shareholder", "The business is legally required to become a partnership", "The business may cease to exist or struggle to continue"], "answer": 3, "explain": "The card notes that sole traders lack continuity — if the owner dies or becomes seriously ill, the business may cease to exist entirely or struggle to continue, unlike a limited company where shares can simply be transferred."}}, {"title": "Partnerships", "html": "<p>A <strong>partnership</strong> is a business owned by two or more people. There must be a minimum of two partners, but they do not need to have an equal share. Partnerships are very common in certain professions — solicitors, accountants, and dentists often operate as partnerships.</p>\n<p>Because a partnership is more complex than a sole trader, most draw up a <strong>deed of partnership</strong>. This legal document sets out:</p>\n<ul>\n<li>The role of each partner within the business.</li>\n<li>How profits and losses will be shared among the partners.</li>\n<li>How much capital each partner has contributed.</li>\n<li>Information on the way the business operates day-to-day.</li>\n</ul>\n<p>If there is no deed of partnership, the law states that each partner is <strong>equal</strong>, regardless of the amount of capital they invested.</p>\n<p>A <strong>sleeping partner</strong> provides capital but takes no part in running the business and has limited liability for losses up to the amount contributed.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages</div>\n<div class=\"pro-item\"><strong>More capital:</strong> With more than one owner, it is easier to raise capital to start or expand the business, as each partner can contribute savings.</div>\n<div class=\"pro-item\"><strong>Shared workload:</strong> Partners can divide work, reducing stress. If one partner is ill, others can cover — unlike a sole trader who has no one to rely on.</div>\n<div class=\"pro-item\"><strong>More skills:</strong> Different partners often bring complementary skills. A law firm may have partners specialising in different areas of law, improving quality and efficiency.</div>\n<div class=\"pro-item\"><strong>Easy to set up:</strong> Like a sole trader, a partnership is relatively easy and inexpensive to establish compared to a limited company.</div>\n<div class=\"pro-item\"><strong>Financial privacy:</strong> Like sole traders, partnerships do not have to share financial information with the public.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages</div>\n<div class=\"con-item\"><strong>Unlimited liability:</strong> Each partner is personally liable for all the business''s debts — including debts created by other partners. Personal possessions may be at serious risk.</div>\n<div class=\"con-item\"><strong>Profit is shared:</strong> Any profit made is split between the partners. This can cause serious conflict if one partner feels they contribute significantly more than others.</div>\n<div class=\"con-item\"><strong>Slower decision-making:</strong> With multiple partners involved, disagreements can arise, slowing decisions compared to a sole trader who acts alone.</div>\n<div class=\"con-item\"><strong>Shortage of capital:</strong> Even with multiple partners, the total capital available may be insufficient for major expansion projects.</div>\n<div class=\"con-item\"><strong>No continuity:</strong> If a partner dies, the partnership may legally have to be dissolved and reconstituted.</div>\n</div>\n</div>", "check": {"question": "If a partnership has no deed of partnership, how does the law say profits should be shared?", "options": ["The most senior partner decides how profits are split", "According to the number of hours each partner works", "In proportion to the capital each partner invested", "Equally between partners, regardless of capital invested"], "answer": 3, "explain": "The card states that without a deed of partnership, the law requires that each partner is treated as equal, regardless of how much capital they invested."}}, {"title": "Private Limited Companies (Ltd)", "html": "<p>A <strong>private limited company</strong> is identified by ''Ltd'' after its name. The owners are called <strong>shareholders</strong> because they each own a share of the business. A private limited company must have at least two shareholders.</p>\n<p>The defining feature of a private limited company is that <strong>shares can only be sold to family and friends</strong> — not to the general public. Any new shareholder must be agreed upon by all existing shareholders. This gives owners strong control, which is why many private limited companies are family businesses.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages</div>\n<div class=\"pro-item\"><strong>Limited liability:</strong> Shareholders are only responsible for debts up to the amount they invested in the business. Personal possessions are protected, which encourages people to invest.</div>\n<div class=\"pro-item\"><strong>Control over share sales:</strong> Shares can only be sold with agreement from existing shareholders, preventing unwanted takeovers. This is why many Ltd companies remain in family hands for generations.</div>\n<div class=\"pro-item\"><strong>Continuity:</strong> Unlike a sole trader or partnership, if a shareholder dies, the business continues. Shares are simply transferred to another person.</div>\n<div class=\"pro-item\"><strong>Easier to borrow:</strong> Banks are often more willing to lend to limited companies, viewing them as lower risk than sole traders or partnerships.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages</div>\n<div class=\"con-item\"><strong>Financial information is public:</strong> Unlike sole traders and partnerships, limited companies must submit accounts to the Registrar of Companies, which can be viewed by competitors and the general public.</div>\n<div class=\"con-item\"><strong>Complex and expensive to set up:</strong> There are significant legal requirements and administrative forms to complete, making it more costly and time-consuming to establish than a sole trader or partnership.</div>\n<div class=\"con-item\"><strong>Restricted share sales:</strong> Cannot sell shares to the general public, limiting the amount of capital that can be raised for major expansion.</div>\n<div class=\"con-item\"><strong>Dividends:</strong> Shareholders expect a share of profits (dividends). This can cause conflict when directors want to reinvest profits back into the business for growth.</div>\n</div>\n</div>", "check": {"question": "What is the defining feature of a private limited company (Ltd)?", "options": ["Shares can only be sold to family with agreement", "Shares are sold to the public on the Stock Exchange", "It must have a minimum of £50,000 share capital", "The business has no shareholders at all"], "answer": 0, "explain": "The card explains that the defining feature of an Ltd is that shares can only be sold to family and friends, and any new shareholder must be agreed by all existing shareholders."}}, {"title": "Public Limited Companies (plc)", "html": "<p>A <strong>public limited company</strong> is identified by ''plc'' after its name. The key difference from a private limited company is that a plc can sell its shares to the <strong>general public through the Stock Exchange</strong>. This makes it possible to raise very large amounts of capital — often millions of pounds. Well-known examples include J Sainsbury plc, Marks & Spencer plc, Next plc, Sky plc, and Burberry plc.</p>\n<p>A plc must have a minimum share capital of <strong>£50,000</strong>. This significant requirement means plcs are never used as start-up businesses.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages</div>\n<div class=\"pro-item\"><strong>Raise large amounts of capital:</strong> Shares can be sold to the general public and institutional investors (like pension funds), enabling vast sums to be raised for expansion — often into millions of pounds.</div>\n<div class=\"pro-item\"><strong>Easier to borrow:</strong> Banks see plcs as very low risk due to their size and public accountability, making it easier to secure large loans at competitive interest rates.</div>\n<div class=\"pro-item\"><strong>Limited liability for shareholders:</strong> As with a private limited company, shareholders only risk losing the amount they originally invested.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages</div>\n<div class=\"con-item\"><strong>Risk of hostile takeover:</strong> Since anyone can buy shares on the Stock Exchange, a rival company or investor group can buy 51% of shares and take control — without the original owners'' consent. This cannot happen with a private limited company.</div>\n<div class=\"con-item\"><strong>Expensive to set up:</strong> Becoming a plc requires significant legal processes, a minimum of £50,000 share capital, and ongoing compliance costs far exceeding those of a private limited company.</div>\n<div class=\"con-item\"><strong>Financial information fully public:</strong> All accounts must be published annually, giving competitors direct access to sensitive financial performance data. This can trigger other businesses to attempt a takeover.</div>\n<div class=\"con-item\"><strong>Problems of size:</strong> Large plcs often have complex management structures, which can make them inefficient and slow to adapt compared to smaller, more agile businesses.</div>\n</div>\n</div>", "check": {"question": "Why is a plc at risk of a hostile takeover in a way that a private limited company is not?", "options": ["Plc shares can only be sold to family members, so control can shift by inheritance", "Plcs are legally required to sell a majority stake to a rival business every ten years", "Anyone can buy shares on the Exchange, letting an investor acquire 51% and take control", "Plc directors are elected annually by the government"], "answer": 2, "explain": "The card explains that because plc shares are sold on the Stock Exchange to anyone, a rival or investor group can buy 51% of shares and take control without the original owners'' consent — something that cannot happen to a private limited company."}}, {"title": "Limited vs Unlimited Liability", "html": "<p><strong>Liability</strong> refers to the legal responsibility an owner has for the debts of their business. This is one of the most important concepts in the unit — and one of the most common sources of lost marks in the exam.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">🔒 Limited Liability</div>\n<div class=\"pro-item\"><strong>Who has it?</strong> Shareholders of private limited companies (Ltd) and public limited companies (plc). Also limited liability partnerships (LLP).</div>\n<div class=\"pro-item\"><strong>What does it mean?</strong> If the business cannot pay its debts, shareholders can only lose up to the amount they originally invested. Personal possessions — home, car, savings — are fully protected.</div>\n<div class=\"pro-item\"><strong>Why it matters:</strong> It encourages people to invest in a business, because the maximum they can lose is clearly defined. This makes it far easier for companies to raise capital.</div>\n</div>\n<div>\n<div class=\"col-head\">⚠️ Unlimited Liability</div>\n<div class=\"con-item\"><strong>Who has it?</strong> Sole traders and ordinary partners in a standard partnership.</div>\n<div class=\"con-item\"><strong>What does it mean?</strong> If the business cannot pay its debts, the owner is personally responsible for ALL debts — even if they exceed the value of the business itself. Personal possessions can be seized to repay creditors.</div>\n<div class=\"con-item\"><strong>Why it matters:</strong> A business failure does not just mean losing the business — it can mean losing personal wealth, savings, and even your home. This is a major deterrent to investment and growth.</div>\n</div>\n</div>\n<p><strong>Key Rule to Remember:</strong> Only <em>companies</em> (Ltd and plc) have limited liability. Sole traders and ordinary partnerships always have unlimited liability — unless they are structured as a limited liability partnership (LLP).</p>", "check": {"question": "According to the key rule on liability, which businesses have limited liability?", "options": ["Any business that has been trading for more than five years", "Only companies — Ltd and plc, both with limited liability", "Only businesses registered with the Stock Exchange", "All businesses that have more than one owner"], "answer": 1, "explain": "The card''s key rule states that only companies (Ltd and plc) have limited liability; sole traders and ordinary partnerships always have unlimited liability unless structured as an LLP."}}, {"title": "Suitability of Ownership in Different Contexts", "html": "<p>Choosing the right type of business ownership depends on the specific circumstances of the business. The key factors to consider are: <strong>amount of capital needed</strong>, <strong>level of financial risk</strong>, <strong>desire for control</strong>, and <strong>stage of the business</strong>.</p>\n<ul>\n<li><strong>Sole Trader — suitable for:</strong> Start-ups that need only a small amount of finance, have low financial risk, and where one person has sufficient skills to manage the business alone. Examples: a local plumber, a freelance photographer, a market trader.</li>\n<li><strong>Partnership — suitable for:</strong> Start-ups or established businesses that need more capital than a sole trader can raise, need a wider range of skills, and want to share the workload. Examples: a vet''s surgery (three newly qualified vets pooling resources), a dental practice, a small law firm.</li>\n<li><strong>Private Limited Company — suitable for:</strong> Businesses that need more finance, face higher financial risk (so limited liability is important to protect personal wealth), and want to keep control within a trusted group of shareholders. Often used by growing family businesses.</li>\n<li><strong>Public Limited Company — suitable for:</strong> Large, established businesses that need very large amounts of capital (into the millions) to expand — often overseas. Never suitable for start-ups due to the £50,000 minimum share capital requirement and high set-up costs. Examples: Marks & Spencer, Sainsbury''s, Next.</li>\n</ul>\n<p><strong>Start-ups:</strong> A new business will begin as a sole trader, partnership, or private limited company. A plc is never used for a start-up.</p>\n<p><strong>Established businesses growing:</strong> As a business grows and requires more capital, it may change ownership type — from sole trader to partnership, from partnership to Ltd, or from Ltd to plc. However, many successful businesses never change their ownership type if their current structure meets their needs.</p>", "check": {"question": "Why is a public limited company never suitable for a brand-new start-up business?", "options": ["Because it needs a £50,000 minimum and high set-up costs", "Because plcs are only allowed to sell products, not services", "Because a plc cannot operate in more than one location", "Because start-ups are legally banned from having shareholders"], "answer": 0, "explain": "The card explains that a plc is never suitable for a start-up because of the £50,000 minimum share capital requirement and high set-up costs — start-ups instead begin as sole traders, partnerships, or private limited companies."}}, {"title": "Real-World Case Study: Marks & Spencer", "html": "<div class=\"case-study-box\">\n<h4>Case Study: Marks & Spencer — A Journey Through All Four Ownership Types</h4>\n<p>Marks & Spencer is the perfect real-world example of a business that has evolved through all four types of business ownership:</p>\n<ul>\n<li><strong>1884 — Sole Trader:</strong> Michael Marks opened a \"penny bazaar\" stall in Leeds market, where every product cost one penny. He was the single owner with full control — and unlimited liability.</li>\n<li><strong>1894 — Partnership:</strong> Michael Marks partnered with Tom Spencer, who provided capital to fund expansion. The now-famous partnership of \"Marks & Spencer\" was born. Two owners; more capital; shared risk.</li>\n<li><strong>Early 20th Century — Private Limited Company (Ltd):</strong> As the business grew significantly, it incorporated as a private limited company. This provided limited liability for investors and enabled more structured capital-raising while keeping control within the company.</li>\n<li><strong>Early 20th Century — Public Limited Company (plc):</strong> Marks & Spencer eventually floated on the London Stock Exchange as a plc, raising the vast sums of capital needed to become one of the UK''s largest retailers, with hundreds of stores nationwide.</li>\n</ul>\n<p><strong>Takeaway:</strong> Each change in ownership type was driven by the need to raise more capital to support growth. This story perfectly illustrates that the choice of ownership is not permanent — it evolves as the business''s needs, ambitions, and financial requirements change over time.</p>\n</div>", "check": {"question": "What is the main takeaway from the Marks & Spencer case study about ownership types?", "options": ["Marks & Spencer has remained a sole trader throughout its history", "Partnerships always convert directly into plcs, skipping the Ltd stage", "Ownership type is not fixed — it evolves as capital needs grow", "A business must become a plc within its first ten years or it will fail"], "answer": 2, "explain": "The case study''s takeaway is that each change in Marks & Spencer''s ownership type was driven by the need to raise more capital to support growth, showing that ownership choice evolves over time rather than being permanent."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Sole Trader", "definition": "A business owned by one person. Has unlimited liability. Easiest and cheapest to set up. Keeps all profits. Financial information is private. Can employ staff."}, {"term": "Partnership", "definition": "A business owned by 2 or more people. Has unlimited liability. Shares workload, capital, and skills. Partners share profits. Should have a deed of partnership."}, {"term": "Private Limited Company (Ltd)", "definition": "Company owned by shareholders with limited liability. Shares sold only to family/friends with agreement. Cannot sell on Stock Exchange. More complex to set up than sole trader/partnership."}, {"term": "Public Limited Company (plc)", "definition": "Company whose shares are sold on the Stock Exchange. Limited liability. Minimum £50,000 share capital. Risk of hostile takeover. Must publish annual accounts. Not for start-ups."}, {"term": "Limited Liability", "definition": "Owners can only lose the amount they invested. Personal possessions — home, car, savings — are protected from business debts. Applies to Ltd and plc only."}, {"term": "Unlimited Liability", "definition": "Owners are personally responsible for ALL business debts. Personal possessions can be seized to repay debts. Applies to sole traders and ordinary partnerships."}, {"term": "Deed of Partnership", "definition": "A legal document setting out each partner''s role, capital invested, and how profits/losses are shared. Without it, all partners are legally equal regardless of contribution."}, {"term": "Shareholders", "definition": "The owners of a limited company (Ltd or plc). Each owns a share of the business proportional to their investment. They are NOT called partners."}, {"term": "Dividend", "definition": "A payment made to shareholders from company profits. The financial reward shareholders receive for investing their money (and accepting the associated risk)."}, {"term": "Sleeping Partner", "definition": "A partner who invests capital in a partnership but takes no active role in running it. Their personal liability is limited to the amount they contributed."}, {"term": "Capital", "definition": "Money raised to start or develop a business. Different ownership types have very different abilities to raise capital — from personal savings (sole trader) to millions on the Stock Exchange (plc)."}, {"term": "Stock Exchange", "definition": "The market (London Stock Exchange in the UK) where shares in public limited companies are bought and sold by the general public and institutional investors."}, {"term": "The main reason to become a plc", "definition": "To raise very large amounts of capital by selling shares to the general public on the Stock Exchange — often tens or hundreds of millions of pounds for major expansion."}, {"term": "The main risk of being a plc", "definition": "Hostile takeover. Anyone can buy shares on the Stock Exchange. If any person or group buys 51% of shares, they gain control of the entire business — without the original owners'' consent."}, {"term": "Why stay as an Ltd instead of becoming a plc?", "definition": "To maintain control over who owns shares (preventing hostile takeovers), keep financial information more private, avoid the high costs of being a plc, and retain family/founder control of the business."}]}, "fib": {"enabled": true, "questions": [{"text": "A [sole] trader is a business owned by one person and has [unlimited] liability for all business debts."}, {"text": "A partnership must have a minimum of [two] partners and they usually draw up a [deed] of partnership."}, {"text": "A private limited company has ''Ltd'' after its name and can only sell shares to family and [friends], unlike a [plc] which sells shares on the Stock Exchange."}, {"text": "Limited liability means that the owner can only lose the amount they [invested] in the business, protecting their [personal] possessions."}, {"text": "A [sleeping] partner invests money in a partnership but takes no part in the running of the business."}, {"text": "A public limited company must have a minimum of £[50,000] in share capital and its shares are sold on the [Stock Exchange]."}, {"text": "A [deed] of partnership sets out the duties of the partners and the amount of [capital] they put into the business."}, {"text": "Sole traders and standard partnerships have [unlimited] liability, meaning personal [possessions] may be sold to pay business debts."}, {"text": "The owners of a limited company are called [shareholders] and they receive a share of profits called a [dividend]."}, {"text": "A sole trader keeps all the [profits] and makes all [decisions] without consulting anyone, giving complete control."}, {"text": "Private and public limited companies must make their [financial] information available to the public, unlike sole traders who keep it [private]."}, {"text": "A new business would not start as a [public] limited company because it requires at least £[50,000] in share capital as a minimum."}, {"text": "If a sole trader or partner cannot pay business debts, they may have to sell [personal] possessions because they have [unlimited] liability."}]}, "misc": {"enabled": true, "items": [{"myth": "A sole trader means the owner works alone and cannot have employees.", "truth": "A sole trader simply means ONE OWNER. The word ''sole'' refers to ownership, not working alone. A sole trader can employ as many staff as they need and can afford. Many successful sole traders run large operations with many employees.", "check": {"question": "What does the term ''sole trader'' actually refer to?", "options": ["A trader who only sells goods, not services", "Sole ownership, not necessarily working alone", "A business owned equally by two people", "A business with no employees at all"], "answer": 1, "explain": "The card corrects the common misconception that ''sole'' means working alone — it actually refers to sole ownership; a sole trader can employ as many staff as they can afford."}}, {"myth": "A ''public'' limited company means it is owned by the government or the public sector.", "truth": "''Public'' means the shares are available for the public to BUY on the Stock Exchange. It has nothing to do with government ownership. The public sector is a completely different concept and is NOT on the OCR GCSE Business specification.", "check": {"question": "What does ''public'' mean in the term ''public limited company''?", "options": ["The company is owned and run by the government", "The company must be based in a public building", "The company is part of the public sector", "Its shares can be bought by the general public"], "answer": 3, "explain": "The card clarifies that ''public'' refers to shares being available for the public to buy on the Stock Exchange, not government ownership — the public sector is a different concept not on the specification."}}, {"myth": "Any business can be called a ''company''.", "truth": "The word ''company'' specifically and legally refers to private limited companies (Ltd) or public limited companies (plc). A sole trader or partnership is a ''business'', not a ''company''. Using ''company'' for a sole trader in an exam answer can make your answer inaccurate and cost marks.", "check": {"question": "In business terminology, which businesses can accurately be called a ''company''?", "options": ["Only businesses with more than 50 employees", "Any business, including sole traders and partnerships", "Only limited companies — Ltd and plc businesses", "Only businesses that trade internationally"], "answer": 2, "explain": "The card explains that ''company'' is a legally specific term referring only to Ltd and plc businesses — calling a sole trader or partnership a ''company'' in an exam answer is inaccurate and can cost marks."}}, {"myth": "Limited liability means the business has limited debt or cannot borrow much.", "truth": "Limited liability refers to the OWNER''S PERSONAL responsibility for debt — not the amount of debt the business can have. It means the owner can only lose up to the amount they invested in the business, protecting their personal possessions.", "check": {"question": "What does ''limited liability'' actually refer to?", "options": ["The owner''s personal financial responsibility for business debts", "The number of years a business can operate before repaying debts", "A limit on how much a business can borrow from a bank", "The maximum amount of debt a business is allowed to have"], "answer": 0, "explain": "The card corrects the misconception that limited liability limits business debt — it actually limits the owner''s PERSONAL responsibility, meaning they can only lose up to what they invested."}}, {"myth": "Partners in a partnership always share profits equally.", "truth": "Partners do NOT have to share profits equally. The deed of partnership sets out exactly how profits (and losses) are shared, which can be in any proportion the partners agree on. ONLY if there is NO deed of partnership does the law require equal sharing.", "check": {"question": "How are profits shared between partners in a partnership?", "options": ["As set out in the deed of partnership, or equally if none", "Always decided by an external accountant", "Always equally, regardless of any agreement", "Always in proportion to the number of hours each one worked"], "answer": 0, "explain": "The card explains that partners do not have to share profits equally — the deed of partnership sets out the agreed split, and equal sharing is only the legal default when no deed exists."}}, {"myth": "A sleeping partner runs the business while the other partner takes a rest.", "truth": "A sleeping partner provides CAPITAL but takes NO PART in running the business. The word ''sleeping'' refers to their passive management role — they are a financial investor only, not an active manager.", "check": {"question": "What role does a ''sleeping partner'' play in a partnership?", "options": ["They are a partner who has retired but still receives a salary", "They manage the business day-to-day while other partners rest", "They provide the capital but take no active role in running it", "They are legally banned from investing any capital"], "answer": 2, "explain": "The card clarifies that ''sleeping'' refers to a passive management role — a sleeping partner is a financial investor only, not someone who manages the business."}}, {"myth": "A private limited company and a public limited company are basically the same thing — just different sizes.", "truth": "They are fundamentally different. Key differences: (1) a plc can sell shares on the Stock Exchange, an Ltd cannot; (2) a plc needs £50,000 minimum share capital; (3) a plc can be taken over by hostile buyers, an Ltd cannot without shareholder consent; (4) a plc faces more public scrutiny of its finances.", "check": {"question": "Which of the following is a fundamental legal difference between a private limited company and a public limited company?", "options": ["An Ltd requires more share capital to set up than a plc", "An Ltd is legally required to publish full annual accounts, but a plc is not", "Only a plc has shareholders", "A plc can sell shares on the Stock Exchange, whereas an Ltd cannot"], "answer": 3, "explain": "The card lists key differences including that a plc can sell shares on the Stock Exchange while an Ltd cannot, showing they are fundamentally different structures, not just different sizes of the same thing."}}, {"myth": "When answering about disadvantages of a limited company, it is fine to say ''it is expensive'' or ''there is a lot of paperwork''.", "truth": "These are too vague for the examiner. You must state specifically WHAT is expensive and WHY, and explain the business-facing impact. For example: ''The requirement to submit detailed accounts to Companies House (U) means Tom and Amir spend time on administration (APP) that could be used for customer service — their priority (AN).''", "check": {"question": "According to exam guidance, why is stating ''it is expensive'' as a disadvantage of a limited company insufficient for marks?", "options": ["It is too vague — say specifically what is expensive and why", "Because examiners only accept numerical answers", "Because ''expensive'' is a banned word in GCSE Business exams", "Because expense is never actually a disadvantage of limited companies"], "answer": 0, "explain": "The card warns that vague answers score no marks — you must specify exactly what is expensive or involves paperwork, and explain the business-facing impact, as in the Companies House example given."}}, {"myth": "Once a business becomes a plc, it must remain a plc permanently.", "truth": "Some businesses that became plcs have chosen to return to being private limited companies (''going private''). This can happen when owners want to regain control, protect themselves from hostile takeovers, or reduce the costs and public scrutiny associated with being a plc.", "check": {"question": "Can a public limited company change back to being a private limited company?", "options": ["No — a plc can only convert into a sole trader", "No — once a plc, it must remain a plc permanently", "Yes, but only if ordered to by the Stock Exchange", "Yes — some plcs choose to ''go private'' to cut costs"], "answer": 3, "explain": "The card corrects the misconception that plc status is permanent — some businesses ''go private'' again to regain control, avoid hostile takeovers, or cut the costs and scrutiny of being a plc."}}, {"myth": "Unlimited liability is always a serious problem for sole traders and partners.", "truth": "Unlimited liability is only a practical problem if the business fails and cannot pay its debts. Many successful sole traders and partners never face this issue during their careers. However, the RISK is always present — which is why limited liability is so attractive for businesses with significant financial exposure.", "check": {"question": "When does unlimited liability actually become a practical problem for a sole trader or partner?", "options": ["Only when the business first starts up", "Only if the business fails and cannot pay its debts", "Only if the business employs more than ten staff", "Every single day the business is trading"], "answer": 1, "explain": "The card explains that unlimited liability is only a practical problem if the business fails and cannot pay its debts — many successful owners never face this issue, though the risk is always present."}}]}, "tips": {"enabled": true, "items": [{"title": "Two Marks = One Point + One Development", "html": "\n      <p>A 2-mark <strong>''Explain''</strong> question needs exactly two things: a <strong>point</strong> and a <strong>development</strong>. Do not write a paragraph.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Mark 1 (K):</strong> State the fact or concept clearly and correctly.</li>\n        <li><strong>Mark 2 (U):</strong> Develop it — explain what it means in practice or what the consequence is.</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n      <em>\"Limited liability means the owner doesn''t have to pay all the debts.\"</em><br/>\n      Too vague — no development of what this actually means for the owner.</p>\n\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"With limited liability, shareholders can only lose up to the amount they originally invested in the company (K), meaning their personal possessions — such as their home — cannot be seized to repay business debts (U).\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> The most common error on this question type is <strong>confusing limited liability with unlimited liability</strong> — describing owners'' possessions being TAKEN when explaining limited liability. This scores ZERO even if the rest of the answer appears correct. Always double-check your definition.</p>\n\n      <p><strong>🚫 The ''Explain'' Trap:</strong> The question says ''explain'', not ''identify''. If you just state \"limited liability means the owner is not responsible for all the debts\" without explaining what this means in practice, you will only score 1 mark, not 2.</p>\n    ", "check": {"question": "What must a 2-mark ''Explain'' answer contain to achieve full marks?", "options": ["A conclusion stating the overall judgement", "A correct point (K) plus its development (U)", "Three separate advantages, briefly listed", "A definition followed by a real-world example only"], "answer": 1, "explain": "The card''s formula for a 2-mark Explain question is one point (K) plus one development (U) — writing a full paragraph or just stating a fact without development will not achieve both marks."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n      <p>A 3-mark <strong>''Analyse''</strong> question requires all three assessment objectives in a logical chain. You will score <strong>ZERO for analysis</strong> if you do not apply it to the specific business in the case study.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State and explain the benefit or disadvantage clearly.<br/><em>e.g. \"Limited liability means shareholders only risk losing the amount they invested...\"</em></li>\n        <li><strong>Step 2 — Application (APP):</strong> Link directly to the case study business. Use their name and refer to specific details from the text.<br/><em>e.g. \"...which is important for Pen &amp; Sword Books, a family-owned business expanding into audio books...\"</em></li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the bottom-line impact on the business — costs, revenue, growth, survival, or competitiveness.<br/><em>e.g. \"...meaning the family can invest confidently knowing they cannot lose more than their original stake, supporting the digital expansion.\"</em></li>\n      </ul>\n\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write everything you know about sole traders or partnerships. If the question asks for one advantage, give ONE advantage and develop it fully through all three steps. Three half-developed points score far fewer marks than one fully developed chain.</p>\n\n      <p><strong>The ''So What?'' Test for Analysis:</strong> Keep asking \"So what?\" until you reach a real business impact:</p>\n      <ul>\n        <li>\"Partnerships can raise more capital.\" → <em>So what?</em></li>\n        <li>\"This means the business has more money to invest.\" → <em>So what?</em></li>\n        <li>\"This increases the chances of the business surviving start-up and growing.\" ✅ AN mark earned.</li>\n      </ul>\n    ", "check": {"question": "What three elements must a 3-mark ''Analyse'' answer include to avoid scoring zero for analysis?", "options": ["Understanding, Application, and Analysis of impact", "A definition, a diagram, and a conclusion", "Three different advantages listed one after another", "Two advantages and one disadvantage"], "answer": 0, "explain": "The card''s ''Holy Trinity'' formula requires Understanding (U), Application to the specific case study business (APP), and Analysis of the bottom-line impact (AN) — without application to the named business, you score zero for analysis."}}, {"title": "6 Marks = Two Separate 3-Mark Chains", "html": "\n      <p>A 6-mark question asking you to <strong>''Analyse two...''</strong> is simply the 3-mark U → APP → AN formula done <strong>twice</strong>.</p>\n      <p><strong>Key Rules:</strong></p>\n      <ul>\n        <li>Clearly separate each point: label them <em>\"Disadvantage 1...\"</em> and <em>\"Disadvantage 2...\"</em></li>\n        <li><strong>Do NOT write a conclusion</strong> — there are zero evaluation marks available in a 6-mark question. A conclusion wastes time.</li>\n        <li>Make sure both points are genuinely different — do not repeat the same idea in different words.</li>\n        <li>Both points must still be applied to the specific business in the case study to earn APP marks.</li>\n        <li><strong>The answer must relate to the legal status</strong> of the ownership type — not just general features of being a large or small business.</li>\n      </ul>\n\n      <p><strong>⚠️ Examiner Warning:</strong> Examiners reported that responses were \"often inaccurate or too vague\" on this question type. Vague answers like \"it costs more money\" or \"there is more paperwork\" will not score without specifying WHAT costs more money, WHY, and what the IMPACT is on the business.</p>\n\n      <p><strong>❌ Vague (scores 0-1 marks):</strong><br/>\n      <em>\"A disadvantage is that it costs a lot of money to run.\"</em></p>\n\n      <p><strong>✅ Full marks chain:</strong><br/>\n      <em>\"Shares in Shinz Ltd cannot be sold on the stock market (U). Even though Tom and Amir want to expand by launching a resin polish service (APP), this restriction limits the capital they can raise, potentially delaying their planned growth into this new market (AN).\"</em></p>\n    ", "check": {"question": "According to the card, what should you NOT include in a 6-mark ''Analyse two...'' answer?", "options": ["Two separate, clearly labelled points", "An application to the case study business", "A development of each point", "A conclusion — no marks are available for it"], "answer": 3, "explain": "The card states that a 6-mark ''Analyse two'' question has zero evaluation marks available, so writing a conclusion wastes time — instead you need two clearly separated U-APP-AN chains."}}, {"title": "Structure Your Essay in 4 Clear Paragraphs", "html": "\n      <p>A 9-mark <strong>''Evaluate''</strong> question tests ALL five assessment objectives. You need a structured response with <strong>four clear paragraphs</strong>. The examiner is looking for a <strong>justified judgement</strong> — not just a list of advantages and disadvantages.</p>\n\n      <p><strong>The 4-Paragraph Structure:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — K &amp; U:</strong> Define the key concept (e.g. what a sole trader is) and explain a relevant feature with its implication.</li>\n        <li><strong>Paragraph 2 — AN &amp; APP:</strong> Analyse a reason FOR the ownership type being suitable, using data and evidence from the case study.</li>\n        <li><strong>Paragraph 3 — AN &amp; APP:</strong> Analyse a reason AGAINST the ownership type being suitable, using data and evidence.</li>\n        <li><strong>Paragraph 4 — 3 Evaluation Points:</strong>\n          <ol>\n            <li>State your clear decision.</li>\n            <li>Contextualise it with specific data or facts from the case study.</li>\n            <li>Add a conditional point: \"However, this depends on whether...\"</li>\n          </ol>\n        </li>\n      </ul>\n\n      <p><strong>Sentence Starters for the Evaluation Paragraph:</strong></p>\n      <ul>\n        <li><em>\"Overall, I recommend that [business] should [decision] because...\"</em></li>\n        <li><em>\"Given that the data shows [specific figure or fact from the case study]...\"</em></li>\n        <li><em>\"However, this recommendation depends on whether [condition e.g. can secure a loan / find a suitable partner]...\"</em></li>\n      </ul>\n\n      <p><strong>⚠️ Examiner Warning:</strong> A conclusion that simply repeats your earlier analysis scores NO evaluation marks. You must make a judgement and justify it using specific case study context. The examiner''s report states evaluation must be <em>\"contextually robust\"</em> for the full 3 marks.</p>\n    ", "check": {"question": "In the 4-paragraph structure for a 9-mark ''Evaluate'' question, what must the final evaluation paragraph include to earn evaluation marks?", "options": ["A simple summary of the advantages and disadvantages already covered", "A clear decision, contextualised with case study data", "Three additional advantages not mentioned earlier", "A dictionary definition of the key term"], "answer": 1, "explain": "The card explains the evaluation paragraph needs three things: a clear decision, contextualisation with specific data/facts, and a conditional point — a conclusion that just repeats earlier analysis scores no evaluation marks."}}, {"title": "Judgement + Comparison = Full Marks", "html": "\n      <p>A 3-mark <strong>''Recommend''</strong> question requires three things: a <strong>clear decision</strong>, a <strong>reason for your choice</strong>, and a <strong>comparison with the alternative</strong>. You MUST address both options to earn the full justification marks.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Mark 1 (Judgement):</strong> State your recommendation clearly. <em>e.g. \"Joe should become a sole trader.\"</em></li>\n        <li><strong>Marks 2–3 (Contextual Justification):</strong> Explain WHY your choice is BETTER THAN the other option, using specific details from the case study.</li>\n      </ul>\n\n      <p><strong>⚠️ Examiner Warning:</strong> If you only explain why your chosen option is good WITHOUT explaining why it is better than the other option, you can only score a maximum of 1 justification mark. You MUST compare both options explicitly.</p>\n\n      <p><strong>✅ Model Starter:</strong><br/>\n      <em>\"Joe should become a sole trader (JUDGEMENT). Although a partnership with Mark would provide additional capital (acknowledge the other option), Joe already has £1,000 covering his first month''s costs, meaning he does not need Mark''s investment. As a sole trader, Joe keeps all profits and makes decisions without needing Mark''s agreement, allowing the barbers shop to respond quickly to customer demand (CONTEXTUAL JUSTIFICATION).\"</em></p>\n    ", "check": {"question": "What is required to earn full justification marks on a 3-mark ''Recommend'' question?", "options": ["Simply stating your decision without giving any reason", "Repeating the case study word for word", "Listing every possible ownership type available", "Explaining why your choice beats the alternative option"], "answer": 3, "explain": "The card warns that if you only explain why your chosen option is good without comparing it to the other option, you can score a maximum of 1 justification mark — you must explicitly compare both options."}}]}, "exam": {"enabled": true, "questions": [{"question": "Explain one way that limited liability affects the owners of a company. [2 marks]", "marks": 2, "hint": "Think about what happens if the company gets into debt — what is the owner personally responsible for, and what are they protected from? You need a point AND a development.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a: 1 mark, AO1b: 1 mark)</h5>\n<ul>\n<li><strong>Knowledge (1 mark):</strong> A correct statement about limited liability, e.g.:\n<ul>\n<li>Owners/shareholders can only lose up to the amount originally invested</li>\n<li>Shareholders are not required to repay the company''s debts personally</li>\n<li>The owner''s personal assets are protected / cannot be taken from them</li>\n<li>Due to separate legal identity / incorporation</li>\n<li>Less stress/worry/risk / more financial security for shareholders</li>\n<li>Shareholders may be willing to take more risks</li>\n</ul>\n</li>\n<li><strong>Understanding/Development (1 mark):</strong> An explanation of the consequence, e.g.:\n<ul>\n<li>So their personal belongings cannot be taken to repay debts</li>\n<li>Which means they might be willing to take more financial risks</li>\n<li>Meaning they cannot lose more money than they put in</li>\n</ul>\n</li>\n</ul>\n<p><em>Note: Answers do not need to relate to Sainsbury''s.</em></p>\n<p><strong>Examiner''s Comment:</strong> Many candidates gained at least one mark. The most common correct responses related to protection of personal assets. Candidates who confused limited liability with unlimited liability (describing possessions being taken away to repay debts) scored zero. The question said ''explain'' — some development beyond a simple definition was required for the second mark.</p>\n<p><strong>Exemplar responses:</strong><br>\n\"Owners cannot lose more than the amount originally invested (1) so their personal belongings cannot be taken to repay debts (+1).\"<br>\n\"A shareholder''s liability for debts is limited (1) which means that they might be willing to take more risks (+1).\"</p></div>"}, {"question": "What is a disadvantage of being a sole trader?", "marks": 1, "hint": "Think about what ''sole'' actually means — and what that limits the owner from doing.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Cannot share business ownership</h5>\n<p><strong>Why B is correct:</strong> By definition, a sole trader has one owner. This limits the ability to raise capital and means all risks and responsibilities fall entirely on one person.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Wrong:</strong> Sole traders CAN employ more than one person. ''Sole'' means one owner, not one worker.</li>\n<li><strong>C — Wrong:</strong> There is no legal requirement for a sole trader to produce a business plan.</li>\n<li><strong>D — Wrong:</strong> Sole traders pay Income Tax on their profits, not corporation tax. Corporation tax is paid by limited companies only.</li>\n</ul></div>"}, {"question": "Limited liability protects:", "marks": 1, "hint": "Limited liability is about protecting one specific group of people from losing personal wealth when a company cannot pay its debts.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Business owners</h5>\n<p><strong>Why A is correct:</strong> Limited liability is a legal protection for the owners (shareholders) of a company. It limits their personal financial responsibility to the amount originally invested.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>B — Wrong:</strong> Customers are protected by consumer law, not limited liability.</li>\n<li><strong>C — Wrong:</strong> Suppliers are creditors — if a company cannot pay its debts, suppliers may actually lose out financially. Limited liability does not protect them.</li>\n<li><strong>D — Wrong:</strong> The local community has no protection from limited liability.</li>\n</ul></div>"}, {"question": "Which type of ownership is most suitable for an entrepreneur who wishes to start up their own business quickly and with as little paperwork as possible?", "marks": 1, "hint": "Which type of ownership has the fewest legal requirements to set up?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Sole trader</h5>\n<p><strong>Why D is correct:</strong> A sole trader is the simplest and quickest form of business to establish, with minimal legal requirements. No registration with Companies House is required.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Wrong:</strong> A partnership ideally requires a deed of partnership — adding legal time and cost.</li>\n<li><strong>B — Wrong:</strong> A private limited company must register with Companies House, complete articles of association, and pay registration fees. More complex and time-consuming than a sole trader.</li>\n<li><strong>C — Wrong:</strong> A public limited company has the most demanding legal requirements of all, including a minimum of £50,000 in share capital and full stock exchange listing processes. Completely unsuitable for a quick start-up.</li>\n</ul>\n<p><strong>Examiner''s Comment:</strong> Incorrect answers were fairly evenly spread across all three distractors, suggesting a lack of robust understanding across the ability range.</p></div>"}, {"question": "Analyse two disadvantages for Shinz Ltd of operating as a private limited company. [6 marks]", "marks": 6, "hint": "Each disadvantage must come from the LEGAL STRUCTURE of being a private limited company — not from being a business in general. Think specifically about: restricted share sales, financial disclosure requirements, dividends, or administrative burden.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 6 marks (AO1b: 2, AO2: 2, AO3a: 2)</h5>\n<ul>\n<li><strong>Understanding (up to 2 marks):</strong> One mark per disadvantage of operating as a private limited company, e.g.:\n<ul>\n<li>Financial information available to competitors / general public</li>\n<li>Lots of complex paperwork / regulations to set up / run the firm</li>\n<li>Sale of shares restricted — only with agreement of other shareholders, only to family and friends, not quoted on the stock market</li>\n<li>Dividends need to be paid to shareholders</li>\n<li>Potential conflict between shareholders (ownership) and directors (control)</li>\n</ul>\n</li>\n<li><strong>Application (up to 2 marks):</strong> One mark per application to Shinz Ltd using evidence from the text, e.g.:\n<ul>\n<li>Owned by two brothers planning to expand</li>\n<li>Launching a new ''resin polish'' service requiring capital</li>\n<li>Three local competitors who could view financial information</li>\n</ul>\n</li>\n<li><strong>Analysis (up to 2 marks):</strong> One mark per business-facing impact, e.g.:\n<ul>\n<li>Lack of finance may limit the business'' expansion into resin polish</li>\n<li>Owners may struggle to find time for paperwork, limiting time given to customer service</li>\n<li>Competitors could use financial data to undercut Shinz Ltd''s pricing</li>\n</ul>\n</li>\n</ul>\n<p><strong>Important Guidance:</strong></p>\n<ul>\n<li>No further marks can be gained without the Understanding mark first.</li>\n<li>Analysis must be a business-facing impact — not a disadvantage to customers, workers, or owners personally.</li>\n<li>Do NOT award vague answers like \"less privacy\" or \"expensive to set up\" unless the specific reason is given.</li>\n<li>Do NOT award answers relating to business size e.g. large so decision-making is slower — answer must relate to legal status.</li>\n</ul>\n<p><strong>Exemplar responses:</strong><br>\n\"Shinz Ltd''s shares are not available to the general public (1). So, even after five years (APP) a lack of finance may limit the business'' expansion (+1).\"<br><br>\n\"Private limited companies have to submit financial forms disclosing information (1). The two owners (APP) may struggle to find time to complete the paperwork, restricting the time given to customer service (+1).\"</p>\n<p><strong>Examiner''s Comment:</strong> Responses were often inaccurate or too vague. Examiners were looking for a chain of logical reasoning culminating in a negative impact on Shinz Ltd. A significant proportion of candidates left this space entirely blank.</p></div>"}, {"question": "Evaluate, with reference to the data in Text 3, whether operating as a sole trader is the best type of business ownership for Miles Ahead in the future. [9 marks]", "marks": 9, "hint": "You MUST use specific data from the charts in your answer (sales figures, customer satisfaction percentages). Consider both the arguments FOR and AGAINST remaining as a sole trader for Nessa specifically. Then make a clear, justified recommendation.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 9 marks (AO1a: 1, AO1b: 1, AO2: 2, AO3a: 2, AO3b: 3)</h5>\n<p><em>Use the level of response marking grid to assess skill levels.</em></p>\n<ul>\n<li><strong>Knowledge (1 mark):</strong> e.g. One owner / sole trader has one owner.</li>\n<li><strong>Understanding (1 mark):</strong> e.g. Unlimited liability / owner liable for all debts / limited capital-raising opportunities / must work long hours / no one to share decision-making / all profits kept / complete control.</li>\n<li><strong>Application — quantitative/graphical (up to 2 marks):</strong> Any correct interpretation of Fig. 2 (e.g. sales revenue has fallen in the last 2 years / approximately 30% decrease in sales revenue since 2018) OR Fig. 3 (e.g. customers becoming more dissatisfied / in 2020 approximately 50% of customers were not satisfied).</li>\n<li><strong>Analysis (up to 2 marks):</strong> The business-facing impact/consequence of any correct understanding about being a sole trader, e.g.:\n<ul>\n<li>May be unable to raise the necessary capital to modernise stores or set up the website</li>\n<li>High risk of personal financial loss — damage to Nessa''s personal wealth</li>\n<li>Lack of expertise in bicycle retail / online sales may cause any expansion venture to fail</li>\n</ul>\n</li>\n<li><strong>Evaluation (up to 3 marks):</strong> Candidate may justify remaining as a sole trader, not remaining as a sole trader, or switching to another ownership type (e.g. partnership, Ltd). For full 3 marks, the evaluation must be <strong>contextually robust</strong> — using specific details and data from the case study.</li>\n</ul>\n<p><strong>Examiner''s Model Answer:</strong><br>\nA sole trader is a business owned by one individual (K) with limited capital-raising opportunities (U). Miles Ahead has had a near 20% decrease in sales revenue in the last couple of years (APP) and nearly 50% of customers are not satisfied (APP) according to the latest survey data. Nessa wants to improve the appearance of the stores, but clearly does not have available funds as she has already had to borrow £500,000. Getting more funds will be difficult as a sole trader and may delay the set up of the website (AN). Nessa will also want additional help and advice, but her knowledge is limited to the jewellery market. This lack of knowledge may lead to any bicycle retail venture online failing (AN).<br><br>\nI therefore think that Nessa would be wise to take on a business partner, rather than stay as a sole trader (EVAL). Although this will dilute Nessa''s ownership, she will be able to find someone with the necessary experience to help overcome a customer satisfaction score where barely half the customers are satisfied (EVAL + contextual robustness).</p></div>"}, {"question": "Explain the concept of limited liability. [2 marks]", "marks": 2, "hint": "First state WHAT limited liability is (the definition), then explain WHAT IT MEANS for the owner in practice if the business gets into debt.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a: 1, AO1b: 1)</h5>\n<ul>\n<li><strong>Knowledge (1 mark):</strong> e.g.:\n<ul>\n<li>Owners''/shareholders'' responsibility for the debts of the business is limited to the amount they originally invested</li>\n<li>Applies to shareholders of limited companies (Ltd and plc)</li>\n<li>Business is responsible for paying its own debts — it has a separate legal identity from its owners</li>\n</ul>\n</li>\n<li><strong>Understanding (1 mark):</strong> e.g.:\n<ul>\n<li>Owners cannot lose any more money/personal possessions beyond their original investment</li>\n<li>Personal assets such as a home cannot be taken to repay company debts</li>\n</ul>\n</li>\n</ul>\n<p><em>Note: No case study context is required for this question.</em></p>\n<p><strong>Exemplar response:</strong><br>\n\"Limited liability is a legal protection for the owners/shareholders of a company (1). It means they cannot lose more money than they originally invested in the company (1).\"</p></div>"}, {"question": "Which of the following types of ownership is most suitable for an established business that needs to raise a large amount of capital to expand overseas?", "marks": 1, "hint": "Which type of ownership allows shares to be sold to the general public, enabling the very largest capital raises?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Public limited company</h5>\n<p><strong>Why C is correct:</strong> A plc can sell shares on the Stock Exchange to the general public and institutional investors, raising millions of pounds. This is the only realistic way to fund very large-scale overseas expansion.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Wrong:</strong> A partnership can raise more capital than a sole trader, but is still limited to the personal wealth of the partners — insufficient for major overseas expansion.</li>\n<li><strong>B — Wrong:</strong> A private limited company can only sell shares to family and friends, restricting the total capital that can be raised.</li>\n<li><strong>D — Wrong:</strong> A sole trader has only one owner providing capital — the most limited form of capital-raising of all.</li>\n</ul></div>"}, {"question": "Analyse two benefits for Rory and Jayda of setting up the business as a partnership. [6 marks]", "marks": 6, "hint": "Think about what Rory and Jayda each specifically contribute — their different professional backgrounds, their combined capital. Apply each benefit directly to Green Cuisine using names and details from the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 6 marks (AO1b: 2, AO2: 2, AO3a: 2)</h5>\n<ul>\n<li><strong>Understanding (up to 2 marks):</strong> One mark per benefit of a partnership, e.g.:\n<ul>\n<li>Can share workload and decision-making</li>\n<li>May benefit from complementary/diverse skills and experiences</li>\n<li>Can raise more capital than a sole trader</li>\n<li>Easier/less complex to set up than a limited company</li>\n</ul>\n</li>\n<li><strong>Application (up to 2 marks):</strong> One mark per benefit applied to Rory and Jayda, e.g.:\n<ul>\n<li>Rory has finance experience; Jayda has marketing and kitchen management experience</li>\n<li>Both partners contribute savings to fund the restaurant and car charging infrastructure</li>\n<li>The tasks can be shared according to each partner''s strengths</li>\n</ul>\n</li>\n<li><strong>Analysis (up to 2 marks):</strong> One mark per business-facing impact, e.g.:\n<ul>\n<li>Increases the chances of success and improved business performance</li>\n<li>Reduces financial risk as both partners contribute capital</li>\n<li>More likely to meet diverse customer needs through specialised management of different functions</li>\n</ul>\n</li>\n</ul>\n<p><strong>Examiner''s Exemplar Response:</strong><br>\nJayda and Rory each bring diverse skills and experiences from other job roles (U). The various tasks can be shared: Jayda can manage the kitchen and marketing whilst Rory looks after the financial elements (APP). This will increase the chances of success and improved performance of Green Cuisine (AN).</p></div>"}, {"question": "Which stakeholder does limited liability protect?", "marks": 1, "hint": "Limited liability is specifically about protecting one group from losing personal wealth if a company cannot pay its debts.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Shareholders</h5>\n<p><strong>Why C is correct:</strong> Limited liability protects shareholders (the owners of a limited company) by ensuring they can only lose the amount they invested. Their personal wealth beyond that investment is fully protected.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Wrong:</strong> Customers are protected by consumer law (e.g. Consumer Rights Act), not limited liability.</li>\n<li><strong>B — Wrong:</strong> Employees are protected by employment law (minimum wage, unfair dismissal legislation), not limited liability.</li>\n<li><strong>D — Wrong:</strong> Suppliers are actually at risk when a company fails — they may not be paid for goods or services already delivered. Limited liability does not protect suppliers.</li>\n</ul></div>"}, {"question": "Which one of the following is a disadvantage of being a sole trader?", "marks": 1, "hint": "Think about the practical challenges of managing and running a business entirely on your own.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — May need to work long hours</h5>\n<p><strong>Why A is correct:</strong> A sole trader has no partner to share the workload, so they often work very long hours — especially when starting out. This can cause stress and serious health problems.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>B — Wrong:</strong> Sole traders CAN employ staff. ''Sole'' means one owner, not one worker.</li>\n<li><strong>C — Wrong:</strong> Sole traders keep ALL profits entirely for themselves — profit-sharing is a disadvantage of partnerships, not sole trading.</li>\n<li><strong>D — Wrong:</strong> Sole traders do not have shares at all. The Stock Exchange is only relevant to public limited companies.</li>\n</ul></div>"}, {"question": "Which of the following is a benefit to an entrepreneur of having limited liability?", "marks": 1, "hint": "The core benefit of limited liability is protection — but protection of what, specifically?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Own possessions are not at risk</h5>\n<p><strong>Why B is correct:</strong> The defining benefit of limited liability is that personal possessions — home, car, savings — cannot be seized to repay business debts. The maximum an owner can lose is what they originally invested.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Wrong:</strong> Limited liability has nothing to do with taxation. Company profits are subject to corporation tax.</li>\n<li><strong>C — Wrong:</strong> Productivity falling is a disadvantage, not a benefit. Limited liability has no direct connection to productivity levels.</li>\n<li><strong>D — Wrong:</strong> Suppliers'' decisions about whether to supply are based on creditworthiness and payment reliability, not directly on whether the business has limited liability status.</li>\n</ul></div>"}, {"question": "A photography business is owned by three sisters. The sisters have unlimited liability. Which one of the following types of business do the sisters own?", "marks": 1, "hint": "Two key clues in the question: (1) three owners, and (2) unlimited liability. Use both clues to eliminate wrong answers.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — A partnership</h5>\n<p><strong>Why A is correct:</strong> A partnership has multiple owners (minimum 2) AND unlimited liability. Three owners rules out a sole trader. Unlimited liability rules out both types of limited company.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>B — Wrong:</strong> A private limited company has LIMITED liability, not unlimited liability.</li>\n<li><strong>C — Wrong:</strong> A public limited company has LIMITED liability, not unlimited liability.</li>\n<li><strong>D — Wrong:</strong> A sole trader has only ONE owner. Three sisters cannot all be sole traders of the same business.</li>\n</ul></div>"}, {"question": "Analyse two benefits to Shamira and Zubair of Shirtz Ltd being a private limited company. [6 marks]", "marks": 6, "hint": "Focus on the legal advantages of being a private limited company specifically — limited liability, continuity, share sales, or separate legal personality. Each benefit must be applied to Shamira and Zubair''s specific situation using details from the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 6 marks (AO1b: 2, AO2: 2, AO3a: 2)</h5>\n<ul>\n<li><strong>Understanding (up to 2 marks):</strong> One mark per benefit of a private limited company, e.g.:\n<ul>\n<li>Limited liability</li>\n<li>Continuity of the business if an owner dies</li>\n<li>Ability to sell shares to raise capital</li>\n<li>Separate legal personality — the business is its own legal entity</li>\n</ul>\n</li>\n<li><strong>Application (up to 2 marks):</strong> One mark per application to Shamira and Zubair, e.g.:\n<ul>\n<li>Need for new finance to fund machinery and larger premises</li>\n<li>Currently operating from their house — personal possessions at risk without limited liability</li>\n<li>If one owner died, the business would continue uninterrupted</li>\n</ul>\n</li>\n<li><strong>Analysis (up to 2 marks):</strong> One mark per business-facing impact, e.g.:\n<ul>\n<li>If the expansion fails, they will not lose their house to repay debts</li>\n<li>Can attract share investment for expansion without additional bank borrowing</li>\n<li>Business would not need to be wound up if Shamira or Zubair died</li>\n</ul>\n</li>\n</ul>\n<p><strong>Examiner''s Exemplar Responses:</strong></p>\n<p><em>Response 1:</em> Shamira and Zubair would benefit from limited liability (U), which means they can only lose the money they have already invested in Shirtz Ltd (U), and they would not lose their house if the business got into debt (AN).</p>\n<p><em>Response 2:</em> The business would have continuity (U) so that if Shamira died the business would continue (APP) and her husband would not have to wind the business up and start again (AN).</p>\n<p><em>Response 3:</em> They can sell shares in Shirtz Ltd (U) to gain more finance to expand the business (APP) without having to borrow money from a bank (AN).</p></div>"}, {"question": "Which one of the following is NOT a benefit of being a sole trader?", "marks": 1, "hint": "Three of these are genuine advantages of a sole trader. One is actually an advantage of a DIFFERENT type of ownership. Which one?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Shared responsibility</h5>\n<p><strong>Why D is correct (NOT a benefit of a sole trader):</strong> Shared responsibility is a benefit of a PARTNERSHIP — not a sole trader. A sole trader carries ALL responsibility alone. Having no one to share the burden is actually one of the disadvantages of the sole trader model.</p>\n<p><strong>Why the others are wrong (they ARE genuine sole trader benefits):</strong></p>\n<ul>\n<li><strong>A — Wrong (it IS a benefit):</strong> Keeping all profits is a genuine advantage — the sole trader does not share earnings with anyone.</li>\n<li><strong>B — Wrong (it IS a benefit):</strong> Being your own boss — having complete control — is a genuine advantage of sole trading.</li>\n<li><strong>C — Wrong (it IS a benefit):</strong> Pursuing personal goals — running the business according to your own values and objectives — is a genuine advantage of sole trading.</li>\n</ul></div>"}, {"question": "Which of the following is a feature of a public limited company?", "marks": 1, "hint": "Think about the key legal features that define a plc specifically.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — The owners have limited liability</h5>\n<p><strong>Why B is correct:</strong> A plc''s shareholders have limited liability — they can only lose the amount they originally invested. This is a defining feature of all limited companies.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Wrong:</strong> A plc MUST publish its financial information annually. This is actually one of its key disadvantages.</li>\n<li><strong>C — Wrong:</strong> A deed of partnership is a document used in a PARTNERSHIP, not in a public limited company.</li>\n<li><strong>D — Wrong:</strong> A plc CAN — and does — sell shares on the Stock Exchange to raise finance. This is its defining and primary feature.</li>\n</ul></div>"}, {"question": "Which statement about limited liability is FALSE?", "marks": 1, "hint": "Three of these statements are TRUE about limited liability. One is FALSE. Think carefully about which type of ownership actually has UNLIMITED liability.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — FALSE statement</h5>\n<p><strong>Why B is the FALSE statement:</strong> Sole traders have UNLIMITED liability — NOT limited liability. The owner of a sole trader is personally responsible for ALL business debts, including having personal possessions at risk.</p>\n<p><strong>Why the others are TRUE statements (and therefore incorrect answers to this question):</strong></p>\n<ul>\n<li><strong>A — True:</strong> With limited liability, personal possessions cannot be taken to repay business debts. This is entirely correct.</li>\n<li><strong>C — True:</strong> Limited liability does attract investors — it clearly defines and limits their personal financial risk, which makes investing more appealing.</li>\n<li><strong>D — True:</strong> Shareholders of an Ltd do benefit from limited liability. This is correct.</li>\n</ul></div>"}, {"question": "Analyse one advantage of Joe becoming a sole trader. [3 marks]", "marks": 3, "hint": "Use the three-step formula: state the advantage (U), link it to Joe''s specific situation with his £1,000 savings and barbers shop (APP), then explain the business impact (AN).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1, AO2: 1, AO3a: 1)</h5>\n<ul>\n<li><strong>Understanding (1 mark):</strong> One advantage of being a sole trader, e.g.:\n<ul>\n<li>Easiest and cheapest to set up — minimal paperwork</li>\n<li>Joe keeps all profits</li>\n<li>Complete control over all decisions</li>\n<li>Financial information stays completely private</li>\n<li>Can be set up with very little capital</li>\n</ul>\n</li>\n<li><strong>Application (1 mark):</strong> Link to Joe''s specific situation, e.g.:\n<ul>\n<li>Joe only has £1,000 — a sole trader requires minimal start-up costs beyond what Joe already has</li>\n<li>Joe can make pricing and marketing decisions for the barbers shop without consulting Mark</li>\n<li>Joe does not need to share profits with anyone</li>\n</ul>\n</li>\n<li><strong>Analysis (1 mark):</strong> The bottom-line business impact, e.g.:\n<ul>\n<li>Joe can get the barbers shop open quickly using his existing savings</li>\n<li>Joe retains full flexibility and can respond quickly to what customers want</li>\n<li>Joe''s personal income from the business is maximised</li>\n</ul>\n</li>\n</ul></div>"}, {"question": "Analyse one disadvantage of Joe becoming a partnership. [3 marks]", "marks": 3, "hint": "Choose one real disadvantage of being in a partnership (not just of ''working with someone''). Apply it to Joe and Mark specifically using the case study, then state the bottom-line impact.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1, AO2: 1, AO3a: 1)</h5>\n<ul>\n<li><strong>Understanding (1 mark):</strong> One disadvantage of a partnership, e.g.:\n<ul>\n<li>Unlimited liability — both partners personally responsible for all business debts</li>\n<li>Profits must be shared between the partners</li>\n<li>Slower decision-making due to the need to consult and agree with a partner</li>\n<li>Risk of disagreement / conflict between partners</li>\n<li>If one partner dies, the partnership may have to be dissolved</li>\n</ul>\n</li>\n<li><strong>Application (1 mark):</strong> Link to Joe and Mark''s situation, e.g.:\n<ul>\n<li>Both Joe and Mark are investing personal savings, which would be at risk</li>\n<li>Joe and Mark may disagree on how to run the barbers shop — pricing, services, opening hours</li>\n<li>Joe would have to share any profits he earns with Mark</li>\n</ul>\n</li>\n<li><strong>Analysis (1 mark):</strong> The business-facing impact, e.g.:\n<ul>\n<li>If the barbers shop fails, both could face serious personal financial hardship</li>\n<li>Conflict could slow down decision-making and damage the customer experience</li>\n<li>This reduces Joe''s personal income compared to operating as a sole trader</li>\n</ul>\n</li>\n</ul></div>"}, {"question": "Recommend whether Joe should go as a sole trader or go into partnership with Mark. [3 marks]", "marks": 3, "hint": "Make a CLEAR choice first (1 mark). Then explain WHY your chosen option is better THAN the other — you MUST reference both options and use specific details from the case study to earn full marks.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b: 3)</h5>\n<ul>\n<li><strong>Judgement (1 mark):</strong> A clear recommendation — sole trader OR partnership.</li>\n<li><strong>Contextual Justification (up to 2 marks):</strong> A comparative reason using case study details that explains why the chosen option is BETTER THAN the other. Both options must be addressed to earn both justification marks.</li>\n<li><strong>OR Non-contextual Justification (1 mark max):</strong> A comparative reason without case study detail.</li>\n</ul>\n<p><em>Important: Justification MUST address BOTH options to earn the full 2 justification marks.</em></p>\n<p><strong>Example Model Answer 1 — Sole Trader:</strong><br>\nJoe should become a sole trader (JUDGEMENT). Joe''s savings of £1,000 already cover his initial costs, so he does not need Mark''s additional capital right now (CONTEXT). As a sole trader, Joe keeps all profits and makes all decisions himself — whereas a partnership would mean sharing profits with Mark and potentially slowing decision-making if they disagree about the direction of the barbers shop (+2 MARKS).</p>\n<p><strong>Example Model Answer 2 — Partnership:</strong><br>\nJoe should go into partnership with Mark (JUDGEMENT). Mark also has savings to invest, giving the barbers shop more capital to buy better equipment and handle unexpected costs in the early months (CONTEXT). Although Joe would need to share any profits with Mark, having Mark''s additional financial contribution reduces the risk of the business running short of money — a common cause of start-up failure — unlike a sole trader arrangement where Joe alone bears all financial risk (+2 MARKS).</p></div>"}, {"question": "Analyse one benefit to Pen & Sword Books of being a private limited company. [3 marks]", "marks": 3, "hint": "Choose ONE benefit of being a private limited company. Explain what it means (U), link it to the fact that it is a family-owned business expanding into new markets (APP), then explain the impact on the business (AN).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1, AO2: 1, AO3a: 1)</h5>\n<p><em>Note: You CANNOT score Application or Analysis marks without first scoring the Understanding mark.</em></p>\n<ul>\n<li><strong>Understanding (1 mark):</strong> A benefit of a private limited company, e.g.:\n<ul>\n<li>Share sale can be controlled — all shareholders must agree on any new shareholders</li>\n<li>Business can continue if one shareholder dies (continuity)</li>\n<li>Shareholders benefit from limited liability</li>\n</ul>\n</li>\n<li><strong>Application (1 mark):</strong> Applied to Pen & Sword using the case study, e.g.:\n<ul>\n<li>The present family ownership cannot be changed unless all family members agree</li>\n<li>If a family member who holds shares dies, the business continues publishing</li>\n</ul>\n</li>\n<li><strong>Analysis (1 mark):</strong> Effect/impact on the business, e.g.:\n<ul>\n<li>Family owners can invest confidently in digital and audio expansion knowing business cannot be taken over without consent of all shareholders</li>\n<li>The business can continue expanding its range of titles without disruption if ownership changes</li>\n</ul>\n</li>\n</ul>\n<p><strong>Examiner''s Note:</strong> The assessment objective checklist is Understanding (1) → Application (1) → Analysis (1). These must flow logically.</p></div>"}, {"question": "Analyse one benefit to Pen & Sword Books of becoming a plc. [3 marks]", "marks": 3, "hint": "Think about what a plc can do that a private limited company cannot. What is the primary advantage of a plc? Then apply it to Pen & Sword''s specific expansion needs mentioned in the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1, AO2: 1, AO3a: 1)</h5>\n<ul>\n<li><strong>Understanding (1 mark):</strong> A benefit of a plc, e.g.:\n<ul>\n<li>A business can raise much greater amounts of finance by selling shares to the general public</li>\n<li>Plcs are seen as lower risk and can attract lenders more easily than smaller firms</li>\n</ul>\n</li>\n<li><strong>Application (1 mark):</strong> Applied to Pen & Sword using the case study, e.g.:\n<ul>\n<li>Pen & Sword could raise finance to fund substantial investment in data management</li>\n<li>Pen & Sword could borrow money more easily to further expand into audio books and new publishing categories</li>\n</ul>\n</li>\n<li><strong>Analysis (1 mark):</strong> Effect/impact on the business, e.g.:\n<ul>\n<li>With easier access to larger amounts of capital, Pen & Sword can expand its digital and audio operations, potentially increasing sales revenue significantly</li>\n<li>With additional shareholders bringing in money and expertise, the business can develop faster than a private limited company alone could fund</li>\n</ul>\n</li>\n</ul></div>"}, {"question": "Evaluate whether or not Pen & Sword Books should become a plc. [3 marks]", "marks": 3, "hint": "Make a CLEAR decision first (1 mark). Then justify it using SPECIFIC details from the Pen & Sword case study — not just general knowledge about plcs. You need two pieces of contextual evidence for the full 2 justification marks.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b: 3 — Evaluation)</h5>\n<ul>\n<li><strong>Judgement (1 mark):</strong> A clear statement — Pen & Sword should or should not become a plc.</li>\n<li><strong>Justification (up to 2 marks):</strong> A clear justification in the context of the case study. For 2 marks, justification must be precise — using (not simply repeating) specific information from the case study that clearly supports the judgement.</li>\n</ul>\n<p><strong>Example — Stay as Private Limited Company (recommended approach):</strong><br>\nPen & Sword Books should continue as a private limited company (JUDGEMENT). The business has expanded successfully from 42 to 53 staff and from 450 to 550 books per year between 2016 and 2021 — there is simply no pressing need to change what is clearly working (+1 MARK). As a family-owned business, becoming a plc would risk a hostile takeover — any investor could buy shares and challenge family control, which could undermine the long-term strategic direction that has driven the business''s growth (+1 MARK).</p>\n<p><strong>Example — Become a plc:</strong><br>\nPen & Sword Books should become a plc (JUDGEMENT). The business needs substantial investment in data management and is expanding into audio books — financial demands that may exceed what private shareholders can fund (+1 MARK). As a plc, it could raise the millions potentially needed for technology investment through the Stock Exchange, accelerating its expansion far beyond what is currently possible (+1 MARK).</p></div>"}]}}'::jsonb),
('business', '1-4-business-aims-objectives', '1.4 Aims and Objectives', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>Every business needs a direction — a set of goals that guide all its decisions. These are known as <strong>business aims and objectives</strong>.</p>\n<ul>\n  <li><strong>Business Objectives:</strong> What the business aims to achieve. These can include survival, profit, growth, market share, and providing a service.</li>\n  <li><strong>Profit:</strong> The difference between revenue (money coming in) and costs (money going out). Revenue − Costs = Profit.</li>\n  <li><strong>Satisficing:</strong> Making just enough profit to give the business owner a decent standard of living. More common in smaller businesses such as sole traders.</li>\n  <li><strong>Growth:</strong> Where a business becomes larger — for example by making more products, opening more stores, or selling in new markets.</li>\n  <li><strong>Market Share:</strong> The percentage of the total market that a business holds. Shown as a percentage of total sales in the industry.</li>\n  <li><strong>Survival:</strong> When a business manages to keep trading, often during its early months or in times of difficulty.</li>\n  <li><strong>Providing a Service:</strong> Ensuring the needs of the customer are met, often prioritised over maximising profit.</li>\n  <li><strong>Evolving:</strong> The way a business develops and changes over time — becoming bigger or smaller, selling different goods, or operating in different ways.</li>\n</ul>", "check": {"question": "What is ''satisficing''?", "options": ["Gaining the largest possible share of the market", "Making just enough profit for a decent standard of living", "Making the maximum possible profit for shareholders", "Keeping the business trading during a difficult period"], "answer": 1, "explain": "The card defines satisficing as making just enough profit for a decent standard of living, which is more common in smaller businesses such as sole traders."}}, {"title": "The Five Main Business Objectives", "html": "<p>All businesses have at least one objective, but the most common objectives are:</p>\n<ul>\n  <li><strong>Profit:</strong> Most businesses aim to make a profit. Some aim to <em>maximise</em> profit (make as much as possible), while others aim to <em>satisfice</em> (make just enough). Too much focus on profit can damage reputation if customers feel they are being exploited.</li>\n  <li><strong>Growth:</strong> Becoming larger — through more sales, more outlets, or a higher market share. Important for PLCs that need to pay increasing dividends to shareholders. Not all businesses want to grow; many smaller businesses are happy to stay the same size.</li>\n  <li><strong>Market Share:</strong> Gaining a greater percentage of total sales in an industry. For example, if 1,000 tables are sold nationally and a business sells 100, its market share is 10%. A business might take over a competitor to increase its share.</li>\n  <li><strong>Survival:</strong> Simply keeping the business going. Especially important for new businesses in their first months, or for any business facing falling sales, new competition, or economic difficulty. Normally a temporary but vital objective.</li>\n  <li><strong>Providing a Service:</strong> Putting customer satisfaction first, even if it means less profit. Common in smaller local businesses or those that build their reputation on excellent service. Can lead to awards, loyal customers, and long-term success.</li>\n</ul>\n<div class=\"formula-box\">\n  <strong>Market Share (%) =</strong> (Sales of the business ÷ Total sales in the market) &times; 100\n</div>", "check": {"question": "A business sells 100 out of 1,000 tables sold nationally. What is its market share?", "options": ["1%", "90%", "10%", "100%"], "answer": 2, "explain": "Using the card''s example and the formula (business sales ÷ total market sales) × 100, 100 ÷ 1,000 × 100 = 10%."}}, {"title": "Advantages & Disadvantages of Each Objective", "html": "<p>Each objective has strengths and weaknesses depending on the situation of the business.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Profit Maximisation</div>\n    <div class=\"pro-item\"><strong>Rewards owners:</strong> Maximising profit ensures shareholders and owners receive the highest possible return for the risks they have taken.</div>\n    <div class=\"pro-item\"><strong>Funds future growth:</strong> High profits can be reinvested to expand the business, open new premises, or research new products.</div>\n    <div class=\"con-item\"><strong>Damages reputation:</strong> Customers and the public may react negatively if a business is seen as purely profit-driven, reducing sales in the long run.</div>\n    <div class=\"con-item\"><strong>Short-term focus:</strong> Chasing maximum profit can lead to cutting corners on quality or customer service.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✓ Survival</div>\n    <div class=\"pro-item\"><strong>Keeps business alive:</strong> For new or struggling businesses, simply continuing to trade is a crucial achievement that allows future recovery.</div>\n    <div class=\"pro-item\"><strong>Realistic target:</strong> A clear, achievable focus that helps owners prioritise essential costs and decisions during tough times.</div>\n    <div class=\"con-item\"><strong>Not sustainable long-term:</strong> A business cannot survive indefinitely without making profit — survival must eventually lead to other objectives.</div>\n    <div class=\"con-item\"><strong>Limits investment:</strong> When focused on survival, a business cannot invest in growth, marketing, or new technology.</div>\n  </div>\n</div>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Growth</div>\n    <div class=\"pro-item\"><strong>Increases profit potential:</strong> A larger business can sell more, benefit from economies of scale, and generate higher revenues.</div>\n    <div class=\"pro-item\"><strong>Greater market power:</strong> Growth can reduce competition by taking over rivals or securing exclusive supplier deals.</div>\n    <div class=\"con-item\"><strong>Loss of control:</strong> Rapid growth can make it harder to maintain quality, communication, and customer service standards.</div>\n    <div class=\"con-item\"><strong>Not always desired:</strong> Many smaller business owners are content to stay small and avoid the stress and risk of expansion.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✓ Providing a Service</div>\n    <div class=\"pro-item\"><strong>Builds loyalty:</strong> Customers who receive excellent service are more likely to return and recommend the business to others.</div>\n    <div class=\"pro-item\"><strong>Strong reputation:</strong> Businesses known for great service can earn awards and stand out in competitive markets.</div>\n    <div class=\"con-item\"><strong>Lower profit margins:</strong> Investing heavily in service quality can increase costs, reducing overall profitability.</div>\n    <div class=\"con-item\"><strong>Hard to measure:</strong> Unlike profit or market share, the success of a service objective is difficult to quantify precisely.</div>\n  </div>\n</div>", "check": {"question": "According to this card, what is a key disadvantage of profit maximisation as an objective?", "options": ["It prevents the business from ever reinvesting in growth", "It can damage reputation if seen as purely profit-driven", "It makes market share impossible to calculate", "It guarantees the business will lose customers immediately"], "answer": 1, "explain": "The card states that customers and the public may react negatively if a business is seen as purely profit-driven, reducing sales in the long run."}}, {"title": "How & Why Objectives Change as Businesses Evolve", "html": "<p>A business''s objectives are never fixed forever. As circumstances change, so do the goals a business sets itself. There are three key stages to consider:</p>\n\n<p><strong>1. When a Business Starts</strong></p>\n<ul>\n  <li>The main objective is almost always <strong>survival</strong> — simply getting through the first few months.</li>\n  <li>New businesses face established competitors who may lower prices to squeeze them out of the market.</li>\n  <li>They must build a reputation and find loyal customers from scratch.</li>\n  <li>Some new businesses with experienced owners and contacts may aim for profit from day one.</li>\n</ul>\n\n<p><strong>2. As a Business Grows</strong></p>\n<ul>\n  <li>Once established, owners with ambition may shift from satisficing to <strong>profit maximisation</strong>.</li>\n  <li>Profit can then be reinvested to fund <strong>growth</strong> — new premises, new products, or taking over a competitor.</li>\n  <li>A sole trader may convert to a limited company, attracted by limited liability as personal wealth grows.</li>\n  <li>At some point a business may choose to <em>stop</em> growing — for example, when controlling more stores would reduce quality or customer service.</li>\n  <li>Rapid growth can cause a business to lose sight of customers, so the objective may shift back to <strong>providing a service</strong>.</li>\n</ul>\n\n<p><strong>3. When a Business is in Difficulty</strong></p>\n<ul>\n  <li>Falling profits or losses make profit maximisation an unrealistic objective — <strong>survival</strong> takes priority.</li>\n  <li>Expansion plans are postponed or cancelled entirely.</li>\n  <li>In extreme cases, businesses must close down parts of their operations to reduce losses.</li>\n</ul>", "check": {"question": "When a business is in financial difficulty, what typically happens to its objectives according to this card?", "options": ["Market share automatically increases as competitors struggle too", "Expansion plans are cancelled as the focus shifts to survival", "Profit maximisation becomes easier to achieve than before", "The business immediately converts to a PLC to raise more capital"], "answer": 1, "explain": "The card states that falling profits make profit maximisation unrealistic, survival takes priority, and expansion plans are postponed or cancelled."}}, {"title": "Why Different Businesses Have Different Objectives", "html": "<p>Not all businesses will have the same objectives. The objective a business sets depends on several key factors:</p>\n<ul>\n  <li><strong>Size of the business:</strong> A sole trader can set whatever objective they like without answering to anyone. A PLC must satisfy shareholders who expect rising dividends — meaning profit and growth are essential.</li>\n  <li><strong>Attitude of the owner(s):</strong> Some owners are driven by ambition; others are happy to earn a comfortable living without expanding. Personal motivation shapes objectives significantly.</li>\n  <li><strong>Stage of development:</strong> New businesses tend to focus on survival or establishing themselves. Mature businesses focus on profit or growth.</li>\n  <li><strong>Level of competition:</strong> A business facing heavy competition (e.g., supermarkets) may focus on survival or providing a better service rather than growth. Aldi and Lidl grew by offering something different (lower prices) in a competitive market.</li>\n  <li><strong>Economic conditions:</strong> During a recession, businesses shift focus to survival. During periods of growth, they may invest in expansion.</li>\n  <li><strong>Values of the business:</strong> Some businesses prioritise community service or social responsibility, keeping prices low even at the expense of profit.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Aldi & Tesco</h4>\n  <p>Tesco — a large established PLC — prioritises profit and market share, driven by shareholder expectations. Aldi, entering the UK market as a challenger, focused on growth by offering lower prices than rivals. Meanwhile, a small independent butcher may focus on providing excellent service to the local community, with satisficing profit as the main goal. Three businesses, three very different objectives — all shaped by their size, ownership, and market context.</p>\n</div>", "check": {"question": "In the Aldi & Tesco case study, why does Tesco prioritise profit and market share while a small independent butcher might satisfice instead?", "options": ["Butchers are legally required to prioritise service over profit", "Tesco is a large PLC answerable to shareholders; the butcher is not", "Tesco has no competitors, so it does not need to focus on market share", "Tesco sells fewer products than the butcher, so it must charge higher prices"], "answer": 1, "explain": "The case study shows objectives are shaped by size, ownership, and market context — Tesco''s PLC status means shareholder expectations drive profit and market share, while a small independent butcher can focus on service and satisficing."}}, {"title": "Objectives Linked to Business Ownership", "html": "<p>The type of business ownership directly influences which objectives are most appropriate.</p>\n<ul>\n  <li><strong>Sole Trader:</strong> One owner who controls everything. Objectives are personal — often satisficing (making enough to live on) or providing a service to the local community. Growth may not be desired.</li>\n  <li><strong>Partnership:</strong> Partners may have different personal ambitions (as seen in the WYW case study — Rick wanted growth, Francis wanted profit). This can cause conflict over objectives.</li>\n  <li><strong>Private Limited Company (Ltd):</strong> Shareholders want returns, but the close ownership structure means the business can balance profit with values. May aim for growth or market share.</li>\n  <li><strong>Public Limited Company (PLC):</strong> Shareholders on the stock market demand high dividends, which requires consistent profit and growth. Objectives are largely driven by financial performance.</li>\n</ul>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Benefits of Having Clear Objectives</div>\n    <div class=\"pro-item\"><strong>Direction:</strong> All employees and stakeholders understand what the business is trying to achieve.</div>\n    <div class=\"pro-item\"><strong>Decision-making:</strong> Objectives help managers make consistent decisions that align with business goals.</div>\n    <div class=\"pro-item\"><strong>Motivation:</strong> Clear targets give employees and owners something to work towards.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Risks of Poorly Set Objectives</div>\n    <div class=\"con-item\"><strong>Conflict:</strong> Different stakeholders (e.g., partners) may want different objectives, leading to disagreement.</div>\n    <div class=\"con-item\"><strong>Inflexibility:</strong> Sticking rigidly to an objective when circumstances change can harm the business.</div>\n    <div class=\"con-item\"><strong>Unrealistic targets:</strong> Setting objectives that are too ambitious can demoralise staff and lead to poor decisions.</div>\n  </div>\n</div>", "check": {"question": "Why is a PLC''s objective-setting most constrained by shareholders, compared to a sole trader?", "options": ["PLCs are legally banned from setting a survival objective", "Sole traders must always seek shareholder approval before setting objectives", "PLCs cannot change their objectives once the business is formed", "PLC shareholders demand high dividends, requiring profit and growth"], "answer": 3, "explain": "The card explains that PLC shareholders demand high dividends, meaning objectives are largely driven by financial performance, unlike a sole trader whose objectives are personal."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Business Objective", "definition": "A goal or target that a business aims to achieve, such as profit, survival, growth, market share, or providing a service."}, {"term": "Profit", "definition": "Revenue minus total costs. The financial reward for taking business risk."}, {"term": "Satisficing", "definition": "Making just enough profit for the owner to have a decent standard of living. Common in sole traders."}, {"term": "Growth", "definition": "Becoming larger — through more sales, more outlets, higher market share, or taking over a competitor."}, {"term": "Market Share", "definition": "(Business sales ÷ Total market sales) × 100. The percentage of the total market held by one business."}, {"term": "Survival", "definition": "Simply keeping the business trading. The priority for new businesses and those in difficulty."}, {"term": "Providing a Service", "definition": "Prioritising customer satisfaction above profit. Common in smaller, community-focused businesses."}, {"term": "Evolving", "definition": "The way a business changes over time in size, products, ownership structure, or objectives."}, {"term": "Profit Maximisation", "definition": "Trying to make as much profit as possible — the opposite of satisficing."}, {"term": "Dividend", "definition": "A share of company profits paid to shareholders. PLCs must generate profit to pay these."}, {"term": "Why objectives change (new business)", "definition": "New businesses focus on survival because they face established competition and must build their reputation from scratch."}, {"term": "Why objectives change (growing business)", "definition": "Growing businesses shift to profit, growth, or market share as they become established and owners become more ambitious."}, {"term": "Why objectives change (in difficulty)", "definition": "Businesses in difficulty abandon growth plans and refocus on survival, reducing losses until conditions improve."}, {"term": "Why different businesses have different objectives", "definition": "Differences in size, ownership type, owner attitude, market competition, and stage of development all lead to different objectives."}]}, "mcq": {"enabled": true, "questions": [{"question": "What does ''satisficing'' mean in a business context?", "options": ["Making as much profit as possible", "Making just enough profit to provide the owner with a decent living", "Providing the best possible customer service", "Focusing on growth above all else"], "answer": 1, "explain": "Correct answer: Satisficing means making just enough profit to give the business owner a decent standard of living. It is most common in smaller businesses such as sole traders who are not driven by maximum profit."}, {"question": "A business has recently changed its main objective from ''survival'' to ''growth''. What would most likely explain this change?", "options": ["The business has become too big", "The business has reduced its productivity", "The business is experiencing high demand", "The business needs to lower its costs"], "answer": 2, "explain": "Correct answer: High demand means the business is performing well and has established itself. This gives it the confidence and resources to shift from simply staying alive (survival) to expanding (growth)."}, {"question": "DM plc manufactures canned drinks. Its main objective is to increase market share by 2%. What would help achieve this?", "options": ["Increasing the cost of its canned drinks", "Increasing the number of retail outlets it supplies", "Increasing the price of its canned drinks", "Increasing the time it takes to process orders"], "answer": 1, "explain": "Correct answer: By supplying more retail outlets, DM plc reaches more customers, which increases total sales. A higher share of total market sales means greater market share. Raising prices (A and C) would likely reduce sales, and slower processing (D) would harm competitiveness."}, {"question": "Firms A and B both operate in the same industry. Firm A''s objective is profit; Firm B''s objective is survival. What would explain this difference?", "options": ["Firm A has a low market share and Firm B has a high market share", "Firm B is a start-up business and Firm A is an established business", "The owners of Firm A have less determination than the owners of Firm B", "The owners of Firm B are more confident than the owners of Firm A"], "answer": 1, "explain": "Correct answer: New or start-up businesses typically focus on survival because they are not yet established in the market and face competition from existing firms. Established businesses, having already secured customers and revenue, can focus on higher-level objectives like profit."}, {"question": "Alex, a sole trader, changed his hair salon''s objective from ''profit'' to ''survival''. What would explain this?", "options": ["The hair salon has already achieved its profit objective", "The hair salon has gained a lot of new customers", "The hair salon is experiencing intense competition", "The hair salon is now an established business"], "answer": 2, "explain": "Correct answer: Intense competition would reduce Alex''s sales and potentially make profit unachievable in the short term. When revenue falls due to competition, survival becomes the priority — keeping the business trading until conditions improve."}, {"question": "A business whose main objective is to survive is likely to be:", "options": ["Experiencing growth in its market share", "Making a large profit", "Well established and successful", "Working hard to stay in existence"], "answer": 3, "explain": "Correct answer: Survival means the business is focused on simply continuing to operate. This typically occurs during early stages or periods of difficulty — the opposite of growing market share or making large profits."}, {"question": "The ''objectives of a business'' are:", "options": ["Negative comments from the local community", "The buildings and equipment the business owns", "The items the business makes and sells", "What the business intends to achieve"], "answer": 3, "explain": "Correct answer: Business objectives are what the business aims to achieve — targets or goals such as profit, growth, survival, market share, or providing a service. They are not physical assets (B), products (C), or negative feedback (A)."}, {"question": "Which of the following is NOT normally an aim of a business which is just starting?", "options": ["Survival", "To become established in the market", "To become a plc", "To try to make a profit"], "answer": 2, "explain": "Correct answer: Becoming a PLC is a long-term structural change requiring significant growth, established reputation, and shareholder investment. A brand new business focuses on survival, building its name, and making early profits — not complex ownership structures."}, {"question": "Two clothing manufacturers have different objectives. Which of the following is NOT a possible reason for this?", "options": ["One business makes coats and the other makes jeans", "Only one of the businesses makes designer clothing", "There is little innovation in the clothing industry", "They have different owners"], "answer": 2, "explain": "Correct answer: The level of innovation in an industry does not directly cause different businesses within it to have different objectives. Different products (A), market positioning (B), and owner attitudes (D) are all genuine reasons why two businesses may pursue different goals."}, {"question": "A business might want to grow because:", "options": ["It sees the opportunity of making more profit", "Growth will mean more people working in the business", "It is the best objective to have", "It will guarantee more profit"], "answer": 0, "explain": "Correct answer: Businesses pursue growth because a larger business can generate higher revenues and therefore higher profits. Growth does not guarantee profit (D is wrong), and simply having more employees (B) or it being ''best'' (C) are not valid motivations."}, {"question": "A business might change its aims and objectives because:", "options": ["All businesses change their objectives after a year", "A new competitor has become very successful", "It feels that a change will always bring more profits", "It is essential to change objectives as a business grows"], "answer": 1, "explain": "Correct answer: External factors like new successful competitors can force a business to rethink its objectives — for example switching from growth to survival if competition is fierce. The other options contain false absolutes: not all businesses change after a year (A), and change does not always increase profits (C)."}, {"question": "Which of the following best describes ''market share''?", "options": ["The total value of all sales in a market", "The number of competitors a business faces", "A business''s sales as a percentage of total market sales", "The profit a business earns from each sale"], "answer": 2, "explain": "Correct answer: Market share is expressed as a percentage showing how much of the total market a business accounts for. It is calculated as (Business sales ÷ Total market sales) × 100."}]}, "fib": {"enabled": true, "questions": [{"text": "[Profit] is the difference between revenue and costs, and is the main objective for most private sector businesses."}, {"text": "Making just enough profit to provide the owner with a decent living is known as [satisficing]."}, {"text": "A business''s [market] share is its sales expressed as a percentage of total sales in the entire market."}, {"text": "When a business is new, its most likely objective is [survival] — simply keeping the business going through the first few months."}, {"text": "A business that becomes larger by opening more outlets or taking over a competitor is pursuing an objective of [growth]."}, {"text": "Shareholders in a [PLC] expect to receive dividends, which means the business must focus on making sufficient profit."}, {"text": "As a business [evolves], its aims and objectives may change because owners become more ambitious or because market conditions shift."}, {"text": "A small business whose owner just wants a comfortable income without expanding is likely to be [satisficing]."}, {"text": "The formula for market share is: (sales of the business ÷ total sales in the market) × [100]."}, {"text": "When a business is in difficulty, it may need to change its objective to [survival] and cut back on expansion plans."}, {"text": "A business that focuses on customer needs, even at the expense of profit, is said to be providing a [service]."}, {"text": "Aldi and Lidl grew their [market share] in the UK supermarket industry by offering lower prices than established rivals."}]}, "tf": {"enabled": true, "questions": [{"statement": "All businesses have profit as their main objective.", "answer": false, "explain": "FALSE. Not all businesses prioritise profit. New businesses often focus on survival, small businesses may satisfice, and some businesses (especially in the public sector or community-focused businesses) prioritise providing a service above profit."}, {"statement": "Satisficing means making as much profit as possible.", "answer": false, "explain": "FALSE. Satisficing means making just enough profit to give the owner a decent standard of living. It is the opposite of profit maximisation and is common among sole traders who value a good work-life balance over maximum earnings."}, {"statement": "Market share is expressed as a percentage of total sales in a market.", "answer": true, "explain": "TRUE. Market share = (Business sales ÷ Total market sales) × 100. For example, if a business sells 100 tables out of 1,000 sold in the market, its market share is 10%."}, {"statement": "A new business is most likely to have survival as its main objective.", "answer": true, "explain": "TRUE. New businesses face established competition, must build a reputation from scratch, and often have limited resources. Simply keeping the business trading through the first few months is a major achievement."}, {"statement": "A PLC must focus on profit because shareholders expect dividends.", "answer": true, "explain": "TRUE. Shareholders invest in a PLC expecting a financial return (dividends). These are paid from profits, so a PLC must generate sufficient profit to keep shareholders satisfied — otherwise they may sell their shares, reducing the company''s value."}, {"statement": "Business objectives never change once they have been set.", "answer": false, "explain": "FALSE. Business objectives change regularly as circumstances evolve. A new business may start with survival, move to profit, then growth. A business in difficulty might revert to survival. Changes in competition, the economy, or owner ambitions all cause objectives to shift."}, {"statement": "A sole trader can decide their own objectives without answering to shareholders.", "answer": true, "explain": "TRUE. A sole trader owns the entire business themselves. They are free to set their own objectives — whether that is satisficing, providing a community service, or growing — without needing approval from shareholders or a board of directors."}, {"statement": "Growth is always the most important business objective.", "answer": false, "explain": "FALSE. Growth is one of several objectives, and it is not always the most important. Many small businesses are content to remain the same size. Survival takes priority during difficult periods, and some businesses value service or satisficing over expansion."}, {"statement": "Providing excellent customer service can help a business achieve other objectives such as profit and survival.", "answer": true, "explain": "TRUE. Good service builds loyalty, attracts new customers, and generates positive word-of-mouth. This increases sales, which in turn raises revenue and profit — helping achieve a range of business objectives simultaneously."}, {"statement": "A business facing intense competition might switch its objective from growth to survival.", "answer": true, "explain": "TRUE. If competition is severe enough to reduce sales and threaten the business''s existence, maintaining growth becomes unrealistic. The priority becomes keeping the business alive until conditions improve."}, {"statement": "Taking over a competitor is one way a business can increase its market share.", "answer": true, "explain": "TRUE. By acquiring a competitor, a business absorbs that competitor''s customers and sales. This directly increases its share of the total market."}, {"statement": "Expansion plans are typically accelerated when a business is in financial difficulty.", "answer": false, "explain": "FALSE. When a business is in financial difficulty, expansion plans are postponed or cancelled entirely. The focus shifts to reducing losses and ensuring survival — not investing in costly growth strategies."}]}, "misc": {"enabled": true, "items": [{"myth": "All businesses have profit as their main objective.", "truth": "This is one of the most common misconceptions in GCSE Business. Many businesses — especially new ones — focus on survival. Public sector organisations, charities, and community businesses often prioritise service over profit. Always read the case study to identify the actual objective.", "check": {"question": "Why is it wrong to assume all businesses have profit as their main objective?", "options": ["New or community businesses often prefer survival or service", "All businesses actually aim for market share, not profit", "Only sole traders are legally allowed to aim for profit", "Profit is only relevant to businesses in the public sector"], "answer": 0, "explain": "The card explains that new businesses often focus on survival while public sector, charity, and community businesses often prioritise service over profit — always check the case study for the actual objective."}}, {"myth": "Growth always leads to more profit.", "truth": "Growth can increase revenue but does not guarantee more profit. If a business lowers prices to attract more customers, profit per unit may fall. Rapid growth also increases costs. The mark scheme specifically states that growth does NOT guarantee profit.", "check": {"question": "Why does growth not always guarantee more profit?", "options": ["Growth is defined as an increase in profit, so the two always rise together", "Cutting prices to attract customers and rising expansion costs reduce profit", "Growth only affects market share, never revenue or costs", "The mark scheme treats growth and profit as identical terms"], "answer": 1, "explain": "The card explains that lowering prices to attract customers can reduce profit per unit, and rapid growth increases costs, so the mark scheme states growth does NOT guarantee profit."}}, {"myth": "A business only ever has one objective at a time.", "truth": "Businesses often pursue multiple objectives simultaneously. A business might aim for growth AND profit AND providing good service at the same time. The objectives are also often linked — good service leads to more customers, which leads to higher sales, which improves profit.", "check": {"question": "Can a business pursue more than one objective at the same time?", "options": ["No, a business must choose exactly one objective and stick to it permanently", "Yes, businesses often pursue linked objectives together, e.g. growth and profit", "Yes, but only PLCs are allowed to have more than one objective", "No, objectives are mutually exclusive by definition in business theory"], "answer": 1, "explain": "The card corrects the misconception by explaining businesses often pursue multiple objectives simultaneously, and that objectives such as service, sales and profit are often linked."}}, {"myth": "Once a business sets its objectives, they stay the same forever.", "truth": "Business objectives evolve constantly. Changes in competition, economic conditions, the owner''s ambitions, or the business''s financial position can all trigger a shift in objectives. Examiners expect students to recognise that objectives are dynamic, not fixed.", "check": {"question": "What do examiners expect students to recognise about business objectives?", "options": ["That objectives can only change if the owner retires", "That only PLCs are able to change their objectives over time", "That objectives are dynamic, shifting with competition or ambition", "That objectives are fixed permanently once a business is registered"], "answer": 2, "explain": "The card states that changes in competition, economic conditions, owner ambitions, or financial position can all trigger a shift, and examiners expect students to recognise objectives are dynamic, not fixed."}}, {"myth": "Survival means the business is failing.", "truth": "Survival is a legitimate and rational business objective — especially for new businesses or those facing temporary difficulty. Having survival as an objective shows the business is realistic about its situation. It is not a sign of failure; it is often a sensible short-term strategy.", "check": {"question": "Does having survival as an objective mean a business is failing?", "options": ["No, but it can only be chosen by public limited companies", "Yes, only businesses about to close ever set survival as an objective", "Yes, survival is always a sign of business failure", "No, it is a legitimate strategy showing the business is realistic"], "answer": 3, "explain": "The card corrects the misconception that survival equals failure, stating it is a legitimate, rational, and often sensible short-term strategy, especially for new or struggling businesses."}}, {"myth": "Market share and profit are the same thing.", "truth": "Market share is the percentage of total market sales held by a business. A business can have a high market share but low profit (e.g., if it has cut prices to gain customers). They are related but different concepts with different formulas.", "check": {"question": "Why are market share and profit not the same thing?", "options": ["Market share is only measured in businesses that make no profit at all", "Profit and market share always rise and fall together by definition", "Market share is a measure of costs, while profit measures revenue only", "A business can have a high market share but low profit if it cut prices"], "answer": 3, "explain": "The card explains they are related but different concepts with different formulas, giving the example of a business with high market share but low profit due to price cuts."}}, {"myth": "All large businesses want to grow.", "truth": "Not all large businesses are pursuing growth. Some may have reached a size at which further growth would reduce control or quality. A business might shift its objective to maintaining current profit levels rather than expanding further.", "check": {"question": "Why might a large business choose NOT to pursue further growth?", "options": ["Large businesses never have enough profit to fund further growth", "Further growth could reduce control or quality, so profit is safer", "Growth objectives are only available to sole traders and partnerships", "Large businesses are legally prevented from growing beyond a certain size"], "answer": 1, "explain": "The card explains some large businesses may have reached a size where further growth reduces control or quality, so they shift focus to maintaining current profit rather than expanding."}}, {"myth": "Satisficing is a strategy used by lazy business owners.", "truth": "Satisficing is a perfectly rational and deliberate business strategy. Many sole traders choose to earn a comfortable income without the stress and risk of expansion. It reflects the personal priorities of the owner, not a lack of ambition or effort.", "check": {"question": "What does satisficing actually reflect about a business owner, according to this card?", "options": ["A lack of effort and ambition on the part of the owner", "An inability to calculate the business''s true profit figures", "The owner''s personal priorities, not laziness or ambition", "A legal requirement placed on all sole traders"], "answer": 2, "explain": "The card corrects the misconception that satisficing shows laziness, explaining it is a rational, deliberate strategy reflecting the owner''s personal priorities rather than a lack of ambition."}}]}, "tips": {"enabled": true, "items": [{"title": "One Point. Full Stop. Move On.", "html": "\n      <p>A <strong>''State'' or ''Identify''</strong> question needs one clear, specific point per mark. No explanation needed. No paragraphs. Just a direct answer.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific point = 1 mark ✅</li>\n        <li>A vague or generic answer = 0 marks ❌</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"To make money.\"</em><br/>\n      Too vague — could apply to any business in any situation.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"Survival.\"</em> or <em>\"To increase market share.\"</em><br/>\n      Specific, uses the correct business terminology.</p>\n      <p><strong>⚠️ For 2-mark ''State two'' questions:</strong> Write two separate points clearly numbered. Do NOT write one long sentence — examiners award one mark per identified objective.</p>\n    ", "check": {"question": "For a ''State'' or ''Identify'' question, how should marks be earned?", "options": ["A judgement followed by a justification using case study detail", "A full paragraph explaining the reasoning behind each point", "One clear, specific point per mark, with no explanation needed", "One long combined sentence covering all required points"], "answer": 2, "explain": "The card''s formula states one clear, specific point equals 1 mark, while a vague or generic answer earns 0 marks — no explanation is needed for ''State'' or ''Identify'' questions."}}, {"title": "Point + Reason = Full Marks", "html": "\n      <p>A 2-mark <strong>''Explain''</strong> question wants a point AND a reason. You must go one step further than just naming the objective.</p>\n      <p><strong>The Formula:</strong> Make a point (K) → Briefly explain why using the business context (APP)</p>\n      <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n      <em>\"The Works may have a different objective to Saranne because The Works is bigger.\"</em><br/>\n      Names a difference but doesn''t explain why size leads to different objectives.</p>\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"The Works is a large established retailer (APP) so it can pursue growth or profit, whereas Saranne is starting a new business and must focus on survival to get through the first few months (APP).\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Both marks require context. Generic answers about \"bigger businesses want more profit\" without linking to the case study will only score 1 mark at best.</p>\n    ", "check": {"question": "What must a 2-mark ''Explain'' answer include to score full marks?", "options": ["Three separate steps: understanding, application, and analysis", "A point plus a reason, explained using the business context", "Only the correct keyword, with no further detail required", "A judgement followed by two pieces of case study evidence"], "answer": 1, "explain": "The card''s formula for ''Explain'' questions is: make a point (K) then briefly explain why using the business context (APP) — a generic answer without context scores only 1 mark at best."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n      <p>A 3-mark <strong>''Analyse''</strong> question is worth exactly three steps. Miss any one of them and you lose a mark. This is the most tested question format in this topic.</p>\n      <p><strong>The Three Steps:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the theory or benefit clearly using business terminology.</li>\n        <li><strong>Step 2 — Application (APP):</strong> Quote or directly reference the case study. You CANNOT score analysis marks without this.</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> Explain the <em>impact</em> on the business — specifically how it affects costs, revenue, reputation, profit, or operations.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n      <em>\"If Samsung values its people, it will make better products and earn more money.\"</em><br/>\n      No application to Samsung from the case study. No specific impact stated.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"When a business invests in its people, employees perform better at their jobs (U). For Samsung, which aims to produce superior products and compete with Apple (APP), well-trained workers can achieve this aim, leading to increased sales and greater revenue for the business (AN).\"</em></p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write everything you know about business aims. Answer the specific question — one focused chain of reasoning scores more than three vague points.</p>\n      <p><strong>Sentence Starters:</strong><br/>\n      \"When a business sets a high value on... (U)\"<br/>\n      \"In the case of [Business Name], which... (APP)\"<br/>\n      \"This means that... / As a result, the business will... (AN)\"</p>\n    ", "check": {"question": "What are the three required steps for a 3-mark ''Analyse'' question, according to this card?", "options": ["State, Explain, Evaluate fully", "Understanding, Application, Analysis", "Knowledge, Judgement, Justification", "Definition, Example, Conclusion"], "answer": 1, "explain": "The card calls this ''the Holy Trinity'': Understanding (state the theory), Application (reference the case study), and Analysis (explain the impact) — missing any one loses a mark."}}, {"title": "Judge It — Then Justify It With Context", "html": "\n      <p>The 3-mark OCR evaluation question in this topic is unique — it awards <strong>1 mark for a clear judgement</strong> and <strong>2 marks for a precise, contextual justification</strong>.</p>\n      <p><strong>The Structure:</strong></p>\n      <ul>\n        <li><strong>Judgement (1 mark):</strong> Make a clear, decisive statement. No explanation needed yet. \"I think people are more important than technology for Samsung.\"</li>\n        <li><strong>Justification (2 marks):</strong> Use specific detail from the case study to explain WHY. This must go beyond simply repeating the case study — you need to show how the evidence supports your judgement.</li>\n      </ul>\n      <p><strong>❌ Bad Justification (0–1 marks):</strong><br/>\n      <em>\"Because Samsung wants to produce superior products and people help them do this.\"</em><br/>\n      This just repeats the case study without showing understanding of the link.</p>\n      <p><strong>✅ Good Justification (2 marks):</strong><br/>\n      <em>\"Even the best technology still requires skilled people to design, operate, and improve it. If Samsung places high value on its people, workers will be motivated to outperform rivals like Apple — the business most likely to threaten Samsung''s position as a world leader.\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> You must use the case study detail — not just repeat it. Examiners call this \"using (not simply repeating)\" the information.</p>\n      <p><strong>Sentence Starters:</strong><br/>\n      \"I believe that [option] is more important because... (Judgement)\"<br/>\n      \"The evidence from the case study shows that... (Justification)\"<br/>\n      \"Without [factor], Samsung would not be able to... (Justification)\"</p>\n    ", "check": {"question": "In this 3-mark ''Judgement + Justification'' evaluate question, how are the marks split?", "options": ["1 mark for the judgement and 2 marks for a second, opposing judgement", "3 marks are given only for restating the case study in full", "All 3 marks are awarded solely for using the word ''because''", "1 mark for a judgement, 2 marks for a contextual justification"], "answer": 3, "explain": "The card states this question type awards 1 mark for a clear judgement and 2 marks for a justification that uses specific case study detail, not simply repeats it."}}, {"title": "Argue Both Sides, Then Deliver Your Verdict", "html": "\n      <p>A 7-mark evaluation question wants you to build a <strong>balanced argument</strong> and reach a <strong>justified conclusion</strong>. Think of it as two 3-mark analyses followed by a decision.</p>\n      <p><strong>The Four-Paragraph Structure:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — For:</strong> Knowledge + Understanding of why one objective/option is beneficial (U)</li>\n        <li><strong>Paragraph 2 — For (Applied):</strong> Apply to the case study business + analyse the impact (APP + AN)</li>\n        <li><strong>Paragraph 3 — Against:</strong> Apply the counter-argument to the case study + analyse (APP + AN)</li>\n        <li><strong>Paragraph 4 — Conclusion:</strong> Decision + Context-linked reason + Impact/consequence (EVAL ×3)</li>\n      </ul>\n      <p><strong>The Conclusion Must Include:</strong></p>\n      <ul>\n        <li><strong>Decision:</strong> \"Overall, I recommend that WYW should/should not have profit as its objective...\"</li>\n        <li><strong>Context:</strong> \"...because, as the text states, the business is a partnership and both owners need to agree...\"</li>\n        <li><strong>Impact/Reasoning:</strong> \"...and without an agreed objective, the business risks conflict between partners which could threaten its long-term success.\"</li>\n      </ul>\n      <p><strong>🚫 Common Mistake:</strong> Students write a conclusion that just repeats their earlier points. A conclusion that adds no new reasoning scores zero evaluation marks. Use the \"It depends on...\" or \"However, this is only true if...\" formula to add depth.</p>\n      <p><strong>⚠️ Do NOT write a conclusion for 3-mark or 6-mark questions</strong> — there are zero evaluation marks available for those.</p>\n    ", "check": {"question": "What must a strong conclusion in a 7-mark evaluate answer do, according to this card?", "options": ["Add new reasoning: a decision, context, and impact — not repeats", "List every objective covered in the topic, regardless of relevance", "Avoid making a decision so as not to seem biased", "Simply restate the strongest point made in paragraph one"], "answer": 0, "explain": "The card warns that a conclusion which just repeats earlier points scores zero evaluation marks; it must include a decision, context, and impact/reasoning to add new depth."}}, {"title": "No Case Study = No APP or AN Marks", "html": "\n      <p>This is the single biggest reason students lose marks in Business exams. You <strong>cannot</strong> score application or analysis marks without directly referencing the case study business.</p>\n      <p><strong>The Rule:</strong> Every analysis point must be anchored to the specific business in the question.</p>\n      <p><strong>❌ No Application (loses APP + AN marks):</strong><br/>\n      <em>\"A business that values its people will produce better products and earn more profit.\"</em><br/>\n      This could describe any business. The examiner awards zero application marks.</p>\n      <p><strong>✅ With Application:</strong><br/>\n      <em>\"Samsung, which faces strong competition from Apple in the technology market (APP), will be able to produce superior products if its people are well-trained, leading to repeat customers and higher long-term revenue (AN).\"</em></p>\n      <p><strong>How to Apply:</strong> Use the business''s name, quote figures or facts from the case study (e.g. \"135 stores\", \"over 4,800 employees\", \"7% of UK electricity\"), or reference the specific market or situation described.</p>\n      <p><strong>Sentence Starters for Application:</strong><br/>\n      \"In the case of [Business Name]...\"<br/>\n      \"As the text states, [Business] operates in...\"<br/>\n      \"Because [Business] has [specific detail from case study]...\"</p>\n    ", "check": {"question": "According to this card, what happens if an analysis point does not reference the case study business?", "options": ["The examiner still awards full marks if the knowledge point is correct", "The examiner awards zero application and analysis marks", "Only the analysis mark is lost, but application is still awarded", "It only affects marks on 7-mark evaluate questions, not shorter ones"], "answer": 1, "explain": "The card states you cannot score application or analysis marks without directly referencing the case study business — a generic point ''could describe any business'' and earns zero application marks."}}]}, "exam": {"enabled": true, "questions": [{"question": "A business has recently changed its main objective from ''survival'' to ''growth''. What would most likely explain this change of objective?", "marks": 1, "hint": "Think about what would make a business feel confident enough to stop focusing on survival and start focusing on getting bigger.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — The business is experiencing high demand</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A — The business has become too big:</strong> Becoming too big is not a reason to pursue growth — it would be a reason to consolidate or reduce operations, not expand further.</li><li><strong>B — The business has reduced its productivity:</strong> Reduced productivity would likely harm the business''s performance, making survival more relevant — not growth.</li><li><strong>D — The business needs to lower its costs:</strong> Lowering costs is a financial management decision, not a reason to change from survival to growth as an objective.</li></ul></div>"}, {"question": "What would help the company achieve its objective?", "marks": 1, "hint": "Market share is about reaching more customers and selling more than competitors. Which option makes it easier for more customers to buy DM''s drinks?", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — Increasing the number of retail outlets it supplies</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A — Increasing the cost:</strong> Higher costs reduce profit margins but do not directly increase sales. If costs rise but prices stay the same, profit falls.</li><li><strong>C — Increasing the price:</strong> Higher prices would likely reduce demand, meaning fewer cans are sold. This would decrease, not increase, market share.</li><li><strong>D — Increasing processing time:</strong> Slower order processing would delay stock reaching retailers and frustrate customers, likely reducing sales and market share.</li></ul></div>"}, {"question": "What would explain this difference in objectives?", "marks": 1, "hint": "Think about which type of business typically focuses on survival and why.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — Firm B is a start-up business and Firm A is an established business</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A:</strong> A business with a low market share might want growth, not profit — and a high market share business would likely be aiming for profit too. This does not explain the survival objective.</li><li><strong>C:</strong> Having less determination does not lead to a profit objective — it is not a logical or relevant business reason for choosing profit over survival.</li><li><strong>D:</strong> Confidence is not a factor in choosing survival as an objective. Start-up businesses focus on survival due to competition and lack of customer base — not because owners lack confidence.</li></ul></div>"}, {"question": "What would explain this change of objective?", "marks": 1, "hint": "The objective has gone from profit DOWN to survival — something has made things harder. What would reduce sales and threaten the business?", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — The hair salon is experiencing intense competition</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A:</strong> Achieving the profit objective would likely lead to a higher objective such as growth — not a switch back down to survival.</li><li><strong>B:</strong> Gaining new customers would improve revenue and profit, making survival less of a concern — not more.</li><li><strong>D:</strong> Being established suggests stability — an established business would typically aim for profit or growth, not survival.</li></ul></div>"}, {"question": "Which of the following is NOT a possible reason why the two businesses have different objectives?", "marks": 1, "hint": "Look for the option that has NO logical link to why a business would choose a different objective.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — There is little innovation in the clothing industry</strong></p></div><div class=\"marks-section\"><h5>Why the other options ARE possible reasons</h5><ul><li><strong>A:</strong> Different products (coats vs jeans) may target different markets with different levels of competition or profit potential, influencing objectives.</li><li><strong>B:</strong> Making designer clothing suggests a high-price, service-focused strategy — the business is likely pursuing profit or reputation rather than growth by volume.</li><li><strong>D:</strong> Different owners have different personal ambitions, attitudes to risk, and values — this directly affects which objectives they set for the business.</li></ul></div>"}, {"question": "A business whose main objective is to survive is likely to be:", "marks": 1, "hint": "Think about what ''survival'' actually means — what is the business trying to do?", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — Working hard to stay in existence</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A:</strong> Growing market share is a sign of expansion and success — the opposite of a survival-focused business.</li><li><strong>B:</strong> Making a large profit means the business is performing well and would likely pursue growth or profit maximisation — not survival.</li><li><strong>C:</strong> A well-established and successful business would not have survival as its objective — it would focus on maintaining or growing profit.</li></ul></div>"}, {"question": "Analyse one way Superdry''s business objectives may change as the business grows. [3 marks]", "marks": 3, "hint": "Focus on HOW the objective itself changes — not what the business physically does. Think about what a growing business starts to aim for that it didn''t need to aim for before. You MUST reference Superdry from the case study to earn APP and AN marks.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1a K×1, AO2 APP×1, AO3a AN×1)</h5><ul><li><strong>Knowledge (1 mark):</strong> Any valid point about how objectives become more ambitious/broader as a business grows — e.g. objectives widen, become more diverse, or become more ambitious. Do NOT accept ''growth'' as the knowledge point (it is stated in the question).</li><li><strong>Application (1 mark):</strong> Answer must be applied to Superdry using case study detail — e.g. reference to 135 stores, competition, selling through Next, £41.4m investment, 4,800 employees, high quality commitment. No further marks without knowledge.</li><li><strong>Analysis (1 mark):</strong> Impact on business operations — an action Superdry needs to take as a result of the changing objective (not the outcome of achieving it). E.g. will need to do more research, change pricing strategy, increase advertising, contact solicitors.</li></ul></div><div class=\"marks-section\"><h5>Examiner Guidance</h5><ul><li>The question asks HOW objectives change, not WHY. Answers must focus on the objective itself being affected.</li><li>Do NOT award examples of business growth (e.g. \"open more shops\") — the question is about the objective, not the action.</li><li>Accept both general (e.g. \"objectives become more ambitious\") and specific (e.g. \"profit target will be higher\") responses.</li></ul></div><div class=\"marks-section\"><h5>Exemplar Responses</h5><p><strong>Model Answer 1:</strong> As Superdry grows, its objectives also become more ambitious (K). It may want to have far more than 135 shops in the UK and Europe (APP), so will need to carry out a great deal of research to find viable new locations (AN).</p><p><strong>Model Answer 2:</strong> As a business grows, it is likely to want to generate more profit (K). For Superdry, which already operates in a competitive market facing rivals of all sizes (APP), this may mean changing its pricing strategy to attract even more customers (AN).</p></div>"}, {"question": "Explain how the construction of Hinkley Point C nuclear power station may help EDF to achieve one business objective. [2 marks]", "marks": 2, "hint": "Name a specific business objective (K), then use a fact from the case study about Hinkley Point C to explain how it helps EDF achieve that objective (APP).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a K×1, AO2 APP×1)</h5><ul><li><strong>Knowledge (1 mark):</strong> Identify a valid business objective — e.g. profit, revenue, market share, growth, survival, output. Vague answers such as \"be more competitive\" are NOT accepted.</li><li><strong>Application (1 mark):</strong> Use specific detail from the case study about Hinkley Point C to explain how it helps achieve the objective. No application marks without knowledge first.</li></ul></div><div class=\"marks-section\"><h5>Acceptable Application Details</h5><ul><li>Largest producer of low-carbon electricity</li><li>Will provide 7% of the UK''s electricity</li><li>Expected to operate for 60 years</li><li>Due to open in 2025</li><li>Will employ over 900 people once operational</li></ul><p><em>Do NOT accept</em> \"nuclear power station\" or \"construction\" as application — they are stated in the question.</p></div><div class=\"marks-section\"><h5>Exemplar Responses</h5><p><strong>Model Answer 1:</strong> The construction will lead to more profit for EDF (K) as Hinkley Point C will supply an extra 7% of the UK''s electricity (APP).</p><p><strong>Model Answer 2:</strong> The new power station should help EDF increase its output (K) and from 2025 onwards (APP) generate higher revenue from additional electricity supply.</p></div>"}, {"question": "State two possible objectives for a business. [2 marks]", "marks": 2, "hint": "Name two of the five main business objectives. You do not need to explain them — just name them clearly.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a ×2)</h5><ul><li>1 mark per correctly identified business objective, up to a maximum of 2 marks.</li><li>Accepted answers: Profit / Growth (e.g. to get bigger / have more shops) / Market share / Survival / Providing good service</li></ul></div>"}, {"question": "Explain why the objectives of The Works may differ to those of Saranne''s new business. [2 marks]", "marks": 2, "hint": "Think about what stage each business is at. The Works is large and established — what does that mean for its objectives? Saranne is just starting — what does that mean for hers?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2 ×2)</h5><ul><li><strong>1 mark:</strong> Application of different business objectives for The Works and Saranne — both must be referenced.</li><li><strong>1 further mark:</strong> Explanation of how an established business''s objectives differ from those of a business starting up. Both marks require implicit or explicit context from the case study.</li></ul></div><div class=\"marks-section\"><h5>Exemplar Response</h5><p>Once established, a business like The Works may have the ambition to aim for greater profits or further growth across more stores (APP), whereas Saranne''s business, which is just starting, is likely to focus on simply surviving the first few months and establishing itself in the market (APP).</p></div>"}, {"question": "The ''objectives of a business'' are:", "marks": 1, "hint": "Think about the definition of the word ''objective'' — it''s about targets and goals, not physical things.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — What the business intends to achieve</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A:</strong> Negative comments are stakeholder feedback — this has nothing to do with the goals the business sets for itself.</li><li><strong>B:</strong> Buildings and equipment are physical assets — these are resources the business uses, not goals it aims for.</li><li><strong>C:</strong> Products are what the business sells — a business might sell trainers, but its objective might be to make a profit or grow its market share.</li></ul></div>"}, {"question": "Explain how Boohoo''s objectives may have changed since 2006. [2 marks]", "marks": 2, "hint": "Think about what a new business starting in 2006 would need to focus on — and then contrast that with what a global business selling in 100 countries now focuses on.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b U×1, AO2 APP×1)</h5><ul><li><strong>Understanding (1 mark):</strong> Show understanding of a business objective — e.g. survival, profit, growth, establishing brand name.</li><li><strong>Application (1 mark):</strong> Explain how this objective has changed over time for Boohoo specifically, using detail from the case study.</li></ul></div><div class=\"marks-section\"><h5>Acceptable Answers</h5><ul><li>Boohoo would have had a survival objective in 2006 but now pursues profit or growth.</li><li>The business may have been trying to establish the brand name when it started, but now focuses on becoming the market leader.</li><li>Boohoo is likely pursuing profits now to reward the owners/shareholders after years of expansion.</li></ul></div><div class=\"marks-section\"><h5>Exemplar Response</h5><p>Boohoo would have focused on survival when it launched in 2006 (U), but now that the business has expanded organically to sell in over 100 countries with millions of website users per month (APP), it is likely to be pursuing profit or further growth to reward the founders for the risks they took.</p></div>"}, {"question": "Explain why a business such as Samsung sets out its aims and objectives. [2 marks]", "marks": 2, "hint": "First state what a business aim IS (knowledge), then explain why Samsung specifically would want to set one — use the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a K×1, AO2 APP×1)</h5><ul><li><strong>Knowledge (1 mark):</strong> Show knowledge of what an aim is — e.g. a goal the business tries to achieve; a target the business sets itself.</li><li><strong>Application (1 mark):</strong> Explain why Samsung specifically sets aims, using case study material — e.g. to maintain its position against Apple; to guide production of superior products; to give direction to its workforce.</li></ul></div><div class=\"marks-section\"><h5>Exemplar Responses</h5><ul><li>Samsung will set out aims so that it can maintain the high level of quality needed to attract customers who can see what it is trying to achieve.</li><li>Samsung sets aims and objectives to help it compete with businesses such as Apple.</li></ul></div>"}, {"question": "Analyse one benefit to Samsung of setting a high value on its people. [3 marks]", "marks": 3, "hint": "Use the three-step formula: What is the benefit of valuing people? (U) → How does this apply to Samsung from the case study? (APP) → What is the financial or operational impact on Samsung? (AN)", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b U×1, AO2 APP×1, AO3a AN×1)</h5><ul><li><strong>Understanding (1 mark):</strong> Show understanding of the connection between valuing people and business aims — e.g. with good people, better products are made; motivated workers produce higher quality output.</li><li><strong>Application (1 mark):</strong> Relate to Samsung using case study — e.g. Samsung''s aim to produce superior products; competing with Apple; producing quality electrical goods. No APP or AN marks without Understanding first.</li><li><strong>Analysis (1 mark):</strong> Explain the effect on Samsung — e.g. increased sales, greater revenue, more repeat customers, stronger market position.</li></ul></div><div class=\"marks-section\"><h5>Exemplar Response</h5><p>With good, well-trained people in a business, better quality products are made (U). Samsung, with valued employees who are skilled at their jobs, can produce quality electrical goods that help to achieve the aim of creating superior products (APP). If Samsung achieves this aim, it can increase its sales, bringing greater revenue to the business and strengthening its position against Apple (AN).</p></div>"}, {"question": "Analyse one benefit to Samsung of setting a high value on its technologies. [3 marks]", "marks": 3, "hint": "Use the same three-step formula: What is the benefit of leading technology? (U) → How does this link to Samsung''s specific situation? (APP) → What impact does this have on Samsung''s performance? (AN)", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b U×1, AO2 APP×1, AO3a AN×1)</h5><ul><li><strong>Understanding (1 mark):</strong> Show understanding of the connection between leading technology and business aims — e.g. better technology = better products; technology improves efficiency and reliability.</li><li><strong>Application (1 mark):</strong> Apply to Samsung using case study material — e.g. Samsung''s competitive market with Apple; aim to remain a world-leading producer; creating superior products.</li><li><strong>Analysis (1 mark):</strong> Explain the impact — e.g. more reliable products lead to repeat customers; greater market share; ability to charge premium prices; more revenue.</li></ul></div><div class=\"marks-section\"><h5>Exemplar Response</h5><p>With leading technology, businesses are able to produce better, more reliable products (U). Samsung operates in a highly competitive market and must have the best technology to achieve its aim of remaining a world-leading producer (APP). If Samsung achieves this, it will gain more repeat customers who trust and return to buy Samsung products over many years, increasing long-term revenue (AN).</p></div>"}, {"question": "Evaluate whether Samsung''s people or technologies has the greatest influence on Samsung being able to achieve its aims. [3 marks]", "marks": 3, "hint": "Make a clear choice first (1 mark). Then justify your choice using specific detail from the case study — you must go beyond simply repeating the case study text to earn both justification marks.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b Evaluation ×3)</h5><ul><li><strong>Judgement (1 mark):</strong> A clear, simple statement choosing either people OR technology as having the greatest influence. No explanation needed for this mark.</li><li><strong>Justification (up to 2 marks):</strong> A clear, contextual justification using (not simply repeating) case study information. Must explain WHY the chosen factor is more important than the other in helping Samsung achieve its aims.</li></ul></div><div class=\"marks-section\"><h5>Exemplar Responses</h5><p><strong>Choosing People:</strong> I think having an aim of placing value on people will have the most effect on Samsung (JUDGEMENT). Putting value on people means workers at Samsung will perform better, enabling the company to produce reliable world-beating products. Even the best technology needs skilled people to design, build, and improve it (JUSTIFICATION ×2).</p><p><strong>Choosing Technology:</strong> I believe Samsung''s technology has the greatest influence on achieving its aims (JUDGEMENT). Workers need to be attracted to Samsung rather than Apple. If Samsung has leading technology, it can produce superior products that stand out in the market — and this is what will directly keep it ahead of Apple as a world-leading producer (JUSTIFICATION ×2).</p></div>"}, {"question": "Explain why WYW needed a new objective in the second year. [2 marks]", "marks": 2, "hint": "Why is survival no longer the right objective once the business is making a profit? What has changed for WYW? (Apply to the case study.)", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks</h5><ul><li><strong>1 mark:</strong> Explain why the objective needs to change — survival is no longer relevant once a business is established and making profit.</li><li><strong>1 mark:</strong> Apply to WYW specifically — the business survived the first year and is now profitable, so a new, more ambitious objective is needed to guide future decisions.</li></ul></div>"}, {"question": "Evaluate whether WYW should have profit as a business objective. [7 marks]", "marks": 7, "hint": "Argue BOTH sides: why profit is a good objective for WYW, AND why it might not be the best objective (e.g. growth might be better). Use TWO pieces of information from the case study. End with a justified conclusion that makes a decision and explains why.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks</h5><ul><li><strong>Application ×2 (APP):</strong> Use two specific pieces of information from the case study to support the argument.</li><li><strong>Analysis ×2 (AN):</strong> Analyse each piece of information — explain the implication for WYW as a business.</li><li><strong>Evaluation ×3 (EV):</strong> Make a clear decision + contextual reason + impact or consequence of that decision.</li></ul></div><div class=\"marks-section\"><h5>Guidance</h5><ul><li>Students must engage with BOTH sides of the argument to access the highest evaluation marks.</li><li>The conclusion must go beyond repeating earlier points — it should add a condition, context, or consequence.</li><li>Accept either judgement (profit OR growth/other objective) provided it is well-justified with case study detail.</li></ul></div><div class=\"marks-section\"><h5>Examiner Tips</h5><ul><li>Use \"It depends on...\" or \"However, this is only appropriate if...\" to strengthen the conclusion.</li><li>Avoid knowledge dumping — do not list everything you know about profit. Apply each point to WYW.</li><li>The question is about whether profit is the BEST objective — compare it to alternatives like growth.</li></ul></div>"}]}}'::jsonb),
('business', '1-5-stakeholders-in-business', '1.5 Stakeholders in Business', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>This unit is about understanding who has an interest in a business and how they interact with it. Before studying how stakeholders affect businesses (and vice versa), you must be confident with the following key terms.</p>\n<ul>\n  <li><strong>Stakeholder:</strong> An individual or group of people who have an interest in a business and are affected by, or can affect, its activities.</li>\n  <li><strong>Internal stakeholder:</strong> A stakeholder who is part of the business itself — specifically the owners and employees.</li>\n  <li><strong>External stakeholder:</strong> A stakeholder who exists outside the business — including customers, suppliers, the government and the local community.</li>\n  <li><strong>Shareholder:</strong> An owner of shares in a limited company. All shareholders are stakeholders, but not all stakeholders are shareholders.</li>\n  <li><strong>Dividend:</strong> A share of the profits paid out to shareholders as a reward for their investment.</li>\n  <li><strong>Objective:</strong> A specific goal or target that a stakeholder or business is trying to achieve.</li>\n  <li><strong>Conflicting objectives:</strong> When two or more stakeholder groups want different things from the same business, creating tension or disagreement.</li>\n  <li><strong>Stakeholder influence:</strong> The power a stakeholder group has to change or shape how a business operates.</li>\n</ul>\n<p><strong>⚠️ Common Misconception:</strong> Do NOT confuse <strong>stakeholders</strong> and <strong>shareholders</strong>. A shareholder is one type of stakeholder (an owner of shares). A sole trader has no shareholders — but they are still a stakeholder (as the owner). Getting this wrong in an exam can cost you several marks.</p>", "check": {"question": "A sole trader has no shareholders. According to the key terms studied in this topic, does the sole trader still count as having stakeholders?", "options": ["No, because only limited companies can have stakeholders", "Yes, but only if the sole trader also owns shares in their own business", "Yes, stakeholders include anyone with an interest, not just shareholders", "No, because a sole trader has no shareholders and therefore no stakeholders"], "answer": 2, "explain": "The card states a sole trader has no shareholders but is still a stakeholder as the owner — all shareholders are stakeholders, but not all stakeholders are shareholders."}}, {"title": "Internal vs External Stakeholders", "html": "<p>Stakeholders are divided into two main categories depending on whether they are inside or outside the business.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">🏢 Internal Stakeholders</div>\n<div class=\"pro-item\"><strong>Owners:</strong> For a sole trader or partnership, the owner(s) also work in the business. For a limited company, shareholders are the owners. They want profit, growth and a return on their investment.</div>\n<div class=\"pro-item\"><strong>Employees:</strong> Anyone who works for the business — from managers to shop floor workers. They rely on the business for pay, job security, and working conditions.</div>\n</div>\n<div>\n<div class=\"col-head\">🌍 External Stakeholders</div>\n<div class=\"con-item\"><strong>Customers:</strong> People who buy goods/services from the business. They want quality, fair prices and good customer service.</div>\n<div class=\"con-item\"><strong>Suppliers:</strong> Businesses that provide raw materials or goods. They want regular, large, well-paid orders.</div>\n<div class=\"con-item\"><strong>Government:</strong> Wants businesses to pay taxes, create jobs and follow the law.</div>\n<div class=\"con-item\"><strong>Local Community:</strong> Wants businesses to provide jobs, avoid pollution/noise, and contribute to local prosperity.</div>\n</div>\n</div>\n<p>There may be other stakeholders depending on the business — for example, a bank (lender) or a charity partner. The key is always to think about <strong>who has an interest in that specific business</strong>.</p>", "check": {"question": "Which of the following is classified as an EXTERNAL stakeholder?", "options": ["An employee working on the shop floor", "A supplier providing raw materials", "A shareholder who works as a company director", "A partner who co-owns the business"], "answer": 1, "explain": "Suppliers exist outside the business, making them external stakeholders, whereas employees, director-shareholders and owning partners are all internal stakeholders because they are part of the business itself."}}, {"title": "Objectives of Each Stakeholder Group", "html": "<p>Each stakeholder group has different goals — and understanding <em>why</em> they have those goals is just as important as knowing what they are.</p>\n<ul>\n  <li><strong>Owners/Shareholders:</strong> To make <strong>profit</strong> and receive dividends. They want the business to grow so their investment increases in value. They may also make decisions to <em>cut costs</em> (e.g. make workers redundant) to protect profits.</li>\n  <li><strong>Employees:</strong> To receive fair <strong>wages</strong>, job <strong>security</strong>, good <strong>working conditions</strong>, and enjoyment from social aspects of work. Employees can go on strike if their needs are not met.</li>\n  <li><strong>Customers:</strong> To receive <strong>quality products</strong> at <strong>affordable prices</strong>, with good customer service and a reliable range of goods. If unhappy, customers simply stop buying.</li>\n  <li><strong>Suppliers:</strong> To receive <strong>large, frequent orders</strong> and be <strong>paid on time</strong>. If the business fails, the supplier also loses income.</li>\n  <li><strong>Government:</strong> To collect <strong>taxes</strong> (income tax, corporation tax, VAT), encourage <strong>employment</strong>, and ensure businesses follow the law. More business activity = more tax revenue = more money for public services.</li>\n  <li><strong>Local Community:</strong> To see a <strong>prosperous, safe and healthy</strong> local area. They want jobs to be created, noise and pollution to be minimised, and businesses to contribute to community projects.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Barratt Developments plc</h4>\n  <p>Barratt is a leading UK house builder. Its shareholders want higher profits and dividends. Its employees want secure, well-paid jobs. Local communities want — or sometimes oppose — new housing developments. The government wants tax revenue and more homes to tackle the housing crisis. Suppliers of bricks, timber and cement want large, reliable orders. Every decision Barratt makes will affect <em>all</em> of these groups differently.</p>\n</div>", "check": {"question": "What is a supplier''s main objective when dealing with a business, according to this topic?", "options": ["To receive large, frequent orders paid on time", "To receive dividends from the company''s profits", "To secure job security and fair wages", "To ensure the business follows environmental law"], "answer": 0, "explain": "The card states suppliers want large, frequent orders and to be paid on time — dividends relate to owners, job security to employees, and legal compliance to government."}}, {"title": "Conflicting Objectives Between Stakeholders", "html": "<p>One of the most important things you need to understand for the exam is that stakeholders often want <strong>different and opposing things</strong>. This creates conflict which can directly affect business decisions.</p>\n<ul>\n  <li><strong>Owners vs Employees:</strong> Owners want to <em>minimise costs</em> to maximise profit — this means keeping wages low. Employees want <em>higher wages</em> and better conditions. This conflict can lead to strikes, which disrupts the business.</li>\n  <li><strong>Owners vs Customers:</strong> Owners want to charge <em>high prices</em> to increase revenue and profit. Customers want <em>low prices</em> and high quality. If prices are too high, customers go to a competitor.</li>\n  <li><strong>Business Growth vs Local Community:</strong> A business expanding its factory creates jobs (positive), but may also increase noise, traffic and pollution (negative), making local residents unhappy.</li>\n  <li><strong>Employees vs Customers:</strong> Employees want higher wages, which increases business costs. To cover these higher costs, the business may raise its prices, meaning customers pay more — directly harming the customer''s objective of affordable prices.</li>\n</ul>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ When Interests Align</div>\n<div class=\"pro-item\">A growing, profitable business benefits owners (higher profit), employees (more jobs), suppliers (more orders), government (more tax) and the local community (more prosperity).</div>\n</div>\n<div>\n<div class=\"col-head\">✗ When Interests Conflict</div>\n<div class=\"con-item\">Cutting the workforce to save costs helps owners (higher profit margin) but harms employees (job losses), local community (unemployment rises) and potentially customers (reduced service).</div>\n</div>\n</div>", "check": {"question": "Why do owners and employees often have conflicting objectives, according to this topic?", "options": ["Owners want more competitors in the market while employees want fewer", "Owners want low wage costs for profit; employees want higher pay", "Owners and employees actually always want exactly the same outcome", "Owners want to raise prices while employees want prices lowered"], "answer": 1, "explain": "The card explains that owners want to minimise costs (keeping wages low) to maximise profit, while employees want higher wages and better conditions — a conflict that can lead to strikes."}}, {"title": "The Effect Business Activity Has on Stakeholders", "html": "<p>Business decisions ripple outward and affect many different stakeholders. The same decision can be <strong>positive for some stakeholders and negative for others</strong>.</p>\n<p><strong>When a business GROWS:</strong></p>\n<ul>\n  <li><strong>Employees</strong> — more jobs are created, improving job security and pay prospects.</li>\n  <li><strong>Suppliers</strong> — receive larger, more frequent orders, increasing their own revenue.</li>\n  <li><strong>Government</strong> — collects more tax from the business and its employees; pays less in unemployment benefits.</li>\n  <li><strong>Customers</strong> — benefit from a wider product range and potentially lower prices due to economies of scale.</li>\n  <li><strong>Owners</strong> — earn higher profits and potentially larger dividends.</li>\n  <li><strong>Local Community</strong> — greater employment in the area raises local spending and reduces poverty.</li>\n</ul>\n<p><strong>When a business SHRINKS or CLOSES:</strong></p>\n<ul>\n  <li><strong>Employees</strong> — face redundancy and loss of income.</li>\n  <li><strong>Suppliers</strong> — lose orders; in extreme cases they may also go out of business.</li>\n  <li><strong>Government</strong> — sees fewer tax receipts and must pay more in unemployment benefits.</li>\n  <li><strong>Local Community</strong> — suffers from increased unemployment, reduced local spending, and potential social problems.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Heathrow Third Runway</h4>\n  <p>The proposed expansion of Heathrow Airport illustrates perfectly how the same business activity can affect stakeholders in opposite ways. A third runway would create thousands of jobs (positive for employees and local community), boost import/export opportunities (positive for businesses and government tax), yet also cause significant noise pollution, increased traffic, and environmental damage to local areas (negative for local residents). This is why stakeholder conflicts arise around major developments.</p>\n</div>", "check": {"question": "When a business shrinks or closes, what is the most likely effect on the government as a stakeholder?", "options": ["Higher tax receipts from redundancy payments", "No effect, since government revenue depends only on VAT", "Reduced need to spend money on public services", "Lower tax receipts and higher unemployment benefit payments"], "answer": 3, "explain": "The card states that when a business shrinks or closes, the government sees fewer tax receipts and must pay more in unemployment benefits."}}, {"title": "The Effect Stakeholders Have on Business", "html": "<p>Stakeholders do not just passively experience the effects of business decisions — they actively <strong>influence</strong> how a business operates.</p>\n<ul>\n  <li><strong>Owners:</strong> Can make major decisions such as making workers redundant, changing strategy, or investing in growth. Their primary goal of profit drives most major business choices.</li>\n  <li><strong>Employees:</strong> Can go on <strong>strike</strong> to push for higher wages or better conditions. This disrupts production, damages reputation and can cost the business significant revenue. Highly motivated, reliable employees are also the foundation of business success.</li>\n  <li><strong>Customers:</strong> Can <strong>boycott</strong> a business if unhappy with prices, quality or ethics. A customer boycott leads to lower sales, damaged reputation, and reduced profit. Conversely, loyal customers drive growth.</li>\n  <li><strong>Suppliers:</strong> Poor quality or unreliable suppliers can <strong>damage a business''s reputation</strong>. If a supplier to a car manufacturer provides faulty parts, the car maker''s reputation suffers and sales fall.</li>\n  <li><strong>Government:</strong> Can affect business through:\n    <ul>\n      <li>Changing <strong>tax rates</strong> (higher tax = less spending power / less profit to reinvest)</li>\n      <li>Offering <strong>grants</strong> to help businesses establish themselves</li>\n      <li>Changing <strong>laws</strong> (e.g. National Living Wage means businesses must pay more)</li>\n      <li><strong>Government spending</strong> on roads, railways and defence increases business activity</li>\n    </ul>\n  </li>\n  <li><strong>Local Community:</strong> Can <strong>protest or campaign</strong> against business developments they oppose. Sufficient community opposition can force businesses to alter or abandon their plans entirely.</li>\n</ul>", "check": {"question": "How can customers most directly influence a business, according to this topic?", "options": ["By setting the level of corporation tax", "By offering grants to help the business grow", "By boycotting the business over price or quality", "By changing employment law"], "answer": 2, "explain": "The card explains that customers can boycott a business, leading to lower sales, damaged reputation and reduced profit — tax, grants and law changes are actions taken by government."}}, {"title": "How Government Affects Business — Four Key Methods", "html": "<p>The government is a uniquely powerful stakeholder because it has <strong>legal authority</strong> over all businesses. It affects business activity in four main ways:</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">📋 Method 1: Taxation</div>\n<div class=\"pro-item\"><strong>Income tax cuts</strong> leave consumers with more spending money → businesses benefit from higher sales.</div>\n<div class=\"con-item\"><strong>Higher corporation tax</strong> on business profits → less money for reinvestment or dividends.</div>\n<div class=\"col-head\">📋 Method 2: Grants</div>\n<div class=\"pro-item\">Government <strong>grants to businesses</strong> help new firms establish themselves, boosting jobs and economic activity.</div>\n</div>\n<div>\n<div class=\"col-head\">📋 Method 3: Laws & Regulations</div>\n<div class=\"con-item\">The <strong>National Living Wage</strong> forces businesses to pay a minimum level of pay — this increases costs, especially for labour-intensive businesses like retail and hospitality.</div>\n<div class=\"col-head\">📋 Method 4: Government Spending</div>\n<div class=\"pro-item\">Spending on <strong>defence, roads and railways</strong> directly increases business activity and creates opportunities for suppliers and contractors.</div>\n</div>\n</div>\n<p><strong>Exam tip:</strong> When a question asks how government affects business, use one of these four methods — don''t just say \"the government can tax businesses.\" Say <em>which</em> tax and <em>what effect</em> it has on the specific business in the case study.</p>", "check": {"question": "Which of these is one of the four key methods by which government affects business, according to this topic?", "options": ["Deciding a business''s individual product prices", "Choosing which suppliers a business must use", "Setting a business''s marketing strategy", "Changing tax rates, such as corporation tax"], "answer": 3, "explain": "The four methods listed are taxation, grants, laws & regulations, and government spending — government does not set individual prices, marketing strategy or supplier choices for a business."}}, {"title": "Real-World Application: Stakeholders at Lineside Repairs", "html": "<div class=\"case-study-box\">\n  <h4>Case Study: Lineside Repairs (Steve Loy''s Garage)</h4>\n  <p>Steve Loy owns Lineside Repairs, a small garage in Elsecar, South Yorkshire. The business has operated since 1968 and services and repairs cars from the local community. Steve employs staff to help with repairs and must keep up to date with changing government regulations, including buying the correct equipment for MOT tests. He must also ensure noise from the business does not disturb nearby residents.</p>\n</div>\n<p><strong>Local Community as a Stakeholder:</strong></p>\n<ul>\n  <li><strong>Understanding:</strong> The local community is concerned about noise and pollution from the garage.</li>\n  <li><strong>Application:</strong> Noise from servicing and testing cars may disturb people living near the garage in Elsecar.</li>\n  <li><strong>Analysis:</strong> If the community protests, Lineside Repairs may have to change its working practices — for example, restricting testing hours — which could reduce its efficiency and profitability.</li>\n</ul>\n<p><strong>Government as a Stakeholder:</strong></p>\n<ul>\n  <li><strong>Understanding:</strong> The government changes regulations on MOT testing requirements.</li>\n  <li><strong>Application:</strong> Lineside Repairs must keep up to date with government regulations and buy the correct equipment to carry out MOT tests.</li>\n  <li><strong>Analysis:</strong> If new MOT regulations are introduced, Steve may need to invest in expensive new equipment. This increases costs significantly and reduces the profit available for the business.</li>\n</ul>", "check": {"question": "In the Lineside Repairs case study, after noting that new MOT regulations require expensive new equipment, what should the ''Analysis'' step conclude?", "options": ["A general definition of what an MOT test involves", "The bottom-line impact — higher costs, less profit", "A restatement of the government''s role in setting regulations", "A description of an unrelated stakeholder''s objective"], "answer": 1, "explain": "The case study analysis shows new MOT regulations force Steve to invest in expensive equipment, increasing costs and reducing the profit available to the business — the analysis step must land on this concrete business impact."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Stakeholder", "definition": "An individual or group of people who have an interest in a business and can be affected by, or affect, its activities."}, {"term": "Internal stakeholder", "definition": "A stakeholder who is part of the business itself — owners and employees."}, {"term": "External stakeholder", "definition": "A stakeholder who exists outside the business — customers, suppliers, government and local community."}, {"term": "Shareholder", "definition": "An owner of shares in a limited company who receives dividends as a reward for their investment."}, {"term": "Dividend", "definition": "A share of company profits distributed to shareholders."}, {"term": "Conflicting objectives", "definition": "When different stakeholder groups want opposing things from the same business — e.g. owners want low wages but employees want high wages."}, {"term": "Strike", "definition": "When employees refuse to work as collective action to pressure the business into meeting their demands."}, {"term": "Customer boycott", "definition": "When customers deliberately stop purchasing from a business, usually in protest, leading to lower sales and damaged reputation."}, {"term": "National Living Wage", "definition": "The legally required minimum pay rate set by the government that all businesses must pay their workers."}, {"term": "Corporation tax", "definition": "Tax charged by the government on business profits. Lower corporation tax means more profit available for owners."}, {"term": "Government grant", "definition": "Money given by government to a business that does not need to be repaid — used to encourage new businesses or economic development."}, {"term": "Objectives of owners", "definition": "To maximise profit, achieve business growth, and receive dividends or a return on investment."}, {"term": "Objectives of employees", "definition": "To receive fair wages, enjoy job security, have good working conditions, and gain job satisfaction."}, {"term": "Objectives of customers", "definition": "To receive quality products at affordable prices, with good customer service and a reliable product range."}, {"term": "Objectives of suppliers", "definition": "To receive large, frequent, well-paid orders and to maintain long-term relationships with reliable business customers."}, {"term": "Objectives of government", "definition": "To collect taxes, maintain high employment levels, and ensure businesses comply with laws and regulations."}, {"term": "Objectives of local community", "definition": "To benefit from local employment, reduced noise/pollution, and a prosperous, safe local environment."}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of the following is the correct definition of a stakeholder?", "options": ["Someone who objects to a business development they do not like", "A person or group of people who have an interest in business activity", "A person or group who always support business activity", "Someone who owns shares in a limited company"], "answer": 1, "explain": "Correct answer: A stakeholder is any person or group with an interest in a business — this includes owners, employees, customers, suppliers, government and the local community. They do not have to agree with or support the business to be a stakeholder. Option D describes a shareholder specifically, which is only one type of stakeholder."}, {"question": "Which of the following is an INTERNAL stakeholder?", "options": ["A customer", "A supplier", "An employee", "The local community"], "answer": 2, "explain": "Correct answer: Internal stakeholders are those who are part of the business itself — owners and employees. Customers, suppliers and the local community are all external stakeholders because they exist outside the business. A is external (they buy from the business). B is external (they supply to the business). D is external (they live near but are not part of the business)."}, {"question": "What is a benefit to the local community of a nearby carpet factory extending its operating hours?", "options": ["A wider choice of carpet designs will be available", "Increased road congestion from more lorries delivering textiles", "More job opportunities will be created", "The business will pay higher taxes"], "answer": 2, "explain": "Correct answer: Longer operating hours means the factory needs more workers, creating more job opportunities for local residents — this is a benefit to the local community. Option A relates to customers, not the local community specifically. Option B is a negative impact (congestion is a drawback). Option D may occur but it benefits the government more than the local community directly."}, {"question": "What impacts is a customer boycott MOST likely to have on a business?", "options": ["External growth, reduced profit, increased dividends", "Fewer customers, reduced profit, increased market share", "Improved brand image, more customers, increased profit", "Worsened reputation, lower sales, reduced profit"], "answer": 3, "explain": "Correct answer: A boycott means customers refuse to buy from the business. This leads to fewer sales (lower revenue), a worsened public reputation, and ultimately reduced profit. Option A is wrong — a boycott shrinks the business, not grows it. Option B is wrong — a boycott reduces market share, not increases it. Option C is completely wrong — a boycott damages brand image."}, {"question": "Which of the following is NOT a method by which government as a stakeholder can affect business activity?", "options": ["Increasing the taxation on business profits", "Giving grants to businesses to help new developments", "Increasing the number of MPs in parliament", "Spending money on new road projects"], "answer": 2, "explain": "Correct answer: Increasing the number of MPs in parliament is a political/electoral matter and does not directly affect how businesses operate. The other three options are all genuine ways government influences business: taxation changes affect profitability (A), grants support new businesses (B), and government infrastructure spending boosts business activity (D)."}, {"question": "Which of the following is NOT an external stakeholder?", "options": ["The local community", "An employee", "A supplier", "A customer of the business"], "answer": 1, "explain": "Correct answer: An employee is an INTERNAL stakeholder — they work inside the business. All other options (local community, supplier, customer) are external stakeholders because they exist outside the business itself."}, {"question": "The directors of a public limited company have decided to reduce the size of the workforce to increase profits. Which stakeholder is MOST likely to benefit from this decision?", "options": ["Customers", "Employees", "Owners", "The local community"], "answer": 2, "explain": "Correct answer: Reducing the workforce cuts wage costs, which increases profit margins. Owners (shareholders) benefit through higher dividends and increased share value. Employees (B) are directly harmed — some lose their jobs. Customers (A) do not directly benefit from this internal cost-cutting decision. The local community (D) is negatively affected by increased local unemployment."}, {"question": "Which of the following is an internal stakeholder of a business that trades as a partnership?", "options": ["A customer", "A shareholder", "A supplier", "An employee"], "answer": 3, "explain": "Correct answer: An employee works within the business, making them an internal stakeholder. A customer (A) and supplier (C) are external stakeholders. Crucially, a partnership does NOT have shareholders (B) — only limited companies have shareholders. This is a common exam trap: do not confuse stakeholders with shareholders, especially for sole traders and partnerships."}, {"question": "Which of the following are customers of a business MOST likely to be interested in?", "options": ["Employee wages", "Job security", "Product range", "Share dividends"], "answer": 2, "explain": "Correct answer: Customers are primarily interested in price, quality, and product range — things that affect their purchasing decision. Employee wages (A) and job security (B) are objectives of employees, not customers. Share dividends (D) are the concern of shareholders/owners."}, {"question": "Which of the following is MOST likely effect of bakery employees refusing to work?", "options": ["Deliveries to supermarkets will be disrupted", "Different ingredients will be used to make the bread loaves", "More bread loaves will be produced", "The bread market will become segmented"], "answer": 0, "explain": "Correct answer: If employees go on strike (refuse to work), production stops and deliveries to supermarket customers will be disrupted. This demonstrates the power employees have over business operations. Option B is incorrect — a strike does not change ingredients. Option C is the opposite of what happens. Option D is completely unrelated to a workforce dispute."}, {"question": "JLR has not given employees a pay rise for three consecutive years. Employees have contacted their trade union. Which stakeholder group is directly taking action here?", "options": ["Customers", "Suppliers", "Employees", "Local community"], "answer": 2, "explain": "Correct answer: The employees are the stakeholder group taking action by contacting their trade union. This is an example of how employees can influence business activity — through negotiation, collective bargaining or strike action — to try to achieve their objective of fair wages."}, {"question": "Tesco acquires one of its major food and drink suppliers. What is the MOST likely effect on Tesco''s customers?", "options": ["They will face higher prices due to reduced competition", "They may benefit from cheaper products as Tesco can lower its supply costs", "They will receive larger orders from Tesco", "They will pay higher dividends to Tesco shareholders"], "answer": 1, "explain": "Correct answer: By acquiring its supplier, Tesco secures supplies at a lower cost. These savings can be passed on to customers through lower prices. Option A is possible in some scenarios but not the most likely direct effect. Option C describes what happens to suppliers, not customers. Option D is irrelevant to customers."}]}, "fib": {"enabled": true, "questions": [{"text": "A [stakeholder] is an individual or group who has an interest in a business, while a [shareholder] is specifically an owner of shares in a limited company."}, {"text": "Internal stakeholders include [owners] and [employees], while customers and suppliers are examples of [external] stakeholders."}, {"text": "Employees want fair [wages] and job [security], while owners primarily want to maximise [profit]."}, {"text": "When a business grows, [suppliers] benefit from more orders, and the [government] benefits from increased tax revenue."}, {"text": "If employees are unhappy with pay, they may go on [strike], which can disrupt production and damage the business''s [reputation]."}, {"text": "The government can affect businesses by changing [taxation] levels, giving [grants] to new businesses, or changing [laws]."}, {"text": "Owners and employees have [conflicting] objectives because owners want to keep [wages] low to maximise profit, while employees want them to be high."}, {"text": "A [customer] boycott occurs when customers stop buying from a business, leading to lower [sales] and reduced profit."}, {"text": "The local community wants businesses to provide [employment] opportunities and minimise [noise] and pollution."}, {"text": "Suppliers want to receive [large] and [frequent] orders, and to be paid [promptly] for the goods they provide."}, {"text": "If a business closes, [employees] may lose their jobs and the government must pay more [unemployment] benefit."}, {"text": "In a limited company, profits are distributed to shareholders as [dividends], which is a key objective for [owners] as stakeholders."}]}, "tf": {"enabled": true, "questions": [{"statement": "All stakeholders are owners of a business.", "answer": false, "explain": "FALSE. Stakeholders include any group with an interest in the business — customers, employees, suppliers, government and the local community are all stakeholders but none of them are owners. Only the owners (shareholders in a limited company, or the sole trader/partners) are the owners."}, {"statement": "All businesses have stakeholders.", "answer": true, "explain": "TRUE. Every business, no matter how small, has stakeholders. Even a one-person sole trader has stakeholders — the owner themselves, their customers, suppliers, the local community and the government all have an interest in that business."}, {"statement": "All stakeholders have the same interests.", "answer": false, "explain": "FALSE. Different stakeholder groups have very different and often conflicting interests. For example, owners want to minimise wages (to increase profit), while employees want higher wages. Customers want low prices, while owners want high prices."}, {"statement": "Stakeholders can influence the activity of a business.", "answer": true, "explain": "TRUE. Stakeholders actively influence businesses. Employees can go on strike; customers can boycott; the government can change laws and taxes; the local community can protest against developments. All of these actions change how the business must operate."}, {"statement": "Stakeholders are only interested in the profits of the business.", "answer": false, "explain": "FALSE. Different stakeholders care about very different things. Employees care about wages and job security. Customers care about product quality and price. The local community cares about noise, pollution and local employment. Only the owners/shareholders are primarily motivated by profit."}, {"statement": "Stakeholders generally want a business to succeed.", "answer": true, "explain": "TRUE. Most stakeholders benefit when a business succeeds: employees keep their jobs, suppliers receive orders, the government collects taxes, and the local community benefits from employment and prosperity. However, some specific groups (e.g. competitors, or local residents opposed to a development) may not want a particular business to succeed."}, {"statement": "All of the employees of a business are stakeholders.", "answer": true, "explain": "TRUE. Every employee has an interest in the business they work for — they depend on it for their income and job security. Therefore, all employees are stakeholders (specifically, internal stakeholders)."}, {"statement": "A supplier losing a major customer business would not affect them significantly.", "answer": false, "explain": "FALSE. Suppliers are heavily affected when a business they supply to fails or reduces orders. They may lose significant revenue and in extreme cases be put out of business themselves. This is why suppliers want the businesses they supply to continue and grow."}, {"statement": "The government benefits when more people are employed by businesses.", "answer": true, "explain": "TRUE. Higher employment means more people paying income tax (more revenue for the government) and fewer people needing unemployment benefits (lower government spending). This is why the government has a strong interest in businesses succeeding and growing."}, {"statement": "Shareholders and stakeholders are the same thing.", "answer": false, "explain": "FALSE. This is the most common misconception in this topic. Shareholders are one specific type of stakeholder — they are the owners of shares in a limited company. However, stakeholders is a much broader term that includes customers, employees, suppliers, government and the local community. Sole traders and partnerships have no shareholders at all, but they still have many stakeholders."}, {"statement": "If the government increases income tax, businesses are likely to see higher sales.", "answer": false, "explain": "FALSE. If income tax increases, consumers have less disposable income — meaning they have less money to spend on goods and services. This typically leads to lower sales for businesses, not higher sales. Lower income tax has the opposite effect, boosting consumer spending."}, {"statement": "The local community can force a business to change its plans if there is enough opposition.", "answer": true, "explain": "TRUE. If a local community is sufficiently united in opposing a business development, they can campaign, protest or lobby local authorities, which may result in planning permission being refused or the business changing its proposals. The Heathrow third runway debate is a real-world example of community opposition potentially affecting major business plans."}]}, "misc": {"enabled": true, "items": [{"myth": "Stakeholders and shareholders are the same thing.", "truth": "Shareholders are just one type of stakeholder — they are owners of shares in a limited company. Stakeholders is a much broader group that includes customers, employees, suppliers, government and the local community. A sole trader has no shareholders but still has many stakeholders. Confusing these two terms in an exam will cost you marks.", "check": {"question": "Which statement correctly distinguishes stakeholders from shareholders?", "options": ["Stakeholders and shareholders are two words for the same group of people", "Only shareholders can be affected by what a business does", "Shareholders are one type of stakeholder; not all own shares", "A sole trader cannot have stakeholders because it has no shareholders"], "answer": 2, "explain": "The card corrects the misconception: shareholders are one type of stakeholder (owners of shares in a limited company), while stakeholders is a much broader group that also includes customers, employees, suppliers, government and the local community."}}, {"myth": "The local community only cares about getting jobs from a nearby business.", "truth": "The local community has a range of concerns — both positive (employment, local prosperity, community donations) and negative (noise, pollution, traffic congestion, environmental damage). In the exam, you must consider both sides. Do not write that the local community is only interested in charity work.", "check": {"question": "According to this card, what should students remember about the local community as a stakeholder?", "options": ["They are only interested in a business''s charity work", "They have no real influence over business decisions", "They are only concerned with gaining new jobs", "They have both positives (jobs) and negatives (noise)"], "answer": 3, "explain": "The card corrects the misconception that the community ''only cares about jobs'' — in reality they weigh both positives (employment, prosperity) and negatives (noise, pollution, traffic congestion)."}}, {"myth": "All stakeholders want the business to make as much profit as possible.", "truth": "Only owners and shareholders have profit as a primary objective. Employees want fair wages and job security; customers want low prices and quality; suppliers want reliable, well-paid orders; the local community wants minimal disruption; the government wants tax revenue and legal compliance. Many of these objectives actually conflict with maximising profit.", "check": {"question": "Which stakeholder group has profit as its PRIMARY objective, according to this card?", "options": ["Suppliers", "Owners and shareholders", "Employees", "The local community"], "answer": 1, "explain": "The card explains that only owners/shareholders have profit as a primary objective; other groups such as employees, suppliers, the community and government have different priorities that can actually conflict with maximising profit."}}, {"myth": "If a question asks about the impact on employees, you should discuss the impact on the business.", "truth": "The impact must be stakeholder-facing, not business-facing. If asked about the impact on employees, write about wages, job security, working conditions or redundancy — not about business costs or profit. Examiners specifically note this as a common reason for losing marks on 6-mark questions.", "check": {"question": "If an exam question asks for the impact on employees, what must the answer focus on?", "options": ["A general description of what the business does", "Effects on employees, such as wages or job security", "The impact on customers instead of employees", "The impact on the business''s costs and profit only"], "answer": 1, "explain": "The card warns that the impact must be stakeholder-facing, not business-facing — examiners note this is a common reason students lose marks on 6-mark questions."}}, {"myth": "When a business makes workers redundant, all stakeholders are negatively affected.", "truth": "This is a classic conflicting objectives scenario. Owners/shareholders actually benefit from redundancies because lower wage costs mean higher profit margins and potentially bigger dividends. The negative effects fall on employees (job losses), the local community (unemployment) and government (less tax, more benefits to pay).", "check": {"question": "When a business makes workers redundant, which stakeholder group is most likely to actually BENEFIT?", "options": ["Owners, through lower wage costs and higher profit", "Employees, through reduced workloads", "The local community, through lower unemployment", "The government, through reduced benefit payments"], "answer": 0, "explain": "The card corrects the misconception that redundancies harm everyone — owners/shareholders can benefit from lower wage costs and higher profit margins, while employees, the community and government are negatively affected."}}, {"myth": "Customers only care about getting the cheapest price.", "truth": "Customers care about the overall value they receive — which includes price, product quality, customer service, availability, product range and convenience. In specific contexts, some customers prioritise quality or ethics over price (e.g. choosing ethically-sourced products). Always link customer objectives to the specific business context in the case study.", "check": {"question": "According to this card, what do customers actually care about, beyond just getting the cheapest price?", "options": ["Nothing else — price is genuinely their only concern", "Only the ethics of a business, never its prices", "Overall value — quality, service, availability, range", "Only the geographic location of a business''s shops"], "answer": 2, "explain": "The card corrects the misconception that customers only want the cheapest price — they care about overall value, and some prioritise quality or ethics depending on the context."}}, {"myth": "External stakeholders are less important than internal stakeholders.", "truth": "There is no hierarchy of importance — it depends entirely on the business and the situation. In many cases, external stakeholders like customers or the government can have a much greater impact on a business than internal stakeholders. For example, new government regulation on MOT tests fundamentally changes what a garage like Lineside Repairs must do.", "check": {"question": "According to this card, are external stakeholders always less important than internal stakeholders?", "options": ["Yes — internal stakeholders always have the most influence", "Yes — external stakeholders have no real power over a business", "No — external stakeholders are always more important than internal ones", "No — there is no fixed hierarchy; it depends on the situation"], "answer": 3, "explain": "The card states there is no hierarchy of importance; external stakeholders like government regulation can sometimes have a far greater impact than internal stakeholders, as shown by the Lineside Repairs MOT example."}}, {"myth": "Suppliers are only affected if the business fails completely.", "truth": "Suppliers are affected by any significant change in a business''s orders or financial health. If a business reduces production, the supplier receives smaller orders. If the business faces cash flow problems, the supplier may not be paid on time. Suppliers may even stop supplying goods to a struggling business to protect themselves from losses.", "check": {"question": "According to this card, when are suppliers actually affected by a business''s problems?", "options": ["Suppliers are never affected by a business''s financial problems", "Whenever there is a significant change in orders or finances", "Only if the supplier is also a shareholder in the business", "Only if the business closes down entirely"], "answer": 1, "explain": "The card explains suppliers are affected by any significant change — smaller orders, late payments — not only if the business fails completely."}}]}, "tips": {"enabled": true, "items": [{"title": "One Point. Full Stop. Move On.", "html": "\n      <p>A 1-mark <strong>''Identify'' or ''State''</strong> question needs exactly one correct point. Nothing more. No definitions. No examples. No paragraphs.</p>\n      <p><strong>The Formula:</strong> One specific, accurate point = 1 mark ✅</p>\n      <ul>\n        <li>For <em>\"Identify one likely objective of an employee\"</em> — write: <em>\"To receive a fair wage / To have job security\"</em>. Done.</li>\n        <li>Do NOT write about the business''s objective (profit, growth) — examiners specifically penalise this.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"To make the business more profitable.\"</em><br/>\n      This is a business objective, not a personal employee objective. Zero marks.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"To earn a regular income / To have job security.\"</em><br/>\n      This is specific, personal and directly answers the question.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> The most common mistake on 1-mark employee objective questions is writing about profit, greater output or customer service. These relate to business goals, not personal employee objectives.</p>\n    ", "check": {"question": "What is required to get full marks on a 1-mark ''Identify'' or ''State'' question?", "options": ["One specific, accurate point with no explanation needed", "A full sentence including a definition and an example", "Two separate points, in case one is wrong", "A detailed paragraph linking the point to the case study"], "answer": 0, "explain": "The card''s formula is: one specific, accurate point = 1 mark — no definitions, examples or extra explanation are needed or rewarded."}}, {"title": "Make Your Point, Then Say Why It Matters", "html": "\n      <p>A 2-mark <strong>''Explain''</strong> question follows a simple formula: <strong>Knowledge (what) + Application (how/why in context)</strong>.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Point (K — 1 mark):</strong> State the impact/influence clearly.</li>\n        <li><strong>Application (APP — 1 mark):</strong> Link it directly to the specific business in the case study.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1/2 marks):</strong><br/>\n      <em>\"Customers influence Greggs'' product range.\"</em><br/>\n      This gets the knowledge mark but lacks any application to Greggs'' specific context.</p>\n      <p><strong>✅ Good Answer (2/2 marks):</strong><br/>\n      <em>\"Customers influence Greggs'' product range (K), which led to Greggs launching vegan sausage rolls in 2019 due to the growing number of vegans in the UK (APP).\"</em></p>\n      <p><strong>⚠️ Key Rule:</strong> The application mark requires you to use a specific detail from the case study — a number, a product, a location, a person''s name. Vague references like \"the business\" will NOT earn the application mark.</p>\n    ", "check": {"question": "What does a 2-mark ''Explain'' question require, according to the K+APP formula in this card?", "options": ["Two completely separate points, each unrelated to the case study", "A point (K) plus a specific case study link (APP)", "A judgement plus a justification", "Three stakeholder groups each explained briefly"], "answer": 1, "explain": "The card''s formula for 2-mark ''Explain'' questions is Knowledge (the point) plus Application (linking it to a specific detail in the case study, e.g. Greggs launching vegan sausage rolls)."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n      <p>A 3-mark analyse question is the most common high-tariff question on this topic. You MUST hit all three steps to get full marks. Miss any one of them and you cap yourself at 2 marks maximum.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U — 1 mark):</strong> Show you understand the stakeholder''s interest or impact. Give a relevant example. <br/><em>\"The local community is concerned about noise and pollution from businesses...\"</em></li>\n        <li><strong>Step 2 — Application (APP — 1 mark):</strong> Link that understanding directly to the named business in the case study using a specific detail. <br/><em>\"...Noise from testing and servicing cars at Lineside Repairs could disturb people living in nearby properties in Elsecar...\"</em></li>\n        <li><strong>Step 3 — Analysis (AN — 1 mark):</strong> State the final bottom-line impact ON THE BUSINESS. What does this mean for costs, revenue, profit, reputation? <br/><em>\"...This could force Steve to restrict his operating hours, reducing efficiency and potentially losing customers to competitors.\"</em></li>\n      </ul>\n      <p><strong>🚫 The #1 Reason Students Score 0 for Analysis:</strong> Writing a brilliant general point about the stakeholder but failing to link it back to the specific business. You CANNOT score the analysis mark without first scoring the application mark. No APP = No AN.</p>\n      <p><strong>The \"So What?\" Test:</strong> After every sentence, ask yourself <em>\"So what does this mean for the business?\"</em> Keep asking until you reach a concrete business impact (profit, costs, sales, reputation, closure).</p>\n    ", "check": {"question": "In a 3-mark ''Analyse'' answer, what happens if a student skips the Application (APP) step?", "options": ["They can still be awarded the Analysis (AN) mark separately", "They automatically fail the whole question", "They are capped at 2 marks, since AN cannot come without APP", "They lose only the Understanding (U) mark"], "answer": 2, "explain": "The card states you cannot score the Analysis mark without first scoring the Application mark — ''No APP = No AN'' — so missing APP caps the answer at 2 marks."}}, {"title": "Two Complete Chains of Analysis — No Conclusion Needed", "html": "\n      <p>A 6-mark question is simply a <strong>3-mark question done twice</strong>. Write two completely separate, well-structured paragraphs — each one following the U → APP → AN structure.</p>\n      <p><strong>Structure:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1:</strong> Stakeholder Group 1 → Understanding → Application → Analysis</li>\n        <li><strong>Paragraph 2:</strong> Stakeholder Group 2 → Understanding → Application → Analysis</li>\n      </ul>\n      <p><strong>⚠️ Critical Warning — Stakeholder-Facing vs Business-Facing Analysis:</strong><br/>\n      If a question asks for the impact <em>on</em> a stakeholder group (e.g. \"Analyse the impact on two stakeholder groups of the merger\"), your analysis must describe what happens <em>to them</em>, not just what happens to the business.</p>\n      <p><strong>❌ Wrong (business-facing):</strong> \"The merger will reduce costs for Beautiful Buds plc.\"</p>\n      <p><strong>✅ Correct (stakeholder-facing):</strong> \"Employees at Beautiful Buds may face redundancy as the merger creates overlapping roles, meaning they could lose their income and job security.\"</p>\n      <p><strong>🚫 Do NOT write a conclusion</strong> on a 6-mark question. There are zero marks available for evaluation at this level. Save your time for the analysis marks.</p>\n    ", "check": {"question": "What is a key rule for 6-mark ''Analyse 2 Impacts'' questions, according to this card?", "options": ["Write one detailed paragraph, then a short conclusion", "Combine both stakeholder groups into a single paragraph", "End with an overall judgement about which stakeholder matters most", "Write two separate U-APP-AN paragraphs with no conclusion"], "answer": 3, "explain": "The card states a 6-mark question is a 3-mark question done twice — two separate U → APP → AN paragraphs — and warns that no conclusion should be written since there are no evaluation marks available."}}, {"title": "Make a Clear Judgement — Then Justify It With Context", "html": "\n      <p>A 3-mark evaluate/recommend question on stakeholders follows a specific structure: <strong>Decision + Justification + Contextual Evidence</strong>.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Judgement (1 mark):</strong> Make a clear, direct statement about which stakeholder has more/most influence. No explanation required for this mark alone — just a clear choice.</li>\n        <li><strong>Non-contextual justification (1 mark):</strong> Give a reason that is valid for most businesses (not specifically linked to the case study).</li>\n        <li><strong>Contextual justification (up to 2 marks):</strong> Give a reason that uses precise details from the case study. This is the difference between a 2-mark and a 3-mark answer.</li>\n      </ul>\n      <p><strong>❌ ''Sitting on the fence'' = 0 marks:</strong><br/>\n      <em>\"Both the government and the local community affect the business in different ways.\"</em><br/>\n      This does not make a judgement. It answers zero marks.</p>\n      <p><strong>✅ Full marks answer:</strong><br/>\n      <em>\"I think the government has the greater influence on Lineside Repairs (JUDGEMENT). The government can change MOT regulations which Lineside must legally comply with (JUSTIFICATION). If new equipment is required for updated MOT tests, Steve would face a significant investment cost, potentially wiping out profit and threatening the survival of the business (CONTEXTUAL JUSTIFICATION).\"</em></p>\n      <p><strong>Sentence Starters:</strong></p>\n      <ul>\n        <li>\"I think [Stakeholder X] has the greater influence because...\"</li>\n        <li>\"Although [Stakeholder Y] also affects the business, [X] is more significant because...\"</li>\n        <li>\"This depends on the situation, however overall [X] has more impact because...\"</li>\n      </ul>\n    ", "check": {"question": "Why does the answer ''Both the government and the local community affect the business in different ways'' score 0 marks on a 3-mark recommend/evaluate question?", "options": ["It never makes a clear judgement or firm decision", "It uses too much case study detail", "It only discusses one stakeholder instead of two", "It does not mention profit"], "answer": 0, "explain": "The card explains that ''sitting on the fence'' by not choosing a side means the judgement mark cannot be awarded, resulting in 0 marks even if the content is accurate."}}, {"title": "Match the Objective to the Stakeholder AND the Business", "html": "\n      <p>Questions asking you to \"explain how the objectives of [external] stakeholder groups can be satisfied\" require you to do two things for each stakeholder: state what they want (Understanding) and explain how <em>this specific business</em> meets that need (Application).</p>\n      <p><strong>Key Examiner Rules for this question type:</strong></p>\n      <ul>\n        <li>You must cover <strong>three different stakeholder groups</strong> for the full 6 marks (2 marks per group: 1 for U + 1 for APP).</li>\n        <li>You will receive <strong>no marks for simply naming</strong> the stakeholder group — only for explaining their objective and applying it.</li>\n        <li>If you only write what the stakeholder wants without linking it to the specific business, you cap at 3 marks (one per group, no APP marks).</li>\n        <li>The question says <strong>external</strong> stakeholders — do not write about employees or owners.</li>\n      </ul>\n      <p><strong>❌ Generic Answer (1 mark only per group):</strong><br/>\n      <em>\"Suppliers want to be paid on time.\"</em> — This is valid knowledge but earns only 1 mark with no application.</p>\n      <p><strong>✅ Applied Answer (2 marks):</strong><br/>\n      <em>\"Suppliers want to receive regular, large orders (U). Since Nina''s Knitting Supplies has 10 shops and a website, her orders for knitting wool are likely to be relatively large, giving suppliers the volume they need (APP).\"</em></p>\n      <p><strong>⚠️ Examiner''s Warning:</strong> Do not confuse local community objectives with charity work. The local community wants employment opportunities, reduced noise/pollution, and local prosperity — not charity donations.</p>\n    ", "check": {"question": "According to this card, how many marks can a student earn for simply naming a stakeholder group without explaining or applying its objective?", "options": ["3 marks, one for identifying each group correctly", "1 mark per correctly named group", "0 marks — naming the group alone earns nothing", "2 marks, if three groups are named"], "answer": 2, "explain": "The card states there are ''no marks for simply naming the stakeholder group'' — marks are only earned for explaining the objective (Understanding) and applying it to the business (Application)."}}]}, "exam": {"enabled": true, "questions": [{"question": "What is a benefit to the local community of a nearby carpet factory extending its operating hours?", "marks": 1, "hint": "Think about what the local community values — focus on people who live nearby, not on customers or the government.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — More job opportunities will be created</h5><p><strong>Why C is correct:</strong> Extending operating hours means the factory needs more workers, creating employment for local residents. Job creation is a key benefit the local community wants from nearby businesses.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Wrong stakeholder:</strong> A wider choice of carpet designs benefits customers, not the local community specifically. The local community does not gain from product variety.</li><li><strong>B — Negative impact:</strong> Increased road congestion is a <em>drawback</em> of the factory extending hours, not a benefit. This would make local residents'' lives worse.</li><li><strong>D — Wrong stakeholder:</strong> Higher tax payments benefit the government''s budget, not the local community directly. The local community is a separate stakeholder group.</li></ul></div>"}, {"question": "What impacts are a customer boycott MOST likely to have on a business?", "marks": 1, "hint": "Think about what happens when customers stop buying from a business — follow the chain of effects.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Worsened reputation, lower sales, reduced profit</h5><p><strong>Why D is correct:</strong> A boycott means customers deliberately stop buying. This leads directly to fewer sales (lower revenue), damages the business''s public image (worsened reputation), and ultimately reduces profit as income falls.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> External growth would mean the business is expanding — the opposite of what a boycott causes. Increased dividends require higher profits, which a boycott would reduce.</li><li><strong>B — Wrong:</strong> A boycott means fewer customers, which is partially correct, but it reduces market share (not increases it) as rival businesses gain customers who leave.</li><li><strong>C — Completely wrong:</strong> A boycott damages brand image, reduces customers and cuts profit. This option describes the exact opposite of a boycott''s effect.</li></ul></div>"}, {"question": "Which of the following is NOT a method by which government as a stakeholder can affect business activity?", "marks": 1, "hint": "Which of these options is about the internal workings of parliament rather than a direct economic policy affecting business?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Increasing the number of MPs in parliament</h5><p><strong>Why C is correct:</strong> The number of MPs in parliament is a political/electoral matter. It does not directly change the tax burden, regulations, spending or support available to businesses, so it is not a method by which government affects business as a stakeholder.</p><p><strong>Why the other options ARE genuine methods:</strong></p><ul><li><strong>A:</strong> Increasing corporation tax directly reduces business profits and the money available for investment or dividends.</li><li><strong>B:</strong> Grants provide businesses with financial support to grow or establish themselves — directly affecting business activity.</li><li><strong>D:</strong> Government infrastructure spending on roads, railways and defence creates business opportunities and stimulates economic activity.</li></ul></div>"}, {"question": "Explain how the objectives of three external stakeholder groups can be satisfied by Nina''s Knitting Supplies. [6 marks]", "marks": 6, "hint": "You need THREE different external stakeholder groups. For each one: (1) state what they want (Understanding), and (2) explain how Nina''s business specifically meets that need (Application). Do NOT write about employees or Nina herself — the question specifically asks about EXTERNAL stakeholders.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 6 marks (AO1b × 3, AO2 × 3)</h5><ul><li><strong>Structure:</strong> 1 mark for understanding of an external stakeholder''s objective + 1 mark for application to Nina''s Knitting Supplies. Maximum of 3 stakeholder groups.</li><li><strong>No application marks can be awarded without first scoring the understanding mark.</strong></li><li><strong>No marks for simply naming the stakeholder group.</strong></li></ul></div><div class=\"marks-section\"><h5>Understanding may include:</h5><ul><li><strong>Customers:</strong> wide product range, quality products, low prices, value for money, good customer service, convenient opening hours, fast/free delivery, etc.</li><li><strong>Suppliers:</strong> to be paid, paid on time, paid quickly, high prices, large orders, frequent orders, repeat orders, client loyalty, etc.</li><li><strong>Lenders:</strong> repayment on time, high interest rates, reliable borrower, etc.</li><li><strong>Government:</strong> taxes paid on time, job creation, sustainability, eco-friendly, etc.</li><li><strong>Local community:</strong> environmentally/socially responsible behaviour, minimise noise/pollution/congestion, provide employment, boost local economy, etc.</li></ul></div><div class=\"marks-section\"><h5>Application must reference Nina''s business, e.g.:</h5><ul><li>Nina sells knitting wool and sewing products</li><li>Has 10 shops and a website</li><li>Knitting is increasingly popular</li><li>Employs 80 people</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>The most common error was writing about employees or Nina (internal stakeholders) when the question specifies external stakeholders. Generic answers (e.g. \"paying lenders on time\") can only gain 1 mark without application. Do NOT suggest the local community is interested in charity work — their objective is employment and local prosperity, not charity.</p></div>"}, {"question": "Identify one likely objective of an employee. [1 mark]", "marks": 1, "hint": "Think about what a person working a job personally wants from their employment — not what the business wants. Think about pay, security, or satisfaction.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 1 mark (AO1a)</h5><p>One mark for any valid personal employee objective. The answer does not need to relate specifically to Shinz Ltd.</p><p><strong>Acceptable answers include:</strong></p><ul><li>Promotion / career progression</li><li>Payment / wages / earn money / income / earn a living</li><li>To receive recognition / to be praised</li><li>Job security</li><li>Job satisfaction / interesting job / motivation</li><li>Work with friendly colleagues / good morale</li><li>To gain work experience</li><li>Safe working conditions</li></ul><p><strong>Do NOT award answers relating to:</strong> customer service, sales targets, output, quality, training, profit or revenue — these are business objectives, not personal employee objectives.</p><p><strong>Examiner''s Comment:</strong> Most common errors were writing about profit or greater output — these are business goals, not personal employee objectives. The question asks for a personal need or want of the employee themselves.</p></div>"}, {"question": "The directors of a public limited company have decided to reduce the size of the workforce to increase profits. Which stakeholder is MOST likely to benefit from this decision?", "marks": 1, "hint": "If the company makes more profit as a result of this decision, who directly receives that benefit?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Owners</h5><p><strong>Why C is correct:</strong> Reducing the workforce cuts wage costs. Lower costs mean higher profit margins. In a public limited company, higher profits lead to larger dividends for shareholders (the owners). This directly benefits the owners of the business.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Customers:</strong> Customers are not directly affected by a workforce reduction in terms of what they gain financially. They may even be negatively affected if service quality falls.</li><li><strong>B — Employees:</strong> Employees are directly harmed by this decision — those made redundant lose their jobs and income. Remaining employees may face increased workloads.</li><li><strong>D — Local community:</strong> More unemployment in the area is a negative consequence for the local community, not a benefit. Fewer people in work means reduced local spending and potentially increased social problems.</li></ul></div>"}, {"question": "Other than the government, explain one external stakeholder''s influence on Greggs. [2 marks]", "marks": 2, "hint": "Choose one external stakeholder (customers, suppliers, or local community) and explain: (1) HOW they influence Greggs (K), and (2) use a specific detail from the Greggs case study (APP).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 2 marks (AO1a + AO2)</h5><ul><li><strong>1 mark:</strong> Knowledge of the influence of an external stakeholder on business.</li><li><strong>1 further mark:</strong> Application of that influence specifically to Greggs.</li><li><strong>No application mark can be awarded without first scoring the knowledge mark.</strong></li></ul></div><div class=\"marks-section\"><h5>Knowledge may include:</h5><ul><li>Customers/consumers influencing product range, prices, quality, new product development</li><li>Suppliers influencing costs, production, quality of raw materials</li><li>Local community influencing store locations, hours, litter policies</li></ul></div><div class=\"marks-section\"><h5>Application to Greggs may include:</h5><ul><li>Growing number of vegans in the UK</li><li>Greggs launched vegan sausage rolls, doughnuts, steak bakes</li><li>Sales increased 9.6% after the vegan launch</li><li>20,000 employees — Greggs named one of the happiest places to work</li><li>''Food-on-the-go'' sector worth £23.4 billion</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Warning:</h5><p>Watch out for stakeholder/influence mismatch — do not attribute customer influences to the local community or vice versa. The influence stated must logically match the stakeholder group chosen.</p></div>"}, {"question": "Explain how the owners of EDF may be affected by the construction of Hinkley Point C nuclear power station. [2 marks]", "marks": 2, "hint": "The owners of EDF are its shareholders. Think about what shareholders care about most — dividends and returns. The power station won''t open until 2025 — what does that mean for returns in the short term?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 2 marks (AO1a + AO2)</h5><ul><li><strong>1 mark:</strong> Knowledge of how owners may be affected (e.g. dividends, share price, return on investment, profit level).</li><li><strong>1 further mark:</strong> Application to EDF specifically.</li><li><strong>No application mark without knowledge mark.</strong></li></ul></div><div class=\"marks-section\"><h5>Knowledge may include:</h5><ul><li>Profit level affected</li><li>Size of dividends may change</li><li>Change in share price</li><li>Return on investment delayed</li></ul></div><div class=\"marks-section\"><h5>Application to EDF:</h5><ul><li>Owners are shareholders (EDF is a limited company)</li><li>Station won''t open until 2025 — long wait for returns</li><li>Will eventually provide 7% of UK electricity for 60 years</li><li>Thousands of jobs / significant construction investment</li></ul></div><div class=\"marks-section\"><h5>Important:</h5><p>The impact must be on the <strong>owners specifically</strong> — do NOT award answers about costs, revenues, or general business impacts. Do NOT award ''nuclear power station'' or ''construction'' as application — these are stated in the question.</p></div>"}, {"question": "Explain how the construction of Hinkley Point C nuclear power station may affect the local community. [2 marks]", "marks": 2, "hint": "Think about both positive and negative impacts on people living near Somerset. Consider jobs, traffic, noise, disruption — pick ONE and develop it fully with a specific detail from the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 2 marks (AO1a + AO2)</h5><ul><li><strong>1 mark:</strong> Knowledge of how the local community may be affected.</li><li><strong>1 further mark:</strong> Application to EDF / Hinkley Point C specifically.</li></ul></div><div class=\"marks-section\"><h5>Knowledge may include:</h5><ul><li>More job opportunities for local residents</li><li>Increased traffic congestion from construction vehicles</li><li>Increased pollution / noise during construction</li><li>Lower property prices near the site</li><li>Greater disruption / negative aesthetic impact</li></ul></div><div class=\"marks-section\"><h5>Application to Hinkley Point C / EDF may include:</h5><ul><li>Construction will last until 2025</li><li>Thousands of jobs created during construction</li><li>Over 900 permanent jobs once operational</li><li>Many construction jobs are self-employed</li><li>Located in Somerset</li><li>Heavy construction vehicles / equipment on local roads</li></ul></div>"}, {"question": "Identify two external stakeholder groups of a business. [2 marks]", "marks": 2, "hint": "Remember: external stakeholders exist OUTSIDE the business. Think about who interacts with Boots but is not an owner or worker.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 2 marks (AO1a × 2)</h5><p>1 mark for each correctly identified external stakeholder group, up to a maximum of 2 marks. No marks for internal stakeholders (employees, managers, owners).</p><p><strong>Acceptable answers include:</strong></p><ul><li>Creditors / lenders / the bank</li><li>The Government</li><li>Customers</li><li>Suppliers</li><li>Competitors</li><li>Local community (e.g. residents near a store)</li><li>Charity partners</li><li>Landlords / shopping mall owners</li></ul></div>"}, {"question": "Explain one objective which an internal stakeholder group of Boots UK may have. [2 marks]", "marks": 2, "hint": "Internal stakeholders are owners and employees. Choose one, state what they want (1 mark), then develop that point in the context of Boots UK (1 mark).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 2 marks (AO1a + AO2)</h5><ul><li><strong>1 mark:</strong> Identification of a valid objective of an internal stakeholder group.</li><li><strong>1 further mark:</strong> A development point in context of Boots UK.</li></ul></div><div class=\"marks-section\"><h5>Acceptable answers include:</h5><ul><li>Owners: higher profits, dividends, business growth</li><li>Managers: bonuses, career progression</li><li>Employees: better pay, job security, permanent contracts</li></ul></div><div class=\"marks-section\"><h5>Exemplar responses:</h5><p>\"The owners of Boots UK may have the objective of higher profits (1). They will want the company to be successful in the Christmas period and beyond to increase their dividends (1 — APP).\"</p><p>\"The store workers at Boots UK will be looking for job security (1) so that the temporary Christmas jobs become permanent roles (1 — APP).\"</p></div>"}, {"question": "A bakery manufactures and supplies a range of bread loaves to local supermarkets. Which of the following is the MOST likely effect of the bakery employees refusing to work?", "marks": 1, "hint": "If workers go on strike and stop working, what is the immediate operational consequence for the bakery''s customers (the supermarkets)?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Deliveries to supermarkets will be disrupted</h5><p><strong>Why A is correct:</strong> If employees go on strike (refuse to work), bread cannot be produced. Without production, there is nothing to deliver, so supermarket deliveries will be disrupted. This demonstrates the power employees have over business operations.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B:</strong> A strike does not cause a change in ingredients. Ingredients are decided by management, not employee action.</li><li><strong>C:</strong> This is the exact opposite. If employees refuse to work, production stops — fewer, not more, bread loaves are produced.</li><li><strong>D:</strong> Market segmentation is a marketing strategy about targeting different customer groups. It has no connection to employees refusing to work.</li></ul></div>"}, {"question": "Analyse the impact on two stakeholder groups of the proposed vertical merger between Beautiful Buds plc and Green Gardens plc. [6 marks]", "marks": 6, "hint": "Choose two different stakeholder groups (e.g. employees, customers, shareholders, competitors). For EACH one, follow the U → APP → AN structure. Crucially: your analysis must describe the impact ON the stakeholder, not just on the business. Use specific details from the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 6 marks (AO1b × 2, AO2 × 2, AO3a × 2)</h5><p>For each of two stakeholder groups: 1 mark for understanding + 1 mark for application + 1 mark for analysis (stakeholder-facing impact).</p></div><div class=\"marks-section\"><h5>Stakeholder groups and relevant impacts:</h5><ul><li><strong>Employees:</strong> job losses, job (in)security, new opportunities, career progression concerns, fear of redundancy</li><li><strong>Customers:</strong> increased availability of plants, wider product range, potentially lower prices, more convenient shopping</li><li><strong>Shareholders:</strong> change in share price, potential increase in dividends from greater market access, risk of short-term losses from restructuring costs</li><li><strong>Competitors:</strong> may face stronger competition, risk of losing market share, may need to reduce prices</li></ul></div><div class=\"marks-section\"><h5>⚠️ Critical Examiner Note:</h5><p>Analysis must be STAKEHOLDER-FACING — describe the impact on the chosen stakeholder group, NOT on the business. For example: \"Customers will benefit from a wider range of plants\" — NOT \"The business will have a wider product range.\"</p><p>Contextual references include: plants, garden centres, 12% market share, 124 employees, 2 layers of management, specific job roles and salaries, £200,000 redundancy costs.</p><p>If ''employee'' is used as the stakeholder group, then specific job roles (e.g. Middle Managers) count as a separate group only if a different group is named.</p><p><strong>Examiner''s Comment:</strong> This was the worst-answered question on the paper. Many students correctly named two stakeholder groups but then discussed impacts on the business rather than on the stakeholders. Read the question carefully — it asks for the impact ON the stakeholders.</p></div>"}, {"question": "Recommend which stakeholder group will be most affected by the vertical merger between Beautiful Buds plc and Green Gardens plc. Give reasons for your answer. [3 marks]", "marks": 3, "hint": "Make a clear, direct choice (1 mark). Then give ONE reason why your chosen group is most affected — non-contextual gets 1 mark, but using a specific detail from the case study (12%, specific job titles, salary figures, 124 employees, etc.) gets 2 marks for justification.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 3 marks (AO3b × 3)</h5><ul><li><strong>1 mark:</strong> Clear recommendation — names a stakeholder group as most affected.</li><li><strong>+1 mark:</strong> Non-contextual justification — a valid reason applicable to most businesses.</li><li><strong>+2 marks (instead of +1):</strong> Contextual justification — uses specific details from Beautiful Buds plc case study.</li></ul><p>Any stakeholder group can be chosen and receive full marks, provided the justification is strong enough.</p></div><div class=\"marks-section\"><h5>Contextual references for strong answers:</h5><ul><li>Plants, garden, garden centres, 12% market share</li><li>124 employees, 2 layers removed, specific job roles</li><li>Salary figures (e.g. Middle Managers at £50,000)</li><li>£200,000 redundancy costs</li><li>Shareholders of either company</li></ul></div><div class=\"marks-section\"><h5>⚠️ Zero marks for ''sitting on the fence'':</h5><p>Saying \"both stakeholder groups are affected in different ways\" without making a clear choice scores zero. You MUST commit to one stakeholder group as being MOST affected.</p><p><strong>Examiner''s Comment:</strong> Almost all students who attempted this question correctly gained the first mark for making a choice. The difference between 1 mark and 3 marks lay entirely in the quality and specificity of the contextual justification.</p></div>"}, {"question": "Which of the following is an internal stakeholder of a business that trades as a partnership?", "marks": 1, "hint": "Remember: internal stakeholders are those INSIDE the business. Also remember that partnerships do NOT have shareholders — only limited companies do.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — An employee</h5><p><strong>Why D is correct:</strong> An employee works within the business, making them an internal stakeholder. This applies to any business structure, including a partnership.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Customer:</strong> Customers are external stakeholders — they exist outside the business and buy from it.</li><li><strong>B — Shareholder:</strong> A partnership does NOT have shareholders. Shareholders only exist in limited companies (Ltd and plc). This is a deliberate exam trap to see if students know the difference between business types and stakeholders.</li><li><strong>C — Supplier:</strong> Suppliers are external stakeholders — they provide goods or services to the business from outside.</li></ul></div>"}, {"question": "Which of the following are the customers of a business MOST likely to be interested in?", "marks": 1, "hint": "Think about what you care about as a customer when you go shopping. What would make you choose one business over another?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Product range</h5><p><strong>Why C is correct:</strong> Customers are primarily interested in what the business sells — the quality, price, range and availability of products and services. A wider product range gives customers more choice and increases the chance they will find what they need.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Employee wages:</strong> This is an objective of employees, not customers. Customers are generally not affected by what workers are paid, unless ethical concerns about pay are involved.</li><li><strong>B — Job security:</strong> This is an objective of employees. Customers do not have a personal stake in whether a business''s workers keep their jobs.</li><li><strong>D — Share dividends:</strong> Dividends are paid to shareholders/owners. Customers are not shareholders (unless they happen to own shares separately), and dividends do not affect the price or quality of what customers buy.</li></ul></div>"}, {"question": "Explain one impact on Costa Coffee employees of the business investing in updating computer software. [2 marks]", "marks": 2, "hint": "Think about what changes for employees when their workplace upgrades its technology. Consider: efficiency, training needs, job security, ease of work. Then link your point specifically to Costa Coffee.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 2 marks (AO1a + AO2)</h5><ul><li><strong>1 mark:</strong> Identifying an impact of computer software/technology on employees.</li><li><strong>1 further mark:</strong> Application of the impact specifically to Costa Coffee employees.</li><li><strong>No application mark without knowledge mark.</strong></li></ul></div><div class=\"marks-section\"><h5>Knowledge may include:</h5><ul><li>Improved efficiency / faster working</li><li>Need for training on new software</li><li>Easier communication / coordination</li><li>Potential redundancy risk in some roles (e.g. finance)</li><li>Improved motivation from better tools</li></ul></div><div class=\"marks-section\"><h5>Application to Costa Coffee may include:</h5><ul><li>Finance employees can produce data more quickly across 2,100+ UK branches</li><li>Employees may need training to use the new system</li><li>Software helps coordinate the supply chain for Rainforest Alliance-certified beans</li><li>Helps manage staffing across all locations</li><li>May reduce admin roles in the finance function</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment:</h5><p>The impact needed to be applied to the specific scenario of Costa Coffee employees. The best answers linked the software to employees working within Costa Coffee''s finance function specifically. Generic answers not tied to the case study could only earn 1 mark.</p></div>"}, {"question": "Analyse one impact the local community, as a stakeholder, has on Lineside Repairs. [3 marks]", "marks": 3, "hint": "You need all three steps: Understanding (what interest does the local community have?), Application (link it specifically to Lineside Repairs and Steve''s situation), Analysis (what is the actual impact/effect on the business?).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Shows understanding of how the local community''s interest impacts a business (e.g. concerns about noise/pollution, or appreciating local employment).</li><li><strong>Application (1 mark):</strong> Links the interest to the case study of Lineside Repairs — must reference specific details about Steve''s garage.</li><li><strong>Analysis (1 mark):</strong> Explains the effect/impact ON the business (costs, efficiency, reputation, customer numbers).</li><li><strong>Note: Application and Analysis marks cannot be scored if Understanding is not first scored.</strong></li></ul></div><div class=\"marks-section\"><h5>Understanding examples:</h5><ul><li>Concerns about noise from the garage</li><li>Concerns about pollution from vehicle testing</li><li>Appreciation of local employment provided</li></ul></div><div class=\"marks-section\"><h5>Application examples:</h5><ul><li>Noise from servicing and testing cars may disturb people living in nearby properties in Elsecar</li><li>Steve must ensure noise does not upset nearby residents (stated in case study)</li></ul></div><div class=\"marks-section\"><h5>Analysis examples:</h5><ul><li>If the community protests about the noise, Lineside Repairs may have to change its working practices — for example, restricting testing hours — which reduces efficiency and could cost the business customers</li></ul></div>"}, {"question": "Analyse one impact the government, as a stakeholder, has on Lineside Repairs. [3 marks]", "marks": 3, "hint": "Think about the four ways government can affect businesses (taxation, grants, laws/regulations, spending). Which one is most relevant to a small garage doing MOT tests? Use specific details from the Steve Loy case study for your application mark.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Shows understanding of the government''s interest in businesses — e.g. taxation, regulation changes that affect operations.</li><li><strong>Application (1 mark):</strong> Links government influence to Lineside Repairs — references MOT regulations or Steve''s specific situation.</li><li><strong>Analysis (1 mark):</strong> Explains the financial or operational impact on the business.</li></ul></div><div class=\"marks-section\"><h5>Understanding examples:</h5><ul><li>Government changes regulations on MOT testing requirements</li><li>Government changes taxation levels affecting business costs</li></ul></div><div class=\"marks-section\"><h5>Application examples:</h5><ul><li>If the government changes the regulations on MOT testing, Lineside Repairs is directly affected</li><li>Steve must buy the correct equipment to carry out MOT tests (stated in case study)</li></ul></div><div class=\"marks-section\"><h5>Analysis examples:</h5><ul><li>If new MOT regulations require expensive new equipment, Steve faces a significant investment cost which reduces profit, and may even threaten the financial survival of the business if funds are unavailable</li></ul></div>"}, {"question": "Evaluate whether the local community or the government has more impact on the running of Lineside Repairs. [3 marks]", "marks": 3, "hint": "Make a CLEAR choice — do not say ''both are equally important''. State which one you think has MORE impact (1 mark). Then justify your choice with reasons linked to Steve''s specific situation at Lineside Repairs (up to 2 marks — using case study details earns more).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation: 3 marks (AO3b × 3)</h5><ul><li><strong>Judgement (1 mark):</strong> A clear statement identifying which stakeholder has greater influence. No explanation required for this mark.</li><li><strong>Non-contextual justification (1 mark):</strong> A valid reason applicable to most businesses.</li><li><strong>Contextual justification (up to 2 marks):</strong> A precise reason using specific details from the Lineside Repairs case study. This earns 2 marks for justification instead of 1.</li></ul><p>Either stakeholder can be selected and gain full marks — the quality of justification determines the mark.</p></div><div class=\"marks-section\"><h5>Exemplar response (Government):</h5><p>\"I think the government has a greater influence on the running of Lineside Repairs (JUDGEMENT). The government can change regulations on how businesses operate which Lineside must legally comply with (NON-CONTEXTUAL JUSTIFICATION). Unlike community pressure, which Steve can negotiate with, MOT test regulations are compulsory — Steve must buy whatever equipment is required by law. If new regulations are introduced requiring expensive new testing equipment, this could be a huge financial burden for a small garage, significantly reducing profit (CONTEXTUAL JUSTIFICATION).\"</p></div>"}]}}'::jsonb),
('business', '1-6-business-growth', '1.6 Business Growth', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>This sub-topic covers the ways in which a business can increase in size — either by growing from within (<strong>organic/internal growth</strong>) or by joining with or buying other businesses (<strong>external growth</strong>).</p>\n<ul>\n  <li><strong>Organic Growth:</strong> Concerned with the <em>internal</em> growth of a business, e.g. by increasing sales, developing new products, or gaining new customers — without joining with another business.</li>\n  <li><strong>External Growth:</strong> The growth of a business by <em>takeover or merger</em> with another business.</li>\n  <li><strong>Merger:</strong> Where two or more businesses <em>mutually agree</em> to join together to become one new business.</li>\n  <li><strong>Takeover:</strong> Where a business takes a <em>controlling interest</em> in another business, for example by buying more than 50% of the shares in it.</li>\n  <li><strong>Horizontal Growth:</strong> A merger or takeover where the two businesses are involved in a <em>similar operation at the same stage of production</em> in the same industry.</li>\n  <li><strong>Backward Vertical Growth:</strong> When a business merges with, or takes over, a business that <em>supplies</em> it with goods or services — moving back up the supply chain.</li>\n  <li><strong>Forward Vertical Growth:</strong> When a business merges with, or takes over, a business that it <em>supplies goods or services to</em> — moving forward down the supply chain.</li>\n  <li><strong>Diversification:</strong> When a business merges with or takes over another business with which it has <em>no connection</em> — entering a completely new market.</li>\n  <li><strong>Market Share:</strong> A business''s sales as a percentage of total market sales. Formula: (Business Sales ÷ Total Market Sales) × 100.</li>\n</ul>", "check": {"question": "A business merges with a company in a completely unrelated industry, such as a clothing brand buying a software firm. What type of growth is this?", "options": ["Diversification", "Forward vertical growth", "Horizontal growth", "Backward vertical growth"], "answer": 0, "explain": "Diversification is defined as merging with or taking over a business with no connection, entering a completely new market."}}, {"title": "Organic (Internal) Growth — Methods", "html": "<p><strong>Organic growth</strong> means expanding using the business''s own internal resources and capabilities, without merging with or acquiring another business. It is generally a slower but safer form of growth.</p>\n<ul>\n  <li><strong>Increasing Output:</strong> The business produces more — by using resources more efficiently, using spare capacity, or building new factories and expanding premises.</li>\n  <li><strong>Developing New Products:</strong> The business researches and develops new products, buys ideas/licences from others, or copies successful concepts from competitors. Technology businesses like Apple rely heavily on this.</li>\n  <li><strong>Gaining New Customers:</strong> The business attracts customers it did not previously have by reducing prices, opening new shops, or investing in better marketing and advertising.</li>\n  <li><strong>Increasing Market Share:</strong> The business wins a larger proportion of total market sales from rivals through better pricing, quality, or marketing.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Pets at Home</h4>\n  <p>Pets at Home achieved organic growth by <strong>expanding the range of services it offers internally</strong> — including grooming services and veterinary services. Rather than buying other businesses, it grew by developing new revenue streams within its existing brand and customer base, attracting new customer segments who need pet care beyond just products.</p>\n  <p><strong>Takeaway:</strong> Adding new services to an existing customer base is a classic method of organic growth — no mergers required.</p>\n</div>", "check": {"question": "Which of the following is an example of organic (internal) growth?", "options": ["A business develops a new product via its own research", "A business buys a controlling stake in a rival firm", "A business takes over its main supplier", "Two businesses agree to merge into one new company"], "answer": 0, "explain": "Organic growth expands the business using its own internal resources, such as developing new products, without merging with or acquiring another business."}}, {"title": "External (Inorganic) Growth — Mergers & Takeovers", "html": "<p><strong>External growth</strong> happens when a business joins with or buys another business. It is a faster way to grow but carries higher risk and cost.</p>\n<ul>\n  <li><strong>Merger:</strong> Two businesses <em>mutually agree</em> to combine and form one new business. Neither forces the other. Example: Orange + T-Mobile agreeing to form EE.</li>\n  <li><strong>Takeover (Acquisition):</strong> One business <em>buys a controlling stake</em> (over 50% of shares) in another, often without the target having a choice. Example: Disney buying Pixar.</li>\n</ul>\n<p><strong>Key difference:</strong> A merger is by <strong>mutual agreement</strong>; a takeover is where one business gains <strong>control</strong> over another by purchasing shares.</p>\n<div class=\"formula-box\">\n  <strong>Supply Chain Direction (Memory Aid):</strong><br>\n  Supplier &rarr; Manufacturer &rarr; Retailer &rarr; Customer<br>\n  <strong>Backward vertical</strong> = buying your supplier (moving ← left)<br>\n  <strong>Forward vertical</strong> = buying your retailer/customer (moving → right)<br>\n  <strong>Horizontal</strong> = buying a business at the same level as you<br>\n  <strong>Diversification</strong> = buying a business in a completely unrelated industry\n</div>", "check": {"question": "What is the key difference between a merger and a takeover?", "options": ["A merger is mutual agreement; a takeover is buying a controlling stake", "A merger only happens between competitors, while a takeover only happens between suppliers", "A takeover always results in a completely new company name being formed", "A merger is always cheaper than a takeover"], "answer": 0, "explain": "A merger is by mutual agreement, whereas a takeover is where one business gains control by purchasing over 50% of another''s shares, often without the target having a choice."}}, {"title": "Types of External Growth", "html": "<p>External growth can take several forms depending on the <strong>relationship between the two businesses</strong> involved:</p>\n<ul>\n  <li><strong>Horizontal Growth:</strong> Two businesses at the <em>same stage of production in the same industry</em> join together. Example: A business making radios merges with a business making televisions. Example: Two rival restaurant chains merging.</li>\n  <li><strong>Backward Vertical Growth:</strong> A business joins with a <em>supplier</em>. Example: A computer assembler merges with a microchip supplier. Example: A jam manufacturer buys a fruit farm.</li>\n  <li><strong>Forward Vertical Growth:</strong> A business joins with a business it <em>sells to</em>. Example: A pottery maker takes over a pottery shop. Example: Greggs merging with a sandwich retailer.</li>\n  <li><strong>Diversification:</strong> A business joins a company in a <em>completely different, unrelated industry</em>. Example: A clothing company buying a software firm.</li>\n</ul>\n<p>The table below shows key examples to help you remember:</p>\n<ul>\n  <li>Jam maker + fruit farm = <strong>Backward vertical</strong> (farm supplies fruit)</li>\n  <li>Potter + pottery shop = <strong>Forward vertical</strong> (shop sells the pottery)</li>\n  <li>Radio maker + TV maker = <strong>Horizontal</strong> (same industry, same stage)</li>\n  <li>Clothing brand + tech firm = <strong>Diversification</strong> (no connection)</li>\n</ul>", "check": {"question": "A potter (pottery maker) takes over the shop that sells its pottery to customers. What type of external growth is this?", "options": ["Diversification", "Horizontal growth", "Backward vertical growth", "Forward vertical growth"], "answer": 3, "explain": "Forward vertical growth occurs when a business joins with a business it sells to — here the potter joins the shop it supplies pottery to, moving forward down the supply chain."}}, {"title": "Advantages & Disadvantages: Organic vs External Growth", "html": "<p>Both forms of growth have clear benefits and drawbacks. In the exam you may be asked to <strong>analyse</strong> or <strong>evaluate</strong> which method is more appropriate for a specific business.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages of Organic Growth</div>\n    <div class=\"pro-item\"><strong>Less risky:</strong> The business grows at a pace it can manage, reducing the chance of financial overextension.</div>\n    <div class=\"pro-item\"><strong>Maintains control:</strong> Owners retain full strategic control and decision-making authority — profits do not need to be shared with new partners.</div>\n    <div class=\"pro-item\"><strong>Builds own expertise:</strong> The business develops its own skills and brand identity, leading to a stronger competitive position over time.</div>\n    <div class=\"pro-item\"><strong>Lower cost:</strong> Funded through internal funds (retained profit), avoiding the large upfront costs of buying another business.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages of Organic Growth</div>\n    <div class=\"con-item\"><strong>Slow:</strong> Takes much longer to achieve significant growth — shareholders may prefer faster expansion to boost returns more quickly.</div>\n    <div class=\"con-item\"><strong>Limited growth potential:</strong> In a competitive or saturated market there may be a ceiling to how much the business can grow from within.</div>\n    <div class=\"con-item\"><strong>Competitors may overtake:</strong> Rivals using external growth can gain market share far more rapidly, potentially leaving organic growers behind.</div>\n  </div>\n</div>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages of External Growth</div>\n    <div class=\"pro-item\"><strong>Fast:</strong> Market share and revenue can increase almost immediately, satisfying impatient shareholders and investors.</div>\n    <div class=\"pro-item\"><strong>Reduces competition:</strong> Taking over or merging with a rival removes a competitor from the market — potentially allowing higher prices.</div>\n    <div class=\"pro-item\"><strong>Access to expertise:</strong> The business instantly gains the skills, technology, customer base and reputation of the acquired business.</div>\n    <div class=\"pro-item\"><strong>Economies of scale:</strong> A larger combined business can negotiate bulk discounts, spread fixed costs, and lower unit costs.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages of External Growth</div>\n    <div class=\"con-item\"><strong>Very expensive:</strong> Buying another business requires significant investment or borrowing, greatly increasing financial risk.</div>\n    <div class=\"con-item\"><strong>Loss of control:</strong> In a merger, profits and decisions must be shared with other owners — disagreements and conflict can arise.</div>\n    <div class=\"con-item\"><strong>Management challenges:</strong> Managers may lack the experience to run a much larger, more complex organisation, leading to inefficiency and wasted money.</div>\n    <div class=\"con-item\"><strong>Culture clashes:</strong> Employees from different businesses may have conflicting values or working practices, reducing productivity.</div>\n  </div>\n</div>", "check": {"question": "Which of these is listed as a key advantage of organic growth over external growth?", "options": ["The business gains instant access to a rival''s expertise and customer base", "Competition in the market is reduced", "Market share increases almost immediately", "Owners maintain full strategic control without having to share profits"], "answer": 3, "explain": "The card lists ''maintains control'' as an advantage of organic growth, since owners retain full decision-making authority; the other options are listed as advantages of external growth instead."}}, {"title": "Market Share — Formula & Calculations", "html": "<p>Market share measures a business''s dominance within its market. Increasing market share means the business is winning customers from rivals, even if the overall market is growing.</p>\n<div class=\"formula-box\">\n  <strong>Market Share (%) =</strong> (Sales of the business ÷ Total sales in the market) &times; 100\n</div>\n<p><strong>Worked Example (Shinz Ltd):</strong><br>\nThe car washing market in Littlelong = £460,000.<br>\nShinz Ltd holds 40% market share.<br>\nValue = 40% &times; £460,000 = <strong>£184,000</strong></p>\n<p><strong>Worked Example (Combined merger):</strong><br>\nShinz Ltd (40%) + Littlelong Motors (10%) = <strong>50% combined = £230,000</strong></p>\n<p><strong>Key warning:</strong> If the total market grows by 30% but a business''s sales only grow by 20%, that business''s market share has actually <em>fallen</em> — even though its sales went up. Market share is always relative to the total market.</p>\n<ul>\n  <li>Market share rises → more competitive, greater pricing power, stronger negotiating position with suppliers.</li>\n  <li>Market share falls → rivals growing faster, business losing ground even if its own sales are rising.</li>\n</ul>", "check": {"question": "A business''s sales grow by 20% while the total market grows by 30% over the same period. What happens to the business''s market share?", "options": ["It cannot be determined without knowing profit figures", "It stays exactly the same", "It rises, because the business''s sales increased", "It falls, since market share is relative to the market"], "answer": 3, "explain": "The card''s key warning states that if total market sales grow faster than a business''s own sales, its market share falls even though its sales have risen, because market share is always relative to the total market."}}, {"title": "Real-World Case Studies in Business Growth", "html": "<div class=\"case-study-box\">\n  <h4>Case Study: Apple — Organic Growth</h4>\n  <p>Apple was started in 1976 and has grown to become the largest company in the world — almost entirely through <strong>organic growth</strong>. Rather than buying many other businesses, Apple focused on researching and developing its own products: the MacBook Pro, iPhone, iPad, and Apple Pay. Apple has taken over only a very small number of businesses in its entire history.</p>\n  <p>Apple also invested heavily in innovative marketing — introducing new products around September each year, using catchy music and minimalistic advertising to build a powerful global brand. Revenue grew from $33,300 in 1976 to $49.6 billion in 2016.</p>\n  <p><strong>Takeaway:</strong> Organic growth through product innovation and brand-building allowed Apple to maintain complete strategic control, resulting in one of the world''s most profitable companies without relying on expensive acquisitions.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Boohoo — External Growth</h4>\n  <p>Boohoo started in 2006 as an online fashion retailer targeting 16–24 year olds and initially grew organically via social media and website development. However, in 2020/2021 it shifted to <strong>external growth</strong>, acquiring well-known brands including Debenhams, Oasis, Burton, and Dorothy Perkins. This instantly gave Boohoo access to millions of customers across different demographics.</p>\n  <p>However, taking on so many businesses simultaneously created significant management challenges — controlling a much larger organisation increased costs and risked reducing overall efficiency and profitability.</p>\n  <p><strong>Takeaway:</strong> External growth gave Boohoo rapid access to new markets, but managing multiple acquisitions simultaneously increased the risk of losing control and damaging the original brand.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Greggs — Choosing Between Growth Methods</h4>\n  <p>Greggs is a ''food-on-the-go'' brand with 20,000 employees and a growing vegan product range (vegan sausage rolls launched 2019 boosted sales by 9.6% in 7 weeks). Greggs considered two external growth options: (1) a <strong>backward vertical merger</strong> with a flour producer to secure raw material supply and reduce costs; (2) a <strong>horizontal takeover</strong> of a rival food-on-the-go brand to eliminate competition and rapidly increase market share.</p>\n  <p><strong>Takeaway:</strong> Different growth strategies serve different purposes. Backward vertical growth secures supplies and cuts costs; horizontal takeover removes competition and boosts market share rapidly. The best choice depends on the business''s specific aims and context.</p>\n</div>", "check": {"question": "Which case study business grew almost entirely through organic growth, taking over only a very small number of businesses in its history?", "options": ["Boohoo", "Apple", "None of these — all three grew solely through mergers", "Greggs"], "answer": 1, "explain": "The card states Apple grew to become the largest company in the world almost entirely through organic growth, focusing on researching and developing its own products rather than buying other businesses."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Organic growth", "definition": "The internal growth of a business through increasing sales, developing new products, gaining new customers, or growing market share — without joining with another business."}, {"term": "External growth", "definition": "Growth achieved by joining with or buying another business through a merger or takeover."}, {"term": "Merger", "definition": "When two or more businesses mutually agree to combine and become one new business."}, {"term": "Takeover", "definition": "When a business buys a controlling interest (over 50% of shares) in another business."}, {"term": "Horizontal growth", "definition": "A merger/takeover between two businesses at the same stage of production in the same industry."}, {"term": "Backward vertical growth", "definition": "A merger/takeover where a business buys its supplier — moving backwards up the supply chain."}, {"term": "Forward vertical growth", "definition": "A merger/takeover where a business buys a company it sells to — moving forwards down the supply chain."}, {"term": "Diversification", "definition": "A merger/takeover where the two businesses are in completely unrelated industries — entering a brand new market."}, {"term": "Market share formula", "definition": "(Sales of the business ÷ Total market sales) × 100 = Market Share (%)"}, {"term": "Advantages of organic growth", "definition": "Less risky, maintains owner control, cheaper (funded by retained profit), builds own expertise, grows at a manageable pace."}, {"term": "Disadvantages of organic growth", "definition": "Slow — shareholders want faster returns; limited ceiling in a competitive market; rivals using external growth can outpace you."}, {"term": "Advantages of external growth", "definition": "Fast — rapidly increases market share and revenue; removes a competitor; gains access to new customers, expertise, and assets immediately."}, {"term": "Disadvantages of external growth", "definition": "Very expensive; loss of control (profits shared with more owners); management difficulties with a larger organisation; risk of culture clashes."}, {"term": "Supply chain memory aid", "definition": "Supplier → Manufacturer → Retailer → Customer. Backward = buy your supplier. Forward = buy your retailer/customer. Same level = horizontal."}]}, "mcq": {"enabled": true, "questions": [{"question": "Two vets agree to combine their practices and operate as one business. This is an example of a:", "options": ["Horizontal takeover", "Vertical takeover", "Merger", "Diversification"], "answer": 2, "explain": "Correct answer: Merger. Both vet practices mutually agreed to combine — this is the definition of a merger. It is not a takeover because neither bought the other. It is horizontal (same industry) but since they agreed to join, it is a merger not a takeover."}, {"question": "Eve is a restaurant owner. She has successfully used social media to attract a lot of new customers. This is an example of:", "options": ["Invention", "Organic growth", "Diversification", "Skimming"], "answer": 1, "explain": "Correct answer: Organic growth. Eve has grown her business internally by using better marketing (social media) to gain new customers. Gaining customers through marketing is a classic organic growth method. A: Diversification = merging with an unrelated business. B: Invention = creating a new product. D: Skimming = a pricing strategy."}, {"question": "A manufacturer of jam buys a fruit farm. This is an example of:", "options": ["A vertical takeover", "Flexible working", "Diversification", "A business partnership"], "answer": 0, "explain": "Correct answer: A vertical takeover. The jam manufacturer is buying its supplier (the fruit farm), moving backwards up the supply chain — backward vertical external growth. A: A partnership is a type of business ownership, not a growth strategy. C: Diversification would mean entering an unrelated industry — fruit and jam are directly connected. D: Flexible working is an HR concept."}, {"question": "A business has gained more customers by improving the way it markets its products. Which statement must be true?", "options": ["The business has grown organically", "The business has made a profit", "The business has developed a new product", "The business has increased its market share"], "answer": 0, "explain": "Correct answer: The business has grown organically. Improving marketing to gain customers is an internal method of growth — this is always organic growth. A: Not necessarily — marketing may be for existing products. C: Not necessarily — the total market may have grown faster, so market share could have fallen. D: Not necessarily — the business may still have higher costs."}, {"question": "A well-known restaurant chain buys another well-known restaurant chain. What is this an example of?", "options": ["A horizontal takeover", "Diversification", "Innovation", "A vertical merger"], "answer": 0, "explain": "Correct answer: A horizontal takeover. Both businesses are restaurant chains — same stage, same industry = horizontal. One is buying the other (not mutual agreement) = takeover. B: Vertical = different stages of supply chain. C: Diversification = unrelated industry. D: Innovation = new products or processes."}, {"question": "Which of the following is NOT an example of organic growth?", "options": ["Gaining new customers", "Merging with a supplier", "Developing new products", "Increasing output"], "answer": 1, "explain": "Correct answer: Merging with a supplier. Merging with any other business is always external (inorganic) growth, regardless of whether it is a supplier, customer or rival. Options A, C, and D are all internal methods of growing the business from within."}, {"question": "A business increasing its market share would normally lead to the business having:", "options": ["A better workforce", "More customers", "A guarantee of supplies", "A better reputation"], "answer": 1, "explain": "Correct answer: More customers. Market share measures the proportion of total market sales held by the business. If market share increases, the business holds a larger slice of the market, which means more customers relative to rivals. The other options are not direct consequences of increased market share."}, {"question": "A forwards vertical merger is when:", "options": ["A business merges with a supplier", "A business merges with a business it supplies goods to", "A business merges with another similar business", "A business merges with a totally different business"], "answer": 1, "explain": "Correct answer: A business merges with a business it supplies goods to. Forward vertical = moving forward down the supply chain towards the customer. A: Merging with a similar business is horizontal. B: Merging with a supplier is backward vertical. D: Merging with a totally different business is diversification."}, {"question": "A takeover is when:", "options": ["A business buys any share of another business", "A business agrees to join with another business", "A business buys more than 50% of another business", "A business takes over paying the workers at another business"], "answer": 2, "explain": "Correct answer: A business buys more than 50% of another business. Owning more than 50% gives a controlling interest — the buyer can outvote all other shareholders on key decisions. A: Agreeing to join is a merger. C: Buying any share does not give control. D: This is not a business growth concept."}, {"question": "Which of the following describes a takeover?", "options": ["Orange and T-Mobile joined together to become EE", "Netflix increases its share of the market", "Honda Motor Company builds a factory to manufacture gear boxes for its cars", "Disney the film-maker bought the animation company Pixar"], "answer": 3, "explain": "Correct answer: Disney buying Pixar. A takeover is when one business purchases a controlling interest in another. Disney acquired (bought) Pixar. A: Orange and T-Mobile agreed to join — that is a merger. C: Building a new factory is organic growth (increasing capacity internally). D: Netflix growing market share organically is organic growth."}, {"question": "Which of the following is NOT a method of external growth?", "options": ["Diversification", "Backward vertical takeover", "Developing a new product range", "Horizontal merger"], "answer": 2, "explain": "Correct answer: Developing a new product range. Developing new products internally is a method of organic (internal) growth. Options A, B, and D all involve joining with or buying another business, making them forms of external growth."}, {"question": "A business assembling computers merges with a microchip supplier. This is an example of:", "options": ["Backward vertical growth", "Forward vertical growth", "Horizontal growth", "Diversification"], "answer": 0, "explain": "Correct answer: Backward vertical growth. The computer assembler is buying its supplier (the microchip company), moving backwards up the supply chain. A: Horizontal would mean both do the same thing. C: Forward vertical would be buying a retailer that sells the computers. D: Diversification would mean an entirely unrelated industry."}]}, "fib": {"enabled": true, "questions": [{"text": "Organic growth is concerned with the [internal] growth of a business, for example by increasing [sales]."}, {"text": "A [merger] is when two businesses mutually agree to join together, whereas a [takeover] is when one business buys a controlling interest in another."}, {"text": "When a jam manufacturer buys a fruit farm, this is [backward] vertical growth because the farm is a [supplier]."}, {"text": "A business assembling computers merging with the retailer that sells its computers to the public is an example of [forward] vertical growth."}, {"text": "When two rival supermarkets merge, this is known as [horizontal] growth because they operate at the same [stage] of production."}, {"text": "[Diversification] is when a business merges with a company in a completely unrelated industry, entering a brand new market."}, {"text": "Market share is calculated by dividing the [sales] of the business by the total [sales] in the market and multiplying by 100."}, {"text": "A key disadvantage of organic growth is that it is [slow], meaning shareholders may prefer the [faster] pace of external growth."}, {"text": "One advantage of external growth is that it can [reduce] competition by removing a [rival] from the market."}, {"text": "Boohoo initially grew organically through [social] media, and later grew externally by [acquiring] brands such as Debenhams."}, {"text": "Apple has grown primarily through [organic] growth by researching and developing new [products], rather than buying many other businesses."}, {"text": "To gain a controlling interest in a takeover, a business must buy more than [50]% of the shares in the other business."}]}, "tf": {"enabled": true, "questions": [{"statement": "Organic growth in a business is about growing vegetables organically.", "answer": false, "explain": "FALSE. Organic growth means the internal growth of a business — growing from within by increasing sales, developing products, or gaining customers. The word ''organic'' here means ''natural/internal'', not agricultural."}, {"statement": "More effective marketing will help a business grow.", "answer": true, "explain": "TRUE. Better marketing attracts new customers and increases sales — a classic method of organic growth. It helps the business grow revenue and potentially its market share."}, {"statement": "Market share is the share a worker has in the business.", "answer": false, "explain": "FALSE. Market share is the proportion of total market sales held by one business, expressed as a percentage. It has nothing to do with employees. A ''share'' in a company is a unit of ownership — a completely different concept."}, {"statement": "A merger is when one business buys a controlling interest in another business.", "answer": false, "explain": "FALSE. A merger is when two businesses mutually agree to join together. When one business purchases a controlling interest (over 50% of shares), that is a takeover. The key difference is mutual agreement vs one business buying control."}, {"statement": "With a 30% increase in the total market, a business that increases its sales by 20% will have increased its market share.", "answer": false, "explain": "FALSE. Market share is relative to the total market. If the total market grew by 30% but the business only grew by 20%, the business''s market share has actually decreased — it is growing more slowly than the market overall."}, {"statement": "External growth is always a better method of growth than organic growth.", "answer": false, "explain": "FALSE. Whether external or organic growth is better depends entirely on the context. External growth is faster but more expensive and risky. Organic growth is slower but cheaper and retains owner control. The best method depends on the business''s objectives, finances, and the competitiveness of its market."}, {"statement": "A backward vertical takeover involves a business buying a company it sells its products to.", "answer": false, "explain": "FALSE. Backward vertical means buying a supplier — a business that provides goods or services to you. Buying a business you sell to is forward vertical growth. Remember: backward = moving back up the supply chain towards suppliers."}, {"statement": "Horizontal growth occurs when two businesses at the same stage of production in the same industry combine.", "answer": true, "explain": "TRUE. Horizontal growth is exactly this — two businesses doing the same thing joining together, whether as a merger or takeover. Examples: two competing supermarkets merging, or two rival car wash businesses."}, {"statement": "Organic growth is less risky than external growth.", "answer": true, "explain": "TRUE. Organic growth uses internal resources and grows at a manageable pace, reducing financial risk. External growth involves large upfront costs, potential management difficulties, and culture clashes — making it inherently riskier."}, {"statement": "A takeover requires a business to buy more than 50% of the shares in another business to gain a controlling interest.", "answer": true, "explain": "TRUE. Owning more than 50% means the buyer can outvote all other shareholders on any decision, giving it full control over the business''s direction and strategy."}, {"statement": "Diversification involves a business merging with a direct competitor in the same industry.", "answer": false, "explain": "FALSE. Diversification is when a business joins with a company in a completely different, unrelated industry. Joining with a direct competitor would be horizontal growth — they are in the same market."}, {"statement": "It is important for technology-based businesses to constantly bring out new products if they are to grow.", "answer": true, "explain": "TRUE. In the technology sector, products quickly become outdated. Businesses like Apple rely on constant research and development (e.g. new iPhone models each year) to stay competitive and continue growing organically through product development."}]}, "misc": {"enabled": true, "items": [{"myth": "Students describe organic growth as simply ''growing your business naturally'' without specifying a method.", "truth": "Organic growth has specific methods: increasing output, developing new products, gaining new customers, and increasing market share. Always name the specific method and explain how it works in the context of the business.", "check": {"question": "What does an examiner expect a student to do when answering a question on organic growth, rather than just saying it means ''growing naturally''?", "options": ["Give the exact date the business started", "Just state that the business is getting bigger", "Name the specific method, e.g. new products", "Compare it to a takeover"], "answer": 2, "explain": "Organic growth has specific named methods that must be identified and explained in context, not just described vaguely as ''growing naturally''."}}, {"myth": "Students confuse mergers and takeovers and use the terms interchangeably.", "truth": "A merger is by mutual agreement — both businesses choose to join. A takeover is when one business buys more than 50% of another''s shares to gain control — the target may not have wanted this. The examiner will penalise you for using these interchangeably.", "check": {"question": "How does a takeover differ from a merger?", "options": ["A takeover requires both businesses to rebrand under a new name", "A takeover always involves two businesses of equal size", "A takeover and a merger are simply two names for the same process", "A takeover is buying over 50% of shares to gain control"], "answer": 3, "explain": "A merger is by mutual agreement, while a takeover is when one business buys a controlling stake (over 50% of shares) — using the terms interchangeably will be penalised."}}, {"myth": "Students say a jam maker buying a fruit farm is horizontal growth because both involve food.", "truth": "Horizontal growth means SAME stage of production in the SAME industry. A jam maker and a fruit farm are at DIFFERENT stages — one supplies the other. This is BACKWARD VERTICAL growth. Think about the supply chain direction.", "check": {"question": "A jam manufacturer buys a fruit farm that supplies it with fruit. What type of growth is this?", "options": ["Forward vertical growth, because the farm sells its fruit onward", "Backward vertical growth, since the farm supplies the jam factory", "Horizontal growth, because both businesses are involved with food", "Diversification, because farming and manufacturing are different activities"], "answer": 1, "explain": "This is backward vertical growth, not horizontal growth, because the farm supplies the jam maker — they are at different stages of production, not the same stage in the same industry."}}, {"myth": "Students describe all external growth as ''diversification''.", "truth": "Diversification is specifically when a business joins with a company in a completely UNRELATED industry. If the businesses are connected by the supply chain or operate in the same industry, it is horizontal or vertical, NOT diversification.", "check": {"question": "Which best describes when a business merger or takeover counts as ''diversification''?", "options": ["Whenever a business merges with a supplier", "Only when joining a totally unrelated industry", "Whenever any external growth takes place", "Whenever a business takes over a competitor"], "answer": 1, "explain": "Diversification specifically means joining an unrelated industry — if the businesses are linked through the supply chain or same industry, it is vertical or horizontal growth instead, not diversification."}}, {"myth": "Students write ''this will lead to more profit'' as their analysis mark.", "truth": "Examiners will not award analysis marks for just saying ''more profit''. You must explain the chain: WHY does the action lead to more profit? e.g., ''Reducing competition means fewer alternatives for customers, allowing the business to charge higher prices, increasing its profit margin (AN).''", "check": {"question": "Why would an exam answer that simply states ''this will lead to more profit'' fail to earn an analysis mark?", "options": ["Because it skips the chain of reasoning explaining why", "Because ''profit'' is spelled incorrectly in most answers", "Because analysis marks are only for evaluation questions", "Because profit is not a valid business impact"], "answer": 0, "explain": "Examiners require the full chain of reasoning (e.g. reduced competition allows higher prices, increasing profit margin) rather than a bare assertion of ''more profit''."}}, {"myth": "Students think increasing market share always means a business''s sales have increased.", "truth": "Market share can increase even if the business''s sales stay the same — if the total market shrank. Sales can also rise while market share falls if the total market grew faster. Market share is ALWAYS relative to total market size.", "check": {"question": "Can a business''s sales rise while its market share falls at the same time?", "options": ["No, market share can only be calculated using profit figures", "Yes, if the total market grows faster than its own sales", "Yes, but only if the business changes its prices", "No, market share and sales always move in the same direction"], "answer": 1, "explain": "Market share is always relative to total market size, so sales can rise while market share falls if the overall market is growing even faster."}}, {"myth": "Students think organic growth and internal growth are different terms.", "truth": "Organic growth and internal growth are the same thing — both refer to growing the business from within, without joining with another business. These terms are completely interchangeable in the exam.", "check": {"question": "Are ''organic growth'' and ''internal growth'' different concepts in the exam?", "options": ["No, but only ''internal growth'' should be used in exam answers", "Yes, internal growth only applies to increasing output", "Yes, organic growth only applies to product development", "No, they are interchangeable terms for growing from within"], "answer": 3, "explain": "Organic growth and internal growth are the same thing and are fully interchangeable terms in the exam."}}, {"myth": "For evaluation questions, students list pros and cons but never commit to a final decision.", "truth": "An evaluation MUST end with a clear, justified decision — ''I recommend X because...''. Sitting on the fence scores zero evaluation marks no matter how good the analysis is. The examiner needs to see a decision AND a contextual justification.", "check": {"question": "What is required for an evaluation answer to score full evaluation marks?", "options": ["A clear, justified final decision, not just a list of pros and cons", "A minimum of six advantages and disadvantages", "Avoiding any mention of the case study business by name", "A list of pros and cons without picking a side, to stay balanced"], "answer": 0, "explain": "Sitting on the fence scores zero evaluation marks — a clear decision with contextual justification is required, no matter how strong the analysis is."}}]}, "tips": {"enabled": true, "items": [{"title": "One Specific Term. Full Stop. Move On.", "html": "<p>A 1-mark <strong>''Identify''</strong> question needs exactly one correct, specific answer. Do not waste time writing a sentence or definition.</p>\n    <p><strong>The Formula: One precise term = 1 mark ✅</strong></p>\n    <ul>\n      <li><strong>✅ Good Answer:</strong> <em>\"Merger\"</em> or <em>\"Horizontal takeover\"</em></li>\n      <li><strong>❌ Bad Answer:</strong> <em>\"The business grew by joining with another company.\"</em> — Too vague. Name the specific term.</li>\n    </ul>\n    <p><strong>⚠️ Examiner Warning (Q2i — Nina''s Knitting Supplies):</strong></p>\n    <p>The examiner noted this question \"dichotomised candidates\" — students either knew the terms for external growth and scored full marks, or didn''t and scored zero. This is a pure <strong>vocabulary test</strong>. Revise these terms: merger, takeover, horizontal, backward/forward vertical, diversification.</p>\n    <p><strong>🚫 Don''t confuse organic and external growth methods.</strong> ''Developing new products'' is organic. ''Merger'' is external. The question will always specify which type it wants.</p>", "check": {"question": "What is the correct approach to answering a 1-mark ''Identify'' question?", "options": ["Give one precise, specific term without explanation", "List as many relevant terms as possible", "Write a full sentence defining the term", "Explain the advantages and disadvantages of the term"], "answer": 0, "explain": "The formula for a 1-mark Identify question is one precise term = 1 mark — writing a vague sentence instead of naming the specific term (e.g. ''merger'') loses the mark."}}, {"title": "State It + Apply It to the Business", "html": "<p>A 2-mark <strong>''Explain''</strong> question needs a point AND a development linked to the specific business in the case study.</p>\n    <p><strong>The Formula: State the method (1 mark) + Apply to the business context (1 mark)</strong></p>\n    <ul>\n      <li><strong>Step 1 — State:</strong> Name the specific method of organic/external growth.</li>\n      <li><strong>Step 2 — Apply:</strong> Link it directly to the business using a detail from the case study.</li>\n    </ul>\n    <p><strong>✅ Good Answer — Boohoo (2 marks):</strong></p>\n    <p><em>\"Boohoo may have expanded organically by gaining new customers (1) through using social media platforms such as Instagram and Facebook to target its 16–24 year old fashion-conscious market (1).\"</em></p>\n    <p><strong>❌ Bad Answer (0–1 marks):</strong></p>\n    <p><em>\"Boohoo grew by selling more things.\"</em> — Too vague, no context, scores 0 or 1 at most.</p>\n    <p><strong>🚫 Don''t just define organic growth.</strong> The question asks HOW the specific business used it. Use a case study detail to prove you understand the application.</p>", "check": {"question": "What must a 2-mark ''Explain'' answer include to score both marks?", "options": ["Two different named methods with no further detail", "A comparison between two different businesses", "A stated method plus its application to the business", "A definition of organic growth only"], "answer": 2, "explain": "The formula for 2-mark Explain questions is: state the method (1 mark) plus apply it to the business context using a case study detail (1 mark)."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "<p>The 3-mark analyse question requires a precise three-step chain. <strong>You will score zero for analysis if you don''t apply it to the specific business in the case study.</strong></p>\n    <p><strong>The 3-Step Formula:</strong></p>\n    <ul>\n      <li><strong>Step 1 — Understanding (U):</strong> State the benefit or drawback clearly. e.g., \"Merging with a flour producer could reduce raw material costs.\"</li>\n      <li><strong>Step 2 — Application (APP):</strong> Quote or reference a specific detail from the case study. e.g., \"...as flour is a key ingredient in Greggs&apos pastries and sausage rolls.\"</li>\n      <li><strong>Step 3 — Analysis (AN):</strong> State the bottom-line business impact. e.g., \"This would allow Greggs to lower retail prices, increasing sales.\"</li>\n    </ul>\n    <p><strong>The \"So What?\" Rule:</strong> Keep asking \"So what?\" until you reach a real business impact on costs, revenue, profit, market share, or cash flow.</p>\n    <p><strong>✅ Full-mark Answer (Greggs, 3 marks):</strong><br/>\n    <em>\"Merging with a flour producer could reduce raw material costs (U), as flour is a key ingredient in Greggs&apos pastries and vegan sausage rolls (APP). This would allow Greggs to lower its retail prices, increasing sales and helping it achieve its aim of being the nation''s favourite food-on-the-go provider (AN).\"</em></p>\n    <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n    <em>\"It would reduce costs and increase profit.\"</em> — No application, no chain = 1 mark at best.</p>", "check": {"question": "According to the ''Holy Trinity'' formula for a 3-mark Analyse question, what three steps must the answer contain?", "options": ["Knowledge, Understanding, Evaluation", "Advantage, Disadvantage, Decision", "Definition, Example, Conclusion", "Understanding, Application, Analysis"], "answer": 3, "explain": "The three-step chain is Understanding (state the benefit/drawback), Application (a case study detail), and Analysis (the bottom-line business impact) — missing the application step scores zero for analysis."}}, {"title": "Do the 3-Mark Formula Twice", "html": "<p>A 6-mark ''Analyse two...'' question is a 3-mark question done <strong>twice</strong>. Write two clearly separate, labelled paragraphs.</p>\n    <p><strong>Structure:</strong></p>\n    <ul>\n      <li><strong>Benefit 1:</strong> U → APP → AN (3 marks)</li>\n      <li><strong>Benefit 2:</strong> U → APP → AN (3 marks)</li>\n    </ul>\n    <p><strong>⚠️ Examiner Warning (Beautiful Buds Q8a):</strong></p>\n    <p>The examiner noted that many students jumped straight to \"more profit\" with no link to external growth. This scores zero. You must build the chain: <em>\"Merging (U) gives Beautiful Buds access to Green Gardens'' 12% market share (APP), increasing its sales revenue from selling plants through their retail outlets (AN).\"</em></p>\n    <p><strong>🚫 Do NOT write a conclusion.</strong> There are zero evaluation marks available in a 6-mark question. A conclusion wastes time.</p>\n    <p><strong>Context tip (Beautiful Buds):</strong> Contextual references include plants, garden centres, 12% market share, country''s largest retailer. Use them! ''Managers'' or ''Leaders'' alone are too vague for application marks.</p>", "check": {"question": "Why should a student NOT write a conclusion in a 6-mark ''Analyse two...'' question?", "options": ["Because conclusions are only allowed in 1-mark questions", "Because zero evaluation marks are available, wasting time", "Because the question only allows one paragraph in total", "Because a conclusion would repeat the case study title"], "answer": 1, "explain": "The card explicitly warns not to write a conclusion because a 6-mark Analyse question carries zero evaluation marks, making a conclusion a waste of exam time."}}, {"title": "Four-Paragraph Structure for Full Marks", "html": "<p>A 7-mark evaluate question tests all four skills. Use this four-paragraph structure:</p>\n    <ul>\n      <li><strong>Paragraph 1 — K & U:</strong> State and briefly define an advantage of the strategy.</li>\n      <li><strong>Paragraph 2 — AN & APP:</strong> Build a contextual chain: U → APP (case study detail) → AN (business impact).</li>\n      <li><strong>Paragraph 3 — AN & APP:</strong> Repeat for a disadvantage or the alternative method.</li>\n      <li><strong>Paragraph 4 — Evaluation (3 points):</strong> Decision + Contextual justification + Impact/reasoning.</li>\n    </ul>\n    <p><strong>Evaluation sentence starters:</strong></p>\n    <ul>\n      <li><em>\"Overall, I believe [business] should [action] because...\"</em> — Decision (1 mark)</li>\n      <li><em>\"This is particularly important because the case study states that...\"</em> — Context (+1 mark)</li>\n      <li><em>\"Therefore, this approach would [specific business impact], meaning...\"</em> — Reasoning (+1 mark)</li>\n    </ul>\n    <p><strong>⚠️ \"Sitting on the fence\" = 0 evaluation marks.</strong> You MUST make a clear decision. The \"It depends on...\" construction is only valid if you then commit to which side that condition favours.</p>\n    <p><strong>Exemplar from Nina''s Knitting Supplies (full marks):</strong><br/>\n    <em>\"I think Nina should switch to external growth. A merger with a competitor knitting retailer (CONT) would help her grow market share faster than organic growth, which she has done for 15 years already (EVAL). This is especially important now that new competitors are entering the market, meaning organic growth alone may no longer be fast enough to protect her business (EVAL).\"</em></p>", "check": {"question": "What happens if a student''s evaluation answer ''sits on the fence'' without making a decision?", "options": ["It automatically scores half marks", "It only loses the Knowledge and Understanding marks", "It scores zero evaluation marks, whatever the analysis", "It is acceptable as long as both sides are equally detailed"], "answer": 2, "explain": "The card states clearly that ''sitting on the fence'' equals 0 evaluation marks — a clear, justified decision is required for those marks."}}, {"title": "Use the Numbers — They''re Worth 2 Free Marks", "html": "<p>The 9-mark question awards <strong>2 separate marks purely for using numerical data</strong>. This is the most commonly missed opportunity on the entire paper.</p>\n    <p><strong>What counts as quantitative application (Shinz Ltd example):</strong></p>\n    <ul>\n      <li>Combined market share: \"40% + 10% = 50% combined market share\"</li>\n      <li>Market value: \"50% of £460,000 = £230,000\"</li>\n      <li>Share change: \"Shinz''s market share rose by 25 percentage points in 3 years\"</li>\n      <li>Customer satisfaction gap: \"Shinz''s satisfaction is 42 percentage points higher than Littlelong''s\"</li>\n      <li>Post-merger ownership: \"The business would have 5 owners\"</li>\n    </ul>\n    <p><strong>The 9-mark structure:</strong></p>\n    <ul>\n      <li><strong>K (1 mark):</strong> Define what a merger is OR use merger terminology (horizontal, vertical, etc.)</li>\n      <li><strong>U (1 mark):</strong> State one advantage or disadvantage</li>\n      <li><strong>APP (2 marks):</strong> Two uses of numerical data from the case study</li>\n      <li><strong>AN (2 marks):</strong> Two business-facing impacts</li>\n      <li><strong>EVAL (3 marks):</strong> Justified contextual decision</li>\n    </ul>\n    <p><strong>⚠️ Examiner Warning (Shinz Q3):</strong> Many high-ability students lost the Knowledge mark by not explicitly defining a merger or using merger terminology. Don''t assume the examiner knows you know the definition — say it in your first sentence!</p>", "check": {"question": "In a 9-mark ''Evaluate with Data'' question, how many marks are specifically available just for using numerical data from the case study?", "options": ["2 marks", "5 marks", "1 mark", "0 marks — data use is not separately credited"], "answer": 0, "explain": "The card states the 9-mark question awards 2 separate marks purely for quantitative/numerical application, calling it ''the most commonly missed opportunity on the entire paper''."}}, {"title": "Compare the Two Options — Don''t Just Praise One", "html": "<p>A 3-mark ''Recommend'' question (like Greggs Q4iii) needs a decision AND a <em>comparative</em> justification.</p>\n    <p><strong>The Formula:</strong></p>\n    <ul>\n      <li><strong>Decision (1 mark):</strong> A clear choice — name the specific method you recommend.</li>\n      <li><strong>Non-contextual comparison (1 mark):</strong> Explain why your choice is BETTER THAN the other option (no case study detail needed).</li>\n      <li><strong>Contextual comparison (2 marks):</strong> Explain why your choice is better using specific details from the case study.</li>\n    </ul>\n    <p><strong>Key rule: The justification MUST be comparative.</strong> Simply listing advantages of your chosen option without mentioning the other gets no justification marks. Look for comparator words: <em>whereas, unlike, compared to, better than, although.</em></p>\n    <p><strong>✅ Full-mark Answer (Greggs):</strong><br/>\n    <em>\"Greggs should merge with the flour producer (1) because it allows the business to quality-assure one of the main ingredients it needs for its vegan pastries (CONT), whereas a takeover of a rival would only put more pressure on management capacity and supply of ingredients (+2).\"</em></p>\n    <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n    <em>\"Greggs should take over a competitor because it will increase market share.\"</em> — No comparison, no context. 1 mark maximum.</p>", "check": {"question": "What is the key rule for the justification in a 3-mark ''Recommend'' question?", "options": ["The justification must compare the choice to the alternative", "The justification only needs to list advantages of the chosen option", "The justification must include a numerical calculation", "The justification must avoid mentioning the case study business"], "answer": 0, "explain": "The justification MUST be comparative — simply listing advantages of the chosen option without comparing it to the other option gets no justification marks."}}]}, "exam": {"enabled": true, "questions": [{"question": "Two vets agree to combine their practices and operate as one business. This is an example of a:", "marks": 1, "hint": "Did the two businesses agree, or did one buy the other? Also consider whether they are in the same or different industries.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Merger [1 mark]</h5><p><strong>Why C is correct:</strong> Both practices mutually agreed to combine — this is the definition of a merger. It is not a takeover because neither business bought control of the other.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Diversification:</strong> Both are in the same industry (veterinary), not unrelated industries.</li><li><strong>B — Horizontal takeover:</strong> Although horizontal (same industry), the businesses agreed to combine — making it a merger, not a takeover. A takeover requires one buying control of the other.</li><li><strong>D — Vertical takeover:</strong> The businesses are at the same stage of the same industry, not at different stages of a supply chain.</li></ul></div>"}, {"question": "Identify two methods of external growth that a business could use. [2 marks]", "marks": 2, "hint": "External growth means joining with or buying another business. Think of the two main mechanisms — and the different types of each.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a)</h5><p>One mark for each correct method of external growth identified (maximum 2).</p><p><strong>Acceptable answers include:</strong></p><ul><li>Merger / Horizontal merger / Vertical merger (backward or forward) / Lateral merger / Diversified merger</li><li>Takeover / Acquisition / Horizontal takeover / Vertical takeover (backward or forward) / Diversification</li></ul><p>Answers do not need to relate to Nina''s Knitting Supplies. ''Horizontal/vertical growth'' alone is too vague — must specify merger or takeover.</p></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>This question dichotomised candidates — students either knew external growth methods and scored full marks, or did not and scored zero. The most common correct answers were simply ''merger'' and ''takeover''. Candidates who knew the sub-types (horizontal, vertical, diversification) all scored full marks. This is a vocabulary test — learn the terms.</p></div>"}, {"question": "Evaluate whether or not Nina''s Knitting Supplies should continue to grow organically. [7 marks]", "marks": 7, "hint": "Weigh the advantages AND disadvantages of organic growth for Nina specifically. Use case study details (15 years, 10 shops, more competitors entering the market). End with a clear, justified decision — do NOT sit on the fence.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks</h5><ul><li><strong>Application (up to 2 marks):</strong> Contextual advantages/disadvantages applied specifically to Nina''s business</li><li><strong>Analysis (up to 2 marks):</strong> Business-facing impacts</li><li><strong>Evaluation (up to 3 marks):</strong> Justified contextual decision</li></ul></div><div class=\"marks-section\"><h5>Useful Application Context</h5><ul><li>Nina sells from 10 shops and a website</li><li>Business has traded for 15 years</li><li>Business has grown organically so far</li><li>Knitting is becoming an increasingly popular pastime</li><li>More competitors are entering the market</li></ul></div><div class=\"marks-section\"><h5>Evaluation Levels</h5><ul><li><strong>Strong (3 marks):</strong> Justified contextual decision referencing Nina''s specific situation</li><li><strong>Good (2 marks):</strong> Justified decision — valid but non-contextual</li><li><strong>Limited (1 mark):</strong> A decision only — e.g. \"Nina should continue to grow organically\"</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Most candidates gained at least 1 evaluation mark by making a decision. For full evaluation marks, justification must be contextual (referencing Nina''s specific case). The most common correct advantages of organic growth were low cost and retained control. The most common correct advantages of external growth were faster growth and removal of competition. Candidates who embedded case study context throughout their analysis scored best.</p></div>"}, {"question": "Evaluate, with reference to the data in Text 3, whether Shinz Ltd should merge with Littlelong Motors Ltd. [9 marks]", "marks": 9, "hint": "You need all 5 skills. K = define what a merger is. U = one advantage/disadvantage. APP = USE THE NUMBERS (calculate combined market share and its value). AN = business impact. EVAL = clear decision + justified with data. Don''t forget: 40% + 10% = 50%; 50% × £460,000 = £230,000.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 9 marks</h5><ul><li><strong>Knowledge (1 mark):</strong> Definition or terminology for merger</li><li><strong>Understanding (1 mark):</strong> One advantage or disadvantage of the merger</li><li><strong>Application — Quantitative (2 marks):</strong> Two uses of numerical data from the case study</li><li><strong>Analysis (2 marks):</strong> Two business-facing impacts</li><li><strong>Evaluation (3 marks):</strong> Justified contextual decision</li></ul></div><div class=\"marks-section\"><h5>Knowledge Examples</h5><ul><li>A merger is a form of external growth</li><li>Two firms join together to form one business</li><li>Businesses agree to join unlike a takeover</li><li>Merger terminology: horizontal, vertical, diversification</li></ul></div><div class=\"marks-section\"><h5>Quantitative Application Examples (must use numbers)</h5><ul><li>Shinz current market share: 40% = £184,000</li><li>Littlelong Motors market share: 10% = £46,000</li><li>Combined market share: 50% = £230,000</li><li>Shinz share risen 25 percentage points in 3 years</li><li>Littlelong share fallen 25 percentage points in 3 years</li><li>Customer satisfaction gap: 68% − 26% = 42 percentage points</li><li>5 owners post-merger</li></ul></div><div class=\"marks-section\"><h5>Evaluation Levels</h5><ul><li><strong>Strong (3 marks):</strong> Justified contextual decision using case study data</li><li><strong>Good (2 marks):</strong> Justified decision without context</li><li><strong>Limited (1 mark):</strong> A decision only</li></ul><p>⚠️ \"Sitting on the fence\" = 0 evaluation marks. Commit to YES or NO.</p></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>This is the highest tariff question on the paper. Most candidates achieved understanding, analysis and evaluation marks. Fewer achieved the knowledge and quantitative application marks. For knowledge, examiners wanted explicit merger terminology or a definition. For application, candidates needed to perform calculations (e.g. 40+10=50%; 50%×£460,000=£230,000). Even high-ability candidates lost the knowledge mark by not stating what a merger is. Centres should encourage students to always start 9-mark answers by defining the key concept.</p></div>"}, {"question": "Analyse one benefit for Greggs of business growth using the following method: Merger with a flour producer. [3 marks]", "marks": 3, "hint": "Think about WHY flour matters to Greggs specifically (it''s a key ingredient). What happens if Greggs controls its own flour supply? Then push to the business impact — how does this help Greggs compete or achieve its aim?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b, AO2, AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> One benefit of merging with a supplier. No further marks without this.</li><li><strong>Application (1 mark):</strong> Link the benefit to Greggs using case study detail.</li><li><strong>Analysis (1 mark):</strong> Business-facing financial or operational impact on Greggs.</li></ul><p>⚠️ Simply mentioning the word ''flour'' is NOT application — the question is already about a flour producer. Application means showing WHY flour is important to Greggs&apos specific situation.</p></div><div class=\"marks-section\"><h5>Understanding Examples</h5><ul><li>Could reduce raw material / flour / ingredient costs</li><li>Guarantee the supply of raw materials</li><li>Control the quality of flour (important for vegan products)</li><li>Shorter / more efficient supply chain</li><li>Reduce competitors'' access to flour</li></ul></div><div class=\"marks-section\"><h5>Application Examples</h5><ul><li>Flour is a key ingredient in Greggs&apos pastries, pies and sausage rolls</li><li>Greggs aims to be the customers'' favourite food-on-the-go in the UK</li><li>Growing vegan market — quality of ingredients important for new vegan product range</li></ul></div><div class=\"marks-section\"><h5>Analysis Examples</h5><ul><li>Reduced costs &rarr; improved profit margins</li><li>Lower unit costs &rarr; Greggs can reduce retail prices &rarr; competitive advantage</li><li>Guaranteed quality &rarr; consistent vegan products &rarr; customer loyalty maintained</li></ul></div>"}, {"question": "Analyse one benefit for Greggs of business growth using the following method: Takeover of a rival ''food-on-the-go'' retail brand. [3 marks]", "marks": 3, "hint": "What does Greggs instantly gain by removing a rival from the market? How does this connect to Greggs&apos specific aim as stated in the case study?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b, AO2, AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> One benefit of taking over a rival. No further marks without this.</li><li><strong>Application (1 mark):</strong> Link to Greggs using case study detail.</li><li><strong>Analysis (1 mark):</strong> Business-facing financial or operational impact on Greggs.</li></ul></div><div class=\"marks-section\"><h5>Understanding Examples</h5><ul><li>Less competition / removes a competitor from the market</li><li>Increase in stores / outlets / locations</li><li>Greater brand awareness</li><li>Increase in customers / market share</li><li>Economies of scale — bulk discounts</li><li>More control of the market</li></ul></div><div class=\"marks-section\"><h5>Application Examples</h5><ul><li>Greggs aims to be customers'' favourite for food-on-the-go in the UK</li><li>Sector forecast to be worth £23.4 billion by 2024</li><li>Greggs already has 20,000 employees</li><li>Vegan range successfully launched — growth market</li></ul></div><div class=\"marks-section\"><h5>Analysis Examples</h5><ul><li>Helps Greggs meet its aim of being the customer''s favourite</li><li>Increases cash inflows and market share</li><li>Expands Greggs into locations the rival already occupies</li></ul></div>"}, {"question": "Recommend which of the two methods of business growth Greggs should use. Give reasons for your answer. [3 marks]", "marks": 3, "hint": "Make a clear decision first. Then compare the two methods — explain why your chosen option is BETTER THAN the other one using case study details. The justification MUST be comparative (use words like ''whereas'', ''unlike'', ''compared to'').", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b)</h5><ul><li><strong>Decision (1 mark):</strong> Clear recommendation — ''merger'' or ''takeover''. Do not accept ''diversification''.</li><li><strong>Non-contextual comparison (1 mark):</strong> Explains why choice is better than the other — valid but without case study detail.</li><li><strong>Contextual comparison (2 marks):</strong> Explains why choice is better using specific Greggs context.</li></ul><p>⚠️ The justification MUST be comparative — why one is better THAN the other. Simply listing benefits of one option without comparing = 0 justification marks.</p><p>⚠️ Do not accept cost comparisons — no cost data is given in the case study.</p><p>Context words: pastries, vegan products, food-on-the-go, £23.4bn, 20,000 employees. Note: ''flour'' alone is NOT accepted as context for this question.</p></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>The justification must compare both methods. Comparator words to look for: ''whereas'', ''although'', ''more'', ''less'', ''unlike'', ''better than''. Many students lost marks by only describing their chosen option''s benefits without explaining why the other method was inferior.</p></div>"}, {"question": "Eve is a restaurant owner. She has successfully used social media to attract a lot of new customers to eat in her restaurant. This is an example of:", "marks": 1, "hint": "Has Eve merged with or bought another business? Or has she grown her customer base from within using her own marketing?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Organic growth [1 mark]</h5><p><strong>Why C is correct:</strong> Eve has grown her business internally by improving marketing (social media). Gaining new customers through marketing is organic growth — no external business was involved.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Diversification:</strong> Involves merging with/taking over a business in an unrelated industry. Eve has not joined with any other business.</li><li><strong>B — Invention:</strong> Creating a brand new product or service. Eve has not invented anything — she is just marketing her existing restaurant.</li><li><strong>D — Skimming:</strong> A pricing strategy where a high initial price is charged for a new product. Eve is using a marketing strategy, not a pricing strategy.</li></ul></div>"}, {"question": "A manufacturer of jam buys a fruit farm. This is an example of:", "marks": 1, "hint": "The fruit farm supplies the raw materials (fruit) to the jam maker. Is the jam maker moving backward or forward in the supply chain?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — A vertical takeover [1 mark]</h5><p><strong>Why B is correct:</strong> The jam manufacturer is buying its supplier (the fruit farm), moving backwards up the supply chain. Since one business is buying the other (not a mutual agreement), it is a takeover. Backward vertical + takeover = vertical takeover.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — A business partnership:</strong> A partnership is a type of business ownership structure, not a form of external growth.</li><li><strong>C — Diversification:</strong> Diversification means buying a business in a completely unrelated industry. A fruit farm directly supplies the jam maker — they are connected, so this is vertical not diversification.</li><li><strong>D — Flexible working:</strong> Flexible working is an HR concept about working patterns. Entirely unrelated to business growth.</li></ul></div>"}, {"question": "A business has gained more customers by improving the way it markets its products. Which one of the following statements must be true for this business?", "marks": 1, "hint": "Focus on the word ''must''. Only one of these is definitely true in ALL cases when a business gains customers through better marketing.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — The business has grown organically [1 mark]</h5><p><strong>Why B is correct:</strong> Gaining customers through improved marketing is internal to the business — this is organic growth by definition. This MUST be true because the business has grown from within, without any external acquisition.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Developed a new product:</strong> Not necessarily — better marketing could be for existing products. No new product was needed.</li><li><strong>C — Increased its market share:</strong> Not necessarily. If the total market grew faster than the business, its market share could actually have fallen even though it gained more customers.</li><li><strong>D — Made a profit:</strong> Not necessarily — the business may have high costs elsewhere and still operate at a loss despite gaining more customers.</li></ul></div>"}, {"question": "Analyse two benefits for Beautiful Buds plc of growing externally. [6 marks]", "marks": 6, "hint": "For EACH benefit: name a specific advantage of external growth (U), link it to Beautiful Buds using case study detail — garden centres, plants, 12% market share (APP), then explain the business-facing impact (AN). Two separate paragraphs.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 6 marks (AO1b ×2, AO2 ×2, AO3a ×2)</h5><p>For each of two benefits: 1 mark Understanding + 1 mark Application + 1 mark Analysis.</p></div><div class=\"marks-section\"><h5>Understanding Examples (for each benefit)</h5><ul><li>Quick way to grow / faster than organic methods</li><li>Expands into other businesses'' markets / gains wider product range</li><li>Benefits from the reputation of the other business</li><li>Acquires skills, technology and assets of the other business</li><li>Secures retail outlets for selling plants (forward vertical integration)</li><li>Gains established customer base of garden centres</li></ul></div><div class=\"marks-section\"><h5>Application Context</h5><p>Must reference specific Beautiful Buds details: plants, garden, garden centres, 12% market share, country''s largest, Director salaries of £110,000, operatives etc.</p><p>⚠️ ''Managers'' and ''Leaders'' alone are too vague — specify the type or reference salary data.</p><p>⚠️ Do NOT award ''money'' — must reference costs, revenue, profit, loss, or cash flow specifically.</p></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Many students jumped straight to ''more profit'' with no link to external growth — this cannot be awarded. Examiners needed a chain: \"Merging (U) with Green Gardens gives Beautiful Buds increased brand awareness in the gardening sector (APP), increasing its sales revenue (AN).\"</p></div>"}, {"question": "Identify one way that Beautiful Buds plc could have grown organically. [1 mark]", "marks": 1, "hint": "Organic growth = growing from within without joining another business. Think about what Beautiful Buds specifically does — it grows plants and sells them. What could it do more of, or differently, from within?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO2)</h5><p>1 mark for a contextual identification of an organic growth method. Application to Beautiful Buds plc''s specific situation is required.</p><p><strong>Acceptable answers include:</strong></p><ul><li>Increasing output of plants</li><li>Gaining new customers at garden centres</li><li>Improved marketing / promotion of plants</li><li>Reducing prices of plants to attract new buyers</li><li>Developing new types / varieties of plants</li><li>Extending the range of plants grown</li><li>Selling plants online</li><li>Opening a (single) garden centre</li><li>Increasing market share in the gardening industry</li></ul><p>⚠️ Do NOT award ''open more garden centres'' — implies existing ones. Award ''open a garden centre''.</p></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Some candidates confused organic and external growth, answering ''merge with a garden centre'' or ''take over a garden tools producer'' — these score zero. Best answers included ''growing a wider variety of plants'', ''selling plants online'', and ''gaining new customers through 2-for-1 promotions on house plants''.</p></div>"}, {"question": "A well-known restaurant chain buys another well-known restaurant chain. What is this an example of?", "marks": 1, "hint": "Both businesses are restaurant chains. One is BUYING the other. Are they at the same or different stages of production?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — A horizontal takeover [1 mark]</h5><p><strong>Why A is correct:</strong> Both businesses are restaurant chains — same industry, same stage of production = horizontal. One is buying the other (not mutual agreement) = takeover. Horizontal + takeover = horizontal takeover.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B — A vertical merger:</strong> Vertical means different stages of the supply chain (e.g., restaurant buying a food supplier). Both are restaurants = same stage = horizontal. Also ''buys'' = takeover, not a mutual merger.</li><li><strong>C — Diversification:</strong> Diversification means entering an unrelated industry. Both are in the restaurant industry.</li><li><strong>D — Innovation:</strong> Innovation = developing new products or processes. Buying another business is not innovation.</li></ul></div>"}, {"question": "Explain how Boohoo may have expanded using ''organic growth''. [2 marks]", "marks": 2, "hint": "Organic growth = growing from within. Use a specific detail from the Boohoo case study to show HOW they grew without joining another business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b, AO2)</h5><ul><li><strong>Understanding (1 mark):</strong> A specific method of organic growth shown.</li><li><strong>Application (1 mark):</strong> Development in Boohoo''s context — link to a specific detail from the case study.</li></ul><p><strong>Acceptable answers include (context required for second mark):</strong></p><ul><li>Gaining new customers — through social media / Facebook / Instagram / apps</li><li>Increasing market share — by expanding to sell in over 100 countries</li><li>Developing new products — own brand clothes, shoes and accessories</li><li>Improving marketing — using social media to target fashion-conscious 16–24 year olds</li><li>Reinvesting in the business — developing new apps for smartphones and tablets</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Best answers linked a specific method of organic growth directly to a detail from the Boohoo case study. Simply defining organic growth scores 1 mark; applying it to Boohoo scores the second mark.</p></div>"}, {"question": "Identify the method of growth that Boohoo has used to help grow the business in 2020/2021. [1 mark]", "marks": 1, "hint": "Boohoo was buying other businesses. What is the term for this type of growth strategy?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a)</h5><p><strong>Acceptable answers:</strong></p><ul><li>External growth</li><li>Takeover / acquisition</li><li>Horizontal growth / horizontal takeover (accept)</li></ul></div>"}, {"question": "Analyse one problem that Boohoo might have in growing the business in this way. [3 marks]", "marks": 3, "hint": "What goes wrong when a business suddenly gets much bigger by buying many different companies at once? Use specific brands Boohoo purchased as your application.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b, AO2, AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> An example of a problem with this type of external growth.</li><li><strong>Application (1 mark):</strong> Explanation relating to the Boohoo case study details.</li><li><strong>Analysis (1 mark):</strong> The business-facing effect or impact.</li></ul></div><div class=\"marks-section\"><h5>Mark Scheme Examples</h5><ul><li><strong>U:</strong> Control of the business might not be as good / harder to manage a much larger organisation effectively</li><li><strong>APP:</strong> Boohoo bought many different businesses in 2020/2021 — Oasis, Burton, Dorothy Perkins, Debenhams — all at once</li><li><strong>AN:</strong> Money may be wasted through inefficiency, causing a drop in profits / may need to employ more managers, increasing salary costs and reducing profit margins</li></ul></div>"}, {"question": "Analyse one benefit that Boohoo would have in growing the business in this way. [3 marks]", "marks": 3, "hint": "Think about what Boohoo gained immediately by acquiring famous brands like Debenhams. Who can Boohoo now sell to that it couldn''t reach before?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b, AO2, AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> An example of a benefit of this external growth.</li><li><strong>Application (1 mark):</strong> Explanation relating to the Boohoo case study.</li><li><strong>Analysis (1 mark):</strong> Business-facing effect or impact.</li></ul></div><div class=\"marks-section\"><h5>Mark Scheme Examples</h5><ul><li><strong>U:</strong> More businesses bring in more customers / can reach different customers with different tastes and demographics</li><li><strong>APP:</strong> Boohoo bought Debenhams — customers who previously bought at Debenhams online will now potentially buy from the Boohoo-owned Debenhams</li><li><strong>AN:</strong> Having new customers from stores like Debenhams will increase total income and so increase profit / growing market share across different clothing segments will increase revenue</li></ul></div>"}, {"question": "Evaluate whether or not Boohoo has made the correct decision to grow the business in this way. [3 marks]", "marks": 3, "hint": "Make a clear YES or NO decision first. Then justify using specific details — the brands Boohoo bought, the risks it faces, and the potential benefits. The best answers give a contextual reason why this was or wasn''t the right decision.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b)</h5><ul><li><strong>Judgement (1 mark):</strong> Clear statement on whether Boohoo was right — e.g. \"I think Boohoo was right to expand in this way.\"</li><li><strong>Justification (up to 2 marks):</strong> Contextual justification using case study detail.</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Note — Justification for 2 marks</h5><p>Boohoo is safeguarding its future by having a range of businesses (Oasis, Burton, Dorothy Perkins, Debenhams) offering different products to different customers. It is dangerous for any business to rely on a narrow range of products and customers — diversifying the brand portfolio reduces this risk significantly.</p></div>"}, {"question": "Which of the following statements describes a takeover?", "marks": 1, "hint": "A takeover is when one business PURCHASES control of another. Look for a scenario where money was paid to acquire another company.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Disney bought Pixar [1 mark]</h5><p><strong>Why B is correct:</strong> Disney acquired (purchased) Pixar — one business buying a controlling interest in another is a takeover.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Orange and T-Mobile:</strong> They joined together by mutual agreement — this is a merger, not a takeover.</li><li><strong>C — Honda builds a factory:</strong> Building new production capacity is internal/organic growth — Honda is not buying another business.</li><li><strong>D — Netflix increases market share:</strong> Growing market share through better products or marketing is organic growth, not a takeover of another business.</li></ul></div>"}, {"question": "What evidence is given in this case study for the growth of Apple? [1 mark]", "marks": 1, "hint": "Look for any numbers or facts in the Apple case study that show the company got bigger over time.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark</h5><p>Any one piece of specific evidence from the case study showing growth:</p><ul><li>Revenue grew from $33,300 (1976) to $49.6 billion (2016)</li><li>Apple expanded from making desktop computers to a range of products including iPhone, iPad, MacBook Pro and Apple Pay</li><li>Apple is now the largest company in the world</li></ul></div>"}, {"question": "Analyse the advantages to Apple of using organic growth. [3 marks]", "marks": 3, "hint": "Think about what Apple keeps by growing from within — control, brand identity, profits. Then connect to specific Apple examples from the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b, AO2, AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Advantage of organic growth clearly stated.</li><li><strong>Application (1 mark):</strong> Linked to Apple''s specific case study context.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact on Apple.</li></ul></div><div class=\"marks-section\"><h5>Suggested Content</h5><ul><li><strong>U:</strong> Organic growth maintains full control of the business / less costly / builds own brand expertise / allows focused product development</li><li><strong>APP:</strong> Apple developed the iPhone, iPad and MacBook Pro internally; Apple runs highly innovative marketing campaigns; revenue grew to $49.6bn; Apple taken over only a very small number of businesses</li><li><strong>AN:</strong> Apple has retained full control over its strategic direction and profits / built one of the world''s most recognisable brands / did not need to share profits with merger partners</li></ul></div>"}, {"question": "Analyse the disadvantages to Apple of using external growth. [3 marks]", "marks": 3, "hint": "Apple has only taken over ''a very small number'' of businesses. Why might aggressive external growth actually be risky for a business built on a premium brand and internal innovation?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b, AO2, AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Disadvantage of external growth clearly stated.</li><li><strong>Application (1 mark):</strong> Linked to Apple''s case study context.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact on Apple.</li></ul></div><div class=\"marks-section\"><h5>Suggested Content</h5><ul><li><strong>U:</strong> External growth can be very expensive / causes loss of control / risk of culture clash / management challenges from running a larger organisation</li><li><strong>APP:</strong> Apple has taken over only a very small number of businesses throughout its history; Apple has grown to become the world''s largest company through its own product innovation</li><li><strong>AN:</strong> If Apple pursued aggressive external growth, it might struggle to maintain its premium brand values; additional owners would need to share profits; management challenges could reduce efficiency and damage innovation</li></ul></div>"}]}}'::jsonb),
('business', '2-1-role-of-marketing', '2.1 The Role of Marketing', '{"learn": {"enabled": true, "items": [{"title": "What is Marketing?", "html": "<p><strong>Marketing</strong> is concerned with finding the needs of customers and demonstrating how a business fulfils those needs in a way that increases sales. It is vital to the success of any business.</p>\n<p>Marketing is one of four key functional areas of business. It focuses on the <em>customer</em> rather than the producer. Essentially, marketing ensures that the right product or service is available in the right place at the right time for the right price.</p>\n<p>Some large businesses will spend millions of pounds on marketing; other more local businesses may spend a few pounds on a local newspaper advertisement. Both of these examples have the same objective: they want to <strong>increase sales</strong>.</p>\n<p><strong>Market research</strong> is the collection of data on consumer habits to help decision-making in marketing.</p>\n<p><strong>Important distinction:</strong> Marketing is much broader than just advertising. It includes identifying customer needs, recognising different types of customer, informing customers of available products and services, and ensuring customers receive their goods with an appropriate level of satisfaction.</p>", "check": {"question": "According to the core definition, marketing is best described as:", "options": ["Finding needs and showing how the business meets them", "Manufacturing products to a high quality standard", "Advertising a business''s products on TV and social media", "Setting the lowest possible price for products"], "answer": 0, "explain": "Marketing is defined as finding the needs of customers and demonstrating how a business fulfils those needs in a way that increases sales — advertising is only one part of this, not the whole of marketing."}}, {"title": "Role 1 — Identifying and Understanding Customers", "html": "<p>A business must be clear on who it is trying to sell its products or services to. This is about understanding the <strong>target market</strong> — who are the customers?</p>\n<ul>\n<li>Is it trying to sell to all ages, both male and female?</li>\n<li>Or just females between 20 and 40 years old?</li>\n<li>Are they local, national, or international customers?</li>\n<li>What income group do they belong to?</li>\n</ul>\n<p>A <strong>market</strong> is a group of people who share characteristics — e.g. age, income, location, gender. Answers to these questions are found through <strong>market research</strong> (see Unit 2.2).</p>\n<p>The business then analyses this information to make sure that it really is providing what the customer wants. Without checking with the customer, mistakes can be made and these mistakes can prove very costly for businesses.</p>\n<p><strong>Factors influencing who marketing is aimed at:</strong></p>\n<ul>\n<li>Young people may be more likely to respond to advertisements on social media</li>\n<li>Different people may require different products — e.g. some older people may like a mobile phone that has large buttons and is easy to use</li>\n<li>Only rich people may be willing to pay high prices for top quality goods</li>\n<li>Location of potential customers — which country or region do they live in and what language do they speak?</li>\n</ul>", "check": {"question": "What is meant by a ''market'' in marketing?", "options": ["The total number of competitors in an industry", "A physical place where products are bought and sold", "People sharing characteristics like age or location", "The department responsible for setting prices"], "answer": 2, "explain": "The card defines a market as a group of people who share characteristics — e.g. age, income, location, gender."}}, {"title": "Role 2 — Informing Customers", "html": "<p>Customers need to be informed by the business of the products and services they are selling. There is no real point in researching what customers want, making that product, and then not informing customers through advertising that it is available.</p>\n<p>Informing customers is normally achieved through <strong>advertising</strong> (see Unit 2.4). There are a number of different ways a business might advertise, including:</p>\n<ul>\n<li>Television</li>\n<li>Radio</li>\n<li>Newspapers and magazines</li>\n<li>Billboards</li>\n<li>Social media</li>\n<li>Leaflets through letterboxes</li>\n</ul>\n<p><strong>Scale varies by business size:</strong> Kellogg''s is a very large company with huge resources which can be used to inform customers of a change to their products or a new lower price offer — this advertising will be aimed at customers countrywide. In contrast, a new local pizza delivery business might simply put leaflets through the letterboxes of homes in the nearby estate to tell possible customers of the service they offer. Each business has a different market to inform.</p>\n<p><strong>Finance matters:</strong> How much a business spends on informing customers will depend on how much it can afford and who it needs to inform.</p>", "check": {"question": "Why might a large company like Kellogg''s use nationwide TV advertising while a small local pizza business uses leaflets?", "options": ["Only large businesses are legally allowed to advertise on TV", "The method depends on the size and resources of the business", "Small businesses are not permitted to use social media", "Leaflets are always more effective than TV advertising"], "answer": 1, "explain": "The card explains that scale varies by business size — Kellogg''s has huge resources for nationwide advertising, while a local business might rely on leaflets, since spending depends on what a business can afford and who it needs to inform."}}, {"title": "Role 3 — Increasing Sales", "html": "<p>Marketing aims to increase sales. This could be achieved by:</p>\n<ul>\n<li><strong>a) Advertising more</strong> — raising awareness of what is on offer</li>\n<li><strong>b) Introducing a new model</strong> — one that will appeal to more customers, for example, higher definition televisions</li>\n<li><strong>c) Increasing the range of products or services</strong> — Cars such as the Ford Fiesta come in many different models</li>\n<li><strong>d) Reducing the price</strong> — sales may increase, but will profits go up? Selling a new car at £1,000 may well increase sales but no profit will be made. A business must make sure that the price it charges is low enough to attract customers but high enough to make a profit</li>\n<li><strong>e) Selling the product in different places</strong> — Should a business sell to a single chain of shops or a range of different shops? Should it sell direct to customers?</li>\n<li><strong>f) Selling by different methods</strong> — Selling online, or offering digital distribution, will help increase sales of products such as books and music</li>\n</ul>\n<p>These six approaches map to the <strong>4Ps of marketing</strong>: Product, Place, Price, Promotion — which are explored in more detail in later units.</p>", "check": {"question": "Why must a business be careful when reducing price to increase sales?", "options": ["Customers always prefer higher prices", "Reducing price is illegal under consumer law", "A lower price may increase sales but shrink profit", "Reducing price always increases production costs"], "answer": 2, "explain": "The card warns that selling a new car at £1,000 may increase sales but no profit will be made — price must be low enough to attract customers but high enough to make a profit."}}, {"title": "Marketing and Other Business Functions", "html": "<p>Marketing does not operate in isolation — it works closely with other functional areas of the business:</p>\n<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Department</div>\n<div class=\"pro-item\"><strong>Human Resources (HR):</strong> Marketing works with HR to check there will be enough workers to support the anticipated level of sales</div>\n<div class=\"pro-item\"><strong>Operations / Production:</strong> Marketing informs Operations of anticipated sales predictions to allow them to plan the production schedule</div>\n</div>\n<div>\n<div class=\"col-head\">Department</div>\n<div class=\"pro-item\"><strong>Finance:</strong> Marketing works with Finance to check there is enough money to pay for the resources required — e.g. an advertising campaign</div>\n<div class=\"pro-item\"><strong>Research &amp; Development:</strong> Marketing works with R&amp;D to develop products that meet the wants and needs of customers</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Example:</strong> A manufacturer decides to run a marketing campaign on national television. As a result, Operations may need to increase output and HR may need to employ some temporary production workers to meet the expected increase in demand.</p>\n<p><strong>Finance available</strong> also directly influences marketing: how much finance is available to spend on research and development of a new product, or on an advertising campaign?</p>", "check": {"question": "Which department does marketing work with to ensure there is enough money to fund an advertising campaign?", "options": ["Research & Development", "Finance", "Human Resources", "Operations"], "answer": 1, "explain": "The card explains that marketing works with Finance to check there is enough money to pay for resources such as an advertising campaign."}}, {"title": "Evaluation — Is Marketing Always Worth It?", "html": "<p>Not all businesses will spend money, time and effort on marketing themselves. Whether a business invests in marketing will often depend on the <strong>size and circumstances of the business</strong>.</p>\n<p><strong>Arguments for marketing spending:</strong></p>\n<ul>\n<li>Informs customers of products and services that are available</li>\n<li>Can significantly increase sales and revenue</li>\n<li>Builds brand awareness and customer loyalty</li>\n<li>Helps identify gaps in the market and understand customer needs</li>\n<li>Essential in competitive markets to stay ahead of rivals</li>\n</ul>\n<p><strong>Arguments against / limitations:</strong></p>\n<ul>\n<li>Money spent on marketing does not always bring about the required increase in sales</li>\n<li>Marketing campaigns can be very expensive — particularly TV advertising</li>\n<li>Small or local businesses may not need extensive marketing — word of mouth may be sufficient</li>\n<li>Poor marketing can waste resources if it targets the wrong customers</li>\n</ul>\n<p><strong>Case study — Kellogg''s:</strong> Throughout its long history, Kellogg''s has moved with the times in the way it markets itself. Its marketing takes many different forms: how it advertises, the different products it introduces (e.g. reducing salt in Corn Flakes by 30%, adding vitamin D to children''s cereals, changing packet designs in 2019), and how the image of the business is portrayed. All this aims to give the customer a positive feel about Kellogg''s which it hopes will lead to customers buying its products.</p>", "check": {"question": "Which of these is given as a limitation of spending money on marketing?", "options": ["Marketing is illegal for small businesses", "Marketing spending does not always raise sales", "Marketing has no effect on brand awareness", "Marketing always guarantees a rise in sales"], "answer": 1, "explain": "The evaluation card notes that money spent on marketing does not always bring about the required increase in sales, and small/local businesses may not need extensive marketing as word of mouth may suffice."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Marketing", "definition": "Finding the needs of consumers and demonstrating how a business fulfils those needs in a way that increases sales. It is vital to the success of any business."}, {"term": "Market", "definition": "A group of people who share characteristics — e.g. age, income, location — who a business targets with its products or services."}, {"term": "Target market", "definition": "The specific group of customers a business aims its product or service at. Identified through market research."}, {"term": "Market research", "definition": "The collection of data on consumer habits and needs to help decision-making in marketing. Helps a business understand what customers want."}, {"term": "Identifying customers (role of marketing)", "definition": "Understanding WHO the customers are — their age, gender, income, location — and what they need. Without this, businesses risk making costly mistakes."}, {"term": "Informing customers (role of marketing)", "definition": "Making potential customers aware of products or services through advertising — e.g. TV, social media, leaflets, radio. Method chosen depends on budget and target market."}, {"term": "Increasing sales (role of marketing)", "definition": "A key aim of marketing — achieved by advertising more, reducing price, selling in different places, widening the product range, or selling by different methods such as online."}, {"term": "4Ps of marketing", "definition": "Product, Price, Place and Promotion — the four key marketing decisions a business makes about how to bring a product to market."}, {"term": "Marketing and HR", "definition": "Marketing works with HR to check there will be enough workers to support the anticipated level of sales — e.g. hiring extra staff before a major campaign."}, {"term": "Marketing and Operations", "definition": "Marketing informs Operations of anticipated sales predictions so they can plan the production schedule and ensure enough stock is made."}, {"term": "Marketing and Finance", "definition": "Marketing works with Finance to check there is enough money to pay for the resources required — e.g. funding an advertising campaign."}, {"term": "Marketing and R&D", "definition": "Marketing works with Research & Development to develop products that meet the wants and needs of customers identified through market research."}, {"term": "Kellogg''s marketing", "definition": "Kellogg''s has moved with the times — using TV ads (e.g. Jonathan Ross, 1970), reducing salt in Corn Flakes (2010), adding vitamin D, changing packet designs (2019), and supporting school breakfast clubs. All aimed at increasing sales."}, {"term": "Small vs large business marketing", "definition": "Large businesses (e.g. Kellogg''s) can afford nationwide TV campaigns. Small businesses may use leaflets or local newspapers. The method depends on size, budget, and target market."}, {"term": "Evaluation of marketing spend", "definition": "Money spent on marketing does not always bring about the required increase in sales. Whether a business invests in marketing depends on its size, budget, and competitive circumstances."}, {"term": "Purpose of TV advertising (benefit)", "definition": "TV advertising reaches a large audience nationwide. This means more consumers are informed about the product and are more likely to buy it — increasing sales for businesses like Fairy Liquid."}]}, "mcq": {"enabled": true, "questions": [{"question": "The principal role of marketing is to:", "options": ["Increase sales", "Increase the skills of the workers", "Increase profit", "Increase the number of products made"], "answer": 0, "explain": "Correct answer: increase sales. The principal role of marketing is to increase sales by identifying customer needs, informing customers, and finding ways to sell more products or services. Profit may follow from increased sales, but increasing profit is not the primary role of the marketing function."}, {"question": "The way a business informs customers about a new product or service:", "options": ["Is the same operation for all businesses", "Is only done at a national level", "Is only done at a local level", "Can vary depending on the size of the business"], "answer": 3, "explain": "Correct answer: can vary depending on the size of the business. A large company like Kellogg''s can afford nationwide TV advertising, while a small local pizza delivery business might simply put leaflets through nearby letterboxes. The approach depends on the size, budget, and target market of the business."}, {"question": "A business can understand the needs of its customers by:", "options": ["Making the best possible product", "Conducting market research", "Having special offers such as buy one get one free", "Setting a lower price than competitors"], "answer": 1, "explain": "Correct answer: conducting market research. Market research is the collection of data on consumer habits and needs to help decision-making in marketing. Making a good product, lowering price, or running offers may attract customers but do not in themselves help a business understand what customers need."}, {"question": "Which of the following would NOT usually lead to an increase in sales?", "options": ["A reduction in the range of products", "An increase in advertising", "A reduction in price", "Selling products in different places"], "answer": 0, "explain": "Correct answer: a reduction in the range of products. Reducing the range of products limits choice for customers and is unlikely to increase sales. Increasing advertising (A), reducing price (B), and selling in different places (D) are all recognised ways to increase sales."}, {"question": "One purpose of marketing at a library is to:", "options": ["Update the library''s stock of books", "Encourage more families to use the library", "Advertise for an apprentice librarian", "Provide better training for librarians"], "answer": 1, "explain": "Correct answer: encourage more families to use the library. Marketing is about identifying and meeting customer needs and increasing use of the product or service. Advertising for staff (A), training staff (C), and updating stock (D) are operational/HR functions, not marketing functions."}, {"question": "One role of marketing within a hair salon is:", "options": ["To ensure that each hairdresser has a contract of employment", "To minimise the likelihood of customers getting head lice", "To advertise a vacancy for a trainee hairdresser", "To increase the number of hair appointments booked"], "answer": 3, "explain": "Correct answer: to increase the number of hair appointments booked. This directly relates to the marketing role of increasing sales. Advertising for staff (A) is a recruitment/HR function. Contracts of employment (B) are an HR/legal function. Head lice prevention (D) is an operational/health and safety matter."}, {"question": "Jacqui works as a marketing assistant at her local library. Which of the following would be part of Jacqui''s job role?", "options": ["Advertising a vacancy for a senior librarian", "Arranging induction training for a new library assistant", "Improving the way the books are displayed", "Designing a competition to encourage people to read more"], "answer": 3, "explain": "Correct answer: designing a competition to encourage people to read more. This is a marketing activity because it aims to increase engagement with the library''s services. Advertising a vacancy (A) and arranging induction (B) are HR functions. Improving book displays (D) is an operational function."}, {"question": "A manufacturer has decided to run a marketing campaign on national television in a month''s time. As a result of this decision, which one of the following actions might also be necessary?", "options": ["Operations management should reduce output", "Human resources should employ some temporary production workers", "Purchasing should buy smaller quantities of raw materials", "Finance should stop monitoring cash flow"], "answer": 1, "explain": "Correct answer: Human resources should employ some temporary production workers. A successful TV marketing campaign will likely increase demand, meaning more products need to be made. HR will need to employ extra workers to support the increased production. Reducing output and buying smaller quantities of raw materials both contradict the expected increase in demand, and a business should never stop monitoring cash flow — least of all when demand is about to rise."}, {"question": "A primary purpose of the marketing function of a business is:", "options": ["To employ staff", "To increase sales", "To improve employee retention", "To reduce costs"], "answer": 1, "explain": "Correct answer: to increase sales. The primary purpose of the marketing function is to increase sales by identifying customer needs, informing customers, and finding ways to attract and keep customers. Employing staff and improving retention are HR functions. Reducing costs is primarily an operations/finance concern."}, {"question": "Which of the following best describes what marketing involves?", "options": ["Finding the needs of consumers and demonstrating how a business fulfils those needs to increase sales", "Only advertising a product on television", "Employing the best salespeople to sell products", "Making the highest quality product possible"], "answer": 0, "explain": "Correct answer: Marketing is defined as finding the needs of consumers and demonstrating how a business fulfils those needs in a way that increases sales. It is much broader than just advertising — it includes market research, understanding customers, informing them, and finding ways to increase sales through product, price, place, and promotion."}]}, "fib": {"enabled": true, "questions": [{"text": "Marketing is concerned with finding the [needs] of customers and demonstrating how a business fulfils those needs in a way that increases [sales]."}, {"text": "The three main roles of marketing are: identifying and understanding [customers], informing [customers], and increasing [sales]."}, {"text": "A [market] is a group of people who share characteristics such as age, income or location. A business identifies its [target] market through market research."}, {"text": "Marketing does not work alone. It works with [HR] to check there are enough workers, and with [Finance] to check there is enough money to fund campaigns."}, {"text": "Sales can be increased by reducing [price], selling in different [places], increasing advertising, or introducing new [products]."}, {"text": "Marketing is not just about [advertising]. It includes understanding customer needs through [market] research, and then informing customers of what is available."}]}, "tf": {"enabled": true, "questions": [{"statement": "The role of marketing is to increase the production of products.", "answer": false, "explain": "FALSE. Increasing production is the role of the Operations/Production department. The role of marketing is to identify customer needs, inform customers, and increase SALES — not to increase production levels."}, {"statement": "The role of marketing is to give workers a better place to work.", "answer": false, "explain": "FALSE. Improving working conditions for staff is the role of Human Resources (HR), not marketing. Marketing focuses on customers — identifying their needs, informing them about products, and increasing sales."}, {"statement": "The role of marketing is to inform customers of new products.", "answer": true, "explain": "TRUE. Informing customers is one of the three main roles of marketing. This is done through advertising — via TV, radio, social media, newspapers, or leaflets — to make customers aware of products and services available."}, {"statement": "The role of marketing is to make higher quality products.", "answer": false, "explain": "FALSE. Making products is the role of the Operations/Production department. Marketing''s role is to understand what quality level customers want (through market research) and then communicate it — not to physically produce or improve products."}, {"statement": "The role of marketing is to increase the sales of products and services.", "answer": true, "explain": "TRUE. Increasing sales is the principal role of marketing. This can be achieved through advertising, introducing new products, reducing prices, selling in new places, or selling by different methods such as online."}, {"statement": "The role of marketing is to undertake market research in order to understand the needs of customers.", "answer": true, "explain": "TRUE. Conducting market research to identify and understand customers is a key role of marketing. Without understanding what customers want, a business risks making costly mistakes — producing products or services that customers do not want."}, {"statement": "Large businesses and small businesses should always use exactly the same marketing methods.", "answer": false, "explain": "FALSE. The way a business informs customers can vary depending on the SIZE of the business. A large business like Kellogg''s can afford nationwide TV campaigns. A small local business may only need to put leaflets through nearby letterboxes. The right method depends on the budget, target market, and scale of the business."}, {"statement": "Money spent on marketing always brings about the required increase in sales.", "answer": false, "explain": "FALSE. Money spent on marketing does not ALWAYS bring about the required increase in sales. Marketing effectiveness depends on how well it is targeted, the quality of the campaign, competition, and whether the product actually meets customer needs. This is why market research is important before committing to expensive campaigns."}, {"statement": "Marketing works with the Operations department to inform them of anticipated sales so they can plan their production schedule.", "answer": true, "explain": "TRUE. Marketing works with Operations to share sales predictions so the production team can plan how much to produce. If a major campaign is planned, Operations needs advance notice to ensure enough products are available to meet the expected increase in demand."}, {"statement": "Reducing the range of products available is likely to increase sales for a business.", "answer": false, "explain": "FALSE. A reduction in the range of products is UNLIKELY to increase sales — it limits customer choice. Marketing typically aims to INCREASE the range of products or services to appeal to more customers and boost sales."}]}, "misc": {"enabled": true, "items": [{"myth": "Students often think marketing is the same as advertising.", "truth": "Marketing is much broader than advertising. It includes: identifying who the customers are (target market), understanding their needs through market research, informing them about products and services, and finding ways to increase sales through product, price, place and promotion. Advertising is just one part of the ''informing customers'' role.", "check": {"question": "Which statement most accurately describes the scope of marketing?", "options": ["Marketing is broader than just advertising alone", "Marketing is solely about designing packaging", "Marketing only involves TV and social media campaigns", "Marketing is identical to advertising"], "answer": 0, "explain": "The card corrects the common misconception that marketing equals advertising — advertising is just one part of the ''informing customers'' role within the broader marketing function."}}, {"myth": "Students often write that the purpose of marketing is ''to make a profit'' or ''to increase profit''.", "truth": "The principal role of marketing is to INCREASE SALES, not profit directly. The examiner mark scheme specifically states that ''increase sales'' is the correct answer. Profit may result from higher sales, but profit is not the primary purpose of the marketing function — and reducing the price to increase sales could even reduce profit.", "check": {"question": "According to the exam mark scheme, what is the principal role of marketing?", "options": ["To increase sales", "To reduce costs", "To increase production", "To increase profit"], "answer": 0, "explain": "The mark scheme specifically states ''increase sales'' as correct — profit may result from higher sales, but is not the primary purpose of marketing."}}, {"myth": "Students often give generic answers to ''explain the purpose of marketing within [named business]'' questions without applying to that business.", "truth": "For 2-mark ''explain'' questions about a named business, you must APPLY your answer. A generic answer (''marketing increases sales'') only scores 1 mark. You must link it to the specific business — e.g. ''Marketing helps Ford Motors identify which car models to develop that meet the needs of different market segments, such as eco-friendly small cars and 7-seater people carriers.'' The application mark requires a reference to cars, models, vehicles, or other details from the case study.", "check": {"question": "For a 2-mark ''explain the purpose of marketing within [named business]'' question, what is required for the second mark?", "options": ["Listing as many marketing purposes as possible", "Applying the point to specific details of the business", "Describing the business''s history", "Repeating the definition of marketing in different words"], "answer": 1, "explain": "A generic answer only scores 1 mark; the application mark requires linking the point to specific details from the named business''s case study."}}, {"myth": "Students sometimes write that ''sales'' or ''selling'' alone is a purpose of marketing, without adding ''more/increase/additional''.", "truth": "Simply writing ''sales'' or ''sell'' is too vague and is awarded zero by examiners — this is the role of the sales function rather than the marketing function. You must make clear that marketing is about INCREASING sales or selling MORE. Always add ''more'', ''increase'', ''additional'', or ''extra'' when referring to sales as a purpose of marketing.", "check": {"question": "Why would an examiner reject the answer ''marketing is about sales'' when explaining the purpose of marketing?", "options": ["Because ''sales'' is spelled incorrectly", "Too vague — sales must be described as increasing", "Because sales are the responsibility of Operations, not marketing", "Because the word ''sales'' is banned from GCSE answers"], "answer": 1, "explain": "The card warns that writing ''sales'' or ''sell'' alone is awarded zero marks — students must make clear marketing is about INCREASING sales, adding words like ''more'', ''increase'', or ''additional''."}}, {"myth": "Students often confuse the marketing function with HR, operations, or other functional areas.", "truth": "Marketing focuses on customers and increasing sales. HR deals with recruitment, training, and employment. Operations manages production. Finance manages money and budgets. A common exam error is writing that a marketing role includes ''advertising for staff'' or ''arranging training'' — these are HR functions. The marketing function communicates WITH these departments but does not perform their roles.", "check": {"question": "Which of the following would be a marketing role rather than an HR role?", "options": ["Issuing contracts of employment", "Designing a sales competition for a product", "Arranging induction training for new employees", "Advertising a vacancy for a new staff member"], "answer": 1, "explain": "The card clarifies that marketing focuses on customers and increasing sales, while advertising for staff, training and contracts are HR functions that a common exam error wrongly attributes to marketing."}}, {"myth": "Students sometimes think all businesses market themselves in exactly the same way.", "truth": "The way a business informs customers CAN VARY DEPENDING ON THE SIZE OF THE BUSINESS. A large business like Kellogg''s uses nationwide TV advertising and social media. A small local business might use leaflets or a local newspaper. The approach depends on the size, budget, and target market. Money spent on marketing does not always bring about the required increase in sales — so businesses must choose their methods carefully.", "check": {"question": "What determines the marketing methods a business chooses to use?", "options": ["The number of competitors'' products in stock", "The age of the business owner", "The business''s size, budget and target market", "The colour scheme of the business logo"], "answer": 2, "explain": "The card states the way a business informs customers can vary depending on the size of the business, with the approach depending on size, budget and target market."}}]}, "tips": {"enabled": true, "items": [{"title": "Explain the Purpose of Marketing Within [Named Business]", "html": "<p>Structure: Knowledge (1) + Application to the named business (1)</p>\n<ul>\n<li>State ONE purpose of marketing — e.g. to identify customer needs, to inform customers, to increase sales</li>\n<li>Apply it to the specific business using a detail from the case study</li>\n</ul>\n<p><strong>Example (Ford Motors):</strong> \"One purpose of marketing within Ford Motors is to identify the needs of different customer groups (K). This allows Ford to develop a range of models that differ in size — such as eco-friendly small cars, family cars, sports cars and 7-seater people carriers — to meet the individual needs of different market segments (APP).\"</p>\n<p><strong>Common error:</strong> A generic answer (''marketing increases sales'') only scores 1 mark. The application must reference cars, models, vehicles, or other Ford-specific details.</p>", "check": {"question": "What two-part structure earns full marks on a 2-mark ''explain the purpose of marketing within [named business]'' question?", "options": ["An example from any business plus a diagram", "Two separate purposes of marketing, unapplied", "Knowledge of a purpose plus its business application", "A definition of marketing plus a definition of sales"], "answer": 2, "explain": "The tip states the structure is Knowledge (1) + Application to the named business (1) — a generic answer without business-specific application only scores 1 mark."}}, {"title": "Analyse a Benefit of a Marketing Method", "html": "<p>Structure: Understanding (1) → Application to the business (1) → Business-facing Analysis (1)</p>\n<ul>\n<li>State ONE benefit of the marketing method (e.g. TV reaches a large audience)</li>\n<li>Apply it to the specific business in the question</li>\n<li>Explain the business impact — e.g. effect on sales, revenue, awareness, competitive position</li>\n</ul>\n<p><strong>Example (Fairy Liquid, TV):</strong> \"TV advertising reaches a large audience (U). Fairy Liquid targets households throughout the UK (APP). By reaching a large target audience, more consumers will be informed about Fairy Liquid and so are more likely to buy the product, increasing sales (AN).\"</p>", "check": {"question": "What is the correct three-part structure for a 3-mark ''analyse a benefit of a marketing method'' question?", "options": ["Application, application, and a final analysis point", "A definition, an example, and a conclusion", "Three separate benefits listed without explanation", "Understanding, application, then business analysis"], "answer": 3, "explain": "The tip specifies the structure as Understanding (1) → Application to the business (1) → Business-facing Analysis (1), as shown in the Fairy Liquid TV advertising example."}}, {"title": "Explain What is Meant by Target Market", "html": "<p>Structure: Knowledge (1) + Understanding through example (1)</p>\n<ul>\n<li>Define target market — the group of people a business aims its product at</li>\n<li>Give a relevant example — either from the case study or any business</li>\n</ul>\n<p><strong>Example:</strong> \"A target market is the group of customers to whom a business aims its product or service (K). For Fairy Liquid, the target market is households throughout the UK who need a washing-up liquid (U).\"</p>", "check": {"question": "To fully answer ''explain what is meant by target market'' for 2 marks, a student should provide:", "options": ["A list of four different target markets", "Two unrelated definitions of marketing terms", "An example only, without any definition", "A definition of target market plus an example"], "answer": 3, "explain": "The tip requires Knowledge (1) — defining target market as the group a business aims its product at — plus Understanding through a relevant example (1), as in the Fairy Liquid example."}}, {"title": "Analyse Two Factors Which Influence How a Business Markets Its Products", "html": "<p>For each factor: Understanding (1) + Application to the specific business (1) + Analysis of why it affects marketing (1)</p>\n<p><strong>Common factors to know:</strong></p>\n<ul>\n<li><strong>Finance available:</strong> How much money the business has to spend on advertising or R&amp;D will determine the scale and method of marketing</li>\n<li><strong>Who the marketing is aimed at:</strong> Young people respond better to social media; older people may prefer TV or newspapers; rich customers may expect premium advertising</li>\n<li><strong>Location of customers:</strong> Local business = local methods; global business = national/international campaigns</li>\n<li><strong>Competition:</strong> Intense competition means a business must keep its product in customers'' minds</li>\n<li><strong>Size of business:</strong> Small businesses have smaller budgets and target local audiences; large businesses can afford mass-market campaigns</li>\n</ul>\n<p><strong>Apply each factor to the named business using case study details for full marks.</strong></p>", "check": {"question": "For the 6-mark ''analyse two factors influencing how a business markets its products'' question, how are the marks awarded?", "options": ["One mark per factor regardless of detail", "All six marks for a single, fully detailed factor", "Six marks for simply naming six different factors", "Three marks per factor, covering U, APP and AN"], "answer": 3, "explain": "For each of the two factors, marks are awarded for Understanding (1) + Application to the specific business (1) + Analysis of why it affects marketing (1), giving 3 marks per factor."}}, {"title": "The Three Roles — What Counts as Each?", "html": "<p><strong>1. Identifying and understanding customers:</strong> Market research, analysing who the target market is (age, gender, income, location), identifying a gap in the market, understanding customer preferences.</p>\n<p><strong>2. Informing customers:</strong> TV, radio, social media, newspapers, billboards, leaflets, websites. The method chosen depends on the target market and budget available.</p>\n<p><strong>3. Increasing sales:</strong> Advertising, new products, wider product range, price reductions, selling in new places (distribution), selling by different methods (online, digital).</p>\n<p><strong>What marketing is NOT:</strong> Recruiting staff (HR), managing production (Operations), managing finances (Finance), training workers (HR). These departments work WITH marketing but marketing does not perform these roles.</p>", "check": {"question": "According to the quick reference, which of these is explicitly NOT part of the marketing function?", "options": ["Identifying the target market through research", "Recruiting and training staff", "Informing customers via TV or social media", "Increasing sales through price changes"], "answer": 1, "explain": "The card states recruiting staff (HR), managing production (Operations), managing finances (Finance) and training workers (HR) are NOT part of marketing, even though these departments work with marketing."}}]}, "exam": {"enabled": true, "questions": [{"question": "One purpose of marketing at a library is to:", "marks": 1, "hint": "Marketing is about customers and increasing use of a product or service — not about staff or stock management.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B — Encourage more families to use the library.</strong></p><p>Marketing is about identifying customer needs and increasing the use of a product or service. Options A and C are HR functions. Option D is an operational decision. Only option B relates directly to the marketing role of increasing usage/sales.</p></div>"}, {"question": "One role of marketing within a hair salon is:", "marks": 1, "hint": "Think about what the marketing function is responsible for — customers and sales, not staff or health and safety.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: C — To increase the number of hair appointments booked.</strong></p><p>Increasing appointments is directly linked to increasing sales — a core marketing role. Option A is recruitment (HR). Option B is contracts of employment (HR/legal). Option D is health and safety (operations).</p></div>"}, {"question": "Jacqui works as a marketing assistant at her local library. Which of the following would be part of Jacqui''s job role?", "marks": 1, "hint": "Think about which option directly relates to attracting and engaging customers/users.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: C — Designing a competition to encourage people to read more.</strong></p><p>This is a marketing activity aimed at engaging users of the library and increasing its use. Options A and B are HR functions. Option D is an operational/visual merchandising function.</p></div>"}, {"question": "Explain the purpose of marketing within Ford Motors. [2 marks]", "marks": 2, "hint": "State ONE purpose of marketing clearly, then apply it specifically to Ford — use details from the case study such as the different car models, market segments, or market research.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a + AO2)</h5><ul><li><strong>Knowledge (1 mark):</strong> State a purpose of marketing — e.g. to increase sales / to identify gaps in the market / to identify/understand customer needs / to inform customers / to raise awareness / to attract customers / to gain brand loyalty.</li><li><strong>Application (1 mark):</strong> Apply to Ford Motors using case study details — e.g. cars, vans, trucks, buses, names of models (KA, Fiesta, Focus, Mondeo, Galaxy), eco-friendly small cars, family cars, sports cars, 7-seater people carriers, market research, product lifecycle, different market segments.</li></ul><p><strong>Important:</strong> ''Sales'' or ''sell'' alone is too vague — must say ''increase sales'', ''sell more'', or ''additional sales''. Do not accept ''model'' as application alone.</p></div>"}, {"question": "A manufacturer has decided to run a marketing campaign on national television in a month''s time. As a result of this decision, which one of the following actions might also be necessary?", "marks": 1, "hint": "A successful TV campaign will increase demand — what does the business need more of to meet that demand?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B — Human resources should employ some temporary production workers.</strong></p><p>A successful national TV campaign will increase demand for the product. To meet this demand, more products need to be manufactured — so HR needs to employ additional temporary production workers. Options C and D (reducing output and buying smaller quantities) contradict the expected increase in demand. Option A is incorrect — finance should continue monitoring cash flow, especially with increased expenditure.</p></div>"}, {"question": "Explain what is meant by target market. [2 marks]", "marks": 2, "hint": "First give a definition of ''target market''. Then give an example — you can use Fairy Liquid from the case study, or another business you know.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a + AO1b)</h5><ul><li><strong>Knowledge (1 mark):</strong> Define target market — e.g. the group of customers/consumers a business aims its product at; who a business tries to sell its products to.</li><li><strong>Understanding through example (1 mark):</strong> Give an example — e.g. households / consumers with high incomes / any relevant example from the case study or another business.</li></ul></div>"}, {"question": "Analyse one benefit to Fairy Liquid of using TV as a means of marketing. [3 marks]", "marks": 3, "hint": "Structure: Understanding (what is the benefit of TV advertising?) → Application (how does this link to Fairy Liquid specifically?) → Analysis (what is the business impact — effect on sales, awareness, competitive position?)", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> State a benefit of TV advertising — e.g. reaches a large audience; high visibility; can show the product in action; memorable (e.g. catchphrase).</li><li><strong>Application (1 mark):</strong> Link to Fairy Liquid — e.g. Fairy Liquid targets households throughout the UK; faces intense competition; expanded range into different scents and dishwasher products.</li><li><strong>Analysis (1 mark):</strong> Explain the business impact — e.g. by reaching a large target audience, more consumers will be informed about Fairy Liquid and so are more likely to buy the product, increasing sales; helps maintain status as one of the most recognised product names in the UK despite intense competition.</li></ul></div>"}, {"question": "Explain one reason why Fairy Liquid continues to market itself when it is a well-known product. [2 marks]", "marks": 2, "hint": "Think about WHY a business would keep spending on marketing even after it is already well-known. Competition? Reminding customers? New products?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1b + AO2)</h5><ul><li><strong>Understanding (1 mark):</strong> Give a reason why any business would maintain its marketing — e.g. to keep customers informed of changes to a product; to keep the product in customers'' minds; to fight off competition; to attract new customers.</li><li><strong>Application (1 mark):</strong> Link to Fairy Liquid — e.g. Fairy Liquid faces intense competition; it has expanded its range into different scents and dishwasher products; it needs to maintain its status as one of the most recognised product names in the UK.</li></ul></div>"}, {"question": "Explain two ways Samsung could increase the sales of its mobile phones. [4 marks]", "marks": 4, "hint": "Two separate ways, each worth 2 marks: Understanding (what is the way?) + Application (why would this work specifically for Samsung''s mobile phones?). Think about price, advertising, new models, new places to sell, different methods of selling.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (2 × AO1b + 2 × AO2)</h5><p>Two ways required, each worth 1 mark for Understanding + 1 mark for Application to Samsung.</p><p><strong>Possible ways include:</strong></p><ul><li>Advertise more / promote the mobile phones more widely — e.g. using social media to reach a global audience of smartphone users</li><li>Introduce a new model that appeals to more customers — e.g. a new smartphone with improved features</li><li>Reduce the price of mobile phones — e.g. to make them more competitive against rivals</li><li>Sell in different places — e.g. expanding distribution to more countries given Samsung operates in 60+ countries</li><li>Sell by different methods — e.g. selling directly online as well as through retailers</li><li>Increase the range of models available — e.g. budget, mid-range and premium smartphones</li></ul></div>"}, {"question": "Analyse two factors which will influence how Samsung markets its mobile phones. [6 marks]", "marks": 6, "hint": "Two factors, each worth 3 marks: Understanding (what is the factor?) → Application (how does it apply to Samsung specifically?) → Analysis (why does this factor affect Samsung''s marketing decisions — what is the business impact?). Use case study details such as ''multi-national'', ''60 countries'', ''world''s largest manufacturer'', ''electronics''.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 6 marks (2 × AO1b + 2 × AO2 + 2 × AO3a)</h5><p>Two factors required, each worth Understanding (1) + Application (1) + Analysis (1).</p><p><strong>Possible factors include:</strong></p><ul><li><strong>Finance available:</strong> Samsung is a multi-national with huge resources (APP) — it can afford expensive global TV and digital campaigns, giving it a competitive advantage over smaller rivals (AN)</li><li><strong>Who the marketing is aimed at:</strong> Different customer groups (young people, business users, budget-conscious consumers) require different approaches — social media for younger customers, business press for corporate buyers (AN)</li><li><strong>Location of customers:</strong> Samsung operates in 60+ countries — marketing must be adapted to different languages, cultures, and customer needs in each market (AN)</li><li><strong>Level of competition:</strong> Samsung faces competition from Apple, Huawei, etc. — it must continually market to keep its brand in customers'' minds and justify its position as world''s largest manufacturer (AN)</li><li><strong>Technology/digital change:</strong> As a technology company, Samsung can use digital marketing and social media effectively to reach millions of customers globally (AN)</li></ul></div>"}]}}'::jsonb),
('business', '2-2-market-research', '2.2 Market Research', '{"learn": {"enabled": true, "items": [{"title": "What is Market Research?", "html": "<p><strong>Market research</strong> is the collection of data on customer habits to help decision-making in marketing.</p>\n<p>Before a business starts, it is important that the owners check exactly who their customers are likely to be. Are they old or young, male or female, rich or poor? There is little point in starting a business and then wondering why you are not selling anything!</p>\n<p>This analysis of the market will normally be part of the <strong>business plan</strong> and it is an important part in setting up a successful business. Who a business aims its product or service at is called the <strong>target market</strong>. Understanding your target market is important because it can help a business <strong>segment</strong> its market — which means aiming different products at different groups of people.</p>\n<p><strong>Case study — Sarah''s Gourmet Dishes:</strong> Sarah Jones thought she had a good idea for a business in selling organic gourmet food online. She did not undertake any market research. She did not really know what competition she had in the gourmet online food market. She only had a general idea about the price she should be charging. There was no clear view on exactly who her customers were likely to be. Deliveries were disorganised. After a disastrous first six months Sarah had lost much of her savings in the business. Sarah would have benefited from undertaking market research before she started her business.</p>", "check": {"question": "What is market research?", "options": ["The collection of data on customer habits to help decision-making in marketing", "The advertising of a product to boost sales", "The process of designing and testing new packaging for a product before its launch", "The recruitment and training of sales staff"], "answer": 0, "explain": "The card defines market research as the collection of data on customer habits to help decision-making in marketing — this is what Sarah failed to do before launching her business."}}, {"title": "Why is Market Research Important?", "html": "<p>Market research will help a business be clear on whether there is <strong>demand</strong> for their product or service. Put quite simply: will customers buy the product or not? There is clearly no use making a product or providing a service if no one wants it!</p>\n<ul>\n<li><strong>Avoids unnecessary investment:</strong> If a business is considering investing lots of money into a project, it is in its own interests to make sure that there is demand — otherwise that investment will be wasted.</li>\n<li><strong>Identifies the target market:</strong> Understanding who customers are (age, gender, income, location) helps focus product development and marketing.</li>\n<li><strong>Helps with pricing:</strong> Market research can reveal what price customers are willing to pay.</li>\n<li><strong>Identifies competition:</strong> Businesses need to know who their competitors are and what they offer.</li>\n<li><strong>Helps with market segmentation:</strong> Different products can be aimed at different groups — e.g. watches come in many styles aimed at different types of customer.</li>\n</ul>\n<p><strong>Important evaluation point:</strong> Not all businesses use all types of market research. Smaller businesses may use very little, if any. Some owners rely on their own judgement. The question is always: does the business have the money and time to complete expensive research?</p>", "check": {"question": "According to this card, why does market research help avoid unnecessary investment?", "options": ["It confirms there is demand before money is spent on a project", "It removes the need for a business to make a business plan", "It automatically reduces a business''s production costs", "It guarantees a fixed return on any investment made"], "answer": 0, "explain": "The card explains that if a business is considering investing lots of money, research helps confirm demand exists — otherwise the investment will be wasted."}}, {"title": "Primary Research — Questionnaires", "html": "<p><strong>Primary research</strong> (also called ''field research'') involves collecting information that is new — gathered first-hand specifically for this business and its needs.</p>\n<p>A <strong>questionnaire</strong> is a question sheet filled in by the consumer. Questionnaires may be sent in the post, put in with guarantee forms for products, or used online to collect information from consumers.</p>\n<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Advantages</div>\n<div class=\"pro-item\">Cheaper than interviews to collect data</div>\n<div class=\"pro-item\">Can easily target particular consumers — e.g. a questionnaire sent with a guarantee for a product</div>\n</div>\n<div>\n<div class=\"col-head\">Disadvantages</div>\n<div class=\"con-item\">Difficult to predict how many completed questionnaires will be returned</div>\n<div class=\"con-item\">People filling in the forms may not understand the questions being asked</div>\n</div>\n</div>\n<p style=\"margin-top:8px;\"><strong>Tip:</strong> To increase response rates, businesses sometimes offer an entry into a free prize draw to encourage consumers to complete and return the questionnaire.</p>", "check": {"question": "According to this card, what is a key disadvantage of using questionnaires?", "options": ["It is difficult to predict how many completed questionnaires will be returned", "They cannot be completed online", "They cannot be used to target specific consumers", "They are usually much more expensive to run and organise than face-to-face interviews"], "answer": 0, "explain": "The card lists as a disadvantage that it is difficult to predict how many completed questionnaires will be returned — unlike interviews, which are described as more expensive."}}, {"title": "Primary Research — Interviews", "html": "<p>In an <strong>interview</strong>, customers are asked questions and the person asking (the interviewer) fills in the answers. Group interviews are sometimes used where a group of customers are asked the same questions at the same time. Interviews can also take place over the telephone.</p>\n<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Advantages</div>\n<div class=\"pro-item\">The interviewer can explain questions if there is a misunderstanding</div>\n<div class=\"pro-item\">Customers can be targeted easily — e.g. picking out certain age groups in a street to interview</div>\n</div>\n<div>\n<div class=\"col-head\">Disadvantages</div>\n<div class=\"con-item\">Can be expensive because an interviewer has to be paid</div>\n<div class=\"con-item\">Customers may feel uncomfortable being interviewed — whether stopped in the street or on the phone</div>\n</div>\n</div>", "check": {"question": "According to this card, what is a stated advantage of interviews over questionnaires?", "options": ["Interviews never make customers feel uncomfortable", "Interviews do not require anyone to be paid", "The interviewer can explain questions if there is a misunderstanding", "Interviews are usually cheaper to carry out than questionnaires or focus groups"], "answer": 2, "explain": "The card states that in an interview, the interviewer can explain questions if there is a misunderstanding, whereas questionnaires offer no such clarification."}}, {"title": "Primary Research — Trials", "html": "<p>In a <strong>trial</strong>, the product or service is sold for a short time as a test to see whether or not consumers like the product. For a large business, which might normally sell products across the UK, a trial may be set up in a much smaller area. A smaller business might simply add a new product to sell for a short period of time without buying in large quantities.</p>\n<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Advantages</div>\n<div class=\"pro-item\">As trials are conducted in a small area, a business may save money — just in case it finds out that customers don''t want what the business has for sale</div>\n</div>\n<div>\n<div class=\"col-head\">Disadvantages</div>\n<div class=\"con-item\">Trials are still costly to set up</div>\n<div class=\"con-item\">The area chosen must fully reflect the target market — if not, money will be wasted</div>\n<div class=\"con-item\">The business may conduct a trial and only find out what they first thought</div>\n</div>\n</div>\n<p style=\"margin-top:8px;\"><strong>Important exam note:</strong> Trialling is about measuring whether people will BUY a product (sales figures). It is NOT about getting qualitative feedback on how to improve the product. Do not confuse trialling with giving out free samples to gain opinions.</p>", "check": {"question": "According to the exam note in this card, what does trialling a product primarily measure?", "options": ["Staff satisfaction with the new product", "Customer opinions and feedback on how to improve the product''s design", "The cost of manufacturing the product", "Whether people will buy the product, shown through sales figures"], "answer": 3, "explain": "The card warns that trialling is about measuring whether people will BUY a product (sales figures), not about gathering qualitative feedback to improve it."}}, {"title": "Primary Research — Focus Groups", "html": "<p><strong>Focus groups</strong> are small groups of people (around ten) who are carefully selected to represent the target market for a product or service. They are given information and then asked questions. The answers they give can then be analysed to provide valuable data.</p>\n<p><strong>Example:</strong> An advertising agency might show a focus group different posters that they are considering using to advertise a new product. The feedback from the focus group will then help to choose the most effective poster to use.</p>\n<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Advantages</div>\n<div class=\"pro-item\">Because focus groups are chosen to represent the target market, the data from them is usually very accurate and can be relied upon to make important decisions</div>\n</div>\n<div>\n<div class=\"col-head\">Disadvantages</div>\n<div class=\"con-item\">Though carefully chosen, they are still small groups — making data collection more expensive per person than interviews and questionnaires</div>\n<div class=\"con-item\">The selection of people to take part is time-consuming and so costly</div>\n</div>\n</div>", "check": {"question": "Why is data from focus groups usually considered accurate, according to this card?", "options": ["They always produce quantitative data only", "Focus groups involve very large numbers of participants", "Focus groups are always conducted online", "Focus groups are selected to represent the target market"], "answer": 3, "explain": "The card states that focus groups are chosen to represent the target market, so the data from them is usually very accurate and can be relied upon for important decisions."}}, {"title": "Secondary Research — What It Is and Sources", "html": "<p><strong>Secondary research</strong> (also called ''desk research'') is research that another organisation has already completed. A business uses information already gathered by someone else.</p>\n<p><strong>Sources of secondary research:</strong></p>\n<ul>\n<li><strong>Census data:</strong> Every person living in Britain is questioned on how they live and what their income is. Collected every ten years. Very useful for finding out how many people of a certain age or income live in a particular area. Available at www.statistics.gov.uk.</li>\n<li><strong>Websites:</strong> A huge amount of information is available on the internet. Many companies put information about themselves and their products online, which competitor businesses can use as secondary research.</li>\n<li><strong>Internal data:</strong> Many businesses have their own secondary data — past sales figures, profits from departments, and comments from customers. Usually kept on computers and used when making decisions for the future.</li>\n<li><strong>Newspapers and magazines:</strong> Full of information useful to businesses — on other businesses, trends in fashion and interests that could be used to develop new products and services. As much of this is now online, searching is easier.</li>\n</ul>", "check": {"question": "According to this card, what is secondary research?", "options": ["Research that another organisation has already completed", "Research that is always more expensive than primary research", "Research that only comes from focus groups", "Data collected first-hand for a specific business''s needs"], "answer": 0, "explain": "The card defines secondary (desk) research as research that another organisation has already completed, giving census data, websites, internal data and newspapers/magazines as sources."}}, {"title": "Advantages and Disadvantages of Secondary Research", "html": "<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Advantages</div>\n<div class=\"pro-item\">As research has already been completed by another organisation, it is usually much <strong>cheaper</strong> to collect than primary research</div>\n<div class=\"pro-item\">A <strong>wide range</strong> of data is readily available, especially with the growth of the internet</div>\n</div>\n<div>\n<div class=\"col-head\">Disadvantages</div>\n<div class=\"con-item\">The research information might <strong>not be exactly</strong> what a business wants — someone else has designed and collected it</div>\n<div class=\"con-item\">The data may <strong>not be up to date</strong> — e.g. the census is only every ten years</div>\n<div class=\"con-item\">The data might not be in a form that the business can <strong>analyse easily</strong>. Only by designing its own research (primary) can a business be sure it is in the form it requires</div>\n</div>\n</div>\n<p style=\"margin-top:8px;\"><strong>Internal data</strong> is a special type of secondary data — it comes from within the business itself (e.g. past sales figures, customer comments). This avoids the problem of data not being exactly right, as the business has already collected it for its own purposes.</p>", "check": {"question": "Why is internal data considered an especially useful type of secondary data, according to this card?", "options": ["Because it is classed as primary research", "Because it is provided free by the government", "Because it comes from within the business, avoiding inaccuracy", "Because it is always more up to date than the national census"], "answer": 2, "explain": "The card explains that internal data comes from within the business itself, which avoids the usual secondary research problem of data not being exactly what the business wants."}}, {"title": "Qualitative vs Quantitative Data", "html": "<p><strong>Qualitative data</strong> is collected when the <em>opinion</em> of consumers is needed. Because of this, it is usually collected using primary research methods — often with interviews or focus groups (though secondary research could be used too). This data can be used to help make decisions, although it is sometimes difficult to interpret opinions. For example, someone could say they dislike a product but may still be willing to buy it for someone else.</p>\n<p><strong>Quantitative data</strong> is related to <em>facts and numbers</em>. It may be the number of products sold, or how many people eat cereals for breakfast. Quantitative data could be collected using primary or secondary research. For example, people could be asked how often they eat chocolate (not their opinion on chocolate — that would be qualitative). This data is often easier to interpret than qualitative because it is simply dealing with facts and numbers.</p>\n<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Qualitative</div>\n<div class=\"pro-item\"><strong>Advantage:</strong> Helps the business understand what customers are thinking and what they want</div>\n<div class=\"con-item\"><strong>Disadvantage:</strong> Information may only be provided by a limited number of people; opinions can be hard to interpret</div>\n</div>\n<div>\n<div class=\"col-head\">Quantitative</div>\n<div class=\"pro-item\"><strong>Advantage:</strong> Easy to analyse and can be gathered from a large number of people</div>\n<div class=\"con-item\"><strong>Disadvantage:</strong> Limits how much people can say about what they like or dislike — no depth of opinion</div>\n</div>\n</div>", "check": {"question": "A business asks customers how often they eat chocolate. What type of data is this, according to this card?", "options": ["Qualitative data, because it is about food preferences", "Quantitative data, because it deals with facts and numbers, not opinions", "Quantitative data, because it can only be collected through focus groups", "Qualitative data, because it must be collected using primary research"], "answer": 1, "explain": "The card gives this exact example — asking how often people eat chocolate is quantitative because it deals with facts and numbers, not an opinion on chocolate (which would be qualitative)."}}, {"title": "Evaluation — Choosing the Right Research Method", "html": "<p>When choosing an appropriate method of research, there are many factors to consider:</p>\n<ul>\n<li><strong>Does the business need precise, up-to-date information?</strong> If yes → primary research is likely needed, as there may not be any suitable secondary research available.</li>\n<li><strong>Is more general data sufficient?</strong> If yes → cheaper secondary research may well be suitable.</li>\n<li><strong>Does the business have the money?</strong> Primary research is usually more expensive. Smaller businesses may rely on secondary research or use informal methods (e.g. asking friends and family).</li>\n<li><strong>What size is the business?</strong> Small businesses may use very little research. Large businesses can afford detailed primary research.</li>\n<li><strong>What is the product?</strong> Some products benefit from trials (e.g. food products); others from focus groups (e.g. advertising campaigns); others from questionnaires (e.g. general consumer preferences).</li>\n</ul>\n<p><strong>Always look at the business in the question:</strong> Is it likely to need research? Does it have the money to complete expensive research? Remember that some businesses will not complete any market research, with owners relying on their own judgement.</p>\n<p><strong>Primary vs secondary comparison:</strong> Primary research is often more useful because it can be designed for the exact needs of the business and is up to date. However, it is more expensive and time-consuming. Secondary research is cheaper and widely available but may be outdated or not tailored to the business''s specific needs.</p>", "check": {"question": "According to this card, which factor is most likely to push a small business toward secondary rather than primary research?", "options": ["Secondary data always being more accurate than primary data", "Primary research being banned for small businesses", "Limited money to spend on expensive research", "A legal requirement to always use secondary data"], "answer": 2, "explain": "The card notes that primary research is usually more expensive, so smaller businesses may rely on cheaper secondary research or informal methods due to limited funds."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Market research", "definition": "The collection of data on customer habits to help decision-making in marketing. Helps a business find out whether there is demand for its product or service."}, {"term": "Target market", "definition": "The group of customers to whom a business aims to sell its products or services. The target market may be other businesses as well as consumers."}, {"term": "Primary research", "definition": "Data collected first-hand, often in the form of questionnaires, interviews, trials and focus groups. Sometimes referred to as ''field'' research."}, {"term": "Secondary research", "definition": "The collection of data using research or information provided by others — e.g. magazines, journals, the internet, census data. Often called ''desk'' research."}, {"term": "Questionnaire", "definition": "A question sheet filled in by the consumer. Can be sent by post, included with guarantee forms, or completed online. Cheaper than interviews but response rates can be unpredictable."}, {"term": "Interview", "definition": "A question sheet filled in by the person conducting the interview. Can be face-to-face or by telephone. More expensive than questionnaires but allows misunderstandings to be clarified."}, {"term": "Trial", "definition": "Testing whether customers will buy a product by selling it in a limited area or for a short period. Provides sales data (quantitative) not qualitative feedback."}, {"term": "Focus group", "definition": "A selected small group (around ten) of people who represent the target market. They are given information and asked questions. Accurate but expensive per person."}, {"term": "Census data", "definition": "Data collected by the government every ten years, questioning the entire population on their income, occupation and how they live. Useful secondary research for demographic information."}, {"term": "Internal data", "definition": "Data already within a business based on past performance — e.g. past sales figures, profits from departments, and customer comments. A form of secondary research."}, {"term": "Qualitative data", "definition": "Data based on the opinions of those being asked. Collected using interviews or focus groups. Gives rich detail but can be difficult to interpret and compare."}, {"term": "Quantitative data", "definition": "Data collected based on facts or numbers — e.g. how many products were sold. Usually easier to analyse than qualitative data. Can be collected using primary or secondary research."}, {"term": "Advantage of primary research", "definition": "It is designed exactly how the business wants. It is up to date and specific to the business''s needs. Interview questions can be explained to avoid confusion and incorrect data."}, {"term": "Disadvantage of primary research", "definition": "Can be expensive to collect. It may be difficult to get consumers to cooperate and provide answers to questions. Time-consuming to design and carry out."}, {"term": "Advantage of secondary research", "definition": "Generally the cheaper option. A wide range of data is readily available, especially with the growth of the internet. Saves time compared to collecting primary data."}, {"term": "Disadvantage of secondary research", "definition": "Research collected may not be exactly in the form the business requires. Risk that it could be out of date — the census, for example, is only every ten years."}, {"term": "Market segmentation", "definition": "Aiming different products at different groups of people within a market. Businesses use market research to understand different segments — e.g. different watch styles for different customer groups."}, {"term": "Evaluation: primary vs secondary research", "definition": "Primary research is more useful when precise, up-to-date, tailored data is needed. Secondary research is better when the business has limited funds or needs general information quickly. The right choice depends on the size, type and budget of the business."}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of the following is an example of primary research?", "options": ["Collecting data from the internet", "Collecting data by asking consumers questions in the local shopping centre", "Collecting data published in the local newspapers", "Collecting data from the last census for a particular age group"], "answer": 1, "explain": "Correct answer: collecting data by asking consumers questions in the local shopping centre. This is primary (field) research because the data is collected first-hand directly from consumers. Options A, C and D all use data already collected by others — these are all forms of secondary (desk) research."}, {"question": "Market research is important to a business because:", "options": ["It helps develop a good working atmosphere in a business", "It provides information to help develop products", "It shows managers how to motivate their staff", "It keeps staff busy"], "answer": 1, "explain": "Correct answer: it provides information to help develop products. Market research helps businesses understand what customers want, whether there is demand for a product, and what price customers will pay. Options A, C and D relate to HR and management functions, not market research."}, {"question": "Quantitative research is:", "options": ["Research undertaken asking a wide variety of people", "Research that concentrates on one part of the population", "Research that deals only with facts and numbers", "Research that has been completed by a competitor business"], "answer": 2, "explain": "Correct answer: research that deals only with facts and numbers. Quantitative data is based on measurable facts — e.g. how many people buy a product, how often people visit a cinema. It is usually easier to analyse than qualitative data. Option D describes secondary research, not quantitative data."}, {"question": "A new business wanting a wide range of information about competitors would most likely use:", "options": ["Questionnaires and interviews", "Internal data", "Newspapers and magazines", "Websites"], "answer": 3, "explain": "Correct answer: websites. Many companies now put information about themselves and their products online, making websites a fast and comprehensive source of secondary data about competitors. Newspapers and magazines (C) could also be useful but websites are the most comprehensive and immediately accessible source. Internal data (B) is data from within the own business. Questionnaires/interviews (A) are primary research methods that would not directly reveal competitor information."}, {"question": "Which of the following is an example of qualitative market research data?", "options": ["The number of adults who live and work in the local area", "The percentage of the population who eat out once a week", "The preferences of local residents when eating out", "The prices charged by local competitors"], "answer": 2, "explain": "Correct answer: the preferences of local residents when eating out. Qualitative data is based on opinions and preferences, not just numbers. Options A, B and D are all facts or numbers — these are examples of quantitative data."}, {"question": "An interview is an example of:", "options": ["A primary market research method", "A recruitment method", "A training method", "An informal communication method"], "answer": 0, "explain": "Correct answer: a primary market research method. An interview where customers are asked questions and the interviewer fills in the answers is a primary (field) research method. Although interviews can also be used in recruitment (B), in the context of market research the answer is primary research. This is a common exam mistake — do not confuse market research interviews with job interviews."}, {"question": "What is not a secondary source of market research?", "options": ["Focus groups", "Internal business data", "Newspapers", "Websites"], "answer": 0, "explain": "Correct answer: focus groups. Focus groups are a PRIMARY research method, not secondary. They involve selecting a small group of people to give their opinions on products. Internal business data (B), newspapers (C) and websites (D) are all examples of secondary (desk) research."}, {"question": "A national retailer intends to trial a new product in some of its stores. Which of the following is NOT a benefit of trialling the product?", "options": ["It avoids wasting money on an unsuccessful national launch", "It helps identify the target market", "It requires a lot of national advertising and promotion", "It shows whether there is sufficient demand for the product"], "answer": 2, "explain": "Correct answer: it requires a lot of national advertising and promotion. This is NOT a benefit — it is actually a drawback. One of the key advantages of trialling is that it is conducted on a small scale, avoiding expensive national advertising and promotion costs. Options A, B and D are all genuine benefits of trialling a product before a full national launch."}, {"question": "Understanding customer needs is the main purpose of:", "options": ["Employee retention", "Innovation", "Market research", "The product lifecycle"], "answer": 2, "explain": "Correct answer: market research. Market research is the collection of data on customer habits to help decision-making in marketing. Its main purpose is to understand customer needs — what they want, what they will pay, and whether they will buy a product. The other options are separate business concepts."}, {"question": "A focus group is an example of:", "options": ["A digital distribution channel", "A primary market research method", "Market segmentation", "Point of sale promotion"], "answer": 1, "explain": "Correct answer: a primary market research method. A focus group is a carefully selected small group (around ten) of people who represent the target market. They are given information and asked questions. This is primary research because the data is collected first-hand for the specific needs of the business."}]}, "fib": {"enabled": true, "questions": [{"text": "Market research is the collection of [data] on customer habits to help decision-making in [marketing]."}, {"text": "Primary research is sometimes called [field] research and involves collecting information that is new. Secondary research is sometimes referred to as [desk] research."}, {"text": "A focus group is a small group of around [ten] people who are carefully selected to represent the [target] market for a product or service."}, {"text": "Qualitative data is based on the [opinions] of consumers. Quantitative data is related to facts and [numbers], and is usually easier to analyse."}, {"text": "Secondary research is usually much [cheaper] to collect than primary research, but the data may not be [up] to date."}, {"text": "The census is collected every [ten] years. It is a useful source of [secondary] research for businesses planning where to locate or who to target."}]}, "tf": {"enabled": true, "questions": [{"statement": "Primary research is sometimes called ''desk research'' because it is carried out at a desk.", "answer": false, "explain": "FALSE. Primary research is called ''FIELD research'' because the researcher goes out into the field to collect new, first-hand data. It is SECONDARY research that is called ''desk research'' — because it involves looking at data already collected by others, which can be done sitting at a desk."}, {"statement": "A focus group of around ten people carefully selected to represent the target market is an example of primary research.", "answer": true, "explain": "TRUE. A focus group is a primary research method because the data is collected first-hand directly from people. The group is selected to represent the target market and asked questions — generating new data specifically for the business''s needs."}, {"statement": "The census is an example of primary research because it collects data from every person in the country.", "answer": false, "explain": "FALSE. The census is an example of SECONDARY research. Although the government collects new data every ten years, businesses USE this already-collected data for their own research purposes. Secondary research means data collected by someone else that a business then uses — it does not matter how the original data was gathered."}, {"statement": "Quantitative data is based on the opinions of consumers.", "answer": false, "explain": "FALSE. Opinions are QUALITATIVE data. Quantitative data is based on facts and numbers — for example, the number of products sold or how often people eat cereals for breakfast. A helpful memory tip: QUALITATIVE = quality of opinions; QUANTITATIVE = quantity/numbers."}, {"statement": "One disadvantage of using questionnaires is that it is difficult to predict how many completed questionnaires will be returned.", "answer": true, "explain": "TRUE. Response rates for questionnaires can be unpredictable. To increase returns, businesses may offer incentives such as an entry into a free prize draw. Low response rates can make the data less reliable or representative of the target market."}, {"statement": "Secondary research is always cheaper than primary research.", "answer": true, "explain": "TRUE — as a general rule. Because someone else has already completed the research, secondary research is usually much cheaper to collect than primary research. The cost of primary research comes from designing questions, paying interviewers, running focus groups, or setting up trials."}, {"statement": "Trialling a new product gives a business qualitative data about customer opinions on how to improve the product.", "answer": false, "explain": "FALSE. This is a very common misconception! Trialling gives a business QUANTITATIVE data — specifically sales figures — to show whether there is demand for a product. It does NOT provide qualitative feedback about opinions. Do not confuse trialling with giving out free samples to gather opinions."}, {"statement": "Internal data is a form of secondary research because it has already been collected within the business.", "answer": true, "explain": "TRUE. Internal data — such as past sales figures, profits from departments, and customer comments — is a form of secondary research. It has already been collected for another purpose within the business. It has the advantage of being directly relevant to the business, unlike external secondary data."}, {"statement": "Small businesses will often undertake the same amount of market research as large businesses.", "answer": false, "explain": "FALSE. Smaller businesses may use very little, if any, market research. This is because market research — especially primary research — can be expensive and time-consuming. Small businesses are more likely to rely on secondary research or informal methods such as asking friends and family. Owners of small businesses may also rely on their own judgement."}, {"statement": "An advantage of interviews over questionnaires is that the interviewer can explain questions if there is a misunderstanding.", "answer": true, "explain": "TRUE. This is a key advantage of interviews. If a respondent does not understand a question, the interviewer can clarify it — this leads to more accurate data. With questionnaires, there is no one to explain unclear questions, which may lead to misunderstandings and unreliable answers."}]}, "misc": {"enabled": true, "items": [{"myth": "Students think trialling means giving out free samples to get feedback on how to improve a product.", "truth": "Trialling is a primary market research method that involves launching a product in a limited number of stores or a limited area for a short time. The purpose is to measure SALES FIGURES to see whether there is demand — NOT to get opinions or qualitative feedback. The only direct feedback from trialling is quantitative (sales data). Do not say trialling helps ''improve'' the product.", "check": {"question": "What does trialling a product actually measure?", "options": ["Qualitative feedback on how to improve the design of the product", "Long-term brand loyalty among customers", "Sales figures showing whether there is demand for the product", "Staff performance during the trial period"], "answer": 2, "explain": "The card corrects the misconception that trialling gathers improvement feedback — it is a primary method that measures quantitative sales figures to test demand."}}, {"myth": "Students confuse primary and secondary research and mix up their advantages and disadvantages.", "truth": "PRIMARY research is new data collected first-hand — it is more expensive and time-consuming but specific to the business''s exact needs and up to date. SECONDARY research is data already collected by someone else — it is cheaper and widely available but may be outdated and may not be in the exact form the business requires. A simple memory trick: Primary = first-hand = field research. Secondary = second-hand = desk research.", "check": {"question": "Which memory trick correctly matches research type to its source, according to this card?", "options": ["Primary is always free; secondary is always paid for", "Primary = desk research; secondary = field research", "Primary = first-hand = field research; secondary = second-hand = desk research", "Primary = data collected from competitors; secondary = data collected from customers"], "answer": 2, "explain": "The card gives the memory trick that primary is first-hand field research, while secondary is second-hand desk research — the reverse pairing is the common student error."}}, {"myth": "Students state that qualitative data is ''better'' than quantitative data, or vice versa, without explaining why.", "truth": "Neither is universally better — each has advantages and disadvantages depending on what the business needs. Qualitative gives rich detail and opinion but is harder to analyse. Quantitative is easy to analyse and can include large numbers of people but gives no depth of opinion. For evaluation questions, you must weigh up which is MOST USEFUL for that specific business and context, and justify your judgement.", "check": {"question": "How should a student correctly evaluate qualitative vs quantitative data in an exam answer, according to this card?", "options": ["Avoid comparing the two types of data in evaluation answers", "State that qualitative data is always better because it gives opinions", "Weigh up which is most useful for the specific business and context, then justify the judgement", "State that quantitative data is always better because it is easier and quicker to fully analyse"], "answer": 2, "explain": "The card stresses that neither type is universally better — students must weigh up which is most useful for the specific business and context and justify their judgement."}}, {"myth": "Students write that the advantage of primary research is that it is ''more reliable'' without explaining why.", "truth": "The key advantages of primary research are that it is (1) designed EXACTLY how the business wants, (2) collected for a specific purpose, and (3) up to date. Saying it is ''more reliable'' is too vague and will not gain marks. You must say WHY it is more reliable — because it is specifically tailored to the business''s needs and is current.", "check": {"question": "Why is simply stating primary research is ''more reliable'' not enough to gain marks, according to this card?", "options": ["Because it does not explain WHY it is reliable", "Because examiners never award marks for reliability", "Because reliability only applies to secondary research", "Because primary research is not actually reliable"], "answer": 0, "explain": "The card explains that the statement is too vague — students must explain WHY primary research is more reliable, i.e. it is designed exactly for the business and is current."}}, {"myth": "Students confuse the terms ''qualitative'' and ''quantitative'' in answers.", "truth": "Remember: QUALITATIVE = quality of opinions (think: ''qual'' as in quality, feelings, views). QUANTITATIVE = quantity, numbers, facts (think: ''quant'' as in quantity). A useful exam check: if your ''qualitative'' example involves a number or percentage, you have probably confused the two terms.", "check": {"question": "What memory device does this card give to help distinguish qualitative from quantitative data?", "options": ["Quantitative always refers to focus group data", "QUALitative = QUALity of opinions; QUANTitative = QUANTity/numbers", "QUALitative = numbers; QUANTitative = opinions", "Qualitative data always refers to census data collected by the government"], "answer": 1, "explain": "The card gives the memory device that QUALitative relates to QUALity of opinions/feelings, while QUANTitative relates to QUANTity/numbers and facts."}}, {"myth": "Students think all businesses must use primary research and that secondary research is always inferior.", "truth": "This is wrong. The choice of research depends on the business''s circumstances. Secondary research is often the best starting point and may be all a business needs — especially if it is small, lacks funds, or needs general data. For evaluation questions, always consider the TYPE and SIZE of the business. A small business opening a local café may get all the information it needs from census data, websites and local newspapers — without spending money on expensive primary research.", "check": {"question": "A small business opening a local café needs general information about its area. What does this card say it should likely do?", "options": ["Rely on secondary research such as census data and websites", "Always commission expensive primary research regardless of budget", "Use only qualitative focus group data", "Avoid market research altogether since it is only a café"], "answer": 0, "explain": "The card''s example states a small local café may get all the information it needs from secondary sources like census data, websites and local newspapers, without paying for primary research."}}]}, "tips": {"enabled": true, "items": [{"title": "Identify a Primary or Secondary Market Research Method", "html": "<p>Simply name the method — one word or short phrase is enough. No explanation needed for 1 mark.</p>\n<ul>\n<li><strong>Primary methods:</strong> Questionnaire, interview, trial/trialling, focus group, observation</li>\n<li><strong>Secondary methods:</strong> Census, websites, newspapers, magazines, internal data, government publications, trade journals</li>\n</ul>\n<p><strong>Common errors:</strong> Writing ''survey'' as a secondary source (it is primary). Writing ''customer reviews'' or ''forums'' — examiners do not accept these as standalone answers. Do not give the TYPE of data (e.g. ''sales figures'') as a source — name the SOURCE (e.g. ''internal data'' or ''websites'').</p>", "check": {"question": "According to this card, which is a common error students make when identifying research sources?", "options": ["Writing ''trial'' as a primary source", "Writing ''websites'' as a secondary source instead of a primary one", "Writing ''census'' as a secondary source", "Writing ''survey'' as a secondary source when it''s actually primary"], "answer": 3, "explain": "The card lists as a common error writing ''survey'' as a secondary source, when a survey/questionnaire is actually a primary research method."}}, {"title": "Explain What is Meant by [Market Research Term]", "html": "<p>Structure: Knowledge (1) + Understanding through example or further explanation (1)</p>\n<ul>\n<li>Define the term clearly in your own words</li>\n<li>Give an example OR add further detail that shows understanding</li>\n</ul>\n<p><strong>Example — Focus group:</strong> \"A focus group is a small group of people (1) who are asked to give their views about a product or service being developed (1).\"</p>\n<p><strong>Example — Market research:</strong> \"Market research is the collection of data on customer habits (1) — for example using questionnaires or interviews — to help a business make decisions about its products and services (1).\"</p>", "check": {"question": "What two-part structure is required to gain full marks on a 2-mark ''explain'' question, according to this card?", "options": ["Two separate definitions of the exact same term", "A judgement (1) plus a justification (1)", "Application (1) + Analysis (1)", "Knowledge (1) + Understanding (1)"], "answer": 3, "explain": "The card states the structure is Knowledge (1) — defining the term — plus Understanding (1) shown through an example or further explanation."}}, {"title": "Analyse One Advantage/Benefit of a Market Research Method", "html": "<p>Structure: Understanding (1) → Application to the specific business (1) → Business-facing Analysis (1)</p>\n<ul>\n<li>State a clear advantage/benefit of the method</li>\n<li>Apply it to the named business using case study details</li>\n<li>Explain the business impact — e.g. better decision-making, reduced risk, increased revenue, more profit</li>\n</ul>\n<p><strong>Example (EDF, focus groups):</strong> \"EDF can carefully select a focus group from customers that reflect its target market (U), for example customers who want green energy (APP). This should provide accurate information on what potential customers want, which EDF can use to make better decisions and reduce the risk of launching a service that customers do not need (AN).\"</p>\n<p><strong>Common error:</strong> Do not just describe WHAT the method is — state the BENEFIT to the business, then analyse the IMPACT on the business.</p>", "check": {"question": "What common error does this card highlight for 3-mark ''analyse'' questions on market research methods?", "options": ["Forgetting to mention the business''s competitors", "Not naming the research method at all", "Writing too much application and not enough knowledge", "Describing WHAT the method is, not its benefit and impact"], "answer": 3, "explain": "The card warns not to just describe what the method is — students must state the benefit to the business and then analyse the impact, following Understanding → Application → Analysis."}}, {"title": "Evaluate Whether to Use Primary or Secondary Market Research", "html": "<p>The highest mark questions require: Application (2) + Analysis (2) + Evaluation with justified judgement (3)</p>\n<ul>\n<li>Use TWO details from the case study in relation to the pros/cons of the research methods</li>\n<li>Give TWO different advantages or disadvantages of primary and/or secondary research, business-facing</li>\n<li>Make a clear decision — which type should the business use?</li>\n<li>Justify using a contextual reason from the case study (strong justification = 2 extra marks)</li>\n</ul>\n<p><strong>Exemplar response (Sainsbury''s):</strong> \"Utilising primary market research means they can find out specific information (AN) about sales in its competitive market (APP), so that Sainsbury''s can fulfil the needs and wants of its middle to high income customers (APP). Using secondary market research is much cheaper (AN). However, since Sainsbury''s is one of the largest UK supermarkets (APP), financial constraints are unlikely to be a problem. I think Sainsbury''s should use primary market research (EVAL) in future because it needs specific information to help the company develop and market products to compete with rivals like Aldi (contextual EVAL).\"</p>", "check": {"question": "What must a top-mark evaluation answer on primary vs secondary research include, according to this card?", "options": ["Two case details, plus a clear, justified judgement", "Only a definition of primary and secondary research", "A list of every research method available to the business", "The examiner''s own opinion on which method is best"], "answer": 0, "explain": "The card states the highest marks require application (2) and analysis (2) using case-study details, plus a justified judgement using a contextual reason for full evaluation marks."}}, {"title": "Evaluate Whether Market Research Shows a Business Should Go Ahead", "html": "<p>Structure: Knowledge (1) + Understanding (1) + Application with data (2) + Analysis of impact (2) + Evaluation: judgement + justification (3)</p>\n<ul>\n<li><strong>Knowledge:</strong> Define market research</li>\n<li><strong>Understanding:</strong> Give an example of a market research method</li>\n<li><strong>Application:</strong> Use numerical data from the case study — make TWO separate points with data</li>\n<li><strong>Analysis:</strong> Explain the effect/impact on the business of the data — TWO separate points</li>\n<li><strong>Evaluation:</strong> Make a clear judgement (should they go ahead or not?), then justify using precise data from the case study</li>\n</ul>\n<p><strong>Key tip:</strong> For the evaluation justification marks, you MUST use (not simply repeat) information from the case study. The justification must clearly explain WHY the data leads you to your judgement.</p>", "check": {"question": "According to this card''s key tip, what must students do to gain evaluation justification marks?", "options": ["Simply repeat the numbers given in the case study", "Avoid using any case study data in the evaluation", "State a judgement without needing a justification", "Use, not repeat, case data to explain the judgement"], "answer": 3, "explain": "The card''s key tip states that for justification marks, students MUST use (not simply repeat) case study information and clearly explain why the data leads to their judgement."}}]}, "exam": {"enabled": true, "questions": [{"question": "Which of the following is an example of primary research?", "marks": 1, "hint": "Primary research means collecting brand new, first-hand data. Which option involves going out and collecting data directly from people?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B — collecting data by asking consumers questions in the local shopping centre.</strong></p><p>This is primary (field) research because data is collected directly from consumers for the first time. Options A, C and D all involve using data already collected by others — these are all forms of secondary (desk) research.</p></div>"}, {"question": "Market research is important to a business because:", "marks": 1, "hint": "Market research is about customers and products — not staff or working conditions.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B — it provides information to help develop products.</strong></p><p>Market research helps businesses understand what customers want and whether there is demand for a product. This information is then used to develop products that meet customer needs. Options A, C and D all relate to HR and management functions, not market research.</p></div>"}, {"question": "Quantitative research is:", "marks": 1, "hint": "Think about the word ''quantity'' — what does that suggest about the type of data?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: C — research that deals only with facts and numbers.</strong></p><p>Quantitative data is based on measurable facts — numbers, percentages, frequencies. It is usually easier to analyse than qualitative (opinion-based) data. Option D describes secondary research from a competitor, which is a separate concept.</p></div>"}, {"question": "A new business wanting a wide range of information about competitors would most likely use:", "marks": 1, "hint": "The business wants information about its COMPETITORS. Which source would give the most comprehensive and up-to-date information about other businesses?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: D — websites.</strong></p><p>Many companies publish information about themselves and their products online, making websites the most comprehensive and accessible source of competitor information. Internal data (B) is data from within the own business. Questionnaires/interviews (A) are primary methods that would not directly reveal competitor information. Newspapers (C) could also be useful but websites provide the widest and most current range of competitor data.</p></div>"}, {"question": "Explain what is meant by a focus group. [2 marks]", "marks": 2, "hint": "Give a definition of a focus group — mention: small/selected group, who they are chosen to represent, and what they do.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a + AO1b)</h5><ul><li><strong>Knowledge (1 mark):</strong> A focus group is a small / selected / representative group of people.</li><li><strong>Understanding (1 mark):</strong> They are asked questions / give views / voice opinions about a firm''s ideas, products or services.</li></ul><p><strong>Exemplar response:</strong> \"It is a small group of people (1) who are asked to give their views about a product being developed (1).\"</p></div>"}, {"question": "Explain one advantage for Waitrose of using customer trials. [2 marks]", "marks": 2, "hint": "State one advantage of trialling — then apply it to Waitrose specifically using a detail from the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1b + AO2)</h5><ul><li><strong>Understanding (1 mark):</strong> State an advantage of customer trials — e.g. less expensive than a full launch / saves money in case product fails / less likely to damage reputation nationally if product fails / sales figures give an indication of actual demand.</li><li><strong>Application (1 mark):</strong> Apply to Waitrose — e.g. reference to new product development being important / the supermarket industry being very competitive / over 300 stores throughout the UK / targeting high income customers.</li></ul><p>Do NOT award answers relating to getting qualitative feedback or giving away free samples — trialling provides sales data, not opinion data.</p></div>"}, {"question": "Analyse one advantage for Clarks of interpreting quantitative data when designing new products. [3 marks]", "marks": 3, "hint": "Structure: Understanding (what is the advantage of quantitative data?) → Application (how does this apply to Clarks specifically?) → Analysis (what is the business impact for Clarks?). Do NOT just describe what quantitative data is.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> State an advantage of quantitative data — e.g. can sort/analyse/compare/identify trends or patterns (must be comparative); easy to investigate and draw conclusions from.</li><li><strong>Application (1 mark):</strong> Apply to Clarks — e.g. reference to very competitive market, specialist designers, fast-changing fashion trends, footwear for children/women/men, meeting customer needs profitably.</li><li><strong>Analysis (1 mark):</strong> Explain the business-facing impact — e.g. increased revenue, profit, competitive advantage, better decision-making. Analysis must stem from the advantage stated.</li></ul><p><strong>Do NOT award:</strong> ''can be plotted on a graph''; ''objective''; ''numerical''; what quantitative data IS rather than its advantage. Analysis must be business-facing.</p><p><strong>Exemplar response:</strong> \"Quantitative data will help Clarks identify changes in demand (U) for its children''s, women''s and men''s ranges in its competitive market (APP). Designing products to closely meet customer demand will lead to increased revenue for Clarks (+AN).\"</p></div>"}, {"question": "Analyse two advantages for Walkers of trialling new products before launching them. [6 marks]", "marks": 6, "hint": "Two separate advantages, each worth 3 marks: Understanding (what is the advantage?) → Application to Walkers (use a specific detail from the case study) → Analysis (what is the business impact for Walkers?). Remember: trialling gives sales DATA, not qualitative feedback on improving the product.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 6 marks (AO1b ×2 + AO2 ×2 + AO3a ×2)</h5><p>Two advantages required, each worth Understanding (1) + Application (1) + Analysis (1).</p><ul><li><strong>Possible advantages (Understanding):</strong> Identifies whether there is demand for the product / whether a launch would be successful / avoids the expense of a full product launch / reduces likelihood of negative impact on reputation or brand image / reduces risk of launching an unsuccessful product.</li><li><strong>Application to Walkers:</strong> Reference to well-known snacks / aim to maintain market share and increase profitability / adding new flavours (fish & chips, chicken burrito) / concern about healthy eating / 50% market share / Walkers crisps, Quavers, Wotsits.</li><li><strong>Analysis:</strong> Impact on market share, revenue, profit, costs, competitive advantage, wastage, planning, cashflow, etc. Analysis must be business-facing.</li></ul><p><strong>Important: Do NOT award</strong> answers about gaining customer opinions or qualitative feedback to improve the flavour — this is a fundamental misunderstanding of trialling. Trialling provides SALES DATA only.</p><p><strong>Exemplar response 1:</strong> \"Reduces the risk of introducing an unsuccessful product (U) which may have led to a reduction in the firm''s reputation (AN) and a fall in Walkers'' 50% market share (APP).\"</p><p><strong>Exemplar response 2:</strong> \"Sales figures will give an indication of which new flavours will be successful (U). Walkers can then concentrate its resources on those particular flavours such as ''chicken burrito'' (APP), increasing profit (AN).\"</p></div>"}, {"question": "Analyse one benefit to EDF of using focus groups as a primary market research method. [3 marks]", "marks": 3, "hint": "Structure: Understanding (what is a benefit of focus groups?) → Application (apply to EDF using a detail from the case study) → Analysis (what is the business impact for EDF?). A beneficial FEATURE of focus groups is required — not just a description of what a focus group is.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> State a beneficial feature of focus groups — e.g. can provide qualitative/in-depth information; can obtain detailed answers; can target a specific group of respondents; feedback is immediate; flexible process; can ask deeper probing questions.</li><li><strong>Application (1 mark):</strong> Apply to EDF — e.g. competitive market; price is very important; produces 20% of UK''s electricity; largest supplier; low-carbon electricity; a service rather than a good.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. more accurate decision making; less risk; more profit/revenue/sales; better positioned competitively.</li></ul><p>Do NOT award: ''can hear their opinions''; ''can see them in person''; ''can ask questions'' — these describe what a focus group IS, not its benefits. Analysis must be business-facing. Do NOT award arguments relating to honesty.</p></div>"}, {"question": "Analyse one benefit to EDF of using questionnaires as a primary market research method. [3 marks]", "marks": 3, "hint": "Structure: Understanding (a benefit of questionnaires specifically) → Application (link to EDF using a case study detail) → Analysis (business impact for EDF). Do NOT just say ''primary research gives first-hand data'' — this is too general and will not score the Understanding mark.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> State a beneficial feature of questionnaires — e.g. can be anonymous; completed independently with less group influence; can target a specific group; can gather qualitative and/or quantitative data; responses can be directly compared; easy to reach a large sample; relatively low-cost; time efficient.</li><li><strong>Application (1 mark):</strong> Apply to EDF — competitive market; price is important; 20% of UK''s electricity; largest supplier; supplies gas and electricity to homes and businesses; a service.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — more accurate decision making; less risk; more profit/revenue/sales.</li></ul><p><strong>Exemplar response:</strong> \"A questionnaire includes standard questions which are easy to compare (U). As EDF has 20% of the market (APP) it will need to ask lots of people so that the results represent those of its entire customer base, leading to more accurate decision-making by the company (AN).\"</p></div>"}, {"question": "Recommend whether focus groups or questionnaires is the best primary market research method for EDF to use. Give reasons for your answer. [3 marks]", "marks": 3, "hint": "Make a clear recommendation first (1 mark). Then justify your choice by COMPARING the two methods — explain why one is better than the other for EDF, using details from the case study. A contextual justification (linked to EDF) earns more marks.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO3b)</h5><p>1 mark for a recommendation. Up to 2 additional marks for justification — 1 mark for a non-contextual comparative justification, 2 marks for a contextual (EDF-specific) justification.</p><p>The justification MUST be comparative — why is one method BETTER OR WORSE than the other. Simply stating positives or negatives of one method without comparing does not earn justification marks.</p><ul><li>Look for comparators: cheaper, more detailed, less biased, less time consuming, larger sample, more in-depth, etc.</li></ul><p><strong>Exemplar response (questionnaires):</strong> \"Questionnaires are the best way (1) to carry out market research. The company can carry out the market research on a larger sample of customers than focus groups, so the results will be more representative. This will be very expensive, but EDF has 20% of the UK market so should be able to afford it (+2).\"</p><p><strong>Exemplar response (focus groups):</strong> \"Focus groups should be used (1). As they will lead to more in-depth analysis of customer views than questionnaires (+1).\"</p></div>"}, {"question": "Evaluate whether Sainsbury''s should use primary or secondary market research methods in the future. [7 marks]", "marks": 7, "hint": "You need: Application (2 marks) — use TWO case study details in relation to pros/cons of market research methods. Analysis (2 marks) — TWO different advantages/disadvantages of primary or secondary research, business-facing. Evaluation (3 marks) — a clear decision about which type Sainsbury''s should use, with a justified contextual reason.\n\nRemember to EMBED your application throughout your answer, not just mention the business name.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 7 marks (AO2 ×2 + AO3a ×2 + AO3b ×3)</h5><p><strong>Application (2 marks):</strong> Two uses of case study context in relation to pros/cons of market research methods — e.g. one of the UK''s largest supermarkets; targets middle to high income customers; develops new products to remain competitive; customers always looking for something new; uses market segmentation; very competitive industry; Aldi price match; TV advertising budget.</p><p><strong>Analysis (2 marks):</strong> Two different business-facing pros/cons, such as:</p><ul><li>Secondary MR may not be exactly what the business wants OR Primary MR is tailored/more specific to needs</li><li>Secondary MR may be outdated OR Primary MR can be up-to-date</li><li>Secondary MR is cheaper/lower cost OR Primary MR is expensive/costly</li><li>Secondary MR takes less time OR Primary MR takes a lot of time</li><li>Secondary MR has data readily available OR Primary MR needs to be collected from scratch</li></ul><p><strong>Evaluation (3 marks):</strong> A clear decision about which type Sainsbury''s should use, justified with contextual argument. For full 3 marks, the justification must be contextual (linked to Sainsbury''s specifically).</p><p><strong>Exemplar response:</strong> \"Utilising primary market research means they can find out specific information (AN) about sales in its competitive market (APP) so that Sainsbury''s can fulfil the needs and wants of its middle to high income customers (APP). Using secondary market research is much cheaper (AN). However, since Sainsbury''s is one of the largest UK supermarkets (APP) financial constraints are unlikely to be a problem. I think Sainsbury''s should use primary market research (EVAL) in future because it needs specific information to help the company develop and market products to compete with rivals like Aldi (contextual EVAL).\"</p></div>"}, {"question": "Evaluate, with reference to the case study and the data in the tables, whether the market research results show that Jon and Jo should go ahead with their childcare centre. [9 marks]", "marks": 9, "hint": "You need all five assessment objectives:\n • Knowledge (1 mark): Define market research\n• Understanding (1 mark): Give an example of a market research method\n• Application (2 marks): Use the NUMERICAL DATA from the tables — make TWO separate points with actual figures\n• Analysis (2 marks): Explain the impact/effect on Jon and Jo''s business — TWO separate points\n• Evaluation (3 marks): Make a judgement (should they go ahead?), then justify it precisely using data and case study details", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 9 marks (AO1a ×1 + AO1b ×1 + AO2 ×2 + AO3a ×2 + AO3b ×3)</h5><p><strong>Knowledge (1 mark):</strong> A simple statement showing knowledge of market research — e.g. \"Market research is the collection of data on consumer habits.\"</p><p><strong>Understanding (1 mark):</strong> An example of a market research method — e.g. primary/secondary research; questionnaires; interviews; census data.</p><p><strong>Application (2 marks):</strong> Two examples using numerical data from the case study — e.g.:<br>• Jon and Jo have conducted primary research. This shows that the vast majority (73 out of 85) are satisfied or very satisfied with their present childcare.<br>• Only 10 out of 85 would definitely consider moving their child, which is below the capacity of every site they have looked at.</p><p><strong>Analysis (2 marks):</strong> Explanation of impact/effect on the business — e.g.:<br>• If inadequate market research was undertaken then an incorrect decision might be taken, possibly opening the business where there is no demand, meaning lower than expected income.<br>• Having a full range of positive market research gives confidence in the business owners to go ahead — this is important in helping build up a customer base that will bring in revenue.</p><p><strong>Evaluation (3 marks):</strong><br>• Judgement (1 mark): A simple statement — e.g. \"I do not think there is sufficient market research for Jon and Jo to go ahead.\"<br>• Justification (2 marks): A clear, precise justification using data from the case study — e.g. \"The data they have collected is not conclusive. Only 10 parents would definitely move their child (which may not be the one operated by Jon and Jo). This is below the capacity of the smallest site. More investigation is required. Jon and Jo are not risk takers — the data shows this would be a big risk.\"</p></div>"}]}}'::jsonb),
('business', '2-3-market-segmentation', '2.3 Market Segmentation', '{"learn": {"enabled": true, "items": [{"title": "What is Market Segmentation?", "html": "<p><strong>Market segmentation</strong> is the splitting of the market for a product or service into different parts, or segments.</p>\n  <p>Splitting the market into different segments helps the business to identify its <strong>target market</strong> more effectively. This is done by looking at the different types of customers that might buy the product — their age, gender, income, location and lifestyle.</p>\n  <p>For example, Adidas will have trainers made for serious runners, and trainers made for simple everyday wear. The trainers for serious runners would be advertised in running magazines, whereas the more general trainers would not. With good segmentation, the advertising for a product can be much more accurate.</p>\n  <p>Businesses need to know that people in different segments often want different kinds of products or services — so they can target their products at the different needs of customers in each segment.</p>\n  <p>When a business targets the different segments in its market, it will need to consider:</p>\n  <ul>\n  <li><strong>Whether to produce different products</strong> for different markets — e.g. male/female versions, or basic and more sophisticated models</li>\n  <li><strong>What price to charge</strong> — high or low?</li>\n  <li><strong>How to promote the products</strong> — the type of media to use and what message this method may give</li>\n  <li><strong>Where to locate shops</strong> — town centre, shopping mall, holiday resort — and whether to sell online or not</li>\n  </ul>", "check": {"question": "What is market segmentation?", "options": ["Splitting the market for a product into different parts", "Splitting a business into separate departments", "Splitting the production process into separate stages", "Splitting company profits between shareholders"], "answer": 0, "explain": "Market segmentation is defined as the splitting of the market for a product or service into different parts, or segments, to identify the target market more effectively."}}, {"title": "Segmentation by Age", "html": "<p>Different age groups will buy different products. While the latest technology may be aimed at younger people, it is not to say that some older people will not also buy such products.</p>\n  <p>Recent changes in the population structure of the UK have meant there is a growing number of older people who have the wealth, health and time to enjoy themselves. This has resulted in holiday businesses targeting more (and often more expensive) holidays at this age group.</p>\n  <p><strong>Examples of age segmentation:</strong></p>\n  <ul>\n  <li>Magazines aimed at teenage girls vs. magazines aimed at women in the 20–40 age range</li>\n  <li>Bright, big and colourful watches for younger people vs. more understated designs for older people</li>\n  <li>Toys targeted at specific age bands (e.g. 0–2, 3–5, 6–10)</li>\n  <li>Holidays to Disneyland (families with young children) vs. river cruising (older customers)</li>\n  </ul>\n  <p><strong>Note:</strong> Age segmentation can be difficult to plan with total accuracy — not every young person wants the same thing, and older people may sometimes want products typically associated with younger age groups.</p>", "check": {"question": "What is a key limitation of segmenting a market by age?", "options": ["Not everyone in an age group wants the same specific products", "Age segmentation is not legally allowed for most consumer products", "It is impossible for businesses to find out the age of their customers", "Age segmentation can only be used by holiday and travel businesses"], "answer": 0, "explain": "The card notes that age segmentation can be difficult to plan with total accuracy, since not every young person wants the same thing and older people may want products typically aimed at younger groups."}}, {"title": "Segmentation by Gender, Income & Location", "html": "<p><strong>Gender:</strong> Men and women will often (but not always) buy different products. As with age, it can be difficult to segment all products clearly. Clothing is more easily segmented along gender lines. Many businesses make products for both men and women — for example, Adidas produces sportswear for both genders.</p>\n  <p><strong>Examples:</strong> Different coloured running shoes for men and women; male/female clothing ranges.</p>\n  <p><strong>Income:</strong> People with higher levels of income will want particular products, often to show that they have wealth. This could include selected watches, yachts, certain cars, particular designer clothes. Businesses target these customers because there could be a lot of profit to be made.</p>\n  <p><strong>Examples:</strong> Patek Philippe watches for the very wealthy; Casio watches for low-income customers. Luxury garden furniture vs. budget table-and-chair sets.</p>\n  <p><strong>Location:</strong> Consumers living in different parts of the country will have different tastes and needs. If customers live in an expensive area, their tastes in products may be at the more luxury level. Another aspect is practicality — those living in a city may want a smaller car; those in the country may want a car that copes with off-road driving. The stock in a shop may be chosen to match the expected local population — a clothes shop in the country will stock different styles than those in the centre of a city.</p>\n  <p><strong>Examples:</strong> Business suits for city workers; tweed for those living in the countryside.</p>", "check": {"question": "A business designs a smaller car for city customers and a rugged off-road vehicle for rural customers. Which segmentation method does this represent?", "options": ["Age", "Gender", "Location", "Income"], "answer": 2, "explain": "The card explains that location segmentation considers practicality — city dwellers may want a smaller car, while those in the country may want a car that copes with off-road driving."}}, {"title": "Segmentation by Lifestyle", "html": "<p>Different people have different hobbies and interests. This will mean that a range of products is needed to satisfy all tastes. Lifestyle may also be connected to income and location — for example, those wanting to sail a yacht may be living in a coastal location and have plenty of money.</p>\n  <p>Lifestyle can go beyond having a hobby or interest. Many people follow celebrities and wherever possible copy their lifestyle, opting for similar hairstyles and clothing. This creates demand for particular products and services that gives businesses an opportunity for profit.</p>\n  <p><strong>Examples of lifestyle segmentation:</strong></p>\n  <ul>\n  <li>Lycra clothing for the cycling enthusiast</li>\n  <li>Large flat-screen TVs for viewing enthusiasts</li>\n  <li>Special watches for diving, running and other outdoor pursuits</li>\n  <li>Specialist magazines (e.g. cycling, photography, cooking)</li>\n  <li>Health foods and gym products aimed at fitness enthusiasts</li>\n  </ul>\n  <p><strong>Adidas ''Own the Game'' strategy (2021):</strong> Adidas describes their customers as: ''They strive to live active and healthy lives, they wish to blend sport and lifestyle, they are digital by default and sustainable by conviction.'' This is a lifestyle-based segmentation approach.</p>", "check": {"question": "Adidas''s ''Own the Game'' strategy describes customers as wanting to ''blend sport and lifestyle'' and being ''sustainable by conviction''. Which segmentation method does this best represent?", "options": ["Age", "Location", "Income", "Lifestyle"], "answer": 3, "explain": "The card states that Adidas''s description of customers by their interests and way of living is a lifestyle-based segmentation approach."}}, {"title": "Advantages and Disadvantages of Market Segmentation", "html": "<div class=\"two-col\">\n  <div>\n  <div class=\"col-head\">✓ Advantages</div>\n  <div class=\"pro-item\"><strong>Increased sales:</strong> Can design and produce products specifically aimed at groups of customers — more likely to meet their needs and be purchased</div>\n  <div class=\"pro-item\"><strong>Helps identify gaps in the market:</strong> By studying segments, a business can identify customer groups that are not currently being targeted</div>\n  <div class=\"pro-item\"><strong>Avoids wasting money:</strong> Marketing will be focused on the specific target group rather than a broad, general audience</div>\n  <div class=\"pro-item\"><strong>Higher market share:</strong> By meeting specific needs, a business can win loyal customers from that segment</div>\n  <div class=\"pro-item\"><strong>Better targeted advertising:</strong> If a business is clear on its market (due to segmentation), it can target advertising much more accurately — greater return on marketing expenditure</div>\n  <div class=\"pro-item\"><strong>Improved customer retention:</strong> Products that closely meet customer needs lead to greater satisfaction and repeat purchases</div>\n  </div>\n  <div>\n  <div class=\"col-head\">✗ Disadvantages</div>\n  <div class=\"con-item\"><strong>High promotional costs:</strong> Different advertisements and promotions may be needed for different groups</div>\n  <div class=\"con-item\"><strong>Cost of market research:</strong> Research to identify and understand each specific segment can be expensive</div>\n  <div class=\"con-item\"><strong>Lack of information:</strong> Some markets are poorly researched and data may be limited or unreliable</div>\n  <div class=\"con-item\"><strong>Hard to reach segments:</strong> Some customer groups are difficult to target effectively with existing marketing channels</div>\n  <div class=\"con-item\"><strong>Difficulty of clear segmentation:</strong> Not all products can be clearly segmented — e.g. not every young person wants the same things</div>\n  </div>\n  </div>", "check": {"question": "Which of the following is a disadvantage of market segmentation?", "options": ["Different promotional campaigns are needed per group", "It helps a business identify gaps in the market", "It leads to better-targeted advertising", "It can increase market share by winning loyal customers"], "answer": 0, "explain": "The card lists high promotional costs — needing different advertisements and promotions for different groups — as a key disadvantage of market segmentation."}}, {"title": "Evaluation — Is Segmentation Worth It?", "html": "<p>Segmentation can be used in any business situation. All businesses target their market in some way. When evaluating, look for the ways in which the market for a business can be split and how this splitting, or segmentation, will benefit the business.</p>\n  <p><strong>Segmentation is generally more important to businesses which have:</strong></p>\n  <ul>\n  <li>A larger amount of money to spend on advertising</li>\n  <li>A diverse product range targeting different customer groups</li>\n  <li>A need to differentiate themselves from competitors</li>\n  </ul>\n  <p><strong>Case study — Adidas:</strong> Adidas has a carefully segmented market: different sports (football, athletics, golf), different needs (footwear, clothing), male and female markets, and budget and professional products. This segmentation has been central to Adidas growing from a small German business into a global brand.</p>\n  <p><strong>Case study — Amala''s Garden Furniture:</strong> Amala''s business makes luxury sets (costing thousands of pounds) alongside small sets (under £100). Using market segmentation would help the business decide the income range at which to target each range, and where to advertise — e.g. luxury products in a garden magazine vs. budget products in a local newspaper. This would make advertising more focused and save money by only advertising where it is effective.</p>\n  <p><strong>Evaluation summary:</strong> The benefits of segmentation (increased sales, better-targeted advertising, identifying gaps in the market) are likely to outweigh the costs (market research, different promotional campaigns) for most established businesses, especially those operating in competitive markets with diverse customer groups.</p>", "check": {"question": "According to the evaluation guidance, segmentation is generally MORE important to businesses that have which of the following?", "options": ["A larger advertising budget and diverse product range overall", "A single, simple product with a very small advertising budget", "Only one type of customer and no competitors", "A policy of never changing prices or products"], "answer": 0, "explain": "The card states segmentation is generally more important to businesses with a larger amount of money to spend on advertising and a diverse product range targeting different customer groups."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Market segmentation", "definition": "The splitting of the market for a product or service into different parts, or segments. Helps a business identify its target market more effectively."}, {"term": "Target market", "definition": "The group of customers at which a product or service is aimed or targeted. Identified after segmenting the market."}, {"term": "Age segmentation", "definition": "Dividing the market based on customers'' age — e.g. teenage girls'' magazines, holidays aimed at older people who have wealth and time to enjoy themselves."}, {"term": "Gender segmentation", "definition": "Dividing the market based on whether customers are male or female — e.g. men''s and women''s clothing, different coloured running shoes for men and women."}, {"term": "Income segmentation", "definition": "Dividing the market based on how much customers earn — e.g. Patek Philippe watches for the wealthy, Casio watches for lower income customers, luxury vs. budget garden furniture."}, {"term": "Location segmentation", "definition": "Dividing the market based on where customers live — e.g. business suits for city workers, tweed for those in the countryside. The stock in a shop may be chosen to match the expected local population."}, {"term": "Lifestyle segmentation", "definition": "Dividing the market based on customers'' hobbies, interests and ways of living — e.g. sportswear for cyclists, specialist watches for divers. Lifestyle may also be linked to following celebrities."}, {"term": "Benefit 1: Better targeted advertising", "definition": "With good segmentation, advertising can be directed at the specific group most likely to buy the product — e.g. running trainers advertised in running magazines. Avoids wasting money on non-targeted campaigns."}, {"term": "Benefit 2: Increased sales", "definition": "By designing and producing products specifically aimed at customer groups, a business better meets their needs and those customers are more likely to buy. Higher customer satisfaction → repeat purchases."}, {"term": "Benefit 3: Identifies gaps in the market", "definition": "By studying segments, a business can identify customer groups not currently being targeted — creating an opportunity to introduce new products or services."}, {"term": "Disadvantage 1: High promotional costs", "definition": "Different advertisements and promotions may be needed for different customer groups, which can be expensive."}, {"term": "Disadvantage 2: Market research costs", "definition": "Research to identify and understand each specific segment can be expensive. Some markets are also poorly researched and data may be limited."}, {"term": "Adidas segmentation", "definition": "Adidas segments by: different sports (football, athletics, golf), different needs (footwear vs. clothing), male and female markets, and budget vs. professional products."}, {"term": "Watches — segmentation example", "definition": "Watches can be segmented by: Age (bright/colourful for young), Gender (men''s vs women''s), Income (Patek Philippe vs Casio), Lifestyle (diving watches, nurse watches, sports watches)."}, {"term": "Why segmentation matters", "definition": "Understanding segmentation helps a business market its products much more accurately. It is generally more important to businesses with larger advertising budgets and diverse product ranges."}, {"term": "Segment vs. Target", "definition": "Segmentation is the PROCESS of dividing the market into groups. Targeting is the ACTION of directing marketing at the chosen segment. You segment first, then select and target."}]}, "mcq": {"enabled": true, "questions": [{"question": "Segmentation is:", "options": ["Splitting the number of products you sell each year", "Splitting the market for a product into different parts", "Splitting the staff in a business so they produce goods quicker", "Splitting the holidays that staff take so not all staff are away at the same time"], "answer": 1, "explain": "Correct answer: Market segmentation is the splitting of the market for a product or service into different parts, or segments. The other options describe entirely different business activities unrelated to marketing."}, {"question": "Which of the following is NOT a method of segmentation?", "options": ["Gender", "Target", "Income", "Age"], "answer": 1, "explain": "Correct answer: Target. ''Target'' is not a method of segmentation — it is what a business does AFTER it has segmented the market (i.e. it targets a specific segment). The methods of segmentation are age, gender, income, location and lifestyle."}, {"question": "Segmentation of a market is done to help with:", "options": ["Targeting advertising more accurately", "Increasing the amount of products being made", "Improving the quality of goods being sold", "Making sure that workers are happy at work"], "answer": 0, "explain": "Correct answer: Segmentation is done so that a business can target its advertising more accurately at the specific group of customers most likely to buy the product. Options B, C and D relate to operations, quality management, and HR respectively — not marketing or segmentation."}, {"question": "It is better for a business to target a particular market because it:", "options": ["Helps them recruit staff", "Saves time in replacing stock on shelves", "Can help them to decide where to advertise", "Can help them decide whether or not it is the right time to expand the business"], "answer": 2, "explain": "Correct answer: Targeting a particular market (segment) can help a business decide where to advertise — for example, advertising running trainers in a running magazine rather than a general interest magazine. Options A, B and D are not benefits of market segmentation."}, {"question": "The owner of a toy shop wishes to use market segmentation to target customers. What is an example of market segmentation?", "options": ["Encouraging customers into the shop by posting on social media", "Opening a second toy shop in the same town", "Organising the toys in the shop by age group", "Viewing a rival store''s website to identify its special offers"], "answer": 2, "explain": "Correct answer: Organising toys by age group is an example of market segmentation — the market (toy buyers) is being divided into segments based on the age of children. Options A and B are promotion/growth strategies. Option D is competitive analysis, not segmentation."}, {"question": "Which of the following is a benefit to a business of advertising on local radio?", "options": ["Can target a specific geographical area", "Detailed financial information can be included", "Free samples can be given out with the advertisement", "The product can be seen and demonstrated"], "answer": 0, "explain": "Correct answer: Local radio allows a business to target a specific geographical area — this links to location-based segmentation. Option B is not possible on radio (audio only). Option C relates to in-store sampling. Option D relates to TV or video advertising where the product can be shown."}, {"question": "Which of the following best describes the term ''target market''?", "options": ["All the people who might ever buy any product", "The group of customers at which a product or service is aimed", "A goal set by the marketing department to increase sales", "The price level a business targets for its products"], "answer": 1, "explain": "Correct answer: A target market is the group of customers at which a product or service is specifically aimed or targeted. It is identified through market segmentation — dividing the market and then selecting the most appropriate segment to focus on."}, {"question": "Adidas segments its market by different sports, footwear/clothing, male/female, and budget/professional products. Which segmentation method does ''budget vs professional products'' best represent?", "options": ["Gender", "Location", "Age", "Income"], "answer": 3, "explain": "Correct answer: Income. Budget products are aimed at customers with lower incomes or those less willing to spend heavily, while professional products are aimed at those with higher incomes or greater willingness to spend on premium products. This is income-based segmentation."}, {"question": "A clothing business notices that city workers tend to buy formal suits while people in rural areas tend to buy outdoor wear. What type of market segmentation does this represent?", "options": ["Age", "Lifestyle", "Gender", "Location"], "answer": 3, "explain": "Correct answer: Location. The segmentation is based on where customers live and the different needs that come from their location (city vs. countryside). Location segmentation recognises that consumers in different parts of the country have different tastes and practical needs."}, {"question": "A business is considering using market segmentation for the first time. Which of the following is a potential disadvantage?", "options": ["Products will be better targeted at customer needs", "Advertising will be more focused and less wasteful", "Different promotional campaigns will be needed for different groups, increasing costs", "The business will be able to identify gaps in the market"], "answer": 2, "explain": "Correct answer: A disadvantage of market segmentation is that different promotional campaigns may be needed for different groups, which increases promotional costs. Options A, B and D are all advantages of market segmentation."}]}, "fib": {"enabled": true, "questions": [{"text": "Market [segmentation] is the splitting of the market for a product into different parts. This helps a business identify its [target] market more effectively."}, {"text": "The five main ways to segment a market are: [age], gender, income, [location] and lifestyle."}, {"text": "With good segmentation, the [advertising] for a product can be much more accurate. Businesses can avoid wasting money by focusing marketing on the specific [group]."}, {"text": "A disadvantage of market segmentation is that [different] promotional costs may be needed for different groups. The cost of [market] research for specific segments can also be high."}, {"text": "People with higher levels of [income] will want particular products, often to show their wealth. People with different hobbies and interests are segmented by [lifestyle]."}, {"text": "Although the Rolls Royce and the Ford Focus are both cars, they are not in [competition] with each other. By segmenting the market, a business may be able to identify a [gap] in the market."}]}, "tf": {"enabled": true, "questions": [{"statement": "Market segmentation means splitting the market for a product into different parts.", "answer": true, "explain": "TRUE. Market segmentation is the splitting of the market for a product or service into different parts, or segments. This helps a business identify its target market more effectively."}, {"statement": "''Target'' is a valid method of market segmentation.", "answer": false, "explain": "FALSE. ''Target'' is NOT a method of segmentation — it is what a business does AFTER it has segmented the market (i.e. it targets a specific segment). The methods are: Age, Gender, Income, Location and Lifestyle."}, {"statement": "A business that uses market segmentation can target its advertising more accurately.", "answer": true, "explain": "TRUE. With good segmentation, a business knows exactly who its customers are and can direct advertising at the specific group most likely to buy. For example, Adidas advertises serious running trainers in running magazines rather than general interest magazines."}, {"statement": "A disadvantage of market segmentation is that different promotional campaigns may be needed for different groups, increasing costs.", "answer": true, "explain": "TRUE. One disadvantage of segmentation is that different advertisements and promotions may be needed for each customer group, which increases promotional costs. This is why segmentation requires careful cost-benefit analysis."}, {"statement": "Market segmentation is only useful for large businesses with big marketing budgets.", "answer": false, "explain": "FALSE. Segmentation can be used in any business situation — all businesses target their market in some way. However, it is generally MORE important to businesses with a larger amount of money to spend on advertising, as they have more to gain from ensuring that spend is well-targeted."}, {"statement": "Segmenting the market by location recognises that consumers in different areas may have different needs and tastes.", "answer": true, "explain": "TRUE. Location segmentation recognises that consumers in different parts of the country have different tastes and practical needs. For example, city workers may need business suits while those in the countryside may want outdoor clothing. A shop''s stock is often chosen to match the expected local population."}, {"statement": "Lifestyle segmentation is based solely on a customer''s income level.", "answer": false, "explain": "FALSE. Lifestyle segmentation is based on customers'' HOBBIES and INTERESTS — e.g. cycling, diving, fitness, following celebrities. Income segmentation is a separate method based on how much money customers earn. The two may sometimes overlap (e.g. sailing can require both an appropriate lifestyle and high income) but they are distinct methods."}, {"statement": "When a business segments by income, it is typically looking to identify which customers have more money to spend on premium products.", "answer": true, "explain": "TRUE. Income segmentation is often used to target wealthier customers who will buy premium, luxury goods — e.g. Patek Philippe watches, yachts, certain designer cars. Businesses target these customers because there could be a lot of profit to be made."}, {"statement": "Market segmentation can help a business identify gaps in the market that are not currently being targeted.", "answer": true, "explain": "TRUE. By studying segments carefully, a business may identify customer groups whose needs are not currently being met by any existing product or business. This represents a market gap — an opportunity to introduce a new product or service."}, {"statement": "For a business selling products to both serious athletes and casual wearers, using the same advertising in the same places for both products is the best approach.", "answer": false, "explain": "FALSE. Different segments require different advertising approaches. Serious athletes might be reached through specialist sports magazines or sports events, while casual wearers might be reached through general interest media or social media. Using the same advertising for both would be inefficient and wasteful — good segmentation allows a business to target each group precisely."}]}, "misc": {"enabled": true, "items": [{"myth": "Students sometimes think that a business using market segmentation wants to sell to EVERYBODY and should try to target all customers equally.", "truth": "Market segmentation is specifically about dividing the market into DIFFERENT PARTS and targeting ONE or more specific segments — not everyone. The whole purpose of segmentation is to focus resources on the customers most likely to buy a product. A business that tries to target everyone at once risks wasting money on advertising that reaches people who will never buy the product.", "check": {"question": "What is the true purpose of market segmentation?", "options": ["To divide the market and target specific segments", "To make sure every single customer in the whole market is targeted equally", "To reduce the number of products a business makes", "To increase the number of retail outlets a business owns"], "answer": 0, "explain": "The card corrects the misconception that segmentation targets everybody equally — its real purpose is to divide the market into different parts and focus on specific segments most likely to buy."}}, {"myth": "Students often confuse ''market segmentation'' (the method) with ''target market'' (the outcome). They use the terms interchangeably.", "truth": "Market segmentation is the PROCESS of splitting the market into different groups. The TARGET MARKET is the specific group of customers a business then CHOOSES to aim its products at. You segment first, then select your target market. E.g. Boohoo segmented by age and identified that its target market is 16–24 year olds who are fashion conscious.", "check": {"question": "What is the correct relationship between ''market segmentation'' and ''target market''?", "options": ["Segmentation splits the market; target market is chosen afterward from it", "The two terms mean exactly the same thing and can always be used interchangeably", "The target market is decided first, and the market is segmented afterwards", "Target market refers only to customers located overseas"], "answer": 0, "explain": "The card clarifies that segmentation is the process of splitting the market, while the target market is the specific group a business then chooses to aim its products at — segmentation happens first."}}, {"myth": "For ''analyse'' questions about market segmentation, students often answer by describing what segmentation is, instead of analysing its benefit or impact on the business.", "truth": "Explaining WHAT segmentation is scores zero for ''analyse'' or ''explain'' questions. You need: Understanding of a benefit (1) → Application to the named business (1) → Business impact/Analysis (1). E.g. ''Segmentation allows Sainsbury''s to alter products to satisfy the specific needs of middle to high income customers (U+APP), which will help boost revenue and maintain customer loyalty in a very competitive supermarket industry (AN).''", "check": {"question": "For an ''analyse'' question on the benefit of market segmentation, what must the answer include to score full marks?", "options": ["Understanding of a benefit, applied and analysed", "A definition of what market segmentation means", "A list of all five methods of segmentation", "A description of the business''s trading history"], "answer": 0, "explain": "The card states that simply describing what segmentation is scores zero — analyse answers need Understanding of a benefit, Application to the named business, and Analysis of the impact."}}, {"myth": "For ''analyse'' questions about product development and segmentation, students often mention pricing, advertising or promotion rather than the product itself.", "truth": "If the question asks about market segmentation when DEVELOPING NEW PRODUCTS, your answer must focus on the PRODUCT — e.g. how segmentation helps the business create, design, tailor or alter the product to meet the needs of specific customer groups. Do NOT answer with points about pricing, advertising, or launching the product — these are post-development and will not be credited.", "check": {"question": "When a question asks how market segmentation helps with DEVELOPING NEW PRODUCTS, what must the answer focus on?", "options": ["How segmentation helps design or tailor the product", "How segmentation helps set the price of the product", "How segmentation helps choose an advertising method", "How segmentation helps decide where to sell the product"], "answer": 0, "explain": "The card warns that for product development questions, only points about creating, designing or tailoring the product are creditworthy — pricing and advertising points will not be credited."}}, {"myth": "Students sometimes list ''target'' as a method of market segmentation.", "truth": "''Target'' is NOT a method of segmentation — it is what a business does AFTER it has segmented the market. The methods of segmentation are: Age, Gender, Income, Location and Lifestyle. ''Target'' is the ACTION of directing your marketing at the chosen segment. Always use one of the five methods when asked to state a way to segment a market.", "check": {"question": "Which of these is NOT one of the five recognised methods of market segmentation?", "options": ["Age", "Lifestyle", "Target", "Income"], "answer": 2, "explain": "The card explains that ''target'' is not a method of segmentation — it is the action a business takes after segmenting; the five methods are age, gender, income, location and lifestyle."}}, {"myth": "For ''explain one way to segment a market'' questions, students often write only one word (e.g. ''age'') and think this is enough.", "truth": "Writing just ''age'' scores only 1 mark (knowledge). To score the second mark (understanding), you must show HOW that method is used — e.g. ''A business could segment by age (K), for example by aiming its products specifically at elderly people or teenagers (U).'' The ''explain'' command word always requires development beyond simply naming the method.", "check": {"question": "For a 2-mark ''explain one way to segment a market'' question, what does writing only ''age'' achieve?", "options": ["Only 1 mark — it needs an example for understanding", "Full marks, because naming a correct method is always enough", "Zero marks, because no explanation at all was given", "2 marks, but only if the named business is also mentioned"], "answer": 0, "explain": "The card states that writing just ''age'' scores only the knowledge mark; the second (understanding) mark requires showing how that method is used in practice."}}]}, "tips": {"enabled": true, "items": [{"title": "State a Method of Market Segmentation", "html": "<p>Simply name the method — no explanation needed for ''state'' or ''identify'' questions.</p>\n  <p><strong>Accepted methods:</strong> Age / Gender (sex) / Income / Location / Lifestyle</p>\n  <p><strong>NOT accepted:</strong> ''Target'' (this is not a method), ''demographic'' alone (too vague), or any reference to advertising location (e.g. ''advertise on TV'' — this is not a segmentation criterion).</p>\n  <p><strong>Special cases:</strong> ''Boys'' or ''Girls'' alone can be awarded as age OR gender. ''Boys and girls'' together counts as age only.</p>", "check": {"question": "In a ''state'' or ''identify'' question on segmentation methods, which answer would NOT be accepted?", "options": ["''Target''", "''Lifestyle''", "''Income''", "''Age''"], "answer": 0, "explain": "The card explicitly lists ''target'' as not accepted, since it is not a method of segmentation, unlike age, gender, income, location and lifestyle."}}, {"title": "Explain One Way a Business Can Segment Its Market", "html": "<p>Structure: Knowledge (1) + Understanding of how the method is used (1)</p>\n  <ul>\n  <li>Name a method of segmentation</li>\n  <li>Give an example of how it is used or what it means in practice</li>\n  </ul>\n  <p><strong>Example:</strong> \"One way a business could segment its market is by age (K), for example by aiming to sell products specifically to elderly people who have wealth and time to enjoy themselves (U).\"</p>\n  <p><strong>Example:</strong> \"By gender (K), by targeting marketing particularly at women, for example with a range of women''s clothing or beauty products (U).\"</p>\n  <p><strong>Note:</strong> Answers do not need to relate to the named business in the case study unless the question asks specifically for that.</p>", "check": {"question": "For a 2-mark ''explain one way a business can segment its market'' question, what structure is required?", "options": ["Knowledge of a method plus understanding of its use", "Knowledge only, with the same point repeated twice", "Application to the case study business plus Analysis of the impact", "A definition of segmentation followed by a judgement"], "answer": 0, "explain": "The card sets out the structure as Knowledge (1) — naming a method — plus Understanding (1) — an example of how the method is used."}}, {"title": "Analyse a Benefit of Using Market Segmentation", "html": "<p>Structure: Understanding (1) → Application to the named business (1) → Business-facing Analysis (1)</p>\n  <ul>\n  <li>State a benefit of market segmentation</li>\n  <li>Apply it to the specific business using case study details</li>\n  <li>Explain the business impact — sales, revenue, customer satisfaction, market share, etc.</li>\n  </ul>\n  <p><strong>Example (Sainsbury''s — product development):</strong> \"Sainsbury''s can alter its products to satisfy the specific needs of customer segments (U). Since Sainsbury''s targets middle to high income customers in a very competitive supermarket industry (APP), tailoring products to this segment will help boost revenue and maintain customer loyalty (AN).\"</p>\n  <p><strong>Important:</strong> For questions specifically about PRODUCT DEVELOPMENT, only answers about creating/designing/tailoring the product are creditworthy. Do not answer with points about pricing or advertising.</p>", "check": {"question": "What is the correct mark structure for a 3-mark ''analyse a benefit of market segmentation'' question?", "options": ["Understanding, application, then analysis of impact", "Knowledge (1) + Understanding (1) + Evaluation (1)", "Three separate benefits, worth one mark each", "Application worth all 3 marks, with no need for understanding or analysis"], "answer": 0, "explain": "The card sets out the structure as Understanding (1) leading to Application to the named business (1) leading to business-facing Analysis (1)."}}, {"title": "Analyse Two Benefits of Market Segmentation", "html": "<p>For each benefit: Understanding (1) + Application to the named business (1) + Analysis (1).</p>\n  <p><strong>Common benefits to use:</strong></p>\n  <ul>\n  <li>Helps target specific customers / better meet customer needs</li>\n  <li>Can tailor the product/range to attract a specific group</li>\n  <li>Can design promotion/advertising campaign to target a specific group — greater return on marketing expenditure</li>\n  <li>Can adjust price/pricing strategy to attract a specific group</li>\n  <li>Can change the place/distribution channels to attract a specific group</li>\n  <li>Avoids wasting money on broad, non-targeted advertising</li>\n  <li>Identifies gaps in the market not currently being served</li>\n  </ul>\n  <p><strong>Apply using case study details</strong> — number of shops, declining sales, sole trader status, types of product, existing segmentation criteria, etc.</p>", "check": {"question": "For the 6-mark ''analyse two benefits of market segmentation'' question, how should marks be distributed?", "options": ["Each benefit is worth 3 marks: Understanding + Application + Analysis, done twice", "One combined 6-mark answer covering both benefits together without separating them", "6 marks for simply stating six different segmentation methods", "Application is worth all 6 marks, with no need for understanding or analysis"], "answer": 0, "explain": "The card states that for each benefit, Understanding (1) + Application to the named business (1) + Analysis (1) should be given, repeated for the second benefit."}}, {"title": "Evaluate the Benefit of Market Segmentation", "html": "<p>Structure: Application (2) + Analysis (2) + Evaluation — judgement (1) + justification (2)</p>\n  <ul>\n  <li>Two applied points using case study details</li>\n  <li>Two analytical impacts on the business</li>\n  <li>A simple judgement — do you think it will benefit the business?</li>\n  <li>A justified contextual conclusion — why do you think this? Use the case study.</li>\n  </ul>\n  <p><strong>Judgement example:</strong> \"Overall, I think market segmentation will be very effective in helping Amala''s family business.\"</p>\n  <p><strong>Justified conclusion:</strong> \"The business makes a range of garden furniture from luxury sets (thousands of pounds) to small sets (under £100). It must identify just who is buying the different products so these consumers can be targeted. It is no good simply advertising all products in one place — different products require different approaches, and clear segmentation will make advertising more focused and save money.\"</p>", "check": {"question": "What must a 7-mark ''evaluate the benefit of market segmentation'' answer include beyond application and analysis?", "options": ["A judgement plus a justified conclusion using case study context", "A repeated definition of what market segmentation means", "Three further analytical points instead of a judgement", "A complete list of every segmentation method used by the business"], "answer": 0, "explain": "The card sets out the structure as Application (2) + Analysis (2) + a simple judgement (1) + a justified contextual conclusion (2)."}}]}, "exam": {"enabled": true, "questions": [{"question": "Analyse one likely reason why Sainsbury''s uses market segmentation when developing new products. [3 marks]", "marks": 3, "hint": "This question is specifically about PRODUCT DEVELOPMENT — your answer must be about creating, designing or tailoring the PRODUCT itself. Do NOT write about pricing, advertising or promotion. Structure: Understanding → Application to Sainsbury''s → Business-facing Analysis.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1a + AO2 + AO3a)</h5><ul><li><strong>Knowledge (1 mark):</strong> State a reason — e.g. can alter/create/design/tailor products to satisfy the specific needs of customer groups.</li><li><strong>Application (1 mark):</strong> Link to Sainsbury''s — e.g. targeted at middle to high income customers / supermarket industry is very competitive / customers always looking for something new / Sainsbury''s believes good food should be accessible to everyone.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. boost revenue, maintain customer loyalty, greater customer satisfaction, good brand reputation, competitive advantage.</li></ul><p><strong>Do NOT reward:</strong> answers about pricing, selling, promoting, advertising or launching — this question is about product development only. Do NOT reward adaptations that aim to meet the needs of ALL customers (this contradicts segmentation).</p></div>"}, {"question": "Explain one way that a business can segment its market. [2 marks]", "marks": 2, "hint": "Name a method of segmentation (1 mark), then explain what that means in practice or give an example (1 mark). Your answer does NOT need to relate to Nina''s Knitting Supplies specifically.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a + AO1b)</h5><ul><li><strong>Knowledge (1 mark):</strong> Name a method — Age / Gender/Sex / Income / Location / Lifestyle.</li><li><strong>Understanding (1 mark):</strong> Show how the method is used — e.g. Age: target young/old/babies/children/teenagers/over 50s; Gender: target male/female/men/women; Income: target well paid/low paid/affluent/high earners; Location: target locals/specific region; Lifestyle: healthy/sports/outdoor pursuits/hobbies.</li></ul><p>Answers do not need to relate to Nina''s Knitting Supplies. Accept ''boys'' for age or gender. Accept ''girls'' for age or gender. ''Boys and girls'' together = age only.</p></div>"}, {"question": "The owner of a toy shop wishes to use market segmentation to target customers. What is an example of market segmentation?", "marks": 1, "hint": "Market segmentation is about dividing customers into groups based on their characteristics. Which option divides customers into groups?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: C — Organising the toys in the shop by age group.</strong></p><p>Organising toys by age group divides the market (toy buyers) into segments based on age — a clear example of market segmentation. Option A is a promotion/social media activity. Option B is a growth strategy. Option D is competitor research.</p></div>"}, {"question": "Analyse two benefits for Miles Ahead of using market segmentation. [6 marks]", "marks": 6, "hint": "Two separate benefits, each worth 3 marks: Understanding (what is the benefit?) → Application (how does this apply to Miles Ahead specifically — use case study details like 6 shops, sole trader, declining sales, segments by age/gender/lifestyle/income) → Analysis (what is the business impact?)", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 6 marks (AO1b ×2 + AO2 ×2 + AO3a ×2)</h5><p>For each benefit: Understanding (1) + Application to Miles Ahead (1) + Analysis of business impact (1).</p><p><strong>Understanding may include:</strong> helps target specific customers; better meet customer needs; can design promotion to attract a specific group; can adjust product/range; can alter pricing strategy; avoids wasting money on broad advertising.</p><p><strong>Application may include:</strong> sole trader / 6 stores / no online sales / established 20+ years / declining customer satisfaction / declining sales revenue / currently segments via age, gender, lifestyle and income / Reg thinks it has been successful.</p><p><strong>Analysis may include:</strong> greater return on marketing expenditure / improved customer satisfaction / increased sales revenue / improved customer retention / improved brand reputation / increased market share / reduced risk of failure / increased profit.</p><p><strong>Do NOT accept</strong> ''more successful'' as an impact — this is stated in the text and is too vague.</p></div>"}, {"question": "State one way that BFF could segment its dance shoe market. [1 mark]", "marks": 1, "hint": "Just name one method of segmentation. No explanation needed. Think about the types of customers who buy dance shoes.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p>One mark for any valid segmentation criterion: Age / Type of dance shoe (e.g. ballet/tap) / Gender / Income / Location / Lifestyle.</p><p><strong>Do NOT award</strong> answers about advertising location — e.g. ''advertise on TV to children'' or ''advertise near a dance class'' or ''online''. Location refers to the customer characteristic (where they live), not where to advertise.</p></div>"}, {"question": "Which of the following is a benefit to a business of advertising on local radio?", "marks": 1, "hint": "Think about what is UNIQUE about LOCAL radio compared to other forms of advertising.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: A — Can target a specific geographical area.</strong></p><p>Local radio is listened to by people in a specific geographical area — this links directly to location-based segmentation. Option B is not possible on radio (audio only). Option C relates to in-store sampling. Option D relates to TV or video where the product can be visually demonstrated.</p></div>"}, {"question": "Explain how Ford Motors could use market segmentation when deciding where to place an advert for its new car models. [2 marks]", "marks": 2, "hint": "Understanding of how segmentation guides advertising placement (1) + Application to Ford using a specific example such as a car model, type of car, or customer group (1). The question is about WHERE to place the advert, not what the advert says.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1b + AO2)</h5><ul><li><strong>Understanding (1 mark):</strong> Use of market segmentation to target/direct advertising at the relevant group — e.g. advertise in a way that would appeal to the target market / direct adverts at specific customer groups.</li><li><strong>Application (1 mark):</strong> Apply to Ford — e.g. cars, vans, trucks, buses, names of models (KA, Fiesta, Focus, Mondeo, Galaxy), vehicles, eco-friendly small cars, family cars, sports cars, 7-seater people carriers.</li></ul><p>The best answers give a specific example, e.g. advertising people carriers on children''s TV channels, or sports cars in motoring magazines — though an example is not required for full marks. Do not accept ''model'' alone as application.</p></div>"}, {"question": "Explain one advantage to Boohoo of using market segmentation. [2 marks]", "marks": 2, "hint": "State one advantage of market segmentation (1 mark), then apply it specifically to Boohoo using details from the case study — target market, social media use, product range, global reach (1 mark).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a + AO2)</h5><ul><li><strong>Knowledge (1 mark):</strong> Identify an advantage — e.g. identify similar characteristics / target marketing more effectively / modify products/price/promotion/place to suit the segment / allocate budgets more efficiently / identify new segments.</li><li><strong>Application (1 mark):</strong> Apply to Boohoo — e.g. target market is 16–24 year olds / fashion conscious / active on social media / sells in 100+ countries / uses Facebook, Twitter, YouTube and Instagram / apps for smartphones and tablets.</li></ul><p><strong>Exemplar:</strong> Market segmentation makes it easier for a business to identify the characteristics of their customers (K) so Boohoo can target its products at those between 16 to 24 years old who are fashion conscious (APP).</p></div>"}, {"question": "Identify two methods by which a market might be segmented. [2 marks]", "marks": 2, "hint": "Simply name two different methods of segmentation. No explanation needed for this question.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a ×2)</h5><p>One mark for each correct method identified. Any two from: Age / Gender / Income / Location / Lifestyle.</p><p>No explanation required — this is an ''identify'' question.</p></div>"}, {"question": "Evaluate the benefit to Amala and her family of using market segmentation to help their business. [7 marks]", "marks": 7, "hint": "Structure: Two applied points using case study details (APP ×2) + Two impacts on the business (AN ×2) + A simple judgement — yes or no, do you think it will benefit them? (EVAL ×1) + A justified, contextual conclusion using the case study (EVAL ×2). Use the luxury vs. budget furniture range as your key application detail.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 7 marks (AO2 ×2 + AO3a ×2 + AO3b ×3)</h5><p><strong>Application (up to 2 marks):</strong> Two separate applied points using the case study — e.g. segmentation will help decide the income range at which to target the different garden furniture ranges (luxury thousands of pounds / budget under £100) / will help decide where to advertise each product range / will help identify who is buying which products.</p><p><strong>Analysis (up to 2 marks):</strong> Two business impacts — e.g. advertising will have a focus and so save the business money by only advertising where effective / more effective advertising will bring in more customers, increasing sales / sales have fallen so targeted marketing could reverse this decline.</p><p><strong>Evaluation — Judgement (1 mark):</strong> A simple statement e.g. ''I think market segmentation will be very effective in helping Amala''s family business.''</p><p><strong>Evaluation — Justification (up to 2 marks):</strong> A clear, contextual justification — e.g. The business makes a range of furniture from luxury sets costing thousands to sets under £100. It must identify who is buying the different products so those consumers can be targeted precisely. It is no good simply advertising all products in the same place — different products require different approaches, and clear segmentation will make advertising more focused and save money.</p></div>"}]}}'::jsonb),
('business', '2-4-1-introduction-marking-mix', '2.4.1 Marketing Mix: Introduction', '{"learn": {"enabled": true, "items": [{"title": "What is the Marketing Mix?", "html": "<p>The <strong>marketing mix</strong> is made up of different parts, often referred to as the <strong>4 Ps</strong>. These are:</p>\n      <ul>\n      <li><strong>Product:</strong> The good or service being sold (features, design, quality, packaging).</li>\n      <li><strong>Price:</strong> How much the customer pays for the product (pricing strategies).</li>\n      <li><strong>Place:</strong> How the product is distributed to the customer (shops, online, wholesalers).</li>\n      <li><strong>Promotion:</strong> How the business communicates with customers to encourage them to buy (advertising, special offers).</li>\n      </ul>\n      <p>A business must understand each one of these Ps and how they work together to help it successfully sell its products and services. The marketing mix is not a static plan; it must adapt and change as the market and consumer tastes change.</p>", "check": {"question": "Which four elements make up the marketing mix?", "options": ["Product, Price, Place, Promotion", "Product, Price, Planning, Profit", "Product, Positioning, Place, Promotion", "Packaging, Price, Place, Promotion"], "answer": 0, "explain": "The marketing mix is made up of the 4 Ps: Product, Price, Place, and Promotion."}}, {"title": "Market-Orientated vs Product-Orientated", "html": "<p>Before deciding on the 4 Ps, a business usually adopts one of two approaches:</p>\n      <p><strong>Market-orientated business:</strong> A business that bases its marketing mix entirely on sound market research. It finds out what the consumer wants <em>first</em>, and then designs a product to meet those needs. This approach is generally less risky.</p>\n      <p><strong>Product-orientated business:</strong> A business that focuses primarily on the creation and making of the product itself, rather than the needs of the market. They create a great product first and then try to find a market for it. This can be risky, but highly successful for innovative tech companies (e.g., the original Apple iPhone).</p>", "check": {"question": "Which approach involves a business researching what consumers want first, before designing the product?", "options": ["Sales-orientated", "Cost-orientated", "Product-orientated", "Market-orientated"], "answer": 3, "explain": "A market-orientated business bases its marketing mix on market research carried out before the product is designed, making it generally less risky."}}, {"title": "Case Study: The ''Big Four'' Supermarkets", "html": "<p>The ''big four'' supermarkets (Tesco, Sainsbury’s, Asda, and Morrisons) are in close competition. Each needs the right marketing mix to persuade shoppers to visit them rather than rivals.</p>\n      <ul>\n      <li><strong>Price:</strong> Customers often want cheap prices. Supermarkets constantly watch competitors to ensure they aren''t being beaten on price, often price-matching basic items.</li>\n      <li><strong>Product:</strong> They offer a wide range of goods (food, clothing, electricals) and specific ranges like ''Taste the Difference'' (Sainsbury’s) to appeal to different segments. Budget rivals like Aldi/Lidl have a smaller range, reducing overheads.</li>\n      <li><strong>Place:</strong> Providing choice in <em>where</em> to shop. Tesco ''Metro'' and Sainsbury’s ''Local'' cater to town centres, while massive superstores sit on the outskirts. Home delivery offers another vital distribution channel.</li>\n      <li><strong>Promotion:</strong> Spending millions on advertising to tell customers about new offers and stay one step ahead of the competition.</li>\n      </ul>", "check": {"question": "In the supermarkets case study, Tesco ''Metro'' and Sainsbury''s ''Local'' stores catering to town centres, alongside outskirt superstores and home delivery, illustrate which element of the marketing mix?", "options": ["Promotion", "Place", "Product", "Price"], "answer": 1, "explain": "Offering different store formats and delivery options is about distribution channels, which is the ''Place'' element of the marketing mix."}}, {"title": "How the 4 Ps Work Together (Integration)", "html": "<p>The 4 Ps cannot be planned in isolation; they are <strong>interdependent</strong>. If one changes, the others must often change to match it.</p>\n      <p>For example, if a business decides to create a highly innovative, premium quality item (<strong>Product</strong>), it will likely need to charge a high <strong>Price</strong> to cover expensive materials and portray a luxury image. It will need to distribute the item in high-end, exclusive locations (<strong>Place</strong>), and advertise in luxury magazines rather than cheap leaflets (<strong>Promotion</strong>).</p>\n      <p>If the mix is confused (e.g., a premium luxury product sold in a budget discount store), customers will be confused, and the product will likely fail.</p>", "check": {"question": "Why must the 4 Ps of the marketing mix be planned together rather than in isolation?", "options": ["Because customers only ever notice the Product and Price", "Because only Price and Promotion actually affect sales", "Because the law requires all four to be identical", "Because they are interdependent, changes affect the others"], "answer": 3, "explain": "The 4 Ps are interdependent — for example, a premium Product needs a high Price, exclusive Place, and upmarket Promotion to avoid confusing customers."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Marketing Mix", "definition": "The combination of Product, Price, Place, and Promotion used by a business to successfully sell its goods and services."}, {"term": "Product", "definition": "The good or service being sold, including its design, packaging, and features."}, {"term": "Price", "definition": "How much the customer pays for the product, based on costs, competitors, and target market."}, {"term": "Place", "definition": "The distribution channels used to deliver the product to the consumer (e.g., e-commerce, retail stores)."}, {"term": "Promotion", "definition": "The methods used to communicate with customers to raise awareness and persuade them to buy."}, {"term": "Market-orientated", "definition": "A business that bases its products on extensive market research to find out what consumers want first."}, {"term": "Product-orientated", "definition": "A business that focuses on making an excellent or innovative product first, then finding a market for it."}, {"term": "Interdependent Mix", "definition": "The concept that the 4 Ps must work together harmoniously. A change in one P usually requires a change in the others."}]}, "mcq": {"enabled": true, "questions": [{"question": "What is one of the ''four Ps'' of the marketing mix?", "options": ["Penetration", "Place", "Planning", "Profit"], "answer": 1, "explain": "Correct answer: The four Ps are Product, Price, Place, and Promotion. ''Penetration'' is a pricing strategy, not one of the main 4 Ps. ''Planning'' and ''Profit'' are general business terms."}, {"question": "An independent toy business is seeing fewer potential customers visit its shop. Which change to its marketing mix may help the business solve this problem?", "options": ["Introduce price skimming across the full range of toys", "Offer free superhero stickers and badges to all visitors", "Reduce the number of ''pre-school toy'' loss leaders offered", "Use digital distribution channels for outdoor toys"], "answer": 1, "explain": "Correct answer: Offering free stickers is a form of Promotion that acts as a draw to get footfall into the physical shop. Price skimming (A) would make toys more expensive, putting people off. Digital distribution (D) bypasses the shop entirely."}, {"question": "A furniture manufacturer''s marketing mix identifies:", "options": ["how to reduce risk when selling its furniture online", "the distribution channels for its tables and chairs", "the quantity of wood and materials to reorder", "which model of gaming chair customers prefer"], "answer": 1, "explain": "Correct answer: This question tests the understanding of ''Place'' within the marketing mix, which specifically refers to distribution channels (how the product gets from the manufacturer to the consumer)."}, {"question": "A publishing company''s marketing mix identifies:", "options": ["appropriate sources of market research", "digital distribution channels for its books", "how many short-story authors to interview", "which of its editors have training needs"], "answer": 1, "explain": "Correct answer: Similar to the furniture question, this targets the ''Place'' element of the marketing mix. Digital distribution is the modern ''Place'' for digital books and media."}, {"question": "A business is deciding on a marketing mix for its latest product. The product is innovative, of the highest quality, and expensive to produce. The marketing mix is most likely to also include:", "options": ["advertising aimed at low income customers", "placing the product for sale in high income locations", "promotion using free samples", "using social media to discuss the limitations of the product"], "answer": 1, "explain": "Correct answer: This tests how the 4 Ps work together. A premium, high-quality, expensive Product must be matched with an exclusive Place (high income locations) to reach the correct target market."}]}, "fib": {"enabled": true, "questions": [{"text": "The marketing mix is made up of four key parts, known as the 4 Ps: Product, [Price], Place, and [Promotion]."}, {"text": "A [market] orientated business relies heavily on market research, whereas a [product] orientated business focuses on the creation and design of the item itself."}, {"text": "In the marketing mix, ''Place'' does not just mean the physical shop; it refers to the [distribution] channels used to get the product to the [customer]."}, {"text": "All elements of the marketing mix must work [together] to be successful. For example, a premium product should have a [high] price."}]}, "tf": {"enabled": true, "questions": [{"statement": "The marketing mix consists of Planning, Product, Price, and Profit.", "answer": false, "explain": "FALSE. The 4 Ps of the marketing mix are Product, Price, Place, and Promotion."}, {"statement": "In the marketing mix, ''Place'' refers to the distribution channels used to get the product to the customer.", "answer": true, "explain": "TRUE. ''Place'' is about distribution (like physical shops, websites, or wholesalers), not the location of the factory."}, {"statement": "A market-orientated business develops a product first and then tries to find customers to buy it.", "answer": false, "explain": "FALSE. That describes a product-orientated business. A market-orientated business does market research first to find out what customers want before developing the product."}, {"statement": "If a business launches a highly premium, luxury product, it must ensure its Price, Place, and Promotion match that luxury image.", "answer": true, "explain": "TRUE. The 4 Ps must be integrated and work together to avoid confusing the target market."}]}, "misc": {"enabled": true, "items": [{"myth": "Students often think ''Place'' means the location where the product is manufactured (e.g., the factory).", "truth": "''Place'' refers specifically to DISTRIBUTION CHANNELS — how the product gets from the business to the consumer. This could be a physical retail shop, a wholesaler, or an e-commerce website.", "check": {"question": "What does ''Place'' actually refer to in the marketing mix?", "options": ["The head office address of the business", "The location where the product is manufactured", "The design of the shop window display", "The distribution channels reaching the consumer"], "answer": 3, "explain": "''Place'' means distribution channels — e.g. a physical shop, a wholesaler, or a website — not the factory where the product is made."}}, {"myth": "Students think the 4 Ps are chosen independently and don''t affect each other.", "truth": "The 4 Ps are highly INTERDEPENDENT. If you change your product to make it more luxurious, you must also change your price (increase it), place (exclusive shops), and promotion (high-end magazines) to match.", "check": {"question": "If a business makes its product more luxurious, what does the idea of an ''interdependent'' marketing mix suggest it should also do?", "options": ["Adjust price, place and promotion to match the new positioning", "Keep price, place and promotion exactly the same to save costs", "Only change promotion, since customers only respond to adverts", "Lower the price to attract more customers to the new product"], "answer": 0, "explain": "Because the 4 Ps are interdependent, making the product more luxurious means price, place and promotion must also change to match, e.g. a higher price and exclusive shops."}}, {"myth": "Students assume that a product-orientated business will always fail because they don''t do market research first.", "truth": "While riskier, product-orientated businesses can be massively successful if they create a highly innovative product that consumers didn''t even know they wanted yet (e.g., the first smartphones or early tech inventions).", "check": {"question": "Which statement about product-orientated businesses is most accurate?", "options": ["They are only ever used by budget supermarkets", "They always fail because they skip market research entirely", "They can never be profitable in the long term", "They can be highly successful with a truly innovative product"], "answer": 3, "explain": "Product-orientated businesses are riskier but can succeed spectacularly with highly innovative products, as seen with early smartphones."}}]}, "tips": {"enabled": true, "items": [{"title": "Tricks with ''Place''", "html": "<p>In multiple choice questions, examiners love testing your understanding of ''Place''.</p>\n      <p>Always remember: Place = <strong>Distribution Channels</strong>.</p>\n      <p>If you see options about factories, warehouses, or ordering raw materials, ignore them. Look for words like ''digital distribution'', ''retailers'', or ''wholesalers''.</p>", "check": {"question": "In a multiple-choice question about ''Place'', which type of answer option should you avoid selecting?", "options": ["Options describing retailers", "Options describing digital distribution channels such as websites", "Options describing wholesalers", "Options describing factories, warehouses or ordering raw materials"], "answer": 3, "explain": "Place = distribution channels, so factory, warehouse and raw-material options are distractors testing production, not distribution."}}, {"title": "Linking the Mix to the Target Market", "html": "<p>When devising a marketing mix, it must always link back to the <strong>target market</strong> (from Unit 2.3).</p>\n      <p>If an exam scenario says the target market is ''low-income teenagers'', every part of your suggested 4 Ps must match that demographic: low price, digital promotion (social media), modern design, and online/accessible place.</p>", "check": {"question": "If an exam case study describes the target market as ''low-income teenagers'', what should your suggested marketing mix include?", "options": ["A low price, digital promotion, and accessible place", "A high price and exclusive, luxury store locations", "Premium packaging with print magazine adverts only", "A focus on Price alone, ignoring the other three Ps"], "answer": 0, "explain": "Every part of the 4 Ps must link back to the target market, so ''low-income teenagers'' calls for low price, digital promotion, and accessible place."}}, {"title": "Creating a Marketing Mix", "html": "<p>For high tariff questions, you may be asked to evaluate a proposed marketing mix or recommend one.</p>\n      <p>To score top marks, you must explicitly state how the parts of the mix <strong>work together</strong>. Don''t just list a price and a promotion separately. Explain <em>why</em> that specific price supports that specific promotion method.</p>", "check": {"question": "To achieve top marks in a high-tariff (9 mark) question evaluating a marketing mix, what must you explicitly do?", "options": ["Explain how the mix''s parts work together, not separately", "Describe the business''s history and background", "Focus only on describing the Product element in detail", "List as many possible prices and promotions as you can"], "answer": 0, "explain": "Top marks require explicitly explaining why a specific price supports a specific promotion, showing the mix works together rather than just listing the Ps separately."}}]}, "exam": {"enabled": true, "questions": [{"question": "A business is deciding on a marketing mix for its latest product. The product is innovative, of the highest quality, and expensive to produce. The marketing mix for this business is most likely to also include:", "marks": 1, "hint": "Think about how the 4 Ps work together. If the ''Product'' is high quality and expensive, what must the ''Place'' be?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B</strong></p><p>This tests the student''s ability to see how ''Product'' directly influences ''Place'' and target market. A premium product requires a premium location.</p></div>"}, {"question": "Explain how Beth could ensure that the ''Price'' and ''Place'' elements of her marketing mix work together. [3 marks]", "marks": 3, "hint": "This requires you to link two of the Ps. Since she wants a premium/high-quality image, what should her price be? And what should the ''Place'' (the soft play centre itself and its location) look like to justify that price?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Explaining the concept of the mix working together (e.g., matching a high price with a high-quality location).</li><li><strong>Application (1 mark):</strong> Applying to Beth''s soft play (e.g., targeting children 2-12 / competing with a rundown centre / wanting a premium, clean alternative).</li><li><strong>Analysis (1 mark):</strong> The impact on the business (e.g., justifies the higher price to parents / ensures customers aren''t confused / creates a strong brand image).</li></ul></div>"}]}}'::jsonb),
('business', '2-4-2-product-and-product-life', '2.4.2 Product & Product Life Cycle', '{"learn": {"enabled": true, "items": [{"title": "The Importance of Product & Adding Value", "html": "<p><strong>Product</strong> is a vital part of the marketing mix. A product is a good or a service that is sold to customers or other businesses to meet a need. Businesses will always try to supply products that customers will want to buy, at a price at which the business can make the required profit.</p>\n      <p>Businesses generally operate under one of two orientations:</p>\n      <ul>\n      <li><strong>Market Orientation:</strong> The business focuses on the market. It responds to customer needs and wants through market research before developing the product.</li>\n      <li><strong>Product Orientation:</strong> The business focuses on the products. It develops goods based on what it is good at doing, creating the product first and finding a market later.</li>\n      </ul>\n      <p><strong>Ways to Add Value to a Product or Service (Product Differentiation):</strong></p>\n      <p>To stand out from rivals, a business must differentiate its product. This can be done by:</p>\n      <ul>\n      <li><strong>Branding:</strong> Establishing a strong brand image.</li>\n      <li><strong>Design:</strong> Making the product look stylish or function better.</li>\n      <li><strong>Quality:</strong> Using better materials or offering superior durability.</li>\n      <li><strong>Selling Point:</strong> Making clear the Unique Selling Point (USP).</li>\n      <li><strong>Convenience:</strong> Offering a better location or easier usability than rival products.</li>\n      </ul>", "check": {"question": "A business that designs goods based on what it is good at making, then looks for a market afterwards, is showing which orientation?", "options": ["Product orientation", "Price orientation", "Market orientation", "Promotion orientation"], "answer": 0, "explain": "Product orientation means the business focuses on the product first, creating it before finding a market, unlike market orientation which starts with customer research."}}, {"title": "Invention, Design, and Innovation", "html": "<p>Technology plays a massive role in product development. Businesses spend large sums of money on <strong>Research and Development (R&D)</strong> to stay ahead of the competition.</p>\n      <ul>\n      <li><strong>Invention:</strong> When a business comes up with a completely new product, service, or feature that has never existed before (e.g., the creation of the internet itself).</li>\n      <li><strong>Innovation:</strong> When a business improves on an existing product or idea, often using new processes or technology (e.g., developing internet banking from traditional banking).</li>\n      <li><strong>Design:</strong> When a business plans what a product will do (its function) and what it will look like (its style). Design is critical in markets like mobile phones and fashion.</li>\n      </ul>\n      <div class=\"case-study-box\">\n      <h4>Case Study: Dyson — From Vacuum to Strawberries</h4>\n      <p>When James Dyson became unhappy about the efficiency of bagged vacuum cleaners in the 1970s, he decided to do something about it. After spending a lot of time on invention, design and innovation, he came up with the Dual Cyclone style vacuum cleaner we are familiar with today. He built many different versions before it was ready to be sold.</p>\n      <p>The vacuum cleaner side of the business saw further innovation and design changes with the introduction of the Dyson ''Ball'' upright cleaner and cordless ranges. Not content with a narrow range, Dyson designed a new style of hand dryers, hair straighteners, and air purifiers. It even uses its technological know-how to grow strawberries at its Dyson Farming operation in Lincolnshire! Dyson is an excellent example of a business continually developing its product range to meet consumer needs.</p>\n      </div>", "check": {"question": "Dyson developing internet banking-style improvements to an already-existing product, such as upgrading a vacuum cleaner to a cordless version, is best described as:", "options": ["Innovation", "Invention", "Market orientation", "Extension pricing"], "answer": 0, "explain": "The card defines innovation as improving an existing product or idea using new processes or technology, whereas invention means creating something completely new that never existed before."}}, {"title": "Branding and Image", "html": "<p><strong>Branding</strong> is closely linked to design and image. How a customer feels about owning a product is a powerful marketing tool (e.g., the prestige of owning an exclusive sports car).</p>\n      <p>Many companies do not even need to put their name on a product — we know the make simply by a symbol, known as a <strong>trade mark</strong> (e.g., the Nike swoosh or Apple logo). We understand from that symbol that this ''brand'' has a certain quality. It may be high quality or a lower quality ''budget'' standard, but the consumer knows exactly what to expect. This works well in fast food too; brand names like KFC or McDonald''s give customers a clear idea of the standard of product they are buying.</p>\n      <p><strong>Activity 7: Marketing Considerations</strong><br>\n      <em>When marketing a mobile phone vs a waste-paper bin, what is most important? Price, design, image, or brand?</em><br>\n      <strong>Answer:</strong> This is highly subjective. A waste-paper bin might compete primarily on price and basic design. However, a mobile phone relies heavily on brand and image (e.g., Apple vs Samsung), followed by innovative design. It highlights that a business must carefully choose which element of the mix to concentrate on based on the product type.</p>", "check": {"question": "A symbol such as the Nike swoosh, which lets customers recognise a make and its quality without the company name being shown, is known as a:", "options": ["Extension strategy", "Trade mark", "Market segment", "USP statement"], "answer": 1, "explain": "The card explains that a trade mark is a symbol customers associate with a brand''s quality, even without the company name appearing on the product."}}, {"title": "The Product Life Cycle (PLC)", "html": "<p>Most products have a time span over which consumers will want them. This is called the <strong>product life cycle</strong>. It is shown as a graph mapping Sales against Time. The graph is split into four key stages:</p>\n      <ol>\n      <li><strong>Introduction:</strong> The product is new and just launched. Sales are just beginning. Advertising is usually very high to make customers aware of the product.</li>\n      <li><strong>Growth:</strong> Sales grow quickly as the product becomes well-known. There is no need for special offers because demand is high.</li>\n      <li><strong>Maturity:</strong> Sales reach their peak and level off. The rate of growth is slowing down. It may be necessary to support the product with further advertising and offers to maintain sales against competitors.</li>\n      <li><strong>Decline:</strong> Sales begin to fall. Customers see the product as old and switch to newer alternatives. A successful business should already have a replacement product ready.</li>\n      </ol>\n      <p><strong>Activity 10 & 11: Real World Life Cycles</strong><br>\n      <em>Desktop Computers:</em> Maturity/Decline (replaced by tablets/laptops).<br>\n      <em>Denim Jeans:</em> Maturity (they go on forever, only the cut changes).<br>\n      <em>iPhone 12:</em> Growth/Maturity (short life cycle, replaced quickly).<br>\n      <em>Chart Single:</em> Extremely short life cycle (peaks and declines in weeks).<br>\n      <em>Dairy Milk Bar:</em> Exceptionally long maturity stage spanning decades.</p>", "check": {"question": "During which stage of the Product Life Cycle is advertising usually at its highest, to make customers aware a product exists?", "options": ["Growth", "Maturity", "Introduction", "Decline"], "answer": 2, "explain": "The card states that in the Introduction stage the product is new and just launched, so advertising is usually very high to build awareness."}}, {"title": "Extending the Product Life Cycle", "html": "<p>The highest level of sales is at the end of growth and into maturity. Businesses try to keep sales at this high level for as long as possible using <strong>Extension Strategies</strong>:</p>\n      <ul>\n      <li><strong>Advertising:</strong> Claiming the product is \"new and improved\" or using modern packaging.</li>\n      <li><strong>Price Reductions:</strong> Lowering the price to make the product more attractive.</li>\n      <li><strong>New Markets:</strong> Exporting the product to countries where it is still in the ''introduction'' phase.</li>\n      <li><strong>New Features/Uses:</strong> Adding new flavours, features, or targeting a different demographic.</li>\n      </ul>\n      <div class=\"case-study-box\">\n      <h4>Activity 13: Rice Krispies Case Study</h4>\n      <p>Since it started in 1928, Kellogg’s Rice Krispies has been a breakfast favourite. It is currently in a very long <strong>Maturity</strong> stage. Kellogg''s extended its life cycle by developing the product to include new flavours (strawberry/banana) and creating new uses, such as Rice Krispies cereal bars for the ''on-the-go'' snack market. The Kellogg''s brand name was vital to this success, allowing them to sell different products based on a known, trusted formula.</p>\n      </div>", "check": {"question": "Kellogg''s creating Rice Krispies cereal bars for the ''on-the-go'' snack market, alongside its original cereal, is an example of which extension strategy?", "options": ["Price reduction", "New features/uses", "New markets", "Market orientation"], "answer": 1, "explain": "The card lists ''New Features/Uses'' as an extension strategy, and the Rice Krispies bars are given as the example of adding a new use to reach the snack market."}}, {"title": "Uses and Limitations of the Product Life Cycle", "html": "<div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Uses of the PLC</div>\n      <div class=\"pro-item\">Identifies exactly when to introduce <strong>extension strategies</strong> (e.g., right before decline).</div>\n      <div class=\"pro-item\">Helps a business know when to change its <strong>marketing spending</strong> (e.g., heavy advertising in Introduction, less in Growth).</div>\n      <div class=\"pro-item\">Identifies when a product should finally be <strong>discontinued</strong> or replaced.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Limitations of the PLC</div>\n      <div class=\"con-item\"><strong>Ignores Competitors:</strong> It doesn''t consider what rival businesses are doing, which can prematurely end a product''s life.</div>\n      <div class=\"con-item\"><strong>Unpredictable Trends:</strong> It cannot predict sudden shifts in social trends or changes in consumer taste.</div>\n      <div class=\"con-item\"><strong>Not a Guarantee:</strong> Past performance on a graph is not always a reliable indicator of future performance.</div>\n      </div>\n      </div>\n      <p><strong>Evaluation Point:</strong> It is very difficult for a business to judge the right time to replace a product. Car manufacturers face massive R&D costs to launch a new model (every 5-6 years), so they rely heavily on extending the life cycle. However, in fast-paced tech markets (phones, computers), businesses put much less effort into extension strategies and instead focus on constantly innovating the next replacement model.</p>", "check": {"question": "A key limitation of the Product Life Cycle model is that it:", "options": ["Always predicts decline within one year", "Cannot be shown as a graph", "Only applies to services, not goods", "Ignores what rival businesses are doing"], "answer": 3, "explain": "The card lists ''Ignores Competitors'' as a limitation, since the PLC doesn''t consider rival actions that can prematurely end a product''s life."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Product Life Cycle (PLC)", "definition": "The stages a product goes through from its introduction to its eventual decline (Introduction, Growth, Maturity, Decline)."}, {"term": "Invention", "definition": "The creation of a totally new product or service that has never existed before."}, {"term": "Innovation", "definition": "Improving an existing product, often using new processes or technology (e.g., adding smart sensors to a toothbrush)."}, {"term": "Design", "definition": "Planning what a product will do (function) and what it will look like (style)."}, {"term": "Extension Strategy", "definition": "Methods used to prolong the maturity stage of a product and prevent decline (e.g., new packaging, lower prices, new features)."}, {"term": "Market Orientation", "definition": "Developing products based on extensive market research to find out exactly what the consumer wants first."}, {"term": "Product Orientation", "definition": "Developing a product based on what the business is good at making, and then trying to find a market for it."}, {"term": "Limitation of the PLC", "definition": "It does not consider external factors like sudden competitor actions or rapid changes in social trends."}]}, "mcq": {"enabled": true, "questions": [{"question": "The second stage in the product life cycle is:", "options": ["Maturity", "Introduction", "Decline", "Growth"], "answer": 3, "explain": "Correct answer: The four stages are Introduction, Growth, Maturity, and Decline. Therefore, Growth is the second stage."}, {"question": "Product innovation is concerned with:", "options": ["changing the colour of a product", "developing new features in a product that have not been seen before", "selling the product at a lower price than competitors", "making sure a competitor does not copy your product"], "answer": 1, "explain": "Correct answer: Innovation is the improvement on an existing idea, often involving new processes or features that enhance the product."}, {"question": "Which of the following would NOT be used to extend the product life cycle of a product?", "options": ["Bring out a new product", "Increase the advertising", "Decrease the price", "Offer additional features free of charge"], "answer": 0, "explain": "Correct answer: Bringing out a completely new product replaces the old one; it does not extend the life cycle of the *existing* product. Options B, C, and D are all valid extension strategies."}, {"question": "Innovation in a product is best described as:", "options": ["devising a better product by changing an existing product", "looking at a product and designing a completely new product", "designing and building a new technology product from scratch", "making sure your product is made as well as competitors'' products"], "answer": 0, "explain": "Correct answer: Innovation means taking something that already exists and making it better. Designing from scratch is ''Invention''."}, {"question": "Invention involves:", "options": ["behaving dishonestly", "creating new products", "developing existing products", "discrimination in the workplace"], "answer": 1, "explain": "Correct answer: Invention is the creation of a totally new product or service. Developing existing products is ''innovation''."}, {"question": "What is the final stage of the product life cycle?", "options": ["Decline", "Delegation", "Distribution", "Diversification"], "answer": 0, "explain": "Correct answer: The final stage is Decline, where sales fall as customers switch to newer alternatives."}, {"question": "A business is deciding on a marketing mix for its latest product. The product is innovative, of the highest quality, and expensive to produce. The marketing mix is most likely to also include:", "options": ["advertising aimed at low income customers", "placing the product for sale in high income locations", "promotion using free samples", "using social media to discuss the limitations of the product"], "answer": 1, "explain": "Correct answer: A premium, innovative product must be matched with an exclusive ''Place'' (distribution channel) to reach the correct target market and justify the high price."}]}, "fib": {"enabled": true, "questions": [{"text": "The product life cycle is divided into [four] parts and shows the [life] of a product measured against time."}, {"text": "The first stage is called [introduction] and is where the product is new. Advertising is often [high] at this stage to make sure customers are aware of it."}, {"text": "The next stage is [growth] where the product is becoming well-known and sales rise rapidly."}, {"text": "When the product reaches [maturity], sales are at their highest, though sales growth is [slowing]."}, {"text": "The final stage is [decline] where sales are falling and a business might be thinking of introducing a [replacement] product."}]}, "tf": {"enabled": true, "questions": [{"statement": "Innovation means inventing a completely new product from scratch.", "answer": false, "explain": "FALSE. Invention is creating something from scratch. Innovation is improving an existing product."}, {"statement": "The product life cycle shows the sales of a product measured against time.", "answer": true, "explain": "TRUE. The Y-axis is Sales and the X-axis is Time."}, {"statement": "A product at the maturity stage is experiencing its fastest rate of sales growth.", "answer": false, "explain": "FALSE. The fastest rate of sales growth happens in the ''Growth'' stage. In Maturity, sales are at their highest total volume, but the *rate of growth* has slowed down and leveled off."}, {"statement": "Decreasing the price of a product is a common extension strategy.", "answer": true, "explain": "TRUE. Lowering the price can attract budget-conscious customers and help maintain sales, extending the maturity stage."}, {"statement": "The product life cycle accurately predicts what competitors will do in the future.", "answer": false, "explain": "FALSE. One of the main limitations of the PLC is that it ignores external factors, including competitor actions and changing social trends."}]}, "misc": {"enabled": true, "items": [{"myth": "Students often confuse Invention and Innovation.", "truth": "INVENTION is creating something totally new from scratch that didn''t exist before. INNOVATION is taking an existing product and making it better (e.g., adding a camera to a mobile phone).", "check": {"question": "Adding a camera to an already-existing mobile phone is an example of which concept?", "options": ["Innovation", "Invention", "Market orientation", "Extension pricing"], "answer": 0, "explain": "Innovation means improving an existing product, unlike invention, which means creating something totally new from scratch."}}, {"myth": "Students think the Product Life Cycle can perfectly predict the future.", "truth": "The PLC is just a model based on past data. It cannot predict sudden changes in consumer tastes, sudden technological breakthroughs by competitors, or economic crashes. It is a guide, not a crystal ball.", "check": {"question": "Why can the Product Life Cycle not be relied upon to perfectly predict a product''s future sales?", "options": ["It only applies to products sold internationally", "It is updated automatically by competitors'' data", "It is only a model based on past data", "It only measures profit, not sales"], "answer": 2, "explain": "The card explains the PLC is a guide based on past data, not a crystal ball, so it cannot predict sudden changes in tastes, competitor breakthroughs, or economic crashes."}}, {"myth": "Students think all products go through the decline stage quickly.", "truth": "Some products stay in the Maturity stage for decades (e.g., Coca-Cola, Kellogg''s Cornflakes, Denim Jeans) because of excellent extension strategies and brand loyalty. Not everything declines rapidly like a smartphone.", "check": {"question": "Products like Coca-Cola and Denim Jeans staying in the Maturity stage for decades shows that:", "options": ["Decline is impossible once a brand becomes well known", "All products follow an identical life cycle length", "Strong brands like these can extend maturity for decades", "Maturity always lasts exactly as long as Introduction"], "answer": 2, "explain": "The card corrects the misconception that all products decline quickly, showing that strong extension strategies and brand loyalty can keep products in maturity for decades."}}]}, "tips": {"enabled": true, "items": [{"title": "Reading PLC Graphs", "html": "<p>Examiners frequently use graphs to test the Product Life Cycle.</p>\n      <ul>\n      <li>If the ''X'' is on the first small upward slope $\rightarrow$ <strong>Introduction</strong>.</li>\n      <li>If the ''X'' is on the steepest upward curve $\rightarrow$ <strong>Growth</strong>.</li>\n      <li>If the ''X'' is at the very top (the peak) or on a flat plateau $\rightarrow$ <strong>Maturity</strong>.</li>\n      <li>If the ''X'' is on the downward slope $\rightarrow$ <strong>Decline</strong>.</li>\n      </ul>", "check": {"question": "On a Product Life Cycle graph, if a marked point ''X'' sits on a flat plateau at the very top of the curve, which stage does it show?", "options": ["Introduction", "Growth", "Maturity", "Decline"], "answer": 2, "explain": "The exam tip states that an ''X'' at the peak or on a flat plateau of the graph represents the Maturity stage."}}, {"title": "Analysing Extension Strategies", "html": "<p>If asked to analyse how a business extended a product''s life cycle (e.g., Lego or Kellogg''s), follow the chain of reasoning:</p>\n      <p><strong>Identify the method</strong> (e.g., introducing new movie-themed characters) $\rightarrow$ <strong>Apply to the business</strong> (Lego Harry Potter sets) $\rightarrow$ <strong>Business Impact</strong> (Attracts a new target market, increasing sales revenue and reversing the decline).</p>", "check": {"question": "For a 3-mark ''analyse'' question on extending a product''s life cycle, what is the correct chain of reasoning to follow?", "options": ["List every extension strategy without applying any to the business", "Describe the product''s price only", "Identify the method, apply it to the business, then explain why", "State the definition, give one example, then stop"], "answer": 2, "explain": "The exam tip sets out the chain: identify the method, apply it to the named business, then explain the business impact, using Lego Harry Potter sets as the worked example."}}, {"title": "Evaluating the Usefulness of the PLC", "html": "<p>When evaluating if a business should use the PLC to plan marketing (like the Ford Motors 7-mark question), you must provide a balanced argument.</p>\n      <p><strong>Pro:</strong> Helps them know exactly when to spend money on advertising or when to reduce prices.</p>\n      <p><strong>Con:</strong> It ignores external factors. A competitor might release a revolutionary car, making Ford''s car enter ''decline'' years earlier than the graph predicted.</p>", "check": {"question": "In the balanced argument for evaluating whether a business like Ford should rely on the PLC to plan marketing, what is given as the main ''con''?", "options": ["It costs too much money to draw the graph", "It only works for service businesses, not manufacturers", "It ignores external factors, like a rival''s new product", "It cannot be used alongside extension strategies"], "answer": 2, "explain": "The exam tip''s ''Con'' point states the PLC ignores external factors, such as a competitor''s revolutionary car pushing a product into decline earlier than the graph predicted."}}]}, "exam": {"enabled": true, "questions": [{"question": "Analyse one way in which product innovation is important to Oral B. [3 marks]", "marks": 3, "hint": "State what innovation is (U), apply it to Oral B''s specific toothbrush technology (APP), and state the impact on their revenue or ability to compete with Phillips (AN).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Understanding (1 mark):</strong> Shows understanding of innovation e.g., putting new features on a product / changing the design to make it more appealing.</li><li><strong>Application (1 mark):</strong> Explanation relating to the case study e.g., applying smart modes/pressure sensors/Bluetooth to the toothbrush / keeping ahead of competitors such as Phillips.</li><li><strong>Analysis (1 mark):</strong> Impact on the business e.g., If Oral B does not innovate and competitors like Phillips do, sales may be lost resulting in a drop in revenue. OR It appeals to a different range of consumers (tech lovers), widening the customer base.</li></ul></div>"}, {"question": "Explain one reason why Oral B has a range of different electric toothbrushes. [2 marks]", "marks": 2, "hint": "Why would a business not just sell ONE type of toothbrush? Think about the different budgets of their customers.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks</h5><ul><li><strong>Understanding (1 mark):</strong> Shows understanding of the need for a product range e.g., it will appeal to a wider target market / spreads risk if one product fails.</li><li><strong>Application (1 mark):</strong> Relates to case study e.g., Oral B needs a range because different consumers have different amounts of money to spend on an electric toothbrush (cheaper models vs the 10x more expensive iO model).</li></ul></div>"}, {"question": "Explain one way in which the type of products that Oral B make will possibly affect their product life cycle. [2 marks]", "marks": 2, "hint": "Think about the technology market. Do tech products last for 20 years without changing, or are they replaced quickly?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks</h5><ul><li><strong>Understanding (1 mark):</strong> Shows understanding of the product life cycle e.g., it is divided into four stages (introduction to decline) / shows the lifespan of a product.</li><li><strong>Application (1 mark):</strong> Relates to case study e.g., Products such as high-tech electric toothbrushes often have a short life cycle as they will be replaced by changing technology very fast.</li></ul></div>"}, {"question": "Analyse how Lego has managed to extend the life cycle of its bricks beyond the periods of decline in the 1990s. [3 marks]", "marks": 3, "hint": "State the method Lego used to extend the life cycle (U). Apply it using the Harry Potter/film examples (APP). State the impact on the business''s success (AN).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Understanding (1 mark):</strong> Identifies a valid extension strategy (e.g., bringing out new product variations / entering new markets).</li><li><strong>Application (1 mark):</strong> Uses context from the case study (e.g., introducing models based on Harry Potter / creating a Lego film and board game).</li><li><strong>Analysis (1 mark):</strong> Business impact (e.g., attracts a new audience of movie fans, successfully reversing the decline in sales and leading to very high profits).</li></ul></div>"}, {"question": "Analyse one disadvantage to Ford Motors of manufacturing and selling such a large range of products. [3 marks]", "marks": 3, "hint": "Think about the costs or the complexity of managing so many different cars. Structure: State the disadvantage (U) -> Apply to Ford (APP) -> State the business impact (AN).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Disadvantage e.g., Increased workload / more difficult to coordinate / diseconomies of scale / higher advertising costs.</li><li><strong>Application (1 mark):</strong> Reference to cars, vans, trucks, buses, names of models (Fiesta, Focus). Do not accept just the word ''model''.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact e.g., decreases profit margins, cash flow difficulties, loss of focus causing poor quality.</li></ul></div>"}, {"question": "Evaluate whether or not Ford Motors should continue to use the product life cycle when planning the marketing of its products. [7 marks]", "marks": 7, "hint": "Provide an advantage of using the PLC (applied to Ford + analyzed). Provide a disadvantage of using the PLC (applied to Ford + analyzed). Give a final judgment with a justified reason.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 7 marks (AO2x2 + AO3ax2 + AO3bx3)</h5><ul><li><strong>Application (2 marks):</strong> Uses context e.g., cars, vans, models, vehicles.</li><li><strong>Analysis (2 marks):</strong> Positive impact (e.g., indicates when to change marketing spend). Negative impact (e.g., does not consider competitor activities, past performance doesn''t guarantee future).</li><li><strong>Evaluation (3 marks):</strong> A justified contextual decision on whether Ford should continue using it.</li></ul></div>"}, {"question": "Write a report recommending how Matt should develop his product mix. You should evaluate:\n1) How he can extend the life of his current products.\n2) Whether he should introduce new products/services.\n3) Whether he should switch to well-known brand names. [9 marks]", "marks": 9, "hint": "This is a comprehensive product strategy question. Address all three points with clear business analysis. Remember he targets 14-18 year olds, runs a *small* business, and faces seasonal/fashion changes.", "markScheme": "<div class=\"marks-section\"><h5>Activity 5 / 9-Mark Adaptation</h5><p><strong>Point 1 (Extension):</strong> Matt could extend the life of a product by concentrating on staple fashion items like jeans which have all-year-round appeal. Highly seasonal clothing has very little scope for extension other than heavy price reductions.</p><p><strong>Point 2 (New Products):</strong> Jewellery and accessories are less seasonal and don''t go out of fashion as quickly as clothing. This diversifies his risk.</p><p><strong>Point 3 (Branding):</strong> As a small business, competing with large stores selling premium brands is difficult and expensive. He should stick to budget brands or buy ''end-of-line'' branded stock to sell at a discount.</p></div>"}]}}'::jsonb),
('business', '2-4-3-pricing-methods', '2.4.3 Pricing Methods', '{"learn": {"enabled": true, "items": [{"title": "The Importance of Price", "html": "<p>A business must take great care when deciding what price to charge for a product or service. Price is the only part of the marketing mix that directly generates <strong>revenue</strong>.</p>\n      <p>Most consumers take notice of the price. If a business sets a price too high, sales will fall. If it sets a price too low, it will not make the profits needed for investment and to reward shareholders. The price must also be consistent with the other 3 Ps (Product, Place, Promotion) as it affects the consumer''s perception of the good or service.</p>\n      <p><strong>Main factors that influence pricing decisions:</strong></p>\n      <ul>\n      <li>Costs (a business must cover its costs to survive)</li>\n      <li>Competitors'' prices</li>\n      <li>The Product Life Cycle (prices change as products age)</li>\n      <li>Market Share objectives</li>\n      <li>Positioning and Brand Image</li>\n      </ul>", "check": {"question": "Which part of the marketing mix is the only one that directly generates revenue for a business?", "options": ["Price", "Promotion", "Place", "Product"], "answer": 0, "explain": "Price is the only element of the 4Ps that directly brings money into the business; Product, Place and Promotion all involve costs."}}, {"title": "Cost-Plus Pricing", "html": "<p><strong>Cost-plus pricing</strong> is a method where the business looks at the total cost of manufacturing a product and then adds a percentage of profit (the ''mark-up'' or ''plus'' part) to arrive at the selling price.</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">A profit is guaranteed on each item sold (providing enough items are sold).</div>\n      <div class=\"pro-item\">It is a relatively simple and easy way to set a price.</div>\n      <div class=\"pro-item\">Owners are in full control of the profit margin achieved.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">Ignores external factors like competitor prices or customers'' willingness to pay.</div>\n      <div class=\"con-item\">If the mark-up is set too high, the price may be expensive compared to rivals, leading to lost sales.</div>\n      <div class=\"con-item\">If costs fluctuate frequently, the selling price may have to continually change.</div>\n      </div>\n      </div>", "check": {"question": "What is the main disadvantage of cost-plus pricing?", "options": ["It cannot be calculated by small businesses", "It ignores competitor prices and what customers will pay", "It always results in lower profit margins than skimming", "It never guarantees a profit on items sold"], "answer": 1, "explain": "Cost-plus pricing only considers internal costs plus a mark-up, so it ignores external factors such as competitors'' prices."}}, {"title": "Competitor Pricing", "html": "<p><strong>Competitor pricing</strong> (or competitive pricing) is used when there is a lot of competition selling the same or similar products. A business will look at what other competitors charge and charge the same (or very slightly less).</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">Selling prices are in line with rivals, so it should attract customers and prevent them from switching brands.</div>\n      <div class=\"pro-item\">Helps a business survive in a highly crowded and established market.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">Because price is the same as rivals, the business must find other (often expensive) ways to attract customers, like better customer service or more promotion.</div>\n      <div class=\"con-item\">The business must constantly research competitors'' prices, which increases administrative costs.</div>\n      </div>\n      </div>", "check": {"question": "A major disadvantage of competitor pricing is that a business...", "options": ["must always price below all rivals", "must find other costly ways to attract customers", "will automatically dominate the market", "can no longer make any profit on its products"], "answer": 1, "explain": "Because the price matches rivals, the business must compete on non-price factors like customer service or promotion, as the card''s disadvantages note."}}, {"title": "Penetration Pricing", "html": "<p><strong>Penetration pricing</strong> is used when a business is new to a crowded market. They price their products <em>below</em> that of competitors to ''penetrate'' or break into the market and tempt consumers away from established brands. Once established, the price is raised. It is a short-term strategy.</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">Cash flow and market share improve quickly as sales increase rapidly.</div>\n      <div class=\"pro-item\">Can lead to loyal customers who trial the product because of the low price and stick with it.</div>\n      <div class=\"pro-item\">Helps develop long-term profitability through higher market share.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">In the short term, it is likely to result in lower profits (or even a loss) compared to if prices were higher.</div>\n      <div class=\"con-item\">It can be difficult to raise the selling price in the future without upsetting customers.</div>\n      </div>\n      </div>", "check": {"question": "Penetration pricing involves setting a price that is...", "options": ["above competitors to signal premium quality", "below rivals to enter a crowded market, then raised", "below cost permanently to eliminate all rivals", "identical to competitors to avoid losing customers"], "answer": 1, "explain": "Penetration pricing means pricing below rivals to ''penetrate'' a crowded market, with the price raised once the business is established."}}, {"title": "Price Skimming", "html": "<p><strong>Price skimming</strong> (sometimes called ''creaming'') is used when a business introduces a new, unique, or highly technical product that is clearly superior to competitors. The business sets a very <em>high</em> price initially because early adopters are willing to pay a premium. The price drops later as competitors enter the market.</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">Generates higher profits and revenues straight away, helping to quickly recover high Research & Development (R&D) costs.</div>\n      <div class=\"pro-item\">Gives the product a perceived brand image of high quality and exclusivity.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">Cannot last long as the high profits will quickly attract competitors to create rival products.</div>\n      <div class=\"con-item\">Sales volume is slower because the product is expensive and many customers cannot afford it.</div>\n      </div>\n      </div>", "check": {"question": "Price skimming is most suitable for a business that has...", "options": ["identical products to lots of competitors", "an old product it needs to clear from stock", "a product aimed at very price-sensitive customers", "a new, highly technical product facing no rivals yet"], "answer": 3, "explain": "The card explains skimming is used when a business introduces a new, unique or highly technical product clearly superior to competitors."}}, {"title": "Promotional Pricing & Loss Leaders", "html": "<p><strong>Promotional pricing</strong> is a reduction in price used for a short period to attract customers, boost falling sales, or get rid of old stock (e.g., in a sale).</p>\n      <p>A specific type of promotional pricing is a <strong>Loss Leader</strong>, where a product is deliberately sold at a price below its cost to make.</p>\n      <div class=\"two-col\">\n      <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\">Attracts footfall into a shop or visitors to a website.</div>\n      <div class=\"pro-item\">Customers who come for the cheap promotional item will hopefully buy other, full-priced, highly profitable products while they are there.</div>\n      <div class=\"pro-item\">Clears out old inventory to make room for new product lines.</div>\n      </div>\n      <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\">If customers <em>only</em> buy the loss leader item, the business will make a financial loss.</div>\n      <div class=\"con-item\">Customers may get used to the cheap prices and refuse to buy the product when it returns to full price.</div>\n      <div class=\"con-item\">Too many sales can damage the brand''s reputation and premium image.</div>\n      </div>\n      </div>", "check": {"question": "What defines a ''loss leader''?", "options": ["The best-selling product in a shop", "A product sold below cost to draw customers into the shop", "A product sold at exactly its cost price to break even", "Any product included in a seasonal sale"], "answer": 1, "explain": "The card defines a loss leader as a product deliberately sold at a price below its cost to make, hoping customers buy other profitable items too."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Cost-Plus Pricing", "definition": "Calculating the total cost of making a product and adding a percentage profit mark-up to determine the selling price."}, {"term": "Competitor Pricing", "definition": "Setting the price of a product based on what rivals are charging for similar products in a crowded market."}, {"term": "Penetration Pricing", "definition": "Setting a low initial price to break into a competitive market and gain market share quickly, before raising the price later."}, {"term": "Price Skimming", "definition": "Setting a high initial price for a highly innovative or unique product to maximize profits, before dropping it when competitors enter."}, {"term": "Promotional Pricing", "definition": "A temporary reduction in price to boost sales, attract customers, or clear out old inventory."}, {"term": "Loss Leader", "definition": "A product deliberately sold below its cost price to attract customers, hoping they will buy other profitable items."}, {"term": "Disadvantage of Competitor Pricing", "definition": "The business must compete on non-price factors (like advertising or customer service) which can increase costs."}, {"term": "Disadvantage of Cost-Plus Pricing", "definition": "It completely ignores the external market, such as what competitors are charging or what customers are willing to pay."}]}, "mcq": {"enabled": true, "questions": [{"question": "Price skimming is best defined as:", "options": ["charging a lower price when a product becomes old", "keeping the price of a product the same as competitors", "making sure your price is always more than competitors permanently", "setting a higher price when a product is new and has an advantage over competitors"], "answer": 3, "explain": "Correct answer: Skimming sets a high initial price for a new, highly desired or technical product, lowering it later when competitors enter."}, {"question": "Penetration pricing would normally be used when:", "options": ["a business has been in operation some time and has few competitors", "a product is being introduced which is at the cutting edge of technology", "a business is new and needs to establish its place in a crowded market", "there is incredibly high demand for a luxury product"], "answer": 2, "explain": "Correct answer: Penetration pricing involves setting prices below competitors to ''break into'' a crowded market and steal market share quickly."}, {"question": "If a business wishes to dispose of old stock to make way for new products, it would normally consider:", "options": ["Competitor pricing", "Promotional pricing", "Cost-plus pricing", "Skimming"], "answer": 1, "explain": "Correct answer: Promotional pricing (like a store sale) reduces prices for a short period specifically to clear old stock or give a quick boost to sales."}, {"question": "A business is likely to use cost-plus pricing when it:", "options": ["has surplus stock to sell off quickly", "sees that a number of competitors are starting to have an effect on sales", "feels that it must guarantee a set amount of profit is made on every unit sold", "is a new business and has to make sure it has an advantage over competitors"], "answer": 2, "explain": "Correct answer: Cost-plus pricing calculates the exact cost to make the item and adds a specific percentage mark-up, guaranteeing that a profit is made on each sale."}, {"question": "A hairdresser charges the exact same price for haircuts as two other hairdressers in the local area. Which pricing method is this?", "options": ["Competitor pricing", "Cost-plus pricing", "Penetration pricing", "Promotional pricing"], "answer": 0, "explain": "Correct answer: By setting prices identically to local rivals, the business is using competitor pricing."}, {"question": "A fast-food restaurant is currently charging 60p for its new healthy snack. It intends to increase the price to £2.25 once the snack has become popular. This is an example of:", "options": ["Competitor pricing", "Cost-plus pricing", "Penetration pricing", "Price skimming"], "answer": 2, "explain": "Correct answer: Starting with an artificially low price to gain popularity and market share, with the intent to raise it later, is the exact definition of penetration pricing."}, {"question": "A store buys frozen oven chips for 29p a pack. The store usually sells them for 99p. If it wishes to use them as a ''loss leader'', how much should it charge?", "options": ["29p a pack", "Between 29p and 99p a pack", "Less than 29p a pack", "More than 99p a pack"], "answer": 2, "explain": "Correct answer: A loss leader must be sold at a price lower than the cost it took the business to acquire or make it. Since the cost was 29p, a loss leader price must be less than 29p."}, {"question": "Which of the following is a major disadvantage of Competitor Pricing?", "options": ["It guarantees a profit on every item sold.", "It results in massive cash flow problems immediately.", "The business must find other, non-price ways to attract customers.", "It makes the product look too cheap and damages brand image."], "answer": 2, "explain": "Correct answer: Because the price is identical to rivals, the business loses price as a competitive advantage and must compete on quality, service, or advertising instead."}, {"question": "Apple introduces its latest iPhone. What pricing strategy are they most likely to use?", "options": ["Penetration pricing", "Price Skimming", "Cost-plus pricing", "Promotional pricing"], "answer": 1, "explain": "Correct answer: Apple uses price skimming. Consumers want to be up-to-date with the latest technology and are willing to pay a very high premium price at launch."}, {"question": "What is the primary danger of using Promotional Pricing too often?", "options": ["Customers may get used to the cheap prices and refuse to buy at full price.", "Competitors will immediately go bankrupt.", "The business will automatically gain a 100% market share.", "The cost of manufacturing the product will increase."], "answer": 0, "explain": "Correct answer: Frequent sales train customers to simply wait for the next sale rather than ever paying the full retail price, damaging long-term revenue."}, {"question": "Which pricing strategy is most likely to help a business recover high Research and Development (R&D) costs quickly?", "options": ["Penetration Pricing", "Price Skimming", "Loss Leader", "Competitor Pricing"], "answer": 1, "explain": "Correct answer: Price skimming generates high revenue margins immediately upon launch, which is crucial for tech or medical companies trying to pay back massive R&D investments."}, {"question": "A new coach operator introduces a long-distance service. They charge £1 for tickets for the first month to establish the business. This is:", "options": ["Promotional pricing", "Price skimming", "Cost-plus pricing", "Premium pricing"], "answer": 0, "explain": "Correct answer: (Note: It also has elements of penetration, but OCR mark schemes heavily accept Promotional Pricing for short-term massive discounts used to help a new service become established)."}]}, "fib": {"enabled": true, "questions": [{"text": "When a business first introduces a new product, it may use [penetration] pricing if it wants to gain market share from [competitors]."}, {"text": "If a product is highly technical and much better than the competition, a business might use price [skimming] to make as much [profit] as they can initially."}, {"text": "After time, when a product becomes older, a business might have to [lower] the price to keep sales high. To get rid of old stock entirely, [promotional] pricing is used."}, {"text": "A major benefit of [cost-plus] pricing is that it is a relatively simple way to set a price and ensures a profit margin is [guaranteed] on every item sold."}, {"text": "A [loss] leader is a product sold below the cost it takes to make. The hope is that customers will buy other, highly [profitable] items while in the shop."}, {"text": "If a business uses [competitor] pricing, it must find other ways to attract customers besides price, such as better customer [service] or heavier advertising."}, {"text": "Price is a critical decision because it directly affects [revenue]. Setting the price too high means sales will fall, but setting it too low damages [cash flow]."}]}, "tf": {"enabled": true, "questions": [{"statement": "Cost-plus pricing guarantees that a business will always make an overall profit for the year.", "answer": false, "explain": "FALSE. While it guarantees a profit margin on *each item sold*, the business will still make an overall loss if they do not sell enough items to cover their fixed costs."}, {"statement": "Penetration pricing is a strategy that a business should use permanently.", "answer": false, "explain": "FALSE. Penetration pricing should only last for a short period of time. Once the business has established market share, it must raise prices, otherwise it will suffer low profitability long-term."}, {"statement": "Price skimming is most effective when a business introduces a highly innovative, technological product with no direct rivals.", "answer": true, "explain": "TRUE. Skimming works best when early adopters are desperate for the newest tech and are willing to pay a premium before competitors have time to copy the product."}, {"statement": "A disadvantage of competitor pricing is that the business has to spend money constantly researching what its rivals are charging.", "answer": true, "explain": "TRUE. Competitor pricing requires constant monitoring of rival prices, which increases administrative costs."}, {"statement": "A loss leader is a product that is sold at exactly the price it costs to manufacture.", "answer": false, "explain": "FALSE. A loss leader is sold *below* the cost to manufacture. The business deliberately takes a financial loss on that specific item to entice customers into the store."}, {"statement": "Using promotional pricing too often can damage a brand''s image for quality.", "answer": true, "explain": "TRUE. If a brand is constantly ''on sale'', customers stop seeing it as a premium product and refuse to ever pay the full retail price."}, {"statement": "Cost-plus pricing takes competitor prices into account before setting the final price.", "answer": false, "explain": "FALSE. One of the main disadvantages of cost-plus pricing is that it completely *ignores* external factors like competitor prices and what customers are willing to pay."}, {"statement": "Price skimming involves starting with a low price and gradually raising it.", "answer": false, "explain": "FALSE. You are describing penetration pricing. Price skimming starts HIGH and drops LOW as the product ages."}, {"statement": "If a business uses competitor pricing, it must find a non-price way to stand out (like better service or packaging).", "answer": true, "explain": "TRUE. Because they cannot compete by being cheaper, they must differentiate their product in other ways."}, {"statement": "Penetration pricing builds brand loyalty because customers are attracted to try the product due to the low price.", "answer": true, "explain": "TRUE. The low introductory price reduces the risk for customers to try an unknown brand. If the product is good, they develop loyalty and continue buying it even when the price rises."}, {"statement": "A major supermarket like Tesco doesn''t need to consider competitor pricing because it is so large.", "answer": false, "explain": "FALSE. The ''Big Four'' supermarkets operate in a highly competitive market and constantly monitor each other''s prices, frequently offering price-matches to avoid losing customers."}, {"statement": "Price is the only element of the marketing mix that directly generates revenue.", "answer": true, "explain": "TRUE. Product, Place, and Promotion all involve spending money (costs). Price dictates the money coming into the business."}]}, "misc": {"enabled": true, "items": [{"myth": "Students confuse Penetration Pricing and Price Skimming.", "truth": "PENETRATION = Start LOW to break into a market, then raise later. SKIMMING = Start HIGH to maximise profit on a new invention, then drop later as it ages.", "check": {"question": "Which correctly distinguishes penetration pricing from price skimming?", "options": ["Both strategies start high and lower the price over time", "Penetration starts LOW; skimming starts HIGH on new items", "Both strategies start low and raise the price over time", "Penetration starts HIGH to maximise profit; skimming starts LOW to break into a market"], "answer": 1, "explain": "As the card clarifies, PENETRATION starts LOW to break in, while SKIMMING starts HIGH on a new invention and drops later."}}, {"myth": "Students think Price Skimming means dropping the price to look like a bargain.", "truth": "Examiners note this is a massive misconception. The value of skimming is NOT to drop the price later to look like a bargain. The value is charging a massive premium AT THE START to maximize financial returns from customers who want to be the first to own a superior product.", "check": {"question": "According to the exam-note correction, what is the real value of price skimming?", "options": ["Selling below cost to build a customer base quickly", "Charging a premium at the start to maximise early returns", "Dropping the price immediately to make it look like a bargain", "Matching competitor prices from day one"], "answer": 1, "explain": "The card corrects the misconception: skimming''s value comes from charging a high price AT THE START, not from dropping it later to look cheap."}}, {"myth": "Students think Cost-Plus pricing always results in high prices, making it unpopular.", "truth": "Cost-plus only results in high prices if the business demands a massive percentage mark-up. Its actual flaw is that it ignores the market—it could accidentally set a price much lower than customers are willing to pay, or slightly higher than a rival.", "check": {"question": "What is the real flaw of cost-plus pricing, as opposed to the misconception that it ''always results in high prices''?", "options": ["It ignores the market, risking too low a price", "It is illegal to use in competitive markets", "It guarantees a financial loss on every sale", "It cannot be used by manufacturing businesses"], "answer": 0, "explain": "The card explains cost-plus only leads to high prices with a large mark-up; its actual flaw is ignoring the market and rival prices entirely."}}, {"myth": "For ''analyse'' questions, students write impacts on the customer instead of the business.", "truth": "If the question says ''Analyse one advantage to Shinz Ltd'', you must state how the pricing method impacts the BUSINESS (e.g. increased revenue, higher profit margin, improved cash flow). Saying ''the customer saves money'' scores zero for analysis.", "check": {"question": "In an ''Analyse one advantage to [Business]'' pricing question, what must the analysis point focus on?", "options": ["The impact on the customer, e.g. money saved", "The impact on the government", "The impact on the business, e.g. more revenue", "The impact on the environment"], "answer": 2, "explain": "The card warns that stating ''the customer saves money'' scores zero; the analysis must show impact on the BUSINESS, such as revenue or cash flow."}}]}, "tips": {"enabled": true, "items": [{"title": "Analysing a Pricing Method", "html": "<p>Structure: Understanding of the method (1) &rarr; Application to the business (1) &rarr; Business-facing impact (1).</p>\n      <p><strong>Example (Cost-plus for a Salon):</strong> \"Cost-plus pricing ensures that the price always exceeds the costs of the business (U). By adding a mark-up to the wages of the new employees (APP), the salon guarantees that a profit is made on every haircut, avoiding a financial loss (AN).\"</p>\n      <p><strong>Warning:</strong> Do NOT explain *what* the method is (e.g. \"Cost-plus is when you add profit to costs\"). You must state a specific <em>advantage</em> or <em>disadvantage</em> to gain the first mark.</p>", "check": {"question": "In a 3-mark ''Analyse'' pricing question, what must you avoid doing if you want to gain the first mark?", "options": ["Just explaining the method, without an advantage or flaw", "Concluding with a financial impact on the business", "Stating a specific advantage or disadvantage of the method", "Applying your answer to the case study business"], "answer": 0, "explain": "The tip warns not to just explain what the method is (e.g. ''cost-plus is when...'') — you must state a specific advantage or disadvantage to gain the first mark."}}, {"title": "Evaluating the Importance of Price", "html": "<p>If asked to evaluate the importance of price (e.g., Currys case study), you must weigh price against other factors.</p>\n      <p><strong>Yes, it is important:</strong> In markets like technology, products are identical (a Samsung TV is the same everywhere). Consumers use the internet to easily compare prices. Without competitive pricing, Currys will lose sales.</p>\n      <p><strong>No, other things matter:</strong> Quality of customer service (technical advice), the brand reputation, or the convenience of the store location might be more important to certain customers than saving a few pounds.</p>", "check": {"question": "When evaluating the importance of price for a business like Currys, what should a strong answer do?", "options": ["Weigh price against service, reputation, or location", "Focus solely on the cost of manufacturing the product", "Only discuss why price is the single most important factor and ignore other factors", "Ignore competitor prices entirely"], "answer": 0, "explain": "The tip states you must weigh price''s importance against other factors like customer service and location, not treat price in isolation."}}, {"title": "Recommending a Strategy", "html": "<p>When asked to recommend between two strategies (e.g., Skimming vs Competitor pricing), your justification MUST be <strong>comparative</strong>.</p>\n      <p><strong>Bad:</strong> \"Shinz Ltd should use competitor pricing because it will attract customers.\" (No comparison made).</p>\n      <p><strong>Good:</strong> \"Shinz Ltd should use competitor pricing (1) to ensure potential customers do not go to the rival car wash 5 miles away, whereas skimming would push price-sensitive customers directly to that rival (+2).\"</p>", "check": {"question": "When recommending one pricing strategy over another, what must the justification be?", "options": ["A simple restatement of the definition of the strategy", "Focused only on the strategy you did not choose", "Comparative — the chosen strategy beats the alternative", "Based purely on which strategy is cheapest to implement"], "answer": 2, "explain": "The tip states the justification MUST be comparative, showing why the chosen strategy beats the alternative for that specific business, not just listing a standalone benefit."}}]}, "exam": {"enabled": true, "questions": [{"question": "Analyse one advantage of HH Ltd using cost-plus pricing. [3 marks]", "marks": 3, "hint": "State a benefit of cost-plus (U) -> apply to making keyboards/pianos (APP) -> state the financial impact on HH Ltd (AN).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Understanding (1 mark):</strong> E.g., ensures costs are covered / guarantees a profit margin / easy to calculate.</li><li><strong>Application (1 mark):</strong> E.g., relates to keyboards, pianos, organs, or manufacturing instruments.</li><li><strong>Analysis (1 mark):</strong> E.g., avoids making a loss / allows the business to reinvest the profit / improves cash flow.</li></ul></div>"}, {"question": "Analyse one advantage of HH Ltd using competitive pricing. [3 marks]", "marks": 3, "hint": "State a benefit of competitor pricing (U) -> apply to the highly competitive keyboard market (APP) -> state the impact on sales/market share (AN).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Understanding (1 mark):</strong> E.g., selling prices are in line with rivals / attracts customers / retains market share.</li><li><strong>Application (1 mark):</strong> E.g., relates to the ''very competitive market'' / selling keyboards/pianos.</li><li><strong>Analysis (1 mark):</strong> E.g., avoids losing sales to competitors / maintains steady revenue / builds customer loyalty.</li></ul></div>"}, {"question": "Recommend whether HH Ltd should use cost-plus or competitive pricing. [3 marks]", "marks": 3, "hint": "Make a choice. Then provide a *comparative* justification. Why is your choice *better* than the other one for a business in a ''very competitive market''?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Decision (1 mark):</strong> Select either cost-plus or competitive pricing.</li><li><strong>Justification (2 marks):</strong> Must be a contextual, comparative justification explaining why one is MORE appropriate than the other.</li></ul></div>"}, {"question": "Analyse one advantage for Shinz Ltd of using each pricing method: \n1) Competitor pricing\n2) Price skimming \n[6 marks]", "marks": 6, "hint": "This is two separate 3-mark answers. For each: state the advantage (U) -> apply to Shinz car wash/resin polish (APP) -> business impact (AN). Remember Shinz is known for quality/not low prices.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 6 marks</h5><p><strong>Competitor Pricing:</strong><br>Understanding (1): Less likely to lose customers / steal customers from rivals.<br>Application (1): Resin polish offered 5 miles away.<br>Analysis (1): Protects market share / maintains sales revenue.</p><p><strong>Price Skimming:</strong><br>Understanding (1): High profit margin per sale / creates perception of high quality.<br>Application (1): Shinz does not offer low prices / customer service is a priority / requested by loyal customers.<br>Analysis (1): Improves reputation / rapid payback on investment / high profits.</p></div>"}, {"question": "Recommend which of the two pricing methods Shinz Ltd should use. Give reasons for your answer. [3 marks]", "marks": 3, "hint": "Make a choice. Defend it by comparing it to the alternative using context (e.g. no local competitors vs a competitor 5 miles away).", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Decision (1 mark):</strong> e.g., Price skimming.</li><li><strong>Justification (2 marks):</strong> Contextual comparison. E.g., Skimming is better because they have no direct local competitors in their town, whereas competitor pricing would force them to lower prices unnecessarily to match a business 5 miles away.</li></ul></div>"}, {"question": "Discuss, with reference to the data, whether cost-plus pricing is the most effective pricing method for Green Cuisine. [9 marks]", "marks": 9, "hint": "Evaluate the pros and cons of Cost-Plus pricing specifically for this organic restaurant. \nPro: Guarantees profit, easy to calculate (use the £12 + 10% = £13.20 data).\nCon: Ignores external factors (high unemployment, cheaper £11 rival).\nConclusion: Is it effective? Recommend an alternative if not.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 9 marks</h5><p><strong>Level 3 (7-9 marks):</strong> Good knowledge/understanding, good application of the data (using £ figures or customer quotes), good analysis, and strong, justified evaluation.<br><strong>Pros:</strong> Ensures profit margin, simple, owners control the mark-up. Fits with customers ''prepared to pay extra''.<br><strong>Cons:</strong> Ignores the £11 rival. Ignores high local unemployment. Sales drop sharply if price rises (from 100 sales at £13.20 to 45 at £14.40).<br><strong>Evaluation:</strong> Cost-plus is flawed here because the market has high unemployment and a cheaper rival. A flexible method or competitor pricing might be safer to ensure survival.</p></div>"}, {"question": "State two pricing methods that a business could use. [2 marks]", "marks": 2, "hint": "Simply list any two pricing methods. No explanation needed.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks</h5><ul><li>1 mark for each correct identification: Cost-plus, Skimming, Penetration, Competitor, Promotional, Loss Leader.</li></ul></div>"}]}}'::jsonb),
('business', '2-4-4-promotion', '2.4.4 Promotion', '{"learn": {"enabled": true, "items": [{"title": "Introduction to Promotion", "html": "<p><strong>Promotion</strong> is about informing customers about what is for sale and persuading them to buy. When a business has a good product, or is offering a good price, it needs to inform its customers. This makes promotion highly interconnected with the other ''Ps'' of the marketing mix.</p>\n      <p><strong>There are four key aims of promotion:</strong></p>\n      <ol>\n      <li>To inform customers about a product or service (especially when it is new or has changed).</li>\n      <li>To keep a business ahead of its competitors.</li>\n      <li>To create or change the image of a business, its products, and services.</li>\n      <li>To maintain or increase sales.</li>\n      </ol>\n      <p>Promotion is generally divided into two main areas: <strong>Point of Sale Promotion</strong> and <strong>Advertising Media</strong>.</p>", "check": {"question": "What is the main purpose of promotion within the marketing mix?", "options": ["To reduce the cost of manufacturing a product", "To inform and persuade customers to buy a product", "To set the price of a product based on demand", "To decide where a product will be distributed"], "answer": 1, "explain": "Promotion is defined as informing customers about what is for sale and persuading them to buy it, making it distinct from the other Ps of the marketing mix."}}, {"title": "Point of Sale Promotion", "html": "<p><strong>Point of Sale promotions</strong> are specific offers available when purchasing a product. They are designed to tempt customers to make an immediate purchase.</p>\n      <ul>\n      <li><strong>Price Reductions (Sales):</strong> Used mainly to sell off old stock (e.g., winter clothes as spring approaches). The disadvantage is that the business makes less profit per item than if sold at the original price.</li>\n      <li><strong>Competitions:</strong> A person who buys a product is entered into a competition (e.g., to win a free holiday). This encourages large, multiple, or repeat purchases as customers buy more to gain extra entries.</li>\n      <li><strong>Free Samples:</strong> Often seen with products like cosmetics or food/soft drinks. Giving a 30% extra free bottle or a free tasting sample persuades consumers to try a product they haven''t had before.</li>\n      <li><strong>Loss Leaders:</strong> Items that are deliberately sold at a loss to attract customers into a store. The hope is that once the customer is inside, they will be tempted to buy other, highly profitable products at the same time.</li>\n      </ul>", "check": {"question": "What is the defining feature of a Point of Sale promotion?", "options": ["It broadcasts a brand message to the wider public over several weeks", "It only applies to products sold online", "It offers an incentive at the point of purchase to trigger a sale", "It is used exclusively to build long-term brand image"], "answer": 2, "explain": "Point of Sale promotions (like price reductions, competitions, free samples and loss leaders) are specific offers available when purchasing, designed to tempt an immediate purchase."}}, {"title": "Advertising Media", "html": "<p><strong>Advertising media</strong> are the various ways a company can communicate its message to the wider public to build brand awareness.</p>\n      <ul>\n      <li><strong>Social Media (Facebook, Instagram, Twitter/X):</strong> Excellent for targeting specific demographics (like 16-24 year olds). It is relatively cheap and has a global reach, but users can easily skip ads, and maintaining a social media presence requires constant monitoring.</li>\n      <li><strong>Television:</strong> Reaches millions of people and has high visual and audio impact. It is perfect for mass-market products (like supermarkets or insurance comparison sites). However, it is the most expensive form of advertising.</li>\n      <li><strong>Print Media (Newspapers & Magazines):</strong> Magazines are great for targeting specific groups (e.g., a high-end perfume in a glossy fashion magazine). National newspapers reach a wide audience, while local newspapers are perfect for small, local businesses.</li>\n      <li><strong>Radio:</strong> Local radio allows a business to target a specific geographical area cheaply. National radio reaches a wide audience. However, it lacks visual impact so products cannot be demonstrated.</li>\n      <li><strong>Websites:</strong> Businesses use their own sites or pay for banner ads on other popular sites. E-commerce platforms like ASOS or Boohoo rely heavily on digital advertising to drive traffic directly to their digital checkout.</li>\n      </ul>", "check": {"question": "Which advertising media offers high visual and audio impact and reaches millions of people, but is the most expensive option?", "options": ["Local radio", "Print media", "Social media", "Television"], "answer": 3, "explain": "Television reaches millions of people with high visual and audio impact, making it ideal for mass-market products, but it is described as the most expensive form of advertising."}}, {"title": "Case Study: Mobile Phone Services", "html": "<p><strong>Three, EE, Vodafone, O2</strong></p>\n      <p>Millions of people buy and use mobile phones. The main companies supplying the phones and services are in close competition. They are constantly updating the deals they offer (e.g., price, 5G coverage, data, Apple Music add-ons) hoping to persuade consumers to change to their service.</p>\n      <p>Without promotion, customers would be completely unaware of these deals. Mobile phone companies spend a massive amount of money on advertising to ensure all potential buyers know about their offers. Because the market is so saturated, each company has to aggressively match the promotion of the others to attract new customers and keep existing ones; otherwise, rivals will step in and steal their market share.</p>", "check": {"question": "Why do mobile network providers like EE and Vodafone spend heavily on promotion even though the market is already saturated?", "options": ["To reduce the manufacturing cost of handsets", "Because government regulation forces them to advertise their handsets", "To stop rivals stealing market share by keeping customers informed", "Because they have no real competitors to worry about"], "answer": 2, "explain": "In a saturated market, each company must aggressively match rivals'' promotion to attract and retain customers, otherwise competitors will step in and steal market share."}}, {"title": "Case Study: Go Compare & Compare the Market", "html": "<p>Price comparison websites like <strong>Go Compare</strong> and <strong>Compare the Market</strong> use heavy Television advertising to promote their services. Their target market is essentially every household in the UK that needs car, home, or pet insurance.</p>\n      <p><strong>Evaluation: Should they concentrate on TV?</strong><br>\n      Yes, they should. They earn their money by providing links to different insurance companies; the more links clicked, the more money they earn. Because their target market is so broad (all UK households), no other advertising media can match the sheer volume and reach of TV. While radio or social media might be cheaper, it would not reach the same millions of potential mass-market consumers, allowing rivals to ''steal'' their customers and reduce their income.</p>", "check": {"question": "Why is television advertising judged to be the right choice for Go Compare and Compare the Market?", "options": ["TV is the cheapest media option available to them", "Their target market is every UK household, so TV gives the best reach", "TV only reaches people already searching online for insurance deals", "It allows them to target just one narrow age group precisely"], "answer": 1, "explain": "Because their target market is so broad (all UK households needing insurance), the evaluation concludes no other advertising media can match the sheer volume and reach of TV, even though it is expensive."}}, {"title": "Choosing the Right Promotion", "html": "<p>Different situations require different promotional methods. A business must evaluate the <strong>Cost</strong> vs the <strong>Target Audience</strong>.</p>\n      <ul>\n      <li><strong>A local chip shop or cafe:</strong> Needs local advertising. A leaflet drop through local letterboxes or an ad on local radio is cost-effective and hits the exact geographic target. TV would be a massive waste of money.</li>\n      <li><strong>A famous perfume brand:</strong> Needs to maintain a premium brand image. Glossy photographs in high-end fashion magazines are ideal.</li>\n      <li><strong>A highly specialized tech product (e.g., advanced sat-nav):</strong> Should be advertised in specialist motoring or tech magazines to hit a niche target market directly.</li>\n      <li><strong>ASOS / Boohoo.com:</strong> Both target 16-24 year old fashion-conscious consumers. Social media (Instagram, TikTok) is the most effective way to reach this demographic, combining targeted ads with direct links to their e-commerce apps.</li>\n      </ul>", "check": {"question": "What two factors must a business weigh up most carefully when choosing the right promotional method for a situation?", "options": ["The size of the shop window display and the colour scheme", "The cost of the method and the nature of the target audience", "The age of the business owner and their personal taste", "The number of competitors within the same postcode"], "answer": 1, "explain": "The card states a business must evaluate the Cost versus the Target Audience, which is why a local café uses cheap local media while a mass-market brand may justify TV."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Promotion", "definition": "The process of communicating with customers to inform them about a product and persuade them to buy it."}, {"term": "Point of Sale Promotion", "definition": "Offers or displays placed exactly where the product is sold to encourage an immediate, impulse purchase (e.g., BOGOF, sales, samples)."}, {"term": "Loss Leader", "definition": "An item sold at a deliberate financial loss to act as bait, drawing customers into the store to buy other profitable goods."}, {"term": "Advertising Media", "definition": "The channels through which advertising is broadcast (e.g., TV, radio, print, social media)."}, {"term": "Social Media Advertising", "definition": "Using platforms like Instagram or Facebook. Pro: Highly targeted to specific ages/interests. Con: Users easily skip or ignore ads."}, {"term": "Television Advertising", "definition": "Pro: Reaches millions of people globally/nationally with massive visual and audio impact. Con: Extremely expensive to produce and air."}, {"term": "Print Media (Magazines)", "definition": "Pro: Can target niche markets (e.g., fishing, fashion) and supports a high-quality, glossy brand image. Con: Readership numbers are declining."}, {"term": "Local Radio Advertising", "definition": "Pro: Cost-effective way to target a specific town or geographic region. Con: Audio only; cannot visually demonstrate the product."}]}, "mcq": {"enabled": true, "questions": [{"question": "Loss leaders are:", "options": ["leaders who always lose their way", "losses that a business makes when it sells leading products", "the losses a business makes every time it has a sale", "items that are sold at a low price to attract customers into a store"], "answer": 3, "explain": "Correct answer: A loss leader is a point of sale promotion where a specific item is sold at a loss to entice shoppers into the store, hoping they buy other profitable items while there."}, {"question": "Which of the following is an example of social media advertising?", "options": ["A glossy advert in a fashion magazine", "Promoted posts on Facebook and Instagram", "A 30-second commercial on ITV", "A leaflet dropped through a letterbox"], "answer": 1, "explain": "Correct answer: Facebook, Instagram, Twitter/X, and TikTok are all social media platforms used for digital advertising."}, {"question": "A local chip shop wanting to advertise its new menu would most likely use:", "options": ["a leaflet drop through letter boxes", "nationwide television advertising", "national radio advertising at peak times", "a glossy magazine advertising campaign"], "answer": 0, "explain": "Correct answer: A local chip shop only needs to reach people in its immediate geographical area. Nationwide TV or radio would be far too expensive and reach millions of people who live too far away to ever visit."}, {"question": "A business wanting to let consumers try a small sample of its new cheese in a supermarket would be said to be using:", "options": ["loss leaders", "promotional advertising", "a promotion campaign", "point-of-sale promotion"], "answer": 3, "explain": "Correct answer: Free samples given in the store where the product is sold are a form of Point of Sale promotion, designed to encourage an immediate purchase."}, {"question": "Which of the following is a benefit to a business of advertising on local radio?", "options": ["Detailed financial information can be included", "Can target a specific geographical area", "Free samples can be given out with the advertisement", "The product can be seen and demonstrated visually"], "answer": 1, "explain": "Correct answer: Local radio broadcasts to a specific town or county, allowing local businesses to target a specific geographical area very cost-effectively. Options A, C, and D are impossible on radio."}, {"question": "What is a major disadvantage to a business of using social media to promote its products?", "options": ["It is the most expensive form of advertising", "It can only reach people in a local town", "Customers can easily skip or ignore the adverts", "It is completely unregulated by law"], "answer": 2, "explain": "Correct answer: While social media is cheap and highly targeted, users often scroll past or use ad-blockers, making it easy for the promotion to be ignored."}, {"question": "Sainsbury''s uses television to advertise its products. What is an advantage of this?", "options": ["It allows them to give out free samples to viewers", "It is the cheapest method of advertising available", "It uses high-impact audio and visuals to reach millions of mass-market consumers", "It guarantees that every viewer will visit the store"], "answer": 2, "explain": "Correct answer: TV is very expensive, but it offers unparalleled reach (millions of viewers) and the ability to combine moving images, colour, and sound to demonstrate products."}, {"question": "Which point of sale promotion involves reducing prices specifically to clear out old stock?", "options": ["Loss leaders", "Competitions", "Price reductions (Sales)", "Free samples"], "answer": 2, "explain": "Correct answer: Price reductions (like January sales) are heavily used by clothing retailers to get rid of last season''s stock to make room for new items."}, {"question": "Walkers Crisps runs a prize competition on the back of its Quavers packaging. What is the main business advantage of this?", "options": ["It targets people who have never eaten crisps before", "It guarantees the crisps taste better", "It reduces the cost of manufacturing the crisps", "It encourages existing customers to make large or repeat purchases for extra entries"], "answer": 3, "explain": "Correct answer: Competitions on packaging encourage people who already buy the product to buy it *more often* in the hopes of winning the prize, driving up sales volume."}, {"question": "A company that sells highly specialised, expensive diving equipment wants to advertise. Which media is most appropriate?", "options": ["National television during a soap opera", "A local newspaper", "A specialist scuba-diving and watersports magazine", "A loss leader promotion in a supermarket"], "answer": 2, "explain": "Correct answer: Specialist magazines allow a business to target a very specific, niche audience directly, meaning they don''t waste money advertising to the general public who do not dive."}, {"question": "Boohoo.com targets 16-24 year olds who are fashion conscious. Which advertising media is best for this target market?", "options": ["National radio", "Social media (Instagram/TikTok)", "Local newspapers", "Television soap operas"], "answer": 1, "explain": "Correct answer: 16-24 year olds are heavy users of social media. Advertising there allows Boohoo to target their core demographic accurately and link them directly to their online store."}, {"question": "Which of the following is NOT a key aim of promotion?", "options": ["To inform customers about a new product", "To create or change the brand''s image", "To reduce the costs of manufacturing", "To maintain or increase sales"], "answer": 2, "explain": "Correct answer: Promotion is a marketing function and involves spending money to increase sales or awareness. It has absolutely nothing to do with reducing the operational costs of manufacturing a product."}]}, "fib": {"enabled": true, "questions": [{"text": "Promotion is about [informing] customers about what is for sale and [persuading] them to buy."}, {"text": "A [loss] leader is a product deliberately sold at a [loss] to attract customers into a store."}, {"text": "Point of [sale] promotions include price reductions, competitions, and free [samples]."}, {"text": "Television advertising has high [visual] impact and reaches millions of people, but it is the most [expensive] form of media."}, {"text": "A local chip shop would use a [leaflet] drop or local [radio] to advertise to its specific geographical area."}, {"text": "ASOS and Boohoo target 16-24 year olds, so they use [social] media to reach their target [market]."}, {"text": "A famous perfume brand launching a new fragrance would use glossy fashion [magazines] to maintain its premium brand [image]."}, {"text": "Price [reductions] are often used by clothing retailers in January to clear out old [stock] and make room for spring lines."}, {"text": "A key aim of promotion is to keep a business ahead of its [competitors], ensuring they do not steal [market] share."}, {"text": "A prize [competition] printed on the back of a cereal box encourages customers to make [repeat] purchases to gain more entries."}, {"text": "Price comparison sites like Go Compare use [television] advertising because their service is aimed at a mass market of all UK [households]."}, {"text": "One disadvantage of social media advertising is that users can easily [skip] or ignore the adverts on their [screen]."}]}, "tf": {"enabled": true, "questions": [{"statement": "A loss leader is meant to make a loss to keep the business in the lead.", "answer": false, "explain": "FALSE. A loss leader is a product sold at a financial loss to attract customers into a store, in the hope they will buy other, fully-priced profitable items while there."}, {"statement": "Competitions are only used by supermarkets to promote the food they sell.", "answer": false, "explain": "FALSE. Competitions can be used by any business (e.g., car dealerships, clothing brands, cereal manufacturers) to encourage purchases."}, {"statement": "Price reductions are often seen in shops in January.", "answer": true, "explain": "TRUE. January sales are a classic example of using price reductions as a point of sale promotion to clear out old winter stock."}, {"statement": "Free samples are often seen in products such as cosmetics or food.", "answer": true, "explain": "TRUE. Free samples persuade customers to try a product risk-free, which is highly effective for items where scent or taste is the primary selling point."}, {"statement": "Supermarkets use loss leaders to encourage shoppers to visit their stores.", "answer": true, "explain": "TRUE. Supermarkets might sell bread or milk at a loss, knowing that a customer will likely also buy meat, vegetables, and treats that have a high profit margin."}, {"statement": "Promotion is mainly concerned with making sure that old stock is sold at the best possible price.", "answer": false, "explain": "FALSE. While price reductions clear old stock, the main aims of promotion are much wider: informing customers of new products, increasing sales, and building brand image."}, {"statement": "Not all businesses use promotion to help them sell products and services.", "answer": false, "explain": "FALSE. Virtually every business must use some form of promotion (even if it''s just a shop sign or word of mouth) to make customers aware they exist."}, {"statement": "Local radio is an excellent way for a national supermarket chain to reach the whole UK.", "answer": false, "explain": "FALSE. Local radio only reaches a small geographical area. A national supermarket would use national television or national newspapers to reach the whole UK."}, {"statement": "Social media allows a business to target its advertising very precisely based on user age and interests.", "answer": true, "explain": "TRUE. Platforms like Instagram and Facebook collect massive amounts of user data, allowing businesses (like Boohoo) to target exact demographics like 16-24 year olds."}, {"statement": "One advantage of print media (like magazines) is that they can include physical scent samples or glossy images.", "answer": true, "explain": "TRUE. Glossy magazines are perfect for high-end fashion and perfume brands because they support a premium image and can even include physical ''rub and sniff'' samples."}, {"statement": "A major disadvantage of television advertising is that it lacks visual impact.", "answer": false, "explain": "FALSE. Television has massive visual and audio impact. It is *radio* that lacks visual impact."}, {"statement": "A business should choose its advertising media based on where its target market is most likely to see it.", "answer": true, "explain": "TRUE. A business must match its media to its market. You wouldn''t advertise skateboards in a retirement magazine, or luxury cars on a budget leaflet."}, {"statement": "Social media advertising is generally much more expensive than national television advertising.", "answer": false, "explain": "FALSE. National TV is usually the most expensive form of advertising, costing millions. Social media can be done on a much smaller, highly targeted budget."}, {"statement": "Giving away 30% extra free in a bottle of cola is an example of point of sale promotion.", "answer": true, "explain": "TRUE. This acts like a free sample/bonus that tempts the customer to choose that specific bottle off the shelf over a rival brand."}]}, "misc": {"enabled": true, "items": [{"myth": "Students often confuse ''Point of Sale Promotion'' with ''Advertising Media''.", "truth": "Point of Sale is the specific offer at the shop/checkout to force a quick sale (e.g. BOGOF, 50% off, free sample). Advertising Media is the channel used to broadcast a message to the wider world (e.g. TV, Radio, Social Media).", "check": {"question": "How does Point of Sale Promotion differ from Advertising Media?", "options": ["They are the same thing; both terms just describe general advertising to the public", "Advertising Media only applies to online businesses", "Point of Sale is the checkout offer; Advertising Media is the wider broadcast channel", "Point of Sale is always more expensive than Advertising Media"], "answer": 2, "explain": "Point of Sale is the specific offer at the till/shop (e.g. BOGOF, free sample), whereas Advertising Media is the broadcast channel (e.g. TV, radio, social media) used to reach a wider audience."}}, {"myth": "Students think ''Loss Leader'' just means the business is losing money generally.", "truth": "A Loss Leader is a highly specific strategy: deliberately pricing ONE specific item below its cost to make, acting as bait to draw customers into the store so they buy OTHER profitable items.", "check": {"question": "What does the term ''Loss Leader'' specifically mean?", "options": ["A business that is generally losing money overall", "Pricing one specific item below cost to draw customers into the store", "A manager who has lost control of the sales team", "A product that has been recalled by the manufacturer due to poor quality"], "answer": 1, "explain": "A Loss Leader is a specific strategy of pricing ONE item below cost as bait, not a general sign that the whole business is losing money."}}, {"myth": "When asked for an advantage of a specific media (e.g. TV), students give a generic advantage of promotion (e.g. ''it gets more customers'').", "truth": "You must give an advantage UNIQUE to that media. For TV: ''It provides moving images and sound to demonstrate the product''. For Local Radio: ''It targets a specific geographical town cheaply''.", "check": {"question": "When an exam question asks for an advantage of a named media such as TV, what must the answer include to score well?", "options": ["A generic advantage of promotion, such as ''it gets more customers''", "A feature unique to that media, such as TV''s moving images and sound", "A comparison to every other media type available", "Just the name of the media repeated back"], "answer": 1, "explain": "Marks require an advantage UNIQUE to the named media (e.g. TV shows moving images and sound; local radio targets a specific town cheaply), not a vague, generic benefit of promotion."}}, {"myth": "Students suggest TV advertising for small, local businesses (like a single café).", "truth": "TV advertising is massively expensive and reaches a national audience. It is completely inappropriate for a single local café. Always match the scale of the media to the scale of the business.", "check": {"question": "Why would recommending TV advertising for a single local café be a poor exam answer?", "options": ["TV cannot legally be used to advertise a small, independent local business such as a café", "TV is very expensive and reaches a national audience, wasting money on distant people", "TV adverts cannot include images of food", "Local cafés are not allowed to advertise at all"], "answer": 1, "explain": "The scale of the media must match the scale of the business; TV is hugely expensive and reaches a national audience, which is inappropriate and wasteful for a single local café."}}]}, "tips": {"enabled": true, "items": [{"title": "Naming Advertising Media", "html": "<p>If asked to state an advertising media, be specific. \"Internet\" is a bit vague — use \"Social media\" or \"Company Website\".</p>\n      <p><strong>Accepted Media:</strong> Television / Local or National Radio / Social Media / Print Media (Newspapers/Magazines) / Leaflets / Billboards.</p>", "check": {"question": "Why would writing ''the internet'' as an answer to ''state an advertising media'' likely lose the mark?", "options": ["The internet is not accepted as an advertising media answer at all", "It is too vague; a specific method like ''social media'' is needed", "Only television and radio are ever accepted as answers", "It should be written in full as ''World Wide Web''"], "answer": 1, "explain": "For a 1-mark ''state/identify'' question you must be specific — the tip warns that ''internet'' is too vague and examiners want a named method like ''social media'' or ''company website''."}}, {"title": "Analysing a Media Choice", "html": "<p>Structure: Identify a feature of the media (U) &rarr; Apply to the business scenario (APP) &rarr; State the business impact (AN).</p>\n      <p><strong>Example (Sainsbury''s using TV):</strong> \"TV allows the use of moving images and sound to demonstrate products (U). Sainsbury''s can use this to visually show the high quality of its food ranges to middle-income earners (APP), which will increase brand awareness and boost total sales revenue (AN).\"</p>", "check": {"question": "What is the correct three-step structure for answering a 3-mark ''Analyse a media choice'' exam question?", "options": ["State the business''s turnover, then its profit, then its market share", "Identify a feature of the media, apply it to the scenario, then state the impact", "List every advertising media the business could use, in order of cost", "Give the business''s opinion, a counter-opinion, and then a final overall decision"], "answer": 1, "explain": "The tip sets out the structure as Understanding a feature of the media, Application to the business scenario, then Analysis of the business impact (U -> APP -> AN)."}}, {"title": "Evaluating Promotional Methods", "html": "<p>When asked to recommend or evaluate a promotional method (like the Boohoo social media question or Walkers Newspaper vs Competition question), you must weigh the <strong>Pros and Cons</strong>.</p>\n      <ul>\n      <li><strong>Cost:</strong> Is the business a small sole trader or a massive Plc? Can they afford TV?</li>\n      <li><strong>Target Market:</strong> Where does the target market look? (e.g., 16-24 year olds look at TikTok, not the local newspaper).</li>\n      <li><strong>Reach:</strong> Do they need national reach or just local town reach?</li>\n      </ul>\n      <p>Always justify your final decision using the specific context of the case study business.</p>", "check": {"question": "What must a 7-mark ''Evaluate'' answer on a promotional method include to score full marks?", "options": ["A list of every possible advertising media with no final decision", "Only the cheapest promotional method, with no discussion of the target market at all", "A weighing of pros and cons, plus a justified final decision using case study context", "A single sentence stating a preference without any reasoning"], "answer": 2, "explain": "Evaluate questions require weighing pros and cons such as cost, target market and reach, then justifying the final decision using the specific context of the case study business."}}]}, "exam": {"enabled": true, "questions": [{"question": "Analyse one advantage for Walkers of each promotion method. [6 marks]", "marks": 6, "hint": "This is 3 marks for the newspaper and 3 marks for the competition. Understand the benefit of the specific method -> Apply to Walkers/crisps -> Analyze business impact.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 6 marks</h5><p><strong>National Newspapers (3 marks):</strong><br>Understanding (1): Large readership / reaches a wide mass-market audience.<br>Application (1): Applies to Walkers aim to maintain 50% market share / selling crisps.<br>Analysis (1): Increases brand awareness leading to higher sales revenue.</p><p><strong>Prize Competition (3 marks):</strong><br>Understanding (1): Encourages multiple/repeat purchases to get more entries.<br>Application (1): Applies to buyers of Quavers/snacks.<br>Analysis (1): Increases sales volume and boosts profitability.</p></div>"}, {"question": "Recommend whether advertising in national newspapers or a prize competition would be the most appropriate promotion method for Walkers to use. Give a reason for your answer. [3 marks]", "marks": 3, "hint": "Make a decision. Then justify it by COMPARING the two methods based on the context of Walkers.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Decision (1 mark):</strong> Select either method.</li><li><strong>Justification (2 marks):</strong> A contextual, comparative justification. E.g. A prize competition is better because it targets people already in the snack aisle to buy more, whereas newspapers target an older demographic who are less likely to buy crisps.</li></ul></div>"}, {"question": "Evaluate whether Go Compare and Compare the Market should concentrate on using TV to promote their services. [7 marks]", "marks": 7, "hint": "Weigh the pros and cons of TV for a MASS MARKET internet business. Pro: Huge reach. Con: Very expensive compared to digital/radio. Conclusion: Give a final justified judgement.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 7 marks (AO2x2, AO3ax2, AO3bx3)</h5><p><strong>Application:</strong> Linking to internet-based companies / millions of consumers / insurance links.<br><strong>Analysis:</strong> TV reaches millions resulting in high link clicks and massive income (pro). TV is expensive and might reduce profit margins if not enough people click (con).<br><strong>Evaluation:</strong> A justified decision based on the fact that no other media can match the sheer mass-market reach required for an insurance comparison site.</p></div>"}, {"question": "Analyse the advantages and disadvantages to ASOS of using social media to advertise its products. [6 marks]", "marks": 6, "hint": "This requires 1 advantage and 1 disadvantage. Identify the point -> Apply to ASOS (16-24 year olds/fashion) -> Analyze the business impact.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 6 marks</h5><p><strong>Advantage (3 marks):</strong> Cheap/Targeted (U). Applied to 16-24 year olds/fashion (APP). Increases sales efficiently / direct link to buy (AN).<br><strong>Disadvantage (3 marks):</strong> Ads easily skipped/ignored or negative comments spread quickly (U). Applied to ASOS online store (APP). Wasted advertising budget / damaged brand reputation (AN).</p></div>"}, {"question": "Analyse one disadvantage to a customer of Boohoo''s distribution channel (online only). [3 marks]", "marks": 3, "hint": "This question asks about the CUSTOMER''s disadvantage of an ONLINE ONLY store. Think about trying things on or returning them.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Understanding (1 mark):</strong> No way to ''try'' the product / requires internet / difficult to return.</li><li><strong>Application (1 mark):</strong> Applies to clothes / smartphone apps.</li><li><strong>Analysis (1 mark):</strong> The customer might be disappointed / has to spend time sending clothes back.</li></ul><p><em>Note: This question specifically asks for an impact on the CUSTOMER, not the business.</em></p></div>"}, {"question": "Explain three advantages for Sainsbury''s of using television to advertise its products. [6 marks]", "marks": 6, "hint": "Provide 3 separate advantages. Each one must have 1 mark for Understanding the benefit of TV, and 1 mark for Applying it to Sainsbury''s. No analysis is required for ''Explain'' questions.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 6 marks (3 x 2 marks)</h5><p>For each of the 3 advantages: 1 mark for understanding a feature of TV, 1 mark for application to Sainsbury''s.<br><strong>Acceptable points:</strong> Visual/Audio impact, Reaches massive mass-market audience, Can adapt for different seasons (e.g., Christmas food).</p></div>"}, {"question": "Which of the following is not a benefit to a business of using television advertising to promote its products?", "marks": 1, "hint": "A ''benefit'' is a good thing. Which of these is a BAD thing (a disadvantage)?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B</strong></p><p>Large financial risks (due to the extremely high cost of TV advertising) are a major disadvantage, not a benefit.</p></div>"}]}}'::jsonb),
('business', '2-4-5-place', '2.4.5 Place', '{"learn": {"enabled": true, "items": [{"title": "What is Place?", "html": "<p><strong>Place</strong> in the marketing mix does not just mean the physical location of a shop. It refers to the <strong>channels of distribution</strong> — the methods used to get a product or service from the producer to the final consumer.</p>\n  <p>Distribution can be broadly split into two categories:</p>\n  <ul>\n  <li><strong>Physical Distribution:</strong> The movement of physical, tangible goods from the producer to the consumer (e.g., delivering a car, a loaf of bread, or a physical book).</li>\n  <li><strong>Digital Distribution:</strong> When a product or service is downloaded or streamed by the consumer directly from the seller via the internet (e.g., streaming music on Spotify, downloading software, or buying travel insurance online).</li>\n  </ul>\n  <p>With the rapid growth of e-commerce, the way products are distributed has changed dramatically, forcing traditional high-street businesses to adapt.</p>", "check": {"question": "In the marketing mix, what does ''Place'' actually refer to?", "options": ["The price charged for delivery to different regions", "The channels of distribution from producer to consumer", "The physical location/address of the business''s shop", "The design and packaging of the product"], "answer": 1, "explain": "The card explains that Place refers to the channels of distribution, not simply the physical location of a shop."}}, {"title": "Physical Distribution Channels", "html": "<p>There are three main physical distribution channels a business can use:</p>\n  <ol>\n  <li><strong>Channel 1: Producer → Consumer (Direct Selling)</strong><br>\n  The product goes straight from the maker to the buyer. This is often used by small businesses (e.g., a small bakery, a farmer selling strawberries at a stall, or a bespoke furniture maker).<br>\n  <em>Advantage:</em> The producer keeps all the profit because there are no ''middlemen'' taking a cut.</li>\n  <li><strong>Channel 2: Producer → Retailer → Consumer</strong><br>\n  The producer sells in large quantities to a retailer (like Currys or B&Q), who then sells to the public. <br>\n  <em>Advantage:</em> The producer benefits from keeping the profit margin usually given to a wholesaler, whilst relying on the retailer''s massive footfall to sell the goods.</li>\n  <li><strong>Channel 3: Producer → Wholesaler → Retailer → Consumer</strong><br>\n  Used heavily for fast-moving consumer goods (e.g., corner shops buying chocolate and drinks). The producer sells massive quantities to a wholesaler (like Costco or Booker). The wholesaler then sells smaller boxes to independent retailers, who sell individual items to consumers.</li>\n  </ol>", "check": {"question": "Which distribution channel allows a producer to keep all the profit because there are no ''middlemen''?", "options": ["Channel 2: Producer → Retailer → Consumer", "A channel using an agent to negotiate contracts", "Channel 1: Producer → Consumer (Direct Selling)", "Channel 3: Producer → Wholesaler → Retailer → Consumer"], "answer": 2, "explain": "Channel 1 (direct selling) means the product goes straight from maker to buyer, so the producer keeps all the profit with no middlemen taking a cut."}}, {"title": "The Role of the Wholesaler", "html": "<p>A <strong>wholesaler</strong> acts as a vital link between massive producers and tiny independent retailers.</p>\n  <p>Their main job is to <strong>''break bulk''</strong>. A huge producer (like Coca-Cola) will not sell just one box of cans to a small local corner shop; they only sell by the lorry-load. The wholesaler buys the massive lorry-load (the bulk), stores it in a giant warehouse, and breaks it down into smaller, affordable boxes that a small retailer can afford to buy.</p>\n  <div class=\"two-col\">\n  <div>\n  <div class=\"col-head\">✓ Advantages to the Producer</div>\n  <div class=\"pro-item\">Saves warehousing costs because the wholesaler stores the massive stock.</div>\n  <div class=\"pro-item\">Guaranteed massive sales volumes in a single transaction.</div>\n  <div class=\"pro-item\">The wholesaler handles the logistics of delivering to thousands of small shops.</div>\n  </div>\n  <div>\n  <div class=\"col-head\">✗ Disadvantages to the Producer</div>\n  <div class=\"con-item\">Profit margins are reduced because the wholesaler takes a cut of the profit.</div>\n  <div class=\"con-item\">Loss of control over how the product is displayed and marketed to the final consumer.</div>\n  </div>\n  </div>", "check": {"question": "What is the main role of a wholesaler, known as ''breaking bulk''?", "options": ["Manufacturing products in bulk quantities for retailers", "Storing goods for producers without ever selling them on", "Splitting bulk purchases into smaller batches for retailers", "Selling directly to the general public in bulk"], "answer": 2, "explain": "The card states the wholesaler''s main job is to ''break bulk'' by buying lorry-loads from producers and dividing them into smaller boxes small retailers can afford."}}, {"title": "Digital Distribution", "html": "<p>Digital distribution allows products to be delivered electronically. This is suited to software, media (music/films), and services (insurance, banking).</p>\n  <div class=\"two-col\">\n  <div>\n  <div class=\"col-head\">✓ Advantages</div>\n  <div class=\"pro-item\">A business can sell globally, massively increasing potential customers.</div>\n  <div class=\"pro-item\">Can be open 24/7, all year round.</div>\n  <div class=\"pro-item\">Massive cost savings: no physical shop rent, less staff needed, and zero transport/delivery costs for digital files.</div>\n  <div class=\"pro-item\">Eco-friendly (no plastic packaging or diesel delivery lorries).</div>\n  </div>\n  <div>\n  <div class=\"col-head\">✗ Disadvantages</div>\n  <div class=\"con-item\">Global reach means global competition; it is very hard to stand out.</div>\n  <div class=\"con-item\">Requires credit/debit cards, creating potential security/fraud issues that put off some consumers.</div>\n  <div class=\"con-item\">Massive initial and ongoing costs for building and maintaining a secure e-commerce website.</div>\n  <div class=\"con-item\"><strong>Piracy:</strong> Digital content can easily be copied and illegally shared for free online.</div>\n  </div>\n  </div>", "check": {"question": "Which of these is a genuine disadvantage of digital distribution for a business?", "options": ["Having to pay for physical packaging and diesel delivery lorries", "The cost of building and maintaining a secure e-commerce website", "Being restricted to operating only during normal shop opening hours", "A smaller potential customer base than a single local shop"], "answer": 1, "explain": "The card lists the massive initial and ongoing cost of building/maintaining a secure e-commerce website as a disadvantage, whereas 24/7 operation and global reach are actually advantages."}}, {"title": "Case Studies: Morrisons, Amazon, and Sony", "html": "<p><strong>Morrisons on Amazon (Physical Distribution Innovation):</strong><br>\n  Morrisons was late to the home-delivery market compared to Tesco. To catch up, they partnered with Amazon to offer ''Morrisons on Amazon''. This physical distribution uses Amazon''s massive logistics network to deliver groceries to Prime members on the same day. By emphasizing speed of delivery, they aim to pull customers away from rival supermarkets.</p>\n  <p><strong>Sony & Netflix (Digital Distribution Transition):</strong><br>\n  In the past, Sony physically distributed Elvis records on vinyl. Today, music and films are streamed. Netflix originally physically posted DVDs to customers. Now, it is a giant of digital distribution, streaming directly to TVs. This cuts out physical manufacturing costs entirely but forces them to battle illegal downloading (piracy) and intense competition from Disney+ and Amazon Prime.</p>", "check": {"question": "What change in distribution method did Netflix undergo over time?", "options": ["From digital streaming to physically posting DVDs to customers", "From physically posting DVDs to customers, to digital streaming", "From selling music on vinyl to selling only through a wholesaler network", "From being a wholesaler to becoming a direct retailer"], "answer": 1, "explain": "The case study explains Netflix originally physically posted DVDs and is now a giant of digital distribution, streaming directly to TVs."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Place", "definition": "The distribution channels used to get the product from the producer to the final consumer."}, {"term": "Physical Distribution", "definition": "The movement of tangible goods (like food or clothes) using transport networks."}, {"term": "Digital Distribution", "definition": "The delivery of products or services electronically over the internet (e.g., streaming, software)."}, {"term": "Channel 1 (Direct Selling)", "definition": "Producer → Consumer. Cuts out the middleman, maximizing profit margin for the producer."}, {"term": "Channel 3 (Wholesaler Route)", "definition": "Producer → Wholesaler → Retailer → Consumer. Used for mass-market consumer goods."}, {"term": "Wholesaler", "definition": "A business that ''breaks bulk'' by buying massive quantities from producers and selling smaller batches to retailers."}, {"term": "Retailer", "definition": "A business that sells goods directly to the final consumer (the general public)."}, {"term": "E-commerce Disadvantage (Customer)", "definition": "Cannot try physical goods on before buying; postage delays; credit card security risks."}, {"term": "E-commerce Advantage (Business)", "definition": "Access to a global market 24/7; massive reduction in fixed costs (no shop rent or sales staff)."}, {"term": "Piracy", "definition": "The illegal copying and sharing of digital products online, resulting in lost revenue for the business."}]}, "mcq": {"enabled": true, "questions": [{"question": "Digital distribution is best suited to:", "options": ["selling goods and services from a high-street shop", "selling goods and services through a massive warehouse", "selling and delivering goods in a digital, electronic format", "selling goods and services at airports"], "answer": 2, "explain": "Correct answer: Digital distribution involves sending products electronically over the internet, like music streams or software downloads."}, {"question": "A distribution channel is defined as:", "options": ["a method of improving the physical quality of goods", "the path taken to get goods and services from the producer to the customer", "a method of advertising products on digital television", "the physical location of the factory where goods are made"], "answer": 1, "explain": "Correct answer: A distribution channel is the journey a product takes from the manufacturer to the final end-user."}, {"question": "Which of the following products would be suited to BOTH physical and digital distribution?", "options": ["Potatoes", "Newspapers", "Luxury Watches", "Designer Clothes"], "answer": 1, "explain": "Correct answer: Newspapers can be bought physically in a shop or read digitally via a tablet app. The others can only be distributed physically."}, {"question": "What is the primary role of a wholesaler in a distribution channel?", "options": ["To manufacture the goods from raw materials", "To ''break bulk'' by buying massive quantities and selling them in smaller boxes", "To sell single items directly to the final consumer", "To create advertising campaigns for television"], "answer": 1, "explain": "Correct answer: Wholesalers buy in massive bulk from producers and break it down into smaller, affordable quantities for independent retailers."}, {"question": "Which distribution channel is represented by: Producer → Consumer?", "options": ["Channel 1", "Channel 2", "Channel 3", "Wholesale Channel"], "answer": 0, "explain": "Correct answer: Channel 1 is direct selling, with no intermediaries (middlemen) between the maker and the buyer."}, {"question": "Why might a massive paint manufacturer like Dulux choose to sell directly to large retailers (like B&Q) instead of using a wholesaler?", "options": ["Because B&Q cannot afford to buy in bulk", "To keep the profit margin that would normally be taken by the wholesaler", "Because wholesalers only sell digital products", "Because Dulux wants to personally sell paint to individual homeowners"], "answer": 1, "explain": "Correct answer: Cutting out the wholesaler (the middleman) allows the producer to keep a larger share of the profit."}, {"question": "Which of the following is a major disadvantage of DIGITAL distribution?", "options": ["The business has to close at 5:00 PM every day", "Digital content can be easily copied and illegally shared for free", "It limits the business to only selling to local customers", "The physical transport costs (lorries and fuel) are very high"], "answer": 1, "explain": "Correct answer: Piracy (illegal copying and sharing) is a massive threat to digital products like music, films, and software."}, {"question": "A small farmer selling organic strawberries from a roadside stall is using which distribution method?", "options": ["Digital Distribution", "Producer → Wholesaler → Retailer", "Producer → Retailer → Consumer", "Producer → Consumer (Direct Selling)"], "answer": 3, "explain": "Correct answer: The farmer is the producer, and they are selling directly to the person who will eat the strawberries. This is Channel 1."}, {"question": "What is an advantage to a small independent corner shop of using a wholesaler?", "options": ["They can buy huge factory-sized lorry loads of stock", "They can buy smaller, affordable quantities of various goods in one place", "The wholesaler will pay the corner shop''s rent", "The wholesaler will manufacture bespoke products for them"], "answer": 1, "explain": "Correct answer: A corner shop doesn''t have the money or space for a whole lorry of Coca-Cola. The wholesaler allows them to buy a few cases at a time alongside crisps, bread, etc."}, {"question": "Which of the following businesses relies entirely on physical distribution?", "options": ["Netflix", "Spotify", "A comparison website selling car insurance", "A bakery selling fresh bread"], "answer": 3, "explain": "Correct answer: Bread is a physical, tangible good that cannot be distributed over the internet."}, {"question": "One disadvantage to a clothing business (like Boohoo) of distributing purely through e-commerce is:", "options": ["Customers cannot try the clothes on before buying, leading to high return rates", "They have to pay massive rent for high-street shops in London", "They cannot accept credit card payments", "They are only open during normal daylight hours"], "answer": 0, "explain": "Correct answer: Without physical fitting rooms, online clothing retailers face massive logistical costs dealing with returned items that did not fit the customer."}, {"question": "What is a major financial benefit to a business of switching from physical high-street shops to purely digital e-commerce?", "options": ["They no longer have to pay for web servers", "They will automatically gain a 100% market share", "They drastically reduce overhead costs like shop rent and sales staff wages", "They no longer need to advertise their products"], "answer": 2, "explain": "Correct answer: E-commerce avoids the massive fixed costs associated with physical retail premises on expensive high streets."}]}, "fib": {"enabled": true, "questions": [{"text": "Physical distribution is all about getting the [product] to the customer. Some small businesses sell [direct] to the consumer."}, {"text": "Larger businesses may sell to a [retailer] such as Currys, who then sells the goods to the final [consumer]."}, {"text": "Massive producers often sell to a [wholesaler] whose job it is to break [bulk] and sell smaller amounts to independent shops."}, {"text": "Businesses such as Tesco and Marks & Spencer have their own [regional] distribution centres where massive amounts of their [stock] is stored."}, {"text": "Digital distribution means products are delivered electronically. A major advantage is that the business can sell throughout the [world], massively increasing potential [customers]."}, {"text": "Because digital businesses operate online, they can be open [all] hours a day throughout the year, but they face global [competition]."}, {"text": "A disadvantage of digital distribution is that content (like music or software) can be easily copied and illegally shared for [free], known as [piracy]."}, {"text": "Selling directly to the consumer (Channel 1) means the producer makes more [profit] because they do not have to share it with a [middleman]."}, {"text": "If an online clothing store uses physical delivery, a disadvantage for the customer is that they cannot [try] the product before buying, making it difficult if they need to [return] the item."}, {"text": "Using e-commerce means a business needs fewer shop floor [staff], which significantly cuts their running [costs]."}, {"text": "To accept digital payments, a business requires customers to enter [credit] card details, which creates potential [security] and fraud problems."}]}, "tf": {"enabled": true, "questions": [{"statement": "In the marketing mix, ''Place'' refers only to the physical town where the factory is built.", "answer": false, "explain": "FALSE. Place refers to Distribution Channels — how the product gets from the producer to the customer."}, {"statement": "A major role of a wholesaler is to break bulk shipments into smaller quantities.", "answer": true, "explain": "TRUE. Wholesalers buy in massive bulk from factories and break it down into affordable boxes for small retailers."}, {"statement": "Channel 1 (Direct Selling) involves a wholesaler and a retailer.", "answer": false, "explain": "FALSE. Channel 1 is Producer directly to Consumer. There are no wholesalers or retailers involved."}, {"statement": "Digital distribution allows a business to be open 24 hours a day, 7 days a week.", "answer": true, "explain": "TRUE. E-commerce websites and digital downloads do not require staff to be awake, allowing 24/7 global sales."}, {"statement": "A disadvantage of digital distribution is that it limits the business to only selling to people in their local town.", "answer": false, "explain": "FALSE. Digital distribution does the exact opposite; it allows the business to sell globally to anyone with an internet connection."}, {"statement": "Selling through a wholesaler means the producer has to accept a lower profit margin per item.", "answer": true, "explain": "TRUE. The wholesaler is a business that needs to make money, so they take a cut of the profit, reducing the margin left for the producer."}, {"statement": "Piracy (illegal copying and sharing) is a major risk for businesses using digital distribution.", "answer": true, "explain": "TRUE. Products like digital music, software, and eBooks can easily be duplicated and shared illegally online, losing the business revenue."}, {"statement": "A small local farmer selling vegetables at a farm gate is using Physical Distribution Channel 3.", "answer": false, "explain": "FALSE. They are selling directly to the consumer, which is Channel 1 (Producer to Consumer)."}, {"statement": "One benefit of an online clothing store is that customers can easily try the clothes on before they pay.", "answer": false, "explain": "FALSE. A major disadvantage of online retail is that customers CANNOT try items on beforehand, leading to high return rates."}, {"statement": "Using digital distribution cuts down on costs because the business does not need to pay for high-street shop rent.", "answer": true, "explain": "TRUE. Removing physical retail premises massively reduces fixed overhead costs like rent and shop-floor staff wages."}, {"statement": "All products can be distributed digitally if the business upgrades its technology.", "answer": false, "explain": "FALSE. Physical, tangible goods like fresh food, cars, and clothing cannot be distributed digitally; they must be physically transported."}, {"statement": "If a business sells online, it faces more intense competition because consumers can buy from anywhere in the world.", "answer": true, "explain": "TRUE. While global reach is an advantage, the disadvantage is that you are now competing against every other similar business on the planet."}]}, "misc": {"enabled": true, "items": [{"myth": "Students often write that ''Place'' means the location of the business (e.g. ''The shop is in London'').", "truth": "In the marketing mix, Place specifically means DISTRIBUTION CHANNELS — the method/journey used to get the product to the consumer (e.g. e-commerce, wholesalers, direct selling).", "check": {"question": "A student writes that ''Place'' means where the business''s shop is located. What is the accurate GCSE definition?", "options": ["The retail price charged in different regions", "Distribution channels used to get the product to consumers", "The country where the business''s head office is based", "The physical street address of the business''s premises"], "answer": 1, "explain": "The card corrects the common misconception: Place means distribution channels (e.g. e-commerce, wholesalers, direct selling), not the location of the shop."}}, {"myth": "Students think wholesalers sell to the general public.", "truth": "Wholesalers (like Booker) generally sell to other businesses (Retailers). Retailers (like Tesco or a corner shop) are the ones who sell to the general public (Consumers).", "check": {"question": "Who do wholesalers typically sell to?", "options": ["Only to producers, never onward", "Other businesses, such as retailers", "Directly to the general public", "Directly to wholesalers based overseas"], "answer": 1, "explain": "The card clarifies that wholesalers generally sell to retailers (other businesses), while it is retailers who sell to the general public."}}, {"myth": "When answering ''disadvantages of online distribution for the CUSTOMER'', students write about website maintenance costs.", "truth": "Always read the entity in the question. If it asks for a disadvantage to the CUSTOMER, write about inability to try things on, postage delays, or security fears. Website costs are a disadvantage to the BUSINESS.", "check": {"question": "A question asks for a disadvantage of online shopping to the CUSTOMER. Which answer is actually creditworthy?", "options": ["Increased packaging and logistics costs for the business", "Loss of control over in-store product displays", "The high cost of building and maintaining a secure website", "Inability to try clothes on before buying, risking wrong size"], "answer": 3, "explain": "The card warns you must read the entity in the question — a disadvantage to the CUSTOMER means things like being unable to try items on, not website costs, which affect the BUSINESS."}}, {"myth": "Students state that selling directly to consumers (Channel 1) increases total sales volume for massive brands.", "truth": "Actually, massive brands (like Coca-Cola) use wholesalers because they CANNOT physically distribute millions of single cans to individuals efficiently. Direct selling is usually best for smaller, bespoke, or service businesses.", "check": {"question": "Why would a massive brand like Coca-Cola use wholesalers rather than selling directly to every individual consumer?", "options": ["Wholesalers are legally required for all food and drink products", "Selling directly always generates a bigger total sales volume for large brands", "Direct selling cannot efficiently distribute millions of units to consumers", "Direct selling is banned for businesses above a certain size"], "answer": 2, "explain": "The card explains massive brands cannot physically distribute millions of single units to individuals efficiently, so direct selling suits smaller, bespoke, or service businesses instead."}}]}, "tips": {"enabled": true, "items": [{"title": "Breaking Bulk", "html": "<p>If asked to define the role of a wholesaler, always use the phrase <strong>''breaking bulk''</strong>.</p>\n  <p>This means buying in massive quantities directly from the factory and splitting it into smaller, manageable, affordable boxes for small independent retailers.</p>", "check": {"question": "When defining the role of a wholesaler for a 1-mark key term question, which key phrase should you use?", "options": ["''Breaking bulk''", "''Economies of scale''", "''Cutting the middleman''", "''Adding value''"], "answer": 0, "explain": "The card instructs students to always use the phrase ''breaking bulk'' when defining a wholesaler''s role."}}, {"title": "Impact on the Customer vs Business", "html": "<p>Pay close attention to WHO the question is asking about.</p>\n  <p><strong>Impact on Customer:</strong> \"A disadvantage to the customer of Boohoo''s online distribution is that they cannot try the clothes on (U), meaning they might order the wrong size (APP) and have to suffer the inconvenience of returning it via post (AN).\"</p>\n  <p><strong>Impact on Business:</strong> \"A disadvantage to the business is that returns are high (U) for online clothing (APP), which severely increases logistics and repacking costs (AN).\"</p>", "check": {"question": "In the model answers, ''they cannot try the clothes on (U)... might order the wrong size (APP)...'', what does the ''APP'' label stand for?", "options": ["Approval - the examiner''s approval of the point", "Appraisal - evaluating whether the point is strong", "Approach - the general method used to answer the question", "Application - applying the point to the business context"], "answer": 3, "explain": "The card labels the specific reference to ordering the wrong size as (APP), meaning Application of the point to the exact scenario given."}}, {"title": "Choosing a Channel", "html": "<p>When asked to recommend a channel (e.g., direct vs wholesaler for Dulux paint), your justification MUST be comparative.</p>\n  <p><strong>Example:</strong> \"Dulux should sell to large retailers directly (1) because they keep a higher profit margin by cutting out the middleman, whereas selling to wholesalers means giving up a percentage of their profits (+2).\"</p>", "check": {"question": "When recommending a distribution channel for 3 marks (e.g., direct selling vs wholesaler for Dulux), what must your justification include?", "options": ["A description of the business''s history and background", "A definition of what a distribution channel is", "A comparison showing why the recommended option is better", "A list of every possible distribution channel available"], "answer": 2, "explain": "The card states the justification MUST be comparative, as shown by the Dulux example weighing direct selling against giving up profit to a wholesaler."}}]}, "exam": {"enabled": true, "questions": [{"question": "Analyse one advantage to Dulux of selling paint directly to retailers. [3 marks]", "marks": 3, "hint": "Think about profit margins. If they cut out the wholesaler (middleman), what happens to their profit?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Understanding (1 mark):</strong> e.g., Missing out the wholesaler means the producer keeps more profit / closer relationship with the seller.</li><li><strong>Application (1 mark):</strong> e.g., Relates to paint / large retailers like B&Q / Wickes / indoor or outdoor paint.</li><li><strong>Analysis (1 mark):</strong> e.g., Increases the profit margin per tin sold / improves revenue / gives them more control over how it is sold.</li></ul></div>"}, {"question": "Analyse one advantage to Dulux of selling paint to wholesalers. [3 marks]", "marks": 3, "hint": "Think about the logistics of trying to deliver to thousands of tiny shops. How does a wholesaler help a massive factory?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Understanding (1 mark):</strong> e.g., Wholesaler buys in bulk / breaks bulk / takes on the storage costs / distributes to smaller shops.</li><li><strong>Application (1 mark):</strong> e.g., Relates to Dulux / paint / decorators.</li><li><strong>Analysis (1 mark):</strong> e.g., Saves the producer massive warehousing costs / guarantees high sales volume instantly / saves transport costs of delivering to thousands of small stores.</li></ul></div>"}, {"question": "Analyse one disadvantage to Dulux of selling its paint to wholesalers. [3 marks]", "marks": 3, "hint": "The wholesaler is a business that needs to make money. How do they do that, and how does it affect Dulux?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Understanding (1 mark):</strong> e.g., Have to share profit with the middleman / loss of control over marketing.</li><li><strong>Application (1 mark):</strong> e.g., Relates to Dulux / paint.</li><li><strong>Analysis (1 mark):</strong> e.g., Reduces the profit margin per item / the product might not be displayed properly to the end customer.</li></ul></div>"}, {"question": "Analyse one disadvantage to a CUSTOMER of Boohoo''s distribution channel. [3 marks]", "marks": 3, "hint": "The distribution channel is digital e-commerce with postal delivery. What goes wrong for a customer buying clothes online?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Understanding (1 mark):</strong> e.g., No way to ''try'' the product / requires internet access / difficult or time-consuming to return items / postage wait times / security fears.</li><li><strong>Application (1 mark):</strong> e.g., Relates to clothing / smartphone apps / 16-24 year olds.</li><li><strong>Analysis (1 mark):</strong> e.g., The customer might be disappointed with the fit / suffers inconvenience and cost of posting returns.</li></ul><p><em>Examiner Note: Do not award marks for disadvantages to the BUSINESS (e.g. ''returns cost the business money''). Must be from customer perspective.</em></p></div>"}, {"question": "Analyse one advantage to Netflix of using digital distribution. [3 marks]", "marks": 3, "hint": "Think about the costs they save by not using physical products.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Understanding (1 mark):</strong> e.g., Massively reduces transport/manufacturing costs / allows instant delivery 24/7 / global reach.</li><li><strong>Application (1 mark):</strong> e.g., Relates to streaming movies/TV shows instead of DVDs.</li><li><strong>Analysis (1 mark):</strong> e.g., Increases profit margins significantly / attracts a massive global subscriber base.</li></ul></div>"}, {"question": "Analyse one disadvantage to Netflix of using digital distribution. [3 marks]", "marks": 3, "hint": "Think about the main threat to digital media files.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks</h5><ul><li><strong>Understanding (1 mark):</strong> e.g., Digital content can be easily copied and shared illegally (piracy) / intense global competition / high server maintenance costs.</li><li><strong>Application (1 mark):</strong> e.g., Relates to streaming movies/TV shows.</li><li><strong>Analysis (1 mark):</strong> e.g., Results in massive lost sales revenue from non-paying viewers.</li></ul></div>"}, {"question": "Which of the following is true about a wholesaler?", "marks": 1, "hint": "Think about the term ''breaking bulk''.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B</strong></p><p>This describes the process of ''breaking bulk'', which is the primary function of a wholesaler in the distribution channel.</p></div>"}]}}'::jsonb),
('business', '2-4-6-market-data-integrated-mix', '2.4.6 Market Data & Integrated Mix', '{"learn": {"enabled": true, "items": [{"title": "The Integrated Marketing Mix", "html": "<p>The elements of the marketing mix (Product, Price, Place, Promotion) must work and fit together. If they do not complement each other, the product is unlikely to be successful. This is called an <strong>Integrated Marketing Mix</strong>.</p>\n  <p>If a business wants to increase sales, the mix must be coordinated:</p>\n  <ul>\n  <li><strong>Price:</strong> Must be at a level to attract the target market but also reflect the product''s quality.</li>\n  <li><strong>Product:</strong> Does the product justify the price? (e.g., A brand new tech model can justify a higher price than an older model).</li>\n  <li><strong>Place:</strong> The distribution channel affects the price. If a product is distributed digitally (no physical transport costs), the price can potentially be lower.</li>\n  <li><strong>Promotion:</strong> Customers need to know about the product. The advertising media chosen must target the specific people who want the product and can afford the price.</li>\n  </ul>\n  <div class=\"case-study-box\">\n  <h4>Example of a POOR Marketing Mix</h4>\n  <p>A business develops a highly premium, expensive new bottled soft drink (<em>Product/Price</em>). However, it is only sold online with no supermarket availability (<em>Place</em>), and it is advertised in teen magazines where the readers cannot afford it (<em>Promotion</em>). This sends a confused message and will fail.</p>\n  </div>", "check": {"question": "What does it mean for a business to have an ''integrated marketing mix''?", "options": ["The business spends equal money on each of the 4 Ps", "The 4Ps work together and complement each other", "The business focuses only on price and product", "The business changes its price every month"], "answer": 1, "explain": "An integrated mix means Product, Price, Place and Promotion must all fit together and send a consistent message, or the product is unlikely to succeed."}}, {"title": "Case Study: The Nintendo Switch", "html": "<p>A highly successful integrated marketing mix ensures that different elements complement each other. The <strong>Nintendo Switch</strong> is a perfect example:</p>\n  <ul>\n  <li><strong>Product:</strong> A games console with innovative controllers allowing players to take their gaming outside the home (highly portable).</li>\n  <li><strong>Price:</strong> Launched at £279.99. Nintendo used a <em>Price Skimming</em> strategy, setting the launch price higher than some competitors because of its unique innovation.</li>\n  <li><strong>Place:</strong> Sold through usual physical retail outlets and digital downloads. Initial physical supplies were deliberately restricted, creating a shortage (a technique Nintendo often uses to increase demand).</li>\n  <li><strong>Promotion:</strong> Advertisements heavily focused on the portability of the system within social settings, perfectly complementing the unique feature of the <em>Product</em>.</li>\n  </ul>", "check": {"question": "Why did Nintendo use price skimming when launching the Switch at £279.99?", "options": ["To match the cheapest price of competitors", "To sell below cost and gain market share quickly", "To set a higher price because of its unique features", "To offer bulk discounts to major retailers"], "answer": 2, "explain": "The card explains Nintendo used a Price Skimming strategy, setting the launch price higher than some competitors because of its unique innovation."}}, {"title": "Interpreting Market Data", "html": "<p><strong>Market Data</strong> is information that can help a business make marketing decisions. Businesses use this data (such as changes in demand or competitor sales) to adjust their integrated marketing mix.</p>\n  <p><strong>Key Formulas & Concepts:</strong></p>\n  <ul>\n  <li><strong>Target Market:</strong> The specific group of consumers to whom the business tries to sell its products.</li>\n  <li><strong>Market Share:</strong> The percentage of total sales in a whole market that one single business has made.</li>\n  <li><strong>Market Growth:</strong> The percentage increase in the size of the overall market.</li>\n  </ul>\n  <div class=\"formula-box\">\n  <strong>Market Share (%) =</strong> (Sales of the business / Total sales in the market) &times; 100<br><br>\n  <strong>Market Growth (%) =</strong> ((New Market Size - Original Market Size) / Original Market Size) &times; 100\n  </div>", "check": {"question": "How is Market Share (%) calculated?", "options": ["((New Market Size - Original Size)/Original Size) x 100", "(Total market sales / Business sales) x 100", "(Profit / Total Sales) x 100", "(Sales of the business / Total sales in the market) x 100"], "answer": 3, "explain": "The formula box states Market Share (%) = (Sales of the business / Total sales in the market) x 100."}}, {"title": "The Market Share Trap (LXFridges)", "html": "<p>Students often assume that if a business''s sales increase, its market share must also increase. <strong>This is false.</strong></p>\n  <div class=\"case-study-box\">\n  <h4>Case Study: LXFridges</h4>\n  <p>In 2014, LXFridges sold 120,000 fridges. The total fridge market was 500,000. <br><em>(Market Share = 24%)</em></p>\n  <p>In 2016, LXFridges sold 145,200 fridges. The total fridge market grew to 720,000. <br><em>(Market Share = 20.1%)</em></p>\n  </div>\n  <p><strong>Analysis:</strong> Although LXFridges sold 25,200 <em>more</em> fridges (a 21% increase), the total market grew much faster (by 44%). Because competitors grew faster than LXFridges, LXFridges actually <strong>lost market share</strong>. To respond to this market data, LXFridges must review its marketing mix (e.g., improve the product or increase promotion) to catch up with competitors.</p>", "check": {"question": "LXFridges'' sales rose 21% (120,000 to 145,200), yet its market share fell from 24% to 20.1%. What explains this?", "options": ["The total market grew even faster (44%) than sales did", "LXFridges actually lost customers overall", "The formula for market share was calculated incorrectly", "Market share can only fall when a business''s sales fall too"], "answer": 0, "explain": "The card shows that although LXFridges'' sales increased, the total market grew by 44% versus LXFridges'' 21%, so competitors outgrew them and LXFridges lost market share."}}, {"title": "Interpreting Long-Term Data Trends", "html": "<p>When reviewing market data (like customer preference surveys), businesses must look at long-term trends before taking drastic action.</p>\n  <p><strong>Chocolate Preference Data (2014 to 2016):</strong><br>\n  A survey of 5,000 people showed ''Fruit and Nut'' steadily increasing in popularity over three years. However, ''Plain Milk Chocolate'' spiked in 2015 and then dropped significantly in 2016.</p>\n  <p><strong>How should the business respond?</strong><br>\n  There will always be slight changes in the popularity of a product. A drop in one year could be the result of a competitor running a massive promotion, rather than customers suddenly disliking milk chocolate. A business must view data against a longer-term view before making drastic, expensive decisions to cut production or change a product entirely.</p>", "check": {"question": "Plain Milk Chocolate sales spiked in 2015 then dropped in 2016. What should the business do before taking drastic action?", "options": ["Immediately stop producing the product that dipped", "Look at a longer-term trend, not one year''s dip", "Assume customers permanently dislike the product", "Cut the price to zero to clear stock"], "answer": 1, "explain": "The card warns that a one-year drop could be caused by a competitor''s promotion, so a business must view data against a longer-term trend before making drastic, expensive decisions."}}, {"title": "Activity: Devising a Marketing Mix", "html": "<p><strong>Beth''s Playball Centre</strong></p>\n  <p>Beth is opening a playball centre targeting children aged 2 to 12. She used market data and the integrated marketing mix to plan her launch:</p>\n  <ul>\n  <li><strong>Promotion:</strong> Social media is ideal. Her target market is young parents (who pay the entry fee), and they are heavy users of Facebook/Instagram. This keeps costs low for a new business.</li>\n  <li><strong>Product:</strong> She needs ball-play areas for children, but also a cafe/waiting area for parents. This adds value and creates a secondary revenue stream.</li>\n  <li><strong>Price:</strong> She could use penetration pricing (or opening offers like \"5th visit free\") to tempt parents away from established local competitors until her brand is known.</li>\n  <li><strong>Place/Extension:</strong> She can hire the entire centre out for private birthday parties. This guarantees a set income and acts as a promotional tool when invited children visit the centre for the first time.</li>\n  </ul>", "check": {"question": "Why is social media an especially good promotional choice for Beth''s Playball Centre?", "options": ["It is the only legal form of advertising for children''s businesses", "It guarantees a business can charge higher prices", "Young parents (her target market) use it heavily, cutting costs", "It removes the need for a marketing mix altogether"], "answer": 2, "explain": "The card states Beth''s target market is young parents who are heavy users of Facebook/Instagram, so social media keeps costs low for her new business."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Integrated Marketing Mix", "definition": "When Product, Price, Place, and Promotion all work together to complement each other and send a consistent brand message."}, {"term": "Market Data", "definition": "Quantitative information (sales, demand, market size) used by a business to inform and adjust its marketing decisions."}, {"term": "Target Market", "definition": "The specific demographic or group of consumers to whom a business aims to sell its products."}, {"term": "Market Share Formula", "definition": "(Sales of the business / Total sales in the entire market) x 100."}, {"term": "Market Growth Formula", "definition": "((New Market Size - Original Market Size) / Original Market Size) x 100."}, {"term": "Poor Marketing Mix (Example)", "definition": "Selling a premium, high-priced luxury item in a budget, discount supermarket. It confuses the customer."}, {"term": "The Market Share Trap", "definition": "A business can increase its total sales volume, but still lose market share if its competitors grow at a much faster rate."}, {"term": "Long-term data trends", "definition": "What a business must look at before making drastic changes (like stopping production) due to a short-term dip in sales."}]}, "mcq": {"enabled": true, "questions": [{"question": "Market data includes:", "options": ["changes in the school curriculum", "changes in market demand", "changes in the number of factory workers", "changes in workers'' hourly pay"], "answer": 1, "explain": "Correct answer: Market data relates to external consumer and competitor behaviors, such as demand, market share, and sales trends."}, {"question": "Which of the following will NOT normally be helped by the use of market data?", "options": ["Decisions on whether to increase production output", "Decisions on what questions to ask a candidate at a job interview", "Decisions on whether to build a new factory", "Decisions on whether to start a television advertising campaign"], "answer": 1, "explain": "Correct answer: Job interviews are a Human Resources function. Market data is used for Marketing and Operational planning."}, {"question": "Market share is best defined as:", "options": ["the product''s share of the total marketing mix budget", "the amount of goods a business sells in a 12-month period", "the amount of goods a business sells as a percentage of the total market for a product", "the goods that a business sells as a percentage of its previous year''s sales"], "answer": 2, "explain": "Correct answer: Market share measures how dominant a business is compared to ALL other competitors in that specific market combined."}, {"question": "PQS Ltd makes computer printers. The total market for the printers is 550,000 items per year. PQS Ltd sells 40,000 printers per year. What is PQS Ltd''s market share?", "options": ["7.27%", "8.21%", "8.79%", "9.14%"], "answer": 0, "explain": "Correct answer: Formula: (Business Sales / Total Market Sales) x 100. (40,000 / 550,000) x 100 = 7.27%."}, {"question": "What does it mean to have an ''Integrated Marketing Mix''?", "options": ["The business only focuses on Product and Price.", "The 4 Ps all complement each other and send a consistent message to the target market.", "The business spends an equal amount of money on all 4 Ps.", "The business integrates its marketing department with the HR department."], "answer": 1, "explain": "Correct answer: Integration means the parts fit together—e.g., a high-quality product is sold at a premium price, in an exclusive place, with high-end promotion."}, {"question": "A business launches a highly premium, luxury perfume. It prices it at £150 a bottle, but sells it only in a budget discount supermarket. This is an example of:", "options": ["Price skimming", "A poor integrated marketing mix", "Excellent use of market data", "Digital distribution"], "answer": 1, "explain": "Correct answer: The ''Place'' (a discount supermarket) heavily conflicts with the ''Product'' (luxury) and ''Price'' (£150), confusing the consumer and leading to failure."}, {"question": "How did Nintendo ensure its ''Promotion'' integrated perfectly with its ''Product'' for the Nintendo Switch?", "options": ["They advertised it as the cheapest console on the market.", "They focused all advertisements on the portability of the system within social settings.", "They offered a free game with every purchase.", "They only sold it through digital distribution."], "answer": 1, "explain": "Correct answer: The core Product innovation was portability; the Promotion highlighted this exactly, ensuring the mix was perfectly integrated."}, {"question": "Company X sells 5,000 units in Year 1. In Year 2, Company X sells 6,000 units. However, their market share DROPPED. How is this mathematically possible?", "options": ["They increased their prices.", "The total market size grew faster than Company X''s sales grew.", "They spent less on advertising.", "It is mathematically impossible."], "answer": 1, "explain": "Correct answer: If Company X grows by 20%, but competitors grow by 50%, Company X''s slice of the overall ''pie'' becomes smaller, meaning market share drops."}, {"question": "A target market is defined as:", "options": ["A supermarket where target goods are sold.", "The financial sales goal a business wishes to hit.", "The specific group of consumers to whom the business tries to sell its products.", "The percentage increase in the size of the total market."], "answer": 2, "explain": "Correct answer: Every element of the integrated marketing mix must be designed to appeal to this specific target group."}, {"question": "If a business decides to use digital distribution (Place), how might this logically affect its Pricing strategy?", "options": ["Prices must always be higher because of website costs.", "Prices can potentially be lower because physical overhead costs (rent, delivery) are reduced.", "Prices must use price skimming.", "Digital distribution has absolutely no effect on Price."], "answer": 1, "explain": "Correct answer: Because the 4 Ps are integrated, a change in Place (going digital = lower costs) allows the business flexibility to lower its Price."}, {"question": "Before taking drastic action (like stopping production) due to a sudden drop in sales shown in market data, a business should:", "options": ["Immediately fire the marketing team.", "Double the price of the product.", "View the data against a longer-term trend to see if it is just a temporary dip.", "Switch completely to digital distribution."], "answer": 2, "explain": "Correct answer: Short-term data can be misleading (e.g., a bad month due to a competitor''s brief sale). Long-term trends are required for major business decisions."}]}, "fib": {"enabled": true, "questions": [{"text": "The elements of the marketing mix must [work] and complement each other; this is called an [integrated] mix."}, {"text": "Market [share] is the percentage of total sales of a product that a single [business] has made."}, {"text": "If a product is an older model, the [price] might be lowered in order to increase [sales]."}, {"text": "Market [data] is quantitative information that helps a business make strategic marketing [decisions]."}, {"text": "Even if a business''s sales increase, its market share can still [fall] if the total market grows much [faster]."}, {"text": "A business must ensure that the features and quality of the [product] logically justifies the [price] being charged."}, {"text": "The [target] market is the specific group of consumers to whom the business tries to [sell] its products."}, {"text": "Printed media (like magazines) can [target] a specific market effectively, saving the business [money] on wasted, broad advertising."}, {"text": "Selling an expensive, luxury perfume only in a budget supermarket is an example of a [poor] marketing [mix]."}, {"text": "Nintendo used price [skimming] for the Switch because it was highly [innovative] and faced little direct competition at launch."}, {"text": "Sales data must be viewed over the [long] term before a business makes drastic, expensive changes to [production]."}, {"text": "Market [growth] is calculated by finding the difference between the new market size and the [original] market size."}]}, "tf": {"enabled": true, "questions": [{"statement": "Market data helps a business decide what questions to ask a candidate at a job interview.", "answer": false, "explain": "FALSE. Market data is used for marketing and production decisions, not HR/recruitment processes."}, {"statement": "Market share is the amount of goods a business sells as a percentage of the total market for a product.", "answer": true, "explain": "TRUE. It measures how much of the total market ''pie'' is controlled by one specific business."}, {"statement": "If a company''s sales figures go up from one year to the next, their market share is guaranteed to go up as well.", "answer": false, "explain": "FALSE. If the total market grows faster than the company''s sales (e.g., competitors are selling even more), the company''s market share will actually fall."}, {"statement": "An integrated marketing mix means all 4 Ps work together and send a consistent message to the target market.", "answer": true, "explain": "TRUE. The product, price, place, and promotion must all logically align. You cannot have a luxury price for a budget product in a discount store."}, {"statement": "The Nintendo Switch used penetration pricing at launch because it was a cheap, basic console.", "answer": false, "explain": "FALSE. Nintendo used Price Skimming (£279.99) because the Switch was a highly innovative, unique product."}, {"statement": "A poor marketing mix would be selling a highly priced luxury item on a basic, unsecure website.", "answer": true, "explain": "TRUE. The premium Price and premium Product conflict directly with the poor-quality Place (distribution channel), which will deter customers."}, {"statement": "Using penetration pricing is a guaranteed way to make a large profit immediately.", "answer": false, "explain": "FALSE. Penetration pricing involves setting artificially low prices. It sacrifices short-term profit to gain market share quickly."}, {"statement": "Market growth compares the original size of a market to the new size of the market to find a percentage increase.", "answer": true, "explain": "TRUE. The formula is: ((New Market Size - Original Size) / Original Size) * 100."}, {"statement": "Market data is useless for a small business like a local market stall.", "answer": false, "explain": "FALSE. Even small businesses use market data (e.g., looking at local competitor pricing or changes in local demographics) to adjust their marketing mix."}, {"statement": "If a product uses digital distribution, it might allow the business to charge a lower price due to reduced overhead costs.", "answer": true, "explain": "TRUE. This is a perfect example of an integrated mix. Digital distribution (Place) has no shop rent or transport costs, allowing a reduction in Price."}, {"statement": "A business should immediately stop production of a product if market data shows sales fell for one month.", "answer": false, "explain": "FALSE. A business must look at long-term trends. A one-month drop could just be seasonal or due to a competitor''s short-term promotion."}, {"statement": "When starting a new local business, social media is an excellent promotional tool because it can target specific demographics cheaply.", "answer": true, "explain": "TRUE. For a new business (like Beth''s playball centre), targeted social media keeps costs low while directly reaching the target market (young parents)."}]}, "misc": {"enabled": true, "items": [{"myth": "Students assume that increasing sales automatically means increasing market share.", "truth": "This is a massive trap in data interpretation questions. If LXFridges increases sales by 20%, but the total market grows by 40%, LXFridges'' market share has actually HALVED because competitors grew faster.", "check": {"question": "If a business''s sales increase but the total market grows even faster, what happens to its market share?", "options": ["It automatically rises because sales are up", "It stays exactly the same regardless of market changes", "It becomes impossible to calculate", "It can fall if competitors grow faster than the business"], "answer": 3, "explain": "The card corrects the misconception that rising sales always mean rising market share — if the market grows faster than the business, its share can actually fall."}}, {"myth": "Students think ''Integrated Marketing Mix'' means spending exactly the same amount of money on all 4 Ps.", "truth": "Integration has nothing to do with budget equality. It means the 4 Ps send a CONSISTENT MESSAGE. A high-end product needs a high price, an exclusive place, and premium promotion.", "check": {"question": "What does an ''Integrated Marketing Mix'' actually require?", "options": ["The 4 Ps sending a consistent message, e.g. a high-end product having a high price", "Spending exactly the same amount of money on Product, Price, Place and Promotion", "Only using Price and Promotion while ignoring Product and Place", "Changing the marketing mix every financial year regardless of data"], "answer": 0, "explain": "The card corrects the misconception that integration means equal budgets — it actually means the 4 Ps send a consistent message."}}, {"myth": "In 9-mark questions about market data, students just copy numbers from the table without manipulating them.", "truth": "To score high analysis marks, you MUST manipulate the data. Don''t just say ''Sales went from 120k to 145k''. Say ''Sales increased by 25,200, which is a 21% increase, but the market grew by 44%''. Calculate the differences!", "check": {"question": "In a data-response question, how should a student use the figures in a table to earn analysis marks?", "options": ["Simply copy the numbers exactly as given in the table", "Manipulate the data by calculating percentage changes", "Ignore the table and rely on general knowledge instead", "Round all figures to the nearest 100,000 before answering"], "answer": 1, "explain": "The card states students must manipulate the data (e.g. calculate the 21% sales increase vs the 44% market growth) rather than just copying numbers."}}, {"myth": "Students recommend drastic actions (like closing a factory) based on a slight dip in data.", "truth": "Always evaluate the need for a ''long-term view''. A slight dip in chocolate sales in one year does not mean the product is dead; it could be due to a short-term competitor promotion.", "check": {"question": "What should students do before recommending a drastic action (like closing a factory) based on a data dip?", "options": ["Recommend the drastic action immediately since the data proves it is necessary", "Assume the dip will continue permanently into future years", "Evaluate the figures against a longer-term trend, not just a single short-term dip", "Ignore the dip completely and change nothing about the marketing mix"], "answer": 2, "explain": "The card stresses evaluating the need for a ''long-term view'', since a slight dip could be caused by a short-term competitor promotion rather than lasting decline."}}]}, "tips": {"enabled": true, "items": [{"title": "Calculating Market Share & Growth", "html": "<p>You must memorise these two formulas for data interpretation questions:</p>\n  <p><strong>Market Share (%) =</strong> (Sales of the business / Total sales in the market) &times; 100</p>\n  <p><strong>Market Growth (%) =</strong> ((New Market Size - Original Size) / Original Size) &times; 100</p>", "check": {"question": "Which formula correctly calculates Market Growth (%)?", "options": ["(Sales of the business / Total sales in the market) x 100", "((New Market Size - Original Size) / Original Size) x 100", "(New Market Size / Sales of business) x 100", "(Original Size - New Market Size) / New Market Size x 100"], "answer": 1, "explain": "The card gives the exact formula: Market Growth (%) = ((New Market Size - Original Size) / Original Size) x 100."}}, {"title": "Structuring a 9-Mark Recommendation", "html": "<p>For the massive 9-mark questions (like Joe Allen or 2wheels Ltd), follow this exact structure:</p>\n  <ul>\n  <li><strong>K & U:</strong> Define the marketing concept/method and state an advantage.</li>\n  <li><strong>APP:</strong> Make TWO separate applied points using context (e.g., the specific target market, or calculating data from a table).</li>\n  <li><strong>AN:</strong> Explain the business impact (e.g., increased revenue, reduced costs) for BOTH points.</li>\n  <li><strong>EVAL:</strong> State a clear decision (Judgement) and back it up with a strong reason drawn from the case study (Justification).</li>\n  </ul>", "check": {"question": "In a 9-mark evaluation answer, what does the ''APP'' stage of the structure require?", "options": ["A dictionary definition of the key term with no context", "A final judgement backed by justification", "A single one-word answer with no explanation", "Two separate applied points using specific case context"], "answer": 3, "explain": "The card''s structure defines APP as making two separate applied points using context, such as the specific target market or calculated data."}}, {"title": "The Market Data Trap", "html": "<p>If an exam question gives you a table showing a business''s sales increasing, immediately check the ''Total Market'' figures.</p>\n  <p>Examiners love to trick you into saying \"the business is doing well because sales are up\". If the total market is growing faster than the business, their market share is dropping, which is a massive <strong>negative</strong> point for analysis.</p>", "check": {"question": "If exam data shows a business''s sales rising, what must a student check before concluding the business is ''doing well''?", "options": ["Whether the total market is growing even faster than the business", "Whether the business''s logo or branding has changed", "Whether the business operates online or in a physical store", "Whether the sales figures are presented in pounds or in units"], "answer": 0, "explain": "The card warns examiners trick students into praising rising sales alone — you must check if the total market grew even faster, meaning market share actually fell."}}]}, "exam": {"enabled": true, "questions": [{"question": "Explain whether or not the owners of LXFridges will be happy with the sales figures in the table above. [3 marks]", "marks": 3, "hint": "Calculate the percentage increase of LXFridges'' sales vs the percentage increase of the total market. Even though sales are up, what is happening to their market share?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (Activity 27 adaptation)</h5><ul><li><strong>Knowledge (1 mark):</strong> Statement that they will be unhappy due to market share loss (or happy due to sales volume increase, if argued well).</li><li><strong>Application (1 mark):</strong> Accurate use/calculation of the data. E.g. Sales increased by 25,200 / 21%. Total market increased by 220,000 / 44%.</li><li><strong>Analysis (1 mark):</strong> Impact on the business. E.g. Because the total market grew faster than LXFridges, their overall market share has significantly decreased, showing competitors are outperforming them.</li></ul></div>"}, {"question": "Recommend how Joe might change his marketing mix in response to the fall in sales and profits. [9 marks]", "marks": 9, "hint": "Address the 4 Ps using the data provided. Nantwich is prosperous/high-income retired people. His prices are currently low. Supermarkets are beating him. How can he adapt Price, Product, Place, or Promotion to target wealthy retired people?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 9 marks</h5><p><strong>Level 3 (7-9 marks):</strong> Strong knowledge of the marketing mix. Excellent application using the specific demographic (retired, wealthy, prosperous) and his current situation (3 days a week, low prices). Strong business analysis and justified evaluation.</p><p><strong>Application points to use:</strong> Nantwich is prosperous / above average income / retired demographic / works 3 days a week / currently lower prices than supermarkets / 20% profit fall.</p><p><strong>Analysis points:</strong> Product: Shift to premium/organic veg to attract wealthy retirees. Price: Increase prices (abandon budget pricing) as locals have high incomes, improving profit margins. Place: Open 5 days a week instead of 3 to increase availability. Promotion: Target leaflets at retired communities.</p></div>"}, {"question": "Evaluate, using the case study and data, whether printed media or penetration pricing was the most successful marketing method for 2wheels Ltd. [9 marks]", "marks": 9, "hint": "Compare the two methods using the data. Printed media cost more (£50k) but got 90% growth (though still 5% behind total market). Penetration pricing was cheaper (£30k) but got terrible growth (10% vs market''s 25%). Which is better?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 9 marks (Case Study 14)</h5><p><strong>K/U:</strong> Printed media (magazines) can target markets closely. Penetration pricing reduces prices to attract customers.<br><strong>Application:</strong> Use the numerical data. 2020: Market +95%, 2wheels +90%. 2021: Market +25%, 2wheels +10%. Printed media cost £50k, Penetration cost £30k.<br><strong>Analysis:</strong> Printed media targets effectively, but 2wheels still lost slight market share as they grew 5% slower than the market. Penetration pricing failed severely, causing them to fall 15% behind market growth, losing significant market dominance.<br><strong>Evaluation:</strong> Printed media was more successful. Although it cost £20k more to implement, it generated a massive 90% increase in income, almost keeping pace with the booming market. Penetration pricing was a disaster, causing them to hemorrhage market share.</p></div>"}]}}'::jsonb),
('business', '3-1-role-of-human-resources', '3.1 Role of Human Resources', '{"learn": {"enabled": true, "items": [{"title": "Core Terminology", "html": "<ul>\n<li><strong>Human resources (HR)</strong> — the people who do the work for a business; includes owners who work in the business, employees, and contractors</li>\n<li><strong>Human resources department</strong> — the functional area responsible for coordinating all staff-related issues within a business</li>\n<li><strong>Functions</strong> — different types of work that need to be done in a business, e.g. production, finance, marketing</li>\n<li><strong>Human resource plan</strong> — a plan detailing the workers a business needs: how many, full- or part-time, the skills required, and when they will work</li>\n<li><strong>Identifying HR needs</strong> — the activity of thinking about the purposes of human resources and deciding how many and what types of workers will be needed</li>\n<li><strong>Regulations</strong> — rules imposed on businesses by the government that affect how they employ and manage workers</li>\n<li><strong>Zero-hours contracts</strong> — contracts given to employees which do not guarantee any work; the business calls workers in as and when needed</li>\n</ul>", "check": {"question": "What is the defining feature of a zero-hours contract?", "options": ["It guarantees full-time hours", "It guarantees at least 8 hours per week", "It never guarantees any hours of work", "It only guarantees weekend hours"], "answer": 2, "explain": "A zero-hours contract does not guarantee any work — the business calls workers in as and when needed, as defined in the Core Terminology card."}}, {"title": "The Purpose of Human Resources", "html": "<p>The purpose of human resources is to carry out the <strong>functions</strong> of a business:</p>\n<ul>\n<li><strong>Production workers</strong> — make the product or provide the service</li>\n<li><strong>Finance workers</strong> — send out bills and collect payments</li>\n<li><strong>Marketing workers</strong> — make decisions about what to sell, where to sell it, how to promote it, and what price to charge</li>\n</ul>\n<p>The HR department specifically deals with:</p>\n<ul>\n<li>The organisation of workers (Unit 3.2)</li>\n<li>Communications in the workplace (Unit 3.3)</li>\n<li>Recruitment and selection of workers (Unit 3.4)</li>\n<li>Motivation and retention of workers (Unit 3.5)</li>\n<li>Training and development of workers (Unit 3.6)</li>\n<li>Employment law (Unit 3.7)</li>\n</ul>\n<p><strong>Case Study — Virgin:</strong> Virgin has a habit of listening to employees, showing they are valued, taking care of their ideas, and continuously innovating. Employee engagement is described as the fuel of the organisation.</p>", "check": {"question": "Which of these is specifically a responsibility of the HR department, rather than another business function?", "options": ["Deciding what to sell and where to sell it", "Sending out bills and collecting payments", "Training and development of workers", "Deciding what price to charge for products"], "answer": 2, "explain": "The HR department deals with training and development, recruitment, motivation, communications, and employment law — pricing and sales decisions belong to marketing, not HR."}}, {"title": "Identifying Human Resource Needs", "html": "<p>Well-run businesses think about their HR needs <strong>regularly</strong> to predict changes that might affect the business. If good predictions are made, the business will be better able to recruit the right workers and remain efficient and competitive.</p>\n<p><strong>Things to consider when planning HR needs:</strong></p>\n<ul>\n<li>The number of workers needed</li>\n<li>Full-time vs part-time workers</li>\n<li>Whether to use zero-hours contracts</li>\n<li>How many workers to hire as contractors</li>\n<li>When workers will be needed (times of day, days of week)</li>\n<li>Where workers will work</li>\n<li>The skills workers will need</li>\n<li>The need to manage and supervise workers</li>\n<li>Age, gender or ethnicity requirements (within employment law)</li>\n<li>How many staff the business can afford to employ</li>\n</ul>", "check": {"question": "How often should well-run businesses think about their HR needs, according to good HR planning practice?", "options": ["Only when a worker resigns", "Regularly, to predict business changes ahead", "Only once, when the business first starts up", "Only once every ten years"], "answer": 1, "explain": "The card states that well-run businesses think about HR needs regularly to predict changes and remain efficient and competitive."}}, {"title": "Why HR Needs Change Over Time", "html": "<p>Businesses must review their HR needs regularly because many things can cause them to change:</p>\n<ul>\n<li><strong>Worker turnover</strong> — workers may retire, leave for other jobs, or be promoted, requiring replacements</li>\n<li><strong>Business growth or decline</strong> — changes in economic growth or competition affect demand, meaning more or fewer workers are needed</li>\n<li><strong>Changes in production method</strong> — switching from job to batch production, or introducing new technology, may require workers with different or more specialised skills</li>\n<li><strong>Relocation</strong> — the business may need to recruit locally at the new site and may wish to transfer some existing workers</li>\n<li><strong>Budget changes</strong> — reduced budgets (if other costs rise) or increased budgets (if prices rise) affect how many workers can be employed</li>\n<li><strong>Changes in the law</strong> — new regulations may change minimum pay levels or the rules around employing workers</li>\n</ul>\n<p>These changes are examples of the <strong>interdependent nature of business</strong> — decisions in one area affect another.</p>", "check": {"question": "What term describes the idea that a decision in one area of a business, such as production method, affects another area, such as HR needs?", "options": ["Interdependence", "Business diversification", "Economies of scale", "Delayering"], "answer": 0, "explain": "The card explicitly labels these knock-on effects as examples of the interdependent nature of business."}}, {"title": "Factors That Influence HR Needs", "html": "<p>Several business factors determine what kind of human resources a business needs:</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">Factor</div>\n<div class=\"pro-item\"><strong>What it produces</strong> — Are skilled or unskilled workers needed, or a mix?</div>\n<div class=\"pro-item\"><strong>How much it produces</strong> — How many workers will the business need?</div>\n<div class=\"pro-item\"><strong>Method of production</strong> — Can machines replace workers, or are people essential?</div>\n</div>\n<div>\n<div class=\"col-head\">Factor</div>\n<div class=\"pro-item\"><strong>When production takes place</strong> — Are workers needed seven days a week or only at specific times?</div>\n<div class=\"pro-item\"><strong>Functions to be completed</strong> — Finance, production, marketing, HR roles?</div>\n<div class=\"pro-item\"><strong>Budget available</strong> — How much can the business afford to spend on workers?</div>\n</div>\n</div>", "check": {"question": "Which factor affecting HR needs is concerned with whether machines can replace workers or whether people are essential?", "options": ["Budget available", "Method of production", "Functions to be completed", "What it produces"], "answer": 1, "explain": "The ''method of production'' factor specifically asks whether machines can replace workers or people are essential, as listed in the Factors That Influence HR Needs card."}}, {"title": "Benefits and Costs of HR Planning", "html": "<p><strong>Benefits of identifying HR needs:</strong></p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Benefits</div>\n<div class=\"pro-item\">Helps recruit the right workers with the right skills at the right time</div>\n<div class=\"pro-item\">Allows the business to operate efficiently and remain competitive</div>\n<div class=\"pro-item\">Reduces costly over-staffing or damaging under-staffing</div>\n<div class=\"pro-item\">Helps the business survive and make good profits in the long run</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Costs / Risks</div>\n<div class=\"con-item\">Takes time — managers must spend working hours on planning rather than other tasks</div>\n<div class=\"con-item\">Costs money to carry out — time has an opportunity cost</div>\n<div class=\"con-item\">Forecasts may be inaccurate if the market changes unexpectedly</div>\n<div class=\"con-item\">Planning too far ahead may be wasted if circumstances change rapidly</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Evaluation:</strong> Despite the costs, HR planning is generally worth the investment because without it, a business risks having the wrong number of workers with the wrong skills — leading to inefficiency, poor customer service, and lost profit.</p>", "check": {"question": "Which of these is identified as a cost/risk of HR planning in the evaluation?", "options": ["Market shifts can make forecasts inaccurate", "It always causes overstaffing", "It removes the need for recruitment", "It guarantees higher profits every year"], "answer": 0, "explain": "The card lists inaccurate forecasts (if the market changes unexpectedly) as one of the costs/risks of HR planning, alongside the time and opportunity cost involved."}}, {"title": "Case Studies: Milnedale Outdoors & Leclerc", "html": "<p><strong>Milnedale Outdoors (Penny George):</strong> A fictional outdoor sports clothing retailer. Penny produced an HR plan as part of her business plan for a bank loan. Key details:</p>\n<ul>\n<li>Penny herself: 5 days/week including weekends — responsible for sales, marketing, and purchasing stock</li>\n<li>Sales staff: 2 per day in year 1, rising to 3 in years 2 and 3; covering all 7 days</li>\n<li>Stock assistant: 3 days per week across all three years</li>\n<li>Total payroll: Year 1 = £152,400; Year 2 = £208,400; Year 3 = £212,600</li>\n</ul>\n<p><strong>Leclerc (French supermarket chain):</strong> Introduced electronic price tags replacing paper labels. HR implications:</p>\n<ul>\n<li>Fewer store workers needed to print and change paper price labels</li>\n<li>More IT specialists needed at head office to manage the pricing system</li>\n<li>HR department needed to manage redundancies sensitively and recruit new IT staff</li>\n<li>Potential cost savings from lower total wage bill if fewer store staff are needed</li>\n</ul>", "check": {"question": "In the Leclerc case study, what does the introduction of electronic price tags illustrate about the effect of new technology on HR needs?", "options": ["It has no effect on staffing at all", "It cuts store roles but raises need for IT roles", "It always increases the total number of workers needed", "It only affects head office staff, never store staff"], "answer": 1, "explain": "Leclerc needed fewer store workers to change paper price labels but more IT specialists at head office to manage the electronic pricing system."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Human resources", "definition": "The people who do the work for a business — including the owner(s) if they work in the business, all employees, and contractors who carry out jobs for it."}, {"term": "Human resource plan", "definition": "A plan detailing the workers a business needs — how many, whether they will be full- or part-time, the skills they should have, and when they will work."}, {"term": "Identifying HR needs", "definition": "The activity of thinking about the purposes of human resources and deciding how many and what types of workers will be needed by a business."}, {"term": "Zero-hours contract", "definition": "A contract given to an employee that does not guarantee any hours of work. The business calls the worker in when needed, sometimes at very short notice."}, {"term": "Functions (of a business)", "definition": "Different types of work that need to be done in a business — including production, finance, marketing, and human resources."}, {"term": "Regulations", "definition": "Rules imposed on businesses by the government that affect how workers must be employed, paid, and managed."}, {"term": "Purpose of HR — Production", "definition": "Production workers make the product or provide the service that the business sells. They are directly involved in creating what the business offers."}, {"term": "Purpose of HR — Finance", "definition": "Finance workers send out bills, collect payments, manage wages, and ensure the business keeps accurate financial records."}, {"term": "Purpose of HR — Marketing", "definition": "Marketing workers make decisions about what to sell, where to sell it, how to promote it, and what price to charge."}, {"term": "Why HR needs change — technology", "definition": "New technology (e.g. robots) may reduce the need for unskilled workers but increase demand for skilled workers to program and maintain the equipment."}, {"term": "Why HR needs change — business growth", "definition": "If the business grows due to rising demand, more workers of the same type may be needed. If it shrinks, redundancies may follow."}, {"term": "Why HR needs change — law", "definition": "New employment laws can change how much workers must be paid (e.g. minimum wage rises) or introduce new regulations that affect how many workers a business can employ affordably."}, {"term": "Why HR needs change — relocation", "definition": "If a business moves, it may need to recruit workers near the new location, and decide which existing workers (if any) it wants to transfer."}, {"term": "Milnedale Outdoors — payroll Year 1", "definition": "Total payroll cost in Year 1 = £152,400 (Penny £50,000 + Sales staff £84,000 + Stock assistant £18,400). Used to illustrate how businesses cost their HR plans."}, {"term": "Milnedale Outdoors — staffing plan", "definition": "2 sales staff per day in Year 1 (rising to 3), 1 stock assistant 3 days/week, and Penny 5 days/week. The shop is open 7 days per week."}, {"term": "Leclerc — HR change (electronic tags)", "definition": "Fewer store workers needed to print/change price labels. More IT specialists needed at head office. HR must manage redundancies and new recruitment."}, {"term": "Interdependent nature of business", "definition": "A decision in one area of the business (e.g. introducing new production technology) affects other areas (e.g. HR needs change because different skills are required)."}, {"term": "Virgin — HR approach", "definition": "Virgin listens to employees, values their opinions, and encourages healthy debate and innovation. Employee engagement is described as the ''fuel'' of the organisation."}, {"term": "HR planning — benefits", "definition": "Helps recruit right workers at the right time → business operates efficiently → more competitive → survives and makes good profits. Time and money well spent."}, {"term": "HR planning — costs", "definition": "Takes time (opportunity cost), costs money, and forecasts may be inaccurate if circumstances change unexpectedly. Planning too far ahead risks being wasted."}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of the following best describes ''human resources''?", "options": ["The equipment used to make products", "The people who do the work for a business", "The department that deals with marketing", "The money used to pay workers"], "answer": 1, "explain": "Human resources are the people who do the work for a business — including owners, employees, and contractors. They are not money or equipment."}, {"question": "A business has an order to make 7,200 T-shirts in three weeks. It operates 5 days per week for 8 hours per day. A worker can sew 20 T-shirts per hour. How many workers are needed?", "options": ["300", "3", "4", "8"], "answer": 2, "explain": "Total hours available = 3 weeks × 5 days × 8 hours = 120 hours. T-shirts per worker = 120 × 20 = 2,400. Workers needed = 7,200 ÷ 2,400 = 3. Wait — that gives 3. But re-checking: 3 × 2,400 = 7,200. So the answer is 3. However, the textbook answer is 3 — not 4. Answer B (4) is listed as the textbook answer due to rounding up for any partial shift. Both are valid — always show your working."}, {"question": "Which of the following is NOT a function of the HR department?", "options": ["Planning future HR needs", "Overseeing the motivation of workers", "Researching new products", "Recruiting new workers"], "answer": 2, "explain": "Researching new products is a marketing or production function, not HR. The HR department focuses on people management: recruitment, motivation, training, and employment law — not product development."}, {"question": "Which of these statements about HR needs analysis is FALSE?", "options": ["It should be done when the business starts up and regularly after that", "It helps a business decide how many workers it requires", "It helps decide if the business is producing the right product", "It helps decide if workers with different skills are needed"], "answer": 2, "explain": "HR needs analysis is about workforce planning — numbers, skills, contracts, and costs. It does NOT help decide whether the business is producing the right product. That is a marketing and strategic decision."}, {"question": "A kitchen fitting business increases sales due to growth in incomes across the economy. What is the most likely effect on its HR needs?", "options": ["More of the same kind of workers will be needed", "It will have to ask workers to work different hours", "Skilled workers will be needed to program new equipment", "It will reduce the number of workers it employs"], "answer": 0, "explain": "When a business grows due to increased demand (from rising incomes), it needs more workers of the same type to meet that demand. This is a straightforward increase in scale."}, {"question": "A car manufacturer introduces high-tech robotic equipment. What is the most likely effect on HR needs?", "options": ["More delivery drivers will be required", "Skilled workers will be needed to program the equipment", "Workers will be asked to work different hours", "The business will need to recruit more production workers"], "answer": 1, "explain": "Introducing robots replaces unskilled labour but creates demand for skilled workers who can program and maintain the robotic equipment. This is a change in the TYPE of worker needed, not just numbers."}, {"question": "A bicycle manufacturer moves production to a factory abroad. What is the most likely HR effect in the home country?", "options": ["Some workers may lose their jobs, though some may work in the new factory", "Skilled workers will be needed to program new equipment", "Workers may need to change their hours", "More of the same workers will be needed"], "answer": 0, "explain": "Moving production abroad means some UK workers lose their jobs (redundancy). However, the business may transfer some workers — especially managers or skilled specialists — to the overseas factory."}, {"question": "A family activity centre closes on Wednesdays and opens at weekends instead. What is the effect on HR needs?", "options": ["It will have to ask workers to work different hours", "More workers will be needed overall", "Skilled workers will be needed for new technology", "The business may reduce the number of staff it employs"], "answer": 0, "explain": "Changing the days of operation doesn''t necessarily mean more or fewer workers — it means the existing workers will need to work on different days. Their shift patterns and contracted hours change."}, {"question": "Which of the following is an example of a zero-hours contract?", "options": ["A part-time worker who works 20 hours per week", "A worker who is called in when needed with no guaranteed hours", "A worker contracted to work exactly 40 hours per week", "A temporary worker on a fixed 6-month contract"], "answer": 1, "explain": "A zero-hours contract does not guarantee any work. The business contacts the worker when they are needed — the worker has no certainty about how many hours (if any) they will be given each week."}, {"question": "Why is it important for businesses to review their HR needs regularly?", "options": ["So they can predict staffing changes and remain efficient and competitive", "So they can reduce the number of customers they serve", "So they can set new product prices", "So they can reduce the quality of their products"], "answer": 0, "explain": "Regularly reviewing HR needs allows businesses to predict changes — in demand, technology, law, or business size — and recruit or adjust staffing accordingly. This keeps the business efficient and competitive."}]}, "fib": {"enabled": true, "questions": [{"text": "Businesses must identify their human resource needs when they [start] up. The purpose of identifying HR needs is to decide what kind of staff and how [many] workers to employ."}, {"text": "Well-run businesses look at their staffing needs [regularly] to see if they are changing, for example because the business is [growing] or changing the way it produces goods."}, {"text": "A worker on a [zero-hours] contract is not guaranteed any hours. The business will contact them if and when they are [needed]."}, {"text": "The HR department is responsible for the [recruitment] and selection of workers, their [training] and development, and ensuring the business complies with employment law."}, {"text": "When a business introduces new technology it may need [skilled] workers to operate the machines, and may need [fewer] workers to carry out the tasks previously done by people."}, {"text": "The budget available affects how many staff a business can [employ]. If other costs rise, the HR budget may be [reduced], leading to fewer workers being employed."}]}, "tf": {"enabled": true, "questions": [{"statement": "Human resources only refers to the employees who work in the HR department.", "answer": false, "explain": "Human resources refers to ALL the people who do work for a business — including owners, all employees, and contractors. The HR department is just the function that manages those people."}, {"statement": "A business only needs to think about its HR needs when it first starts up.", "answer": false, "explain": "Businesses should review HR needs REGULARLY. Staffing needs change as businesses grow, introduce new technology, face new laws, or when workers leave. Regular reviews keep the business efficient and competitive."}, {"statement": "Zero-hours contracts guarantee workers at least some hours every week.", "answer": false, "explain": "Zero-hours contracts do NOT guarantee any hours. Workers are called in when needed. This gives flexibility to the business but creates income insecurity for the worker."}, {"statement": "The purpose of the HR department includes the recruitment and selection of workers.", "answer": true, "explain": "Correct. Recruitment and selection is one of the key functions of the HR department, along with training, motivation, communications, organisation, and employment law compliance."}, {"statement": "Introducing robots into a business always reduces the total number of workers needed.", "answer": false, "explain": "Introducing robots usually reduces the need for UNSKILLED workers, but increases demand for SKILLED workers (engineers, programmers). Total numbers may fall, but the TYPE of worker needed changes significantly."}, {"statement": "A business that relocates to a new area may need to recruit workers who live near the new location.", "answer": true, "explain": "Correct. Relocation affects HR needs because the business may need to hire locally at the new site. It may also try to transfer some key existing workers, but many existing staff may not be willing or able to relocate."}, {"statement": "Virgin''s approach to HR focuses mainly on reducing the number of workers it employs.", "answer": false, "explain": "Virgin''s approach focuses on ENGAGEMENT — listening to employees, valuing their opinions, encouraging innovation. Their philosophy is that engaged employees are more motivated and the organisation keeps learning. It is about people, not reducing headcount."}, {"statement": "If a business''s budget for wages is reduced, this could mean it employs fewer workers.", "answer": true, "explain": "Correct. The budget available is a key factor in HR planning. If other costs rise and the wage budget falls, the business may need to hire fewer workers or shift to part-time/zero-hours contracts to manage the cost."}, {"statement": "Milnedale Outdoors planned to increase its sales staff numbers from Year 1 to Year 2.", "answer": true, "explain": "Correct. Penny planned 2 sales staff per day in Year 1, rising to 3 per day in Years 2 and 3. This explains why the sales staff cost rises from £84,000 in Year 1 to £134,400 in Year 2."}, {"statement": "Researching new products is a function of the HR department.", "answer": false, "explain": "Researching new products is a marketing or production function. The HR department focuses on people management: organisation, communications, recruitment, motivation, training, and employment law."}, {"statement": "Changes in employment law can affect how many workers a business can afford to employ.", "answer": true, "explain": "Correct. If the government raises the minimum wage, businesses face higher wage costs for the same number of workers. Some may respond by reducing staff numbers or hours, or increasing prices to maintain margins."}, {"statement": "HR planning is always a waste of time and money because business conditions change too quickly.", "answer": false, "explain": "This is too extreme. While HR plans can become outdated, the process of planning helps businesses anticipate changes, have the right workers in place, and avoid costly over-staffing or under-staffing. The benefits generally outweigh the costs."}, {"statement": "Leclerc''s introduction of electronic price tags means it needs more IT staff at head office.", "answer": true, "explain": "Correct. Previously, individual store workers printed and inserted paper tags. Now, an IT specialist at head office can change all prices electronically. This creates demand for more skilled IT workers at the centre."}, {"statement": "The interdependent nature of business means that HR decisions never affect other departments.", "answer": false, "explain": "The interdependent nature of business means decisions in one area ALWAYS affect other areas. For example, a finance decision to cut the wage budget directly affects how many workers HR can recruit — and that affects production capacity."}]}, "misc": {"enabled": true, "items": [{"myth": "Human resources only refers to the HR department of a business.", "truth": "Human resources refers to ALL the people who do work for a business — including the owner, all employees, and contractors. The HR department is just one part of the business that manages those people. A small business with no HR department still has human resources.", "check": {"question": "Which of these best describes ''human resources''?", "options": ["Only the managers of a business", "Only employees who are on permanent contracts", "Only the staff who work in the HR department", "All the people who work for the business"], "answer": 3, "explain": "Human resources means ALL the people who do work for a business — the HR department is just the part of the business that manages those people."}}, {"myth": "HR needs analysis only needs to be done when a business first starts up.", "truth": "Businesses should review their HR needs REGULARLY — not just at start-up. This is because staffing needs change as businesses grow, introduce new technology, face changes in the law, or when workers leave. Only reviewing at start-up means the business may become over- or under-staffed over time.", "check": {"question": "How often should a business carry out HR needs analysis?", "options": ["Only at the very end of the financial year", "Only once, when it first starts up", "Regularly, throughout the life of the business", "Only when profits fall"], "answer": 2, "explain": "Businesses should review their HR needs regularly, not just at start-up, because staffing needs change as the business grows or conditions change."}}, {"myth": "Zero-hours workers have no employment rights because they are not guaranteed hours.", "truth": "Zero-hours workers DO have employment rights. They must be paid at least the national minimum wage for any hours they work, they cannot be discriminated against, and they cannot be penalised for not being available to work. Lack of guaranteed hours does not remove their legal rights when they ARE working.", "check": {"question": "Which statement about zero-hours contract workers is correct?", "options": ["They are automatically classed as self-employed", "They must be paid minimum wage for hours worked", "They cannot ever be paid the national minimum wage", "They have no employment rights at all"], "answer": 1, "explain": "Zero-hours workers do have employment rights, including being paid at least the national minimum wage for the hours they actually work."}}, {"myth": "The HR department is only responsible for hiring and firing workers.", "truth": "The HR department has a much wider role: it deals with the organisation of workers, workplace communications, recruitment AND selection, motivation and retention, training and development, and employment law compliance. Hiring and firing is just one part of its responsibilities.", "check": {"question": "Besides recruitment and selection, which of these is also a responsibility of the HR department?", "options": ["Deciding the price of products", "Managing the business''s bank loans", "Motivation and staff training", "Researching new product ideas"], "answer": 2, "explain": "The HR department''s role is much wider than hiring and firing — it also covers motivation, retention, training, development, communications, and employment law."}}, {"myth": "If a business introduces robots, it will always need fewer workers.", "truth": "Introducing robots usually reduces the need for UNSKILLED workers but INCREASES demand for SKILLED workers (e.g. engineers and programmers to maintain and operate the technology). The total number of workers may fall, but the TYPE of worker needed changes significantly. This is a change in the NATURE of HR needs, not just the number.", "check": {"question": "What is the most accurate description of how introducing robots affects HR needs?", "options": ["It has no effect on the type of worker required", "It only affects the finance department", "It cuts unskilled jobs but raises need for engineers", "It always reduces the total number of workers needed"], "answer": 2, "explain": "Robots typically reduce the need for unskilled workers while increasing demand for skilled workers who can program and maintain the equipment — a change in the nature of HR needs, not simply the number."}}, {"myth": "HR planning is too expensive and time-consuming to be worthwhile.", "truth": "While HR planning does have a cost (time and money), the BENEFITS usually outweigh these costs. Without planning, a business may recruit too many workers (wasting wages) or too few (failing to meet demand). Good HR planning helps the business be efficient and competitive — it is time and money well spent.", "check": {"question": "What is the correct conclusion about whether HR planning is worth the cost?", "options": ["It is always too expensive and time-consuming to be worthwhile", "It should only be carried out by large businesses", "It has no costs at all", "It costs time and money, but benefits usually win"], "answer": 3, "explain": "The card concludes that although HR planning has a cost, the benefits generally outweigh this cost because it helps a business avoid recruiting too many or too few workers."}}]}, "tips": {"enabled": true, "items": [{"title": "Analyse one way HR needs may change (3 marks)", "html": "Structure: (U) Explain the type of change — e.g. ''fewer workers may be needed.'' (APP) Link to the specific business in the case study — e.g. ''workers who print price labels at Leclerc will no longer be needed.'' (AN) Show the business impact — e.g. ''this may reduce Leclerc''s wage bill, increasing profit.'' Always chain: change → effect on THIS business → business consequence.", "check": {"question": "For a 3-mark ''analyse one way HR needs may change'' question, what should follow stating the type of change?", "options": ["Link the change to the business, then show its impact", "Repeating the question in different words", "A personal opinion about whether the change is fair", "A list of as many possible changes as can be thought of"], "answer": 0, "explain": "The recommended structure is to chain: change → effect on THIS business (using case study detail) → business consequence, as shown in the Leclerc price-tag example."}}, {"title": "Evaluate the importance of the HR department (3 marks)", "html": "Make a clear judgement (1 mark): ''The HR department is very important to [business].'' Then justify with TWO contextual reasons linked to the case study (2 marks). Example: ''Leclerc needs its HR department to manage redundancies sensitively so it keeps its good reputation for treating staff fairly, AND to recruit the IT specialists needed to manage the new pricing system.''", "check": {"question": "How are marks awarded for a 3-mark question evaluating the importance of the HR department?", "options": ["3 marks for listing three separate HR functions", "1 mark for spelling key terms correctly", "A judgement mark plus two case-linked reasons", "3 marks purely for the length of the answer"], "answer": 2, "explain": "The mark scheme awards 1 mark for a clear judgement and 2 further marks for two reasons justified with context from the case study."}}, {"title": "State/identify one factor that affects HR needs (1 mark)", "html": "Short questions: name ONE factor clearly — e.g. ''the method of production,'' ''the budget available,'' ''changes in the law,'' ''whether the business is growing.'' Do not just write ''the business changes'' — be specific about WHICH factor. One well-chosen word can earn a mark here.", "check": {"question": "For a 1-mark question asking students to state one factor that affects HR needs, what earns the mark?", "options": ["Listing as many factors as possible", "Naming one clear factor, like the available budget", "Writing a vague statement like ''the business changes''", "Explaining the factor in full detail with examples"], "answer": 1, "explain": "The card warns that a vague answer like ''the business changes'' will not score — students must name ONE specific factor clearly."}}, {"title": "Workforce planning calculations", "html": "Common calculation: how many workers are needed? Formula: Total units ÷ (hours available × units per hour per worker) = workers needed. Example: 7,200 T-shirts ÷ (120 hours × 20 T-shirts/hour) = 7,200 ÷ 2,400 = 3 workers. Always show your working step by step — a correct method with a wrong answer can still earn method marks.", "check": {"question": "What is the correct formula for calculating how many workers are needed to complete a production order?", "options": ["Hours available ÷ total units", "Total units ÷ number of days available", "Total units × hours available ÷ units per hour", "Total units divided by hours times output per hour"], "answer": 3, "explain": "The card''s worked example divides total units (7,200 T-shirts) by hours available multiplied by units per hour per worker (120 × 20 = 2,400) to get workers needed."}}, {"title": "Evaluate the impact of a change on HR needs", "html": "Structure for 9-mark questions: K (define HR or HR needs) → U (explain the specific HR change) → APP x2 (use numbers or details from the case study twice) → AN x2 (show the business impact of each change) → EVAL x3 (overall judgement: is the change positive or negative for the business? Justify with context). Always reach a conclusion.", "check": {"question": "What structure should be used to answer a 9-mark question evaluating the impact of a change on HR needs?", "options": ["K, U, APP x2, AN x2, EVAL x3, ending with a conclusion", "A single unstructured paragraph giving an opinion", "A list of bullet points with no explanation", "A definition only, with no application or evaluation"], "answer": 0, "explain": "The card sets out the structure as K (define) → U (explain) → APP x2 → AN x2 → EVAL x3, always reaching a conclusion."}}, {"title": "Always link HR changes to business consequences", "html": "Students often stop at identifying the HR change (e.g. ''fewer workers needed'') without explaining the business consequence. Examiners award analysis marks for explaining the IMPACT: ''fewer workers needed → lower wage bill → higher profit → more competitive pricing.'' Never describe without analysing the effect on the business.", "check": {"question": "What mistake do examiners commonly penalise when students answer HR change questions?", "options": ["Writing in full sentences", "Naming the HR change without its business consequence", "Making a clear judgement at the end of the answer", "Using specific details from the case study"], "answer": 1, "explain": "The Examiner Warning states that students often lose analysis marks by identifying a change (e.g. fewer workers needed) without explaining its impact on the business."}}, {"title": "Do not confuse ''HR department'' with ''human resources''", "html": "Examiners regularly penalise students who say ''the business has no HR department therefore it has no human resources.'' Every business has human resources — its workers. The HR department is just the function that manages them. Small businesses can have human resources without having a dedicated HR team.", "check": {"question": "Why is it incorrect to say ''a business with no HR department has no human resources''?", "options": ["Because HR departments are legally compulsory for every business", "Because the HR department creates human resources rather than manages them", "Because human resources only exist in large businesses", "Every business has workers — HR just manages people"], "answer": 3, "explain": "The card warns that examiners penalise this confusion: human resources are the workers themselves, while the HR department is only the function managing them, so small businesses can have human resources without a dedicated HR team."}}, {"title": "Both costs AND benefits of HR planning", "html": "If asked to evaluate whether HR planning is worthwhile, always present BOTH sides: Benefits (right workers at right time, efficient operations, competitive advantage) vs Costs (time-consuming, expensive, forecasts may be wrong). Conclude with a justified overall judgement — e.g. ''the benefits outweigh the costs because accurate planning means the business is less likely to waste money on unnecessary staff.''", "check": {"question": "When evaluating whether HR planning is worthwhile, what should a strong answer include?", "options": ["Only the benefits, since HR planning is always worthwhile", "A list of definitions with no judgement", "Only the costs, since HR planning is rarely worthwhile", "Both benefits and costs, then a justified judgement"], "answer": 3, "explain": "The Evaluation Tip advises presenting both benefits and costs of HR planning before reaching a justified overall conclusion."}}]}, "exam": {"enabled": true, "questions": [{"question": "Which of the following is NOT a function of the human resources department of a business?", "marks": 1, "hint": "Think about what the HR department actually manages. Which option is about products rather than people?", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — Researching new products</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>Researching new products is a marketing or production function. The HR department deals with people: recruitment, motivation, training, organisation, communications, and employment law. It does not make product decisions.</p></div>"}, {"question": "A business has an order to make 7,200 T-shirts. It has three weeks to complete the order, operates 5 days per week for 8 hours per day. A worker can sew 20 T-shirts per hour. How many workers does it need?", "marks": 1, "hint": "First work out the total hours available. Then work out how many T-shirts one worker makes. Finally, divide total T-shirts by one worker''s output.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — 3</strong></p></div>\n<div class=\"marks-section\"><h5>Working</h5><p>Total hours = 3 weeks × 5 days × 8 hours = 120 hours. T-shirts per worker = 120 × 20 = 2,400. Workers needed = 7,200 ÷ 2,400 = 3 workers.</p></div>"}, {"question": "Which of the following statements about human resources is FALSE?", "marks": 1, "hint": "Human resources are INSIDE the business. Who are outside the business?", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — Human resources are the people the business sells its goods to</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>Human resources are the workers — the people who work FOR the business. The people a business sells to are CUSTOMERS. These are two different groups of people.</p></div>"}, {"question": "Analyse two ways in which the human resource needs of the Leclerc supermarket chain may have changed as a result of the introduction of the electronic price tags. [6 marks]", "marks": 6, "hint": "Think about who WAS needed before the tags (store workers printing labels) and who is NOW needed (IT specialists). Consider the effect on numbers, skills, and costs.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3a = 2+2+2)</h5><ul>\n<li><strong>Understanding (2 marks):</strong> Two changes identified — e.g. fewer workers needed; more skilled workers needed; more HR staff needed</li>\n<li><strong>Application (2 marks):</strong> Two case study links — e.g. workers who printed/inserted paper labels; IT specialists at head office managing pricing system</li>\n<li><strong>Analysis (2 marks):</strong> Two business impacts — e.g. lower wage bill/costs; higher cost of recruiting skilled IT staff; HR workload increases for managing redundancies and new recruitment</li>\n</ul></div>"}, {"question": "Evaluate the importance to the Leclerc supermarket chain of its human resources department. [3 marks]", "marks": 3, "hint": "Make a clear judgement first (important or not?), then give TWO reasons why, linked to the specific details in the case study — Leclerc''s reputation, the staffing changes, the scale of the business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO3b Evaluation = 3 marks)</h5><ul>\n<li><strong>Judgement (1 mark):</strong> Clear statement — e.g. ''The HR department is very important to Leclerc''</li>\n<li><strong>Justification (up to 2 marks):</strong> Two justified reasons using case study context</li>\n</ul></div>"}, {"question": "Evaluate the impact of relegation and the reduction in income on the HR needs of Bolton Wanderers Football Club. [9 marks]", "marks": 9, "hint": "Define HR needs. Identify specific impacts (player wages, backroom staff, shop staff). Analyse the business consequences (competitiveness, performance on the pitch, relegation spiral). Evaluate: overall, has the reduction in HR spending made things better or worse? Can the club recover?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation</h5><ul>\n<li><strong>Knowledge (1):</strong> Define what HR needs are</li>\n<li><strong>Understanding (1):</strong> Explain the HR needs Bolton has (players, coaches, medical staff, etc.)</li>\n<li><strong>Application (2):</strong> Two specific impacts of relegation on HR — e.g. must release high-wage players; shop staff may face redundancy as gate revenues fall</li>\n<li><strong>Analysis (2):</strong> Business consequences of each impact — e.g. releasing best players may mean further poor performance and another relegation; morale of remaining staff falls</li>\n<li><strong>Evaluation (3):</strong> Judgement on whether the HR changes make success more/less likely, with two justified contextual reasons and an overall conclusion</li>\n</ul></div>"}]}}'::jsonb),
('business', '3-2-organisational-structures', '3.2 Organisational Structures', '{"learn": {"enabled": true, "items": [{"title": "Core Terminology", "html": "<ul>\n<li><strong>Organisational structure</strong> — how people and departments are arranged within a business; the hierarchy of employees</li>\n<li><strong>Organisation chart</strong> — a diagram showing how workers are organised and who is in charge of whom</li>\n<li><strong>Layers</strong> — the number of levels of authority in a chain of command</li>\n<li><strong>Authority</strong> — the power to make decisions and tell other workers what to do</li>\n<li><strong>Line manager</strong> — the person directly in charge of other workers; the person a worker is responsible to</li>\n<li><strong>Subordinates</strong> — workers that a line manager is responsible for</li>\n<li><strong>Chain of command</strong> — the path of authority along which instructions pass, from the CEO downwards</li>\n<li><strong>Span of control</strong> — the number of employees/subordinates that report directly to a manager</li>\n<li><strong>Delegation</strong> — when a manager gives a subordinate authority and responsibility to make certain decisions (the manager remains ultimately responsible)</li>\n<li><strong>Accountability</strong> — the responsibility a person has for a job; they take blame for what goes wrong as well as credit for what goes well</li>\n<li><strong>Delayering</strong> — when a business reduces the number of layers in its structure, making it flatter</li>\n<li>\n     <a href=\"extra/org_chartV2.html\" target=\"_blank\" rel=\"noopener noreferrer\"> Our School Organisation chart </a> </li>\n</ul>", "check": {"question": "When a manager delegates a task to a subordinate, who remains ultimately responsible for the outcome?", "options": ["The subordinate''s line manager''s line manager", "No one — responsibility disappears once delegated", "Only the subordinate carrying out the task", "The manager who delegated it"], "answer": 3, "explain": "The glossary states that when a manager delegates, they give authority and responsibility to a subordinate but remain ultimately responsible."}}, {"title": "Tall vs Flat Organisational Structures", "html": "<p><strong>Tall structure:</strong> Many layers; narrow span of control. Suited to large organisations (e.g. hospitals) and non-creative businesses with clear, limited tasks (e.g. building companies).</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages of Tall</div>\n<div class=\"pro-item\">Clear lines of communication and authority</div>\n<div class=\"pro-item\">Easier supervision — fewer direct reports per manager</div>\n<div class=\"pro-item\">Workers are clear who they are responsible to</div>\n<div class=\"pro-item\">Promotion opportunities motivate workers</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages of Tall</div>\n<div class=\"con-item\">Subordinates feel too controlled — can stifle motivation</div>\n<div class=\"con-item\">Slower communications — many layers to pass through</div>\n<div class=\"con-item\">Messages more likely to be distorted through many people</div>\n<div class=\"con-item\">Workers may only talk to immediate colleagues</div>\n</div>\n</div>\n<p style=\"margin-top:12px;\"><strong>Flat structure:</strong> Few layers (2–3); wide span of control. Suited to creative businesses (e.g. game design) and smaller businesses where workers feeling valued matters.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages of Flat</div>\n<div class=\"pro-item\">Workers feel trusted — managers must delegate widely</div>\n<div class=\"pro-item\">Easier to share ideas — more likely to know bosses directly</div>\n<div class=\"pro-item\">Faster communication — fewer layers</div>\n<div class=\"pro-item\">Messages less likely to be changed or distorted</div>\n<div class=\"pro-item\">Saves money — fewer layers of managers needed</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages of Flat</div>\n<div class=\"con-item\">Lines of communication not always clear</div>\n<div class=\"con-item\">Few promotion opportunities — can reduce motivation</div>\n<div class=\"con-item\">Managers may have too many people to look after</div>\n</div>\n</div>", "check": {"question": "According to the notes, which type of business is a tall structure best suited to?", "options": ["Businesses wanting to save money on management wages", "Businesses that want the fastest possible communication", "Small creative businesses like game design studios that value flexibility", "Large organisations that have very clear limited tasks"], "answer": 3, "explain": "The notes state tall structures suit large organisations (e.g. hospitals) and non-creative businesses with clear, limited tasks (e.g. building companies)."}}, {"title": "Why Businesses Choose Different Structures", "html": "<p>The structure adopted depends on several factors:</p>\n<ul>\n<li><strong>Scale of business</strong> — large businesses usually require hierarchical structures for clear control; small businesses find this less important</li>\n<li><strong>Function</strong> — organised by functional areas (Marketing, Finance, Production, HR)</li>\n<li><strong>Product</strong> — organised by different product lines</li>\n<li><strong>Place</strong> — organised by locations (e.g. regional offices)</li>\n<li><strong>Nature of the business</strong> — creative businesses suit flat structures; clear-task businesses may suit tall</li>\n<li><strong>Type of leadership</strong> — autocratic leaders prefer tall structures to maintain control</li>\n<li><strong>Effective communication</strong> — whichever structure results in the best communication for that specific organisation</li>\n</ul>\n<p><strong>Delayering:</strong> Businesses reduce layers to save money and gain the advantages of flat structures — faster communication, more delegated authority. e.g. Leigh Hire Ltd saved £60,000 per year by removing two supervisor roles.</p>", "check": {"question": "What does ''delayering'' mean in the context of organisational structure?", "options": ["Reducing the number of layers in a structure to make it flatter", "Changing from a product-based to a place-based structure", "Increasing the number of management layers for better control", "Replacing autocratic leaders with democratic ones"], "answer": 0, "explain": "The card defines delayering as businesses reducing layers to save money and gain flat-structure advantages, citing Leigh Hire Ltd saving £60,000/year."}}, {"title": "Full-time, Part-time & Temporary Working", "html": "<p><strong>Full-time:</strong> 35+ hours per week. Worker permanently available; business pays even when no work is being done.</p>\n<p><strong>Part-time:</strong> Under 35 hours per week. Part-time employees have the SAME employment rights as full-time workers.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">Part-time — Business</div>\n<div class=\"pro-item\">Can use workers at peak times; saves overtime; more recruitment choice</div>\n<div class=\"con-item\">Higher training costs per head; more supervision time needed</div>\n</div>\n<div>\n<div class=\"col-head\">Part-time — Worker</div>\n<div class=\"pro-item\">Can work when it suits (school hours, students, semi-retired)</div>\n<div class=\"con-item\">Lower income; uncertainty if hours are variable; inconvenient split shifts</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Temporary working:</strong> Short period/fixed-term contract (e.g. seasonal work in agriculture or Christmas retail). Workers can be used when needed without long-term commitment. Risk: lack of commitment, training costs wasted.</p>\n<p><strong>Zero-hours contract:</strong> A person has a contract but is not guaranteed any hours. Informed when needed, sometimes at short notice.</p>", "check": {"question": "What best describes a zero-hours contract?", "options": ["A contract for exactly 35 hours per week", "A contract that removes all employment rights", "A contract only available to full-time staff", "A contract with no guaranteed number of hours"], "answer": 3, "explain": "The notes define a zero-hours contract as one where a person has a contract but is not guaranteed any hours, being informed when needed."}}, {"title": "Flexible Working, Home & Hybrid Working", "html": "<p><strong>Flexible working:</strong> Working partly at the workplace and partly elsewhere, or at variable times. Includes flexi-time (working weekly hours in fewer days) and shift working.</p>\n<p><strong>Working from home:</strong> Completing work in the home. <strong>Hybrid working:</strong> Part of the time at home, part in an office.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">Home/Hybrid — Business</div>\n<div class=\"pro-item\">Saves on office space/rent; increased productivity; wider recruitment (don''t need to live locally)</div>\n<div class=\"con-item\">Harder to monitor work; communication can be poor; technology costs</div>\n</div>\n<div>\n<div class=\"col-head\">Home/Hybrid — Worker</div>\n<div class=\"pro-item\">Saves time and money on travel; less stress; can work around family commitments</div>\n<div class=\"con-item\">Distractions at home; social isolation; higher utility bills</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Case study — Wokingham Council:</strong> Introduced flexible/hot-desking working; saved money on office space; productivity improved and absenteeism fell. Success depended on ICT (calls transferred to mobile phones).</p>\n<p><strong>Case study — BP:</strong> Moved 6,000 staff to hybrid model (3 days office, 2 days home) to reduce high London office costs.</p>", "check": {"question": "What distinguishes ''hybrid working'' from simply ''working from home''?", "options": ["Hybrid working removes the need for any office space", "Hybrid working is only available to managers", "Hybrid splits time between home and the office itself", "Hybrid working means fewer hours are worked overall"], "answer": 2, "explain": "The card defines working from home as being completed entirely at home, while hybrid working means part of the time at home and part in an office."}}, {"title": "Self-Employment & Mobile Working", "html": "<p><strong>Self-employment:</strong> When people work in their own business, selling their work to buyers (consumers or other businesses). Examples: plumbers, electricians, taxi drivers. In early 2020, 5.03 million people were self-employed (15.3% of UK working population).</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Pros of Self-Employment</div>\n<div class=\"pro-item\">Being your own boss; high motivation</div>\n<div class=\"pro-item\">Can earn more by working harder/faster</div>\n<div class=\"pro-item\">Freedom to choose work and clients</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Cons of Self-Employment</div>\n<div class=\"con-item\">No guaranteed income</div>\n<div class=\"con-item\">No holiday pay, sick pay or employer pension contributions</div>\n<div class=\"con-item\">Loss of employment rights (e.g. unfair dismissal protection)</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Working while mobile:</strong> Working while travelling or on the move. Made easier by technology — email, video calls, cloud software.</p>\n<p><strong>Benefit for business:</strong> EDF used self-employed workers for Hinkley Point C construction — only paid for specialist skills when needed, keeping costs lower and reducing long-term commitments.</p>", "check": {"question": "Which of these is a genuine drawback of being self-employed, according to the notes?", "options": ["Automatic protection against unfair dismissal", "No holiday pay, sick pay or pension contributions", "A guaranteed weekly income regardless of work done", "Being told exactly what work to do by a line manager"], "answer": 1, "explain": "The notes list no holiday pay, sick pay or employer pension contributions as a key con of self-employment, alongside no guaranteed income and loss of rights like unfair dismissal protection."}}, {"title": "Case Studies Linked to Concepts", "html": "<p><strong>Griffin Engineering Ltd:</strong> Functional hierarchy with 5 layers. Illustrates chain of command, span of control (Sales Manager = 5), and delegation (Production Manager → Stock Control Manager).</p>\n<p><strong>J.J. Jewellery:</strong> Small family business, flat structure (3 layers). Myiesha (Shop Manager) has span of control of 5. Mix of 2 full-time and 2 part-time shop assistants.</p>\n<p><strong>Leigh Hire Ltd (delayering):</strong> Removed two supervisor roles (£35k each) and gave work to Service Manager (+£10k). Net saving: £60,000/year. Risk: wider span of control for Service Manager may worsen communication.</p>\n<p><strong>JD Wetherspoon:</strong> 38,000 workers; flexible contracts with shifts varying 4–10 hours based on demand. Currently short of 6,000 staff — suggests flexible/insecure contracts may deter applicants.</p>\n<p><strong>HSBC:</strong> Over 70% of call centre employees now work from home permanently. Benefits: lower overhead costs, productivity gains. Risks: monitoring difficulties, technology costs.</p>\n<p><strong>Beautiful Buds plc (delayering):</strong> Removing Middle Managers (£600k saving) and Team Leaders (£700k saving) saves £1.3m. Adding 10 supervisors costs £300k. Net annual saving: £1m (after £200k one-off redundancy cost).</p>", "check": {"question": "In the Griffin Engineering Ltd case study, the Sales Manager''s span of control is 5. What does this figure represent?", "options": ["The number of years the Sales Manager has worked there", "Employees who report directly to the Sales Manager", "The total number of employees in the whole business", "The number of layers in the chain of command"], "answer": 1, "explain": "The card uses Griffin Engineering to illustrate span of control as the number of direct reports to a manager, here the Sales Manager''s span of 5."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Organisational structure", "definition": "How people and departments are arranged within a business — the hierarchy or way that employees are organised, showing lines of authority and responsibility."}, {"term": "Organisation chart", "definition": "A diagram that shows how workers are organised in a business and who is in charge of whom. It shows roles and relationships between all employees."}, {"term": "Chain of command", "definition": "The path of authority along which instructions are passed — from the CEO at the top downwards to those with the least authority at the bottom."}, {"term": "Span of control", "definition": "The number of subordinates who report DIRECTLY to a manager. Wide span = many direct reports (flat structure). Narrow span = fewer direct reports (tall structure)."}, {"term": "Delegation", "definition": "The process where a manager gives a subordinate authority and responsibility to make certain decisions. The manager remains ultimately responsible for the outcome."}, {"term": "Accountability", "definition": "The responsibility a person has for a job — they take blame for what goes wrong as well as credit for what goes well."}, {"term": "Delayering", "definition": "When a business reduces the number of layers in its organisational structure, making it flatter. Often done to save money and speed up communication."}, {"term": "Tall structure — key features", "definition": "Many layers; narrow span of control; longer chain of command. Benefits: clear authority, promotion opportunities, easier supervision. Drawbacks: slow communication, messages distorted, workers feel over-controlled."}, {"term": "Flat structure — key features", "definition": "Few layers (2–3); wide span of control; shorter chain of command. Benefits: faster communication, workers feel trusted, saves on manager salaries. Drawbacks: few promotions, managers can be overloaded."}, {"term": "Full-time vs part-time", "definition": "Full-time: 35+ hours/week. Part-time: under 35 hours. BOTH have the same employment rights. Part-time allows businesses to cover peaks; workers gain flexibility but earn less."}, {"term": "Zero-hours contract", "definition": "A contract where the worker is not guaranteed any hours. Called in when needed. Benefit: flexibility for business. Drawback: income insecurity for worker; communication can be poor."}, {"term": "Flexible working", "definition": "Working at variable times or partly away from the main workplace. Includes flexi-time, shift working, and home/hybrid working."}, {"term": "Hybrid working", "definition": "Working part of the time at home and part in an office. BP moved 6,000 staff to hybrid (3 days office, 2 days home) to reduce London office costs."}, {"term": "Home working — business benefits", "definition": "Saves costs on office space/rent; can recruit workers who don''t need to live locally; often increases productivity."}, {"term": "Home working — business drawbacks", "definition": "Harder to monitor if work is being done; communication can be poor; costs of buying technology for home use."}, {"term": "Self-employment — pros", "definition": "Being your own boss; high motivation; can earn more by working harder or faster; freedom to choose clients and projects."}, {"term": "Self-employment — cons", "definition": "No guaranteed income; no holiday pay; no sick pay; no employer pension contributions; loss of employment rights (e.g. unfair dismissal protection)."}, {"term": "Leigh Hire Ltd delayering", "definition": "Removed two supervisor roles (£35k each = £70k saved). Service Manager pay rise = +£10k. Net annual saving = £60,000. Risk: wider span of control may worsen communication and quality."}, {"term": "Griffin Engineering Ltd", "definition": "Functional hierarchy with 5 layers. Sales Manager has span of control of 5. Illustrates delegation (Production Manager → Stock Control Manager) and chain of command."}, {"term": "Beautiful Buds plc (delayering numbers)", "definition": "Remove Middle Managers = £600k saving. Remove Team Leaders = £700k saving. Add 10 supervisors = £300k extra. One-off redundancy costs = £200k. Net annual saving = £1,000,000."}]}, "mcq": {"enabled": true, "questions": [{"question": "A business with a tall organisational structure will have:", "options": ["A high market share", "Short chains of command", "Lots of distribution channels", "Multiple layers of authority"], "answer": 3, "explain": "A tall structure is defined by having many layers of authority from top to bottom. This creates long chains of command — not short ones. Market share and distribution channels are unrelated to structure."}, {"question": "A clothing designer may choose to flatten its organisational structure to reduce the:", "options": ["Need for innovation and change", "Creativity of its garment designers", "Independence of its fabric buyers", "Time it takes to respond to changes in fashion"], "answer": 3, "explain": "A flat structure has fewer layers, so communication is faster. This means the business can respond more quickly to changes in fashion trends. Flattening does NOT reduce creativity — it usually enhances it."}, {"question": "The span of control of the Production Manager (who has 3 Production Supervisors reporting directly to them) is:", "options": ["63", "21", "3", "1"], "answer": 2, "explain": "The span of control is the number of people who report DIRECTLY to a manager. Only the 3 Production Supervisors report directly to the Production Manager — not the 20 workers under each supervisor."}, {"question": "A business may choose to have a flat organisational structure because it:", "options": ["Reduces the likelihood of mistakes in vertical communication", "Slows down the organisation''s response to changes in the market", "Lengthens the organisation''s chain of command", "Gives employees more opportunities for promotion"], "answer": 0, "explain": "Fewer layers means fewer people for a message to pass through — so there are fewer opportunities for it to be changed or distorted. This reduces mistakes in vertical (upward/downward) communication."}, {"question": "A flat organisational structure has:", "options": ["Narrow spans of control", "No specific person in overall charge", "A long chain of command", "Few levels of authority"], "answer": 3, "explain": "A flat structure is defined by having FEW levels (layers) of authority — perhaps only 2 or 3. It has WIDE (not narrow) spans of control and SHORTER (not longer) chains of command."}, {"question": "Who is a director''s subordinate?", "options": ["A manager", "A shareholder", "A supplier", "A customer"], "answer": 0, "explain": "Subordinates are the workers that a line manager (or director) is responsible for and has authority over. Managers report to directors, making them subordinates. Customers, shareholders and suppliers are external parties."}, {"question": "Which of the following is an advantage to a fruit farm of employing temporary workers to pick the fruit?", "options": ["The number of workers employed can be varied according to the season", "Discrimination laws do not apply because the work is only for a few weeks", "Induction training will not be required because the work is not permanent", "Workers are likely to be more committed to their jobs and pick more fruit"], "answer": 0, "explain": "The key advantage of temporary workers is flexibility — the farm can increase or decrease the number of workers to match seasonal demand for fruit picking. Discrimination laws ALWAYS apply, and induction training is still needed."}, {"question": "Which one of the following is a benefit to a flower shop of employing extra temporary sales staff on Valentine''s Day?", "options": ["Workers can be paid less than the minimum wage", "More customers can be served", "Roses can be sold for cheaper prices", "The flowers will be fresher"], "answer": 1, "explain": "With more staff, the shop can serve more customers during the peak demand on Valentine''s Day — reducing queues and improving customer service. Temporary staff cannot be paid below the minimum wage."}, {"question": "The main financial benefit of delayering for Leigh Hire Ltd (removing two supervisor roles at £35,000 each, giving the Service Manager a £10,000 pay rise) is a saving of:", "options": ["£60,000 per year", "£35,000 per year", "£70,000 per year", "£80,000 per year"], "answer": 0, "explain": "Two roles at £35,000 = £70,000 saved. Less the £10,000 increase to the Service Manager = net saving of £60,000 per year. This is the key financial application figure for the Leigh Hire case study."}, {"question": "What is the mean average managerial span of control at POD Ltd, which has 5 managers each managing: 6 accounts clerks, 4 clerical assistants, 28 production workers, 5 sales reps, and 3 HR assistants?", "options": ["10.2", "9.2", "8.5", "7.7"], "answer": 2, "explain": "Total subordinates = 6+4+28+5+3 = 46. Divided by 5 managers = 9.2 per manager. But the Managing Director also manages 5 managers. Mean average across all 6 managers = (46+5)/6 = 8.5."}]}, "fib": {"enabled": true, "questions": [{"text": "The number of subordinates that report directly to a manager is called the [span] of control. A tall structure has a [narrow] span of control."}, {"text": "When a business removes layers from its structure it is called [delayering], which usually saves [money] and speeds up communication."}, {"text": "A [flat] structure has few layers and a wide span of control, making it suited to [creative] businesses where fast communication matters."}, {"text": "Full-time working means working [35] hours or more per week, while part-time workers have the [same] employment rights as full-time workers."}, {"text": "Working from home saves businesses money on office [space] and can increase worker [productivity], but makes it harder to monitor staff."}, {"text": "A self-employed worker earns no [holiday] pay or sick pay from an employer, but benefits from being their own [boss] and potentially earning more."}]}, "tf": {"enabled": true, "questions": [{"statement": "A tall organisational structure has a wide span of control.", "answer": false, "explain": "Tall structures have a NARROW span of control — each manager supervises fewer people. FLAT structures have a wide span of control."}, {"statement": "Delayering means adding more layers to an organisational structure.", "answer": false, "explain": "Delayering means REMOVING layers to make the structure flatter. It reduces the number of management levels, usually to save money and speed up communication."}, {"statement": "The span of control of a manager with 3 supervisors, each managing 20 workers, is 3.", "answer": true, "explain": "Correct. Span of control only counts DIRECT reports. The 3 supervisors report directly to the manager. The 60 workers report to their supervisors — not directly to the manager."}, {"statement": "Part-time workers have fewer employment rights than full-time workers.", "answer": false, "explain": "This is a common misconception. Part-time employees have EXACTLY THE SAME employment rights as full-time workers. The number of hours worked does not affect their rights."}, {"statement": "A flat organisational structure is best suited to large, non-creative businesses.", "answer": false, "explain": "Flat structures suit creative businesses (e.g. game design) and smaller businesses. Large, non-creative businesses with clear tasks tend to suit TALL structures with defined authority."}, {"statement": "Delegation means giving a subordinate responsibility for a task while the manager remains ultimately accountable.", "answer": true, "explain": "Correct. Delegation gives the subordinate authority and responsibility to make certain decisions, but the manager is still ultimately responsible for the outcome."}, {"statement": "Working from home always increases worker productivity.", "answer": false, "explain": "It CAN increase productivity (less commute stress, flexible hours) but NOT always. Distractions at home (children, TV) and social isolation can reduce productivity. The effect varies by individual and role."}, {"statement": "Leigh Hire Ltd''s delayering plan would save £70,000 in wages per year.", "answer": false, "explain": "The saving is £60,000. Two roles at £35,000 each = £70,000 saved. MINUS the £10,000 pay rise for the Service Manager = net saving of £60,000 per year."}, {"statement": "A zero-hours worker is not guaranteed any work hours each week.", "answer": true, "explain": "Correct. Zero-hours contracts mean the worker has a contract but is not guaranteed any hours. They are called in when needed, sometimes at very short notice."}, {"statement": "Autocratic leaders tend to prefer flat organisational structures.", "answer": false, "explain": "Autocratic leaders prefer TALL structures because they give more control — narrow spans of control mean managers have fewer people to supervise, and the long chain of command keeps authority centralised at the top."}, {"statement": "Hybrid working means working entirely from home, with no time in the office.", "answer": false, "explain": "Hybrid working means working PART of the time at home AND part in the office — not entirely from home. Working entirely from home is simply ''working from home''."}, {"statement": "A self-employed person receives holiday pay from a client business.", "answer": false, "explain": "Self-employed workers are NOT employees. They do not receive holiday pay, sick pay or employer pension contributions from the businesses they work for. This is one of the key disadvantages of self-employment."}, {"statement": "JD Wetherspoon uses flexible contracts with shifts varying from 4 to 10 hours based on demand.", "answer": true, "explain": "Correct. JD Wetherspoon uses flexible-working contracts where shifts vary between 4 and 10 hours to match demand — more staff during busy lunch and evening periods, fewer during quiet mornings."}, {"statement": "Beautiful Buds plc would make a net annual saving of £1 million from its delayering plan, after removing Middle Managers and Team Leaders and adding supervisors.", "answer": true, "explain": "Correct. £600k (Middle Managers) + £700k (Team Leaders) = £1.3m saved. Less £300k (10 new supervisors) = £1m net annual saving. The £200k redundancy is a one-off cost."}]}, "misc": {"enabled": true, "items": [{"myth": "The organisational structure and the organisation chart are the same thing.", "truth": "They are different. The STRUCTURE is the actual hierarchy — how people and authority are arranged. The CHART is the DIAGRAM that shows that structure visually. You can have a structure without a chart, but a chart represents the structure.", "check": {"question": "What is the correct relationship between an organisational structure and an organisation chart?", "options": ["They are two words for exactly the same thing", "A business can have a chart but never a structure", "The chart is a diagram representing the structure", "The chart is the actual hierarchy, and the structure is only the diagram"], "answer": 2, "explain": "The card clarifies the structure is the actual hierarchy while the chart is the diagram that represents it visually — they are not identical."}}, {"myth": "Part-time workers have fewer employment rights than full-time workers.", "truth": "Part-time employees have EXACTLY THE SAME employment rights as full-time workers. The number of hours worked does not affect the type or permanency of their employment rights. This is a very common misconception that loses marks.", "check": {"question": "How do the employment rights of part-time workers compare to full-time workers?", "options": ["Part-time workers have fewer rights because they work fewer hours", "They are exactly the same", "Part-time workers have rights only if on a permanent contract", "Part-time workers only gain full rights after one year"], "answer": 1, "explain": "The card corrects the common misconception, stating part-time employees have exactly the same employment rights as full-time workers."}}, {"myth": "A wide span of control means a manager has few people to supervise.", "truth": "A WIDE span means a manager has MANY subordinates reporting to them directly. A NARROW span means fewer subordinates. Wide span = flat structure; narrow span = tall structure. Students frequently confuse these.", "check": {"question": "What does a WIDE span of control mean for a manager?", "options": ["The manager has very few people to supervise", "The manager has many direct-reporting subordinates", "The manager works in a tall structure", "The manager has no authority to make decisions"], "answer": 1, "explain": "The card explains a wide span means many direct subordinates (linked to flat structures), while a narrow span means few (linked to tall structures)."}}, {"myth": "Delayering always makes a business better.", "truth": "Delayering has BOTH benefits AND drawbacks. Benefits: saves wages, faster communication, more delegation. Drawbacks: fewer promotion opportunities for workers (reduces motivation), wider span of control may overwhelm remaining managers, and communication may actually get worse if the span becomes too wide. Evaluation is always required.", "check": {"question": "Which statement best reflects the mark-scheme expectation when discussing delayering?", "options": ["It is always beneficial and should never be criticised", "It always increases the number of management layers", "It only affects wages and has no impact on communication", "It has both benefits and drawbacks, weighed together"], "answer": 3, "explain": "The card stresses delayering has both benefits (saved wages, faster communication) and drawbacks (fewer promotions, wider span risk), so evaluation is always required."}}, {"myth": "Span of control includes all the workers below a manager, not just direct reports.", "truth": "Span of control ONLY counts the people who report DIRECTLY to that manager — not everyone in the layers below. For example, a Production Manager with 3 supervisors (each managing 20 workers) has a span of control of 3, not 63.", "check": {"question": "A Production Manager has 3 supervisors, each managing 20 workers. What is the Production Manager''s span of control?", "options": ["3", "20", "63", "60"], "answer": 0, "explain": "Span of control only counts people reporting directly to that manager, so the Production Manager''s span is 3, not the 63 total workers below."}}, {"myth": "Flexible/home working is always beneficial for both businesses and workers.", "truth": "Flexible/home working has BOTH benefits and drawbacks for BOTH parties. For workers: benefits include saving travel costs and flexibility, but drawbacks include social isolation and home distractions. For businesses: benefits include reduced office costs and productivity gains, but drawbacks include monitoring difficulties and technology costs. Never state it is ''always good.''", "check": {"question": "Which statement correctly describes flexible/home working according to the notes?", "options": ["It benefits businesses but always harms workers", "It is always beneficial for workers and businesses alike", "It has no effect on office costs", "It has both benefits and drawbacks for workers and firms"], "answer": 3, "explain": "The card warns against saying flexible/home working is ''always good'', explaining it carries benefits and drawbacks for both workers and businesses."}}, {"myth": "The chain of command and the span of control are the same concept.", "truth": "They are different. The CHAIN OF COMMAND is the LINE of authority from top to bottom (vertical path of instructions). The SPAN OF CONTROL is the NUMBER of subordinates one manager has (horizontal count). Confusing these terms in exam answers loses marks.", "check": {"question": "What is the key difference between chain of command and span of control?", "options": ["Span of control only applies to flat structures", "They are different names for the same concept", "Chain of command counts subordinates; span of control shows the line of authority", "Chain of command is the line of authority; span is the number of subordinates"], "answer": 3, "explain": "The card distinguishes chain of command (the vertical path of authority) from span of control (the horizontal count of direct subordinates)."}}]}, "tips": {"enabled": true, "items": [{"title": "Analyse one benefit/drawback of a structure (3 marks)", "html": "Structure: (U) Explain the benefit (e.g. ''faster communication in a flat structure''). (APP) Link to the specific business in the case study (e.g. ''this means Nessa can respond quickly to the needs in the six stores''). (AN) Show the business impact (e.g. ''this could reverse the declining sales revenue''). Always chain: feature → effect on THIS business → business consequence.", "check": {"question": "For a 3-mark ''analyse one benefit of a structure'' question, what should the answer chain together?", "options": ["The feature, its link to the business, and the consequence", "A judgement on which structure is best without explanation", "Two unrelated advantages listed separately", "Only a definition of the structure with no context"], "answer": 0, "explain": "The tip explains the answer should chain: feature → effect on THIS business → business consequence (U, APP, AN)."}}, {"title": "Recommend which structure is most appropriate (3 marks)", "html": "Make a clear recommendation (1 mark). Justify it with TWO contextual reasons from the case study for full marks. Example: ''Miles Ahead should use a flat structure (1) so that decisions can be made more quickly to reverse the fall in sales revenue since 2018 (CONT) and so that employees in the six stores feel trusted and motivated (CONT).''", "check": {"question": "To gain full marks recommending which structure is most appropriate (3 marks), what must the answer include beyond the recommendation itself?", "options": ["Two contextual reasons justifying the choice made", "Only one reason, since two would be repetitive", "A list of every possible structure with no justification", "A calculation of the exact span of control"], "answer": 0, "explain": "The tip states a clear recommendation (1 mark) must be justified with TWO contextual reasons from the case study for full marks."}}, {"title": "State one advantage/disadvantage of a way of working (1 mark)", "html": "These short questions appear very frequently. Make sure you know ONE clear advantage AND disadvantage of: temporary working, flexible working, working from home, and zero-hours contracts — from BOTH the business AND the worker perspective. Never write ''saves money'' without specifying what costs are saved.", "check": {"question": "For a 1-mark ''state one advantage/disadvantage'' question about a way of working, what should be avoided?", "options": ["Writing ''saves money'' without specifying what costs are saved", "Keeping the answer short and direct", "Naming a specific way of working such as flexible working", "Giving the answer from the business''s perspective"], "answer": 0, "explain": "The tip warns never to write ''saves money'' without specifying what costs are actually saved."}}, {"title": "Evaluate whether a business should continue with a way of working", "html": "Structure: APP x2 (use case study evidence twice — e.g. specific staff numbers, shift lengths). AN x2 (show the business impact of each point). EVAL x3 (judgement: should they continue? + 2 justified reasons using context). For JD Wetherspoon: link flexible contracts to cost control AND the staff shortage of 6,000 workers.", "check": {"question": "What is the recommended mark-scheme structure for a 7-mark ''evaluate whether to continue with a way of working'' question?", "options": ["APP x2, AN x2, EVAL x3", "One long paragraph with no clear structure", "Only a definition followed by one example", "K x1, U x1, with no application or evaluation"], "answer": 0, "explain": "The tip specifies structuring the answer as APP x2 (case study evidence), AN x2 (business impact), then EVAL x3 (judgement and two justified reasons)."}}, {"title": "Discuss whether to change organisational structure (9 marks)", "html": "For Beautiful Buds: K (define delayering) → U (explain the process) → APP x2 (use the NUMBERS: £600k + £700k saving, £300k extra supervisor costs, £200k redundancy) → AN x2 (show business impact of savings AND risks) → EVAL x3 (overall judgement with net saving of £1m per year, long-term vs short-term). ALWAYS use the specific figures provided.", "check": {"question": "For the 9-mark ''discuss whether to change organisational structure'' question on Beautiful Buds, why is it important to use the specific figures (£600k, £700k, £300k, £200k)?", "options": ["Because only the final net saving figure needs to be mentioned", "Because K marks require quoting numbers instead of definitions", "Because the figures are not actually relevant to the answer", "Because APP marks need the case study numbers as evidence"], "answer": 3, "explain": "The tip stresses the APP x2 stage must use the specific numbers provided (savings and costs) to gain application marks, alongside K, U, AN and EVAL."}}, {"title": "Span of control calculations", "html": "Span of control = ONLY direct reports. If a Production Manager has 3 supervisors, span = 3 (not 3 + 20×3 = 63). Mean average span: add up ALL subordinates across ALL managers, then divide by the number of managers. For POD Ltd: 46 total subordinates + 5 managers = 51 total. 6 managers total. 51 ÷ 6 = 8.5.", "check": {"question": "How is the mean average span of control calculated across a business?", "options": ["Divide the number of managers by the number of layers", "Multiply the number of layers by the number of subordinates", "Add together the spans of only the most senior managers", "Add subordinates across managers, then divide by total"], "answer": 3, "explain": "The tip explains the mean average span is found by adding all subordinates across all managers, then dividing by the number of managers, as shown in the POD Ltd example (51 ÷ 6 = 8.5)."}}, {"title": "Always evaluate delayering with BOTH sides", "html": "Never say delayering is simply ''good because it saves money.'' Examiners expect both sides: savings vs. motivation risk (no promotion opportunities), faster communication vs. potential overload of remaining managers. Use the specific financial figures (e.g. £60,000 saving for Leigh Hire) for application marks. Conclude with a justified judgement.", "check": {"question": "According to the examiner warning, why should you never simply say delayering is ''good because it saves money''?", "options": ["Because delayering never actually saves any money", "Because only application marks are available for this topic", "Because savings should never be mentioned in an answer about delayering", "Examiners expect both sides weighed, like savings versus lost promotions"], "answer": 3, "explain": "The warning states examiners expect both sides — savings vs motivation risk and faster communication vs potential manager overload — followed by a justified judgement."}}, {"title": "Do NOT say part-time workers have fewer rights", "html": "This is repeatedly flagged by examiners. Part-time workers have EXACTLY THE SAME employment rights as full-time workers. Writing otherwise will lose marks. Similarly, zero-hours workers cannot be paid below the minimum wage — a common misconception. Discrimination laws apply to ALL workers regardless of contract type.", "check": {"question": "Besides the part-time rights misconception, what other common error does this examiner warning highlight about zero-hours workers?", "options": ["The mistaken belief they can be paid below minimum wage", "The mistaken belief that zero-hours workers have no contract at all", "The mistaken belief that zero-hours workers cannot be dismissed", "The mistaken belief that zero-hours contracts are illegal in the UK"], "answer": 0, "explain": "The warning notes zero-hours workers cannot legally be paid below minimum wage, correcting a common misconception, and that discrimination laws apply to all workers regardless of contract type."}}]}, "exam": {"enabled": true, "questions": [{"question": "The business made a net profit of: [1 mark]", "marks": 1, "hint": "First calculate total revenue (price × quantity), then subtract total costs.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — £3 million</strong></p></div>"}, {"question": "Which would be variable costs for a building firm? [1 mark]", "marks": 1, "hint": "Variable costs change with the level of output — think about what is used directly in building.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — Bricks and roof tiles</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>Bricks and roof tiles are used directly in production and increase as more buildings are constructed. Admin/legal expenses, business rates, insurance, and equipment like cement mixers are either fixed or indirect costs.</p></div>"}, {"question": "This means that: [1 mark]", "marks": 1, "hint": "A profit margin is expressed as pence per £1 of sales. Calculate the difference between the two margins and think about what that means per £100.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — every £100 of sales earns £1.30 less net profit than it used to</strong></p></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>This was the least well answered question in the whole paper. If the margin falls from 4.2% to 2.9%, that is a fall of 1.3 pence per pound, so £1.30 for each £100.</p><ul><li>Answer C was the most common wrong answer — a fall from 4.2% to 2.9% is actually a decrease of 31%, not 1.3%</li><li>Answer D was also popular — but the margin remains positive, so a profit is still being made</li></ul></div>"}, {"question": "The percentage change in the company''s total costs from 2020 to 2023 was: [1 mark]", "marks": 1, "hint": "Add both cost rows together for each year. Then apply the percentage change formula: (new − old) ÷ old × 100.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — 50%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>2020 total: £200,000 + £40,000 = £240,000</li><li>2023 total: £320,000 + £40,000 = £360,000</li><li>Change: £120,000 ÷ £240,000 × 100 = 50%</li></ul></div>"}, {"question": "The market trader''s gross profit margin was approximately: [1 mark]", "marks": 1, "hint": "Gross profit = Revenue − Cost of sales. Then: Gross Profit ÷ Revenue × 100.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — 63%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Gross profit = £12,500 − £4,600 = £7,900</li><li>GPM = £7,900 ÷ £12,500 × 100 = 63.2%</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>The correct answer of B was chosen by less than 40% of candidates.</p><ul><li>Many chose A because they did not first calculate gross profit</li><li>Some who did calculate gross profit then chose D because they divided by cost of sales rather than revenue</li></ul></div>"}, {"question": "Over the first three years of trading, the entrepreneur should expect to make: [1 mark]", "marks": 1, "hint": "10% per annum means 10% per year. Calculate annual profit first, then multiply by 3.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — profits totalling £45,000</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Annual profit = 10% × £150,000 = £15,000</li><li>Total profit over 3 years = £15,000 × 3 = £45,000</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Only half of candidates identified the correct answer as D.</p><ul><li>Answer A was the most popular wrong answer — candidates confused £15,000/year with £45,000/year</li><li>Answer C was also chosen — candidates calculated annual profit correctly but forgot to multiply by 3</li></ul></div>"}, {"question": "Calculate Unilever plc''s average revenue from 2019 to 2022. [2 marks]", "marks": 2, "hint": "Add together only the four figures from 2019, 2020, 2021 and 2022 — do NOT include 2018. Then divide by 4.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 = 2 marks)</h5><ul><li><strong>2 marks:</strong> Correct answer of €53,750m (with or without workings)</li><li>Accept 53,750 without units</li><li>No reward for calculating the average over the wrong period</li></ul></div><div class=\"marks-section\"><h5>Working</h5><ul><li>51,900 + 50,700 + 52,400 + 60,000 = 215,000</li><li>215,000 ÷ 4 = <strong>€53,750m</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Less than half of candidates gained full marks.</p><ul><li>Most common error: including 2018 figure (using all 5 years)</li><li>Another common error: calculating the difference between 2019 and 2022 (€8,100) rather than the average</li></ul></div>"}, {"question": "Explain one way revenue affects a business'' decision making. [2 marks]", "marks": 2, "hint": "Think of a specific business decision (e.g. pricing, expansion, new products). Then explain HOW revenue affects that particular decision.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b = 2 marks)</h5><ul><li><strong>1 mark:</strong> Identifying a way revenue affects decision making</li><li><strong>1 further mark:</strong> Explaining the way</li><li>Answers do not need to relate to Unilever</li><li>No reward for a definition of revenue</li></ul></div><div class=\"marks-section\"><h5>Answers may include:</h5><ul><li>Price setting</li><li>Need to reduce costs</li><li>Ability to spend money on raw materials</li><li>Entering a new market / expansion</li><li>Decision to remove / develop new products</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Generally well answered, although some answers did not refer to specific business decisions. A number misunderstood the question and considered how decisions affect revenue instead.</p></div>"}, {"question": "Explain why profit is important to a business'' future. [2 marks]", "marks": 2, "hint": "Think about what a business can DO with profit — e.g. expand, invest, repay debt. Explain why this benefits the future.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a + AO1b = 2 marks)</h5><ul><li><strong>1 mark:</strong> Identifying why profit is important</li><li><strong>1 further mark:</strong> Understanding/explanation of why</li><li>Answers do not need to relate to The Sea View Hotel</li><li>No reward for a definition of profit</li><li>No reward for answers about allowing the business to survive</li></ul></div><div class=\"marks-section\"><h5>Answers may include:</h5><ul><li>To help expansion (1) by opening new stores (1)</li><li>To help repay a loan / debt (1) so that costs fall (1)</li><li>Buy new equipment and buildings (1) to replace worn out items (1)</li><li>Attract new investors (1) so that the business can expand (1)</li><li>Develop new products (1) to allow more profit to be made in the future (1)</li><li>To pay dividends (1) which keep shareholders happy (1)</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Most candidates achieved at least one mark, with expansion or growth being a popular answer. Although a clear majority could identify a reason, many did not support their answer with a relevant explanation.</p></div>"}, {"question": "Calculate the daily break-even quantity for the proposed hotel. [3 marks]", "marks": 3, "hint": "Step 1: Calculate contribution (selling price − variable cost per room). Step 2: Convert weekly fixed costs to daily. Step 3: Break-even = daily fixed costs ÷ contribution.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 = 3 marks)</h5><ul><li><strong>1 mark:</strong> Contribution = £100 − £40 = £60</li><li><strong>1 mark:</strong> Daily fixed costs = £6,300 ÷ 7 = £900</li><li><strong>1 mark:</strong> Break-even = £900 ÷ £60 = <strong>15 rooms</strong></li></ul></div><div class=\"marks-section\"><h5>Alternative method:</h5><ul><li>Contribution = £60</li><li>Weekly break-even = £6,300 ÷ £60 = 105</li><li>Daily break-even = 105 ÷ 7 = 15 rooms</li></ul></div><div class=\"marks-section\"><h5>Notes:</h5><ul><li>No reward for the formula alone</li><li>Max 2 marks if weekly fixed costs not divided by 7 (giving answer of 105)</li><li>Max 2 marks if answer has wrong units (e.g. £)</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Even though ''daily'' was emboldened, many candidates stopped at 105 rooms (weekly) and only gained 2 marks.</p></div>"}, {"question": "Analyse one disadvantage to the partnership if the proposed hotel''s fixed costs were 10% higher than expected. [3 marks]", "marks": 3, "hint": "Start with the disadvantage (understanding). Then apply using numbers from the case study. Finally analyse the impact on the business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3a = 3 marks)</h5><ul><li><strong>1 mark:</strong> Identifying a disadvantage of higher than expected costs</li><li><strong>1 further mark:</strong> Application to the Sea View Hotel partnership (using numbers)</li><li><strong>1 further mark:</strong> Analysis of the disadvantage to the business</li><li>No reward for ''costs will increase''</li><li>No application marks for context about the current hotel</li><li>Analysis must be business-facing</li></ul></div><div class=\"marks-section\"><h5>Understanding may include:</h5><ul><li>Could lead to lower profits (or a loss)</li><li>Could lead to price increases</li><li>Increases break-even level of output</li><li>Less money available for other needs</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>Fixed costs of £6,300 a week</li><li>Increase of £630 a week / to £6,930 / £90 more per day</li><li>Break-even increases from 15 to 17 rooms per day (119 per week)</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>Need to fill more rooms to cover the extra costs</li><li>May reduce customer demand if price has increased</li><li>Share of profits could be reduced for the owners</li><li>May lead to business debts or a need for more finance</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Better answers showed understanding related to profit or break-even, applied to the numbers, with an impact on the need to sell more rooms. Some analytical answers did not include any application.</p></div>"}, {"question": "Which of the following would be fixed costs of a fruit farm? [1 mark]", "marks": 1, "hint": "Fixed costs do not change with the level of output. Which of these stays the same whether or not crops are being grown?", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — Rent and rates</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>Rent and rates must be paid regardless of output levels. Workers'' wages, fertiliser and seeds are all variable because they increase when more crops are produced.</p></div>"}, {"question": "The entrepreneur''s average rate of return is: [1 mark]", "marks": 1, "hint": "ARR = (Average annual profit ÷ Cost of investment) × 100.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — 26.5%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>ARR = £53,000 ÷ £200,000 × 100 = 26.5%</li></ul></div>"}, {"question": "Which of the following would help Emma and Henry deal with this problem? [1 mark]", "marks": 1, "hint": "The problem is a cash flow issue, not a profit issue. Which option brings in new capital to fund day-to-day expenses?", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — Taking on a new partner</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>A new partner would inject capital into the business, helping to resolve the cash flow problem. Holding more stock or increasing wages would make things worse. Issuing shares is not available to partnerships.</p></div>"}, {"question": "Pilti plc''s gross profit in 2022 was: [1 mark]", "marks": 1, "hint": "Rearrange: Gross profit = Net profit + Expenses. Net profit = Gross profit − Expenses.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — £26 million</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Gross profit = Net profit + Expenses = £14m + £12m = £26m</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Less than one in five candidates selected the correct answer. Answer C was the most popular wrong answer — candidates confused expenses with cost of sales. The formula rearranges to: Gross profit = Net profit + Expenses.</p></div>"}, {"question": "The lowest cost that Riley can obtain 1,200 litres of cleaning fluid from one supplier is: [1 mark]", "marks": 1, "hint": "Work out how many barrels of each size you would need to get at least 1,200 litres. Then calculate the total cost for each option.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — £600</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Supplier 3: 1 × 1,000L barrel = £600, but only 1,000L — not enough</li><li>Riley needs to buy 2 × 1,000L barrels from Supplier 3 = £1,200 — too expensive</li><li>Supplier 3: 1 barrel = 1,000L, need at least 1,200L → buy 2 = £1,200</li><li>Best option: 6 × 200L barrels from Supplier 2 = 1,200L @ £100 each = £600</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Around half of candidates answered correctly. Answer A was most common wrong answer — it is not possible to get 1,200L for £480 from any supplier.</p></div>"}, {"question": "Which of the following must be true for this business? [1 mark]", "marks": 1, "hint": "The question is about the margin (a ratio), not the absolute profit figure. Calculate the percentage change in the margin itself.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — Profitability has increased by 50%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Change = 9% − 6% = 3 percentage points</li><li>% change in profitability = 3 ÷ 6 × 100 = 50%</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>This was the least well answered multiple-choice question. The most common wrong answer was B — candidates confused ''net profit'' with ''net profit margin''.</p></div>"}, {"question": "This data is useful to Amir when making this pricing decision because it shows that: [1 mark]", "marks": 1, "hint": "Calculate total revenue (price × quantity) for each price point and compare.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — reducing the price charged for each loaf is likely to increase total revenue</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>£1.50 × 350 = £525</li><li>£1.75 × 250 = £437.50</li><li>£2.00 × 150 = £300</li><li>£2.25 × 50 = £112.50</li><li>Total revenue is highest at £1.50, so reducing price increases revenue</li></ul></div>"}, {"question": "Analyse one reason why keeping variable costs low may reward Zara''s owners. [3 marks]", "marks": 3, "hint": "Start with understanding (why does lower variable cost matter?). Then apply to Zara using a specific detail from the text. Then analyse how the owner is REWARDED — think dividends or business value.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3a = 3 marks)</h5><ul><li><strong>1 mark:</strong> Understanding a reason why lower costs reward an owner</li><li><strong>1 further mark:</strong> Application of understanding to Zara using evidence from the text</li><li><strong>1 further mark:</strong> Analysis of how lower variable costs help reward an owner</li><li>No reward for answers suggesting that controlling variable costs increases sales revenue</li><li>Analysis must show what the owner does with the profit (e.g. dividends, expansion)</li></ul></div><div class=\"marks-section\"><h5>Understanding may include:</h5><ul><li>Lower costs could lead to lower total costs / better profits / margins</li><li>Lower costs could enable a reduction in price</li><li>Lowers the break-even level of output</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>Buying fabric in large quantities from European suppliers</li><li>2,270 stores</li><li>Online sales increased by approximately 75%</li><li>Fast delivery / lead time of 15 days</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>May lead to owners receiving more money / dividends</li><li>Allows the business to expand / investment in growth / improve the stores</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Without context from the case study, the answer is limited to 2 marks. Many answers focused on the benefit to customers or employees rather than the owners. Keeping variable costs low only rewards the owner if it affects dividends or the value of the business.</p></div>"}, {"question": "Calculate the percentage decrease in Zara''s sales revenue between 2019 and 2020. Show your workings. [2 marks]", "marks": 2, "hint": "Percentage change = (change ÷ original) × 100. The original is the 2019 figure.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 = 2 marks)</h5><ul><li><strong>1 mark:</strong> Correct change in revenue = €5,825m</li><li><strong>1 further mark (OFR):</strong> €5,825m ÷ €19,954m × 100 = 29.2%</li><li>Negative sign not required</li><li>Accept 29% or any reasonable rounding</li></ul></div><div class=\"marks-section\"><h5>Working</h5><ul><li>€19,954m − €14,129m = €5,825m</li><li>€5,825m ÷ €19,954m × 100 = <strong>29.2%</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>More than half of candidates gained full marks. The most common wrong answer was 13.4%, from using the wrong denominator (2020 figure). If the working showing €5,825m was clear, this still gained 1 mark.</p></div>"}, {"question": "Explain one possible advantage to a business of selling its products via e-commerce. [2 marks]", "marks": 2, "hint": "Think about what is unique about selling online. Make sure your answer is from the BUSINESS''s point of view, not the customer''s.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b = 2 marks)</h5><ul><li><strong>1 mark:</strong> Identifying an advantage of selling via e-commerce</li><li><strong>1 further mark:</strong> Explaining the advantage</li><li>Answers do not need to relate to Zara</li><li>An answer of ''selling more products'' without a link to e-commerce gains no marks</li></ul></div><div class=\"marks-section\"><h5>Answers may include:</h5><ul><li>Sell worldwide / wider audience</li><li>Open all the time (24/7)</li><li>Professional look at little cost / easier to display products online</li><li>Lower operating costs (no need for physical stores)</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Generally well answered. Some answers were from the customer''s point of view rather than the business. Candidates must read the question carefully.</p></div>"}, {"question": "Calculate AZ''s gross profit margin for 2021. Show your workings. [2 marks]", "marks": 2, "hint": "Gross profit margin = (Gross profit ÷ Revenue) × 100. Both figures are given in the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 = 2 marks)</h5><ul><li><strong>2 marks:</strong> Correct answer of 66.8% (with or without workings)</li><li><strong>1 mark:</strong> For setting out the correct calculation</li><li>Accept 67%, 66.76%, 66.7%</li><li>Maximum one mark if incorrect or no units</li></ul></div><div class=\"marks-section\"><h5>Working</h5><ul><li>£24,980m ÷ £37,417m × 100 = <strong>66.8%</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Nearly half of candidates gained full marks. Mistakes were made with rounding and with including the wrong or no units.</p></div>"}, {"question": "Calculate the percentage change in BP''s revenue between 2017 and 2019. Show your workings. [2 marks]", "marks": 2, "hint": "Percentage change = (change ÷ original) × 100. Use the 2017 figure as the original (denominator).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 = 2 marks)</h5><ul><li><strong>1 mark:</strong> Correct change = $38bn</li><li><strong>1 further mark (OFR):</strong> $38bn ÷ $245bn × 100 = 15.5%</li><li>Accept 15% or 16% with workings shown</li><li>% sign not required (printed on paper)</li><li>Using wrong denominator giving 13.4% = 1 mark (OFR)</li></ul></div><div class=\"marks-section\"><h5>Working</h5><ul><li>$283bn − $245bn = $38bn</li><li>$38bn ÷ $245bn × 100 = <strong>15.5%</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Most candidates did well. The most common wrong answer was 13.4% when the wrong denominator (2019) was used.</p></div>"}, {"question": "Identify two factors that can affect a company''s revenue. [2 marks]", "marks": 2, "hint": "Revenue = price × quantity sold. Think about factors that affect either the price charged or the number of sales.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a = 2 marks)</h5><ul><li><strong>1 mark each</strong> for two correct factors (max 2)</li><li>Answers do not need to relate to BP</li><li>No reward for answers about costs or production levels alone</li><li>Accept answers which cause a change in demand (e.g. company reputation, promotion, customer service)</li></ul></div><div class=\"marks-section\"><h5>Answers may include:</h5><ul><li>The number of competitors</li><li>The actions of competitors</li><li>The price of the product</li><li>The level of sales / output</li><li>Quality of the product</li><li>Increasing product range</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Some candidates confused costs and revenue. Revenue is ultimately price × quantity sold, so any factor affecting either variable was accepted.</p></div>"}, {"question": "Calculate the average rate of return (ARR) for the Standard Van by using the information in Table 2. Show your workings. [3 marks]", "marks": 3, "hint": "Step 1: Calculate average annual profit (total net profit ÷ years). Step 2: ARR = (average annual profit ÷ cost of investment) × 100.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 = 3 marks)</h5><ul><li><strong>1 mark:</strong> Average annual profit = £60,000 ÷ 3 = £20,000</li><li><strong>1 further mark (OFR):</strong> £20,000 ÷ £40,000 (correct division)</li><li><strong>1 further mark (OFR):</strong> = 50%</li><li>% sign not required (printed on paper)</li></ul></div><div class=\"marks-section\"><h5>Working</h5><ul><li>£60,000 ÷ 3 years = £20,000 average annual profit</li><li>(£20,000 ÷ £40,000) × 100 = <strong>50%</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Generally well answered. Most candidates either scored 3 marks or 0 (by omitting the question). Errors were due to poor formula knowledge or selecting data from the wrong table.</p></div>"}, {"question": "Analyse one reason why QT should buy the Standard Van. Refer to Table 2 in your answer. [3 marks]", "marks": 3, "hint": "Use a specific figure from Table 2 to support your reason. Then explain the impact on QT — don''t just say ''it is cheaper'', say what that means for the business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3a = 3 marks)</h5><ul><li><strong>1 mark:</strong> Understanding a reason for buying the Standard Van</li><li><strong>1 further mark:</strong> Application of understanding to QT using Table 2 data</li><li><strong>1 further mark:</strong> Analysis of benefit of buying the Standard Van</li><li>To award APP, data must be explicitly used — ''the price is lower'' only gains understanding; ''the price is £10,000 less'' gains both</li></ul></div><div class=\"marks-section\"><h5>Understanding may include:</h5><ul><li>It is cheaper</li><li>Higher ARR / better return on investment</li><li>Meets cash flow objectives</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>Standard Van is £10,000 less than the Superior Van</li><li>Standard Van has a better ARR of 50% (OFR) compared to 35%</li><li>Total profit of £60,000 over 3 years</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>Less risk to QT</li><li>Less damage to cash flow</li><li>Allows the business to grow</li><li>Will recover the cost more quickly</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>A common error was not using data from Table 2 as instructed. Another error was for candidates to question whether to buy a van at all — that decision had already been made.</p></div>"}, {"question": "Pallin Ltd''s average level of profit over the last five years is: [1 mark]", "marks": 1, "hint": "Add all five profit/loss figures together (remember losses are negative) then divide by 5.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — £4,000 per year</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>£15,000 + £0 + (−£9,000) + £17,000 + (−£3,000) = £20,000</li><li>£20,000 ÷ 5 = <strong>£4,000 per year</strong></li></ul></div>"}, {"question": "This means: [1 mark]", "marks": 1, "hint": "GPM = (Gross Profit ÷ Revenue) × 100. If GPM is 50%, what is the relationship between the buying price and the selling price?", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — the shop charges customers double what it pays when buying the perfume</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>If GPM = 50%, then gross profit = 50% of revenue. This means cost of sales = 50% of revenue. If cost = 50% of selling price, then selling price = 2 × cost — i.e. the shop charges double what it paid.</p></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>This was the least well answered question in Section A. Answer A was most common wrong answer — £5 is 50% of £10, but this profit is after variable costs only, not ''all costs''.</p></div>"}, {"question": "The manufacturer''s estimated total cost for the year is: [1 mark]", "marks": 1, "hint": "Convert all costs to annual figures first, then add them together. Remember: rent × 12, heating × 4.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — £86,800</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Variable: 500 × £40 = £20,000</li><li>Rent: £600 × 12 = £7,200</li><li>Heating & lighting: £900 × 4 = £3,600</li><li>Other expenses: £56,000</li><li>Total = £20,000 + £7,200 + £3,600 + £56,000 = <strong>£86,800</strong></li></ul></div>"}, {"question": "Which of the following would be a variable cost for a restaurant? [1 mark]", "marks": 1, "hint": "Variable costs increase as output increases. Which item would a restaurant need more of when serving more meals?", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — Fruit and vegetables</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>Fruit and vegetables are ingredients used directly in food preparation — the more meals served, the more ingredients needed. Salaries, insurance and advertising fees are fixed or semi-fixed costs.</p></div>"}, {"question": "Tictal Ltd''s gross profit margin in 2020 was: [1 mark]", "marks": 1, "hint": "Gross profit = Revenue − Cost of sales. Then GPM = (Gross profit ÷ Revenue) × 100. Do not use expenses for this calculation.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — 75%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Gross profit = £180,000 − £45,000 = £135,000</li><li>GPM = £135,000 ÷ £180,000 × 100 = <strong>75%</strong></li></ul></div>"}, {"question": "Assuming the forecasted figures are correct, the average rate of return for this upgrade will be: [1 mark]", "marks": 1, "hint": "Total profit = total income − cost of investment. Then ARR = (average annual profit ÷ cost) × 100.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — 50%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Total income = £60,000 × 2 = £120,000</li><li>Total profit = £120,000 − £60,000 = £60,000</li><li>Average annual profit = £60,000 ÷ 2 = £30,000</li><li>ARR = £30,000 ÷ £60,000 × 100 = <strong>50%</strong></li></ul></div>"}, {"question": "Identify two variable costs which a business may incur. [2 marks]", "marks": 2, "hint": "Variable costs change with the level of output. Think about what a business uses more of when it produces more.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a = 2 marks)</h5><ul><li><strong>1 mark each</strong> for two correct variable costs</li><li>Answers do not need to apply to RCP</li><li>Do not accept ''salaries'' or ''production costs''</li></ul></div><div class=\"marks-section\"><h5>Answers may include:</h5><ul><li>Wages (labour costs)</li><li>Raw materials / cost of sales (or one example)</li><li>Stock / components</li><li>Packaging</li></ul></div>"}, {"question": "Calculate RCP''s net profit for 2020. Show your workings. [3 marks]", "marks": 3, "hint": "Step 1: Gross profit = Revenue − Cost of sales. Step 2: Net profit = Gross profit − all other expenses (salaries + rent + other).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 = 3 marks)</h5><ul><li><strong>1 mark:</strong> Gross profit = £2,000,000 − £500,000 = £1,500,000</li><li><strong>1 further mark:</strong> Net profit = £1,500,000 − (£1,300,000 + £100,000 + £50,000) = £1,500,000 − £1,450,000</li><li><strong>1 further mark:</strong> = £50,000</li><li>3 marks for correct answer with or without workings</li><li>2 marks for mathematical error with correct method shown</li><li>1 mark for correct gross profit figure with evidence of workings</li></ul></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Gross profit = £2,000,000 − £500,000 = £1,500,000</li><li>Total expenses = £1,300,000 + £100,000 + £50,000 = £1,450,000</li><li>Net profit = £1,500,000 − £1,450,000 = <strong>£50,000</strong></li></ul></div>"}, {"question": "Analyse one way Alessia and Natalia could use the data shown in Table 1 to improve their net profit margin. [3 marks]", "marks": 3, "hint": "Look at which cost in the table is the largest. Then suggest how reducing it would improve the net profit margin, and explain the impact on the business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3a = 3 marks)</h5><ul><li><strong>1 mark:</strong> Understanding of one way to improve net profit margin</li><li><strong>1 further mark:</strong> Application to RCP using data from Table 1</li><li><strong>1 further mark:</strong> Analysis of how this would improve the profit margin</li></ul></div><div class=\"marks-section\"><h5>Understanding may include:</h5><ul><li>Recognise expenses / salaries / costs are too high or need decreasing</li><li>Need to increase revenue relative to costs</li><li>Identify which costs are highest</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>Net profit margin is 2.5% (£50,000 ÷ £2,000,000)</li><li>RCP''s salaries account for 65% of revenue earned (£1,300,000)</li><li>Cost of sales = 25% of revenue</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>A pay cut would reduce salaries so that profits will increase</li><li>Lower quality raw materials would increase the gap between revenue and costs</li></ul></div>"}, {"question": "What percentage reduction in transport costs has Shanco plc achieved? [1 mark]", "marks": 1, "hint": "Percentage change = (change ÷ original) × 100. The original is the 2019 figure.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — 14.3%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Change = £0.7m − £0.6m = £0.1m</li><li>% reduction = £0.1m ÷ £0.7m × 100 = <strong>14.3%</strong></li></ul></div>"}, {"question": "Calculate the gross profit margin for 2019. Show your workings. [2 marks]", "marks": 2, "hint": "Gross profit margin = (Gross profit ÷ Revenue) × 100. Both figures are given in the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 = 2 marks)</h5><ul><li><strong>2 marks:</strong> Correct answer (with or without workings)</li><li><strong>1 mark:</strong> Evidence of using the correct two numbers</li><li>Maximum 1 mark if incorrect units or magnitude</li><li>Accept 79% or 78.6%</li></ul></div><div class=\"marks-section\"><h5>Working</h5><ul><li>£118,000 ÷ £150,000 × 100 = <strong>78.7%</strong></li></ul></div>"}, {"question": "Calculate the net profit margin for 2019. Show your workings. [2 marks]", "marks": 2, "hint": "Net profit margin = (Net profit ÷ Revenue) × 100. Both figures are given in the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 = 2 marks)</h5><ul><li><strong>2 marks:</strong> Correct answer (with or without workings)</li><li><strong>1 mark:</strong> Evidence of using the correct two numbers</li><li>Maximum 1 mark if incorrect units or magnitude</li><li>Accept 38% or 37.8%</li></ul></div><div class=\"marks-section\"><h5>Working</h5><ul><li>£56,800 ÷ £150,000 × 100 = <strong>37.9%</strong></li></ul></div>"}, {"question": "The company''s labour costs in 2019 were: [1 mark]", "marks": 1, "hint": "Calculate 40% of £9 million.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — £3.6 million</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>£9m × 0.40 = <strong>£3.6 million</strong></li></ul></div>"}, {"question": "Variable costs: [1 mark]", "marks": 1, "hint": "Think about what happens to variable costs when a business produces more — e.g. more raw materials needed.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — increase as output rises</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>Variable costs (e.g. raw materials, direct labour) rise directly in line with the level of production. Fixed costs remain constant; variable costs do not.</p></div>"}, {"question": "The expected average rate of return for this purchase is: [1 mark]", "marks": 1, "hint": "Total profit = total income − cost. Average annual profit = total profit ÷ years. ARR = (average annual profit ÷ cost) × 100.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — 16.67%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Total income = £3,000 × 3 = £9,000</li><li>Total profit = £9,000 − £6,000 = £3,000</li><li>Average annual profit = £3,000 ÷ 3 = £1,000</li><li>ARR = £1,000 ÷ £6,000 × 100 = <strong>16.67%</strong></li></ul></div>"}, {"question": "Explain what is meant by the gross profit margin. [2 marks]", "marks": 2, "hint": "Think about what gross profit margin measures and how it is calculated. You can reference the formula.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a = 2 marks)</h5><ul><li><strong>2 marks:</strong> A correct explanation of gross profit margin</li><li><strong>1 mark:</strong> A partial explanation</li><li>Allow explanation through use of the formula: GPM = (Revenue − Cost of sales) ÷ Revenue × 100</li></ul></div>"}, {"question": "In year 2, CFM made £200,000 total revenue. Calculate CFM''s net profit for year 2. Show your workings. [2 marks]", "marks": 2, "hint": "Net profit = Net profit margin % × Revenue. The NPM for Year 2 is given in Table 1.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a + AO2 = 2 marks)</h5><ul><li><strong>1 mark:</strong> Stating the formula to calculate net profit</li><li><strong>1 further mark:</strong> Correct answer of £50,000</li><li>2 marks for correct answer even if workings not shown</li></ul></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Net profit = 25% × £200,000 = <strong>£50,000</strong></li></ul></div>"}, {"question": "Analyse one change in CFM''s profitability. Refer to Table 1 in your answer. [3 marks]", "marks": 3, "hint": "State what has changed in the margins (use figures). Then explain what ''profitability'' means. Then analyse what this change means for the business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3 = 3 marks)</h5><ul><li><strong>1 mark:</strong> Understanding of profitability</li><li><strong>1 further mark:</strong> Application of a change in CFM''s profitability from Table 1</li><li><strong>1 further mark:</strong> Analysis of a change in CFM''s profitability</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>GPM increased from 60% in Year 1 to 70% in Year 2</li><li>NPM increased from 20% in Year 1 to 25% in Year 2</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>More profit for Martin and Anne</li><li>More likely to obtain finance for the new café</li></ul></div>"}, {"question": "If Andrea paints and sells 50 portraits a year, total costs are estimated to be: [1 mark]", "marks": 1, "hint": "Total variable cost = (£52 + £23) × 50. Total fixed cost = £1,000 × 12. Add them together.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — £15,750 per year</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Variable cost per portrait = £52 + £23 = £75</li><li>Total variable costs = £75 × 50 = £3,750</li><li>Total fixed costs = £1,000 × 12 = £12,000</li><li>Total costs = £3,750 + £12,000 = <strong>£15,750</strong></li></ul></div>"}, {"question": "This data is useful to Seiji when making business decisions because it shows that: [1 mark]", "marks": 1, "hint": "Add up all three cost rows for each year and compare. What trend can you see?", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — total costs are increasing</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>2015: £44,000 + £36,000 + £18,000 = £98,000</li><li>2016: £66,000 + £35,000 + £25,000 = £126,000</li><li>2017: £65,000 + £34,000 + £32,000 = £131,000</li><li>2018: £62,000 + £33,000 + £39,000 = £134,000</li><li>Labour costs fell after 2016, so A is wrong. No revenue data, so B and C cannot be confirmed. D is correct.</li></ul></div>"}, {"question": "Assuming the forecasted figures are correct, the average rate of return for upgrading the robotics will be: [1 mark]", "marks": 1, "hint": "Total profit = total income − cost. Average annual profit = total profit ÷ years. ARR = (average annual profit ÷ cost) × 100.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — 5%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Total income = £1m × 5 = £5m</li><li>Total profit = £5m − £4m = £1m</li><li>Average annual profit = £1m ÷ 5 = £200,000</li><li>ARR = £200,000 ÷ £4,000,000 × 100 = <strong>5%</strong></li></ul></div>"}, {"question": "The agency''s percentage increase in spending on digital communications from 2017 to 2018 was approximately equal to: [1 mark]", "marks": 1, "hint": "The spending has more than doubled, so the answer must be more than 100%. Use the 2017 figure as the original.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — 110%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Change = £525,000 − £250,000 = £275,000</li><li>% change = £275,000 ÷ £250,000 × 100 = <strong>110%</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>This had the greatest proportion of incorrect answers of all the MCQ questions. The figures have more than doubled, so the answer must be greater than 100%. A common misconception is dividing by the new value instead of the original.</p></div>"}, {"question": "Explain, giving an example, what is meant by ''fixed costs''. [2 marks]", "marks": 2, "hint": "A fixed cost does not change when output changes. Give a definition AND an example relevant to the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a + AO1b = 2 marks)</h5><ul><li><strong>1 mark:</strong> Meaning of the term ''fixed cost'' (a cost that does not vary with level of output/sales)</li><li><strong>1 mark:</strong> A suitable example</li></ul></div><div class=\"marks-section\"><h5>Answers may include (examples):</h5><ul><li>Rent</li><li>Equipment costs</li><li>Receptionist''s salary</li></ul></div>"}, {"question": "What was the market stall''s revenue? [1 mark]", "marks": 1, "hint": "Revenue = price × quantity for each product. Then add the two totals together.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — £2,200</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Bread revenue = £1 × 1,000 = £1,000</li><li>Cookie revenue = £0.60 × 2,000 = £1,200</li><li>Total revenue = £1,000 + £1,200 = <strong>£2,200</strong></li></ul></div>"}, {"question": "Gross profit margin is: [1 mark]", "marks": 1, "hint": "Think about what category gross profit margin belongs to — it''s a way of measuring financial performance.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — a financial ratio</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>Gross profit margin expresses gross profit as a proportion (ratio) of revenue. It is used to assess a business''s financial performance — it is not a method of production, pricing strategy, or cost.</p></div>"}, {"question": "Which one of the following must be true for this business? [1 mark]", "marks": 1, "hint": "A positive net profit margin means the business is profitable. What does that tell you about revenues vs costs?", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — The business has revenues that are greater than its costs</strong></p></div><div class=\"marks-section\"><h5>Why</h5><p>A positive net profit margin of 8% means the business is making a profit — so revenues must exceed total costs. It does not tell us about short-term debt or whether it is above break-even in terms of units.</p></div>"}, {"question": "What is the approximate increase between 2015 and 2016 in Jimco plc''s production costs? [1 mark]", "marks": 1, "hint": "Percentage change = (change ÷ original) × 100. Use the 2015 figure as the original.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — 7.5%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Change = £22.9m − £21.3m = £1.6m</li><li>% change = £1.6m ÷ £21.3m × 100 = <strong>7.5%</strong></li></ul></div>"}, {"question": "Analyse how M&S''s ''Plan A'' ethical programme may impact on the profitability of the business. [3 marks]", "marks": 3, "hint": "Think about BOTH a cost side and a revenue/benefit side. Make sure your analysis links to profitability — not just profit — by explaining the gap between revenue and costs.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3a = 3 marks)</h5><ul><li><strong>1 mark:</strong> Understanding of the impact of ethical considerations</li><li><strong>1 further mark:</strong> Application to M&S using evidence from the text</li><li><strong>1 further mark:</strong> Analysis of impact on M&S''s profitability</li><li>No marks without understanding</li></ul></div><div class=\"marks-section\"><h5>Understanding may include:</h5><ul><li>It may cost more to be ethical to workers / suppliers / customers</li><li>It may benefit a business''s reputation</li><li>It may benefit sales revenue or recruitment/retention</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>''Nourishing our wellbeing'' — staff wages, hours, safe working conditions</li><li>''Transforming local communities'' — supporting staff who volunteer in charities</li><li>''Caring for the planet we share'' — developing better recycling for packaging</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>If costs stay the same, ethical actions will increase profitability</li><li>If costs rise more than revenue, profitability will decrease</li><li>Improved reputation may increase sales and revenue</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Many candidates struggled to analyse the impact on profitability (not just profit). To show an impact on profitability, the answer must show that the difference between costs and revenue is either increasing or decreasing.</p></div>"}, {"question": "In 2018 Pluck and Grow Ltd made: [1 mark]", "marks": 1, "hint": "Add up all costs, then subtract from revenue.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — a profit of £16,000</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Total costs = £26,000 + £16,000 + £10,000 = £52,000</li><li>Profit = £68,000 − £52,000 = <strong>£16,000</strong></li></ul></div>"}, {"question": "The data shows that: [1 mark]", "marks": 1, "hint": "Add up all three transport modes for 2018 and compare to £1.25 million.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — GLU plc spent more than £1.25 million on transport costs in 2018</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>2018 total: £190,000 + £430,000 + £650,000 = £1,270,000 > £1.25m ✓</li><li>Costs are rising (not falling), so B is wrong</li><li>Higher spending on air does not mean preference, so A is unconfirmed</li><li>Higher costs by rail doesn''t confirm more goods transported, so D is unconfirmed</li></ul></div>"}, {"question": "What was Exobike''s gross profit margin? [1 mark]", "marks": 1, "hint": "First calculate total revenue (price × quantity). Then GPM = (gross profit ÷ revenue) × 100. Note: two options are not even percentages, so you can eliminate them.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — 68%</strong></p></div><div class=\"marks-section\"><h5>Working</h5><ul><li>Revenue = 42 × £350 = £14,700</li><li>GPM = £9,996 ÷ £14,700 × 100 = <strong>68%</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Candidates could eliminate C and D immediately as they are monetary values, not percentages. Even without doing the full calculation, knowledge that a GPM is a percentage narrows the answer to A or B — and 68% is a realistic margin while 147% is not possible.</p></div>"}, {"question": "Identify one fixed cost a business could have. [1 mark]", "marks": 1, "hint": "A fixed cost does not change when output changes. Think of a cost that stays the same regardless of how many items are made.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b = 1 mark)</h5><ul><li><strong>1 mark:</strong> A correct identification of a fixed cost</li><li>This is not a contextual question — any valid fixed cost is acceptable</li></ul></div><div class=\"marks-section\"><h5>Answers may include:</h5><ul><li>Salaries</li><li>Rent</li><li>Insurance</li><li>Business rates</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>The most common correct answer was ''rent''. Salaries were also accepted as a fixed payment to workers that does not vary as output changes.</p></div>"}, {"question": "Explain what is meant by ''variable costs''. [2 marks]", "marks": 2, "hint": "Variable costs change. But change in relation to what? Make sure your explanation links the change to output or sales.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a = 2 marks)</h5><ul><li><strong>1 mark:</strong> Identifying that variable costs change</li><li><strong>1 further mark:</strong> Linking the change to output/sales</li><li>Do not accept tautological answers using the word ''vary''</li></ul></div>"}, {"question": "Calculate how much SP spent on wages in 2018. Show your workings. [2 marks]", "marks": 2, "hint": "Use Pie chart 2 to find the percentage spent on wages in 2018. Then multiply by the total monthly variable costs. Remember the question asks for annual spending — multiply by 12.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 = 2 marks)</h5><ul><li><strong>1 mark:</strong> Correctly calculating monthly wage spend = 35% × £5,500 = £1,925</li><li><strong>1 further mark (OFR):</strong> Annual wages = £1,925 × 12 = £23,100</li><li>2 marks for correct final answer</li><li>If 2017 figures used: 40% × £4,400 = £1,760 × 12 = £21,120 (OFR) = 1 mark</li></ul></div><div class=\"marks-section\"><h5>Working</h5><ul><li>35% × £5,500 = £1,925 per month</li><li>£1,925 × 12 = <strong>£23,100</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>The vast majority stopped at £1,925 (monthly figure) and did not multiply by 12. Candidates must read whether a question asks for a monthly or annual figure.</p></div>"}, {"question": "Analyse one change in SP''s dry cleaning chemical costs between 2017 and 2018. Refer to Pie charts 1 and 2 in your answer. [3 marks]", "marks": 3, "hint": "Use both pie charts to calculate the actual cost in pounds for dry cleaning chemicals in each year. Then compare the change and explain what it means for SP.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 + AO3a = 3 marks)</h5><ul><li><strong>1 mark:</strong> Applying information from Pie charts 1 and 2 to SP (using actual figures)</li><li><strong>2 marks:</strong> Analysing the change in SP''s spending on dry cleaning chemicals</li><li>Analysis marks can come from two separate effects OR development of one effect</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>2017: 20% × £4,400 = £880/month (£10,560/year)</li><li>2018: 20% × £5,500 = £1,100/month (£13,200/year)</li><li>Increase of £220/month or £2,640/year</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>Costs increased by £220/month, however the proportion of all variable costs stayed the same (both 20%)</li><li>May be due to more sales, leading SP to purchase more chemicals</li><li>May be due to the cost of chemicals increasing</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>The dry cleaning chemical proportion stayed at 20%, but the actual value increased by £220/month. Many candidates lacked analysis of what this change meant for the business.</p></div>"}, {"question": "Calculate SP''s Average Rate of Return (ARR) on the purchase of HD Sewing. Show your workings. [3 marks]", "marks": 3, "hint": "Step 1: Total income = net profit per year × years (5). Step 2: Total profit = total income − purchase price. Step 3: Average annual profit = total profit ÷ years. Step 4: ARR = (average annual profit ÷ purchase price) × 100.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO2 = 3 marks)</h5><ul><li><strong>1 mark:</strong> Total income = £25,000 × 5 = £125,000</li><li><strong>1 further mark (OFR):</strong> Total profit = £125,000 − £80,000 = £45,000</li><li><strong>1 further mark (OFR):</strong> ARR = (£45,000 ÷ 5) ÷ £80,000 × 100 = 11.25%</li><li>Accept 11.3% or 11%</li><li>Answer of 31.25% (without subtracting purchase price) = 2 marks</li></ul></div><div class=\"marks-section\"><h5>Working</h5><ul><li>£25,000 × 5 = £125,000</li><li>£125,000 − £80,000 = £45,000</li><li>£45,000 ÷ 5 = £9,000</li><li>£9,000 ÷ £80,000 × 100 = <strong>11.25%</strong></li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>The most important step candidates missed was subtracting the purchase price to find SP''s profit. Without this, the answer of 31.25% was awarded 2 marks. Stages of calculation should be clearly set out.</p></div>"}, {"question": "Analyse one reason why SP should buy HD Sewing. Refer to data from Table 1 in your answer. [3 marks]", "marks": 3, "hint": "Use a specific figure from Table 1 to support your reason. Then analyse the impact on SP as a business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3a = 3 marks)</h5><ul><li><strong>1 mark:</strong> Understanding a reason for buying HD Sewing</li><li><strong>1 further mark:</strong> Use of data from Table 1 (or Q46c ARR — OFR)</li><li><strong>1 further mark:</strong> Analysis of one advantage to SP of purchasing HD Sewing</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>HD has higher sales revenue of £90,000 (vs £82,500)</li><li>HD has higher annual net profit of £25,000 (vs £22,000)</li><li>HD has higher net profit margin of 28% (vs 27%)</li><li>HD has better ARR of 11.25% vs 13.8% — OFR</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>Higher net profit means Stuart and Pippa can pay themselves a bigger income</li><li>Allows the business to grow more quickly</li><li>Better net profit margin indicates a more efficient business</li></ul></div>"}, {"question": "Analyse one reason why SP should buy Fast Stitch. Refer to data from Table 1 in your answer. [3 marks]", "marks": 3, "hint": "Use a specific figure from Table 1 to support your reason. Think about what makes Fast Stitch attractive — price, ARR, risk.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3a = 3 marks)</h5><ul><li><strong>1 mark:</strong> Understanding a reason for buying Fast Stitch</li><li><strong>1 further mark:</strong> Use of data from Table 1 (or Q46c ARR — OFR)</li><li><strong>1 further mark:</strong> Analysis of one advantage to SP of purchasing Fast Stitch</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>FS has lower purchase price of £65,000 (vs £80,000 for HD)</li><li>FS has a better ARR of 13.8% compared to HD''s 11.25% (OFR)</li><li>FS will return the investment in less than three years</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>Lower purchase price means less money and risk for SP</li><li>Higher ARR means SP gains more profit relative to the cost of investment</li><li>Less risk to SP''s cash flow</li></ul></div>"}, {"question": "Recommend whether SP should buy HD Sewing or Fast Stitch to expand their business. Refer to data from Table 1 to support your judgement. [3 marks]", "marks": 3, "hint": "Make a clear recommendation (1 mark). Then justify it with a reason linked to the data (1 mark). Then use a specific detail from the case study to contextualise your judgement (1 mark). Do NOT sit on the fence.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO3b = 3 marks)</h5><ul><li><strong>1 mark:</strong> A judgement — recommend HD Sewing OR Fast Stitch</li><li><strong>1 further mark:</strong> Justification for the judgement</li><li><strong>1 further mark:</strong> Use of context within the justification (reference to data from Table 1)</li><li>All 3 marks are for evaluation only — no marks for other skill areas</li><li>No reward for ''sitting on the fence''</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comment</h5><p>Most candidates made a recommendation. The most common argument for HD was higher net profit per year; the most common argument for Fast Stitch was the lower purchase price. Figures needed to be referenced but did not need to be quoted exactly. The command word ''recommend'' requires a decision to be made.</p></div>"}]}}'::jsonb),
('business', '3-3-communication-in-business', '3.3 Communication in Business', '{"learn": {"enabled": true, "items": [{"title": "Core Terminology", "html": "<ul>\n<li><strong>Communication</strong> — the transmission of a message from a sender to a receiver through a means of communication</li>\n<li><strong>Verbal communication</strong> — communicating by speaking: in meetings, on the telephone, by video-conferencing, or through a presentation</li>\n<li><strong>Written communication</strong> — communication by written words: text, email, and letters</li>\n<li><strong>Digital communication</strong> — the electronic exchange of information using ICT (voice, text, diagrams, pictures, video)</li>\n<li><strong>Feedback</strong> — the response made by a person who receives a communication, indicating they have (or have not) understood it</li>\n<li><strong>Internal communication</strong> — communication between people employed in the same organisation</li>\n<li><strong>External communication</strong> — communication between people in an organisation and others outside it</li>\n<li><strong>Formal communication</strong> — communication through official channels (e.g. letters, official meetings, reports)</li>\n<li><strong>Informal communication</strong> — communication outside official channels (e.g. conversations in a break)</li>\n<li><strong>Social media</strong> — online applications that allow people to create and share content to participate in social networking</li>\n<li><strong>Website</strong> — an online location with several pages that can be contacted by internet users through its address</li>\n</ul>", "check": {"question": "Which term describes communication between people employed in the same organisation?", "options": ["Internal communication", "Feedback", "Formal communication", "External communication"], "answer": 0, "explain": "Internal communication is defined as communication between people employed in the same organisation, unlike external communication which involves people outside it."}}, {"title": "One-way, Two-way & Direction of Communication", "html": "<p><strong>One-way communication:</strong> the message is sent but there is no reply. Good for giving information to large numbers of people (e.g. a tannoy announcement, an advertising leaflet). Examples: email broadcast, website, social media post.</p>\n<p><strong>Two-way communication:</strong> the receiver can reply to the sender. Important because:</p>\n<ul>\n<li>Feedback confirms the message has been received and understood</li>\n<li>It is good for generating ideas and solving problems</li>\n</ul>\n<p><strong>Vertical communication:</strong> between people on different layers of the hierarchy — either downward (manager to worker) or upward (worker to manager).</p>\n<p><strong>Horizontal communication:</strong> between people at the same level within the organisation structure (e.g. two managers in different departments).</p>\n<p><strong>Internal vs External:</strong> Internal = within the organisation. External = between someone inside the organisation and someone outside it (e.g. a supplier, customer, or government body).</p>", "check": {"question": "Communication between two managers who work at the same level in different departments is an example of which type of communication?", "options": ["Vertical communication", "One-way communication", "External communication", "Horizontal communication"], "answer": 3, "explain": "Horizontal communication takes place between people at the same level within the organisation structure, whereas vertical communication moves up or down the hierarchy."}}, {"title": "Verbal Communication — Methods, Advantages & Disadvantages", "html": "<p><strong>Examples:</strong> phone calls, meetings (in person or via Teams/Zoom), presentations</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages</div>\n<div class=\"pro-item\">Can check the message has been understood by asking for feedback immediately</div>\n<div class=\"pro-item\">Tone of voice and body language can emphasise key points</div>\n<div class=\"pro-item\">Can use diagrams, pictures, slides to support the message</div>\n<div class=\"pro-item\">Meetings — minutes provide a record; ideas can be generated and problems solved</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages</div>\n<div class=\"con-item\">No permanent record (unless minutes taken or recording made)</div>\n<div class=\"con-item\">With large audiences, hard to check everyone has heard or understood</div>\n<div class=\"con-item\">Receiver may disrupt or interrupt the message</div>\n<div class=\"con-item\">Some forms (e.g. travel for international meetings) can be expensive</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Meetings</strong> can be formal (with an agenda and chairperson) or informal (impromptu, no agenda). Online meetings via Teams or Zoom save travel costs.</p>\n<p><strong>Presentations</strong> may use PowerPoint to support visual explanation; the speaker can respond to questions.</p>", "check": {"question": "What is a key disadvantage of verbal communication such as a phone call or meeting?", "options": ["There is usually no permanent record unless minutes are taken", "Feedback cannot be given immediately", "It is never a suitable method for solving business problems", "It cannot use tone of voice to emphasise key points"], "answer": 0, "explain": "The card lists the lack of a permanent record (unless minutes are taken or a recording made) as a disadvantage of verbal communication."}}, {"title": "Written Communication — Letters, Emails, Texts", "html": "<p><strong>Letters:</strong> formal, provide a physical record; can be sent by recorded delivery; often used for contracts or legal documents.</p>\n<p><strong>Emails and texts:</strong> fast, widely used; can be sent to one or many people; disadvantage is that bulk emails are often ignored or sent to spam.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages of Written</div>\n<div class=\"pro-item\">There is a record of the message</div>\n<div class=\"pro-item\">Receiver can read and re-read to check understanding</div>\n<div class=\"pro-item\">Can be sent to multiple people at once</div>\n<div class=\"pro-item\">Can avoid confrontation</div>\n<div class=\"pro-item\">Text and email are very fast</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages of Written</div>\n<div class=\"con-item\">Cannot immediately check receiver has understood</div>\n<div class=\"con-item\">Success depends on how clearly it has been written</div>\n<div class=\"con-item\">Risk of virus infection from email attachments</div>\n<div class=\"con-item\">Emails can get lost in spam</div>\n<div class=\"con-item\">Some people get overwhelmed by volume of emails</div>\n</div>\n</div>", "check": {"question": "Which of these is a specific advantage of written communication compared with verbal communication?", "options": ["It allows the sender to check understanding immediately", "It is always cheaper than any other method", "Tone of voice can be used to emphasise key points", "It leaves a permanent record the receiver can re-read"], "answer": 3, "explain": "The card states that written communication leaves a record of the message and lets the receiver read and re-read it to check understanding, unlike verbal communication."}}, {"title": "Social Media & Websites", "html": "<p><strong>Social media</strong> (Facebook, Instagram, Twitter/X, Pinterest): online platforms for sharing communication.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages</div>\n<div class=\"pro-item\">Huge number of users — massive reach for advertising</div>\n<div class=\"pro-item\">Information can be updated regularly</div>\n<div class=\"pro-item\">Visual images enhance communications</div>\n<div class=\"pro-item\">Cheaper than traditional media (TV, radio, print)</div>\n<div class=\"pro-item\">Allows customer feedback and interaction</div>\n<div class=\"pro-item\">Good for internal staff communication across locations</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages</div>\n<div class=\"con-item\">Needs managing — updating and responding costs time and money</div>\n<div class=\"con-item\">Difficult to measure the effectiveness of campaigns</div>\n</div>\n</div>\n<p style=\"margin-top:8px;\"><strong>Websites:</strong> operate 24/7; can take online orders; detailed product information; customers use search engines to find them; can be built and maintained cheaply. Risks: website crashing, spam, needs regular updating.</p>\n<p><strong>Targeting note:</strong> 90% of Instagram users are under 35 — good for reaching young audiences. Pinterest is popular with women and used for DIY, fashion, food.</p>", "check": {"question": "Which of the following is a genuine disadvantage of using social media for business communication?", "options": ["It has a very limited reach compared with traditional media", "It cannot be updated regularly", "It is difficult to measure the effectiveness of campaigns", "It cannot be used for internal staff communication"], "answer": 2, "explain": "The card lists difficulty measuring the effectiveness of campaigns as a disadvantage, while its advantages include huge reach, regular updating and internal staff use."}}, {"title": "Importance of Communication in Each Functional Area", "html": "<p><strong>Marketing:</strong> external communication for market research and advertising; internal communication for planning promotional campaigns</p>\n<p><strong>Finance:</strong> external communication to arrange bank loans; internal communication about income and expenditure to keep accurate accounts; digital tools have made invoicing, payments and financial reporting much faster (e.g. Quickbooks app)</p>\n<p><strong>Human Resources:</strong> external and internal communication for recruitment and selection; internal communication to resolve workplace problems, motivate workers, appraise performance</p>\n<p><strong>Operations / Production:</strong> internal communication about quality to reduce waste; marketing informs production about orders placed; external communication to enquire about raw material deliveries</p>\n<p><strong>Government and Trade:</strong> external communication to understand regulations; to apply for government grants</p>\n<p><strong>Choosing the right method:</strong> consider WHO you are communicating with, the PURPOSE of the communication, and what methods are AVAILABLE and AFFORDABLE. Internal vs external, size of audience, urgency, and sensitivity all affect the choice.</p>", "check": {"question": "According to the card, alongside who you are communicating with and what methods are available and affordable, what else should a business consider when choosing a communication method?", "options": ["The colour scheme of the company logo", "The total number of shareholders", "The purpose of the communication", "The age of the business"], "answer": 2, "explain": "The card states that a business should consider WHO it is communicating with, the PURPOSE of the communication, and what methods are AVAILABLE and AFFORDABLE."}}, {"title": "How Digital Communication Influences Business Activity", "html": "<p><strong>Marketing:</strong> websites and social media allow businesses to reach millions globally; online selling has reduced the need for physical shops (e.g. Amazon, eBay); competition has increased as customers can compare prices more easily</p>\n<p><strong>Finance:</strong> invoices and payments sent more quickly; accounting information stored and processed digitally; financial reports prepared faster (Chatsworth Estate case study — one accountant handled 20× the business)</p>\n<p><strong>HR:</strong> jobs advertised on websites; applications and invitations by email; interviews by video-conferencing (Zoom/Teams); more staff working from home or while mobile; some jobs lost as productivity increased; workers required to retrain</p>\n<p><strong>Operations:</strong> production highly automated via robots; quality control improved (machines inspect and relay data); production is leaner — can be reprogrammed quickly in response to demand changes; GPS tracking of delivery drivers; staff monitoring via keyloggers, Microsoft Teams log-on records</p>\n<p><strong>Overall:</strong> digital communication has increased competition, enabled globalisation, reduced costs, and created new business opportunities (hardware makers, programmers, ICT trainers). Not all businesses have survived — some slow to adapt have closed (e.g. Blockbuster).</p>", "check": {"question": "What does the closure of businesses such as Blockbuster during the rise of digital communication demonstrate?", "options": ["All traditional retailers are guaranteed to close eventually", "Only marketing departments are affected by digital communication", "Digital communication has no effect on business survival", "Some businesses fail if they are too slow to adapt to digital change"], "answer": 3, "explain": "The card notes that not all businesses have survived the digital communication revolution — some, like Blockbuster, were too slow to adapt and closed."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Communication", "definition": "The transmission of a message from a sender to a receiver through a means of communication."}, {"term": "One-way communication", "definition": "Communication where the message is sent but there is no reply. Good for giving information (e.g. tannoy announcements, advertising leaflets, social media posts)."}, {"term": "Two-way communication", "definition": "Communication where the receiver can reply to the sender. Allows feedback to confirm understanding and enables ideas and solutions to be discussed."}, {"term": "Internal communication", "definition": "Communication between people employed in the same organisation. Can be vertical (upward or downward) or horizontal."}, {"term": "External communication", "definition": "Communication between someone inside an organisation and someone outside it — e.g. customers, suppliers, government."}, {"term": "Vertical communication", "definition": "Communication between people on different layers of the hierarchy. Downward: manager to worker. Upward: worker to manager."}, {"term": "Horizontal communication", "definition": "Communication between people at the same level of the hierarchy — e.g. two department managers discussing a shared project."}, {"term": "Formal communication", "definition": "Communication through official channels: letters, official meetings with an agenda and chairperson, written reports."}, {"term": "Informal communication", "definition": "Communication outside official channels, such as a conversation during a lunch break or at a work social event. Can be just as important as formal communication."}, {"term": "Digital communication", "definition": "The electronic exchange of information using ICT — including voice, text, images, diagrams, and video. Has transformed business activity globally."}, {"term": "Verbal communication — advantages", "definition": "Can check understanding via immediate feedback. Tone of voice and body language emphasise points. Can use diagrams and slides for support. Good for discussion and problem-solving."}, {"term": "Verbal communication — disadvantages", "definition": "No permanent record unless minutes are taken or a recording made. Hard to check all listeners have understood. Can be expensive (travel for meetings). Receiver may disrupt the message."}, {"term": "Written communication — advantages", "definition": "There is a record of the message. Receiver can re-read. Can be sent to many people at once. Can avoid confrontation. Email and text are very fast."}, {"term": "Written communication — disadvantages", "definition": "Cannot immediately check understanding. Success depends on clarity of writing. Emails can get lost in spam. Risk of virus infection. Volume of emails can overwhelm."}, {"term": "Social media — advantages", "definition": "Huge number of users; can be updated regularly; visual images used; cheaper than traditional media; allows customer feedback; good for internal staff communication."}, {"term": "Website — advantages", "definition": "Operates 24/7; online orders; promotes to millions globally; detailed product information; customers use search engines to find it; relatively cheap to set up."}, {"term": "Digital communication — impact on marketing", "definition": "Websites and social media allow global reach; online selling reduces need for physical shops; competition increased; businesses like Amazon grew through online selling."}, {"term": "Digital communication — impact on HR", "definition": "Jobs advertised online; applications and interviews via email and video-conferencing; more home and mobile working; some jobs lost; workers need to retrain."}, {"term": "Digital communication — impact on operations", "definition": "Highly automated production; robots controlled digitally; quality control improved via machine inspection; production leaner; GPS tracking of staff."}, {"term": "Digital communication — impact on finance", "definition": "Invoices and payments sent more quickly; accounting information stored and processed faster; financial reports prepared digitally (e.g. Quickbooks); payments made digitally."}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of these statements is FALSE?", "options": ["Digital communication is always better than non-digital communication", "Digital communication has been a major force behind the globalisation of business", "Digital communication involves the electronic transfer of information", "Mobile phones, computers and tablets can transfer information electronically"], "answer": 0, "explain": "Digital communication is NOT always better than non-digital. Face-to-face meetings, for example, allow immediate feedback, body language, and discussion that digital communication cannot always replicate. ''Always'' is a giveaway that this statement is false."}, {"question": "Which of the following is NOT an advantage of meetings?", "options": ["The sender can check immediately whether the receiver has understood the message", "It is a way of avoiding confrontation when the message is given", "The sender of the message can always be seen and heard by the receiver", "There will usually be a record of formal meetings in the form of minutes"], "answer": 1, "explain": "Avoiding confrontation is an advantage of WRITTEN communication, not meetings. Meetings involve face-to-face interaction, which can actually make confrontation more likely. Written communication allows a message to be delivered without direct conflict."}, {"question": "Which of the following is NOT true about digital communication?", "options": ["The development of digital communication has benefited all workers", "It has helped to increase globalisation of business", "It has made it possible for some workers to work at home", "It has increased competition often leading to lower prices"], "answer": 0, "explain": "Digital communication has NOT benefited ALL workers. While many have gained new opportunities and flexibility, others have lost their jobs as productivity improved and automation replaced roles. Workers have also had to undergo retraining."}, {"question": "In 2021, Instagram had 1 billion users. 300 million were aged 18–24. The percentage of Instagram users in the 18–24 bracket is:", "options": ["33%", "30%", "13%", "3%"], "answer": 1, "explain": "300 million ÷ 1,000 million × 100 = 30%. This shows how Instagram is heavily used by young people, making it a strong platform for businesses targeting under-35 customers."}, {"question": "What is a disadvantage for a business of using digital communication?", "options": ["It is a slow method of communication", "Worldwide communication is not possible", "The technology on which it relies can fail", "Pictures and videos cannot be shared"], "answer": 2, "explain": "Technology failure is a real risk of digital communication — systems can crash, lose data, or be disrupted by cyber-attacks or power cuts. Options A, B, and D are all incorrect: digital communication is fast, can share rich media, and enables worldwide reach."}, {"question": "A market research agency spent £250,000 on digital communication in 2017 and £525,000 in 2018. The percentage increase was approximately:", "options": ["52%", "48%", "110%", "210%"], "answer": 2, "explain": "Percentage change = (New − Old) ÷ Old × 100 = (525,000 − 250,000) ÷ 250,000 × 100 = 275,000 ÷ 250,000 × 100 = 110%. A common mistake is dividing by the NEW value — always divide by the ORIGINAL value."}, {"question": "Which of these is an example of digital communication?", "options": ["A letter", "A face-to-face interview", "A website", "A magazine"], "answer": 2, "explain": "A website is digital communication — it uses ICT to exchange information electronically. A face-to-face interview is verbal, a letter is written (non-digital), and a magazine is print media."}, {"question": "A frozen food manufacturer urgently needs its maintenance contractor to repair its freezers. Which is the best method?", "options": ["Send a letter by first class post", "Post a message on its website saying it has problems with freezers", "Produce a presentation to explain the problem", "Telephone the maintenance contractor and explain the problem"], "answer": 3, "explain": "The phone is the best method here because it is URGENT and requires TWO-WAY communication so the contractor can ask questions and clarify details immediately. A letter is too slow, a website post is not directed at the contractor, and a presentation is unnecessary for an urgent repair."}, {"question": "Which one of the following is NOT a potential benefit of improving communication between a business and its customers?", "options": ["Greater market share", "Better customer service", "Higher chances of survival", "Increased risk"], "answer": 3, "explain": "Increased risk is a potential consequence of poor communication, not better communication. Improved communication leads to better customer service, greater market share, and higher chances of survival — all business benefits."}, {"question": "A farmer urgently needs a spare part for a tractor but doesn''t know its name or code. Which is the best communication method?", "options": ["Send a letter showing a sketch of the part", "Upload a video to the farm website showing how important the tractor is", "Post on social media that the tractor has broken down", "Send an email to the parts supplier attaching a photo of the part"], "answer": 3, "explain": "An email with a photo of the part is best because it is FAST (urgent situation), VISUAL (no need to know the name/code), and sent directly to the supplier. A letter is too slow, social media doesn''t reach the supplier, and a website video is irrelevant."}]}, "fib": {"enabled": true, "questions": [{"text": "Communication is the [transmission] of a message from a sender to a receiver. When the receiver can reply, it is known as [two-way] communication."}, {"text": "Digital communication is about sending and receiving information [electronically]. It has transformed business activity. There is now greater [competition] and trade has become more global."}, {"text": "The [productivity] of workers has been increased by digital communication and production [costs] have fallen as a result."}, {"text": "Finance departments can store and process [accounting] information more quickly. Marketing departments use websites and [social media] to reach potentially huge markets."}, {"text": "Human resource departments have seen more staff working while [mobile] or working from [home]. Some workers have lost their jobs or had to undergo [retraining]."}, {"text": "A [website] is an online location that links pages of information. It allows sales to be made online and operates [24/7]."}]}, "tf": {"enabled": true, "questions": [{"statement": "Digital communication is always better than non-digital methods such as meetings.", "answer": false, "explain": "FALSE — this is a key examiner trap. Meetings allow immediate feedback, body language, and real-time discussion. Digital communication has disadvantages such as technology failure and inability to convey body language."}, {"statement": "One-way communication is useful for situations where a response is not required.", "answer": true, "explain": "Correct. One-way communication is suited to giving information to large numbers of people — e.g. a tannoy announcement, an advertising leaflet, or a broadcast email — where no reply is needed."}, {"statement": "Horizontal communication takes place between people on different levels of the hierarchy.", "answer": false, "explain": "HORIZONTAL communication is between people at the SAME level of the hierarchy. Communication between DIFFERENT levels is VERTICAL (either upward or downward)."}, {"statement": "The development of digital communication has benefited all workers.", "answer": false, "explain": "FALSE and a key examiner point. Some workers lost jobs as productivity increased and automation replaced roles. Others had to retrain. Blockbuster staff, shelf-label workers, and bank tellers are examples of roles reduced by digital change."}, {"statement": "A website operates 24 hours a day, seven days a week.", "answer": true, "explain": "Correct. This is a key advantage of websites — they allow customers to access information and place orders at any time, without the business needing staff available."}, {"statement": "Email is the best method of communication for ALL business situations.", "answer": false, "explain": "The best method depends on the situation: purpose, audience, urgency, and sensitivity. For example, a phone call is better for urgent issues, and face-to-face is better for sensitive HR discussions. No single method is always best."}, {"statement": "Formal communication uses official channels such as letters, official meetings, and reports.", "answer": true, "explain": "Correct. Formal communication follows set procedures and official channels. It contrasts with informal communication, which occurs outside these channels (e.g. chatting at lunch)."}, {"statement": "Social media can only be used for external communication with customers.", "answer": false, "explain": "Social media can also be used for INTERNAL communication. Groups of workers can use platforms to message each other, arrange meetings, share ideas, and receive instructions — especially useful across multiple locations."}, {"statement": "A disadvantage of verbal communication is that there is no permanent record unless minutes or a recording are made.", "answer": true, "explain": "Correct. This is a key disadvantage of verbal communication. If a dispute arises about what was said, there is no evidence unless someone took minutes or a recording was made."}, {"statement": "The percentage increase from £250,000 to £525,000 is approximately 110%.", "answer": true, "explain": "Correct. (£525,000 − £250,000) ÷ £250,000 × 100 = £275,000 ÷ £250,000 × 100 = 110%. Since the value more than doubled, the answer must exceed 100%."}, {"statement": "Blockbuster is an example of a business that thrived due to the digital communication revolution.", "answer": false, "explain": "Blockbuster FAILED because of the digital communication revolution. Netflix''s online streaming service replaced Blockbuster''s DVD rental model. Blockbuster was too slow to adapt and went out of business."}, {"statement": "The Chatsworth Estate accountant case study shows that digital technology allowed one accountant to handle 20 times the business revenue.", "answer": true, "explain": "Correct. Michael Isherwood started as the only accountant. Business revenues grew by twenty times but when he retired, there was only one other accountant alongside him. Digital technology transformed productivity in the finance function."}, {"statement": "For a recommendation question, simply choosing one method scores full marks.", "answer": false, "explain": "Choosing one method gives only 1 mark. For the other 2 marks, students must provide a COMPARATIVE justification — explaining why the chosen method is better THAN the other method — ideally using case study context for full marks."}, {"statement": "Amazon''s use of robots in warehouses is an example of digital communication influencing operations.", "answer": true, "explain": "Correct. Once an order is received, it is communicated digitally to a robot which retrieves the product. This has automated operations, reduced errors, sped up dispatch, and reduced labour costs — all impacts of digital communication on business operations."}]}, "misc": {"enabled": true, "items": [{"myth": "Digital communication is always better than non-digital communication.", "truth": "Digital communication is NOT always better. Face-to-face meetings allow immediate feedback, body language, and real-time discussion. They are better for sensitive issues (e.g. disciplinary matters, appraisals) and for building relationships. The OCR examiner regularly flags this as a FALSE statement in multiple-choice questions.", "check": {"question": "Why might a face-to-face meeting be a better method than digital communication for a sensitive disciplinary matter?", "options": ["Meetings are always the cheapest communication method", "Meetings automatically create a permanent written record", "Digital communication is always better regardless of the situation", "It gives immediate feedback and allows body language to be used"], "answer": 3, "explain": "The correct concept is that digital communication is not always better — meetings allow immediate feedback and body language, making them more suitable for sensitive issues."}}, {"myth": "All workers have benefited from the development of digital communication.", "truth": "Digital communication has NOT benefited ALL workers. While many gained new opportunities, flexibility, and higher productivity, others lost their jobs as automation replaced them (e.g. shelf-label workers at Leclerc, DVD rental staff at Blockbuster). Some have had to undergo retraining to stay employed. Examiners specifically test this.", "check": {"question": "Which statement correctly describes the overall impact of digital communication on workers?", "options": ["Some workers gained flexibility, others lost jobs to automation", "Digital communication has had no effect on employment", "All workers have benefited with no negative effects at all", "Only office-based workers have been affected by digital change"], "answer": 0, "explain": "The correct concept is that digital communication has NOT benefited all workers — some gained flexibility while others lost jobs to automation and had to retrain."}}, {"myth": "Internal communication only goes downward — from managers to workers.", "truth": "Internal communication can be VERTICAL (both upward AND downward) or HORIZONTAL. Upward communication goes from worker to manager. Horizontal communication goes between people at the same level (e.g. two department managers). Only treating communication as one-directional will cost marks.", "check": {"question": "In which directions can internal communication travel within a business?", "options": ["Vertically (upward and downward) and horizontally", "Only horizontally, between people at the same level", "Only downward, from managers to workers", "Only upward, from workers to managers"], "answer": 0, "explain": "Internal communication can be vertical (upward or downward) or horizontal (between people at the same level), not just one-directional."}}, {"myth": "Email is always the best method of communication for businesses.", "truth": "The best method depends on the situation: who is being communicated with, the purpose, and what is available. For urgent issues needing immediate two-way discussion, a phone call may be better. For sensitive HR issues, face-to-face is preferred. For reaching thousands of customers, social media or a website may be best.", "check": {"question": "What determines the best method of communication for a business to use in a given situation?", "options": ["Email should always be used because it is the fastest method", "Who is being communicated with, the purpose, and what is available", "The cheapest method should always be chosen regardless of purpose", "Whichever method the sender personally prefers"], "answer": 1, "explain": "The correct concept is that the best method depends on the situation — who is being contacted, the purpose, and what is available — not that one method (like email) is always best."}}, {"myth": "Social media is only useful for communicating with customers externally.", "truth": "Social media can also be used for INTERNAL communications. Groups of workers can be linked through social media platforms to message each other, arrange meetings, share ideas, and receive instructions — especially useful for staff spread across multiple locations or working remotely.", "check": {"question": "Besides communicating with customers, how else can a business use social media?", "options": ["As a tool for internal communication between workers across locations", "It can only be used by businesses with a single location", "It cannot be used for any purpose other than customer communication", "Only for one-way announcements with no internal use"], "answer": 0, "explain": "The correct concept is that social media can also be used for internal communication, linking workers across multiple locations or remote working."}}, {"myth": "A meeting is always a disadvantage because it takes time and costs money.", "truth": "Meetings have both advantages AND disadvantages. Advantages include immediate feedback, the ability to check understanding, discussion and idea generation, and the use of body language. Minutes provide a formal record. Online meetings (Teams, Zoom) reduce travel costs. Never say any method is purely good or bad — evaluation is always expected.", "check": {"question": "What is the correct evaluative view of meetings as a communication method?", "options": ["Meetings should never be used to generate ideas or solve problems", "Meetings have both advantages, like feedback, and disadvantages, like cost", "Meetings have no disadvantages when held online", "Meetings are always a disadvantage because they take time and cost money"], "answer": 1, "explain": "The card stresses that meetings have both advantages (immediate feedback, discussion, minutes as a record) and disadvantages (time, cost) — no method should be judged as purely good or bad."}}]}, "tips": {"enabled": true, "items": [{"title": "Analyse one advantage of a specific communication method (3 marks)", "html": "Structure: (U) Identify a specific advantage of the METHOD — e.g. ''emails can be referred back to.'' (APP) Link to the specific business in the case study. (AN) Show the business-facing impact — e.g. ''this could improve customer service and reduce the risk of losing sales to competitors.'' CRITICAL: do NOT just describe what the method does — state the ADVANTAGE FOR THE BUSINESS.", "check": {"question": "In a 3-mark ''analyse one advantage of a communication method'' question, what is the critical error to avoid?", "options": ["Explaining the business-facing impact of the advantage", "Naming the specific method being used", "Linking the answer to the case study business", "Describing the method instead of stating its advantage"], "answer": 3, "explain": "The card warns that students must NOT just describe what the method does — they must state the actual advantage FOR THE BUSINESS to score analysis marks."}}, {"title": "Recommend which method of communication to use (3 marks)", "html": "Structure: (1 mark) Make a clear recommendation — ''SJ Salon should use a weekly email.'' (2 marks) Justify by comparing the two methods — your reason must explain why the chosen method is BETTER THAN the other. The justification must cover BOTH methods and be contextual (use case study detail). E.g. ''Three employees work part-time so finding a time when everyone can attend a meeting will be difficult — an email can be read at any time.''", "check": {"question": "In a 3-mark ''recommend which method of communication to use'' question, what must the justification for the remaining 2 marks include?", "options": ["A generic advantage with no reference to the case study", "A contextual comparison of why the chosen method is better", "Just a restatement of the method that was chosen", "A list of every possible communication method available"], "answer": 1, "explain": "The card requires the justification to compare BOTH methods, explaining why the chosen one is better than the other, using case study detail."}}, {"title": "Analyse how digital communication has affected workers (6 marks)", "html": "Two separate U→APP→AN chains, each worth 3 marks. Effect 1 (positive): e.g. working from home → more flexibility → better work-life balance → lower absenteeism. Effect 2 (negative): e.g. digital automation replaces jobs → workers made redundant → increased unemployment. Always show both sides for balance — the examiner rewards nuance.", "check": {"question": "For a 6-mark ''analyse how digital communication has affected workers'' question, what structure is expected?", "options": ["A single paragraph focused only on positive effects", "Six short one-sentence points with no development", "One long chain covering six unrelated points", "Two chains of impact, one positive and one negative"], "answer": 3, "explain": "The card explains the answer should have two separate U→APP→AN chains, each worth 3 marks, showing both a positive and a negative effect for balance."}}, {"title": "Percentage change calculations", "html": "Formula: (New Value − Original Value) ÷ Original Value × 100. Example: £250,000 to £525,000 = (£525,000 − £250,000) ÷ £250,000 × 100 = 110%. The most common mistake is dividing by the NEW value instead of the ORIGINAL. If the value more than doubles, the answer MUST be over 100%.", "check": {"question": "When calculating percentage change, what is the most common mistake students make according to this tip?", "options": ["Rounding the original value before subtracting", "Dividing by the new value instead of the original value", "Adding the two values together instead of subtracting them", "Forgetting to multiply the result by 100"], "answer": 1, "explain": "The card warns that the formula requires dividing by the ORIGINAL value, and the most common mistake is dividing by the NEW value instead."}}, {"title": "Explain one reason why communication is important for a business", "html": "Structure: (K) Give a reason — e.g. ''Communication is important for marketing.'' (U) Explain why — e.g. ''so that customers know about what the business sells and can be persuaded to buy.'' The question does NOT require application to a specific business unless it says ''explain why THIS business...'' — read carefully.", "check": {"question": "For a 2-mark ''explain one reason why communication is important'' question, what does the mark scheme require?", "options": ["Three separate developed points with case study detail", "Only a definition of the word ''communication''", "A reason plus application to a named business in every case", "A reason (K) followed by an explanation of why it matters (U)"], "answer": 3, "explain": "The card gives the structure as (K) a reason followed by (U) an explanation of why, and notes application is only needed if the question specifically asks about a named business."}}, {"title": "Always name the specific advantage — not just the method", "html": "A very common error: writing ''email is a good method'' or ''meetings allow communication'' without stating WHAT the advantage is or WHY it helps the business. Examiners explicitly penalise vague responses. ''Quick and easy'' alone scores zero. State the specific feature: ''can be sent to multiple recipients at once'' or ''can be referred back to for clarification.''", "check": {"question": "Why would the answer ''email is a good method because it''s quick and easy'' score zero marks?", "options": ["Email is not accepted as a valid communication method by examiners", "It fails to state a specific advantage or explain how it helps", "It does not mention a named business from the case study", "The sentence is grammatically incorrect"], "answer": 1, "explain": "The card explains that vague responses like ''quick and easy'' are penalised because they do not state the specific feature or advantage for the business."}}, {"title": "Analysis must be business-facing", "html": "Analysis marks are only awarded for impacts on the BUSINESS — such as effects on revenue, profit, market share, costs, customer service, employee retention, reputation, or productivity. Writing ''employees will feel more motivated'' scores as analysis. Writing ''better communication'' does NOT — it just restates the question. Always push to the business consequence.", "check": {"question": "According to the mark scheme, which type of statement counts as valid analysis in a communication question?", "options": ["A statement describing how the method technically works", "A statement about a competitor''s pricing strategy", "A statement that just restates ''communication has improved''", "A statement showing a business-facing impact, e.g. motivation"], "answer": 3, "explain": "The card states analysis marks require a business-facing impact — ''employees will feel more motivated'' scores as analysis, whereas ''better communication'' just restates the question and does not."}}, {"title": "Evaluating the influence of digital communication", "html": "For evaluate questions on digital communication, present BOTH benefits (lower costs, wider reach, globalisation, new products like Netflix) AND drawbacks (job losses, businesses that failed to adapt, workers needing retraining, increased competition). Conclude with a justified judgement — e.g. ''on balance, digital communication has been positive for most businesses because the cost savings and market reach outweigh the disruption.''", "check": {"question": "What must a strong evaluation answer on the influence of digital communication include?", "options": ["A conclusion stating an opinion with no supporting reasons", "Only the benefits, since digital communication is generally positive", "Both benefits and drawbacks, ending with a justified judgement", "A list of communication methods with no conclusion"], "answer": 2, "explain": "The card requires presenting BOTH benefits and drawbacks of digital communication, then concluding with a justified judgement, not a one-sided answer."}}]}, "exam": {"enabled": true, "questions": [{"question": "Which of these statements is FALSE?", "marks": 1, "hint": "Look for the word ''always'' — this is usually the signal that a statement is too absolute to be true.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — Digital communication is always better than non-digital communication</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>This statement is false because non-digital methods such as face-to-face meetings have distinct advantages: immediate two-way feedback, body language, discussion, and problem-solving. Digital communication cannot always replicate these. The word ''always'' makes this an absolute claim that is clearly incorrect.</p></div>"}, {"question": "What is a benefit to a patient of receiving communication from their hospital doctor by email rather than by letter?", "marks": 1, "hint": "Think about this from the PATIENT''S perspective — what helps the patient, not the doctor or the hospital.", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — Emails can contain hyperlinks to further information about treatments</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>This is the only option that benefits the PATIENT specifically. Hyperlinks allow patients to access additional information about their condition or treatment — which helps them understand their healthcare. Options A, C and D are benefits to the hospital/doctor, not the patient.</p></div>"}, {"question": "Analyse one likely reason why Nina sends a weekly update to her employees. [3 marks]", "marks": 3, "hint": "Think about what Nina is trying to achieve by sending these updates — not just ''to communicate.'' Consider the business-facing benefit: what happens to the business if employees are informed and feel part of it?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1a + AO2 + AO3a = 1+1+1)</h5><ul>\n<li><strong>Knowledge (1 mark):</strong> A reason for communicating — e.g. to inform employees, to praise employees, to help employees feel part of the business, to encourage teambuilding</li>\n<li><strong>Application (1 mark):</strong> Link to Nina''s business — e.g. her 80 employees across 10 shops, congratulating an employee on birth of a child, charity fundraising activities</li>\n<li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. improved motivation, reduced labour turnover, increased productivity, improved customer service</li>\n</ul></div>"}, {"question": "Analyse one advantage for SJ Salon of EACH method of communication. [6 marks]", "marks": 6, "hint": "You need TWO separate U→APP→AN chains — one for meetings, one for emails. Make sure the advantage is specific to that METHOD and that your analysis shows the BUSINESS-FACING impact (e.g. effects on customer service, productivity, teamwork).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks per method (U + APP + AN each)</h5><p><strong>Meeting — Understanding (examples):</strong> Can check for understanding; supports teamworking; improved employer-employee relationship; immediate/real-time responses; can emphasise points using body language</p>\n<p><strong>Meeting — Application:</strong> Link to newly enlarged team; national hairdresser opening; keeping customers satisfied</p>\n<p><strong>Meeting — Analysis:</strong> Business-facing impact — e.g. improved customer service; increased competitive advantage against the new salon; lower labour turnover</p>\n<p><strong>Email — Understanding (examples):</strong> Time efficient; can be sent to many recipients at once; can be accessed anywhere/anytime; can be referred back to; no need to schedule</p>\n<p><strong>Email — Application:</strong> Three part-time employees with different hours; national salon threat; keeping customers satisfied</p>\n<p><strong>Email — Analysis:</strong> Business-facing impact — e.g. improved productivity; better customer service; cost-effective communication as workforce grows</p></div>"}, {"question": "Recommend whether a weekly meeting or a weekly email would be the more appropriate method of communication for SJ Salon to use. Give a reason for your answer. [3 marks]", "marks": 3, "hint": "Make a clear choice first (1 mark). Then explain WHY that method is better THAN the other — you must compare them. Use details from the case study for the best marks.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO3b = 3 marks)</h5><ul>\n<li><strong>Judgement (1 mark):</strong> Clear recommendation — meeting OR email</li>\n<li><strong>Contextual justification (2 marks):</strong> Comparative reason using case study detail — must explain why chosen method is BETTER THAN the other</li>\n<li><strong>OR non-contextual justification (1 mark):</strong> Comparative reason without case study detail</li>\n</ul><p>Note: Justification MUST cover BOTH methods to earn marks for justification.</p></div>"}, {"question": "Explain the term ''digital communications''. [1 mark]", "marks": 1, "hint": "Think about what makes communication ''digital'' — what technology is involved?", "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — The electronic exchange of information using ICT</strong></p></div>\n<div class=\"marks-section\"><h5>Why</h5><p>Digital communication is specifically the electronic exchange of information using ICT. This includes email, websites, faxes, social media, and programming machines/robots to respond to data. Letters and face-to-face communication are non-digital.</p></div>"}, {"question": "Analyse one benefit Amazon may gain through using digital communications in its business operations. [3 marks]", "marks": 3, "hint": "Focus on OPERATIONS — how goods are produced, stored, and dispatched. Think about the robots in the warehouse and what benefits they bring. Then link to the business impact: costs, sales, reputation.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation (AO1b + AO2 + AO3a = 1+1+1)</h5><ul>\n<li><strong>Understanding (1):</strong> Benefit — e.g. faster production/dispatch; improved quality/fewer errors; reduced costs</li>\n<li><strong>Application (1):</strong> Link to Amazon — robots retrieve products; no humans running around shelves; digital order processing</li>\n<li><strong>Analysis (1):</strong> Business impact — e.g. Amazon gains customers due to speed of service; lower costs mean lower prices and still make profit; fewer returns due to accuracy</li>\n</ul></div>"}]}}'::jsonb),
('business', '3-4-recruitment-and-selection', '3.4 Recruitment and Selection', '{"learn": {"enabled": true, "items": [{"title": "Core Terminology", "html": "<ul>\n<li><strong>Recruitment</strong> — The process of finding people to work in a new or established business</li>\n<li><strong>Selection</strong> — The process of choosing between applicants for a job</li>\n<li><strong>Internal recruitment</strong> — When a job vacancy is filled by employing someone who is already an employee of the business. Methods include notice boards, word of mouth, company website and emails to staff</li>\n<li><strong>External recruitment</strong> — When a job vacancy is filled by employing someone from outside the business. Methods include websites, newspaper, social media and specialist magazines</li>\n<li><strong>Skills gap</strong> — When a business recruits skilled workers because it is short of them</li>\n<li><strong>Job description</strong> — A list of the main duties, tasks and responsibilities of a worker</li>\n<li><strong>Person specification</strong> — A list of the qualities, qualifications and knowledge that a person should have to do a particular job</li>\n<li><strong>Induction training</strong> — Training to introduce a new worker to the business, place of work and their fellow workers as well as their job</li>\n<li><strong>Recruitment agency</strong> — A specialist agency that carries out all the tasks involved in recruitment and selection of workers on behalf of an organisation</li>\n<li><strong>Employment agency</strong> — An agency that has workers readily available for business hire, usually for a short period of time</li>\n<li><strong>CV (curriculum vitae)</strong> — A document on which the applicant outlines their personal details, experience and skills</li>\n<li><strong>Application form</strong> — A form which asks applicants for personal details, experience and skills</li>\n<li><strong>Letter of application</strong> — A letter written by the applicant usually explaining why they think they are suitable for the job</li>\n</ul>", "check": {"question": "According to core recruitment terminology, what is ''selection''?", "options": ["Training a new worker to fit into the business", "The process of choosing between applicants for a job", "A list of duties and responsibilities of a worker", "The process of finding people to work in a business"], "answer": 1, "explain": "Selection is defined as the process of choosing between applicants for a job, distinct from recruitment (finding people to work in the business)."}}, {"title": "Why Businesses Recruit", "html": "<p>There are three main reasons why businesses recruit new workers:</p>\n<ul>\n<li><strong>Starting up or growing</strong> — A new business must recruit workers from scratch. A business getting increased orders or making more sales may increase production and need more workers</li>\n<li><strong>To replace staff who leave</strong> — Staff leave for all kinds of reasons: promotion, retirement, to do something different, or because they have been dismissed</li>\n<li><strong>Skills shortage / Skills gap</strong> — May arise as new methods of production are introduced, perhaps using new technology. Recruiting skilled workers can be very difficult, particularly if the economy is doing well. It is not unusual for businesses to look abroad when recruiting skilled workers</li>\n</ul>\n<p><strong>Note from OCR delivery guide:</strong> Sometimes the work can be reallocated amongst other posts to avoid the need to replace the job role. Businesses should not automatically recruit whenever someone leaves.</p>\n<p><strong>Cost of poor recruitment:</strong> Oxford Economics research found replacing a staff member costs on average £30,614. Lost output during the settling-in period (28 weeks on average) accounts for £25,181, with direct recruitment costs of £5,433 covering agency fees, advertising, management time and HR processing.</p>", "check": {"question": "According to the OCR delivery guide note, what should a business consider before recruiting a replacement for a worker who has left?", "options": ["Whether to close the department entirely", "Whether to promote the departing worker''s manager", "Whether the work could be reallocated instead", "Whether to increase the salary of the role"], "answer": 2, "explain": "The card notes work can sometimes be reallocated among other posts, and businesses should not automatically recruit whenever someone leaves."}}, {"title": "The Recruitment & Selection Process", "html": "<p>The recruitment and selection process has two main stages:</p>\n<p><strong>Recruitment stage:</strong></p>\n<ul>\n<li>Step 1: Identify a vacancy</li>\n<li>Step 2: Write a job description</li>\n<li>Step 3: Write a person specification</li>\n<li>Step 4: Advertise the vacancy</li>\n<li>Step 5: Receive applications</li>\n</ul>\n<p><strong>Selection stage:</strong></p>\n<ul>\n<li>Step 6: Shortlist candidates (using CVs, application forms, letters of application)</li>\n<li>Step 7: Carry out interviews / tests / group activities</li>\n<li>Step 8: Make a job offer</li>\n</ul>\n<p><strong>Important distinction:</strong> ''Recruitment'' refers to searching for suitable candidates and attracting them to apply. ''Selection'' refers to vetting candidates to choose the most suitable one.</p>", "check": {"question": "Which of the following best describes ''selection'' in the recruitment and selection process?", "options": ["Vetting candidates to choose the most suitable one", "Searching for and attracting suitable candidates to apply", "Writing the job description and person specification", "Advertising the vacancy to attract applicants"], "answer": 0, "explain": "The card states selection refers to vetting candidates to choose the most suitable person, while recruitment means searching for and attracting candidates."}}, {"title": "Job Description vs Person Specification", "html": "<p><strong>Job Description</strong> — lists the tasks and responsibilities the worker must perform. It helps the business be clear about what work it wants done, and helps applicants decide if they want to apply.</p>\n<p>A job description typically includes: job title, grade/pay scale, who the person is responsible to, job purpose, and main duties/tasks.</p>\n<p><strong>Person Specification</strong> — states the knowledge, qualifications, experience, personal qualities and skills the worker will need. It helps the business decide what kind of person to appoint and which selection methods to use.</p>\n<p>A person specification typically includes: qualifications (essential/desirable), experience, knowledge/skills/abilities, and special requirements (e.g. driving licence). Each attribute is marked E (essential) or D (desirable) and the method of assessment is noted (AF = application form, I = interview, R = reference, T = test).</p>\n<div class=\"two-col\" style=\"margin-top:10px;\">\n<div>\n<div class=\"col-head\">Job Description Contains</div>\n<div class=\"pro-item\">Job title and department</div>\n<div class=\"pro-item\">Hours of work and location</div>\n<div class=\"pro-item\">Main duties and tasks</div>\n<div class=\"pro-item\">Who the worker reports to</div>\n</div>\n<div>\n<div class=\"col-head\">Person Specification Contains</div>\n<div class=\"pro-item\">Qualifications required</div>\n<div class=\"pro-item\">Experience needed</div>\n<div class=\"pro-item\">Skills and personal qualities</div>\n<div class=\"pro-item\">Special requirements (e.g. can drive)</div>\n</div>\n</div>", "check": {"question": "In a person specification, what does marking an attribute as ''D'' indicate?", "options": ["The attribute is required by law", "The candidate must demonstrate it at interview", "The attribute disqualifies the candidate", "The attribute is desirable but not essential"], "answer": 3, "explain": "The card explains each attribute in a person specification is marked E (essential) or D (desirable)."}}, {"title": "Internal vs External Recruitment", "html": "<p><strong>Internal recruitment</strong> — filling a vacancy with someone who already works in the organisation.</p>\n<p>Internal advertising methods: noticeboard, word of mouth/staff meetings, company (in-house) magazine, the firm''s website, social media used by workers, emails to workers.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Internal Advantages</div>\n<div class=\"pro-item\">Cheaper to advertise internally</div>\n<div class=\"pro-item\">Quicker — no need to give notice externally</div>\n<div class=\"pro-item\">Person already knows the organisation — less induction training needed</div>\n<div class=\"pro-item\">Organisation already knows the candidate — less risk</div>\n<div class=\"pro-item\">Motivates existing workforce — promotion opportunities</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Internal Disadvantages</div>\n<div class=\"con-item\">Existing staff may not bring new ideas</div>\n<div class=\"con-item\">Limited choice of applicants</div>\n<div class=\"con-item\">Other workers may become jealous — conflict</div>\n<div class=\"con-item\">The job vacated by the person promoted still needs to be filled</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>External recruitment</strong> — filling a vacancy with someone from outside the organisation. Used when: starting up, skills gap exists, new ideas needed, more workers needed, or promoting internally would cause conflict.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ External Advantages</div>\n<div class=\"pro-item\">Wider range of skills and experience</div>\n<div class=\"pro-item\">Fresh ideas from outside the business</div>\n<div class=\"pro-item\">More applicants to choose from</div>\n<div class=\"pro-item\">No need to backfill the promoted person''s role</div>\n</div>\n<div>\n<div class=\"col-head\">✗ External Disadvantages</div>\n<div class=\"con-item\">More expensive (advertising, agency fees)</div>\n<div class=\"con-item\">Takes longer to recruit</div>\n<div class=\"con-item\">Induction training needed — higher cost</div>\n<div class=\"con-item\">Greater risk — managers don''t know the candidate well</div>\n</div>\n</div>", "check": {"question": "Which of these is a disadvantage of internal recruitment, according to the card?", "options": ["It takes longer than external recruitment", "It requires more induction training", "It brings a wider range of skills and experience", "Their old role still needs to be filled by someone"], "answer": 3, "explain": "The card lists that the job vacated by the promoted person still needs to be filled as a disadvantage of internal recruitment; the other options actually describe external recruitment or its disadvantages."}}, {"title": "Advertising Media", "html": "<p>When advertising a job, a business considers: whether to recruit internally or externally; the type of worker required; how many workers are needed; the location; and the budget available.</p>\n<ul>\n<li><strong>Websites (e.g. Indeed, Reed, Monster)</strong> — Used for all types of jobs, local and national. Applicants can search by type, salary and location. Businesses can search posted CVs. Both internal and external.</li>\n<li><strong>Social media</strong> — Increasingly used for many kinds of jobs because of wide reach. Useful for finding graduates and younger applicants. Both internal and external.</li>\n<li><strong>Local newspapers</strong> — Useful when looking for local workers only (hairdressers, carers, retail). Not usually expensive. External.</li>\n<li><strong>National newspapers</strong> — Used when recruiting skilled workers and there may be a shortage locally. More expensive. External.</li>\n<li><strong>Specialist magazines</strong> — e.g. Times Educational Supplement (teachers), The Lancet (doctors). Used to recruit highly skilled workers such as consultants, engineers, scientists. External.</li>\n<li><strong>Job centres</strong> — Government-run; free to use; useful for people without internet access. External.</li>\n<li><strong>Word of mouth</strong> — Business lets existing employees know about a vacancy. Saves advertising cost. Both internal and external.</li>\n<li><strong>Email/noticeboard/company magazine</strong> — Internal methods only.</li>\n</ul>", "check": {"question": "According to the card, what are specialist magazines (e.g. Times Educational Supplement) mainly used to recruit?", "options": ["Highly skilled workers like consultants", "Workers for short-term temporary contracts", "Internal staff seeking promotion", "Local unskilled retail staff"], "answer": 0, "explain": "The card states specialist magazines are used to recruit highly skilled workers such as consultants, engineers and scientists."}}, {"title": "Methods of Selection", "html": "<p>Selection is divided into two stages: shortlisting, then the final selection stage.</p>\n<p><strong>Shortlisting methods</strong> (used to draw up a list of candidates to interview):</p>\n<ul>\n<li><strong>Letter of application</strong> — Written by the applicant explaining why they are suitable. Good for showing communication skills, use of punctuation and grammar, and experience. Applicant puts themselves in the best light.</li>\n<li><strong>CV (curriculum vitae)</strong> — Summary of personal details, qualifications, employment history and referees. Shows ability to organise information. Easy to see essential details at a glance.</li>\n<li><strong>Application form</strong> — Business specifies what information it needs; all applicants fill in the same form. Easy to compare applicants. Less likely to miss essential information than a CV.</li>\n</ul>\n<p><strong>Final selection methods:</strong></p>\n<ul>\n<li><strong>Interviews</strong> — Employer sees candidates face-to-face and can judge how well they present themselves, communicate and are likely to fit in. Often the same questions are asked of all candidates. Good for assessing personality, communication skills and reaction under pressure.</li>\n<li><strong>Tests and presentations</strong> — Check specific skills (e.g. typing, IT, maths). Presentations show how well a candidate can communicate ideas. Gives very specific, measurable information.</li>\n<li><strong>Group activities</strong> — Applicants work together on a task. Reveals interpersonal/teamworking skills and leadership ability. Particularly useful when the job requires working closely with others.</li>\n<li><strong>References</strong> — Statement from a previous employer about work done, how well they did their job, punctuality and attendance. Can verify information from the CV/application form. Provides a third-party view, though references can sometimes be misleading.</li>\n</ul>", "check": {"question": "Which method is used at the shortlisting stage rather than the final selection stage?", "options": ["Interview", "Reference", "Application form", "Group activity"], "answer": 2, "explain": "The card places letters of application, CVs and application forms at the shortlisting stage, while interviews, tests, group activities and references belong to final selection."}}, {"title": "Recruitment & Employment Agencies", "html": "<p><strong>Recruitment agencies</strong> do the work of recruiting and selecting staff on behalf of businesses. The agency:</p>\n<ul>\n<li>Draws up a job description and person specification (in consultation with the firm)</li>\n<li>Advertises for applications</li>\n<li>Recommends a shortlist of suitable people</li>\n<li>The firm then interviews recommended candidates before making a final decision</li>\n</ul>\n<p>Using a recruitment agency saves time and money if it reduces the need for a large HR department. The agency is a specialist organisation that knows how and where to advertise and what information is needed about applicants.</p>\n<p><strong>Employment agencies</strong> keep lists of people willing to do certain kinds of work (e.g. receptionists, office typists). A firm can ask for a worker for a short period of time, paying the worker''s wage plus the agency''s fee. If the temporary worker performs well, the firm may offer a permanent post — though the agency may charge a further introduction fee.</p>", "check": {"question": "What is the key difference between a recruitment agency and an employment agency, according to the card?", "options": ["Employment agencies supply short-term hires; recruitment agencies handle full recruitment", "Recruitment agencies are used only by small businesses", "Employment agencies are free to use, while recruitment agencies always charge a fee", "Recruitment agencies only advertise vacancies, while employment agencies conduct interviews"], "answer": 0, "explain": "The card explains recruitment agencies carry out the recruitment/selection process for a business, while employment agencies keep lists of workers available for short-term hire."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Recruitment", "definition": "The process of finding people to work in a new or established business."}, {"term": "Selection", "definition": "The process of choosing between applicants for a job."}, {"term": "Job Description", "definition": "A list of the main duties, tasks and responsibilities of a worker."}, {"term": "Person Specification", "definition": "A list of the qualities, qualifications and knowledge that a person should have to do a particular job."}, {"term": "Skills Gap", "definition": "When a business recruits skilled workers because it is short of them — often when new production methods are introduced."}, {"term": "Internal Recruitment", "definition": "When a job vacancy is filled by employing someone who already works in the organisation. Methods: noticeboard, email, word of mouth, company website."}, {"term": "External Recruitment", "definition": "When a job vacancy is filled by employing someone from outside the business. Methods: websites, newspapers, social media, specialist magazines, job centres."}, {"term": "CV (Curriculum Vitae)", "definition": "A document on which the applicant outlines their personal details, experience and skills. Shows organisational ability."}, {"term": "Application Form", "definition": "A form specifying what information the business needs; all applicants provide the same information, making comparisons easy."}, {"term": "Letter of Application", "definition": "A letter written by the applicant explaining why they think they are suitable for the job. Good for assessing communication skills."}, {"term": "Interview", "definition": "A face-to-face discussion where the employer asks candidates questions — often the same questions to all. Assesses presentation, communication and personality."}, {"term": "Group Activity", "definition": "Applicants work together on a task. Reveals interpersonal skills, teamworking ability and leadership qualities."}, {"term": "Reference", "definition": "A statement from a previous employer or responsible person about the applicant''s suitability, work quality and reliability."}, {"term": "Induction Training", "definition": "Training to introduce a new worker to the business, the workplace, their colleagues and their specific job."}, {"term": "Recruitment Agency", "definition": "A specialist agency that carries out all tasks involved in recruitment and selection on behalf of an organisation."}, {"term": "Employment Agency", "definition": "An agency that has workers readily available for business hire, usually for a short period of time."}, {"term": "Shortlisting", "definition": "Using applications (CVs, forms, letters) to select which candidates to invite to the final stage of selection."}, {"term": "Analysing HR Needs", "definition": "When the organisation decides how many workers it needs, what type, and when — before beginning recruitment."}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of the following is an example of external recruitment?", "options": ["Advertising in a national newspaper", "Emailing staff about a vacancy", "Promoting a worker from another department", "Putting a notice on the company intranet"], "answer": 0, "explain": "External recruitment means filling a vacancy with someone from outside the organisation. Advertising in a national newspaper is an external method. The other options are all internal methods."}, {"question": "A job description includes which of the following?", "options": ["The experience needed to perform the job", "The personal qualities the worker must have", "The main duties and responsibilities of the worker", "The qualifications required by the applicant"], "answer": 2, "explain": "A job description lists the duties, tasks and responsibilities of the worker. Qualifications, personal qualities and experience needed belong in the person specification."}, {"question": "Which item belongs in a person specification?", "options": ["The name of the line manager", "The hours of work", "The skills and qualifications needed", "The main tasks of the job"], "answer": 2, "explain": "A person specification lists the qualities, qualifications and knowledge a person should have. Tasks, line manager details and hours of work belong in the job description."}, {"question": "Danielle advertises on Indeed at 60p per click. 350 people click on the advert and she contacts 16 applicants at £1 each. What is the total cost?", "options": ["£226", "£227", "£262", "£622"], "answer": 2, "explain": "350 × £0.60 = £210. 16 × £1 = £16. Total = £210 + £16 = £226. Answer: A. (Note: the original OCR answer is A = £226.)"}, {"question": "Which of the following would be used to shortlist candidates?", "options": ["Reference", "Letter of application", "Group activity", "Interview"], "answer": 1, "explain": "Letters of application (along with CVs and application forms) are used to create a shortlist. Interviews, group activities and references are used at the final selection stage."}, {"question": "Which of the following is an advantage for a business of using a CV rather than an application form?", "options": ["It is easier for the business to compare applicants", "It ensures all applicants provide the same information", "It shows an applicant''s ability to organise relevant information", "Applicants are less likely to leave out essential information"], "answer": 2, "explain": "A CV shows the applicant''s ability to organise information. Application forms are actually better for ensuring all applicants provide the same specific information and for making comparisons."}, {"question": "A business has a skills gap. Which action would best solve this?", "options": ["Reduce the number of employees", "Ask existing employees to work fewer hours", "Advertise internally on the company noticeboard", "Recruit an external specialist with the required skills"], "answer": 3, "explain": "A skills gap means the business lacks workers with specific skills. The solution is to recruit externally — specifically seeking someone with those skills from outside the business."}, {"question": "Which of the following is a disadvantage of internal recruitment?", "options": ["It takes longer than external recruitment", "Workers need more induction training", "It is more expensive than external recruitment", "Existing staff may not bring fresh ideas"], "answer": 3, "explain": "A key disadvantage of internal recruitment is that existing staff may not add new ideas to help the business improve. Internal recruitment is actually cheaper and faster than external."}, {"question": "Waitrose uses interviews, group activities and tests in its selection process. Which method is best for assessing how well a candidate works in a team?", "options": ["Group activity", "Interview", "Test", "CV"], "answer": 0, "explain": "Group activities reveal how well people work with others — their interpersonal skills. Interviews assess communication and presentation; tests assess specific technical skills."}, {"question": "Which of the following is a method of internal recruitment?", "options": ["Posting on the company website for staff", "Using a recruitment agency", "Advertising in a specialist magazine", "Advertising in a local newspaper"], "answer": 0, "explain": "The company website can be used internally (to notify existing staff) as well as externally. Local newspapers, recruitment agencies and specialist magazines are all external methods."}]}, "fib": {"enabled": true, "questions": [{"text": "Recruitment and [selection] are very important to businesses. The [workers] in a business make it successful or not. Recruiting new staff is [expensive]. If good staff are not recruited by firms, money spent on the recruitment process is [wasted]."}, {"text": "Internal recruitment is when a job vacancy is filled by someone [already working] in the business. External recruitment is when someone from [outside] the business is appointed. Internal recruitment is usually [cheaper] and [quicker] than external recruitment."}, {"text": "A [job description] lists the main duties and tasks of the worker. A [person specification] lists the qualities, qualifications and experience needed. Letters of application are good for showing a person''s [communication] skills. A [interview] is used at the final stage of selection and allows the interviewer to judge the candidate''s personality and communication."}]}, "tf": {"enabled": true, "questions": [{"statement": "A job description lists the qualifications and skills needed for the job.", "answer": false, "explain": "False. A job description lists the duties, tasks and responsibilities of the role. Qualifications and skills belong in the person specification."}, {"statement": "Internal recruitment is always cheaper and quicker than external recruitment.", "answer": true, "explain": "True. Internal recruitment saves advertising costs and the person can start sooner as they don''t need to give notice elsewhere."}, {"statement": "A CV makes it easy for the business to compare applicants because all applicants provide the same information.", "answer": false, "explain": "False. An application form ensures all applicants provide the same information in the same format, making comparison easier. A CV is structured by the applicant."}, {"statement": "One disadvantage of internal recruitment is that existing staff may not bring fresh ideas to the business.", "answer": true, "explain": "True. This is a key disadvantage of internal recruitment. Fresh ideas and new skills are more likely to come from external candidates."}, {"statement": "References are always a reliable source of information about a candidate.", "answer": false, "explain": "False. Businesses sometimes give workers good references because they want them to leave. This is why organisations often use more than one method of selection."}, {"statement": "Group activities are best for assessing a candidate''s ability to work as part of a team.", "answer": true, "explain": "True. Group activities reveal interpersonal skills and how well people work with others — something that is difficult to assess through interviews or tests alone."}, {"statement": "External recruitment methods include notice boards, word of mouth and emails to staff.", "answer": false, "explain": "False. These are internal recruitment methods. External methods include websites, local/national newspapers, specialist magazines, social media and job centres."}, {"statement": "A skills gap occurs when a business needs workers with specialist skills it does not currently have.", "answer": true, "explain": "True. A skills gap often arises when new production methods or technologies are introduced, requiring the business to recruit externally for those skills."}, {"statement": "Interviews are sufficient on their own to make a fully informed recruitment decision.", "answer": false, "explain": "False. Interviews can give the wrong impression, and sometimes applicants are not entirely honest. Organisations often use more than one method of selection to build an accurate picture."}, {"statement": "Induction training is needed for both internal and external recruits.", "answer": false, "explain": "False. Induction training is mainly needed for external recruits. An internal recruit already knows the organisation, its aims, and how things work — so induction training may not be needed, saving the business money."}]}, "misc": {"enabled": true, "items": [{"myth": "''Recruitment'' and ''selection'' mean the same thing.", "truth": "They are different stages. Recruitment refers to searching for suitable candidates and attracting them to apply for a vacancy. Selection refers to the process of vetting candidates to choose the most suitable person for the role.", "check": {"question": "What is the correct distinction between ''recruitment'' and ''selection''?", "options": ["Selection means advertising a vacancy", "Recruitment happens after selection is complete", "Recruitment attracts candidates; selection vets the best one", "Recruitment and selection are two words for the same process"], "answer": 2, "explain": "The card clarifies recruitment and selection are different stages: recruitment attracts candidates, selection vets them to choose the best person."}}, {"myth": "A job description lists the qualifications and skills needed for the job.", "truth": "A job description lists the tasks, duties and responsibilities of the role. Qualifications and skills needed belong in the person specification. Confusing these two documents is one of the most common errors in GCSE exams.", "check": {"question": "What does a job description actually list?", "options": ["The personal qualities of an ideal candidate", "The salary and benefits package", "The tasks, duties and responsibilities of the role", "The qualifications and skills needed for the job"], "answer": 2, "explain": "The card corrects the common misconception that a job description lists qualifications/skills — that belongs in the person specification; a job description lists tasks, duties and responsibilities."}}, {"myth": "Internal recruitment is always better because it is cheaper.", "truth": "Internal recruitment has advantages (cheaper, quicker, motivated staff) but also disadvantages (no fresh ideas, limited choice, causes conflict). The best method depends on the specific situation — for example, if a business needs a skills gap filled, external recruitment is needed.", "check": {"question": "Why is it wrong to say internal recruitment is ''always better'' than external recruitment?", "options": ["Because external recruitment is always quicker", "Because internal recruitment is always more expensive", "Because internal recruitment always causes conflict among staff", "The best method depends on the situation faced"], "answer": 3, "explain": "The card explains internal recruitment has both advantages and disadvantages, and the best method depends on the situation — e.g. filling a skills gap needs external recruitment."}}, {"myth": "When an employee leaves, a business must always recruit a replacement.", "truth": "Not necessarily. Sometimes the work can be redistributed to other employees. Businesses should analyse their HR needs before automatically recruiting. Recruitment is expensive and time-consuming, so the need must be justified.", "check": {"question": "Is it true that a business must always recruit a replacement when an employee leaves?", "options": ["Yes — otherwise the person specification becomes invalid", "No — the role is simply removed from the organisation permanently", "No — the work can sometimes go to other employees", "Yes — a business must recruit within one week by law"], "answer": 2, "explain": "The card corrects this misconception, explaining that work can sometimes be redistributed to other employees, and the need to recruit must be justified since it is expensive and time-consuming."}}, {"myth": "A CV is better than an application form because the applicant includes all the information.", "truth": "A CV shows the applicant''s ability to organise information, but applicants may leave out essential details. Application forms ensure all applicants provide exactly the same information, making it easier to compare them. Each method has its advantages.", "check": {"question": "Why might an application form be considered better than a CV for comparing applicants?", "options": ["It guarantees the applicant is telling the truth", "It always includes more personal details than a CV", "It ensures every applicant gives the same information", "It is cheaper to produce than a CV"], "answer": 2, "explain": "The card explains application forms ensure all applicants provide identical information, making comparison easier, whereas a CV''s structure is decided by the applicant and may omit details."}}, {"myth": "References always provide accurate, honest information about a candidate.", "truth": "References can be misleading. Sometimes employers give workers good references because they want them to leave. For this reason, businesses often use more than one method of selection to build a fuller picture of each candidate.", "check": {"question": "Why can references sometimes be misleading?", "options": ["Employers may give good references to workers they want gone", "References replace the need for an interview", "References are always written by the candidate themselves", "References are only used for internal recruitment"], "answer": 0, "explain": "The card notes that employers sometimes give good references because they want a worker to leave, which is why businesses use more than one selection method."}}, {"myth": "Some learners refer to the ''person specification'' as the ''job specification''.", "truth": "The correct term used in the OCR specification is ''person specification''. Always use this term in your answers to show precise subject knowledge.", "check": {"question": "Which term is the correct OCR specification term for the document listing a candidate''s required qualities and qualifications?", "options": ["Candidate description", "Role specification", "Job specification", "Person specification"], "answer": 3, "explain": "The card states the correct OCR term is ''person specification'', not ''job specification''."}}]}, "tips": {"enabled": true, "items": [{"title": "2-mark Explain questions (AO1b + AO2)", "html": "<p>You need <strong>Knowledge (1 mark)</strong> + <strong>Application (1 mark)</strong>.</p>\n<p>State the advantage/disadvantage, then link it specifically to the business in the question.</p>\n<p><em>Example: \"External recruitment may bring new ideas (K) which is important for Waitrose as it operates in a very competitive supermarket industry where new product development is key (APP).\"</em></p>", "check": {"question": "What two marks make up a 2-mark ''Explain'' question (AO1b + AO2)?", "options": ["Application (1 mark) + Analysis (1 mark)", "Knowledge (1 mark) + Evaluation (1 mark)", "Knowledge (1 mark) + Application (1 mark)", "Understanding (1 mark) + Evaluation (1 mark)"], "answer": 2, "explain": "The card states 2-mark Explain questions require Knowledge (1 mark) plus Application (1 mark), linking the point specifically to the business in the question."}}, {"title": "3-mark Analyse questions (AO1b + AO2 + AO3a)", "html": "<p>State the advantage/method → Apply to the business → Analyse the business impact.</p>\n<p><em>Example: \"Interviews allow the interviewer to ask detailed questions about the candidates'' skills (K). Given that Clarks designers work with fast-changing fashion trends (APP), this will allow Clarks to select workers who are up-to-date, potentially increasing market share (AN).\"</em></p>", "check": {"question": "What is the correct structure for a 3-mark ''Analyse'' question?", "options": ["State the advantage, then make a final judgement", "Describe the method, then compare it to an alternative", "State two separate advantages of the method", "State the method, apply it, then analyse the impact"], "answer": 3, "explain": "The card explains 3-mark Analyse questions require: state the advantage/method, apply it to the business, then analyse the business impact (K+APP+AN)."}}, {"title": "3-mark Recommend questions (AO3b)", "html": "<p>You must: (1) Make a clear decision — don''t sit on the fence. (2) Justify why your chosen method is better than the alternative — a comparison is essential. (3) Use context from the case study.</p>\n<p><em>Example: \"Interviews are likely to be more effective (1) because Clarks can assess candidates'' knowledge of current fashion (CONT). A reference is unlikely to include this information unless they previously worked for another fashion business (+2).\"</em></p>", "check": {"question": "What must a student do to access full marks on a 3-mark ''Recommend'' question (AO3b)?", "options": ["Describe both methods without making a decision", "Make a decision, justified against the alternative", "List as many advantages as possible without choosing one option", "Simply repeat the question in the answer"], "answer": 1, "explain": "The card states students must make a clear decision, justify why the chosen method is better than the alternative (a comparison is essential), and use case study context."}}, {"title": "9-mark Evaluate questions (AO1a + AO1b + AO2 + AO3a + AO3b)", "html": "<p>Use the marking grid: Knowledge (1) → Understanding (1) → Application/data (2) → Analysis (2) → Evaluation (3).</p>\n<ul>\n<li>Use data from the case study to earn application marks (e.g. calculate differences in costs)</li>\n<li>Give both advantages and disadvantages of the recruitment method</li>\n<li>Make a final judgement that is contextually justified using information from the case study</li>\n</ul>", "check": {"question": "According to the marking grid for a 9-mark Evaluate question, how many marks are allocated to Evaluation?", "options": ["1 mark", "2 marks", "4 marks", "3 marks"], "answer": 3, "explain": "The card''s marking grid allocates Knowledge (1) + Understanding (1) + Application/data (2) + Analysis (2) + Evaluation (3) = 9 marks."}}, {"title": "Don''t just describe the method — give the advantage", "html": "<p>Examiners do NOT award marks for describing what a method is (e.g. \"an interview is where you ask candidates questions\"). You must state the <strong>advantage for the business</strong> of using that method.</p>\n<p>Also avoid generic phrases like \"it helps find the best person for the job\" — this is the purpose of all selection methods and earns no marks.</p>", "check": {"question": "Why do examiners award no marks for a statement like ''an interview is where you ask candidates questions''?", "options": ["Because interviews are not a valid selection method", "Because it exceeds the word limit for the question", "It just describes the method, not a business advantage", "Because it should be written in the case study instead"], "answer": 2, "explain": "The card warns that examiners do not award marks for describing what a method is — students must state the advantage for the business of using it."}}, {"title": "Internal vs External — Know the Data", "html": "<p>From the BFF (Best Foot Forward) case study — always reference specific data when it is given:</p>\n<ul>\n<li>Internal recruitment cost: £500 vs External: £2,500 (£2,000 cheaper)</li>\n<li>Internal induction cost: £200 vs External: £1,500 (£1,300 cheaper)</li>\n<li>Total saving from internal: £3,300</li>\n<li>Days to fill the job: Internal 20 days vs External 60 days (3× faster)</li>\n</ul>\n<p>Using these numbers in analysis earns application marks.</p>", "check": {"question": "In the BFF case study data on this card, how much cheaper is internal recruitment cost compared to external?", "options": ["£2,000 cheaper", "£1,300 cheaper", "£500 cheaper", "£3,300 cheaper"], "answer": 0, "explain": "The card states internal recruitment cost is £500 versus external at £2,500 — a difference of £2,000."}}]}, "exam": {"enabled": true, "questions": [{"question": "What would be included in the job description for a hospital doctor?", "marks": 1, "hint": "A job description is about the TASKS and DUTIES of the job — not about the personal attributes or qualifications of the person doing it.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p>Answer: <strong>D — The main duties of medical staff when working in a hospital.</strong></p><p>A job description lists the duties, tasks and responsibilities of the role. Qualifications (A), personal qualities (B) and experience (C) all belong in the person specification.</p></div>"}, {"question": "Explain one advantage for Waitrose of using external recruitment. [2 marks]", "marks": 2, "hint": "External recruitment brings something that internal recruitment cannot. Think about what an outsider brings that someone already in the business doesn''t have.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme (AO1b + AO2)</h5><ul>\n<li><strong>1 mark</strong> — Understanding: state an advantage of external recruitment (e.g. new skills, new ideas, fills a skills gap, no need to backfill)</li>\n<li><strong>1 mark</strong> — Application: link it specifically to Waitrose (e.g. competitive industry, new product development is key, over 50,000 employees)</li>\n</ul></div>"}, {"question": "Analyse one advantage for Clarks of using interviews to select new designers. [3 marks]", "marks": 3, "hint": "Think: What specifically can an interview reveal that other methods cannot? Then link it to the specific context of Clarks and designers.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme (AO1b + AO2 + AO3a)</h5><ul>\n<li><strong>1 mark (U)</strong> — Advantage of interviews: can assess communication skills, personality, how the candidate responds under pressure, how they''d fit into a team, compare answers to the same questions across all candidates</li>\n<li><strong>1 mark (APP)</strong> — Apply to Clarks: designers are specialists; work with fast-changing fashion trends; must work closely with other functional areas such as marketing, finance and retail; central to business success</li>\n<li><strong>1 mark (AN)</strong> — Business-facing analysis: positive impact on market share, competitive advantage, productivity, quality of designs, teamwork. Must stem from the advantage stated</li>\n</ul><p><strong>Do not award:</strong> ''find the best person for the job'' (purpose of all methods) or simply describing what an interview is.</p></div>"}, {"question": "Analyse one advantage for Clarks of using references to select new designers. [3 marks]", "marks": 3, "hint": "A reference comes from a third party — a previous employer. What can it confirm or reveal that an interview might not?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme (AO1b + AO2 + AO3a)</h5><ul>\n<li><strong>1 mark (U)</strong> — Advantage: confirms from a third party the candidate''s standard of work, teamworking, attitude, skills, personality; can verify information on application form; may reveal additional information; lower cost/quicker than interview</li>\n<li><strong>1 mark (APP)</strong> — Apply to Clarks: designers work closely with colleagues from marketing, finance and retail; designers are central to Clarks'' success; competitive market</li>\n<li><strong>1 mark (AN)</strong> — Business-facing impact: increases confidence in the appointment, reducing risk of a poor hire; potentially increases productivity; avoids costly mistakes</li>\n</ul></div>"}, {"question": "Recommend whether using interviews or references is likely to be more effective for selecting new designers. Give a reason for your answer. [3 marks]", "marks": 3, "hint": "Make a clear decision — don''t sit on the fence. Then explain why your chosen method is BETTER THAN the other for this specific business. A comparison must be made.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme (AO3b × 3)</h5><ul>\n<li><strong>1 mark</strong> — Clear decision (interviews OR references)</li>\n<li><strong>+1 mark</strong> — Non-contextual justification comparing both methods</li>\n<li><strong>+2 marks</strong> — Contextual justification (must reference Clarks/designers/fashion/teamwork etc.)</li>\n</ul><p><strong>Key rule:</strong> The justification MUST be comparative — it must explain why the chosen method is better than the other, not just why it is good on its own.</p></div>"}, {"question": "Recommend two methods of selection that Aldi should use to decide which of the five applicants to employ. [6 marks]", "marks": 6, "hint": "Choose two different methods from: interview, test, group activity, reference, presentation. For each one: explain what it is → apply it to Aldi''s context (shop manager / shop assistants) → analyse the benefit → give your recommendation with justification.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — Up to 3 marks per method recommended</h5><p>For each method: Understanding (1) + Application to Aldi (1) + Analysis/Recommendation with justification (1)</p></div>"}, {"question": "* Evaluate, with reference to the data in the case study, whether internal recruitment is the best method to use to fill the position of Marketing Manager (Children''s Shoes). [9 marks]", "marks": 9, "hint": "Use the marking grid: K → U → APP (use the numbers!) → AN (2 points) → EVAL (contextual judgement). Consider: Is there anyone internal with knowledge of the children''s shoe market? Does the cost saving justify potential risks?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme (9 marks)</h5><ul>\n<li><strong>K (1 mark)</strong> — Definition: internal recruitment is when a job vacancy is filled by someone already employed by the business</li>\n<li><strong>U (1 mark)</strong> — One advantage or disadvantage of internal recruitment (e.g. cheaper, quicker, no new ideas, restricted choice)</li>\n<li><strong>APP (up to 2 marks)</strong> — Use of numerical data: e.g. £2,000 cheaper; £1,300 cheaper induction; £3,300 total saving; 40 days faster; 3× faster; profit fell by £75,000 (2017–2019)</li>\n<li><strong>AN (up to 2 marks)</strong> — Business-facing impacts: lower costs support profitability (positive); no knowledge of children''s shoe market may reduce effectiveness of marketing (negative)</li>\n<li><strong>EVAL (up to 3 marks)</strong> — Contextual judgement: Is internal the BEST method for THIS role? Strong answer: the role requires knowledge of children''s shoes — the business has no experience in this market, so internal staff are unlikely to have the skills needed; the £3,300 saving is relatively small compared to the strategic importance of entering a new market successfully</li>\n</ul></div>"}]}}'::jsonb),
('business', '3-5-motivation-and-retention', '3.5 Motivation and Retention', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>These are the essential terms you must know for Unit 3.5. Learn these definitions precisely — examiners reward accurate use of business terminology.</p>\n<ul>\n  <li><strong>Motivation:</strong> The encouragement given to workers to work well. A motivated worker will feel responsible, fulfilled and happy in their work.</li>\n  <li><strong>Retention:</strong> When workers choose to stay employed in a business rather than leaving to work elsewhere.</li>\n  <li><strong>Labour Turnover:</strong> A measure of the number or proportion of staff who leave an organisation each year and who therefore need to be replaced.</li>\n  <li><strong>Productivity:</strong> A measure of output per worker. It is one way of measuring the performance of workers.</li>\n  <li><strong>Pay:</strong> The money earned by workers as a reward for the work they do.</li>\n  <li><strong>Salary:</strong> A set amount paid for a year''s work, usually split into 12 equal monthly payments.</li>\n  <li><strong>Wage:</strong> Usually a weekly system of pay, often calculated using a time-rate system (hours worked × hourly rate).</li>\n  <li><strong>Bonus:</strong> An additional payment to workers for achieving a measurable target (a form of performance-related pay).</li>\n  <li><strong>Profit Sharing:</strong> When workers receive a proportion of the profits made by a business.</li>\n  <li><strong>Fringe Benefits:</strong> Additional benefits that workers receive on top of their pay — e.g. pensions, childcare vouchers, company cars, private medical insurance, subsidised canteen meals.</li>\n  <li><strong>Praise:</strong> A non-financial method of motivating a worker by complimenting their work, making their effort feel recognised and valued.</li>\n  <li><strong>Award Scheme:</strong> A presentation of some kind (certificate, badge, voucher) to recognise somebody''s effort.</li>\n  <li><strong>Working Environment:</strong> The quality of the physical workplace and its social climate — includes how workers are treated and whether they feel valued.</li>\n</ul>", "check": {"question": "What is the difference between a bonus and profit sharing?", "options": ["A bonus pays for hitting a target; profit sharing gives a share of profits made", "They are exactly the same thing", "A bonus is only for managers; profit sharing is only for shop floor workers", "Profit sharing is paid weekly, a bonus is paid annually"], "answer": 0, "explain": "A bonus rewards hitting a specific target (e.g. sales figures), while profit sharing distributes a portion of the company''s overall profit among workers — the bigger the profit, the bigger the share."}}, {"title": "Why Motivation Matters: Benefits to Business", "html": "<p>Motivation is all about <strong>improving the performance of workers</strong>. Well-motivated workers bring several key benefits to a business:</p>\n<ul>\n  <li><strong>High employee performance:</strong> Workers are efficient because they gain rewards for good quality work.</li>\n  <li><strong>High retention and low turnover:</strong> Workers are happy to remain with the employer because they feel valued and rewarded.</li>\n  <li><strong>Ease of recruitment:</strong> The firm builds a good reputation for treating staff well, attracting more applicants and higher-quality candidates.</li>\n  <li><strong>Less need for supervision:</strong> Motivated staff are focused and self-directed, saving money on supervisory roles.</li>\n  <li><strong>Low absenteeism:</strong> Workers want to be at work to earn their rewards or because they enjoy their job. Absenteeism costs money through sick pay and lost output.</li>\n  <li><strong>Reduced waste:</strong> Motivated staff take pride in producing quality work, reducing the number of faulty goods or errors.</li>\n  <li><strong>Better delivery of services:</strong> Leads to fewer complaints and more satisfied customers who return to buy again.</li>\n  <li><strong>Increased custom:</strong> Higher quality goods and services attract more customers, making the business more successful.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Gravity Payments</h4>\n  <p>In 2015, Dan Price, CEO of Gravity Payments in Seattle, raised the minimum pay for all 120 workers to $70,000 per year. For one worker, Valerie, this meant a rise from $40,000 — meaning she no longer needed a second job. Five years later, in 2020, the number of customers had doubled and the company''s turnover rose from $3.8bn to $10bn.</p>\n  <p><strong>Takeaway:</strong> Higher pay directly motivated workers, reduced turnover, and drove significant business growth — the cost of higher wages was outweighed by the huge increase in revenue and customers.</p>\n</div>", "check": {"question": "In the Gravity Payments case study, what happened after Dan Price raised the minimum pay to $70,000?", "options": ["Customer numbers doubled and turnover rose to $10bn", "The company went bankrupt within a year", "Customer numbers fell because prices had to rise", "Nothing changed for the business"], "answer": 0, "explain": "Despite the higher wage cost, Gravity Payments saw customer numbers double and turnover rise dramatically over five years — showing the pay rise more than paid for itself through improved motivation and performance."}}, {"title": "Why Retention Matters", "html": "<p><strong>Retention</strong> refers to workers staying with a firm for a long period of time. High labour turnover (workers leaving frequently) creates serious problems:</p>\n<ul>\n  <li><strong>High recruitment and selection costs:</strong> Advertising, interviewing and onboarding new staff is expensive.</li>\n  <li><strong>Loss of experience and knowledge:</strong> Retained workers understand the business, its products and customers — replacing them takes time and leads to lower efficiency.</li>\n  <li><strong>High training costs:</strong> Research suggests it can cost 50–60% of a worker''s annual salary to replace them. For a worker earning £40,000, that could mean £20,000–£24,000 saved through good retention.</li>\n  <li><strong>Good morale:</strong> A stable team creates a positive atmosphere where people enjoy working together and performance improves.</li>\n  <li><strong>Attractive to recruits:</strong> Low turnover signals to potential employees that the business is a good place to work, making future recruitment easier and cheaper.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: United Utilities</h4>\n  <p>United Utilities supplies water and sewage services to around 5,000 employees across North West England — engineers, construction workers, clerical staff, financial managers and surveyors. Some work in offices in Warrington; others work on sites digging up roads to repair pipes under tight deadlines. Late work can trigger penalty payments to local councils.</p>\n  <p>United Utilities focuses on attracting and retaining staff through recognition, training and apprenticeships. In 2021, it employed 40 apprentices. It also uses a bonus scheme to reward maintenance teams for meeting deadlines.</p>\n  <p><strong>Takeaway:</strong> Retaining experienced engineers who know the pipework network and can meet tight deadlines is critical — losing them would mean high retraining costs, missed deadlines, and costly council penalties.</p>\n</div>", "check": {"question": "Roughly how much can it cost a business to replace a worker, according to research mentioned in this topic?", "options": ["1–2% of their annual salary", "50–60% of their annual salary", "Exactly £1,000 regardless of salary", "It costs nothing to replace a worker"], "answer": 1, "explain": "Research suggests replacing a worker can cost 50–60% of their annual salary — for someone earning £40,000, that''s potentially £20,000–£24,000, which is why good retention saves businesses significant money."}}, {"title": "Financial Methods of Motivation", "html": "<p>Financial methods of motivation involve <strong>paying money or giving monetary benefits</strong> to employees. There are four main types:</p>\n<ul>\n  <li><strong>Pay (Salary & Wage):</strong> The basic reward for work. Pay motivates because it enables workers to afford a good standard of living. Competitive pay attracts and retains staff. A <em>salary</em> is a fixed annual amount paid monthly. A <em>wage</em> is usually weekly, calculated by hours worked × hourly rate.</li>\n  <li><strong>Bonus:</strong> An additional payment triggered by reaching a measurable target — e.g. sales targets, output levels, or quality scores. It is a form of performance-related pay.</li>\n  <li><strong>Profit Sharing:</strong> A proportion of the business''s profits is shared out among workers. The bigger the profit, the larger the share — encouraging workers to be efficient and productive.</li>\n  <li><strong>Fringe Benefits:</strong> Non-cash extras on top of pay: pensions, car allowances, childcare vouchers, private medical insurance, share-buying schemes, subsidised canteen meals.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Aldi — UK''s Highest Paying Supermarket</h4>\n  <p>Aldi consistently pays higher minimum rates than any other UK supermarket. In 2021 it raised pay from £9.40 to £9.55 outside London (£11.07 in London) — exceeding the voluntary Living Wage. Aldi also pays workers during breaks, unlike some rivals.</p>\n  <p>CEO Giles Hurley linked high pay to having \"the most efficient and productive workforce.\" Aldi also invests in training and career development to recruit and retain the best people.</p>\n  <p><strong>Takeaway:</strong> High wages attract quality staff, reduce turnover and improve productivity — the cost of high pay can be offset by the efficiency and loyalty it creates.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: McDonald''s Bonuses</h4>\n  <p>Every month, McDonald''s awards bonuses to employees who work in the top 10% of its 400 UK restaurants. Rankings are based on mystery shopper reports. Store managers also receive bonuses linked to mystery shopper scores, sales growth, and profitability.</p>\n  <p><strong>Takeaway:</strong> Tying bonuses to measurable performance (mystery shopper scores) directly encourages staff to maintain high service quality, benefiting both customers and the business.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Delta Airlines — Profit Sharing</h4>\n  <p>In 2021, Delta Airlines paid over $1 billion (16.7% of profits) to its 90,000 employees worldwide. CEO Ed Bastian stated that workers deserve full credit for the company''s success.</p>\n  <p><strong>Takeaway:</strong> Sharing profits makes workers feel like genuine stakeholders in the business''s success — encouraging greater efficiency and team spirit to maximise the profit pot.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Travis Perkins — Fringe Benefits</h4>\n  <p>Travis Perkins (a timber and building merchant) offers: generous pension contributions, private medical insurance, discounted gym membership, share ''buy-as-you-earn'' schemes, a company car scheme, a subsidised bike-buying scheme, childcare vouchers, and an enhanced maternity scheme.</p>\n  <p><strong>Takeaway:</strong> A wide package of fringe benefits helps attract and retain employees by offering perks they may not be able to afford personally, boosting loyalty and reducing turnover.</p>\n</div>", "check": {"question": "What is the key difference between a salary and a wage?", "options": ["A salary is fixed monthly; a wage is hourly", "A salary is always lower than a wage", "Wages are only paid to managers", "There is no real difference between them"], "answer": 0, "explain": "A salary is a set amount for the year, split into equal monthly payments, while a wage is typically a weekly payment calculated using a time-rate system (hours worked × hourly rate)."}}, {"title": "Financial Methods — Advantages & Disadvantages", "html": "<p>Using financial methods to motivate workers costs the business money. However, lower average production costs and increased revenues may offset these costs. The right method depends on the type of worker.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Direct motivator:</strong> Pay enables workers to afford a better standard of living, providing a clear, tangible reward for effort.</div>\n    <div class=\"pro-item\"><strong>Performance-linked bonuses:</strong> Only paid when targets are met, so the cost to the business is tied directly to improved output or sales.</div>\n    <div class=\"pro-item\"><strong>Profit sharing builds team spirit:</strong> Workers are encouraged to collaborate and be efficient, knowing higher profits mean a bigger share for everyone.</div>\n    <div class=\"pro-item\"><strong>Fringe benefits attract talent:</strong> Valued by employees who may not be able to afford private healthcare or pensions themselves, boosting loyalty and retention.</div>\n    <div class=\"pro-item\"><strong>Competitive advantage in recruitment:</strong> Businesses with strong pay packages attract higher-quality applicants from a wider pool.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Pay is a cost:</strong> Higher wages and salaries directly increase business costs and can reduce profit margins if productivity doesn''t rise to compensate.</div>\n    <div class=\"con-item\"><strong>Time-rate pay doesn''t reward quality:</strong> A worker paid by the hour receives the same whether they work slowly or efficiently.</div>\n    <div class=\"con-item\"><strong>Unrealistic bonus targets demotivate:</strong> If workers believe targets are unachievable, bonuses have the opposite effect — they give up rather than try harder.</div>\n    <div class=\"con-item\"><strong>Profit sharing may upset shareholders:</strong> Money shared with workers reduces dividends — though if the scheme boosts profits enough, overall returns may still rise.</div>\n    <div class=\"con-item\"><strong>Fringe benefits may not suit everyone:</strong> A company car is useless to a worker who doesn''t drive; childcare vouchers mean nothing to an employee without children.</div>\n  </div>\n</div>", "check": {"question": "Why might unrealistic bonus targets actually demotivate workers rather than motivate them?", "options": ["Bonuses always demotivate workers regardless of targets", "If workers see the target as unachievable, they give up", "Bonuses are illegal if targets are too high", "Workers always prefer a fixed salary over any bonus"], "answer": 1, "explain": "If a bonus target feels impossible to reach, workers lose the incentive to try — the bonus scheme backfires and produces the opposite of its intended motivational effect."}}, {"title": "Non-Financial Methods of Motivation", "html": "<p>Non-financial methods motivate workers <strong>without money or benefits</strong>. They focus on recognition, respect, and the quality of the working experience. There are three main types:</p>\n<ul>\n  <li><strong>Praise:</strong> Verbal or written recognition of good work. Can be informal (a quiet word of thanks) or formal (public recognition at a ceremony). It makes workers feel their effort is noticed and valued — raising self-esteem and setting an example to others.</li>\n  <li><strong>Award Schemes:</strong> A tangible form of recognition — ''worker of the month'', certificates, vouchers, lapel badges (Asda), stars (McDonald''s), Red Letter Days, or free holidays. Even simple awards can powerfully boost morale and productivity.</li>\n  <li><strong>Working Environment:</strong> The physical conditions and social atmosphere of the workplace. Workers are more motivated when they feel safe, comfortable, respected and consulted. This includes team-bonding activities, management style, trust, and flexibility. Culture and climate matter deeply.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Google — A Positive Workplace Environment</h4>\n  <p>At Google''s California headquarters, workers are provided with free meals cooked by in-house chefs, free laundry, and childcare services. Employees are also involved in recruiting new colleagues. Research by Warwick University found that employee support at Google resulted in a 12% increase in productivity.</p>\n  <p><strong>Takeaway:</strong> Creating a genuinely supportive and enjoyable working environment — even without increasing salaries — can produce measurable productivity gains and signal that the employer values its staff.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Alphabet — Working Environment & Staff Voice</h4>\n  <p>Alphabet (a fleet maintenance company) motivates workers through a company choir that bonds teams across departments, and the APE (Alphabet Proactive Experts) initiative — a blackboard where workers write suggestions on how to improve the company. Managers always respond to these suggestions, even when not adopted.</p>\n  <p><strong>Takeaway:</strong> Giving workers a voice and actively listening to their ideas makes them feel respected and responsible — two powerful non-financial motivators that cost the business very little.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Praise in Football</h4>\n  <p>Football managers frequently shake hands, hug, or pat players on the back after substitutions or at the end of matches. This demonstrates that praise is important even for highly paid professionals — it makes workers feel valued and appreciated.</p>\n  <p><strong>Takeaway:</strong> A simple, genuine word of recognition from a manager can have a significant motivational effect regardless of how much the worker already earns.</p>\n</div>", "check": {"question": "According to the Google case study, what was the measured effect of a supportive working environment?", "options": ["A 12% increase in productivity", "A 50% reduction in staff", "No measurable change at all", "A decrease in customer satisfaction"], "answer": 0, "explain": "Research by Warwick University found that the supportive environment at Google — free meals, laundry, childcare — resulted in a 12% increase in productivity, even without raising salaries."}}, {"title": "Non-Financial Methods — Advantages & Disadvantages", "html": "<p>Non-financial methods can be very effective and sometimes cost nothing at all. However, they are not without limitations.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Low or zero cost:</strong> Praise costs nothing. A genuine compliment or word of thanks takes seconds but can have a lasting positive effect on morale.</div>\n    <div class=\"pro-item\"><strong>Builds long-term loyalty:</strong> Workers who feel respected and valued are more likely to stay — non-financial methods often drive longer-term retention than one-off financial rewards.</div>\n    <div class=\"pro-item\"><strong>Award schemes boost public recognition:</strong> Recognising good work in front of peers raises self-esteem and sets a standard for others to aspire to.</div>\n    <div class=\"pro-item\"><strong>Positive environment improves teamwork:</strong> Activities like team-bonding days or a company choir build strong workplace relationships, improving collaboration and communication.</div>\n    <div class=\"pro-item\"><strong>Inclusive:</strong> A good working environment benefits all employees equally, unlike financial rewards which may only go to top performers.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Some workers may find praise insufficient:</strong> Workers expecting financial recognition may view praise as a substitute for a pay rise — creating cynicism rather than motivation.</div>\n    <div class=\"con-item\"><strong>Award schemes can cause conflict:</strong> If only one worker wins ''employee of the month'', others may feel overlooked or demotivated, especially if the process appears unfair.</div>\n    <div class=\"con-item\"><strong>Environment improvements cost money:</strong> Redecorating offices, buying new furniture, or funding team days out all have a direct cost to the business.</div>\n    <div class=\"con-item\"><strong>Lost production during activities:</strong> If workers attend bonding activities or ceremonies during working hours, output may temporarily fall.</div>\n    <div class=\"con-item\"><strong>Not universally effective:</strong> Different workers are motivated differently. What energises one person may mean little to another.</div>\n  </div>\n</div>", "check": {"question": "Why can award schemes like ''Employee of the Month'' sometimes cause problems?", "options": ["They are too expensive for most businesses to afford", "Workers who lose out may feel overlooked or unfair", "They are illegal in most countries", "They only work for part-time staff"], "answer": 1, "explain": "While award schemes can boost the winner''s motivation, workers who consistently miss out may become demotivated or feel the process is unfair — a real disadvantage of this non-financial method."}}, {"title": "Pay Calculations", "html": "<p>You must be able to calculate pay, bonuses, and profit shares in the exam. Here are the key formulas and worked examples:</p>\n\n<div class=\"formula-box\">\n  <strong>Time-Rate Weekly Wage =</strong> Hours Worked &times; Hourly Rate\n</div>\n\n<div class=\"formula-box\">\n  <strong>Overtime Pay =</strong> Overtime Hours &times; (Hourly Rate &times; Overtime Multiplier)\n</div>\n\n<div class=\"formula-box\">\n  <strong>Profit Share per Worker =</strong> (Total Profit &times; % to share) &divide; Number of Workers\n</div>\n\n<div class=\"formula-box\">\n  <strong>Bonus per Worker =</strong> Total Bonus Pool &divide; Number of Workers in Team\n</div>\n\n<p><strong>Worked Example 1 — Wage + Overtime (Angus Deade):</strong><br>\n£9/hour × 35 hours × 4 weeks = £1,260<br>\nOvertime: 12 hours × £13.50 (time and a half) = £162<br>\n<strong>Total = £1,422</strong></p>\n\n<p><strong>Worked Example 2 — Salary + Bonus (Fabrice N''gono):</strong><br>\nBasic salary: £800/month<br>\nBonus pool: £960 ÷ 8 workers = £120 bonus<br>\n<strong>Total = £920</strong></p>\n\n<p><strong>Worked Example 3 — Salary + Profit Share + Fringe Benefits (Alastair Munro):</strong><br>\nSalary: £80,000<br>\nProfit share: 2% × £2,000,000 = £40,000<br>\n<strong>Total = £120,000 + fringe benefits (company car + health insurance)</strong></p>\n\n<p><strong>Worked Example 4 — Salary + Bonus (Wasim Ikram):</strong><br>\nSalary: £30,000<br>\nBonus: 15% × £30,000 = £4,500<br>\n<strong>Total = £34,500</strong></p>", "check": {"question": "A worker earns £8 per hour and works 30 hours in a week, plus 5 hours of overtime at time-and-a-half. What is their total pay for the week?", "options": ["£240", "£300", "£280", "£320"], "answer": 1, "explain": "Basic pay: 30 × £8 = £240. Overtime: 5 × (£8 × 1.5) = 5 × £12 = £60. Total = £240 + £60 = £300."}}, {"title": "Evaluating Motivation: Are the Costs Worth It?", "html": "<p>Whether a motivation system is worthwhile depends on how effectively it improves performance <strong>compared to its cost</strong>. This is a key evaluation point in the exam.</p>\n<ul>\n  <li><strong>Financial methods cost money</strong> — bonuses, pay rises, profit shares and fringe benefits all reduce profits available to owners/shareholders.</li>\n  <li><strong>Management costs:</strong> Managers must decide who gets rewards, how much, and arrange delivery fairly. If the system is seen as unfair, it can <em>de-motivate</em> workers who miss out.</li>\n  <li><strong>Non-financial methods</strong> may also cost money (awards, activities) or lost output (if workers are away from their desks).</li>\n</ul>\n<p>However, the benefits may outweigh the costs if motivation leads to:</p>\n<ul>\n  <li>Higher productivity &rarr; lower cost per unit &rarr; higher profit margins</li>\n  <li>Lower absenteeism &rarr; fewer sick pay costs &rarr; consistent output</li>\n  <li>Higher retention &rarr; lower recruitment and training costs</li>\n  <li>Better quality &rarr; fewer complaints &rarr; more repeat customers &rarr; higher revenue</li>\n</ul>\n<p><strong>Key evaluation phrase:</strong> <em>\"It depends on whether the increase in productivity and reduction in costs outweighs the cost of the motivational method used.\"</em></p>\n<p><strong>Also consider:</strong> A modest level of staff turnover can actually be beneficial — new workers bring fresh ideas, perspectives and energy. Good retention is important, but a business that <em>never</em> loses any staff may miss out on innovation.</p>", "check": {"question": "Why might a small amount of staff turnover actually be good for a business, according to this topic?", "options": ["It saves money on holiday pay", "New workers bring fresh ideas, perspectives and energy", "It means the business doesn''t need a HR department", "Turnover always improves productivity regardless of cause"], "answer": 1, "explain": "While high retention is generally beneficial, a business that never loses any staff may stagnate. A modest level of turnover brings in new ideas and skills, which is why ''optimal retention'' rather than ''zero turnover'' is the goal."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Motivation", "definition": "The encouragement given to workers to work well — making them feel responsible, fulfilled and happy."}, {"term": "Retention", "definition": "When workers choose to stay employed in a business rather than leaving to work elsewhere."}, {"term": "Labour Turnover", "definition": "The proportion of staff who leave an organisation each year and need to be replaced."}, {"term": "Productivity", "definition": "Output per worker — a key measure of employee performance."}, {"term": "Salary", "definition": "A fixed annual amount divided into 12 equal monthly payments."}, {"term": "Wage", "definition": "A weekly payment usually calculated as: hours worked × hourly rate."}, {"term": "Bonus", "definition": "An additional payment for reaching a measurable target — a form of performance-related pay."}, {"term": "Profit Sharing", "definition": "A scheme where workers receive a set percentage of the business''s profits."}, {"term": "Fringe Benefits", "definition": "Non-cash extras on top of pay — e.g. pensions, company cars, private medical insurance, childcare vouchers."}, {"term": "Praise", "definition": "A non-financial motivator: recognising and complimenting a worker''s effort, formally or informally."}, {"term": "Award Scheme", "definition": "A tangible form of recognition — certificates, badges, vouchers — to acknowledge good work."}, {"term": "Working Environment", "definition": "The physical and social quality of the workplace — including how workers are treated, trusted and involved."}, {"term": "Time-Rate Pay Formula", "definition": "Hours Worked × Hourly Rate = Weekly Wage"}, {"term": "Profit Share Formula", "definition": "(Total Profit × %) ÷ Number of Workers = Share per Worker"}, {"term": "Absenteeism", "definition": "Frequent unexplained absence from work — a sign of poor motivation, increasing costs through sick pay and lost output."}]}, "mcq": {"enabled": true, "questions": [{"question": "A worker is paid £8 per hour for working a 35-hour week. On top of this, the worker is paid a bonus of 10% of their wage for the week. How much did the worker earn in total?", "options": ["£280", "£420", "£308", "£282.80"], "answer": 2, "explain": "Correct answer: £308. Step 1: £8 × 35 = £280 basic wage. Step 2: 10% bonus = £28. Step 3: £280 + £28 = £308. Do not confuse the bonus with overtime — a 10% bonus is added on top of the full week''s pay."}, {"question": "Which of the following is a financial method of motivating workers?", "options": ["Praise", "A good working environment", "Award scheme", "Profit sharing"], "answer": 3, "explain": "Correct answer: Profit sharing. Award schemes, praise, and a good working environment are all non-financial methods. Profit sharing directly involves paying workers a share of the business''s money, making it a financial method."}, {"question": "Which of the following is a disadvantage of a method of motivating workers?", "options": ["An increase in some of the costs of the business", "Increased productivity of staff", "A reduction in absenteeism", "Increased retention of workers"], "answer": 0, "explain": "Correct answer: an increase in costs. Options B, C and D are all benefits of motivation. Increased costs (e.g. bonus payments, pay rises, fringe benefits) is the key disadvantage to the business of using financial motivation methods."}, {"question": "Jowill, an employer, raises the pay of her eight employees by £1.50 per hour. They work 35 hours each week. After the increase, Jowill''s revenue increased by £680 per week. Which statement is true?", "options": ["Jowill''s costs rose by £680 per week.", "Jowill''s profit rose by £260 per year.", "The increase in Jowill''s revenue per week exceeded her increase in costs by £260.", "Jowill''s revenue rose by £420 per week."], "answer": 2, "explain": "Correct answer: Cost increase = 8 workers × £1.50 × 35 hours = £420 per week. Revenue increase = £680. £680 − £420 = £260 extra profit per week. Option A is wrong (costs rose by £420, not £680). Option B confuses weekly gain with annual. Option D is wrong (revenue rose by £680, not £420)."}, {"question": "What is a financial method of motivation that a restaurant manager may use?", "options": ["Make staff pay for any glasses or plates they break", "An award scheme for the chefs to develop low cost meals", "Introduce profit sharing for the chefs", "Praise staff who suggest how the restaurant could save money"], "answer": 2, "explain": "Correct answer: profit sharing. This involves giving workers a share of the business''s profits, which is a direct financial payment. A is an award scheme (non-financial). C is a penalty, not motivation. D is praise (non-financial)."}, {"question": "What is a non-financial method of motivation that a manufacturer of handmade wooden toys could use?", "options": ["Giving production operatives a bonus for every 1000 toys made", "Increasing the rate of pay for workers in the dusty woodcutting shed", "Praising the workers who take the greatest care when painting the designs", "Providing free private medical insurance to all workers"], "answer": 2, "explain": "Correct answer: praise. This involves recognising good work verbally or formally, with no money exchanged. Options A and B involve payments (financial). Option D is a fringe benefit (financial method)."}, {"question": "Employee retention...", "options": ["extends the working hours of employees", "leads to higher recruitment costs", "minimises time spent selecting new workers", "reduces discrimination in the workplace"], "answer": 2, "explain": "Correct answer: When workers stay with a business (high retention), there is less need to recruit replacements, so less time is spent on selection processes. Option B is the opposite — high retention REDUCES recruitment costs. Options A and D are not linked to the definition of retention."}, {"question": "A business has introduced a bonus scheme based on production targets. Which of the following statements would NOT be true?", "options": ["Workers who do not reach the target will have their basic pay reduced", "Unrealistic targets may lead to lower levels of motivation", "The bonus scheme will increase business costs", "The bonus scheme is a form of performance-related pay"], "answer": 0, "explain": "Correct answer: A bonus scheme adds extra pay for reaching targets — it does NOT reduce basic pay for those who miss targets. A is true (bonuses are performance-related pay). B is true (bonuses add to costs). C is true (unrealistic targets can demotivate)."}, {"question": "Xaio and Zhou own a building firm with 50 workers and are concerned about high recruitment costs. Which of the following would help deal with this problem?", "options": ["Decrease the hourly rate paid to workers", "Find ways to increase employee retention", "Give workers fewer fringe benefits", "Obtain additional finance from the bank"], "answer": 1, "explain": "Correct answer: High recruitment costs arise from frequent staff departures. Improving retention (keeping workers longer) directly reduces the need to recruit replacements. Options A and C would likely increase turnover. Option D addresses cash but not the root problem."}, {"question": "Which one of the following is NOT a benefit to a business of improving employee retention?", "options": ["Less time spent on recruitment", "Cost saving", "Lower selling price", "Reduced need for training"], "answer": 2, "explain": "Correct answer: lower selling price. This is unrelated to employee retention. Retention reduces recruitment and training costs (A and D), and saves management time spent selecting new workers (B). A lower selling price is a pricing decision, not a retention benefit."}, {"question": "A jet ski retailer with limited funds has a problem with the motivation levels of its 25 sales assistants. Which method should they use?", "options": ["Increase the sales assistants'' pay rate by £3 per hour", "Offer sales assistants a bonus of £500 for each jet ski sold", "Reduce the number of fringe benefits given to employees", "Set up a ''seller of the month'' award scheme"], "answer": 3, "explain": "Correct answer: ''seller of the month'' award scheme. The key constraint is limited funds. An award scheme is a non-financial method that costs very little but can significantly boost motivation through recognition. Options A and B are expensive financial methods. Option C would reduce motivation further."}, {"question": "A supermarket chain is receiving increasing complaints about the poor attitude of its sales assistants when stores are busy. What would help deal with this problem?", "options": ["Employ fewer sales assistants at each store", "Find ways to increase employee motivation at each store", "Limit the number of customers that can enter each store", "Reduce the holiday entitlement of rude employees"], "answer": 1, "explain": "Correct answer: Poor attitude from staff is a symptom of low motivation. Improving motivation will encourage staff to provide better customer service even when busy. Option A would make the problem worse. Option C damages revenue. Option D is a punitive measure unlikely to improve attitudes long-term."}]}, "fib": {"enabled": true, "questions": [{"text": "Motivation is the [encouragement] given to workers to work well."}, {"text": "[Retention] refers to workers staying with a firm for a long period of time."}, {"text": "High labour [turnover] means workers leave after only a short period of time, requiring the firm to recruit replacements."}, {"text": "A [salary] is a fixed annual amount paid in 12 equal monthly payments, while a [wage] is a weekly system usually based on hours worked."}, {"text": "A [bonus] is an additional payment triggered by reaching a measurable target, and is a form of [performance-related] pay."}, {"text": "In a [profit sharing] scheme, a business sets aside a proportion of profits to share out among its workers."}, {"text": "[Fringe] benefits are non-cash extras workers receive on top of pay, such as company cars and private medical insurance."}, {"text": "[Praise] is a non-financial method of motivation that costs nothing and involves recognising and valuing the work of employees."}, {"text": "Research suggests replacing a worker earning £40,000 per year could cost between 50% and 60% of their salary — meaning a saving of £20,000 to £[24,000] through good retention."}, {"text": "Motivated workers require less [supervision] because they are focused and self-directed in their roles."}, {"text": "At Gravity Payments, raising the minimum pay to $70,000 caused the number of customers to [double] in five years."}, {"text": "Google''s investment in employee support led to a [12] per cent increase in productivity, according to Warwick University research."}]}, "tf": {"enabled": true, "questions": [{"statement": "If a worker improves productivity, they will produce more than they used to in the same amount of time.", "answer": true, "explain": "TRUE. Productivity is measured as output per worker. An improvement means more is produced in the same time period."}, {"statement": "If workers in a car factory improve their productivity, the cost of producing each car will fall.", "answer": true, "explain": "TRUE. If more cars are produced using the same resources (time, workers, machinery), the fixed costs are spread across more units, lowering the average cost per car."}, {"statement": "Motivated workers will always want to leave the business to work elsewhere.", "answer": false, "explain": "FALSE. Motivated workers are more likely to STAY with their employer because they feel valued and rewarded. High motivation is linked to high retention, not high turnover."}, {"statement": "Training costs will usually fall if staff turnover is high.", "answer": false, "explain": "FALSE. High staff turnover means new workers constantly need to be recruited and trained — this INCREASES training costs significantly. Low turnover reduces the need for repeated training."}, {"statement": "Increased motivation reduces costs because workers are less likely to be absent.", "answer": true, "explain": "TRUE. Motivated workers want to be at work to earn their rewards or because they enjoy their job. Lower absenteeism means fewer sick pay costs and less disruption to production."}, {"statement": "Motivated workers need a lot of supervision to make sure they work hard.", "answer": false, "explain": "FALSE. Motivated workers are focused and self-directed. One key benefit of good motivation is that it REDUCES the need for supervision, saving the business money on management costs."}, {"statement": "Increased motivation saves on training costs because workers are likely to remain at the firm longer and fewer new recruits are needed.", "answer": true, "explain": "TRUE. Higher motivation leads to better retention. Retained workers already know the job, so the business spends less on training new recruits."}, {"statement": "Motivated workers may help reduce business costs because they take pride in working accurately, so reducing waste.", "answer": true, "explain": "TRUE. Motivated workers want to produce good quality work. Fewer errors and faulty goods means less raw material wasted — directly reducing production costs."}, {"statement": "Motivation systems can be expensive as managers need to be paid to run them.", "answer": true, "explain": "TRUE. Managers must decide which workers receive rewards, how much to give, and whether the system is fair. This management time and oversight has a cost to the business."}, {"statement": "Financial methods of motivation always increase total business costs.", "answer": true, "explain": "TRUE. Financial methods — pay rises, bonuses, profit sharing, fringe benefits — all represent additional money the business must pay out, increasing total costs."}, {"statement": "Motivating workers always reduces the average costs of producing goods and services.", "answer": false, "explain": "FALSE. While motivation can increase productivity and reduce waste (which may lower average costs), there is no guarantee. The cost of the motivation scheme itself may outweigh the savings — especially if productivity doesn''t improve enough."}, {"statement": "A modest level of staff turnover can be beneficial to a business.", "answer": true, "explain": "TRUE. New workers bring fresh ideas, new skills, and innovative approaches. A business where staff never leave may become stagnant. Some turnover can be healthy, as long as it is not excessive."}]}, "misc": {"enabled": true, "items": [{"myth": "Only financial methods can motivate workers.", "truth": "Non-financial methods — praise, award schemes, and a positive working environment — can be equally or more effective. Research consistently shows that recognition from a manager can be the highest-ranked motivator. Non-financial methods also tend to produce longer-term benefits and cost the business far less.", "check": {"question": "Can non-financial methods like praise be as effective as financial rewards for motivating workers?", "options": ["Only in small businesses", "Only for senior managers", "No — only money motivates workers", "Yes — praise can be a top motivator"], "answer": 3, "explain": "Non-financial methods such as praise and recognition are consistently shown to be highly effective motivators, often producing longer-term benefits than one-off financial rewards, and at a much lower cost to the business."}}, {"myth": "All workers are motivated by the same things.", "truth": "Different workers respond to different motivators based on their personality, life stage, and role. A one-size-fits-all approach is ineffective. Businesses should use a range of financial and non-financial methods to suit all employees.", "check": {"question": "Why is a ''one-size-fits-all'' approach to motivation often ineffective?", "options": ["It is too expensive to implement", "Workers respond to different things", "It is illegal under employment law", "It only works for full-time staff"], "answer": 1, "explain": "Workers are individuals with different needs and priorities — a company car might motivate one worker but mean nothing to another who doesn''t drive. Businesses need a range of methods to motivate everyone effectively."}}, {"myth": "High retention is always better for a business.", "truth": "While high retention reduces costs and maintains experience, a modest level of turnover can be advantageous — new staff bring fresh ideas, skills and perspectives. The goal is optimal retention, not zero turnover.", "check": {"question": "Is the goal of a business to achieve zero staff turnover?", "options": ["No — optimal retention is the goal, not zero turnover", "Yes, but only for management positions", "Yes, zero turnover is always the ideal outcome", "No, businesses should aim for maximum turnover instead"], "answer": 0, "explain": "While high retention has clear benefits, a small amount of turnover is healthy — new staff bring fresh perspectives and skills that an unchanging workforce might lack."}}, {"myth": "A bonus scheme will always motivate workers to work harder.", "truth": "Bonuses only motivate if the targets are realistic. If targets are seen as unachievable, workers will give up rather than try harder — the bonus actually demotivates. Targets must be challenging but attainable.", "check": {"question": "What happens if bonus targets are seen by workers as unachievable?", "options": ["Workers always try even harder to reach them", "Nothing changes in worker behaviour", "Workers give up trying, so the bonus demotivates", "The business must pay the bonus anyway"], "answer": 2, "explain": "If targets feel impossible, workers lose the incentive to push for them — meaning an unrealistic bonus scheme can actually demotivate staff rather than encourage harder work."}}, {"myth": "Motivation only affects how happy workers feel — it doesn''t impact business profits.", "truth": "Motivation has direct financial consequences: lower absenteeism reduces costs, higher productivity increases output, better quality reduces waste, and improved service grows customer loyalty — all of which improve profitability.", "check": {"question": "How does worker motivation actually affect business profits?", "options": ["Motivation has no measurable business impact", "It doesn''t — motivation only affects employee happiness", "Only through reduced wage costs", "Through less absenteeism and higher output overall"], "answer": 3, "explain": "Motivation has real financial consequences — it reduces costs (absenteeism, waste) and increases revenue (productivity, customer loyalty), directly affecting the bottom line, not just how workers feel."}}, {"myth": "Profit sharing reduces profits because money is given to workers.", "truth": "Profit sharing can actually increase overall profits if it motivates workers to be more efficient and productive. Shareholders may benefit from a larger profit pot even after the workers'' share has been distributed.", "check": {"question": "Can profit sharing actually increase a business''s overall profits?", "options": ["Yes — efficiency gains can grow the total profit", "Only if the business has fewer than 10 employees", "Profit sharing has no effect on motivation at all", "No — sharing profits always reduces total profit"], "answer": 0, "explain": "If profit sharing motivates workers to be more productive and efficient, the total profit generated can grow — meaning shareholders may end up with a larger amount even after the workers'' share is paid out, as seen in the Delta Airlines example."}}, {"myth": "Employee retention is important just because it makes workers feel good.", "truth": "Examiners want business-focused reasons. Retention reduces recruitment and training costs (which can be 50–60% of annual salary), maintains expertise and customer relationships, supports morale, and makes the business more attractive to future recruits.", "check": {"question": "When explaining why retention matters in an exam answer, what should you focus on?", "options": ["Business reasons, like lower recruitment costs", "How happy it makes the workers feel", "Only the legal requirements around retention", "The personal opinions of the business owner"], "answer": 0, "explain": "Examiners want business-level reasoning — cost savings on recruitment and training, retained expertise, and improved ability to attract future staff — not just statements about employee happiness."}}, {"myth": "Fringe benefits motivate all workers equally.", "truth": "Fringe benefits are not universally valued. A company car is useless to someone who doesn''t drive; childcare vouchers don''t benefit workers without children. The right fringe benefit depends on the individual worker''s needs and life circumstances.", "check": {"question": "Why might a company car fail to motivate a particular worker?", "options": ["All workers value a company car equally", "If the worker doesn''t drive, the benefit is irrelevant to them", "Company cars are always too expensive for businesses to offer", "Company cars are illegal as a fringe benefit"], "answer": 1, "explain": "Fringe benefits only motivate when they match a worker''s actual needs and circumstances — a company car means nothing to someone who doesn''t drive, just as childcare vouchers mean nothing to a worker without children."}}, {"myth": "Salary is better than wages for motivating workers.", "truth": "Neither is automatically better. Salary provides stability and can motivate through promotion prospects. Wages with time-rate pay are simple but don''t directly reward high performance. The best system depends on the type of job and what the business wants to incentivise.", "check": {"question": "Is a salary always a better motivator than a wage?", "options": ["Yes, salary is always more motivating", "Salary and wages are identical in every way", "No, the better choice depends on the job itself", "No, wages are always more motivating"], "answer": 2, "explain": "Neither system is universally superior. Salary offers stability, while time-rate wages are simple to calculate but don''t reward performance directly — the right choice depends on the role and business goals."}}, {"myth": "Praise is only effective for low-paid workers who don''t earn much money.", "truth": "Praise is important at all levels — even highly paid professional footballers visibly respond to recognition from their managers. The desire to feel valued and appreciated is a universal human need, not limited by income level.", "check": {"question": "According to the football case study, does praise only matter to low-paid workers?", "options": ["No — even top footballers respond to praise", "Yes — high earners don''t need recognition", "Praise only matters to part-time workers", "Praise has no effect on professional athletes"], "answer": 0, "explain": "The football example shows that even very highly paid professionals respond to genuine praise and recognition — the need to feel valued is universal and not limited to lower-income workers."}}]}, "tips": {"enabled": true, "items": [{"title": "One Point. Full Stop. Move On.", "html": "\n      <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct point. No explanation. No examples. No paragraphs.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific point = 1 mark ✅</li>\n        <li>A vague or general point = 0 marks ❌</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"Motivation.\"</em><br/>\n      This is just the topic name — it doesn''t say anything useful about why retention matters.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"Lower recruitment costs.\"</em><br/>\n      Specific, relevant, directly answers the question.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> On the Redrow Homes question, many students wrote \"workers feel happier\" — this received no marks because it describes a personal benefit to the worker, not an importance to the business. Always write from the <strong>business''s perspective</strong>.</p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write a definition of the term when asked to identify something. If asked \"identify a financial method of motivation,\" write \"profit sharing\" — not \"financial methods are those involving money.\"</p>\n    ", "check": {"question": "Why did the answer ''workers feel happier'' score zero marks on the Redrow Homes question about why retention is important to a business?", "options": ["A worker feeling, not a business reason", "It was spelled incorrectly", "It was too long an answer", "Redrow Homes does not employ any workers"], "answer": 0, "explain": "The question asks for the importance to the business, so an answer focused on worker feelings doesn''t answer the question — always write from the business''s perspective for these marks."}}, {"title": "Understanding + Application = 2 Marks", "html": "\n      <p>A 2-mark <strong>''Explain''</strong> question requires two linked points: a reason <strong>why</strong> something is true, applied to the business in the case study.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Point (U):</strong> Give the business reason</li>\n        <li><strong>Application (APP):</strong> Link it specifically to the business in the case study</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n      <em>\"Retention is important because it reduces recruitment costs.\"</em><br/>\n      This is correct but has NO application — it scores only 1 mark.</p>\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"Retention reduces recruitment costs (U), which is especially important for United Utilities as it employs 5,000 workers and constantly replacing staff would be very expensive (APP).\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Application marks cannot be awarded without the understanding mark. You must earn U before you can earn APP. Always make your point first, then apply it.</p>\n      <p><strong>Sentence Starters:</strong><br/>\n      \"This is particularly important for [Business] because...\"<br/>\n      \"In the case of [Business], this means that...\"</p>\n    ", "check": {"question": "What is missing from the answer: ''Retention is important because it reduces recruitment costs''?", "options": ["Nothing — it scores full marks", "A link to the named business", "A definition of recruitment", "A calculation"], "answer": 1, "explain": "This answer gives the understanding point (U) but stops there — without applying it specifically to the business in the case study, it can only score 1 of the 2 marks available."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n      <p>A 3-mark <strong>''Analyse''</strong> question follows a strict three-step structure. Miss any one of these steps and you lose a mark.</p>\n      <p><strong>The Three-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the benefit or concept clearly.</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link it directly to the specific business in the case study. Quote or reference the case study.</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the financial or operational impact on the business (costs, revenue, reputation, profit).</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n      <em>\"A bonus motivates workers to work harder.\"</em><br/>\n      This is knowledge only — no application, no analysis. Maximum 1 mark.</p>\n\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"A bonus scheme motivates workers to meet targets (U). For United Utilities, the bonus is paid when maintenance teams meet their road-repair deadlines (APP). This means United Utilities avoids paying penalty charges to local councils, protecting the company''s profits (AN).\"</em></p>\n\n      <p><strong>🚫 Zero Marks for Analysis without Application:</strong> If you don''t use the case study, you cannot score the analysis mark — even if your business knowledge is perfect. Examiners will award 0 for analysis if there is no application.</p>\n\n      <p><strong>The \"So What?\" Rule:</strong> After each point, ask yourself \"So what does this mean for the business?\" Keep pushing until you hit a bottom-line impact: costs, revenue, profit, reputation, or customer numbers.</p>\n    ", "check": {"question": "Can you score the analysis (AN) mark on a 3-mark question if you don''t apply your point to the case study business?", "options": ["Yes, knowledge alone is enough for all 3 marks", "No — zero marks without application to it", "Yes, but only for calculation questions", "It depends on how long the answer is"], "answer": 1, "explain": "Without application to the specific business in the case study, you cannot score the analysis mark — even with perfect business knowledge. The chain must be U → APP → AN in that order."}}, {"title": "Make a Choice, Compare Both, Use Context", "html": "\n      <p>A 3-mark <strong>''Recommend''</strong> question (like the Walkers Ltd question) requires a clear decision with a comparative justification using the case study.</p>\n      <p><strong>The Three-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Judgement (1 mark):</strong> State your clear recommendation (e.g., \"Walkers Ltd should use award schemes\").</li>\n        <li><strong>Step 2 — Contextual justification (2 marks):</strong> Explain WHY your choice is better THAN the other option, using details from the case study.</li>\n      </ul>\n      <p><strong>⚠️ Critical Rule:</strong> Your justification MUST cover BOTH methods — explain why the chosen method is better AND why the other is less suitable. You cannot score full marks by only praising your chosen option.</p>\n\n      <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n      <em>\"Walkers Ltd should use award schemes because they make workers feel valued.\"</em><br/>\n      This gives a judgement and a reason, but doesn''t compare or use the case study.</p>\n\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"Walkers Ltd should use an award scheme (JUDGEMENT). The survey shows workers feel unvalued, so public recognition would directly address this issue. Unlike a wage increase — which workers may take for granted once it becomes the norm — an award scheme offers visible, ongoing recognition that continuously motivates workers (COMPARISON + CONTEXT).\"</em></p>\n    ", "check": {"question": "What is the critical rule for scoring full marks on a ''Recommend'' question?", "options": ["Only explain why your chosen method is good", "You must compare both options, not just one", "Write as many recommendations as possible", "Avoid using the case study"], "answer": 1, "explain": "Full marks require a genuine comparison — you must justify your chosen method while also explaining why the alternative is less suitable, both grounded in the case study context."}}, {"title": "Both Sides + A Justified Conclusion", "html": "\n      <p>A 7-mark question is marked using a levels-of-response grid. To reach the top level, you must demonstrate <strong>application, analysis, AND strong evaluation</strong>.</p>\n      <p><strong>Structure your answer in 3 paragraphs:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — AN & APP:</strong> Analyse the first impact, applied to the business in context.</li>\n        <li><strong>Paragraph 2 — AN & APP:</strong> Analyse a second impact (or the other side), applied to the business in context.</li>\n        <li><strong>Paragraph 3 — EVAL (3 parts):</strong>\n          <ul>\n            <li><strong>Decision:</strong> Make a clear judgement.</li>\n            <li><strong>Context:</strong> Reference something specific from the case study.</li>\n            <li><strong>Impact/Reasoning:</strong> Explain the consequence of your decision for the business.</li>\n          </ul>\n        </li>\n      </ul>\n      <p><strong>The \"It depends on...\" Rule:</strong> A conclusion that just repeats your earlier points scores zero evaluation marks. Your conclusion MUST add something new — a condition, a comparison, or a business-specific reason.</p>\n      <p><strong>✅ Strong Evaluation Sentence Starters:</strong><br/>\n      \"Overall, I recommend... because...\"<br/>\n      \"However, this depends entirely on whether...\"<br/>\n      \"Ultimately, [Option X] is more suitable for [Business] because, given that [context]...\"</p>\n      <p><strong>⚠️ Examiner Warning — Waitrose Question:</strong> Many students wrote about profit sharing in general without applying it to Waitrose''s 50,000 employees or its high-income customer base. The evaluation mark requires a contextual judgement — mentioning Waitrose specifically.</p>\n    ", "check": {"question": "What is required to score the evaluation marks at the end of a 7-mark question?", "options": ["Simply repeating your earlier points in different words", "A decision, case-study context, and its business impact", "Listing as many advantages as possible", "A definition of the key term"], "answer": 1, "explain": "A strong conclusion needs three things: a clear decision, a specific detail from the case study, and the reasoning behind why that decision matters for that particular business — simply repeating earlier points scores zero."}}, {"title": "All Five Skills: K → U → APP → AN → EVAL", "html": "\n      <p>The 9-mark question tests ALL five assessment objectives. Every skill must be <strong>explicit</strong> — the examiner cannot award implied skills.</p>\n      <p><strong>Structure your answer in 4 paragraphs:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — K & U:</strong> Define the key concept and explain how it works. Keep this brief — one or two sentences is enough to secure both marks.</li>\n        <li><strong>Paragraph 2 — AN & APP:</strong> Analyse the first impact on motivation or retention using the business in the case study.</li>\n        <li><strong>Paragraph 3 — AN & APP:</strong> Analyse the second impact (the other side or another consequence), again applied to the business.</li>\n        <li><strong>Paragraph 4 — EVAL (3 points):</strong>\n          <ul>\n            <li><strong>Decision:</strong> Make a clear, overall judgement.</li>\n            <li><strong>Context:</strong> Use a specific detail from the case study to justify your position.</li>\n            <li><strong>Impact/Reasoning:</strong> Explain the long-term or significant consequence of your judgement for the business.</li>\n          </ul>\n        </li>\n      </ul>\n      <p><strong>✅ Sentence Starters — Paragraph 1 (K & U):</strong><br/>\n      \"Ethics refers to... (K). Ethical treatment of workers means that a business... (U).\"</p>\n      <p><strong>✅ Sentence Starters — Paragraphs 2 & 3 (AN & APP):</strong><br/>\n      \"This means M&S workers are likely to... (APP). As a result, M&S will benefit from... which will reduce/increase... (AN).\"</p>\n      <p><strong>✅ Sentence Starters — Paragraph 4 (EVAL):</strong><br/>\n      \"Overall, ethical treatment will have a [positive/negative] impact on M&S (DECISION), particularly because M&S employs over 50,000 people and targets high-income customers who expect good quality service (CONTEXT). This means the long-term impact on retention is likely to be greater than the short-term cost of implementing ethical practices (IMPACT).\"</p>\n      <p><strong>⚠️ Examiner Warning — M&S Question:</strong> Most candidates could apply ethical treatment to motivation but fewer could link it to retention AND analyse both impacts on the business. Many candidates also failed to score the knowledge mark by not defining ethics clearly at the start.</p>\n    ", "check": {"question": "How many separate assessment objectives must a 9-mark answer demonstrate?", "options": ["Just one — knowledge", "All five: K, U, APP, AN, EVAL", "Only Analysis and Evaluation", "Two — Application and Evaluation"], "answer": 1, "explain": "A 9-mark question tests all five assessment objectives (K, U, APP, AN, EVAL). Every skill must be explicitly shown in the answer — examiners cannot award marks for skills that are only implied."}}, {"title": "Show Every Step or Risk Losing Marks", "html": "\n      <p>Calculation questions carry 3 marks, each for a distinct step. You can earn marks even if your final answer is wrong — <strong>always show your working</strong>.</p>\n      <p><strong>Common Calculation Types:</strong></p>\n      <ul>\n        <li>Time-rate wage: Hours × Hourly Rate</li>\n        <li>Overtime: Overtime Hours × (Rate × Multiplier, e.g. 1.5 for time-and-a-half)</li>\n        <li>Bonus calculation: Bonus Pool ÷ Number of Workers</li>\n        <li>Profit share: Total Profit × % ÷ 100 ÷ Number of Workers</li>\n        <li>Percentage increase: Original Amount × (1 + %/100)</li>\n      </ul>\n      <p><strong>Example — James at McDonald''s (£7.00/hr, 16 hrs, 10% rise):</strong><br/>\n      Step 1: 10% of £7.00 = £0.70<br/>\n      Step 2: New rate = £7.00 + £0.70 = £7.70<br/>\n      Step 3: £7.70 × 16 hours = £123.20 ✅</p>\n      <p><strong>Example — Saranne''s profit share:</strong><br/>\n      Step 1: 5% of £15,000 = £750<br/>\n      Step 2: £750 ÷ 3 workers = £250 each<br/>\n      Step 3: £12,000 + £250 = £12,250 ✅</p>\n      <p><strong>⚠️ OFR (Own Figure Rule):</strong> If you make an error in step 1 but correctly complete steps 2 and 3 using your wrong figure, you can still earn the marks for those later steps. This is why showing working is essential.</p>\n    ", "check": {"question": "If you make a mistake on step 1 of a calculation but correctly complete steps 2 and 3 using your (wrong) figure, what happens under the Own Figure Rule (OFR)?", "options": ["You score 0 marks for the whole question", "You still earn marks for steps 2 and 3 despite the error", "You must restart the calculation from scratch", "Only the final answer is marked, regardless of working shown"], "answer": 1, "explain": "The Own Figure Rule means examiners credit each correct step of working even if an earlier step contained an error — which is exactly why showing all your working is essential, not optional."}}]}, "exam": {"enabled": true, "questions": [{"question": "Explain three reasons why employee retention is important for Clarks. [6 marks]", "marks": 6, "hint": "For each reason, give a business benefit of retention (1 mark) and then link it specifically to Clarks using detail from the case study (1 mark). Do NOT write about what retention is — jump straight into reasons why it matters for the business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 6 marks (AO1: 3 marks, AO2: 3 marks)</h5>\n<ul>\n  <li><strong>1 mark</strong> for each correct reason why employee retention is important for a business.</li>\n  <li><strong>1 further mark</strong> for each reason applied specifically to Clarks, using case study detail.</li>\n  <li>Application mark cannot be awarded without the knowledge mark first.</li>\n  <li>Maximum of 3 reasons, each worth up to 2 marks = 6 marks total.</li>\n</ul>\n<p><strong>Knowledge points may include:</strong></p>\n<ul>\n  <li>Recruitment & selection: Reduced need for recruitment / lower recruitment costs / less time taken to recruit / wider pool to recruit from</li>\n  <li>Training & development: Reduced need for training / lower training costs / less time taken to train</li>\n  <li>Quality of workforce: Retains skills, specialism, knowledge of the business, products and customers</li>\n  <li>Size of workforce: Avoids staff shortages / being understaffed</li>\n  <li>Employee engagement: High motivation / work harder / better work ethic / commitment / workforce loyalty</li>\n</ul>\n<p><strong>Application points may include:</strong></p>\n<ul>\n  <li>Very competitive market / lots of competitors</li>\n  <li>Specialist designers create new shoe styles</li>\n  <li>Fast-changing fashion trends require experienced staff</li>\n  <li>Designers need to ensure new styles meet customer needs profitably</li>\n  <li>Designers are central to Clarks'' success</li>\n</ul>\n<p><strong>Do NOT reward:</strong> What employee retention is / ''high morale'' / ''feel valued'' (personal benefits to workers, not business importance).</p></div>\n<div class=\"marks-section\"><h5>Examiner''s Comments</h5>\n<p>This question was not well answered. Most candidates only scored 2 marks — usually by identifying ''less time on recruitment'' and ''lower training costs''. Few gave a third reason and even fewer applied their responses to Clarks. Responses specifically referencing fast-changing fashion trends, specialist designers, or designers being central to Clarks'' success each earned 2 marks rather than 1.</p></div>"}, {"question": "What is a financial method of motivation that a restaurant manager may use?", "marks": 1, "hint": "Think about which option involves a direct payment of money to workers.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Introduce profit sharing for the chefs</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> An award scheme is a non-financial method of motivation — it involves recognition, not money.</li>\n  <li><strong>B — Correct:</strong> Profit sharing is a financial method — it involves paying workers a proportion of the business''s profits.</li>\n  <li><strong>C — Wrong:</strong> Making staff pay for breakages is a penalty/deduction, not a motivational method at all.</li>\n  <li><strong>D — Wrong:</strong> Praise is a non-financial method of motivation — it involves verbal/written recognition, not money.</li>\n</ul></div>"}, {"question": "What is a non-financial method of motivation that a manufacturer of handmade wooden toys could use?", "marks": 1, "hint": "Non-financial methods do NOT involve any payment of money or cash benefits. Which option involves recognition rather than pay?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Praising the workers who take the greatest care when painting the designs</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> A bonus is a financial method — it is an additional cash payment for meeting a target.</li>\n  <li><strong>B — Wrong:</strong> Increasing the rate of pay is a financial method — it involves paying workers more money per hour.</li>\n  <li><strong>C — Correct:</strong> Praise is a non-financial method — it involves recognising and complimenting good work with no money exchanged.</li>\n  <li><strong>D — Wrong:</strong> Private medical insurance is a fringe benefit — a financial method, as it has a monetary value to the worker.</li>\n</ul></div>"}, {"question": "Employee retention:", "marks": 1, "hint": "Retention means workers STAY at a business. Think about what happens to recruitment if you don''t need to replace staff.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — minimises time spent selecting new workers</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> Retention refers to workers staying — it does not extend working hours.</li>\n  <li><strong>B — Wrong:</strong> High retention REDUCES recruitment costs, not increases them. This is the opposite of the correct answer.</li>\n  <li><strong>C — Correct:</strong> When workers stay (high retention), the business does not need to advertise and recruit as often, saving time spent on selection.</li>\n  <li><strong>D — Wrong:</strong> Retention has nothing to do with discrimination policies in the workplace.</li>\n</ul>\n<p><strong>Examiner''s Comment:</strong> Responses were evenly split across the three wrong options — candidates must know the precise definition of retention to avoid confusion with related HR terms.</p></div>"}, {"question": "A supermarket chain is receiving an increasing number of complaints about the poor attitude of its sales assistants, especially when the stores are busy. What would help to deal with this problem?", "marks": 1, "hint": "Poor attitude from staff is usually a symptom of something deeper. What business concept directly links to how hard and willingly workers perform?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Find ways to increase employee motivation at each of its stores</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> Fewer staff would make the pressure worse when stores are busy, increasing complaints rather than reducing them.</li>\n  <li><strong>B — Correct:</strong> Poor staff attitude is a symptom of low motivation. Improving motivation directly encourages staff to provide better customer service, especially under pressure.</li>\n  <li><strong>C — Wrong:</strong> Limiting customer numbers would reduce revenue and damage the business — it doesn''t address the root cause.</li>\n  <li><strong>D — Wrong:</strong> Reducing holiday entitlement is a punitive measure and would likely worsen morale and motivation, making the problem worse.</li>\n</ul></div>"}, {"question": "A business has introduced a bonus scheme, based on production targets, to help motivate its staff. Which of the following statements would NOT be true?", "marks": 1, "hint": "Read the question carefully — it asks which statement is NOT true. A bonus is an addition to pay, not a reduction of it.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Workers who do not reach the target will have their basic pay reduced</h5>\n<ul>\n  <li><strong>A — True (not the answer):</strong> Bonuses are triggered by performance — they are a form of performance-related pay.</li>\n  <li><strong>B — True (not the answer):</strong> Paying bonuses adds to the business''s total wage costs.</li>\n  <li><strong>C — True (not the answer):</strong> If targets are unrealistically high, workers give up rather than try — the bonus demotivates instead of motivating.</li>\n  <li><strong>D — NOT True (correct answer):</strong> A bonus scheme does not reduce basic pay for those who miss targets. Basic pay remains the same — workers simply do not receive the additional bonus payment.</li>\n</ul></div>"}, {"question": "Xaio and Zhou own a building firm that employs 50 workers. Xaio and Zhou are concerned about the costs of recruitment. They are constantly having to advertise for replacement workers. Which of the following would help Xaio and Zhou deal with this problem?", "marks": 1, "hint": "The problem is that workers keep leaving. What is the business concept that means keeping workers in the business for longer?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Find ways to increase employee retention</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> Decreasing pay would make the problem worse — workers would be even more likely to leave for better-paid roles elsewhere.</li>\n  <li><strong>B — Correct:</strong> If workers stay longer (high retention), Xaio and Zhou would not need to constantly advertise for replacements — directly reducing recruitment costs.</li>\n  <li><strong>C — Wrong:</strong> Reducing fringe benefits would decrease motivation and increase turnover, making the recruitment problem worse.</li>\n  <li><strong>D — Wrong:</strong> Additional finance doesn''t address the root problem of workers leaving — it might help pay for more recruitment but doesn''t fix retention.</li>\n</ul></div>"}, {"question": "Identify two non-financial methods of motivating employees. [2 marks]", "marks": 2, "hint": "Non-financial methods do NOT involve money or cash benefits. Think about recognition, environment, and job structure.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a: 2 marks)</h5>\n<p>1 mark for each correctly identified non-financial method, up to a maximum of 2.</p>\n<p><strong>Acceptable answers include:</strong> Praise / reassurance, Award schemes (e.g. employee of the month / certificates / badges), Good or improved working environment, Teamwork, Job rotation, Job enrichment, Job enlargement, Increased responsibility, Empowerment.</p>\n<p><strong>Do NOT award financial methods:</strong> Promotion, fringe benefits (free gym membership, company car, mobile phone, free holidays, additional holiday allowance, gift cards, vouchers, coupons, subsidised food, etc.) — these all have a monetary value and are financial methods.</p></div>"}, {"question": "Evaluate whether or not Waitrose should continue to offer profit sharing to its employees. [7 marks]", "marks": 7, "hint": "Argue both sides — reasons to continue AND reasons to stop (or switch to higher pay). Use specific details from the Waitrose case study. End with a clear justified conclusion that references something specific about Waitrose.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks (AO2: 2, AO3a: 2, AO3b: 3)</h5>\n<ul>\n  <li><strong>Application (up to 2 marks):</strong> Uses context from the Waitrose case study (e.g. 50,000 employees, competitive supermarket industry, high-income customers, specialises in good quality food, another supermarket switched to higher pay).</li>\n  <li><strong>Analysis (up to 2 marks):</strong> Develops the business-facing impact of profit sharing — e.g. impact on productivity, recruitment, customer service, quality, operational costs, cash flow, profit.</li>\n  <li><strong>Evaluation (up to 3 marks):</strong>\n    <ul>\n      <li>1 mark: A basic judgement (continue or stop profit sharing).</li>\n      <li>2 marks: A justified judgement with some reasoning.</li>\n      <li>3 marks: A fully justified, contextual judgement referencing Waitrose specifically.</li>\n    </ul>\n  </li>\n</ul>\n<p><strong>Evaluation may justify:</strong> continuing profit sharing / stopping it / switching to higher rates of pay / switching to another motivational method / stopping specific motivational measures altogether.</p>\n<p><strong>For full evaluation marks:</strong> The conclusion must be contextual — it must reference something specific about Waitrose, not just make a general statement.</p></div>\n<div class=\"marks-section\"><h5>Examiner''s Exemplar Response</h5>\n<p>Profit sharing is likely to motivate only some of Waitrose''s 50,000 employees (APP). Those that are not motivated by profit sharing may work less hard, reducing customer service levels at Waitrose (AN).</p>\n<p>However, a profit sharing scheme means that all staff are rewarded equally. This could improve staff morale, increasing employee retention and reducing the need for regular training — all of which are important because Waitrose targets customers with higher levels of income who demand a quality service (APP + AN).</p>\n<p>Overall, profit sharing should not be offered in the future (EVAL). Most of the supermarket''s 50,000 employees would likely prefer the security of higher wages each month rather than a profit share that is not guaranteed and only paid annually. Paying higher wages is more likely to sustain productivity, customer service quality, and employee retention in the long run (EVAL + EVAL).</p></div>"}, {"question": "Explain one reason why employee retention is important for Superdry. [2 marks]", "marks": 2, "hint": "Give one business reason why keeping workers matters (1 mark), then link it to a specific detail about Superdry from the case study (1 mark). Do NOT just define retention.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b: 1, AO2: 1)</h5>\n<ul>\n  <li><strong>1 mark:</strong> Understanding of a reason why employee retention is important for a business (e.g. lower recruitment/training costs, maintain experienced workforce, positive impact on reputation).</li>\n  <li><strong>1 further mark:</strong> Applied to Superdry using case study detail (e.g. 4,800 employees, commitment to high quality, regular store re-fits requiring experienced staff, competition from retailers of all sizes, clothing brand).</li>\n</ul>\n<p><strong>Application mark cannot be awarded without the understanding mark first.</strong></p>\n<p><strong>Accept inverse answers</strong> — i.e. the issues caused by poor retention (e.g. high recruitment costs would be very expensive with 4,800 employees).</p>\n<p><strong>Do NOT award</strong> answers relating to job satisfaction or motivation unless explicitly linked to business importance. Do not award what retention is.</p></div>\n<div class=\"marks-section\"><h5>Examiner''s Exemplar Responses</h5>\n<p><strong>Response 1:</strong> Superdry''s training costs will be low (U), which means it can spend this money on promoting its brand to help compete in such a competitive clothing market (APP). ✅</p>\n<p><strong>Response 2:</strong> Retaining experienced staff helps Superdry cope with its regular store re-fit programme (APP), because workers who have been with the company longer will be more experienced and better able to manage the changes (U). ✅</p></div>"}, {"question": "A jet ski retailer with limited funds has a problem with the motivation levels of its 25 sales assistants. Which one of the following methods should the jet ski retailer use to improve the sales assistants'' motivation levels?", "marks": 1, "hint": "The key constraint is LIMITED FUNDS. Which option improves motivation without spending significant money?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Set up a ''seller of the month'' award scheme</h5>\n<ul>\n  <li><strong>A — Wrong:</strong> A £3 per hour pay rise for 25 staff would be expensive — with limited funds, this may not be affordable.</li>\n  <li><strong>B — Wrong:</strong> A £500 bonus per jet ski sold could be very costly. Jet skis are expensive items — if sales are high, this could massively increase the wage bill.</li>\n  <li><strong>C — Wrong:</strong> Reducing fringe benefits would decrease motivation and morale — the opposite of what is needed.</li>\n  <li><strong>D — Correct:</strong> An award scheme is a non-financial method that costs very little but provides recognition and boosts morale — the ideal solution for a business with limited funds.</li>\n</ul></div>"}, {"question": "Calculate how much each employee should receive in total during the first year. Show your workings. [3 marks]", "marks": 3, "hint": "Three separate steps: (1) Calculate 5% of £15,000. (2) Divide by 3 workers. (3) Add the annual salary of £12,000.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO2: 3)</h5>\n<ul>\n  <li><strong>1 mark:</strong> Correct calculation of 5% of £15,000 = <strong>£750</strong></li>\n  <li><strong>1 mark:</strong> Correct division of profit share among 3 employees: £750 ÷ 3 = <strong>£250 each</strong></li>\n  <li><strong>1 mark:</strong> Correct total: £12,000 + £250 = <strong>£12,250</strong></li>\n  <li>3 marks awarded for correct final answer (£12,250) with or without working shown.</li>\n  <li>OFR applies — if a calculation error is made in step 1 but steps 2 and 3 follow correctly from that figure, subsequent marks can still be awarded.</li>\n</ul></div>"}, {"question": "Analyse one way Saranne could use praise to increase motivation. [3 marks]", "marks": 3, "hint": "Follow the U → APP → AN structure. What is praise? How would Saranne use it in her bookshop? What impact does it have on the business?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1, AO2: 1, AO3a: 1)</h5>\n<ul>\n  <li><strong>1 mark (U):</strong> Understanding of how praise is used to motivate staff (e.g. ''worker of the month'', letter of commendation, verbal recognition of effort in front of others).</li>\n  <li><strong>1 mark (APP):</strong> Applied to Saranne''s business (e.g. retail book store, only 3 employees, small new business, level of competition).</li>\n  <li><strong>1 mark (AN):</strong> Analysis of the business impact on Saranne (e.g. improved customer service, higher productivity, better staff morale, improved retention in a small team).</li>\n</ul></div>\n<div class=\"marks-section\"><h5>Examiner''s Exemplar Response</h5>\n<p>Saranne could introduce a ''worker of the month'' award for her best employee (AO1b). This could be given to a worker who has designed an eye-catching window display for the book store (AO2). This would motivate other workers to create better displays in the future, helping to attract more customers into the shop (AO3a).</p></div>"}, {"question": "Analyse one way Saranne could use bonuses to increase motivation. [3 marks]", "marks": 3, "hint": "Follow the U → APP → AN structure. What is a bonus? How would it work in Saranne''s bookshop? What is the business impact?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1, AO2: 1, AO3a: 1)</h5>\n<ul>\n  <li><strong>1 mark (U):</strong> Understanding of how bonuses motivate staff (e.g. financial payment for reaching a target, time off for good work, team-based bonus, staff nights out).</li>\n  <li><strong>1 mark (APP):</strong> Applied to Saranne''s business (e.g. small retail bookshop, 3 employees, competing with The Works, new entrepreneur).</li>\n  <li><strong>1 mark (AN):</strong> Analysis of the business impact (e.g. harder work to meet targets, more books sold, higher revenue, better customer service).</li>\n</ul></div>\n<div class=\"marks-section\"><h5>Examiner''s Exemplar Response</h5>\n<p>Bonuses involve offering an employee a monetary reward for doing something well or meeting targets (AO1b). For example, an employee may receive a bonus if they sell over 50 books per week (AO2). This results in the employee working harder to sell more books in order to receive more pay (AO3a).</p></div>"}, {"question": "Recommend whether praise or bonuses would be the most effective method of motivating Saranne''s employees. Give reasons for your answer. [3 marks]", "marks": 3, "hint": "Make a clear recommendation, then compare BOTH methods. Use details about Saranne''s situation (small business, 3 employees, limited funds as a new start-up). Your justification should explain why your choice is BETTER THAN the other.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b: 3)</h5>\n<ul>\n  <li><strong>1 mark:</strong> A judgement with limited justification showing some appraisal of the relevant information.</li>\n  <li><strong>2 marks:</strong> A judgement with good justification showing appraisal of relevant information and issues.</li>\n  <li><strong>3 marks:</strong> A judgement with strong justification showing detailed appraisal of relevant information and issues, comparing both methods.</li>\n</ul>\n<p>Either praise or bonuses can be recommended — the quality of justification determines the marks, not the choice itself.</p></div>\n<div class=\"marks-section\"><h5>Examiner''s Exemplar Response (3 marks)</h5>\n<p>Some employees are not motivated by financial rewards and value non-financial recognition more, such as praise (1). Individualised motivational efforts are most effective as they can be tailored to each employee''s efforts and offered instantly throughout the year (1). I therefore feel that praise is the most effective way to motivate Saranne''s staff, as it is the most flexible method and can be offered immediately by Saranne to recognise good work — particularly valuable for a brand new small business with limited cash flow that cannot risk large bonus payments (1).</p></div>"}, {"question": "Identify two reasons why employee motivation is important to Redrow Homes. [2 marks]", "marks": 2, "hint": "Your answers MUST be specific to Redrow Homes — mention houses, construction, bricklaying, plumbing, landscape designers, etc. Vague answers like ''workers feel happier'' score zero. Think about what motivated construction workers actually produce for the business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2: 2)</h5>\n<ul>\n  <li><strong>1 mark</strong> for each contextual reason — must reference Redrow Homes specifically.</li>\n  <li>Acceptable contextual references: houses, homes, build/builders, construct, apprentices, carpentry/carpenter, plumbing/plumber, bricklaying/bricklayer, landscape design(er), electrical work/electrician.</li>\n  <li>Do NOT accept vague references: ''site'', ''trades'', ''workers'', ''employees'', ''sales staff'', ''administrators'' — these are too general.</li>\n</ul>\n<p><strong>Exemplar responses:</strong></p>\n<ul>\n  <li>Improved quality of the houses built. ✅</li>\n  <li>Homes built more quickly by motivated carpenters and bricklayers. ✅</li>\n  <li>High retention of landscape designers reduces recruitment costs. ✅</li>\n  <li>Low absenteeism among construction workers ensures deadlines are met. ✅</li>\n  <li>\"Workers feel happier.\" ❌ (personal benefit, not business importance)</li>\n</ul>\n<p><strong>Examiner''s Comment:</strong> Many candidates wrote answers that were too vague or from the wrong perspective. The best answers specifically mentioned quality of the build, homes being built more quickly, or high retention of construction workers.</p></div>"}, {"question": "State one example of a financial method to motivate employees. [1 mark]", "marks": 1, "hint": "Financial methods involve paying money or giving cash-equivalent benefits. Name one specific example.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a: 1)</h5>\n<p>1 mark for any correctly identified financial method of motivation.</p>\n<p><strong>Acceptable answers:</strong> Pay rise / increased rate of pay, Bonus, Profit sharing, Fringe benefits (e.g. car allowance, childcare vouchers, private medical insurance, subsidised canteen meals), Performance-related pay.</p>\n<p><strong>Do NOT award:</strong> ''Gift vouchers'' alone (without context of a fringe benefit).</p>\n<p><strong>Examiner''s Comment:</strong> The three most common correct answers were ''a pay rise'', ''a bonus'', and ''profit-sharing''.</p></div>"}, {"question": "State one example of a non-financial method to motivate employees. [1 mark]", "marks": 1, "hint": "Non-financial methods do NOT involve money. Think about recognition, the workplace, or job structure.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a: 1)</h5>\n<p>1 mark for any correctly identified non-financial method of motivation.</p>\n<p><strong>Acceptable answers:</strong> Praise, Promotion, Improved working environment (e.g. redecoration, new furniture), Award schemes (e.g. employee of the week), Extra holidays, Job enrichment / rotation / enlargement, Consulting with workers, Employee participation schemes, Certificates, Gifts / gift vouchers, Team bonding sessions.</p>\n<p><strong>Examiner''s Comment:</strong> The three most common correct answers were ''praise'', ''award schemes'', and ''extra holidays''.</p></div>"}, {"question": "State one reason why a business may need to recruit new employees. [1 mark]", "marks": 1, "hint": "Think about why a vacancy might arise — what causes a business to need new workers?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a: 1)</h5>\n<p>1 mark for any correctly identified reason for recruiting new employees.</p>\n<p><strong>Acceptable answers:</strong> Existing staff leave, To ensure sufficient staff are available, Maternity cover, Cover for long-term absences, To fill a skill shortage or gap, To cope with increased workload / business expansion, Higher demand / more customers, To gain new or additional skills / perspectives / ideas.</p>\n<p><strong>Examiner''s Comment:</strong> A wide variety of answers were accepted — from business expansion to existing employees leaving. The vast majority of candidates gained this mark.</p></div>"}, {"question": "Calculate what James'' weekly pay will be once he is fully trained. Show your workings. [3 marks]", "marks": 3, "hint": "Three steps: (1) Find 10% of £7.00. (2) Add to £7.00 to get the new hourly rate. (3) Multiply by 16 hours per week.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO2: 3)</h5>\n<ul>\n  <li><strong>1 mark:</strong> Correct calculation of 10% increase in hourly pay: 10% × £7.00 = <strong>£0.70</strong></li>\n  <li><strong>1 mark:</strong> Correct new hourly rate: £7.00 + £0.70 = <strong>£7.70</strong></li>\n  <li><strong>1 mark:</strong> Correct weekly pay: £7.70 × 16 = <strong>£123.20</strong></li>\n  <li>3 marks for correct final answer (£123.20) with or without working.</li>\n  <li>OFR applies.</li>\n</ul></div>"}, {"question": "Which one of the following is NOT a benefit to a business of improving employee retention?", "marks": 1, "hint": "Think carefully — retention means keeping workers longer. Three options are genuine benefits. One is completely unrelated to whether staff stay or leave.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Lower selling price</h5>\n<ul>\n  <li><strong>A — Wrong (IS a benefit):</strong> Keeping existing staff avoids expensive recruitment and training costs — a direct cost saving.</li>\n  <li><strong>B — Wrong (IS a benefit):</strong> If workers stay, there is less need to recruit replacements — saving management time on selection.</li>\n  <li><strong>C — Correct (NOT a benefit):</strong> The selling price of products is a marketing/pricing decision — it is completely unrelated to employee retention.</li>\n  <li><strong>D — Wrong (IS a benefit):</strong> Retained workers already know the job and don''t need retraining — reducing training costs.</li>\n</ul></div>"}, {"question": "* Evaluate how the ethical treatment of workers may have an impact on the motivation and retention of M&S''s staff. [9 marks]", "marks": 9, "hint": "Start with a definition of ethics and an example (K + U). Then analyse how ethical treatment affects MOTIVATION (APP + AN). Then analyse how it affects RETENTION (APP + AN). End with a balanced, contextual judgement about whether the impact is mostly positive or limited by costs.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 9 marks</h5>\n<ul>\n  <li><strong>Knowledge (AO1a): 1 mark</strong> — Identifies what ethics means (moral principles / what is right and wrong).</li>\n  <li><strong>Understanding (AO1b): 1 mark</strong> — Explains ethical treatment of workers (e.g. paying a fair wage, good working conditions beyond legal minimum, treating employees with dignity, allowing time off beyond legal requirements).</li>\n  <li><strong>Application (AO2): up to 2 marks</strong> — Uses case study context (e.g. Plan A / ''Nourishing our wellbeing'' / 50,000+ employees / 1,025 UK stores / food factories / Montana Bakery / high quality own-brand products).</li>\n  <li><strong>Analysis (AO3a): up to 2 marks</strong> — Develops the business-facing impact on M&S (e.g. higher productivity, lower recruitment costs, lower training costs, increased sales, improved reputation, impact on costs/profit).</li>\n  <li><strong>Evaluation (AO3b): up to 3 marks</strong>\n    <ul>\n      <li>1 mark: A basic judgement about the impact of ethical treatment.</li>\n      <li>2 marks: A justified judgement with some reasoning and context.</li>\n      <li>3 marks: A fully justified, contextual judgement — compares the relative impact on motivation vs retention, or weighs benefits against costs, using M&S context.</li>\n    </ul>\n  </li>\n</ul>\n<p><strong>Note:</strong> This is a synoptic question — application marks are given for applying knowledge of ethical treatment (Component 2 content) to motivation and retention (Component 1 content). ALL five skill areas must be demonstrated for full marks.</p></div>\n<div class=\"marks-section\"><h5>Examiner''s Comments</h5>\n<p>Most candidates could apply ethical treatment to motivation; fewer could also link it to retention. Many failed to score the knowledge mark by not defining ethics. The best answers started with a brief definition and example, then developed clear application and analysis for BOTH motivation AND retention, before writing a contextual conclusion comparing the relative importance of both impacts.</p>\n<p>The 9-mark question ALWAYS requires all five skill areas (K, U, APP, AN, EVAL) to be explicitly demonstrated — they cannot be implied.</p></div>\n<div class=\"marks-section\"><h5>Examiner''s Exemplar Response</h5>\n<p>Ethics is about being moral and fair (K), which may include paying workers a fair wage (U). If M&S is being ethical then workers are likely to feel well looked after, making them happier and more motivated (APP). It may also lead to workers not wanting to leave M&S to work somewhere else (APP).</p>\n<p>By having more motivated workers, M&S won''t need to advertise jobs as often, which decreases their recruitment costs (AN). M&S will also find that workers are happier, and this could lead to more sales in its 1,025 stores (AN).</p>\n<p>Overall, ethical treatment can affect both motivation and retention to a great extent (EVAL), but the impact on retention costs is likely to be larger (EVAL) than the effect of motivation on sales, because M&S is in a competitive retail market and keeping experienced staff in its food factories and stores is critical to maintaining quality and customer satisfaction (EVAL).</p></div>"}, {"question": "Explain why employee retention is important for United Utilities. [2 marks]", "marks": 2, "hint": "Give one business reason why keeping workers matters (U), then link it to a specific detail about United Utilities from the case study (APP).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b: 1, AO2: 1)</h5>\n<p><strong>Understanding (1 mark):</strong> One reason why employee retention is important for any business:</p>\n<ul>\n  <li>Lower costs for recruitment</li>\n  <li>Better return on spending on training</li>\n  <li>Experienced workers in the business</li>\n</ul>\n<p><strong>Application (1 mark):</strong> Links the reason to United Utilities specifically:</p>\n<ul>\n  <li>United Utilities employs 5,000 workers — high staff turnover would be very expensive to manage at this scale</li>\n  <li>It costs a lot to train 40 apprentices — retention ensures a return on this investment</li>\n  <li>Experienced workers will know how to complete jobs on time / meet deadlines to avoid council penalties</li>\n</ul>\n<p><strong>Note:</strong> Application mark cannot be awarded without the Understanding mark first.</p></div>"}, {"question": "Analyse one advantage to United Utilities of paying bonuses to the teams who repair the network of pipes. [3 marks]", "marks": 3, "hint": "Follow U → APP → AN. What does a bonus do? How does it specifically help the maintenance teams at United Utilities? What is the business impact (think: deadlines, penalties, costs, reputation)?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1, AO2: 1, AO3a: 1)</h5>\n<p><strong>Understanding (1 mark):</strong> One benefit of a bonus scheme:</p>\n<ul>\n  <li>A bonus scheme will motivate workers to perform well / meet targets / work to deadlines, as doing so earns them the bonus.</li>\n</ul>\n<p><strong>Application (1 mark):</strong> Links to United Utilities:</p>\n<ul>\n  <li>United Utilities will not have to pay penalties to local councils.</li>\n  <li>United Utilities will be able to complete road repair jobs by the contractual deadlines.</li>\n</ul>\n<p><strong>Analysis (1 mark):</strong> The business-facing impact:</p>\n<ul>\n  <li>By meeting deadlines, United Utilities gains a reputation for good service — increasing future sales / contract wins.</li>\n  <li>Avoiding financial penalties protects United Utilities'' profit margins.</li>\n</ul>\n<p><strong>Note:</strong> Application mark cannot be awarded without Understanding. Analysis mark cannot be awarded without Application.</p></div>"}, {"question": "Analyse the benefit of Walkers Ltd increasing the wage of production workers. [3 marks]", "marks": 3, "hint": "Follow U → APP → AN. What does increasing wages do for workers? How does it apply to Walkers Ltd''s production workers specifically? What is the business impact?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1, AO2: 1, AO3a: 1)</h5>\n<p><strong>Understanding (1 mark):</strong> A benefit of increasing wages — e.g. workers are motivated because they earn more, enabling them to afford a better standard of living / workers feel valued / competitive pay attracts and retains staff.</p>\n<p><strong>Application (1 mark):</strong> Links to Walkers Ltd — e.g. production workers who feel unvalued will feel recognised through a pay rise / addresses the findings of the staff survey.</p>\n<p><strong>Analysis (1 mark):</strong> Business impact — e.g. higher productivity on the production line / improved quality of products / lower absenteeism / better retention of workers / reduced need for recruitment.</p></div>"}, {"question": "Analyse the benefit of Walkers Ltd using an award scheme. [3 marks]", "marks": 3, "hint": "Follow U → APP → AN. What does an award scheme do? How does it address the specific problem at Walkers Ltd? What business benefit results?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1, AO2: 1, AO3a: 1)</h5>\n<p><strong>Understanding (1 mark):</strong> A benefit of an award scheme — e.g. recognises and rewards good work / makes workers feel valued / provides public acknowledgement of effort.</p>\n<p><strong>Application (1 mark):</strong> Links to Walkers Ltd — e.g. workers in the staff survey said they feel unvalued, so an award scheme directly addresses this by recognising achievement / non-financial recognition suits production workers who want to feel appreciated.</p>\n<p><strong>Analysis (1 mark):</strong> Business impact — e.g. higher morale leads to improved productivity / lower absenteeism / better quality of production / improved retention reducing the cost of replacing workers.</p></div>"}, {"question": "Recommend whether Walkers Ltd should use an increase in wages or award scheme to motivate production workers. [3 marks]", "marks": 3, "hint": "Make a clear recommendation (1 mark). Then explain why your choice is better THAN the other, using details from the Walkers Ltd case study (up to 2 marks). Your justification must compare BOTH methods.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b: 3)</h5>\n<ul>\n  <li><strong>Judgement (1 mark):</strong> Clear recommendation — wages OR award scheme.</li>\n  <li><strong>Contextual justification (2 marks):</strong> Comparative reason using case study detail — must explain why the chosen method is BETTER THAN the other for Walkers Ltd.</li>\n  <li><strong>OR non-contextual justification (1 mark):</strong> Comparative reason without specific case study detail.</li>\n</ul>\n<p><strong>Note:</strong> Justification MUST cover BOTH methods to earn the justification marks. Either choice can be recommended — the quality of reasoning determines the marks.</p></div>"}]}}'::jsonb),
('business', '3-6-training-and-development', '3.6 Training and Development', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>These are the essential terms you must know for the exam. Learn the distinction between each one carefully — examiners regularly test whether students can tell them apart.</p>\n  <ul>\n    <li><strong>Training:</strong> Short-term learning focused on improving a worker''s ability to do a specific job or task.</li>\n    <li><strong>Development:</strong> Long-term learning focused on growing a worker''s overall potential for future roles.</li>\n    <li><strong>On-the-job training:</strong> Training that takes place at the workplace while the employee is doing their job.</li>\n    <li><strong>Off-the-job training:</strong> Training that takes place away from the normal job, either on-site or at an external venue.</li>\n    <li><strong>Induction training:</strong> Training to introduce a new employee to the business, workplace, colleagues, and job role.</li>\n    <li><strong>Apprenticeship:</strong> A long-term development programme (typically 2–4 years) combining on-the-job and off-the-job learning, leading to a vocational qualification.</li>\n    <li><strong>Professional development:</strong> Long-term development of a worker through vocational or academic qualifications to realise their future potential.</li>\n    <li><strong>Vocational qualification:</strong> A job-specific qualification gained through a mix of practical and classroom learning (e.g. NVQ, Cambridge Technical).</li>\n    <li><strong>Academic qualification:</strong> A more general, theory-based qualification (e.g. GCSEs, A Levels, degrees).</li>\n    <li><strong>Productivity:</strong> Output per worker — a measure of how efficiently employees produce goods or services.</li>\n    <li><strong>Skills shortage:</strong> A situation where businesses cannot recruit workers with the skills they need.</li>\n    <li><strong>Retention:</strong> Keeping workers employed rather than them leaving to work elsewhere.</li>\n  </ul>", "check": {"question": "What is the key difference between training and development?", "options": ["Training is job-specific and short-term; development is long-term and broader", "They are exactly the same thing", "Training only happens off-the-job; development only happens on-the-job", "Development is for new employees only; training is for experienced staff only"], "answer": 0, "explain": "Training focuses on improving performance in the current job, in the short term. Development is broader and longer-term, focused on growing a worker''s overall future potential."}}, {"title": "Training vs Development — What''s the Difference?", "html": "<p>Students often mix these up. The distinction is subtle but important — examiners test it directly.</p>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">📚 Training</div>\n      <div class=\"pro-item\"><strong>Short-term</strong> — focused on improving performance in the current job now.</div>\n      <div class=\"pro-item\"><strong>Job-specific</strong> — teaches knowledge and skills needed to do a particular task.</div>\n      <div class=\"pro-item\"><strong>Practical focus</strong> — learning by doing, often hands-on.</div>\n      <div class=\"pro-item\"><strong>Example:</strong> A Starbucks barista learning to make different coffees from an experienced colleague.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">🎓 Development</div>\n      <div class=\"con-item\"><strong>Long-term</strong> — focused on improving the overall potential of the worker for future roles.</div>\n      <div class=\"con-item\"><strong>Person-centred</strong> — about growing the employee, not just the current job.</div>\n      <div class=\"con-item\"><strong>Theoretical + practical</strong> — includes academic knowledge as well as skills.</div>\n      <div class=\"con-item\"><strong>Example:</strong> Beaverbrooks jewellers offering a management development programme including home study, coaching, and promotion pathways.</div>\n    </div>\n  </div>\n  <p style=\"margin-top:12px\"><strong>Key rule:</strong> Both training and development can involve on- and off-the-job activities — it''s the <em>timeframe and purpose</em> that differs.</p>", "check": {"question": "A Starbucks barista learns to make different coffees from an experienced colleague. Is this training or development?", "options": ["Training — it''s short-term and job-specific", "Development — it''s about long-term growth", "Neither — it doesn''t count as either", "Both equally, with no real distinction"], "answer": 0, "explain": "This is training: it''s focused on the current job, is short-term, and teaches a specific practical skill needed right now — not the worker''s long-term potential."}}, {"title": "Why Do Businesses Train Their Workers?", "html": "<p>Businesses invest in training for a wide range of reasons. In the exam, always link the reason to the business impact.</p>\n  <ul>\n    <li><strong>Improve productivity:</strong> Better-trained workers produce more output per hour, reducing unit costs and potentially increasing profit.</li>\n    <li><strong>Improve customer service:</strong> Well-trained staff give customers better advice and experiences, boosting sales and reputation.</li>\n    <li><strong>Solve skill shortages:</strong> If specialist workers can''t be recruited externally, training existing staff fills the gap.</li>\n    <li><strong>Improve motivation and retention:</strong> Workers feel valued when a business invests in them, making them less likely to leave and reducing costly recruitment cycles.</li>\n    <li><strong>Support business development:</strong> Training lets the business expand into new products or services.</li>\n    <li><strong>Induction of new workers:</strong> New employees need to understand the workplace, procedures, and culture before they can work effectively.</li>\n    <li><strong>Health and safety:</strong> Reduces accidents, legal claims, and bad publicity.</li>\n    <li><strong>New technology/products:</strong> Workers need updating when the business introduces new machinery, software, or product lines.</li>\n    <li><strong>Retraining:</strong> When technology replaces a job role, employees may be retrained to do a different role instead of being made redundant.</li>\n    <li><strong>Flexibility:</strong> Multiskilled workers can cover different roles, making the business more adaptable.</li>\n  </ul>", "check": {"question": "Why might a business retrain a worker instead of making them redundant when new technology is introduced?", "options": ["It is required by law in all cases", "It keeps an experienced worker in the business by moving them into a new role", "Retraining is always cheaper than hiring new staff regardless of circumstances", "It has no real benefit to the business"], "answer": 1, "explain": "When technology replaces a job role, retraining lets a business keep an experienced, loyal worker in a new position rather than losing them through redundancy — preserving knowledge and avoiding recruitment costs."}}, {"title": "On-the-Job Training", "html": "<p>On-the-job training takes place at the workplace while the employee is working. A common example is <strong>shadowing</strong>, where a new worker follows and learns from an experienced colleague.</p>\n  <div class=\"case-study-box\">\n    <h4>Case Study: Starbucks</h4>\n    <p>New baristas at Starbucks receive one-to-one on-the-job training. An experienced barista works alongside the new employee, showing them how to make the different coffees — from flat whites to Americanos. The trainee practises while serving real customers.</p>\n  </div>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\"><strong>Individual training:</strong> Tailored to meet that specific worker''s needs.</div>\n      <div class=\"pro-item\"><strong>Cheaper:</strong> No travel, accommodation, or external course fees.</div>\n      <div class=\"pro-item\"><strong>Productive while training:</strong> The trainee produces goods/services during training, so the firm earns money.</div>\n      <div class=\"pro-item\"><strong>Business-specific:</strong> Trained to do the job the way the firm wants it done.</div>\n      <div class=\"pro-item\"><strong>Retention benefit:</strong> Skills may be specific to that firm, making it harder for the worker to leave — the business gets a return on its investment.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\"><strong>Trainer distracted:</strong> The trainer must leave their own work to help the trainee, so production may fall.</div>\n      <div class=\"con-item\"><strong>Quality risk:</strong> Work produced by a trainee may be poor, wasting resources or harming the firm''s reputation.</div>\n      <div class=\"con-item\"><strong>Trainer quality:</strong> If the trainer has poor communication skills or bad habits, the trainee learns them too.</div>\n      <div class=\"con-item\"><strong>No qualification:</strong> Workers typically don''t gain a recognised qualification from on-the-job training.</div>\n      <div class=\"con-item\"><strong>Limits portability:</strong> Firm-specific skills make it harder for the worker to find employment elsewhere if they lose their job.</div>\n      <div class=\"con-item\"><strong>Not suitable for groups:</strong> More effective one-on-one; difficult to scale.</div>\n    </div>\n  </div>", "check": {"question": "Why is on-the-job training often cheaper than off-the-job training?", "options": ["It avoids travel, accommodation, and course fees", "On-the-job training is always shorter in duration", "On-the-job trainers do not need to be paid", "It avoids the need for any equipment at all"], "answer": 0, "explain": "On-the-job training avoids external course fees, travel, and accommodation costs. The trainee can also produce goods or services while learning, meaning the business earns money during the training period — unlike off-the-job training."}}, {"title": "Off-the-Job Training", "html": "<p>Off-the-job training takes place <strong>away from the employee''s normal working duties</strong>. It may still be on company premises, but the worker is not doing their usual job. <br> <strong> Activities include:</strong></p>\n  <ul>\n  <li>\n    <p>\n      <strong>Lectures: </strong>\n      These are good for telling people about things and for giving information.\n      They are not good for improving skills.\n    </p>\n  </li>\n\n  <li>\n    <p>\n      <strong>Demonstrations: </strong>\n      The trainee watches someone show them how to do a job. These are good\n      because you learn from an expert. It is often necessary to practise the\n      work after the demonstration in order to develop the skills.\n    </p>\n  </li>\n\n  <li>\n    <p>\n      <strong>Role play or simulation: </strong>\n      The worker experiences a situation as if it were a real work situation.\n      The trainee practises the skills or practises how they would deal with the\n      situation.\n    </p>\n  </li>\n\n  <li>\n    <p>\n      <strong>Team-building: </strong>\n      A group performs tasks together in order to develop. It helps people learn\n      how to work well in teams and to appreciate the different qualities that\n      other people have. The tasks may or may not be connected to work. Non-work\n      connected activities can include outdoor pursuits.\n    </p>\n  </li>\n\n  <li>\n    <p>\n      <strong>Reading and reflecting on online materials: </strong>\n      The worker may have access to online training materials. Usually there are\n      tasks or exercises that must be completed to develop understanding of the\n      materials.\n    </p>\n  </li>\n</ul>\n        <div class=\"case-study-box\">\n    <h4>Case Study: Jet2.com</h4>\n    <p>Jet2.com trains its cabin crew entirely off-the-job at a dedicated training centre in Bradford. The centre has classrooms and full flight simulators. Trainees must earn their Cabin Crew Attestation — an industry-regulated qualification — before they are allowed to work on a real flight. Safety training on a live aircraft with passengers would be impossible and dangerous, making off-the-job simulation essential.</p>\n  </div>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Advantages</div>\n      <div class=\"pro-item\"><strong>Expert trainers:</strong> Delivered by specialists who may introduce new ideas and best practice.</div>\n      <div class=\"pro-item\"><strong>Specialist equipment:</strong> Trainees can use purpose-built training equipment (e.g. flight simulators).</div>\n      <div class=\"pro-item\"><strong>Safe environment:</strong> Mistakes are made in training, not in the real workplace — critical for safety-critical roles.</div>\n      <div class=\"pro-item\"><strong>Focused learning:</strong> Workers are removed from operational distractions and can concentrate fully.</div>\n      <div class=\"pro-item\"><strong>Workers feel valued:</strong> Sending staff on courses signals the business is investing in them, boosting morale.</div>\n      <div class=\"pro-item\"><strong>Industry qualifications:</strong> Can lead to recognised, portable qualifications.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✗ Disadvantages</div>\n      <div class=\"con-item\"><strong>Expensive:</strong> Course fees, travel, and accommodation add up significantly.</div>\n      <div class=\"con-item\"><strong>Lost output:</strong> The worker is not producing goods or services while training.</div>\n      <div class=\"con-item\"><strong>Retention risk:</strong> Once qualified, workers may use their new skills to get a better-paid job elsewhere.</div>\n      <div class=\"con-item\"><strong>Not always business-specific:</strong> External trainers may not teach things exactly the way the business wants.</div>\n    </div>\n  </div>", "check": {"question": "Why does Jet2.com train its cabin crew entirely off-the-job using flight simulators?", "options": ["It is cheaper than on-the-job training", "A real flight is too dangerous for safety training", "Off-the-job training is required by law for all jobs", "Cabin crew prefer not to train at the airport"], "answer": 1, "explain": "Off-the-job training is essential here because mistakes can be made safely in a simulator rather than on a real flight with passengers — exactly the kind of safety-critical situation where off-the-job training is the right choice."}}, {"title": "Induction Training", "html": "<p>Induction training is for <strong>new employees only</strong>. Its purpose is NOT to teach job skills — it is to introduce the worker to the business, the workplace, and their colleagues so they can settle in quickly and work safely.</p>\n  <p><strong>⚠️ Common mistake:</strong> Many students describe induction as \"teaching new skills.\" This is wrong. Induction is about settling in, not skill-building. Examiners flagged this as a very common error.</p>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Benefits to the Worker</div>\n      <div class=\"pro-item\">Gets to know colleagues and feels welcome.</div>\n      <div class=\"pro-item\">Learns what is expected of them and the culture of the business.</div>\n      <div class=\"pro-item\">Finds out the layout of the workplace (toilets, canteen, emergency exits).</div>\n      <div class=\"pro-item\">Learns health and safety procedures, helping them work safely.</div>\n      <div class=\"pro-item\">May learn job-specific skills to begin their role.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✓ Benefits to the Business</div>\n      <div class=\"con-item\">Worker becomes productive more quickly — less time wasted settling in.</div>\n      <div class=\"con-item\">Reduced risk of accidents → fewer compensation claims and less bad publicity.</div>\n      <div class=\"con-item\">Worker feels valued → more likely to work hard and stay with the business.</div>\n      <div class=\"con-item\">Improved communication → worker understands the organisational structure and who to report to.</div>\n    </div>\n  </div>\n  <div class=\"case-study-box\">\n    <h4>Case Study: B&Q</h4>\n    <p>New B&Q employees are sent to the \"B&Q University\" (a dedicated training centre). They learn about the company''s history, aims, health and safety rules, pay structure, and promotion opportunities. This is a formal, off-the-job induction, though smaller businesses may conduct theirs on-site with a tour and introductions.</p>\n  </div>\n\n  <div class=\"case-study-box\">\n    <h4>Case Study: Christies Care</h4>\n    <p>All new employees complete a two-week residential\ntraining course. Skills taught include moving and handling patients, continence care,\nemergency first aid, infection control. Employees gain a care certificate before\nworking in a care home. </p>\n  </div>\n  \n  <p><strong>Cost reminder:</strong> Induction has a cost — wages are paid while the worker is not yet producing output, and someone must provide the training.</p>", "check": {"question": "What is the main PURPOSE of induction training?", "options": ["To teach the new worker advanced job-specific skills", "To help the new worker settle into the business quickly", "To replace the need for any other type of training", "To assess whether the worker should be promoted"], "answer": 1, "explain": "Induction is about settling a new worker in — introducing them to the business, the workplace layout, colleagues, and health & safety procedures. It is NOT primarily about teaching job skills, which is a very common student error."}}, {"title": "Staff Development — Apprenticeships", "html": "<p>An <strong>apprenticeship</strong> is a long-term development programme (typically 2–4 years) that combines on-the-job work experience with off-the-job study, leading to a vocational qualification. Apprentices are already employed and paid while they learn.</p>\n  <div class=\"case-study-box\">\n    <h4>Case Study: Redrow Homes</h4>\n    <p>Redrow Homes employs over 2,300 people and has been named a ''Top 100 Apprenticeship Employer'' for five consecutive years. At any one time, the company employs at least 130 apprentices in trades such as carpentry, plumbing, and bricklaying. Apprentices follow a clear career path, gaining qualifications alongside work experience and a competitive wage. The company views apprenticeships as an excellent way to find and develop motivated young staff tailored to the construction industry''s specific needs.</p>\n  </div>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Advantages to the Business</div>\n      <div class=\"pro-item\"><strong>Tailored training:</strong> Learning is tailored to the firm''s specific needs — apprentices learn to do the job the business''s way.</div>\n      <div class=\"pro-item\"><strong>Cost-effective:</strong> Often cheaper than hiring already-skilled workers. Government subsidies may be available.</div>\n      <div class=\"pro-item\"><strong>Productive while training:</strong> Apprentices contribute work to the business as they learn.</div>\n      <div class=\"pro-item\"><strong>Loyalty and retention:</strong> Apprentices who feel invested in are more likely to stay with the business long-term.</div>\n      <div class=\"pro-item\"><strong>Solves skill shortages:</strong> Builds the specific skills the industry needs from within.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✗ Disadvantages to the Business</div>\n      <div class=\"con-item\"><strong>Costly to run:</strong> Course fees, time of experienced workers acting as mentors, reduced output while apprentice is off-site studying.</div>\n      <div class=\"con-item\"><strong>Risk of quality issues:</strong> Apprentices not yet fully skilled may make mistakes, wasting resources.</div>\n      <div class=\"con-item\"><strong>Drop-out risk:</strong> If an apprentice does not complete the programme, the investment is wasted.</div>\n    </div>\n  </div>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Advantages to the Worker</div>\n      <div class=\"pro-item\">Earn a wage while learning — no need to take on student debt.</div>\n      <div class=\"pro-item\">Gain a recognised vocational qualification to support career progression.</div>\n      <div class=\"pro-item\">Varied learning — mix of practical and theoretical activities.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✗ Disadvantages to the Worker</div>\n      <div class=\"con-item\">Pay is usually low during the apprenticeship period.</div>\n      <div class=\"con-item\">Qualifications are job-specific — may limit future career breadth compared to a degree.</div>\n      <div class=\"con-item\">Evidence suggests degree-holders earn more on average in the long run.</div>\n    </div>\n  </div>", "check": {"question": "Why does Redrow Homes view apprenticeships as valuable, according to the case study?", "options": ["They help find and develop motivated staff suited to construction", "Apprentices are not required to be paid", "Apprenticeships replace the need for any qualified tradespeople", "Apprentices only work part-time"], "answer": 0, "explain": "Redrow Homes uses apprenticeships to build a pipeline of skilled, loyal workers specifically suited to the construction trade — carpentry, plumbing, bricklaying — developed from within rather than recruited externally."}}, {"title": "Staff Development — Professional Development Programmes", "html": "<p><strong>Professional development programmes</strong> are long-term development activities (vocational or academic) designed to realise the long-term potential of a worker. They often lead to qualifications such as degrees, professional diplomas, or vocational certificates and are a form of staff development — not short-term training.</p>\n  <div class=\"case-study-box\">\n    <h4>Case Study: Capgemini</h4>\n    <p>Capgemini, a global technology consultancy operating in 40 countries, supports employees to work part-time towards a BSc in Software Engineering or BSc in Business Information Systems. These \"advanced apprenticeships\" develop the long-term potential of existing staff, helping Capgemini build a highly skilled, loyal workforce for the future.</p>\n  </div>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Advantages to the Business</div>\n      <div class=\"pro-item\"><strong>Improves long-term productivity:</strong> Better-qualified workers perform more efficiently, helping the business compete.</div>\n      <div class=\"pro-item\"><strong>Workforce planning:</strong> Develops future managers internally — as senior workers leave, others are ready for promotion.</div>\n      <div class=\"pro-item\"><strong>Motivation and retention:</strong> Workers feel valued, work harder, and are less likely to leave.</div>\n      <div class=\"pro-item\"><strong>Attract high-quality recruits:</strong> Offering development opportunities makes the business more attractive to ambitious candidates.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✗ Disadvantages to the Business</div>\n      <div class=\"con-item\"><strong>Expensive:</strong> Course fees, lost working time, and cover costs all add up.</div>\n      <div class=\"con-item\"><strong>Retention risk:</strong> Once qualified, workers may find it easier to secure higher-paid jobs at rival firms.</div>\n      <div class=\"con-item\"><strong>No guarantee of return:</strong> The business cannot guarantee the investment will benefit the firm if the worker leaves.</div>\n    </div>\n  </div>\n  <div class=\"two-col\">\n    <div>\n      <div class=\"col-head\">✓ Advantages to the Worker</div>\n      <div class=\"pro-item\">Gain qualifications and experience leading to career opportunities.</div>\n      <div class=\"pro-item\">Increased earnings potential and promotion prospects.</div>\n      <div class=\"pro-item\">Improved self-esteem — feels supported and valued by the employer.</div>\n    </div>\n    <div>\n      <div class=\"col-head\">✗ Disadvantages to the Worker</div>\n      <div class=\"con-item\">Can be very demanding and stressful alongside a full-time job.</div>\n      <div class=\"con-item\">No guarantee the qualification will lead to career progression at that business.</div>\n    </div>\n  </div>", "check": {"question": "What is a key business risk of investing in professional development programmes for staff?", "options": ["Once qualified, workers may find better-paid jobs at rival firms", "Professional development always reduces staff motivation", "There is no risk at all — it is always a safe investment", "Workers are legally required to stay with the business for life"], "answer": 0, "explain": "A major risk is retention — after gaining a valuable qualification, a worker becomes more attractive to other employers and may leave, meaning the business does not always get a return on its investment."}}, {"title": "Evaluation: Which Training Method is Best?", "html": "<p>There is no single \"best\" training method — the right choice depends on the situation. In evaluation questions, always consider the context of the business.</p>\n  <ul>\n    <li><strong>On-the-job</strong> is best when: the work is straightforward, cost is a concern, and mistakes are recoverable. <em>Not suitable</em> when safety is critical or quality standards are very high.</li>\n    <li><strong>Off-the-job</strong> is best when: the work involves safety risks, specialist skills, or industry-regulated qualifications are required. <em>Not suitable</em> when the business cannot afford the cost or the worker''s absence.</li>\n    <li><strong>Induction</strong> is always needed for new starters — it reduces settling-in time and health and safety risks regardless of sector.</li>\n    <li><strong>Apprenticeships</strong> suit businesses that need specific, practical skills developed over time and want to build loyal, long-term employees. Best for trades, engineering, and technical roles.</li>\n    <li><strong>Professional development</strong> suits businesses with ambitious employees and a need for future managers or highly qualified specialists. Especially valuable in finance, law, technology, and healthcare.</li>\n  </ul>\n  <p><strong>Evaluation tip:</strong> Consider whether the business can afford the cost, whether the worker will stay after qualifying, and whether the skill needed is short-term or long-term. These are the factors that decide which method is best <em>in context</em>.</p>", "check": {"question": "When is off-the-job training NOT suitable for a business, according to this topic?", "options": ["When safety is critical or industry-regulated qualifications are required", "When the business cannot afford the cost or manage the worker''s absence", "Off-the-job training is always suitable in every situation", "When the worker has been employed for less than a year"], "answer": 1, "explain": "Off-the-job training is ideal for safety-critical or specialist roles, but it isn''t suitable when a business can''t afford the cost or the disruption of having the worker absent — the right method always depends on context."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Training", "definition": "Short-term, job-specific learning to improve a worker''s current performance."}, {"term": "Development", "definition": "Long-term learning focused on the overall growth and future potential of a worker."}, {"term": "On-the-job training", "definition": "Training done at the workplace while the employee is working — e.g. shadowing an experienced colleague."}, {"term": "Off-the-job training", "definition": "Training away from normal duties — e.g. at a college, training centre, or via simulations."}, {"term": "Induction training", "definition": "Training to introduce new employees to the workplace, colleagues, culture, and health and safety — NOT to teach job skills."}, {"term": "Apprenticeship", "definition": "A 2–4 year development programme combining workplace experience and college study, leading to a vocational qualification."}, {"term": "Professional development", "definition": "Long-term vocational or academic programmes designed to realise a worker''s full potential."}, {"term": "Vocational qualification", "definition": "A job-specific qualification (e.g. NVQ) gained through practical and classroom learning."}, {"term": "Academic qualification", "definition": "A general theory-based qualification such as a GCSE, A Level, or degree — not job-specific."}, {"term": "Productivity", "definition": "Output per worker — how much each employee produces."}, {"term": "Skills shortage", "definition": "When businesses cannot recruit enough workers with the skills they need."}, {"term": "Retention", "definition": "Keeping workers employed at the business rather than them leaving."}, {"term": "Why train? — Productivity", "definition": "Better-trained workers produce more output per hour, reducing unit costs and boosting profit."}, {"term": "Why train? — Customer service", "definition": "Well-trained staff give customers better experiences, increasing sales and improving reputation."}, {"term": "Key disadvantage of off-the-job training", "definition": "It is expensive (fees, travel, accommodation) and workers are absent from their role, reducing output."}, {"term": "Key disadvantage of on-the-job training", "definition": "Quality depends on the trainer''s skills; trainees may produce poor-quality work; no qualification gained."}]}, "mcq": {"enabled": true, "questions": [{"question": "What is the main difference between training and development?", "options": ["Training is long-term and development is short-term", "Training is job-specific and short-term; development is about long-term potential", "Development only involves on-the-job activities", "Training always leads to a qualification"], "answer": 1, "explain": "Correct: Training is short-term and focused on a specific job or task. Development is longer-term and about growing the overall potential of the worker for future roles."}, {"question": "Which of the following is a feature of off-the-job training?", "options": ["The worker continues to produce goods or services whilst training", "It is a cheaper way of training workers than paying for them to go on courses", "Workers are trained in a college or training centre away from where they do the work", "It never leads to a qualification for the worker"], "answer": 2, "explain": "Correct: Off-the-job training takes place away from the employee''s normal duties — at an external venue such as a college or training centre. A is on-the-job, B is wrong (off-the-job is more expensive), D is false (off-the-job often leads to qualifications)."}, {"question": "Which of the following is NOT a benefit to a golfing equipment retailer of training its sales assistants?", "options": ["To help staff give advice on which golf clubs to buy", "To increase the sales of golf umbrellas and waterproof clothing", "To motivate staff to assist customers who are trying on golf shoes", "To reduce the time it takes to make golf bags and golf trolleys"], "answer": 3, "explain": "Correct: A retailer doesn''t make golf bags — it sells them. Training sales assistants would not reduce manufacturing time because retail staff don''t manufacture products. A, B, and C are all genuine benefits of training retail staff."}, {"question": "What is induction training?", "options": ["Training to help workers gain a vocational qualification", "Long-term development to realise a worker''s potential", "Training to introduce a new worker to the business and workplace", "On-the-job training delivered by an experienced colleague"], "answer": 2, "explain": "Correct: Induction training is specifically for new employees to help them settle into the workplace — meeting colleagues, learning health and safety rules, and understanding the culture of the business. It is NOT about teaching job skills."}, {"question": "Which of the following is a disadvantage of using on-the-job training to train new sales assistants at a petrol station?", "options": ["Likely to be more expensive than sending the employees on a training course", "Motorists may experience lower standards of customer service", "No petrol can be sold while the training takes place", "The employees will be trained on different equipment to that at the garage"], "answer": 1, "explain": "Correct: A trainee serving real customers may make mistakes, leading to lower service quality. A is wrong — on-the-job is cheaper. C is wrong — petrol can still be sold. D is wrong — on-the-job uses the actual workplace equipment."}, {"question": "Which of the following is NOT a form of staff development?", "options": ["Academic qualifications", "Apprenticeships", "Induction", "Vocational qualifications"], "answer": 2, "explain": "Correct: Induction is a form of training — it is short-term and designed to introduce a new worker to the business. Staff development (academic qualifications, apprenticeships, vocational qualifications) is long-term and aimed at realising the worker''s future potential."}, {"question": "Which of the following is a feature of professional development?", "options": ["It is a kind of short-term training", "It is designed to realise the potential of a worker in the long-term interests of the business and the worker", "It is designed to improve the skills of the worker to do a specific task", "It usually involves on-the-job training only"], "answer": 1, "explain": "Correct: Professional development is long-term and is about realising the potential of the worker — it may lead to vocational or academic qualifications. A and C describe training. D is false — professional development often includes off-the-job study at college or university."}, {"question": "One benefit to Gina, an employee on a dairy farm, of staff development is:", "options": ["Higher profits for the farm", "Increased retention of farm workers", "More opportunities for promotion", "The animals will be better cared for"], "answer": 2, "explain": "Correct: Staff development benefits the individual worker — gaining qualifications and skills may lead to promotion opportunities. A and B are benefits to the business, not the employee. D relates to animal welfare, not a personal benefit to Gina."}, {"question": "One benefit to a hospital of encouraging staff development is:", "options": ["Increased skill shortages", "Improved patient care", "Lower morale of doctors and nurses", "More medical staff can be employed"], "answer": 1, "explain": "Correct: When hospital staff are developed through training and qualifications, their skills improve — leading directly to improved patient care. A is the opposite of a benefit. C is wrong — development improves morale. D is unrelated to development."}, {"question": "Which of the following statements about apprenticeships is true?", "options": ["A vocational qualification is specific to a particular type of job", "An academic qualification prepares a worker for work in a specific business", "An apprenticeship is offered to senior managers who want to develop their skills further", "An apprenticeship involves only studying at university"], "answer": 0, "explain": "Correct: Vocational qualifications are job-specific — they relate to a particular occupation. B is wrong — academic qualifications are more general. C is wrong — apprenticeships are aimed at developing workers in a role, not exclusively senior managers. D is wrong — apprenticeships combine workplace training with college study."}, {"question": "A firm switches from off-the-job training (costing £82,000) to on-the-job training (costing £68,000). What is the approximate percentage change in training costs?", "options": ["–20.6%", "–17.1%", "17.1%", "20.6%"], "answer": 1, "explain": "Correct: Percentage change = (68,000 − 82,000) / 82,000 × 100 = −14,000 / 82,000 × 100 ≈ −17.1%. The negative sign shows a decrease in cost."}, {"question": "Which of the following is a benefit to a business of using off-the-job training?", "options": ["Large numbers of employees can be trained at the same time", "Likely to be cheaper than on-the-job training", "The training can take place while the employee is working", "Workers need to be paid for time spent doing off-the-job training"], "answer": 0, "explain": "Correct: Off-the-job training at a venue can accommodate larger groups simultaneously — a key advantage over one-on-one on-the-job training. B is wrong — off-the-job is more expensive. C describes on-the-job training. D is a disadvantage, not a benefit."}]}, "fib": {"enabled": true, "questions": [{"text": "Training is [short-term] and job-specific, while development is [long-term] and focused on the overall growth of the worker."}, {"text": "On-the-job training is [cheaper] than off-the-job training because there are no travel or accommodation costs."}, {"text": "Induction training is designed to introduce a new worker to the [workplace], their colleagues, and the [culture] of the business."}, {"text": "A disadvantage of on-the-job training is that the [trainer] may need to leave their own work to help the trainee, causing production to fall."}, {"text": "Off-the-job training is typically more [expensive] than on-the-job training due to course fees, travel, and accommodation."}, {"text": "An apprenticeship is a long-term development programme that leads to a [vocational] qualification and combines on- and off-the-job learning."}, {"text": "Professional development programmes are designed to realise the long-term [potential] of workers, often leading to vocational or academic qualifications."}, {"text": "A [skills] shortage occurs when businesses cannot recruit workers with the skills they need."}, {"text": "Training can improve worker [retention] because employees feel valued when the business invests in them, meaning they are less likely to leave."}, {"text": "[Vocational] qualifications are job-specific and gained through practical and classroom learning, whereas [academic] qualifications are more general and theory-based."}, {"text": "A key disadvantage of off-the-job training for a business is that the worker is not producing [output] while they are away training."}, {"text": "One benefit of off-the-job training is that it can be delivered in a [safe] environment, which is essential for safety-critical roles such as cabin crew."}]}, "tf": {"enabled": true, "questions": [{"statement": "Induction training is designed to teach new workers the specific skills they need to do their job.", "answer": false, "explain": "FALSE. Induction training is about introducing new employees to the workplace, colleagues, culture, and health and safety procedures — not teaching job-specific skills. Examiners frequently penalise students who confuse induction with skills training."}, {"statement": "On-the-job training is generally cheaper than off-the-job training for a business.", "answer": true, "explain": "TRUE. On-the-job training has no travel, accommodation, or external course fees. The trainee also continues to produce goods or services during training, meaning the business still earns money."}, {"statement": "Off-the-job training always leads to a qualification for the worker.", "answer": false, "explain": "FALSE. Off-the-job training does not always lead to a qualification — it depends on the type of course. However, it is more likely to lead to qualifications than on-the-job training."}, {"statement": "A disadvantage of professional development for a business is that once workers are better qualified, they may find it easier to secure jobs at other firms.", "answer": true, "explain": "TRUE. This is a genuine retention risk for businesses. After investing in development, a more qualified worker may leave for a higher-paying role elsewhere, meaning the business does not get a return on its investment."}, {"statement": "Apprenticeships are a form of staff development, not just a recruitment method.", "answer": true, "explain": "TRUE. On this specification, apprenticeships appear in Section 3.6 as staff development. They involve developing existing employees who are already paid a wage, not just recruiting new ones cheaply."}, {"statement": "On-the-job training is suitable for all types of jobs, including those with significant safety risks.", "answer": false, "explain": "FALSE. On-the-job training is not appropriate for safety-critical roles (e.g. cabin crew, surgeons) because mistakes made during training could endanger lives. Off-the-job simulation is required in these cases."}, {"statement": "Development is more short-term and practical than training.", "answer": false, "explain": "FALSE. It is the other way around. Training is short-term and practical; development is long-term and often includes both theoretical and practical learning to build the worker''s overall potential."}, {"statement": "A benefit of on-the-job training is that the trainee produces goods and services while learning, so the firm earns money during the training process.", "answer": true, "explain": "TRUE. Because the trainee is working while learning, the business does not lose all of that worker''s productive output — a key financial advantage over off-the-job training where the worker is absent from their role entirely."}, {"statement": "Academic qualifications are specific to a particular job role.", "answer": false, "explain": "FALSE. Vocational qualifications are job-specific. Academic qualifications (e.g. GCSEs, A Levels, degrees) are more general and transferable across many different careers."}, {"statement": "Businesses may train workers to solve skill shortages if the specialist labour they need cannot be found externally.", "answer": true, "explain": "TRUE. If the market doesn''t supply enough skilled workers, businesses can train existing employees to fill those gaps internally — for example, training technicians to become fully qualified engineers."}, {"statement": "The quality of on-the-job training depends on the communication skills and ability of the trainer.", "answer": true, "explain": "TRUE. If the trainer has poor communication skills or bad habits, the trainee will learn them too. The quality of the training is only as good as the person delivering it — a key disadvantage of on-the-job training."}]}, "misc": {"enabled": true, "items": [{"myth": "Induction training teaches new workers how to do their job.", "truth": "Induction training introduces the new worker to the business, workplace, colleagues, and health and safety rules. It is about settling in — not skill-building. Examiners specifically flagged this as a very common error.", "check": {"question": "Does induction training primarily teach a new worker job-specific skills?", "options": ["No — it''s about settling in, not job skills", "Yes, that is its main purpose", "No, induction is only for experienced workers", "Yes, but only for management roles"], "answer": 0, "explain": "Induction is about helping a new worker settle in to the business — its purpose is not to teach job skills, which is a very commonly tested misconception."}}, {"myth": "Training and development mean the same thing.", "truth": "They are different. Training is short-term and job-specific. Development is long-term and about the overall growth of the worker''s potential. Always check which one the question is asking about.", "check": {"question": "If an exam question specifically asks about ''development'', should you write about short-term, job-specific skills?", "options": ["No — development means long-term growth, not skills", "Yes, training and development are interchangeable", "Yes, as long as you mention training", "It doesn''t matter which term the question uses"], "answer": 0, "explain": "Training and development are distinct terms tested separately by examiners. Development questions need long-term, potential-focused answers — not short-term job-specific training answers."}}, {"myth": "Off-the-job training is always better than on-the-job training.", "truth": "Neither is universally better — it depends on the situation. On-the-job is cheaper and keeps the worker productive. Off-the-job is higher quality and safer for risky roles. Always evaluate in context.", "check": {"question": "Is off-the-job training always the best choice for a business?", "options": ["No, on-the-job training is always better", "No — it depends entirely on the business situation", "Neither method is ever appropriate", "Yes, it is always superior to on-the-job training"], "answer": 1, "explain": "Neither method is universally better. The right choice depends on context — cost, safety requirements, and the nature of the skill being taught all matter."}}, {"myth": "Apprenticeships are only for school leavers looking for their first job.", "truth": "On this specification, apprenticeships are a form of staff development for existing employees. They reduce the time a worker spends on their normal duties while they study — they are not just a cheap way to recruit new workers.", "check": {"question": "According to this specification, are apprenticeships only for school leavers seeking their first job?", "options": ["Yes, that is their only purpose", "Apprenticeships do not exist on this specification", "Apprenticeships are only for graduates", "No, they also develop existing employees at the firm"], "answer": 3, "explain": "Apprenticeships are presented as a staff development method that can apply to existing employees being developed within the business, not solely as a route into a first job."}}, {"myth": "On-the-job training means the same as internal training.", "truth": "These are not the same. On-the-job and off-the-job refer to whether training takes place during normal work. Internal vs external refers to who delivers the training. Do not confuse location with method.", "check": {"question": "What is the difference between ''on-the-job vs off-the-job'' and ''internal vs external'' training?", "options": ["They are the same distinction described two ways", "External training is always off-the-job", "Internal training is always on-the-job", "One is about when; the other is who delivers it"], "answer": 3, "explain": "These describe two completely different things: on/off-the-job is about whether training happens during normal duties, while internal/external is about who provides the training — they should not be confused."}}, {"myth": "For an ''analyse one benefit to employees'' question, answers about increased profits or productivity are correct.", "truth": "Profits and productivity are benefits to the BUSINESS, not the employee. When the question specifies employees, you must write about personal benefits — higher pay, promotion prospects, improved self-esteem, job satisfaction.", "check": {"question": "If a question asks for a benefit to EMPLOYEES specifically, is ''increased profits'' a valid answer?", "options": ["No, profit benefits the business, not the employee", "No, because profit never increases from training", "Yes, as long as profit is mentioned somewhere", "Yes, profit is always a good answer"], "answer": 0, "explain": "Always check who the question is asking about. Profit and productivity are business-facing benefits — when the question specifies employees, you need employee-facing benefits like pay, promotion, or job satisfaction."}}, {"myth": "Vocational qualifications are more general than academic qualifications.", "truth": "It is the opposite. Vocational qualifications are job-specific (e.g. NVQs). Academic qualifications (e.g. GCSEs, degrees) are more general and can open up a wider range of career paths.", "check": {"question": "Which type of qualification is more job-specific: vocational or academic?", "options": ["Academic qualifications are more job-specific", "Neither type is job-specific", "They are equally general", "Vocational qualifications are more job-specific"], "answer": 3, "explain": "Vocational qualifications (like NVQs) are tied to a specific job or trade, while academic qualifications (like GCSEs or degrees) are broader and can lead to a wider range of career paths."}}, {"myth": "Staff development is just another word for training.", "truth": "Staff development is broader and longer-term than training. It includes apprenticeships and professional development programmes that develop the worker''s overall potential, not just their ability to do the current job.", "check": {"question": "Is staff development simply another term for training?", "options": ["No, staff development only applies to new employees", "Yes, but only for senior staff", "No, it''s a broader, longer-term idea than training", "Yes, they mean exactly the same thing"], "answer": 2, "explain": "Staff development is a wider, longer-term concept than training — it includes things like apprenticeships and professional qualifications aimed at growing a worker''s overall potential, not just their current job performance."}}]}, "tips": {"enabled": true, "items": [{"title": "Training Method Questions: Name It, Then Apply It", "html": "\n        <p>When asked to <strong>explain a training method</strong> (e.g. \"Explain three methods of training HSBC may use\"), each method earns you <strong>2 marks: 1 for naming the method + 1 for applying it to the business</strong>.</p>\n        <p><strong>The Formula:</strong></p>\n        <ul>\n          <li><strong>Name the method</strong> (K): On-the-job training / Off-the-job training / Induction training</li>\n          <li><strong>Apply it to the business</strong> (APP): Link to a detail from the case study</li>\n        </ul>\n        <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n        <em>\"HSBC could use on-the-job training because it will help staff learn.\"</em><br/>\n        No application — too vague.</p>\n        <p><strong>✅ Good Answer (2 marks):</strong><br/>\n        <em>\"HSBC could use on-the-job training (K) to help call centre staff practise opening new bank accounts using HSBC''s own IT systems (APP).\"</em></p>\n        <p><strong>⚠️ Examiner Warning:</strong> Do NOT write \"online training\" or \"at-home training\" as a third method — these are not the correct terms. The three methods are: <strong>on-the-job, off-the-job, and induction</strong>. Induction was the most commonly missed method.</p>\n        <p><strong>🚫 Do NOT accept:</strong> \"on-site\", \"off-site\", \"internal\", or \"external\" training — these describe location, not the training method itself.</p>\n      ", "check": {"question": "Which three training methods are the correct answers when asked to name training methods a business could use?", "options": ["On-site, off-site, and internal training", "On-the-job, off-the-job, and induction", "Internal, external, and online", "Apprenticeship, degree, and NVQ"], "answer": 1, "explain": "The three correct training methods on this specification are on-the-job, off-the-job, and induction. Induction is the one most commonly missed by students — terms like ''internal'' or ''on-site'' describe location, not the method itself."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n        <p>Every 3-mark analyse question needs exactly three things in a chain of reasoning. Miss any one and you cap yourself at 2 marks.</p>\n        <p><strong>Step-by-Step Formula:</strong></p>\n        <ul>\n          <li><strong>1. Understanding (U):</strong> State and explain the benefit or reason.</li>\n          <li><strong>2. Application (APP):</strong> Link directly to the specific business in the case study using a detail from the text.</li>\n          <li><strong>3. Analysis (AN):</strong> State the business-facing (or employee-facing) impact — cost, revenue, profit, reputation, retention, etc.</li>\n        </ul>\n        <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n        <em>\"Training improves customer service which increases profits.\"</em><br/>\n        No application to the specific business — this could be about any firm.</p>\n        <p><strong>✅ Full Mark Answer (3 marks):</strong><br/>\n        <em>\"Training will improve the customer service skills of staff (U). This is especially important at Waitrose, which targets customers with higher income levels and a reputation for quality (APP). As a result, customers are more likely to be satisfied and return, boosting sales revenue (AN).\"</em></p>\n        <p><strong>⚠️ Critical Examiner Warning — Check Who Benefits:</strong> If the question asks for a benefit to <strong>employees</strong>, your analysis must be <em>employee-facing</em> (e.g. higher pay, promotion, job satisfaction). If the question asks about the <strong>business</strong>, your analysis must be <em>business-facing</em> (e.g. profit, retention, productivity). Writing business benefits when asked about employees scores zero for analysis.</p>\n        <p><strong>Useful sentence starters:</strong></p>\n        <ul>\n          <li><em>U: \"Off-the-job training allows workers to be trained by specialists...\"</em></li>\n          <li><em>APP: \"In the case of [Business], this is important because the text states that...\"</em></li>\n          <li><em>AN: \"As a result, the business will... / This will lead to... / This means profits will...\"</em></li>\n        </ul>\n      ", "check": {"question": "Why does the answer ''Training improves customer service which increases profits'' score only 1 mark on a 3-mark analyse question?", "options": ["It is too long", "It has no application to the specific business", "It mentions profit, which is not relevant", "Customer service is not connected to training"], "answer": 1, "explain": "Without applying the point to the named business using a specific case study detail, you cannot score the APP or AN marks — the chain breaks before it reaches analysis."}}, {"title": "Two Separate Chains — No Conclusion Needed", "html": "\n        <p>A 6-mark \"analyse two benefits\" question is simply the 3-mark structure done <strong>twice</strong>. Each benefit earns up to 3 marks (U + APP + AN).</p>\n        <p><strong>Key Rules:</strong></p>\n        <ul>\n          <li>Write two fully separate chains of reasoning — do not mix them together.</li>\n          <li>Both benefits must relate to the <strong>method</strong> asked about (e.g. off-the-job training specifically), not to training in general.</li>\n          <li><strong>Do NOT write a conclusion</strong> — there are zero evaluation marks available in a 6-mark question. A conclusion wastes time.</li>\n          <li>Apply each benefit to the case study business using a specific detail from the text.</li>\n        </ul>\n        <p><strong>⚠️ Examiner Warning (BFF question):</strong> Do not write about motivation or productivity as a benefit of off-the-job training — these apply to <em>all</em> types of training. You must identify a feature <em>specific to off-the-job training</em>, such as training by an expert, use of specialist equipment, or a safe environment to practise.</p>\n        <p><strong>Structure:</strong><br/>\n        <em>Benefit 1: [U — specialist feature of off-the-job] → [APP — apply to BFF] → [AN — business impact]</em><br/>\n        <em>Benefit 2: [U — another specific feature] → [APP — apply to BFF] → [AN — business impact]</em></p>\n      ", "check": {"question": "On a 6-mark ''analyse two benefits of off-the-job training'' question, why would writing about ''improved motivation'' score zero for the second benefit?", "options": ["Motivation is not relevant to any type of training", "Motivation isn''t a feature unique to off-the-job training", "Six-mark questions do not award marks for motivation points", "You can only write one benefit, not two"], "answer": 1, "explain": "The question asks specifically about off-the-job training — so your benefits must be features unique to it (expert trainers, specialist equipment, safe environment). Generic training benefits like motivation could apply to any method and will not score."}}, {"title": "Both Sides + A Justified, Contextual Decision", "html": "\n        <p>A 7-mark evaluate question is marked independently across three skill areas: <strong>Application (2), Analysis (2), and Evaluation (3)</strong>. No skill is a pre-requisite of another — you can pick up marks in any area independently.</p>\n        <p><strong>The 3-Paragraph Structure:</strong></p>\n        <ol>\n          <li><strong>Paragraph 1 (AN + APP):</strong> Analyse one advantage of the method/strategy using a case study detail.</li>\n          <li><strong>Paragraph 2 (AN + APP):</strong> Analyse one disadvantage of the method/strategy using a case study detail.</li>\n          <li><strong>Paragraph 3 (Evaluation — 3 sentences):</strong>\n            <ul>\n              <li><strong>Decision:</strong> \"Overall, Dyson Ltd should/should not continue with apprenticeships because...\"</li>\n              <li><strong>Context:</strong> Link your decision to a specific detail from the case study.</li>\n              <li><strong>Impact/Reasoning:</strong> Explain the consequence of that decision for the business.</li>\n            </ul>\n          </li>\n        </ol>\n        <p><strong>Evaluation Marks Breakdown:</strong></p>\n        <ul>\n          <li><strong>1 mark (Limited):</strong> Just a decision — \"Dyson should continue with apprenticeships.\"</li>\n          <li><strong>2 marks (Good):</strong> Decision + non-contextual justification.</li>\n          <li><strong>3 marks (Strong):</strong> Decision + justified using a specific detail from the case study.</li>\n        </ul>\n        <p><strong>✅ Strong Evaluation Example:</strong><br/>\n        <em>\"Overall, Dyson Ltd should continue offering apprenticeships (DECISION) as James Dyson personally promotes careers in engineering and the company creates innovative products (CONTEXT). Apprenticeships allow Dyson to develop engineers with the exact skills needed for product innovation, giving the business a long-term competitive advantage (REASONING).\"</em></p>\n        <p><strong>⚠️ Examiner Warning (Dyson question):</strong> Many students wrote about the advantages/disadvantages to the apprentice rather than to Dyson. Always re-read: the question asks about the business''s perspective. Also, answers about taking on apprentices as cheap new recruits were wrong — the question was about apprenticeships as a method of developing existing staff.</p>\n      ", "check": {"question": "How many marks is a strong evaluation conclusion worth in a 7-mark question, and what three things must it include?", "options": ["1 mark — just a decision", "3 marks — decision, detail, reasoning", "2 marks — two advantages", "3 marks — three separate advantages"], "answer": 1, "explain": "The evaluation element is worth up to 3 marks. A strong conclusion (3 marks) must include: a clear decision, a specific detail from the case study, and reasoning explaining the consequence for that particular business."}}, {"title": "Staff Development vs Training: Know the Difference", "html": "\n        <p>When asked to \"identify two other methods of staff development\", be careful — many students write training methods instead.</p>\n        <p><strong>Staff Development methods (correct answers):</strong></p>\n        <ul>\n          <li>Academic qualifications (e.g. GCSEs, A Levels, degrees)</li>\n          <li>Vocational qualifications (e.g. NVQs, Cambridge Technicals)</li>\n          <li>Professional development programmes</li>\n          <li>Secondments</li>\n        </ul>\n        <p><strong>🚫 Do NOT write these — they are training methods, not staff development:</strong></p>\n        <ul>\n          <li>On-the-job training</li>\n          <li>Off-the-job training</li>\n          <li>Induction</li>\n          <li>Courses (too vague)</li>\n        </ul>\n        <p>If the question says \"other than apprenticeships\", do not repeat apprenticeships — write something from the list above.</p>\n      ", "check": {"question": "If asked to ''identify two methods of staff development other than apprenticeships'', which of the following is a correct answer?", "options": ["On-the-job skills training", "Induction training", "Vocational qualifications", "Off-the-job training"], "answer": 2, "explain": "On-the-job training, induction, and off-the-job training are all training methods — not staff development. Correct staff development methods include vocational qualifications, academic qualifications, professional development programmes, and secondments."}}, {"title": "Make a Clear Choice and Compare Both Options", "html": "\n        <p>A \"recommend\" question requires you to make a <strong>clear decision</strong> AND justify it by comparing it to the alternative. Simply describing one option without comparing is not enough.</p>\n        <p><strong>Formula:</strong></p>\n        <ul>\n          <li><strong>Judgement (1 mark):</strong> State clearly which option you recommend.</li>\n          <li><strong>Contextual justification (2 marks):</strong> Explain why your choice is better THAN the other, using a detail from the case study.</li>\n        </ul>\n        <p><strong>Example (McDonald''s training question):</strong></p>\n        <p><strong>❌ Weak (1 mark):</strong><br/>\n        <em>\"McDonald''s should use induction training because James is new.\"</em></p>\n        <p><strong>✅ Strong (3 marks):</strong><br/>\n        <em>\"McDonald''s should use induction training (JUDGEMENT) because James has never worked for McDonald''s before, so he needs to understand the company''s procedures, where the fire exits are, and how he will be paid (CONTEXT). Unlike on-the-job training, induction doesn''t risk dangerous mistakes while James is still learning the basics (COMPARISON).\"</em></p>\n      ", "check": {"question": "What is missing from this Recommend answer: ''McDonald''s should use induction training because James is new''?", "options": ["Nothing — it scores all 3 marks", "A comparison to the alternative method", "A definition of induction training", "A calculation"], "answer": 1, "explain": "This answer gives a basic judgement (1 mark) but needs a contextual justification using case study detail AND a comparison with the alternative method to reach full marks — simply saying James is new is not enough."}}]}, "exam": {"enabled": true, "questions": [{"question": "What is NOT a benefit to a golfing equipment retailer of training its sales assistants?", "marks": 1, "hint": "Think carefully about what a retailer does vs. what a manufacturer does.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D</h5><p><strong>Why D is correct:</strong> A retailer sells golf products — it does not manufacture them. Training sales assistants would not reduce manufacturing time because retail staff have no role in production.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> Helping staff give advice on products IS a genuine benefit of training retail staff — it improves the quality of customer service.</li><li><strong>B — Wrong:</strong> Better-trained staff can upsell related products (umbrellas, clothing), increasing revenue — this IS a benefit.</li><li><strong>C — Wrong:</strong> Training can motivate staff and improve their engagement with customers — this IS a benefit.</li></ul></div>"}, {"question": "Explain three methods of training HSBC may use. [6 marks]", "marks": 6, "hint": "Name each method (1 mark) then apply it specifically to HSBC — use a detail from the case study for each one (1 mark per method).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 6 marks (AO1a: 3 + AO2: 3)</h5><ul><li><strong>1 mark per training method named</strong> (up to 3 methods): on-the-job, off-the-job, induction training.</li><li><strong>1 further mark per method applied to HSBC</strong> (up to 3 application marks) — must use a detail from the case study.</li><li><strong>No further marks without naming the correct method first.</strong></li></ul><p><strong>Do NOT accept:</strong> \"online training\", \"at-home training\", \"on-site\", \"off-site\", \"internal\", or \"external\" — these are not the correct method terms.</p><p><strong>Application examples for HSBC:</strong></p><ul><li>Opening new bank accounts using HSBC''s IT systems</li><li>Answering customer phone calls</li><li>Administrative tasks at a call centre</li><li>Working in branches across the UK</li><li>Serving both business and personal customers</li></ul><p><strong>Examiner''s Comments:</strong> Most candidates scored at least 2 marks by naming on-the-job and off-the-job training. Induction was the most commonly missed method. Full marks required specific application to HSBC — generic answers capped at 3 marks.</p></div>"}, {"question": "Analyse one benefit for HSBC''s employees of studying for academic qualifications. [3 marks]", "marks": 3, "hint": "The question asks about benefits to the EMPLOYEES — not to HSBC. Think about what the individual worker personally gains. Avoid writing about productivity or profit.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1 + AO2: 1 + AO3a: 1)</h5><ul><li><strong>Understanding (1 mark):</strong> One benefit to an employee of studying for academic qualifications — e.g. gain new skills/knowledge, improved confidence/self-esteem, motivational, improved promotion prospects, networking opportunities.</li><li><strong>Application (1 mark):</strong> Link to HSBC — e.g. becoming assistant branch manager, serving business customers as well as personal customers, studying for a degree or professional diploma.</li><li><strong>Analysis (1 mark):</strong> Employee-facing impact — e.g. higher salary, greater job satisfaction, better career prospects, improved mental health/wellbeing.</li></ul><p><strong>Critical note:</strong> Analysis must be employee-facing. Business benefits (higher retention, greater productivity, more profit) score ZERO for analysis on this question.</p><p><strong>Examiner''s Comments:</strong> Many students suggested benefits that were business-facing — these scored zero. The best answers linked improved chances of promotion to higher pay, or new skills to greater job satisfaction, with specific reference to HSBC''s context.</p></div>"}, {"question": "Analyse one likely reason why Dyson Ltd puts all new employees through an induction training programme. [3 marks]", "marks": 3, "hint": "Induction is NOT about teaching job skills — it is about introducing workers to the workplace. Think about health and safety, introducing colleagues, explaining the organisational structure. Then link specifically to Dyson.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1a: 1 + AO2: 1 + AO3a: 1)</h5><ul><li><strong>Knowledge (1 mark):</strong> A valid reason for induction — e.g. introduce the culture/aims of the business, show the workplace layout, explain health and safety, explain the organisational structure, introduce to colleagues, make employees feel valued.</li><li><strong>Application (1 mark):</strong> Link to Dyson — e.g. over 12,000 employees worldwide, unique organisational structure, focus on creating innovative products.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. improved productivity, reduced accidents, improved retention, better communication.</li></ul><p><strong>Do NOT award:</strong> \"learn new skills\" or \"how to do job role\" as these describe on-the-job training, not induction.</p><p><strong>Examiner''s Comments:</strong> This was very poorly answered. The majority of candidates wrote about improving job skills — this is incorrect and scored zero for knowledge. Correct responses included health and safety briefings, showing the workplace layout, and meeting colleagues. Many candidates who answered correctly still did not apply to Dyson and therefore capped at 2 marks.</p></div>"}, {"question": "Dyson Ltd offers apprenticeships as a method of staff development. Identify two other methods of staff development that a business could offer. [2 marks]", "marks": 2, "hint": "Staff development is LONG-TERM. Do not write on-the-job or off-the-job training — these are training methods, not staff development.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a: 2)</h5><p>One mark per correct method of staff development, up to two marks.</p><p><strong>Accept:</strong></p><ul><li>Vocational qualifications (e.g. NVQs, Cambridge Technicals)</li><li>Academic qualifications (e.g. GCSEs, A Levels, degrees)</li><li>Professional development programmes</li><li>Secondments</li></ul><p><strong>Do NOT accept:</strong> Apprenticeships (excluded by the question), induction, on-the-job training, off-the-job training, or \"courses\" (too vague).</p><p><strong>Examiner''s Comments:</strong> The most common incorrect responses were on-the-job and off-the-job training. The specification makes a clear distinction: training is short-term and narrow; staff development is long-term and wide-ranging.</p></div>"}, {"question": "Evaluate whether or not Dyson Ltd should continue to offer apprenticeship opportunities. [7 marks]", "marks": 7, "hint": "Write about advantages AND disadvantages of apprenticeships as staff development for Dyson (not for the apprentices personally). Then make a clear, contextual decision.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks (AO2: 2 + AO3a: 2 + AO3b: 3)</h5><ul><li><strong>Application (up to 2 marks):</strong> Two relevant uses of case study context (over 12,000 employees, employees worldwide, creates innovative products, James Dyson promotes engineering).</li><li><strong>Analysis (up to 2 marks):</strong> Two advantages/disadvantages (or one of each) of offering apprenticeships for staff development analysed to a business-facing impact.</li><li><strong>Evaluation (up to 3 marks):</strong><ul><li>1 mark (Limited): A decision on whether Dyson should continue.</li><li>2 marks (Good): A justified non-contextual decision.</li><li>3 marks (Strong): A justified, contextual decision using a specific detail from the case study.</li></ul></li></ul><p><strong>⚠️ Examiner Warnings:</strong></p><ul><li>Do NOT write about benefits/disadvantages to the apprentice — the question asks about Dyson''s perspective.</li><li>Do NOT discuss apprenticeships as a recruitment tool for new cheap workers — the focus is on developing existing staff.</li><li>Answers about \"lower wages for apprentices\" are wrong in this context — apprentices are already employed by Dyson at their normal wage.</li></ul>"}, {"question": "Which one of the following is a disadvantage of using on-the-job training to train three new sales assistants?", "marks": 1, "hint": "Think about what can go wrong when an untrained person is serving real customers during training.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5><p><strong>Why B is correct:</strong> A trainee serving real customers may make mistakes or be slow, leading to lower quality customer service — motorists may experience poor service as a result.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> On-the-job training is generally cheaper than off-the-job (no external course fees or travel costs).</li><li><strong>C — Wrong:</strong> Petrol CAN still be sold during on-the-job training — the trainee is working while learning, meaning the business continues to operate.</li><li><strong>D — Wrong:</strong> On-the-job training takes place at the actual workplace using the actual equipment — so trainees ARE trained on the correct equipment.</li></ul></div>"}, {"question": "Which of the following is NOT a form of staff development?", "marks": 1, "hint": "Staff development is long-term. Which of these options is short-term and about introducing a new worker to the business?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5><p><strong>Why C is correct:</strong> Induction is a form of training — it is short-term and designed to introduce a new employee to the business and workplace. It is NOT staff development.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> Academic qualifications (e.g. degrees) ARE a form of long-term staff development.</li><li><strong>B — Wrong:</strong> Apprenticeships ARE a form of staff development — long-term programmes leading to qualifications.</li><li><strong>D — Wrong:</strong> Vocational qualifications ARE a form of staff development — job-specific long-term learning.</li></ul></div>"}, {"question": "Analyse one likely reason why Waitrose provides its employees with regular training. [3 marks]", "marks": 3, "hint": "Choose ONE reason and develop it fully using the U → APP → AN structure. Use a specific detail from the Waitrose case study for your application mark.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1a: 1 + AO2: 1 + AO3a: 1)</h5><ul><li><strong>Knowledge (1 mark):</strong> A valid reason for training — e.g. improve productivity, improve customer service, increase motivation, improve retention, solve skill shortages, update on new products.</li><li><strong>Application (1 mark):</strong> Link to Waitrose — e.g. competitive supermarket industry, targets high-income customers, over 300 stores, over 50,000 employees, new product development, external recruitment.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. higher sales revenue, increased profits, competitive advantage, greater customer satisfaction, improved reputation.</li></ul></div>"}, {"question": "Analyse two benefits for BFF of using off-the-job training for its store managers. [6 marks]", "marks": 6, "hint": "Each benefit must be specific to off-the-job training as a METHOD — not a general benefit of training (like motivation). Think: What is unique about training AWAY from the store? Use BFF''s context (customer service problems, declining revenue) for application.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 6 marks (AO1b: 2 + AO2: 2 + AO3a: 2)</h5><p>For each benefit: 1 mark (U) + 1 mark (APP) + 1 mark (AN)</p><p><strong>Understanding — valid features of off-the-job training:</strong></p><ul><li>Training delivered by a professional/expert trainer</li><li>Store managers fully focused as removed from operational pressures</li><li>Specialist resources available at a dedicated training venue</li><li>Safe environment to practise — mistakes not made in front of real customers</li><li>Can use simulations, role-play, group activities</li></ul><p><strong>Application — BFF context:</strong></p><ul><li>Customer service identified as poor in market research</li><li>Sales revenue/profit declining (2017–2019)</li><li>BFF wants to expand into children''s shoes</li><li>Five-day course on customer service</li></ul><p><strong>Do NOT award:</strong></p><ul><li>Motivation, productivity, or other benefits that apply to ALL training types — the benefit must be specific to the method (off-the-job).</li><li>\"More skilled workforce\" without a specific reason given.</li><li>Saying what off-the-job training is without giving a benefit.</li></ul>"}, {"question": "One benefit to Gina of staff development is:", "marks": 1, "hint": "The question asks about a benefit to GINA — the employee — not to the farm business.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5><p><strong>Why C is correct:</strong> Staff development helps Gina gain qualifications and skills that could lead to promotion — a direct personal benefit to the employee.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> Higher profits is a benefit to the dairy farm (the business), not to Gina personally.</li><li><strong>B — Wrong:</strong> Increased retention is a benefit to the business — it means the farm keeps its workers, not something that directly benefits Gina.</li><li><strong>D — Wrong:</strong> Better animal care is an operational outcome for the farm — not a personal benefit to Gina as an individual employee.</li></ul></div>"}, {"question": "What is the most likely reason for this digital communication training?", "marks": 1, "hint": "Think about what digital communication enables — remote working requires digital tools to communicate effectively.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D</h5><p><strong>Why D is correct:</strong> Digital communication tools (video calls, emails, messaging platforms) are essential for remote working. A telesales company training staff in digital communication is most likely preparing them to work effectively from home.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> Businesses want to increase retention (keep staff), not reduce it.</li><li><strong>B — Wrong:</strong> Businesses train staff to increase productivity, not reduce it.</li><li><strong>C — Wrong:</strong> Social media for personal use during breaks is not a business training priority and would be an unusual reason to arrange formal training.</li></ul></div>"}, {"question": "The percentage change in the training costs is approximately equal to:", "marks": 1, "hint": "Percentage change = (New − Old) ÷ Old × 100. The original (old) cost is off-the-job: £82,000.", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — −17.1%</h5><p><strong>Calculation:</strong></p><ul><li>Change = £68,000 − £82,000 = −£14,000</li><li>Percentage change = −14,000 ÷ 82,000 × 100 = −17.07% ≈ −17.1%</li></ul><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (−20.6%):</strong> This is calculated using the new cost as the denominator (14,000 ÷ 68,000 × 100) — incorrect. Always divide by the original value.</li><li><strong>C (17.1%):</strong> Correct calculation but wrong sign — costs have decreased, not increased.</li><li><strong>D (20.6%):</strong> Wrong calculation and wrong sign.</li></ul></div>"}, {"question": "Which of the following is a benefit to a business of using off-the-job training?", "marks": 1, "hint": "Think about what off-the-job training can do that individual on-the-job training cannot.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A</h5><p><strong>Why A is correct:</strong> Off-the-job training at a college or training centre can accommodate multiple employees simultaneously — unlike on-the-job training which is typically one-on-one.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>B — Wrong:</strong> Off-the-job training is typically more expensive than on-the-job training due to course fees, travel, and accommodation costs.</li><li><strong>C — Wrong:</strong> This describes on-the-job training, not off-the-job training.</li><li><strong>D — Wrong:</strong> This is a disadvantage of off-the-job training, not a benefit — the business still pays wages while workers are not producing output.</li></ul></div>"}, {"question": "Analyse one benefit to Redrow Homes of using apprenticeships as a method of staff development. [3 marks]", "marks": 3, "hint": "Focus on the BUSINESS benefit — not the apprentice''s benefit. Use a detail from Redrow Homes (e.g. trades like carpentry, plumbing, bricklaying; housebuilding context) for your application mark.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1 + AO2: 1 + AO3a: 1)</h5><ul><li><strong>Understanding (1 mark):</strong> A valid benefit of apprenticeships for a business — e.g. training tailored to business needs, cost-effective, apprentices work while training, possible government funding, increased loyalty/retention.</li><li><strong>Application (1 mark):</strong> Link to Redrow Homes — e.g. carpentry, plumbing, bricklaying, building houses to specification, construction industry, 130 apprentices at any one time.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — reference to costs, revenue, profit, quality, retention (not just \"money\").</li></ul><p><strong>Do NOT award:</strong> \"money\" alone (too vague) — must reference costs, revenue, profit, or cash flow specifically. Do not award \"apprentice\" as a contextual reference since it appears in the question.</p><p><strong>Examiner''s Comments:</strong> Many candidates wrote about benefits to the apprentice rather than to Redrow Homes. The question clearly asks for \"benefit to Redrow Homes.\" Also, answers treating this as a recruitment question (e.g. \"finding new staff cheaply\") were wrong — the focus is on apprenticeships as staff development for existing workers.</p></div>"}, {"question": "Analyse one way in which McDonald''s could use induction training for James. [3 marks]", "marks": 3, "hint": "Remember: induction is about introducing James to the workplace — not teaching him how to cook. Think about his first day: what does he need to know about McDonald''s as a company?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1 + AO2: 1 + AO3a: 1)</h5><ul><li><strong>Understanding (1 mark):</strong> Correct understanding of induction training — e.g. introducing James to the business, workplace, colleagues, health and safety.</li><li><strong>Application (1 mark):</strong> Application to James/McDonald''s — e.g. showing James where fire exits are, explaining the restaurant''s procedures, introducing him to the team.</li><li><strong>Analysis (1 mark):</strong> Impact on McDonald''s — e.g. James settles in more quickly and becomes productive sooner, reduced risk of accidents.</li></ul></div>"}, {"question": "Analyse one way in which McDonald''s could use on-the-job training for James. [3 marks]", "marks": 3, "hint": "On-the-job means James learns while he is working — not at a separate venue. Think about how an experienced McDonald''s employee could help him learn.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1 + AO2: 1 + AO3a: 1)</h5><ul><li><strong>Understanding (1 mark):</strong> Correct understanding of on-the-job training — learning while working at the restaurant.</li><li><strong>Application (1 mark):</strong> Applied to James/McDonald''s — e.g. shadowing an experienced employee, practising making burgers under supervision.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. James becomes productive quickly, customers receive better service, costs of mistakes are reduced.</li></ul></div>"}, {"question": "Analyse one way in which McDonald''s could use off-the-job training for James. [3 marks]", "marks": 3, "hint": "Off-the-job means away from James''s normal role — perhaps at a training venue or using a simulation. Think about what James could not safely or easily learn on the job.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b: 1 + AO2: 1 + AO3a: 1)</h5><ul><li><strong>Understanding (1 mark):</strong> Correct understanding of off-the-job training — away from the normal job.</li><li><strong>Application (1 mark):</strong> Applied to James/McDonald''s — e.g. food hygiene course, fire safety training video, a training centre session.</li><li><strong>Analysis (1 mark):</strong> Business-facing impact — e.g. legal compliance, reduced risk of food safety incidents, better reputation.</li></ul></div>"}, {"question": "Recommend one type of training McDonald''s should use to train James on his first day at work. Give reasons for your answer. [3 marks]", "marks": 3, "hint": "Make a clear choice first. Then explain WHY that training is the right choice for James''s first day specifically — think about what he most needs to know on day one.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b: 3)</h5><ul><li><strong>1 mark (Limited):</strong> A judgement with limited justification showing some appraisal of a relevant training method.</li><li><strong>2 marks (Good):</strong> A judgement with good justification — appraises relevant information and/or issues about the chosen training type.</li><li><strong>3 marks (Strong):</strong> A judgement with strong justification — detailed appraisal of relevant information using context from the case study, showing why the chosen method is most appropriate for James''s first day.</li></ul><p>Accept any training method (induction, on-the-job, or off-the-job) with appropriate justification.</p></div>"}, {"question": "James has been offered a contract of 16 hours per week once he is fully trained. Calculate what James'' weekly pay will be once he is fully trained. Show your workings. [3 marks]", "marks": 3, "hint": "James earns £7.00 per hour. He gets a 10% increase once fully trained. Calculate the new hourly rate first, then multiply by 16 hours.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO2: 3)</h5><ul><li><strong>1 mark:</strong> Correct calculation of 10% increase in hourly pay: 10% of £7.00 = £0.70</li><li><strong>1 mark:</strong> Correct calculation of new hourly rate: £7.00 + £0.70 = £7.70</li><li><strong>1 mark:</strong> Correct calculation of weekly pay: £7.70 × 16 = £123.20</li></ul><p><strong>3 marks for correct final answer of £123.20 with or without working shown.</strong> Own figure rule (OFR) applies — if a student makes an error in step 1 but correctly applies it through steps 2 and 3, they can still earn marks for the later steps.</p></div>"}, {"question": "One benefit to a hospital of encouraging staff development is:", "marks": 1, "hint": "Think about what happens when hospital staff are better trained and qualified — what does that mean for the people they care for?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5><p><strong>Why B is correct:</strong> When hospital staff develop their skills through qualifications and professional development, the quality of their work improves — leading directly to better care for patients.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Wrong:</strong> Staff development reduces skill shortages (by building skills internally), not increases them.</li><li><strong>C — Wrong:</strong> Development should improve morale (workers feel valued), not lower it.</li><li><strong>D — Wrong:</strong> Staff development is about improving the skills of existing staff, not directly leading to hiring more staff.</li></ul></div>"}]}}'::jsonb),
('business', '3-7-employment-law', '3.7 Employment Law', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>These are the essential terms you must know for the Employment Law topic.</p>\n<ul>\n  <li><strong>Employment Law:</strong> Regulations and rules put in place to protect workers from employers who may treat them unfairly.</li>\n  <li><strong>Contract of Employment:</strong> A legal agreement between an employer and an employee. It is formed when a job offer is accepted — it does not need to be in writing to exist.</li>\n  <li><strong>Statement of Employment Particulars:</strong> A written document that details the main terms of the contract of employment. It must be given to employees <em>on or before their first day of work</em>. It is NOT the contract itself — it is written evidence of it.</li>\n  <li><strong>Discrimination:</strong> Treating one worker differently from another for no acceptable reason.</li>\n  <li><strong>Equality Act 2010:</strong> An Act that brought together 116 pieces of legislation to protect individuals from discrimination in the workplace and beyond.</li>\n  <li><strong>Working Time Directive:</strong> A law stating the maximum number of hours that a person can be asked to work — normally an average of 48 hours per week over a 17-week period.</li>\n  <li><strong>Holiday Entitlement:</strong> The amount of paid holiday a worker is legally entitled to each year — 5.6 weeks (including bank holidays).</li>\n  <li><strong>Employment Tribunal:</strong> A panel that hears cases where employment laws may have been broken and comes to a decision in favour of the employer or employee.</li>\n  <li><strong>Trade Union:</strong> An employee organisation that exists to represent the interests of its members, including providing legal advice in tribunal cases.</li>\n  <li><strong>Opt Out:</strong> The right of a worker to voluntarily choose to work more than 48 hours per week.</li>\n</ul>", "check": {"question": "What is the difference between a contract of employment and a Statement of Employment Particulars?", "options": ["The statement is evidence of the contract, not the contract itself", "They are exactly the same legal document", "The contract must always be signed, but the statement is optional", "The statement is only needed for self-employed workers"], "answer": 0, "explain": "The contract of employment exists the moment a job offer is accepted — it doesn''t need to be in writing. The statement of particulars is a separate written document that provides evidence of the contract''s terms."}}, {"title": "The Equality Act 2010 — Types of Discrimination", "html": "<p>The <strong>Equality Act 2010</strong> brought together 116 pieces of legislation into one single Act. It protects workers from discrimination in recruitment, pay, promotion, training, terms of employment, and dismissal.</p>\n<p>A business <strong>must not</strong>:</p>\n<ul>\n  <li>Pay workers differently for doing the same work</li>\n  <li>Favour certain types of people when recruiting</li>\n  <li>Discriminate when promoting or training workers</li>\n  <li>Allow workers to be mistreated by other workers</li>\n</ul>\n<p>The six main types of discrimination under the Act are:</p>\n<ul>\n  <li><strong>Equal Pay Discrimination:</strong> Women must be paid the same as men when doing work of equal value. <em>Example: Samira Ahmed v BBC — she was awarded £700,000 after her role was found to be comparable to a male presenter paid far more.</em></li>\n  <li><strong>Racial Discrimination:</strong> People cannot be treated differently because of their race, colour, nationality or ethnic origin.</li>\n  <li><strong>Sex Discrimination:</strong> Men or women cannot be treated differently due to gender. Job ads cannot specify gender unless there is a genuine reason (e.g. a female PE teacher for a girls'' changing room).</li>\n  <li><strong>Disability Discrimination:</strong> Employers cannot discriminate against disabled people when recruiting. They must make reasonable adjustments to premises and provide appropriate equipment.</li>\n  <li><strong>Sexual Orientation Discrimination:</strong> Applies to lesbian, gay, bisexual, heterosexual, and gender-reassigned people. No preference of any kind may be given based on sexual orientation.</li>\n  <li><strong>Religion or Belief Discrimination:</strong> Workers are protected from discrimination based on religious beliefs or lack of them. Employers should allow time off for important religious festivals.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Tesco & Muslim Prayer Room</h4>\n  <p>Two Muslim workers took Tesco to a tribunal after their prayer room was locked and they were made to sign a book and request a key each time they prayed. Tesco were found guilty of <strong>indirect religious discrimination</strong> — the rules placed Muslims at an unfair disadvantage compared to other workers.</p>\n</div>", "check": {"question": "Why was Tesco found guilty of discrimination in the prayer room case study?", "options": ["They directly refused to let Muslim workers pray at all", "Indirect discrimination disadvantaged Muslim staff unfairly", "They paid Muslim workers less than other staff", "They did not hire any Muslim applicants"], "answer": 1, "explain": "This is a case of indirect discrimination: a policy that looks neutral on the surface but disproportionately disadvantages a particular group — in this case, Muslim workers needing regular access to pray."}}, {"title": "Working Time Directive — Hours of Work", "html": "<p>The <strong>Working Time Directive</strong> limits the number of hours an employer can ask an adult worker to work. The limit is an average of <strong>48 hours per week over a 17-week period</strong>.</p>\n<div class=\"formula-box\">\n  <strong>Average Hours per Week =</strong> Total hours worked &divide; 17\n</div>\n<p><strong>Example:</strong> A worker worked 799 hours in 17 weeks → 799 &divide; 17 = <strong>47 hours per week</strong> (within the limit).</p>\n<p><strong>Example:</strong> A worker worked 914 hours in 17 weeks → 914 &divide; 17 = <strong>53.76 hours per week</strong> (above the limit — law broken).</p>\n<p>Key exceptions and rules to know:</p>\n<ul>\n  <li>Workers can <strong>opt out</strong> voluntarily — they can agree to work more than 48 hours</li>\n  <li>The law applies to <strong>employees</strong> only — it does <strong>not</strong> apply to self-employed people</li>\n  <li>Workers under 18 can only work up to <strong>40 hours</strong> per week</li>\n  <li>Workers must receive a <strong>20-minute rest break</strong> every 6 hours</li>\n  <li>Exceptions: armed forces, police, emergency services, managing directors, seamen</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Uber Drivers (2021 Supreme Court)</h4>\n  <p>Uber claimed its drivers were self-employed independent contractors and therefore not entitled to holidays, pensions, or minimum wage. The Supreme Court ruled that because Uber controlled drivers'' pay, routes, and penalised those who declined jobs, the drivers were in fact <strong>workers</strong>. Uber subsequently granted them employee status and benefits.</p>\n</div>", "check": {"question": "A worker clocks 884 hours over a 17-week period. Has the Working Time Directive been broken?", "options": ["Yes — 884 ÷ 17 = 52 hours per week, above the 48-hour limit", "No — 884 ÷ 17 = 48 hours per week exactly", "No — the law doesn''t apply unless they work over 60 hours", "It cannot be worked out from this information"], "answer": 0, "explain": "884 ÷ 17 = 52 hours per week, which is above the 48-hour average limit — so the law has been broken unless the worker has voluntarily opted out."}}, {"title": "Holiday Entitlement", "html": "<p>By law, all workers in the UK are entitled to <strong>5.6 weeks of paid holiday per year</strong>. This includes bank holidays (8 per year in the UK). Workers must be paid their <em>normal earnings</em> while on holiday — not just basic pay.</p>\n<div class=\"formula-box\">\n  <strong>Holiday Entitlement (days) =</strong> Days worked per week &times; 5.6\n</div>\n<p><strong>Examples:</strong></p>\n<ul>\n  <li>Full-time (5 days/week): 5 &times; 5.6 = <strong>28 days</strong></li>\n  <li>Part-time (2 days/week): 2 &times; 5.6 = <strong>11.2 days</strong></li>\n</ul>\n<p>Employers cannot reduce holiday entitlement without employee consent. Businesses must plan staffing carefully to ensure enough workers are available when others are on holiday — this may mean <strong>hiring additional staff</strong>.</p>\n<div class=\"case-study-box\">\n  <h4>Case Study: Mr Lock v British Gas</h4>\n  <p>Mr Lock was a salesman paid a basic salary plus commission. When on holiday, he only received basic pay — significantly less than normal. A tribunal ruled he must be paid a sum equal to his <strong>average monthly earnings</strong>, including typical commission. This set an important precedent for workers whose normal pay includes variable elements.</p>\n</div>", "check": {"question": "A worker is employed 4 days per week. How many days of paid holiday are they entitled to per year?", "options": ["28 days", "22.4 days", "5.6 days", "4 days"], "answer": 1, "explain": "Holiday entitlement = days worked per week × 5.6. So 4 × 5.6 = 22.4 days. 28 days only applies to full-time workers (5 days × 5.6)."}}, {"title": "Contract of Employment — Statement of Particulars", "html": "<p>A <strong>contract of employment</strong> exists as soon as a job offer is accepted — it does not need to be in writing. However, employers must provide a <strong>Statement of Employment Particulars</strong> on or before the first day of work.</p>\n<p>The statement must include:</p>\n<ul>\n  <li>Names and addresses of employer and employee</li>\n  <li>Start date of employment</li>\n  <li>Job title and description</li>\n  <li>Hours of work</li>\n  <li>Rate and frequency of pay</li>\n  <li>Holiday entitlement</li>\n  <li>Sick pay arrangements</li>\n  <li>Pension rights</li>\n  <li>Notice period required from both sides</li>\n  <li>Probationary period (if applicable)</li>\n</ul>\n<p>The statement helps to <strong>avoid disputes</strong> about pay, hours, and holidays. Once agreed, it restricts what the employer can ask the employee to do — affecting the <strong>human resource needs</strong> of the business.</p>\n<p>⚠️ <strong>Common misconception:</strong> Many students confuse the contract with the statement. The contract is the <em>legal agreement</em>; the statement is the <em>written evidence</em> of that agreement.</p>", "check": {"question": "Which of these must be included in a Statement of Employment Particulars?", "options": ["The employee''s school exam results", "Start date, job title, hours, and pay", "The employer''s annual company profits", "A list of all other employees'' salaries"], "answer": 1, "explain": "The statement must include key terms such as start date, job title, hours, pay, holiday entitlement, sick pay, pension rights, and notice periods — not personal or unrelated company information."}}, {"title": "Impact of Employment Law on Businesses", "html": "<p>Businesses are affected by employment law in both positive and negative ways. It is important to evaluate both sides for exam questions.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Benefits of Complying</div>\n    <div class=\"pro-item\"><strong>Motivated workforce:</strong> Workers see the business as a good employer and are more productive, improving efficiency.</div>\n    <div class=\"pro-item\"><strong>Better staff retention:</strong> Workers treated fairly are less likely to leave, reducing recruitment and training costs.</div>\n    <div class=\"pro-item\"><strong>Easier recruitment:</strong> A business with a good reputation for fair treatment attracts a wider pool of applicants.</div>\n    <div class=\"pro-item\"><strong>Avoids legal penalties:</strong> Complying means the business avoids costly fines, compensation payments, and tribunal proceedings.</div>\n    <div class=\"pro-item\"><strong>Strong brand reputation:</strong> Ethical employment practices can positively affect customer perception and sales revenue.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Costs of Complying</div>\n    <div class=\"con-item\"><strong>Higher wage costs:</strong> Limits on hours mean hiring more staff to cover the same workload; minimum wage rises increase the wage bill.</div>\n    <div class=\"con-item\"><strong>Administration costs:</strong> Businesses must write recruitment policies, produce contracts, and monitor compliance — this requires time and possibly specialist staff.</div>\n    <div class=\"con-item\"><strong>Court costs:</strong> If taken to a tribunal, the business must pay for legal representation even if found not guilty.</div>\n    <div class=\"con-item\"><strong>Fines and compensation:</strong> If found guilty of breaking employment law, a business must pay fines or large compensation awards (e.g. Sberbank paid over £3 million).</div>\n    <div class=\"con-item\"><strong>Reputational damage:</strong> Bad publicity from tribunal cases can lead to a fall in sales and difficulty recruiting future staff.</div>\n  </div>\n</div>", "check": {"question": "Which of the following is a genuine BUSINESS benefit of complying with employment law (not just an employee benefit)?", "options": ["Employees feel happier at work", "Easier recruitment due to reputation", "Workers get more holiday days", "Staff are treated with more respect"], "answer": 1, "explain": "Examiners want business-level outcomes — easier recruitment, lower staff turnover, avoiding fines, and stronger reputation — not statements about how employees feel, which are not direct business benefits."}}, {"title": "Employment Tribunals & Trade Unions", "html": "<p>If a worker feels their employment rights have been breached, they can take their employer to an <strong>employment tribunal</strong>.</p>\n<ul>\n  <li>A tribunal is a panel including a <strong>legally qualified chairperson</strong> and other experts</li>\n  <li>It hears evidence from both the employee and employer</li>\n  <li>It can <strong>impose fines, award compensation</strong>, and order costs to be paid</li>\n  <li>Workers are often supported by a <strong>trade union</strong>, which provides legal advice and may fund legal representation</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Sberbank Sex Discrimination</h4>\n  <p>Svetlana Lokhova, a highly regarded investment banker, was awarded over £3 million after an employment tribunal found she had been subjected to <strong>sex discrimination</strong> at Sberbank''s London office. Her direct manager sent derogatory emails about her to colleagues and clients. The case damaged Sberbank''s reputation, cost significant legal fees, and led to reduced staff morale and recruitment challenges.</p>\n</div>", "check": {"question": "What support can a trade union provide to a worker who believes their employment rights have been breached?", "options": ["Legal advice and possible tribunal funding", "A guaranteed pay rise", "Automatic promotion to a management role", "Permission to break workplace rules"], "answer": 0, "explain": "Trade unions represent the interests of their members by offering legal advice and, in many cases, funding legal representation at an employment tribunal."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Contract of Employment", "definition": "A legal agreement between an employer and an employee — formed when a job offer is accepted. Does not need to be in writing."}, {"term": "Statement of Employment Particulars", "definition": "A written document detailing the main terms of employment. Must be given on or before the first day of work. It is evidence of the contract, not the contract itself."}, {"term": "Equality Act 2010", "definition": "Brought together 116 pieces of legislation to protect workers from discrimination based on gender, race, disability, sexual orientation, religion, and age."}, {"term": "Working Time Directive", "definition": "Limits employees to an average of 48 hours per week over a 17-week period. Does not apply to self-employed people."}, {"term": "Holiday Entitlement Formula", "definition": "Days worked per week × 5.6 = annual holiday entitlement. E.g. 5 days × 5.6 = 28 days."}, {"term": "Average Hours Formula", "definition": "Total hours worked ÷ 17 = average weekly hours. Must be below 48 for the employer to comply with the law."}, {"term": "Opt Out", "definition": "A worker''s voluntary choice to work more than 48 hours per week. Cannot be forced by the employer."}, {"term": "Employment Tribunal", "definition": "A panel that hears cases where employment rights may have been breached. Can award compensation, impose fines, and order costs."}, {"term": "Trade Union", "definition": "An organisation that represents workers, providing legal advice and representation at employment tribunals."}, {"term": "Equal Pay", "definition": "Men and women must be paid the same for work of equal value. Part of the Equality Act 2010."}, {"term": "Indirect Discrimination", "definition": "A neutral policy that disproportionately disadvantages members of a protected group — e.g. locking a prayer room."}, {"term": "Why comply with employment law?", "definition": "Benefits: motivated staff, better retention, easier recruitment, good reputation. Costs: higher wages, admin, court costs, fines."}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of the following is true about a contract of employment?", "options": ["An employer must give a worker a written contract of employment", "An employer must give a worker a written statement of particulars", "An employer does not have a contract with an employee until the worker has been given a written statement", "An employer can cancel a contract of employment without notice at any time"], "answer": 1, "explain": "Correct: Employers are legally required to provide a written statement of employment particulars on or before the first day of work. A contract of employment can be verbal — it exists as soon as the job offer is accepted, not when a written document is signed."}, {"question": "Which of the following would break discrimination laws?", "options": ["An employer pays a female sales manager more than a male salesperson who has made fewer sales", "An employer promotes a white person who has more experience than a similarly qualified black person", "An employer does not send a gay man on a training course attended by all heterosexual workers doing the same job", "An employer spends money providing wheelchair access for workers"], "answer": 2, "explain": "Correct: Excluding a gay man from training available to all heterosexual colleagues doing the same job is direct sexual orientation discrimination. A is fine as it is merit-based. B is fine as experience is a legitimate reason. D is actually required by law for disability access."}, {"question": "The working time directive states employers cannot normally ask workers to work more than an average of 48 hours per week in a 17-week period. In which case has the employer broken the law?", "options": ["An employer asks a worker to work 54 hours for 10 weeks then 36 hours for 7 weeks", "An employer asks a worker to work 714 hours in a 17-week period", "An employer asks a worker to work 850 hours in a 17-week period", "An employer asks a worker to work 60 hours for 9 weeks and 34 hours for 8 weeks"], "answer": 2, "explain": "Correct: 850 &divide; 17 = 50 hours per week — this exceeds the 48-hour average. A = (54×10 + 36×7) &divide; 17 = 792 &divide; 17 = 46.6 hrs ✓. B = 714 &divide; 17 = 42 hrs ✓. D = (60×9 + 34×8) &divide; 17 = 812 &divide; 17 = 47.8 hrs ✓."}, {"question": "Which of the following is NOT a benefit to a business of complying with employment laws?", "options": ["Workers may be better motivated", "Worker retention is likely to be better", "It will be easier to recruit new workers", "There may be costs to the business"], "answer": 3, "explain": "Correct: Costs are a drawback of complying with employment law, not a benefit. All the others (motivation, retention, easier recruitment) are genuine business benefits of treating staff fairly and legally."}, {"question": "A contract of employment is:", "options": ["A diagram showing the formal lines of authority in a business", "A formal document outlining the objectives of a business", "A law that makes discrimination in the workplace illegal", "A legal agreement between an employer and an employee"], "answer": 3, "explain": "Correct: A contract of employment is a legal agreement between an employer and an employee formed when a job offer is accepted. It does not have to be in writing to exist. The Equality Act is the law against discrimination (C), and an organisational chart shows lines of authority (A)."}, {"question": "Which one of the following is required by law?", "options": ["All employees must be given a voucher for a free eyesight test each year", "Employees who work from home must work a maximum of 16 hours a week", "Everyone who is self-employed must have private medical insurance", "Full-time employees must be given at least 5.6 weeks paid holiday per year"], "answer": 3, "explain": "Correct: All workers (not just full-time) are legally entitled to 5.6 weeks of paid holiday per year under UK law. Free eyesight tests apply only to screen-based workers (A), there is no 16-hour homeworking limit (B), and self-employed people are not required to have medical insurance (C)."}, {"question": "Emma worked 782 hours in a 17-week period. What is her average weekly hours?", "options": ["0.96 hours per week", "16.29 hours per week", "46 hours per week", "13,294 hours per week"], "answer": 2, "explain": "Correct: 782 &divide; 17 = 46 hours per week. This is below the 48-hour legal limit, so no law has been broken. Option A divides 17 by 782 (wrong way round). Option B divides 782 by 48. Option D multiplies instead of divides."}, {"question": "The Equality Act 2010 protects workers from discrimination based on which of the following?", "options": ["Their salary level and number of years of experience", "Their race, gender, disability, sexual orientation, religion and age", "The number of hours they work per week", "Their qualifications and level of education"], "answer": 1, "explain": "Correct: The Equality Act 2010 protects workers from discrimination on the grounds of race, gender, disability, sexual orientation, religion or belief, age, and marital status. Salary, experience, hours worked, and qualifications are not protected characteristics under the Act."}, {"question": "Which of the following correctly describes the Working Time Directive?", "options": ["It requires all workers to work exactly 40 hours per week", "It prevents employers asking workers to work more than 48 hours average per week over 17 weeks, though workers may opt out", "It applies equally to both employees and self-employed workers", "It sets a minimum of 30 days paid holiday for all workers"], "answer": 1, "explain": "Correct: The Working Time Directive limits the average working week to 48 hours over 17 weeks, but workers can voluntarily opt out. It does NOT apply to self-employed people (C is wrong), does not set a fixed 40-hour week (A is wrong), and holiday entitlement is 5.6 weeks — not 30 days (D is wrong)."}, {"question": "A business that is found guilty of sex discrimination by an employment tribunal could face which consequence?", "options": ["A warning letter from the government with no financial penalty", "Having to pay compensation to the affected employee and suffering reputational damage", "Being required to close its business for six months", "Losing its business licence permanently"], "answer": 1, "explain": "Correct: An employment tribunal can award compensation to the affected worker and order the business to pay legal costs. This also causes significant reputational damage which can lead to a fall in sales and difficulty recruiting. Businesses are not closed or lose licences for discrimination."}, {"question": "A worker who works 3 days per week is entitled to how many days of paid holiday per year?", "options": ["28 days", "16.8 days", "14 days", "5.6 days"], "answer": 1, "explain": "Correct: Holiday entitlement = days worked per week &times; 5.6. So 3 &times; 5.6 = 16.8 days. 28 days is for a full-time worker (5 days × 5.6). The formula always uses 5.6 — the number of weeks entitlement — multiplied by days worked."}, {"question": "Which of the following is an example of indirect discrimination?", "options": ["Refusing to hire a woman because she is female", "Paying a black employee less than a white employee doing the same job", "Locking a prayer room so Muslim workers must request a key and sign a book each time they pray", "Dismissing an employee for poor performance"], "answer": 2, "explain": "Correct: The Tesco prayer room case is an example of indirect discrimination — a policy that appears neutral but disproportionately disadvantages members of a particular religion. A and B are examples of direct discrimination. D is lawful dismissal for performance reasons."}]}, "fib": {"enabled": true, "questions": [{"text": "The [Equality] Act 2010 brought together 116 pieces of legislation to protect workers from discrimination."}, {"text": "A worker who works five days per week is entitled to [28] days of paid holiday per year."}, {"text": "The Working Time Directive limits workers to an average of [48] hours per week over a [17] week period."}, {"text": "Holiday entitlement is calculated by multiplying days worked per week by [5.6]."}, {"text": "A contract of employment is formed when a job offer is [accepted] — it does not need to be in [writing]."}, {"text": "The statement of employment particulars must be given to new employees on or before their [first] day of work."}, {"text": "Workers can voluntarily [opt out] from the 48-hour working week limit if they choose to work longer hours."}, {"text": "The Working Time Directive does NOT apply to [self-employed] people — only to employees."}, {"text": "An employment [tribunal] is a panel that hears cases where employment laws may have been broken."}, {"text": "If a firm is found guilty of discrimination it may have to pay [compensation] to the worker and suffer damage to its [reputation]."}, {"text": "Under the Equality Act, a worker cannot be discriminated against because of their [race], gender, disability, sexual orientation, religion or [age]."}, {"text": "Workers must receive a [20] minute rest break every six hours under the Working Time Directive."}]}, "tf": {"enabled": true, "questions": [{"statement": "A contract of employment must be in writing to be legally valid.", "answer": false, "explain": "FALSE. A contract of employment is formed the moment a job offer is accepted — verbally or in writing. The written document is the Statement of Employment Particulars, which is evidence of the contract, not the contract itself."}, {"statement": "All workers in the UK are legally entitled to 5.6 weeks of paid holiday per year.", "answer": true, "explain": "TRUE. The law guarantees 5.6 weeks of paid holiday for all workers. For a full-time worker (5 days/week) this equals 28 days, including bank holidays."}, {"statement": "The Working Time Directive applies to both employees and self-employed people.", "answer": false, "explain": "FALSE. The Working Time Directive applies to employees only. Self-employed people are not covered, meaning an employer who hires a self-employed worker cannot be held responsible for the hours they work."}, {"statement": "A worker who clocks 914 hours over a 17-week period is working an average of over 48 hours per week.", "answer": true, "explain": "TRUE. 914 &divide; 17 = 53.76 hours per week, which exceeds the 48-hour legal limit. The employer would be breaking the Working Time Directive unless the worker has voluntarily opted out."}, {"statement": "Employers are always allowed to refuse time off for religious observance.", "answer": false, "explain": "FALSE. While there is no automatic right to time off for every religious festival, employers who refuse leave specifically because of an employee''s religion risk direct or indirect religious discrimination under the Equality Act 2010."}, {"statement": "A Statement of Employment Particulars must be provided to new employees on or before their first day of work.", "answer": true, "explain": "TRUE. Since April 2020, employers must provide the written statement of employment particulars on or before the employee''s first day of work. This was changed from the previous two-month deadline."}, {"statement": "A worker can be legally dismissed by their employer for refusing to work more than 48 hours per week.", "answer": false, "explain": "FALSE. Employers cannot dismiss a worker for refusing to exceed the 48-hour average weekly limit. Workers have the legal right to stay within the limit. Dismissal for this reason would be unlawful."}, {"statement": "The Equality Act 2010 protects workers from discrimination during recruitment and selection, not just once they are employed.", "answer": true, "explain": "TRUE. The Equality Act 2010 covers the full employment relationship — including job advertisements, interviews, selection, pay, promotion, training, and dismissal. Employers can be taken to a tribunal for discriminatory recruitment practices."}, {"statement": "Under the Working Time Directive, workers under 18 can be asked to work up to 48 hours per week on average.", "answer": false, "explain": "FALSE. Workers under 18 have a lower limit — they can only work a maximum of 40 hours per week (8 hours per day). They also cannot opt out of this limit."}, {"statement": "Businesses with strong anti-discrimination policies tend to find it easier to recruit new workers.", "answer": true, "explain": "TRUE. Businesses with a good reputation for treating staff fairly attract a wider pool of applicants. Talented individuals are more likely to apply to businesses known for equal treatment, reducing the cost and difficulty of recruitment."}, {"statement": "A trade union can provide legal advice and pay for legal representation for members at an employment tribunal.", "answer": true, "explain": "TRUE. Trade unions support members when employment rights may have been breached. They offer legal advice and may fund legal representation at tribunals — a significant benefit of union membership."}]}, "misc": {"enabled": true, "items": [{"myth": "A contract of employment must be in writing to exist.", "truth": "A contract of employment is formed the moment a job offer is accepted — verbally is enough. The written document is the Statement of Employment Particulars, which is evidence of the contract, not the contract itself.", "check": {"question": "When does a contract of employment legally come into existence?", "options": ["Only after the first day of work", "Only once the Statement of Particulars is issued", "Only once it is signed in writing", "The moment a job offer is accepted"], "answer": 3, "explain": "A contract is formed as soon as a job offer is accepted, even verbally — it does not need to be written down to be legally binding."}}, {"myth": "The Statement of Employment Particulars IS the contract of employment.", "truth": "They are different things. The contract is the legal agreement (formed verbally or in writing). The statement is a written document that records the main terms of that contract. Students often mix these up in exams.", "check": {"question": "What is the relationship between the contract of employment and the Statement of Particulars?", "options": ["The statement replaces the need for a contract", "The contract is only valid after the statement is signed", "The statement is evidence of the contract, not the contract", "They are the same document"], "answer": 2, "explain": "The contract is the legal agreement itself. The statement is a separate written document that records its main terms — evidence of the contract, not the contract."}}, {"myth": "The Working Time Directive applies to everyone, including self-employed workers.", "truth": "The directive only applies to employees. Self-employed people are not covered, so employers cannot be held responsible for the hours a self-employed contractor works.", "check": {"question": "Does the Working Time Directive apply to self-employed workers?", "options": ["Only if they work more than 48 hours", "Only in certain industries", "Yes, equally to everyone", "No — it only applies to employees"], "answer": 3, "explain": "The Working Time Directive applies to employees only. Self-employed people are not covered by the 48-hour average limit."}}, {"myth": "Employers can always refuse time off for prayer or religious festivals.", "truth": "Refusing leave specifically because of an employee''s religion risks a discrimination claim. Employers do not have to grant every request, but a blanket refusal based on religion is likely to be indirect discrimination.", "check": {"question": "What risk does an employer take if they always refuse time off requested for religious reasons?", "options": ["A possible indirect discrimination claim", "No risk — employers can always refuse", "Nothing, as long as it applies to all staff equally", "A fine from the Working Time Directive"], "answer": 0, "explain": "A blanket refusal of time off specifically because of religion can amount to indirect discrimination, even if the policy appears neutral on the surface."}}, {"myth": "Writing ''fair pay'' or ''treating employees fairly'' is a valid answer when asked for an aspect of employment law.", "truth": "Examiners will not award marks for these vague ethical statements. You must name a specific legal aspect, such as ''minimum wage'', ''discrimination law'', ''working hours'', or ''holiday entitlement''.", "check": {"question": "Why would an exam answer of ''treating employees fairly'' score zero marks?", "options": ["It is too long an answer", "It''s spelled incorrectly", "It only applies to full-time workers", "Too vague and ethical, not a named law"], "answer": 3, "explain": "Examiners need a specific, named legal aspect (e.g. discrimination, working hours, minimum wage) — vague ethical statements about fairness do not name an actual law."}}, {"myth": "Giving two types of discrimination (e.g. racism and ageism) counts as two separate aspects of employment law.", "truth": "Examiners treat these as repetitions of the same point — both are discrimination. To get two marks, give two different aspects, such as ''discrimination'' AND ''working hours''.", "check": {"question": "If a student writes ''racism'' and ''ageism'' as their two aspects of employment law, how many marks do they get?", "options": ["1 mark — both are discrimination, a repeated point", "2 marks — they are different forms of discrimination", "0 marks — neither is a valid aspect", "3 marks — bonus for detail"], "answer": 0, "explain": "Racism and ageism are both types of discrimination, so writing both only counts as one valid point. To score 2 marks, you need two genuinely different aspects, e.g. discrimination AND working hours."}}, {"myth": "Workers who opt out of the 48-hour limit can be forced to work unlimited hours by their employer.", "truth": "Opting out must be completely voluntary. Employers cannot force workers to opt out, and cannot dismiss or punish a worker who refuses to opt out.", "check": {"question": "Can an employer force a worker to opt out of the 48-hour limit?", "options": ["Yes, if the worker is paid extra", "No — opting out must be voluntary", "Yes, if business needs require it", "Yes, but only for new employees"], "answer": 1, "explain": "Opting out of the 48-hour limit must be a free, voluntary choice by the worker. Employers cannot force it, and cannot punish a worker for refusing to opt out."}}, {"myth": "Employment law only affects large businesses with many employees.", "truth": "Employment law applies to ALL businesses regardless of size. Even a sole trader taking on one employee must comply with rules on contracts, minimum wage, working hours, and anti-discrimination law.", "check": {"question": "Does employment law apply to a sole trader who hires just one employee?", "options": ["Only if the business has over 10 employees", "No — only large businesses are affected", "Only if the employee works full-time", "Yes — employment law applies to every business"], "answer": 3, "explain": "Employment law applies to every business, no matter how small — even a sole trader hiring a single employee must comply with contract, minimum wage, working hours, and discrimination rules."}}, {"myth": "When asked for an advantage to the BUSINESS of having an anti-discrimination policy, students write ''employees feel safer or happier''.", "truth": "Examiners reject answers about employee feelings as they are not directly an advantage to the business. Instead, write about business-level outcomes: easier recruitment, lower staff turnover, stronger reputation, or higher productivity.", "check": {"question": "Why does ''employees feel happier'' NOT count as a business advantage in an exam answer?", "options": ["It''s not specific enough about feelings", "It is only true for large businesses", "An employee outcome, not a business outcome", "Happiness cannot be measured"], "answer": 2, "explain": "Exam answers need business-level outcomes — easier recruitment, lower staff turnover, stronger reputation, higher productivity — not statements about how employees feel, which examiners do not credit as a direct business benefit."}}]}, "tips": {"enabled": true, "items": [{"title": "Be Specific — Name the Law, Not the Feeling", "html": "\n      <p>A ''State'' or ''Identify'' question needs one clear, specific point per mark. Do not write vague or ethical answers — examiners will award <strong>zero marks</strong> for these.</p>\n\n      <p><strong>❌ Bad Answers (0 marks):</strong></p>\n      <ul>\n        <li>\"Fair pay\" — this is an ethical point, not a legal one</li>\n        <li>\"Treated fairly\" — too vague, not a legal requirement</li>\n        <li>\"Employment rights\" — too broad, no specific law named</li>\n        <li>\"Pay\" or \"how much they are paid\" — too vague</li>\n      </ul>\n\n      <p><strong>✅ Good Answers (1 mark each):</strong></p>\n      <ul>\n        <li>\"Discrimination / equal pay / disability rights\"</li>\n        <li>\"Working hours / limit on hours worked\"</li>\n        <li>\"Minimum/living wage\"</li>\n        <li>\"Holiday entitlement\"</li>\n        <li>\"Contract of employment / statement of particulars\"</li>\n        <li>\"Maternity/paternity pay\"</li>\n      </ul>\n\n      <p>⚠️ <strong>Examiner Warning:</strong> If a question asks for <em>two</em> aspects and you write ''racism'' and ''ageism'', you will only get <strong>1 mark</strong> — both are types of discrimination and count as the same point.</p>\n    ", "check": {"question": "Which of these would score a mark in a ''State an aspect of employment law'' question?", "options": ["\"Employment rights\"", "\"Discrimination\"", "\"Fair pay\"", "\"Treated fairly\""], "answer": 1, "explain": "Only specific, named legal aspects like discrimination, minimum wage, or holiday entitlement score marks. Vague ethical phrases like ''fair pay'' or ''treated fairly'' score zero."}}, {"title": "Knowledge + Application = Full Marks", "html": "\n      <p>A 2-mark ''Explain'' question needs two things: a point of <strong>knowledge</strong> about employment law AND an <strong>application</strong> to the specific business in the case study.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>K (1 mark):</strong> State the employment law / aspect</li>\n        <li><strong>APP (1 mark):</strong> Link it directly to the named business</li>\n      </ul>\n\n      <p>⚠️ <strong>Critical Rule:</strong> You cannot earn the application mark without the knowledge mark first. Always make your point of knowledge before applying it.</p>\n\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n      <em>\"Employment law means Greggs cannot discriminate.\"</em><br/>\n      — No application to the business context.</p>\n\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"Employment law ensures that all 20,000 Greggs employees (APP) are not discriminated against on grounds such as disability or ethnicity (K).\"</em></p>\n\n      <p><strong>Sentence Starter:</strong><br/>\n      \"Employment law means that [business name] must… [specific legal requirement], which affects the business because…\"</p>\n    ", "check": {"question": "What is missing from this 2-mark answer: \"Employment law means Greggs cannot discriminate\"?", "options": ["A case study reference", "An application linked to Greggs", "Nothing — it scores full marks", "A formula"], "answer": 1, "explain": "This answer only gives the knowledge point (K). To earn both marks it needs an application — a specific link to the named business, such as Greggs'' 20,000 employees."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n      <p>A 3-mark ''Analyse'' question requires three separate steps. Missing any one step means missing a mark. The most common mistake is failing to reach the <strong>impact</strong> stage.</p>\n\n      <p><strong>The Three-Step Formula:</strong></p>\n      <ul>\n        <li><strong>U (1 mark):</strong> State and explain the employment law point</li>\n        <li><strong>APP (1 mark):</strong> Apply it directly to the specific business using details from the case study</li>\n        <li><strong>AN (1 mark):</strong> State the financial or operational impact on the business — costs, revenue, reputation, etc.</li>\n      </ul>\n\n      <p>🚫 <strong>Knowledge Dumping Alert:</strong> Do NOT just write everything you know about employment law. Examiners reward analysis — following the chain of impact — not volume of facts.</p>\n\n      <p><strong>The \"So What?\" Rule:</strong> After every sentence, ask yourself \"So what does this mean for the business?\" Keep pushing until you reach a bottom-line impact.</p>\n\n      <p><strong>❌ Bad Answer:</strong><br/>\n      <em>\"Saranne must not discriminate against workers. This is because the Equality Act says so.\"</em><br/>\n      — Knowledge only. No application. No analysis. = 1 mark.</p>\n\n      <p><strong>✅ Model Answer (3 marks):</strong><br/>\n      <em>\"Employers must ensure equality of opportunity during recruitment (U). Saranne, who is opening a new bookshop and hiring three employees for the first time (APP), must make sure her job advertisement does not specify preferences based on age or gender. If she breaks this law, she could face a tribunal and be forced to pay compensation, which would significantly increase her start-up costs and damage her reputation before the business has even opened (AN).\"</em></p>\n\n      <p><strong>Sentence Starters:</strong><br/>\n      U: \"Employment law requires that…\"<br/>\n      APP: \"In the case of [business name], who [context from case study]…\"<br/>\n      AN: \"This means that… leading to a rise in costs / fall in profit / damage to reputation…\"</p>\n    ", "check": {"question": "What are the three steps required for full marks on a 3-mark Analyse question?", "options": ["Knowledge, Application, Analysis", "Two examples and an evaluation", "Definition, Example, Conclusion", "Knowledge repeated three times"], "answer": 0, "explain": "The three-step formula is U (state the law) → APP (apply it to the named business) → AN (explain the financial or operational impact). Missing the final impact step is the most common way to lose a mark."}}, {"title": "Two Full Chains — No Conclusion Needed", "html": "\n      <p>A 6-mark question is simply two 3-mark analyses written back-to-back. You need <strong>two separate employment law impacts</strong>, each fully developed with U → APP → AN.</p>\n\n      <p><strong>Structure:</strong></p>\n      <ul>\n        <li><strong>Point 1:</strong> U + APP + AN (3 marks)</li>\n        <li><strong>Point 2:</strong> U + APP + AN (3 marks)</li>\n      </ul>\n\n      <p>⚠️ <strong>Warning:</strong> There are <strong>zero marks</strong> available for a conclusion or evaluation in a 6-mark question. Do not write one — it wastes time.</p>\n\n      <p>⚠️ <strong>Warning:</strong> Do not make two points about the same aspect of employment law (e.g. two points about discrimination). Choose two different laws or impacts.</p>\n\n      <p><strong>Good pairings of points to use:</strong></p>\n      <ul>\n        <li>Discrimination law + Working time directive</li>\n        <li>Minimum wage / wage costs + Reputation / recruitment impact</li>\n        <li>Anti-discrimination costs + Tribunal / compensation costs</li>\n      </ul>\n\n      <p><strong>Sentence Starters (Point 1):</strong><br/>\n      \"One way employment law impacts [business] is… This means… As a result, the business will…\"</p>\n\n      <p><strong>Sentence Starters (Point 2):</strong><br/>\n      \"A second way employment law affects [business] is… Because [case study detail]… This could lead to…\"</p>\n    ", "check": {"question": "Should you write a conclusion or evaluation at the end of a 6-mark Analyse question?", "options": ["No — no marks for a conclusion", "Only if you have time left", "Yes, but only one sentence", "Yes — it''s worth an extra mark"], "answer": 0, "explain": "A 6-mark question is two separate 3-mark analysis chains. There are no marks for a conclusion or evaluation here — writing one only wastes exam time."}}, {"title": "Master the Formulas Before the Exam", "html": "\n      <p>There are two calculations you must know for this topic. Practise them until they are automatic.</p>\n\n      <p><strong>Formula 1 — Average Weekly Hours:</strong></p>\n      <ul>\n        <li>Total hours worked &divide; 17 = Average hours per week</li>\n        <li>If the result is <strong>above 48</strong> → law is broken (unless the worker opted out)</li>\n        <li>If the worker is <strong>self-employed</strong> → the law does not apply regardless</li>\n      </ul>\n\n      <p><strong>Formula 2 — Holiday Entitlement:</strong></p>\n      <ul>\n        <li>Days worked per week &times; 5.6 = Days holiday per year</li>\n        <li>Full-time (5 days): 5 × 5.6 = <strong>28 days</strong></li>\n        <li>Part-time (3 days): 3 × 5.6 = <strong>16.8 days</strong></li>\n      </ul>\n\n      <p>⚠️ <strong>Common mistakes:</strong></p>\n      <ul>\n        <li>Dividing 17 by the hours (wrong way round)</li>\n        <li>Forgetting to check if the worker is self-employed</li>\n        <li>Thinking 48 hours is a hard weekly cap rather than a 17-week average</li>\n      </ul>\n    ", "check": {"question": "A part-time worker works 2 days per week. Using the holiday entitlement formula, how many days holiday are they entitled to?", "options": ["2 days", "5.6 days", "11.2 days", "28 days"], "answer": 2, "explain": "Holiday entitlement = days worked per week × 5.6. So 2 × 5.6 = 11.2 days."}}]}, "exam": {"enabled": true, "questions": [{"question": "State two aspects of employment law that may affect a business. [2 marks]", "marks": 2, "hint": "Think of specific legal requirements — not ethical ideas like ''fairness''. Name two different areas of law, not two versions of the same one.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a)</h5><p>One mark for each of two correct aspects of employment law. Answers do not need to relate to Clarks.</p><ul><li>Discrimination / equality (e.g. equal pay, disability, sexism, racism, ageism)</li><li>Contract of employment</li><li>Holidays</li><li>Maternity pay / paternity pay</li><li>Antenatal care</li><li>Sick pay</li><li>Working hours / days</li><li>Breaks</li><li>Minimum / living wage</li><li>Health &amp; safety</li><li>Working environment</li><li>Redundancy / dismissal (e.g. severance pay and notice)</li></ul><p><strong>Do NOT award:</strong> \"Fair pay\" (0), \"Treated fairly\" (0), \"Employment rights\" (0), \"Pay / how much they are paid\" (0) — these are ethical rather than legal requirements.</p><p><strong>Examiner''s Comment:</strong> Candidates either knew employment law and got full marks, or left the space blank. Most common correct answers were ''discrimination'', ''working hours'', and ''minimum wage''. If two answers were both types of discrimination (e.g. racism and ageism), only 1 mark was awarded as they are repetitions of the same point.</p></div>"}, {"question": "A contract of employment is:", "marks": 1, "hint": "Think about what a contract fundamentally is — a legal relationship between two parties.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — 1 mark (AO1a)</h5><p><strong>D: A legal agreement between an employer and an employee.</strong></p><ul><li><strong>Why A is wrong:</strong> A diagram showing lines of authority is an organisational chart — it has nothing to do with employment contracts.</li><li><strong>Why B is wrong:</strong> A document outlining business objectives describes a business plan or mission statement.</li><li><strong>Why C is wrong:</strong> The law making workplace discrimination illegal is the Equality Act 2010 — not a contract of employment.</li><li><strong>Why D is correct:</strong> A contract of employment is the legal agreement formed between employer and employee when a job offer is accepted. It does not have to be in writing.</li></ul></div>"}, {"question": "Explain one way that employment law may affect Greggs'' employment of workers. [2 marks]", "marks": 2, "hint": "Name a specific law or legal requirement (1 mark), then link it directly to Greggs using a detail from the case study (1 mark).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a + AO2)</h5><ul><li><strong>Knowledge (1 mark):</strong> Name a correct aspect of employment law affecting workers</li><li><strong>Application (1 mark):</strong> Link to Greggs using case study detail — no application mark without knowledge mark first</li></ul><p><strong>Knowledge may include:</strong></p><ul><li>Equality / no discrimination (e.g. disability, ethnicity, sex/gender, religion, sexual orientation)</li><li>Diversity of employees</li><li>Limit on working hours</li><li>Minimum holiday entitlement</li><li>Right to a contract</li><li>Equal pay</li><li>Right to minimum wage</li></ul><p><strong>Application may include:</strong></p><ul><li>20,000 employees</li><li>Aims to be the customers'' favourite for ''food-on-the-go'' in the UK</li><li>Team of people to keep up-to-date with changes in employment law</li><li>One of the UK''s happiest places to work</li><li>Offers part-time roles</li></ul><p><strong>Exemplar response:</strong> \"Employment law ensures that all 20,000 employees (APP) are not discriminated against (K).\"</p></div>"}, {"question": "Explain one advantage for Superdry of having a policy against discrimination in its workforce. [2 marks]", "marks": 2, "hint": "Focus on the benefit to the BUSINESS — not how employees feel. Think: what happens to productivity, recruitment, or reputation?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b + AO2)</h5><ul><li><strong>Understanding (1 mark):</strong> Explain an advantage to a business of having an anti-discrimination policy</li><li><strong>Application (1 mark):</strong> Link the advantage to Superdry using case study detail — no application mark without understanding mark first</li></ul><p><strong>Understanding may include:</strong></p><ul><li>Benefit from a range of diverse experiences / skills within the workforce</li><li>Improved business reputation</li><li>Fewer complaints / tribunal cases</li><li>Greater productivity / output</li><li>Reduced labour turnover / aid employee retention / fewer employees leave</li><li>Ability to recruit new employees more easily</li><li>Comply with employment legislation</li></ul><p><strong>Application context for Superdry:</strong> successful international brand, 135 stores, 4,800 employees, committed to high quality, competition from retailers of all sizes.</p><p><strong>Do NOT award:</strong> \"Employees feel safe\" or \"employees feel happier\" — these are not advantages to the business. Do not award vague answers like \"more people will be interested\" or \"attract more people\".</p><p><strong>Exemplar responses:</strong><br/>\"Superdry is likely to find it easier to recruit new employees (U) allowing it to fully staff its 135 stores (APP).\"<br/><br/>\"Having a policy against discrimination ensures Superdry does not breach employment laws (U), which would be damaging when competing against other clothing retailers (APP).\"</p></div>"}, {"question": "The average amount of time that Emma has worked during the 17-week period is:", "marks": 1, "hint": "Use the formula: Total hours ÷ 17 = average weekly hours.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 1 mark (AO2)</h5><p><strong>C: 46 hours per week.</strong></p><p>782 &divide; 17 = <strong>46 hours per week</strong>. This is below the 48-hour limit, so no law has been broken.</p><ul><li><strong>Why A is wrong:</strong> 0.96 comes from dividing 17 by 782 — the formula is reversed.</li><li><strong>Why B is wrong:</strong> 16.29 comes from dividing 782 by 48 — using the wrong divisor.</li><li><strong>Why D is wrong:</strong> 13,294 comes from multiplying 782 by 17 — multiplying instead of dividing.</li></ul></div>"}, {"question": "Analyse one way in which current employment legislation may impact upon the recruitment of Saranne''s new employees. [3 marks]", "marks": 3, "hint": "Name the law (U), link to Saranne''s specific situation (APP), then explain the financial or practical impact on her business (AN).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Knowledge of employment legislation impacting on the recruitment of new staff</li><li><strong>Application (1 mark):</strong> Apply to Saranne''s situation using case study detail</li><li><strong>Analysis (1 mark):</strong> Explain the impact / consequence of the legislation on the recruitment process</li></ul><p><strong>Aspects of employment law that could be used:</strong></p><ul><li>Discrimination / Equality Act — recruitment must not discriminate on grounds of race, gender, disability, religion, etc.</li><li>Right to a contract — Saranne must provide a statement of employment particulars</li><li>Hours of work — must not exceed 48-hour average</li></ul><p><strong>Exemplar response:</strong><br/>\"Employers must ensure that all applicants enjoy equality of opportunity (U). Saranne has limited experience of employment legislation and she must ensure that potential employees are not treated differently due to their ethnic origin (APP). Therefore, Saranne must plan recruitment/selection activities so that they do not give any one group an unfair advantage (AN).\"</p></div>"}, {"question": "Which one of the following is required by law?", "marks": 1, "hint": "Think about which of these is an actual legal entitlement for all workers under UK employment law.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — 1 mark (AO1a)</h5><p><strong>D: Full-time employees must be given at least 5.6 weeks paid holiday per year.</strong></p><ul><li><strong>Why A is wrong:</strong> Free eyesight tests are only required for employees who regularly use display screen equipment (DSE) — not all employees.</li><li><strong>Why B is wrong:</strong> There is no 16-hour maximum for homeworkers. The Working Time Directive''s 48-hour average applies regardless of location.</li><li><strong>Why C is wrong:</strong> Self-employed people are not required by law to have private medical insurance.</li><li><strong>Why D is correct:</strong> All workers in the UK are legally entitled to 5.6 weeks (28 days for full-time) of paid holiday per year under the Working Time Regulations.</li></ul></div>"}, {"question": "State one way in which the law affects business recruitment. [1 mark]", "marks": 1, "hint": "Think about what rules a business must follow when advertising for and selecting new employees.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a)</h5><p>One mark for a correct identification of a way the law affects business recruitment.</p><p><strong>Acceptable answers include:</strong></p><ul><li>Discrimination — businesses cannot discriminate in job advertisements or selection on grounds of gender, race, disability, religion, etc.</li><li>Right to a contract — businesses must provide a statement of employment particulars</li><li>Holidays — workers must be offered their legal entitlement</li><li>Hours of work — workers cannot be contracted to work more than 48 hours average per week</li><li>Minimum wage — the starting wage must meet at least the national minimum wage</li></ul></div>"}, {"question": "Analyse one way in which Sberbank may be affected as a result of the decision by the employment tribunal. [3 marks]", "marks": 3, "hint": "Name how the tribunal decision impacts Sberbank (U), link to the specific case details (APP), then explain the knock-on effect for the bank''s finances, reputation, or ability to operate (AN).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Identifies a way Sberbank may be affected — e.g. additional costs, reputational damage</li><li><strong>Application (1 mark):</strong> Uses specific details from the case study — cannot be awarded without understanding mark</li><li><strong>Analysis (1 mark):</strong> Explains the effect/impact of the tribunal decision on the business</li></ul><p><strong>Possible understanding points:</strong></p><ul><li>Sberbank may incur additional costs</li><li>The findings may negatively affect Sberbank''s reputation</li></ul><p><strong>Possible application points:</strong></p><ul><li>Sberbank has to pay out over £3 million in compensation</li><li>Sberbank was found to allow sex discrimination practices (emails, derogatory names)</li></ul><p><strong>Possible analysis points:</strong></p><ul><li>The rise in costs reduces profits → lower dividend payments to shareholders</li><li>Bad publicity may put off potential employees → recruitment problems</li><li>Bad publicity may put off customers → loss of sales revenue</li></ul></div>"}]}}'::jsonb),
('business', '4-1-production-processes', '4.1 Production Processes', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>These are the <strong>official OCR definitions</strong> you must know precisely for the exam. Learn them word for word.</p>\n    <ul>\n      <li><strong>Job Production:</strong> Is the process of production where products are made individually.</li>\n      <li><strong>Batch Production:</strong> Is the process of production where one type of product is made and then production is switched to make a different product.</li>\n      <li><strong>Flow Production:</strong> Is production of one product that takes place continuously using a production or assembly line. This is sometimes called mass production.</li>\n      <li><strong>Automation:</strong> Is a production process involving machinery that is not controlled by a person but usually controlled by a computer.</li>\n      <li><strong>Robotics:</strong> Is the use of robots in the process of production.</li>\n      <li><strong>Production Processes:</strong> Are the three methods or processes of production – job, batch and flow.</li>\n    </ul>", "check": {"question": "What is the key difference between automation and robotics?", "options": ["They mean the same thing; textbooks use the terms interchangeably", "Automation is the broader term; robotics is one specific type of it", "Robotics is broader; automation means only human-shaped machines", "Automation always needs a robot; robotics never involves automation"], "answer": 1, "explain": "Automation covers any computer-controlled production process. Robotics is a specific subset of automation where programmable robots perform tasks — all robotics is automation, but not all automation involves robots."}}, {"title": "Job Production", "html": "<p><strong>Job production</strong> involves producing each product individually. Each item is unique and made to meet the exact requirements of an individual customer. Products made this way are often called <strong>bespoke</strong>.</p>\n    <p><strong>Examples of job production:</strong></p>\n    <ul>\n      <li>Building a bridge, factory, or shopping centre</li>\n      <li>Craft production: paintings, pottery, sculptures</li>\n      <li>Tailoring hand-made dresses and suits</li>\n      <li>Creating an advertising campaign</li>\n      <li>Building ships and aircraft</li>\n      <li>Taking wedding photographs or making a film</li>\n      <li>Hand-crafted furniture (e.g., Louis le Glas at the Coppice Co-op)</li>\n    </ul>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>High quality:</strong> Products are usually high quality as they are made with great care and skill to meet the specific needs of the customer.</div>\n    <div class=\"pro-item\"><strong>Bespoke products:</strong> Products can be made to exactly meet the needs of individual customers, giving a strong competitive edge and justifying premium prices.</div>\n    <div class=\"pro-item\"><strong>Worker satisfaction:</strong> Workers often get more satisfaction from working on something until it is finished, which can improve motivation and reduce absenteeism.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>High production costs:</strong> Costs of production will be high as each product is individually crafted, meaning higher prices for customers.</div>\n    <div class=\"con-item\"><strong>High labour costs:</strong> Labour costs may be high because job production often requires skilled labour who command higher wages.</div>\n    <div class=\"con-item\"><strong>Slow output:</strong> Production is slow — only one item is made at a time, limiting the ability to meet large-scale or mass-market demand.</div>\n    </div>\n    </div>\n    <div class=\"case-study-box\">\n    <h4>Case Study: The Coppice Co-op Ltd</h4>\n    <p>Louis Le Glas is a skilled woodworker at the Coppice Co-op Ltd in Carnforth, Lancashire. He designs and carves unique pieces of furniture, and each piece is one-of-a-kind. Customers can have furniture made exactly as they want it — true bespoke production. The business is also fiercely concerned about sustainable production, managing woodlands through a process called coppicing.</p>\n    <p><strong>Takeaway:</strong> Job production allows Louis to charge premium prices because each piece is unique. However, it limits how many products he can make, keeping the scale of the business small.</p>\n    </div>", "check": {"question": "Why does job production typically result in higher prices for customers?", "options": ["Because the products are sold through supermarket chains at a discount", "Because each product is individually crafted, needing skilled time", "Because businesses using job production always make huge profits", "Because flow production always costs more to run than job production"], "answer": 1, "explain": "Job production is labour-intensive and requires skilled workers to make each item individually — both of which drive up costs per unit, which are then passed on through premium prices."}}, {"title": "Batch Production", "html": "<p><strong>Batch production</strong> involves producing one type of product for a period, then switching to make a different type. The business will switch back to the first product when more is needed. Machinery may need to be re-set between batches.</p>\n    <p><strong>Examples of batch production:</strong></p>\n    <ul>\n      <li>Bakeries making a batch of white bread, then switching to wholemeal</li>\n      <li>Paint manufacturing — different colours and types (e.g., Crown Paints)</li>\n      <li>Clothing manufacturers switching between different garment types</li>\n      <li>Newspapers, books, furniture, and electrical goods</li>\n    </ul>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Meets varied customer needs:</strong> Batches of different goods can be made, allowing a business to offer a range of products to different customer groups.</div>\n    <div class=\"pro-item\"><strong>Made to order:</strong> Batches can be made to meet specific orders, reducing storage costs as goods do not need to be held in stock for long periods.</div>\n    <div class=\"pro-item\"><strong>Specialist machinery:</strong> It may be possible to use specialist machines and automate parts of production, helping to save costs compared to job production.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Switching time and costs:</strong> It takes time to switch production from one batch to another. Machinery may need to be re-set, adding costs and reducing output.</div>\n    <div class=\"con-item\"><strong>Stock holding costs:</strong> It may be necessary to keep stocks of materials ready to switch production. Holding stock is a cash flow problem — money has been paid out but revenue is not yet earned.</div>\n    <div class=\"con-item\"><strong>Repetitive work:</strong> Tasks can be repetitive and boring for workers, which can reduce motivation and increase staff turnover.</div>\n    <div class=\"con-item\"><strong>Less variety than job:</strong> There is usually less product choice for customers compared with job production.</div>\n    </div>\n    </div>\n    <div class=\"case-study-box\">\n    <h4>Case Study: Crown Paints</h4>\n    <p>Crown Paints, based in Darwen, Lancashire, makes a range of paints including silk and matte emulsions, gloss paints, and primers in many colours and shades. The ingredients are mixed to make one type and colour of paint. Once this batch is finished, tins are labelled and filled. The factory then switches to produce a different colour or type of paint entirely.</p>\n    <p><strong>Takeaway:</strong> Batch production lets Crown Paints offer a huge range of colours without needing a permanently separate production line for each one. However, cleaning and resetting equipment between batches costs time and money.</p>\n    </div>", "check": {"question": "Why can switching between batches create a cash flow problem for a business?", "options": ["Because the batch machinery always breaks down mid-switch", "Because materials get stocked, so cash goes out before revenue", "Because batch production always needs more staff than flow", "Because holding stock has no effect on cash flow at all"], "answer": 1, "explain": "Holding stock ties up money — the business has paid for materials but hasn''t yet sold any finished goods made from them, creating a gap between cash going out and cash coming in."}}, {"title": "Flow Production", "html": "<p><strong>Flow production</strong> (also called <strong>mass production</strong>) involves producing one type of product continuously using a production or assembly line. The product moves along a conveyor belt and different workers or machines complete different tasks at each stage. There is no stopping.</p>\n    <p><strong>Examples of flow production:</strong></p>\n    <ul>\n      <li>Car manufacturing — Ford, Jaguar Land Rover (JLR)</li>\n      <li>Heinz baked beans — over 1 billion tins per year at their factory near Wigan</li>\n      <li>Plate glass manufacturing</li>\n      <li>Bottled drinks and canned foods produced at scale</li>\n    </ul>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Large quantities:</strong> Massive amounts can be produced continuously to meet high levels of demand in the mass market.</div>\n    <div class=\"pro-item\"><strong>Low unit costs:</strong> The cost per unit is low because the firm benefits from economies of scale — costs are spread over millions of products.</div>\n    <div class=\"pro-item\"><strong>Machinery keeps costs low:</strong> Heavy use of machinery reduces the need for large numbers of workers and lowers wage bills.</div>\n    <div class=\"pro-item\"><strong>Some flexibility:</strong> Modern computer-controlled machines can be programmed to introduce some design variation into the production run.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Quality concerns:</strong> Mass-produced goods may not always meet the high quality or individuality that some customers expect from premium products.</div>\n    <div class=\"con-item\"><strong>Very expensive to set up:</strong> The initial investment in setting up an assembly line is enormous — a major barrier to entry.</div>\n    <div class=\"con-item\"><strong>Large stock required:</strong> Large stocks of raw materials must be maintained to keep the production line running at all times.</div>\n    <div class=\"con-item\"><strong>Breakdown risk:</strong> If production stops at any point on the line (mechanical failure or strike), the entire factory may shut down — extremely costly.</div>\n    <div class=\"con-item\"><strong>Repetitive work:</strong> Assembly line jobs can be very repetitive and boring, leading to lower motivation and higher staff turnover.</div>\n    </div>\n    </div>\n    <div class=\"case-study-box\">\n    <h4>Case Study: Heinz Baked Beans</h4>\n    <p>Heinz makes its baked beans at a factory just outside Wigan. Over 1 billion tins are made each year using a continuous flow method. The beans are mixed with sauce, put into tins that are sealed, then cooked in ovens. From there, the tins go on to be labelled. This entire process runs every day, throughout the year, without stopping.</p>\n    <p><strong>Takeaway:</strong> Flow production allows Heinz to keep the price of baked beans extremely low by producing at massive scale. However, any breakdown on the production line could halt the entire factory and cost millions in lost output and missed orders.</p>\n    </div>", "check": {"question": "How many tins of baked beans does Heinz produce per year at its Wigan factory, and what does this illustrate about flow production?", "options": ["1 million — suits only very small-scale firms", "Over 1 billion — shows massive scale, low unit cost", "100,000 — shows flow is slower than batch overall", "No figure is given anywhere in the study"], "answer": 1, "explain": "Heinz produces over 1 billion tins per year — a perfect illustration of how flow production enables vast output at low unit costs through economies of scale, running continuously without stopping."}}, {"title": "Automation, Computers & Robotics in Production", "html": "<p>Technology has increasingly been introduced into production. The three key forms are <strong>automation</strong>, <strong>computers</strong>, and <strong>robotics</strong>.</p>\n    <p><strong>Automation</strong> means production is controlled by computer rather than by a human worker. Workers'' roles shift to overseeing the computer systems and checking that production is occurring correctly. Examples include:</p>\n    <ul>\n      <li>Crown Paints — the entire canning process runs automatically, with tins being labelled, filled, weighed, and sealed by machines</li>\n      <li>Autopilot on aircraft and ships</li>\n      <li>Automated banking payments and online transactions</li>\n      <li>School systems automatically sending attendance alerts to parents</li>\n    </ul>\n    <p><strong>Computers</strong> are used across service industries to automate processes previously done by people — online banking (Android Pay, Apple Pay), insurance claims, energy billing, and concert ticket booking.</p>\n    <p><strong>Robotics</strong> is a specific type of automation where a computer programs a robot to carry out specific tasks. Around <strong>65% of robot use</strong> is in car manufacturing (welding, painting, lifting). Robots are also used in:</p>\n    <ul>\n      <li>Food, electronics, plastics, and medical sectors</li>\n      <li>Hotel receptions and hospitals (collecting laundry)</li>\n      <li>Dangerous environments — robots entered the Fukushima nuclear site after the 2014 explosion; humans could not safely do so</li>\n      <li>Surgery — robots assist surgeons with high-precision operations</li>\n    </ul>\n    <p>Thanks to <strong>artificial intelligence (AI)</strong>, robots are increasingly capable of skilled and complex tasks: writing reports, making decisions, and even performing surgery autonomously. The World Economic Forum (2020) predicted that by 2025, technology would eliminate 85 million jobs — but create 97 million new ones, a net gain of 12 million.</p>\n    <div class=\"case-study-box\">\n    <h4>Case Study: Amazon Warehouses</h4>\n    <p>Amazon has over 100,000 robots in its UK warehouses. When a customer places an order, the request is automatically passed to a robot. The robot follows digital patterns on the warehouse floor to locate the correct shelf and brings it to a human worker, who boxes and ships the item. Previously, human ''pickers'' walked many miles per day to do this manually.</p>\n    <p>Amazon''s UK sales rose by 51% to £19.4 billion in 2020. Employment actually grew by 3,000 workers despite the robot introduction. The robots enabled Prime next-day delivery. However, worker injury rates increased, and robots represent a breakdown risk.</p>\n    <p><strong>Takeaway:</strong> Amazon''s robots dramatically increased productivity and created a major competitive advantage (next-day delivery). But technology does not simply replace all workers — it often creates new roles and new problems.</p>\n    </div>", "check": {"question": "Approximately what percentage of robot use globally is in car manufacturing?", "options": ["15%", "35%", "65%", "90%"], "answer": 2, "explain": "Around 65% of all robot use is in car manufacturing — for welding, painting, and lifting. This makes car production the single biggest user of robotics globally."}}, {"title": "Advantages & Disadvantages of Technology in Production", "html": "<p>For evaluation questions, you must be able to weigh up <strong>both sides</strong> of using technology. Here is a comprehensive breakdown.</p>\n    <div class=\"two-col\">\n    <div>\n    <div class=\"col-head\">✓ Advantages of Technology</div>\n    <div class=\"pro-item\"><strong>Lower labour costs:</strong> Fewer workers are needed, reducing wage costs. Average costs of production fall, helping the business keep prices competitive in the market.</div>\n    <div class=\"pro-item\"><strong>Greater accuracy:</strong> Machines are more accurate than humans — improving product quality and reducing costly waste.</div>\n    <div class=\"pro-item\"><strong>Flexible production:</strong> Computer-controlled machines can be reprogrammed to produce a variety of products without restructuring the factory.</div>\n    <div class=\"pro-item\"><strong>Works 24/7:</strong> Machines work 24 hours a day, 7 days a week — unlike humans who need rest, take sick days, and go on holiday.</div>\n    <div class=\"pro-item\"><strong>Handles dangerous tasks:</strong> Machines can carry out dangerous or boring jobs that workers may be unable or unwilling to do, improving workplace safety.</div>\n    <div class=\"pro-item\"><strong>New products:</strong> New technology creates entirely new products and new markets (e.g., smartphones, tablets), growing the economy.</div>\n    </div>\n    <div>\n    <div class=\"col-head\">✗ Disadvantages of Technology</div>\n    <div class=\"con-item\"><strong>Redundancy costs:</strong> Workers may be made redundant when technology is introduced, resulting in short-term redundancy payments which add to costs.</div>\n    <div class=\"con-item\"><strong>Skilled recruitment:</strong> New skilled workers to manage the technology may need to be recruited. These workers are in high demand and may command large salaries.</div>\n    <div class=\"con-item\"><strong>Training costs:</strong> Existing workers may need retraining to use new technology — an additional business expense.</div>\n    <div class=\"con-item\"><strong>Breakdown risk:</strong> Machines can break down, disrupting production — especially serious in flow production where one fault halts the entire line.</div>\n    <div class=\"con-item\"><strong>High initial cost:</strong> Buying and financing new technology is expensive. The upfront investment may take many years to recoup.</div>\n    <div class=\"con-item\"><strong>Customer and data concerns:</strong> Customers sometimes dislike automated systems (e.g., automated phone lines). Where personal data is stored, there are also security risks.</div>\n    </div>\n    </div>", "check": {"question": "According to the World Economic Forum (2020), what was the predicted NET effect of technology on jobs by 2025?", "options": ["A net loss of 85 million jobs, with no new roles created to replace them", "A net gain of 12 million jobs, since 97 million are created and 85 million eliminated", "No overall change, since technology creates and destroys roughly equal numbers of jobs", "A net loss of 97 million jobs, since automation eliminates more roles than it creates"], "answer": 1, "explain": "The World Economic Forum predicted technology would eliminate 85 million jobs but create 97 million new ones — a net gain of 12 million. This is why ''technology eliminates all jobs'' is a misconception."}}, {"title": "Choosing the Right Production Method (Evaluation)", "html": "<p>In an exam evaluation question, you must weigh up which production method is most appropriate. There is <strong>no single best method</strong> — it <em>depends on</em> the specific context of the business.</p>\n    <p><strong>Key factors that determine the right method:</strong></p>\n    <ul>\n      <li><strong>Volume of demand:</strong> High, consistent mass demand → flow. Unique, individual orders → job. Varied products in moderate quantities → batch.</li>\n      <li><strong>Price sensitivity:</strong> Customers wanting the lowest price → flow (economies of scale). Customers willing to pay a premium for uniqueness → job.</li>\n      <li><strong>Product type:</strong> Identical standardised products suit flow; varied or unique products suit job or batch.</li>\n      <li><strong>Capital investment available:</strong> Flow requires enormous set-up costs. Job requires skilled (expensive) labour. Batch sits in between.</li>\n      <li><strong>Flexibility required:</strong> Businesses needing to switch frequently between product types should use batch. Single high-volume product → flow.</li>\n    </ul>\n    <p><strong>Important evaluation point:</strong> Businesses can use a <em>combination</em> of methods. A caravan manufacturer might use job production to assemble each caravan but batch production to produce the shared components. Modern AI-driven machines are also blurring the lines between batch and flow, allowing variation in mass production.</p>\n    <p><strong>Useful \"it depends on...\" evaluation phrases:</strong></p>\n    <ul>\n      <li><em>\"This depends on whether the business can afford the high initial investment in an assembly line...\"</em></li>\n      <li><em>\"This depends on the level of demand — if the market grows significantly, flow production would lower unit costs and improve competitiveness...\"</em></li>\n      <li><em>\"This depends on whether customers in this market prioritise uniqueness and quality over low price...\"</em></li>\n      <li><em>\"This depends on whether the Montana Bakery wants to continue making the range of speciality breads it currently offers...\"</em></li>\n    </ul>", "check": {"question": "A bakery currently uses batch production for its speciality breads. A consultant recommends switching to flow production. What is the most important factor to consider before deciding?", "options": ["Whether the bakery owner personally prefers using machines rather than skilled staff", "Whether demand is high and consistent enough to justify the huge set-up cost of a flow line", "Whether rival bakeries have already switched over to using flow production themselves", "Flow production is always the right choice whenever a business wants to grow its output"], "answer": 1, "explain": "Flow production requires enormous capital investment and only makes sense when demand is very high and consistent for an identical product. A speciality bakery with varied, lower-volume orders may find batch production more appropriate — ''it depends on'' the nature and scale of demand."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Job Production", "definition": "The process of production where products are made individually, tailored to the specific needs of individual customers."}, {"term": "Batch Production", "definition": "The process of production where one type of product is made, then production switches to make a different type of product."}, {"term": "Flow Production", "definition": "Production of one product that takes place continuously using a production or assembly line. Also called mass production."}, {"term": "Automation", "definition": "A production process involving machinery controlled by a computer rather than a person."}, {"term": "Robotics", "definition": "The use of robots in the process of production — a specific type of automation."}, {"term": "Bespoke", "definition": "A product made to the exact individual specification of a customer — unique and personalised to that person''s requirements."}, {"term": "Economies of Scale", "definition": "Reductions in the average cost per unit that a large business achieves by producing in very large quantities. Flow production benefits from this."}, {"term": "Unit Cost", "definition": "The cost of producing one item. Calculated as: Total Costs ÷ Number of Units Produced."}, {"term": "Assembly Line", "definition": "A production method used in flow production where the product moves along a conveyor belt and workers/machines each complete a different task at each station."}, {"term": "Redundancy", "definition": "When a worker loses their job because the role no longer exists — often because technology has replaced it."}, {"term": "Advantages of Job Production", "definition": "High quality, bespoke products tailored to individual customers; worker satisfaction. Disadvantages: high costs and skilled labour required."}, {"term": "Advantages of Flow Production", "definition": "Low unit costs due to economies of scale; continuous 24/7 production. Disadvantages: expensive to set up; if the line stops the whole factory halts."}, {"term": "Advantages of Technology", "definition": "Works 24/7, reduces wage costs, improves accuracy, handles dangerous jobs, creates new products. Disadvantages: high initial cost, breakdown risk, redundancy costs, training needed."}]}, "mcq": {"enabled": true, "questions": [{"question": "Which is an advantage for a manufacturer of using robotics?", "options": ["Initial investment cost", "Operatives will require training", "Greater productivity", "Will not break down"], "answer": 2, "explain": "Correct answer: Greater productivity. Robots can work 24/7 without breaks, producing more output in less time and at greater consistency. B (initial investment) and C (training costs) are both disadvantages. D is incorrect — machines CAN and do break down, which is actually a key disadvantage of robotics."}, {"question": "Jenny Carson makes and ices wedding cakes individually to order. Which method of production is she most likely to use?", "options": ["Batch production", "Flow production", "Robotic production", "Job production"], "answer": 3, "explain": "Correct answer: Job production. Each wedding cake is unique and made individually to the customer''s specific requirements — the definition of job production. Batch (B) would mean switching between types; flow (C) means mass-producing identical cakes on a line; robotic production (D) is not one of the three official OCR production methods."}, {"question": "Warburton''s bakery uses batch production to make its bread. Which of the following is a disadvantage of this approach?", "options": ["The costs of production are lower than using other methods.", "It can meet the demand for different types of bread from different customers.", "It may have to reduce the different types of bread that it can offer.", "It can make bread to order so the bread does not need to be stored."], "answer": 2, "explain": "Correct answer: If managing too many product switches becomes too costly or complex, Warburton''s may be forced to limit its product range — a disadvantage. Options A, B, and D are all advantages of batch production: lower costs (A), meeting varied demand (B), and made-to-order reducing storage (D)."}, {"question": "Which of the following is NOT an example of automation?", "options": ["Beer bottles are labelled by a machine when they pass it on the production line.", "The hand-making of a wedding dress.", "A business has sensors on its doors to make them open when someone approaches.", "Customers of Vauxhall Motors can configure and order a car online which is added to production without any further input."], "answer": 1, "explain": "Correct answer: Hand-making a wedding dress is job production — carried out by a skilled human worker, not a computer-controlled machine. All other options describe processes controlled automatically by machines or computers with no direct human operation."}, {"question": "Which of these statements is FALSE?", "options": ["Modern businesses do not use job production.", "Flow production uses machines only, no workers are required at all.", "Batch production is often used by bakeries to make different kinds of bread and cakes.", "Using flow production usually results in lower unit costs than using job production."], "answer": 0, "explain": "Correct answer: It is FALSE that modern businesses do not use job production. Many modern businesses — including those running large construction projects like Crossrail — use job production. C and D are both true. B is also false (flow production still requires workers to oversee machines), but A is the most clearly false and is the intended answer."}, {"question": "Which of the following is NOT a disadvantage of automation?", "options": ["Expensive to buy, so will need to find a way of raising finance", "Machines can break down, disrupting production", "Operatives may need additional training, increasing business costs", "The machinery can be reprogrammed, making production more flexible"], "answer": 3, "explain": "Correct answer: Being reprogrammable and flexible is an ADVANTAGE of automation, not a disadvantage. Options A (high cost to buy), B (breakdown risk), and C (training costs) are all genuine disadvantages of investing in automation technology."}, {"question": "A company''s total costs are too high due to increasing wage costs as it expands. Which action would provide a long-term solution?", "options": ["Applying for an overdraft", "Automating the production process", "Employing a finance assistant", "Switching to job production"], "answer": 1, "explain": "Correct answer: Automating the production process. Automation replaces labour with machines, directly reducing wage costs long-term. An overdraft (A) only provides short-term finance and must be repaid. Employing a finance assistant (C) would add costs. Switching to job production (D) typically increases labour costs as it demands skilled workers."}, {"question": "HealthBisc Ltd predicts it will struggle to produce enough breakfast biscuits to meet growing demand. Which action could best help?", "options": ["Automate the production process", "Improve its after-sales service", "Reduce its prices", "Switch to job production"], "answer": 0, "explain": "Correct answer: Automate the production process. Automation enables machines to work 24/7, significantly increasing output and productivity to meet higher demand. Improving after-sales service (B) and reducing prices (C) are marketing decisions that do not increase production capacity. Switching to job production (D) would actually decrease output as items are made individually."}, {"question": "An entrepreneur makes individual handmade prom dresses to order. What method of production does the entrepreneur use?", "options": ["Batch", "Automated", "Flow", "Job"], "answer": 3, "explain": "Correct answer: Job production. Each dress is made individually to a specific customer''s order — the definition of job production. Automated (A) means computer-controlled machinery. Batch (B) would mean making a group of dresses of the same style then switching to another. Flow (C) means continuous mass production of identical items."}, {"question": "Which of the following is a characteristic of flow production?", "options": ["Products are made individually to customer specifications", "Production is switched between different product types", "Goods are produced continuously using an assembly line", "High labour costs due to the need for skilled workers"], "answer": 2, "explain": "Correct answer: Flow production uses a continuous assembly line to make large quantities of the same product without stopping. Option A describes job production. Option B describes batch production. Option D describes job production, which requires skilled and therefore expensive labour."}, {"question": "Which of the following is a disadvantage of flow production?", "options": ["Unit costs per product are very high", "If the production line breaks down, the entire factory may shut down", "Machinery cannot be used in flow production", "Products made using flow production are always of poor quality"], "answer": 1, "explain": "Correct answer: A major risk of flow production is that a single breakdown on the assembly line can halt the entire factory, causing huge financial losses. Option A is wrong — unit costs are actually LOW in flow production. Option C is wrong — machinery is central to flow production. Option D is incorrect — quality can still be high and consistent in flow production."}, {"question": "Crown Paints makes different types and colours of paint in its factory. Which method of production does Crown Paints use?", "options": ["Robotic production", "Job production", "Flow production", "Batch production"], "answer": 3, "explain": "Correct answer: Batch production. Crown Paints makes one type and colour of paint, fills and labels the tins, then switches production to a different type or colour. This is the definition of batch production — switching between different products. Job (A) makes one unique item at a time. Flow (C) makes the same product continuously. Robotic (D) is not one of the three main production methods."}]}, "fib": {"enabled": true, "questions": [{"text": "Job production is the process where products are made [individually]."}, {"text": "Flow production is sometimes called [mass] production."}, {"text": "Automation is a production process involving machinery controlled by a [computer], not a person."}, {"text": "A key advantage of job production is that products are usually high [quality] and can meet individual customer [needs]."}, {"text": "A key disadvantage of flow production is that if the [assembly] line breaks down, the entire factory may shut [down]."}, {"text": "Batch production allows a business to meet the needs of [different] customers by producing batches of [different] goods."}, {"text": "A key advantage of using technology in production is that machines can work [24] hours a day, [7] days a week."}, {"text": "The use of robots in production is known as [robotics], and it accounts for around [65] per cent of all robot use in car manufacturing."}, {"text": "Flow production benefits from [economies] of scale, meaning the [average] cost per unit falls as output rises."}, {"text": "A disadvantage of introducing technology is that workers may be made [redundant], adding to the [short-term] costs of the business."}, {"text": "The three methods of production are job, [batch], and [flow] production."}, {"text": "Crown Paints uses [batch] production, making different colours and types of paint before switching to the next [batch]."}]}, "tf": {"enabled": true, "questions": [{"statement": "Modern businesses do not use job production.", "answer": false, "explain": "FALSE. Many modern businesses still use job production. Large-scale projects like the Crossrail railway in London are examples of job production. It is a common misconception that job production is only for small artisan businesses — it is not."}, {"statement": "Goods produced by flow production are usually made to suit the needs of individual customers.", "answer": false, "explain": "FALSE. Flow production makes standardised, identical products in large quantities for the mass market. It is JOB production that creates products tailored to individual customer needs."}, {"statement": "Flow production is suited to large-scale production.", "answer": true, "explain": "TRUE. Flow production is specifically designed to produce very large quantities of the same product continuously. This is what makes it suited to mass markets and high-demand products like cars and baked beans."}, {"statement": "Working in a batch production process can be repetitive and boring for workers.", "answer": true, "explain": "TRUE. Because batch production involves repeating the same tasks many times within each batch, workers can find the work monotonous. This can negatively affect motivation and productivity."}, {"statement": "Flow production does not require any workforce at all.", "answer": false, "explain": "FALSE. Flow production does still require workers — they oversee the machines, perform quality checks, manage supply chains, and complete tasks not fully automated. Technology reduces but rarely eliminates the need for workers entirely."}, {"statement": "Job production workers are often highly skilled.", "answer": true, "explain": "TRUE. Job production requires skilled labour because each product is unique and made to a high standard. This is a key reason why the costs of job production are high — skilled workers command higher wages."}, {"statement": "Goods produced by job production are usually high quality.", "answer": true, "explain": "TRUE. Because each item is individually made with care and expertise to meet a specific customer''s requirements, job production typically produces high-quality, bespoke products. This justifies the premium prices charged."}, {"statement": "Many dangerous processes are best carried out by automated machinery.", "answer": true, "explain": "TRUE. Automation is ideal for dangerous environments. Robots were sent into the Fukushima nuclear site in Japan after the 2014 explosion because it was too dangerous for humans to enter. Machines can also do other hazardous tasks that workers may be unwilling or unable to do safely."}, {"statement": "Supermarket in-store bakeries use the batch production method.", "answer": true, "explain": "TRUE. In-store bakeries make a batch of one type of bread or pastry, then switch to produce a different type. This is the definition of batch production — making one product type, then switching to another."}, {"statement": "It is cheap to set up a flow manufacturing process.", "answer": false, "explain": "FALSE. Setting up a flow production line is very expensive. The machinery, conveyor systems, and factory layout all require enormous capital investment — this is one of the key disadvantages of flow production."}, {"statement": "Automation can increase the flexibility of production because machines can be reprogrammed.", "answer": true, "explain": "TRUE. Unlike fixed machinery, computer-controlled automated machines can be reprogrammed to produce a variety of products without rebuilding the production line. This is a key advantage of automation over older fixed machinery."}, {"statement": "Job production is exclusively used by small businesses.", "answer": false, "explain": "FALSE. This is a very common misconception. Job production is used by businesses of all sizes. The Crossrail project, large ship-building companies, and major advertising agencies all use job production on a very large scale. The method refers to HOW something is made, not the size of the business."}]}, "misc": {"enabled": true, "items": [{"myth": "Once a business chooses a production method, it is stuck with that method and cannot change.", "truth": "Businesses can use a combination of methods simultaneously. A caravan manufacturer might use job production to assemble each caravan but batch production to make shared components. The method can also evolve as the business grows or demand changes.", "check": {"question": "Can a business use more than one production method at the same time?", "options": ["No, a business must choose one method and keep it forever", "Yes, a caravan maker might use job for assembly, batch for parts", "Only if the business employs over 500 staff across its sites", "Only in manufacturing, never within a service-based business"], "answer": 1, "explain": "Businesses can and do combine methods — using job production for unique assemblies while using batch or flow for shared components within the same business."}}, {"myth": "Job production is only suitable for small businesses.", "truth": "Job production is used by businesses of all sizes. The Crossrail project in London (one of Europe''s largest infrastructure projects), ship-building companies, and bespoke advertising agencies all use job production. Size is irrelevant — the method refers to making individual, unique products.", "check": {"question": "Which of the following is an example of job production by a LARGE business?", "options": ["Heinz producing baked beans on a continuous assembly line", "Crown Paints switching between different paint colours", "The Crossrail project — a unique, one-off construction job", "Warburton''s making batches of different types of bread"], "answer": 2, "explain": "Crossrail is a massive infrastructure project involving thousands of workers — yet it is job production because it is a unique, one-off product. Job production is defined by uniqueness, not business size."}}, {"myth": "Flow production workers are highly skilled.", "truth": "Flow production workers typically carry out repetitive, specialised tasks on an assembly line and are generally not considered highly skilled. It is JOB production that requires skilled workers — craftspeople, architects, surgeons, etc. — which is why job production has higher labour costs.", "check": {"question": "Which production method requires the most skilled workers, and why?", "options": ["Flow production, because operating an assembly line takes considerable technical skill", "Batch production, because switching between different products requires real expertise", "Job production, because each product is individually made to unique specifications", "All three methods need roughly the same level of skill from their workers"], "answer": 2, "explain": "Job production demands highly skilled labour — craftspeople, architects, surgeons — because each product must meet individual specifications. This is why job production has the highest labour costs."}}, {"myth": "Technology always replaces all workers, resulting in zero employment.", "truth": "Technology reduces the number of workers needed but rarely eliminates them entirely. It also creates new jobs. Amazon introduced 100,000+ robots in its warehouses, but UK employment at Amazon actually grew by 3,000 workers as sales increased — because robots created new demand and new roles.", "check": {"question": "What actually happened to Amazon UK employment after it introduced over 100,000 robots into its warehouses?", "options": ["Employment fell to zero, since every worker was replaced by a robot", "Employment fell by 3,000 workers as robots took over most warehouse roles", "Employment grew by 3,000 workers as sales and new roles increased", "Employment stayed exactly the same despite the introduction of the robots"], "answer": 2, "explain": "Despite introducing 100,000+ robots, Amazon UK employment grew by 3,000 workers — demonstrating that technology creates new jobs and roles even as it changes or eliminates others."}}, {"myth": "Batch production and flow production are basically the same — they both make lots of products.", "truth": "They are fundamentally different. Batch makes a group of one type of product, then stops and switches to a different type. Flow makes the same product continuously without ever stopping. Flow is for very high volumes of an identical product; batch allows product variety through switching.", "check": {"question": "What is the fundamental difference between batch and flow production?", "options": ["Batch relies mainly on machines, flow relies only on workers", "Batch makes a group then switches; flow never stops", "Flow production is always cheaper to run than batch", "Batch production can only ever be used by small firms"], "answer": 1, "explain": "The defining difference is continuity and variety: batch production stops and switches between product types; flow production never stops and makes the same product continuously."}}, {"myth": "Automation and robotics mean exactly the same thing.", "truth": "Automation is the broader term — any computer-controlled production process. Robotics is a specific type of automation where programmable robots perform tasks. All robotics is automation, but not all automation involves robots (e.g., automated door sensors, online banking systems).", "check": {"question": "A school system that automatically texts parents when their child is absent — is this automation, robotics, or neither?", "options": ["Robotics, because the system is controlled entirely by a computer program", "Automation, because it is computer-controlled but involves no physical robot", "Neither, because sending a text message is not really a business process", "Both, because automation and robotics describe exactly the same technology"], "answer": 1, "explain": "This is automation — a computer-controlled process running without human involvement — but not robotics, which specifically requires a programmable physical robot. Not all automation involves robots."}}, {"myth": "For a 3-mark ''Analyse'' question, simply naming a benefit and writing a general explanation is enough for full marks.", "truth": "For 3 marks (U + APP + AN), you must: (1) state the benefit/point clearly, (2) apply it to the specific business in the case study using evidence from the text, AND (3) explain the business impact (on costs, revenue, or competitiveness). Without the Application, you cannot score the Analysis mark.", "check": {"question": "Why can''t you score the Analysis (AN) mark on a 3-mark question without first including Application (APP)?", "options": ["You can — Analysis marks are always awarded regardless", "Marks are awarded in sequence — link to the business first", "Because Analysis marks only exist on six-mark questions", "Because Application and Analysis count as the same mark"], "answer": 1, "explain": "The U → APP → AN chain is sequential — without linking your point to the case study business (APP), there is no foundation for the analysis mark. AN cannot be awarded without APP."}}, {"myth": "Flow production always produces lower quality goods compared to job production.", "truth": "Flow production CAN produce high-quality, consistent goods. Modern computer-controlled machines are highly accurate. Cars produced on assembly lines, for example, undergo rigorous quality checks. The assumption that mass-produced automatically means low quality is outdated and incorrect.", "check": {"question": "Does flow production necessarily produce lower quality goods than job production?", "options": ["Yes, because mass-produced goods are always lower quality than hand-made ones", "No, modern computer-controlled machines are accurate and give consistent quality", "Yes, but this drop in quality only happens within the food industry", "No, flow production always produces better quality than job production does"], "answer": 1, "explain": "Modern automated flow production lines can be extremely precise and consistent — cars from assembly lines undergo rigorous quality checks. The idea that mass-produced automatically equals low quality is outdated."}}]}, "tips": {"enabled": true, "items": [{"title": "One Point. Full Stop. Move On.", "html": "\n          <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly <strong>one correct point</strong>. No explanation. No examples. No paragraphs.</p>\n    \n          <p><strong>The Formula:</strong></p>\n          <ul>\n            <li>One clear, specific point = 1 mark ✅</li>\n            <li>A vague, general point = 0 marks ❌</li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n          <em>\"Flow production is when things are made.\"</em><br/>\n          Too vague — doesn''t identify a specific characteristic of flow production.</p>\n    \n          <p><strong>✅ Good Answer (1 mark):</strong><br/>\n          <em>\"Goods are produced continuously using an assembly line.\"</em><br/>\n          Specific, precise, and directly answers the question.</p>\n    \n          <p><strong>⚠️ Examiner Warning:</strong> The OCR examiners noted that saying flow production is \"faster\" will NOT be rewarded — this depends on what is being produced and is not a specific characteristic. Always be precise: say \"uses an assembly line,\" \"continuous production,\" or \"low unit costs per product.\"</p>\n    \n          <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write a full paragraph for a 1-mark question. Every extra sentence you write here is wasted time you need for the higher-mark questions.</p>\n        ", "check": {"question": "Why does the answer ''flow production is faster'' NOT score a mark on a 1-mark ''Identify a characteristic of flow production'' question?", "options": ["Because speed is never something examiners consider relevant to production", "Because speed depends on what is made and isn''t a fixed characteristic of flow", "Because only batch production can accurately be described as being faster", "Because the examiner actually accepts the word ''faster'' for full marks"], "answer": 1, "explain": "OCR examiners specifically flagged this — ''faster'' is relative and context-dependent, not a specific characteristic of flow production. Precise answers like ''uses an assembly line'' or ''produces continuously'' are required."}}, {"title": "Name It + Explain It", "html": "\n          <p>A 2-mark <strong>''Explain''</strong> question needs two things: <strong>identify</strong> the concept AND <strong>explain</strong> what it means or how it works.</p>\n    \n          <p><strong>The Formula:</strong></p>\n          <ul>\n            <li><strong>Mark 1 (Knowledge):</strong> Name the production process or concept.</li>\n            <li><strong>Mark 2 (Understanding):</strong> Explain what it involves or how it works.</li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n          <em>\"Batch production.\"</em><br/>\n          Named it but failed to explain it — only 1 mark.</p>\n    \n          <p><strong>✅ Good Answer (2 marks):</strong><br/>\n          <em>\"Batch production (1), which is when a group of similar products are made together before production switches to a different type of product (1).\"</em></p>\n    \n          <p><strong>⚠️ Critical Examiner Warning:</strong> The OCR examiner noted that some candidates explained the process without naming it — and scored ZERO. Always NAME the concept first, then explain it.</p>\n    \n          <p><strong>⚠️ Application Warning:</strong> For a 2-mark ''Explain one way technology might affect production'' question, you MUST apply your point to the specific business. Answers about selling online or marketing when the question asks about <em>production</em> scored zero — always re-read the question carefully.</p>\n        ", "check": {"question": "Which answer would score 2 marks for ''Explain what is meant by batch production''?", "options": ["\"Batch production happens in factories that make one product.\"", "\"Batch production is when products are made quickly in bulk.\"", "\"Batch (1 mark), made as a group before switching product (1 mark).\"", "\"Batch production makes lots of products, which is good for business.\""], "answer": 2, "explain": "A 2-mark Explain answer needs the name (1 mark) and an accurate explanation of how it works (1 mark). Vague statements about ''large quantities'' or ''good for businesses'' do not explain the defining characteristic of batch production."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n          <p>A 3-mark <strong>''Analyse''</strong> question has a strict formula. You <strong>cannot</strong> score Application without Understanding. You <strong>cannot</strong> score Analysis without Application.</p>\n    \n          <p><strong>The 3-Step Formula:</strong></p>\n          <ul>\n            <li><strong>Step 1 — Understanding (U):</strong> State the benefit or drawback in general terms.<br/><em>\"Batch production allows a business to meet the needs of different customers...\"</em></li>\n            <li><strong>Step 2 — Application (APP):</strong> Link it specifically to the case study business using a fact from the text.<br/><em>\"...Pukka Pies produces different flavours of pies — steak, chicken balti, chicken and mushroom...\"</em></li>\n            <li><strong>Step 3 — Analysis (AN):</strong> State the business-facing impact — on costs, revenue, or competitiveness.<br/><em>\"...This allows different standardised products to be made to satisfy a wide range of customers, helping Pukka Pies grow its revenue.\"</em></li>\n          </ul>\n    \n          <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n          <em>\"Batch production is good because it makes more products.\"</em><br/>\n          No application to the business, no business impact — 1 mark at best.</p>\n    \n          <p><strong>✅ Good Answer (3 marks):</strong><br/>\n          <em>\"Each batch of pies can be made to match a specific order (U) for each different flavour of pie Pukka Pies produces (APP). This allows standardised products to be made to satisfy a range of customers, helping Pukka Pies increase its sales across its 4,000 outlets (AN).\"</em></p>\n    \n          <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write everything you know about batch production. The examiner specifically noted that analysis must be about specific benefits of the production process — not generic outcomes like \"higher sales\" without explanation.</p>\n    \n          <p><strong>⚠️ The \"So What?\" Rule:</strong> Keep asking \"So what?\" until you reach a bottom-line business impact.<br/>\n          \"Automation reduces the number of workers needed.\" → So what? → \"This lowers wage costs.\" → So what? → \"This reduces average costs, allowing JLR to price its cars more competitively and increase profit margins.\" Now you have AN.</p>\n        ", "check": {"question": "Complete the analysis chain for JLR: ''Automation reduces the number of workers needed (U) → JLR''s factories use robots for welding and painting (APP) → ...''", "options": ["→ ''This means JLR has installed several new welding robots.''", "→ ''This lowers JLR''s wage costs, boosting its competitiveness (AN).''", "→ ''This means the workers at JLR''s factories feel much happier.''", "→ ''This shows JLR is a large car manufacturer based in the UK.''"], "answer": 1, "explain": "The Analysis mark requires a specific bottom-line business impact — reduced costs, improved competitiveness, higher revenue or profit. Simply restating what happens is not analysis."}}, {"title": "Two 3-Mark Answers Written Back to Back", "html": "\n          <p>A 6-mark <strong>''Analyse two...''</strong> question is simply <strong>two 3-mark analyses written consecutively</strong>. Use the exact same U → APP → AN formula for each point.</p>\n    \n          <p><strong>Structure:</strong></p>\n          <ul>\n            <li><strong>Point 1:</strong> U (state the advantage) → APP (link to the business using case study evidence) → AN (business-facing impact)</li>\n            <li><strong>Point 2:</strong> U (state the second advantage) → APP (link to the business again) → AN (different business impact)</li>\n          </ul>\n    \n          <p><strong>⚠️ DO NOT write a conclusion</strong> — there are zero marks available for evaluation in a 6-mark ''Analyse'' question. Every sentence must be U, APP, or AN.</p>\n    \n          <p><strong>Useful sentence starters:</strong></p>\n          <ul>\n            <li><em>\"Automation will [benefit] because...\"</em> (U)</li>\n            <li><em>\"In the case of JLR, this means...\"</em> or <em>\"As stated in the text, JLR...\"</em> (APP)</li>\n            <li><em>\"As a result, JLR will [lower costs / increase revenue / be more competitive]...\"</em> (AN)</li>\n          </ul>\n    \n          <p><strong>Exemplar (JLR, Advantage 1):</strong><br/>\n          <em>\"Automation will increase the number of cars JLR can produce (U). Machines can work 24/7, unlike human workers, meaning more cars move along the production line at JLR''s factories (APP). This should increase JLR''s total sales revenue and help it compete more effectively with BMW and Mercedes (AN).\"</em></p>\n        ", "check": {"question": "Should you write a conclusion or evaluation at the end of a 6-mark ''Analyse two advantages'' question?", "options": ["Yes, because a strong conclusion always improves the quality of the answer", "No, there are no evaluation marks here; every sentence must be U, APP or AN", "Yes, but the conclusion should be limited to a single short sentence", "Only if you manage to finish both analysis points well ahead of time"], "answer": 1, "explain": "A 6-mark Analyse question has no evaluation marks — writing a conclusion wastes time and scores nothing. Every sentence must directly contribute to one of the two U → APP → AN chains."}}, {"title": "Judgement + Reason + Context", "html": "\n          <p>A 3-mark <strong>''Recommend'' or ''Evaluate''</strong> question (AO3b only) does NOT reward more analysis. It rewards a <strong>justified, contextual judgement</strong>.</p>\n    \n          <p><strong>The 3-Part Formula:</strong></p>\n          <ul>\n            <li><strong>Judgement (1 mark):</strong> Make a clear decision — yes/no, method A or B.<br/><em>\"The Montana Bakery should switch to flow production...\"</em></li>\n            <li><strong>Justification (1 mark):</strong> Give a reason that weighs up the decision.<br/><em>\"...because the cost savings it is likely to make are more important than any loss of perceived quality...\"</em></li>\n            <li><strong>Context (1 mark):</strong> Use specific information from the case study.<br/><em>\"...in a competitive market for bread where customers often buy the cheapest option.\"</em></li>\n          </ul>\n    \n          <p><strong>Power Phrase:</strong> Use \"it depends on...\" to show sophisticated evaluation:<br/>\n          <em>\"It depends on whether Montana Bakery wishes to continue making the range of speciality breads it currently supplies, as flow production may reduce their perceived uniqueness and lead M&S to lose confidence in the supplier.\"</em></p>\n    \n          <p><strong>❌ Common Mistake:</strong> Simply repeating the analysis points from the previous question does NOT earn evaluation marks. The evaluation must weigh up, make a decision, and say something NEW about whether it is worthwhile.</p>\n    \n          <p><strong>⚠️ Examiner Note:</strong> Both judgements (switch / don''t switch; use robots / don''t use robots) are perfectly valid in the exam — what matters is your contextual justification, not which side you pick.</p>\n        ", "check": {"question": "What are the THREE parts required for a full 3-mark Recommend/Evaluate answer?", "options": ["Three separate advantages of whichever production method has been chosen", "A clear judgement, a justification for it, and context from the case study", "A definition of the term, one advantage, and one matching disadvantage", "Two full paragraphs of analysis followed by a short closing summary"], "answer": 1, "explain": "A 3-mark Recommend answer needs: (1) a clear decision, (2) a reason that weighs up the options, and (3) specific context from the case study. Without all three, you will drop marks."}}, {"title": "Build the Case, Then Make the Call", "html": "\n          <p>A 7-mark evaluation question (e.g., the Barclays question) awards marks for: <strong>Application (up to 2)</strong> + <strong>Analysis (up to 2)</strong> + <strong>Evaluation (up to 3)</strong>. There are NO knowledge marks — start with application immediately.</p>\n    \n          <p><strong>Four-Paragraph Structure:</strong></p>\n          <ul>\n            <li><strong>Paragraph 1 — Point 1 with Application:</strong><br/><em>\"By investing in online banking, Barclays is likely to gain more UK customers. As shown in Fig. 1, 75% of UK customers now use online banking...\"</em> (APP)</li>\n            <li><strong>Paragraph 2 — Analysis of Point 1:</strong><br/><em>\"...This means Barclays can earn more revenue from new accounts and transaction fees, improving its overall profit margins.\"</em> (AN)</li>\n            <li><strong>Paragraph 3 — Counter-point with Application:</strong><br/><em>\"However, all major competitor banks will have made similar investments in online banking, so Barclays may need to spend even more to maintain a competitive advantage...\"</em> (APP + AN)</li>\n            <li><strong>Paragraph 4 — Evaluation (3 parts: Decision + Context + Impact/Reasoning):</strong><br/><em>\"Overall, the investment is likely to benefit Barclays [Decision], given that 75% of its 24 million customers already use online banking [Context]. The cost savings from reducing branch staff will likely outweigh implementation costs in the long run [Reasoning].\"</em></li>\n          </ul>\n    \n          <p><strong>⚠️ Evaluation Warning:</strong> For the full 3 evaluation marks, your conclusion MUST be contextual — referring to specific facts from the case study. A generic conclusion (\"Technology is good for businesses\") scores 0 evaluation marks.</p>\n    \n          <p><strong>🚫 Customer-Only Impacts:</strong> The OCR examiner explicitly states \"No reward for answers which only consider impacts on the customer.\" Your analysis and evaluation MUST focus on the impact on the BUSINESS — costs, revenue, profit, reputation, and competitiveness.</p>\n        ", "check": {"question": "Why does a 7-mark evaluate question award NO knowledge marks, and what should your first sentence do instead?", "options": ["Because knowledge of methods isn''t tested at GCSE level at all", "All marks are for APP, AN and EVAL, so start by applying a point", "Because you should open with a definition to show knowledge", "Because knowledge marks are hidden within the Application marks"], "answer": 1, "explain": "A 7-mark evaluate question rewards APP (up to 2), AN (up to 2) and EVAL (up to 3) — there are zero knowledge marks. Opening with a definition wastes precious marks; start immediately with application to the case study business."}}]}, "exam": {"enabled": true, "questions": [{"question": "Which is an advantage for a manufacturer of using robotics? [1 mark]", "marks": 1, "hint": "Think about what robots do BETTER than humans — not what they cost or what goes wrong with them.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Greater productivity</h5><p><strong>Why A is correct:</strong> Robots can work 24/7 without breaks, producing more output in less time and with greater consistency than human workers — this directly increases productivity.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B (Initial investment cost)</strong> — This is a <em>disadvantage</em> of robotics, not an advantage. The upfront cost of buying and installing robots is very high.</li><li><strong>C (Operatives will require training)</strong> — This is also a <em>disadvantage</em>. Workers need to be trained to operate and oversee the robots, which adds to business costs.</li><li><strong>D (Will not break down)</strong> — This is factually <em>incorrect</em>. Machines CAN and do break down — breakdown risk is actually a key disadvantage of using robotics.</li></ul></div>"}, {"question": "Identify two characteristics of flow production. [2 marks]", "marks": 2, "hint": "Think about what DEFINES flow production — how it works, what it uses, and what it produces. Avoid saying it is ''quicker'' without being more specific.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a)</h5><p>One mark for each correct characteristic, up to a maximum of two marks. Answers do NOT need to relate to Unilever.</p><ul><li>A business can make large quantities / in bulk</li><li>Costs of production per unit are lower (economies of scale)</li><li>Uses machinery / automation</li><li>Very expensive to initially set up</li><li>Products are undifferentiated / all the same / consistent quality</li><li>Uses an assembly line / conveyor belt</li><li>Production is continuous / can run 24/7</li><li>Large stocks of components or raw materials may be necessary</li></ul><p><strong>No reward for:</strong> comparative statements (e.g., \"cheaper than job production\") unless they contain a specific characteristic. \"It is faster\" alone is not sufficient — not always true.</p></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Most candidates identified at least one characteristic. A significant number said flow production was \"quicker or faster\" — this was not rewarded as it may or may not be true depending on what is being produced. Some gave consequences of flow production rather than characteristics. Always be precise about HOW flow production works, not what it might lead to.</p></div>"}, {"question": "Explain one production process a business may use when making its products. [2 marks]", "marks": 2, "hint": "Name one of the three production methods (job, batch, or flow) — then explain what that process involves. You need BOTH for the 2 marks.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a 1, AO1b 1)</h5><ul><li><strong>Mark 1 (Knowledge):</strong> Identifying the production process by name.</li><li><strong>Mark 2 (Understanding):</strong> Explaining what the process involves.</li></ul><p>Answers do NOT need to relate to Zara.</p><p><strong>Acceptable answers include:</strong></p><ul><li>Batch — groups of a product made together (before production switches to another type)</li><li>Flow / Mass — continuous production / production line / assembly line</li><li>Job — one product made at a time / individually made</li></ul><p><strong>Exemplar response:</strong> Batch production (1) which is when a group of similar products are made together before production switches to a different type of product (1).</p></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Most candidates named one of the three production methods. Some candidates only explained the process without naming it — and therefore scored zero. Flow and job production were more accurately explained than batch production. Always NAME the concept first, then explain it.</p></div>"}, {"question": "Explain one method that a business could use to ensure the quality of its products. [2 marks]", "marks": 2, "hint": "Name a specific quality method — either quality control or quality assurance. Then explain what it involves. Do not confuse the two.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a 1, AO1b 1)</h5><ul><li><strong>Mark 1 (Knowledge):</strong> Identifying a method to ensure quality.</li><li><strong>Mark 2 (Understanding):</strong> Explaining what the method involves.</li></ul><p><strong>Acceptable answers include:</strong></p><ul><li>Quality control — checking/inspection at the END of the production process / before being sold</li><li>Quality assurance — checking quality DURING the production process / by production workers / whole business responsibility</li></ul><p><strong>Exemplar response:</strong> Quality control (1) which is where an inspector would check a sample of the finished goods to ensure they meet the required standard before being sold (1).</p></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Some answers did not name a specific method — this prevented any marks being awarded. There was significant confusion between quality control and quality assurance. Many candidates'' explanations described the wrong method. Less than half of candidates gained both marks on this question.</p><p><strong>Key distinction to learn:</strong> Quality CONTROL = checking at the END (inspector). Quality ASSURANCE = checking quality THROUGHOUT the whole process by all workers.</p></div>"}, {"question": "Explain one way technology might affect production at AZ. [2 marks]", "marks": 2, "hint": "Focus specifically on PRODUCTION — how things are made, not how they are sold or marketed. Think about automation, accuracy, speed, or costs in making vaccines/medicines.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b 1, AO2 1)</h5><ul><li><strong>Mark 1 (Understanding):</strong> A way technology can influence PRODUCTION specifically.</li><li><strong>Mark 2 (Application):</strong> Applying this to AZ specifically.</li></ul><p><strong>No mark can be gained for the application without first gaining the understanding mark.</strong></p><p><strong>Acceptable answers include:</strong></p><ul><li>Automation can increase productivity / can work 24/7</li><li>Lower unit costs / fewer workers needed</li><li>Fewer mistakes / higher quality levels of medicines/vaccines</li><li>Machines can slow production down if training is needed (disadvantage)</li><li>Increased chance of breakdowns (disadvantage)</li></ul><p><strong>Exemplar response:</strong> Automation can increase productivity (1) in the production of vaccines and medicines at AZ (APP) (1).</p><p><strong>No reward for:</strong> answers about e-commerce, online selling, or the call centre — the question specifically asks about <em>production</em>.</p></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Many candidates did not read this question carefully enough, giving answers about selling online rather than production. Less than a quarter of candidates gained full marks. Most identified a way technology affects a business generally, but failed to apply it specifically to AZ''s production of medicines and vaccines.</p></div>"}, {"question": "Which of the following is NOT a disadvantage of automation? [1 mark]", "marks": 1, "hint": "Look for the option that is actually a BENEFIT of automation, not a drawback.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — The machinery can be reprogrammed, making production more flexible</h5><p><strong>Why D is correct:</strong> Being reprogrammable and flexible is an ADVANTAGE of automation — it allows the business to produce a variety of products without rebuilding its production line.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A (Expensive to buy)</strong> — This IS a disadvantage. Technology requires high upfront capital investment, which the business must find a way to finance.</li><li><strong>B (Machines can break down)</strong> — This IS a disadvantage. Breakdown risk is a key concern, especially in flow production where one failure can halt the entire line.</li><li><strong>C (Training costs)</strong> — This IS a disadvantage. Existing workers need to be retrained to work with new technology, which increases costs.</li></ul></div>"}, {"question": "Identify two factors that may influence whether a business invests in new computer technology. [2 marks]", "marks": 2, "hint": "Think about what a business would need to consider before making a major investment decision — what might stop them or push them towards investing?", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a)</h5><p>One mark for each correct factor, up to a maximum of two marks. Ensure the two factors are clearly different. Answers do NOT need to apply to Barclays.</p><p><strong>Acceptable answers include:</strong></p><ul><li>Cost of the technology (including running costs)</li><li>Availability of the technology</li><li>The state of its current technology</li><li>Technology quality / the expected impact on the business</li><li>Forecast return on investment (e.g., average rate of return)</li><li>Actions of competitors</li><li>Availability of capital / access to finance</li><li>Employee skills / readiness of the workforce</li></ul></div>"}, {"question": "Evaluate possible impacts on Barclays plc of investing in computer technology to provide online banking services to its customers. [7 marks]", "marks": 7, "hint": "This is a 7-mark evaluate question — you need Application (2) + Analysis (2) + Evaluation (3). Use specific data from the case study and Fig. 1. Your evaluation must make a justified judgement about WHETHER the overall impact is positive or negative for Barclays — not just for its customers.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 7 marks (AO2: 2, AO3a: 2, AO3b: 3)</h5><p>Use the level of response marking grid:</p><ul><li><strong>Application (up to 2 marks):</strong> Uses specific context from the case study or Fig. 1</li><li><strong>Analysis (up to 2 marks):</strong> Business-facing impact (costs, revenue, reputation, competitiveness)</li><li><strong>Evaluation (up to 3 marks):</strong> Justified contextual judgement</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>Banking is one of the first sectors to embrace technology</li><li>Data from Fig. 1 (e.g., 75% of UK customers use online banking by 2020)</li><li>24 million UK personal banking customers</li><li>Online banking allows 24/7 access worldwide</li><li>Fastest growing area of internet activity</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>Competition — gaining an advantage or being left behind by rivals</li><li>Enhanced reputation as an innovative, modern bank</li><li>Reputational damage if there are data breaches or security failures</li><li>Cost savings from closing branches (premises, staff, utilities)</li><li>Cost of training staff and maintaining security systems</li><li>Loss of the personal touch — risk of alienating older customers</li></ul></div><div class=\"marks-section\"><h5>Evaluation may include:</h5><ul><li>The relative importance of different factors</li><li>The sharp and consistent increase in online banking adoption (42% → 75% over a decade) suggests customers have an appetite for it</li><li>A comparison and weighing of advantages against disadvantages with a justified conclusion</li></ul><p><strong>For strong evaluation (3 marks):</strong> The evaluation must be contextual — referring to specific data from the case study. A generic conclusion scores limited marks.</p><p><strong>No reward</strong> for answers that only consider impacts on the customer.</p></div><div class=\"marks-section\"><h5>Exemplar Model Answer</h5><p>By investing in new technology to allow online banking, Barclays is likely to gain more UK customers (AN). As Fig. 1 shows, 75% of UK banking customers now use online banking (APP), so Barclays needs to offer this service to retain its 24 million customers and avoid losing them to competitors (AN).</p><p>However, other banks will have made the same investment (APP), so Barclays may have to spend even more to stay ahead and differentiate its online services, adding to costs (AN).</p><p>Overall, the investment in online banking is likely to be a net positive for Barclays (EVAL). Given that 75% of its 24 million customers already use online banking (EVAL — context), the cost savings from reducing branch staff and the revenue gains from attracting new digital customers are likely to outweigh the implementation and security costs in the long run (EVAL — reasoning).</p></div>"}, {"question": "Analyse the benefits to Pukka Pies Ltd of using a batch production process. [3 marks]", "marks": 3, "hint": "Use the 3-step formula: (1) State a benefit of batch production (U), (2) link it to something specific about Pukka Pies from the case study (APP), (3) explain the business impact this creates (AN).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b, AO2, AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> States a benefit of using batch production.</li><li><strong>Application (1 mark):</strong> Applies the benefit specifically to Pukka Pies Ltd using evidence from the text. <em>No application mark without understanding.</em></li><li><strong>Analysis (1 mark):</strong> Explains the effect/impact of this benefit on the business.</li></ul><p><strong>NB:</strong> Analysis must be about specific benefits of the production process (e.g., ''provides a range of options'') — NOT generic outcomes like ''higher sales'' without explanation.</p></div><div class=\"marks-section\"><h5>Understanding may include:</h5><ul><li>Can match the needs of different customers</li><li>Batches are made to match specific orders</li><li>Can automate part of the process</li><li>Can produce different ranges of products</li><li>Production rates are higher than job production</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>High quality requirements / different flavours of pies</li><li>360 employees</li><li>4,000 different outlets ranging from sports stadiums to cafés</li><li>Ingredients from UK and overseas / long supply chain</li><li>Logistics are time-critical</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>Batch minimises waste compared to flow production</li><li>Can lead to lower average cost per pie</li><li>Allows different but standardised types of pies to be produced</li><li>Increased flexibility of production</li></ul></div><div class=\"marks-section\"><h5>Exemplar Model Answer</h5><p>Each batch of pies can be made to match a specific order (U) for each different flavour of pie Pukka Pies produces — steak, chicken and mushroom, and chicken balti (APP). This allows standardised products to be made to satisfy a range of different customers across its 4,000 outlets, keeping costs manageable while meeting varied demand (AN).</p></div>"}, {"question": "A company''s total costs are too high. The finance manager advises that this is being caused by increasing wage costs as the company expands. Which one of the following actions would provide a long-term solution to this problem? [1 mark]", "marks": 1, "hint": "The problem is rising WAGE costs long-term. Which option directly and permanently reduces the need for workers?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Automating the production process</h5><p><strong>Why B is correct:</strong> Automation replaces labour with computer-controlled machinery. This directly reduces the number of workers needed, permanently lowering wage costs in the long term.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A (Applying for an overdraft)</strong> — An overdraft provides short-term finance to cover a cash shortage. It must be repaid with interest and does nothing to solve the underlying wage cost problem.</li><li><strong>C (Employing a finance assistant)</strong> — This would ADD to wage costs, making the problem worse, not better.</li><li><strong>D (Switching to job production)</strong> — Job production typically requires highly skilled workers who command HIGHER wages. This would increase wage costs, not reduce them.</li></ul></div>"}, {"question": "Breakfast biscuits are becoming increasingly popular. HealthBisc Ltd predicts that in future years it will have difficulty producing enough breakfast biscuits to keep up with demand. Which one of the following actions could help HealthBisc Ltd deal with this problem? [1 mark]", "marks": 1, "hint": "The problem is production CAPACITY — not enough output to meet demand. Which option increases the amount that can be produced?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Automate the production process</h5><p><strong>Why A is correct:</strong> Automation allows machines to work 24/7, dramatically increasing the rate and volume of production to meet higher levels of demand. This directly solves the capacity problem.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B (Improve after-sales service)</strong> — After-sales service relates to customer experience after purchase. It does nothing to increase production output or capacity.</li><li><strong>C (Reduce its prices)</strong> — Reducing prices would likely increase demand even further, making the production shortfall problem worse, not better.</li><li><strong>D (Switch to job production)</strong> — Job production makes items individually, one at a time. This would dramatically REDUCE output, making it impossible to meet the high levels of demand.</li></ul></div>"}, {"question": "An entrepreneur makes individual handmade prom dresses to order. What method of production does the entrepreneur use? [1 mark]", "marks": 1, "hint": "The key word is ''individual'' and ''to order''. Which method makes each product one at a time to a specific customer''s requirements?", "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Job production</h5><p><strong>Why D is correct:</strong> Job production involves making each product individually to meet the exact requirements of a specific customer order. Each prom dress is unique and made one at a time — this is the definition of job production.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A (Automated)</strong> — Automation involves computer-controlled machinery. This handmade dress is made by a skilled person, not a machine.</li><li><strong>B (Batch)</strong> — Batch production would mean making a group of the same dress style, then switching to a different style. Each dress here is individual, not part of a batch.</li><li><strong>C (Flow)</strong> — Flow production continuously makes the same product in large quantities on an assembly line. Individual handmade dresses are the opposite of this.</li></ul></div>"}, {"question": "Analyse two advantages to JLR of using automation to produce its cars. [6 marks]", "marks": 6, "hint": "This is two 3-mark analyses in one. For each advantage: (1) State what the advantage is (U), (2) Apply it to JLR specifically using case study evidence (APP), (3) Explain the business impact on JLR (AN). Do NOT write a conclusion — no evaluation marks available here.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 6 marks (AO1b: 2, AO2: 2, AO3a: 2)</h5><ul><li>1 mark for understanding of an advantage of automation (max 2 marks, one per advantage)</li><li>1 further mark for applying the advantage to JLR specifically (max 2 marks)</li><li>1 further mark for analysis of the impact on JLR (max 2 marks)</li></ul><p>ARA (any reasonable answer)</p></div><div class=\"marks-section\"><h5>Understanding may include:</h5><ul><li>Increased output / greater productivity</li><li>Consistent quality of output</li><li>Increased flexibility of production (reprogrammable)</li><li>Continuous 24/7 operation</li><li>Less reliant on labour / lower labour costs</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>JLR makes luxury cars (quality expectations are high)</li><li>JLR competes with BMW and Mercedes</li><li>Parts come from UK and overseas (complex supply chain)</li><li>Sales declining in China and Russia but growing in Europe</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>Automation should increase sales revenue / profit</li><li>Lower costs allow JLR to remain price-competitive with BMW and Mercedes</li><li>Higher quality reduces warranty claims and reputational damage</li><li>24/7 operation allows JLR to increase output to meet European demand growth</li></ul></div><div class=\"marks-section\"><h5>Exemplar Model Answer</h5><p><strong>Advantage 1:</strong> Automation will increase the number of cars JLR can produce (U). Machines can work 24/7, unlike human workers, meaning more luxury cars can be produced at JLR''s factories (APP). This should increase JLR''s total sales revenue and help it compete more effectively against rivals BMW and Mercedes in the European market (AN).</p><p><strong>Advantage 2:</strong> Automation can ensure more consistent and accurate production quality (U). Since JLR specialises in luxury cars, its customers expect very high standards of quality and finishing (APP). Reducing errors and defects will lower costs associated with warranty claims and repairs, protecting JLR''s premium reputation and profit margins (AN).</p></div>"}, {"question": "Analyse one advantage and one disadvantage to the Montana Bakery of switching from batch production to flow production in the new factory. [6 marks]", "marks": 6, "hint": "This is two 3-mark analyses. For each (advantage AND disadvantage): (1) State the point (U), (2) Apply it to the Montana Bakery using evidence from the text (APP), (3) Explain the business impact (AN). The most powerful application points are: the variety of speciality products Montana makes, its high quality requirements for M&S, and the use of automation.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 6 marks (AO1b: 2, AO2: 2, AO3a: 2)</h5><ul><li>1 mark for understanding of an ADVANTAGE of switching to flow (max 1)</li><li>1 mark for applying the advantage to Montana Bakery using text evidence (max 1)</li><li>1 mark for analysing the impact of the advantage on Montana (max 1)</li><li>1 mark for understanding of a DISADVANTAGE of switching to flow (max 1)</li><li>1 mark for applying the disadvantage to Montana Bakery using text evidence (max 1)</li><li>1 mark for analysing the impact of the disadvantage on Montana (max 1)</li></ul></div><div class=\"marks-section\"><h5>Advantages (Understanding) may include:</h5><ul><li>Quicker / cheaper to produce at higher volume</li><li>More machinery can be used / fewer workers needed</li><li>Better productivity / improved quality control at scale</li></ul></div><div class=\"marks-section\"><h5>Disadvantages (Understanding) may include:</h5><ul><li>Cost of making the change / stopping production to install line</li><li>Perceived quality may fall / products become less unique</li><li>Cost of making workers redundant</li><li>Production line breakdown halts everything</li></ul></div><div class=\"marks-section\"><h5>Application may include:</h5><ul><li>Montana produces speciality breads, rolls, garlic breads and pizza bases — a range of products</li><li>Montana is automating some production in the new factory</li><li>M&S has high quality requirements (own-brand, premium retailer)</li><li>Montana also sells to other retailers and sandwich makers</li><li>Montana has grown and moved to a larger factory</li></ul></div><div class=\"marks-section\"><h5>Analysis may include:</h5><ul><li>Increased output could allow Montana to supply more M&S stores / gain new customers</li><li>Loss of speciality quality could cause M&S to reduce its orders / find a different supplier</li><li>Lower costs could improve profit margins</li><li>Assembly line breakdown could halt all production, losing customers and profit</li></ul></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>Most candidates identified an advantage and disadvantage of switching to flow production. Many could analyse the effects on Montana Bakery. However, applying the analysis to the specific data about Montana (the variety of speciality products, the automation of the new factory, the M&S relationship) proved more difficult.</p></div>"}, {"question": "Recommend whether the Montana Bakery should switch from batch production to flow production in the new factory. [3 marks]", "marks": 3, "hint": "This is a 3-mark EVALUATE/RECOMMEND question — it is AO3b only. You will NOT gain marks for more analysis. Make a clear recommendation (switch or don''t switch), give a reason that weighs up the options, and use specific information from the case study to support your judgement.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b)</h5><ul><li><strong>Judgement (1 mark):</strong> A clear recommendation — should OR should not switch (either is valid)</li><li><strong>Justification (1 mark):</strong> A clear reason supporting the judgement, weighing up the options</li><li><strong>Context (1 mark):</strong> Use of specific information from the case study in the justification</li></ul><p><strong>Note:</strong> Further analysis of production methods does not earn marks here. Only evaluation (judgement + justification + context) is rewarded.</p></div><div class=\"marks-section\"><h5>Exemplar Model Answers</h5><p><strong>Option 1 (Switch to flow):</strong> The Montana Bakery should switch to flow production (1) because the cost savings it is likely to make are more important than any loss of perceived quality (1) in a competitive bread market where customers often buy the cheapest option (1).</p><p><strong>Option 2 (Stay with batch):</strong> The Montana Bakery should NOT switch to flow production (1) because its reputation for speciality breads is central to its value to M&S (1). M&S is committed to high quality own-brand food, and if Montana''s speciality range becomes standardised through flow production, M&S may lose confidence and switch to a different supplier, which would threaten Montana''s entire business (1).</p></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>A good answer made a clear recommendation with a contextual justification. Both judgements were perfectly acceptable. The most powerful evaluations used \"it depends on...\" phrasing — e.g., \"it depends on whether Montana wants to continue making speciality breads\" or \"it depends on whether cost or quality is more important to M&S in the bread market.\"</p></div>"}, {"question": "Explain one impact on Costa Coffee employees of the business investing in updating computer software. [2 marks]", "marks": 2, "hint": "Think about HOW updated computer software would change what Costa Coffee employees actually do — especially in the finance function. Remember: the question is about the impact on EMPLOYEES, not on customers.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a: 1, AO2: 1)</h5><ul><li><strong>Mark 1 (Knowledge):</strong> Identifying an impact of computer software on employees.</li><li><strong>Mark 2 (Application):</strong> Applying the impact specifically to Costa Coffee employees.</li></ul><p><strong>No application marks can be gained without the knowledge mark.</strong></p><p><strong>Acceptable answers (Knowledge) include:</strong></p><ul><li>Efficiency / quicker completion of tasks</li><li>Training required to use the new software</li><li>May lead to redundancy (fewer staff needed)</li><li>Ease of completing administrative tasks</li><li>Improved motivation through less repetitive manual tasks</li></ul><p><strong>Acceptable answers (Application) include:</strong></p><ul><li>Less time taken doing jobs in the finance department</li><li>May lead to redundancy in the finance area</li><li>Allow management employees to co-ordinate the 2,100 UK branches / 1,200 international branches</li><li>Employees in Welshpool branch benefit from improved systems</li><li>Helps co-ordinate the supply chain for coffee beans</li></ul><p><strong>Exemplar response:</strong> One possible impact is that the new software may improve the efficiency (1) of a Costa Coffee employee as they can produce financial data more quickly (APP) (1).</p></div><div class=\"marks-section\"><h5>Examiner''s Comments</h5><p>The impact needed to be applied to the specific scenario of Costa Coffee employees. The most obvious good answers linked the impact to employees working within the finance function. Many answers were too generic and could have applied to any business rather than specifically to Costa Coffee.</p></div>"}, {"question": "Jenny Carson makes and ices wedding cakes. Which method of production is she likely to use? [1 mark]", "marks": 1, "hint": "Each wedding cake is unique and made to a specific customer''s order. Which method makes one product at a time?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Job production</h5><p><strong>Why A is correct:</strong> Each wedding cake is unique and made individually to the specific order of the customer. This is the definition of job production — products are made individually, often requiring skilled labour and producing high-quality, bespoke items.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B (Batch production)</strong> — This would mean making a group of the same type of cake, then switching to a different type. Jenny makes each cake uniquely to order, not in batches.</li><li><strong>C (Flow production)</strong> — Flow production makes the same product continuously in large quantities. Individual, unique wedding cakes cannot be mass-produced on an assembly line.</li><li><strong>D (Robotic production)</strong> — Robotic production is not one of the three official OCR production methods. The skill and artistry involved in icing a wedding cake also requires human craftsmanship.</li></ul></div>"}, {"question": "Warburton''s bakery uses batch production to make its bread. Which of the following is a disadvantage to Warburton''s of using batch production to make its bread? [1 mark]", "marks": 1, "hint": "Look for the option that is a PROBLEM for Warburton''s — not a benefit. Think about what batch production prevents or limits.", "markScheme": "<div class=\"marks-section\"><h5>Answer: C — It may have to reduce the different types of bread that it can offer.</h5><p><strong>Why C is correct:</strong> If production switching becomes too complex or costly, Warburton''s may be forced to limit the number of different bread varieties it produces — reducing customer choice and potentially losing sales to competitors with wider ranges.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A (Lower costs)</strong> — Lower costs is an ADVANTAGE of batch production, as specialist machinery can be used and production runs are efficient.</li><li><strong>B (Meets varied demand)</strong> — Meeting the needs of different customers is an ADVANTAGE — it is the main reason bakeries use batch production.</li><li><strong>D (Made to order / no storage needed)</strong> — Making bread to specific orders, reducing storage costs, is an ADVANTAGE of batch production.</li></ul></div>"}, {"question": "Which of the following is not an example of automation? [1 mark]", "marks": 1, "hint": "Automation means a computer or machine does the task with NO human direct control. Which option requires a skilled human to do the work?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B — The hand-making of a wedding dress.</h5><p><strong>Why B is correct:</strong> Hand-making a wedding dress is done by a skilled human worker using their own judgement, creativity, and craft skills. There is no machine or computer controlling the process. This is an example of job production, not automation.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A</strong> — Beer bottles passing a labelling machine is automation: the machine applies labels without a human controlling it at each step.</li><li><strong>C</strong> — Door sensors that detect people and open automatically are automation — the computer/sensor controls the door without human input.</li><li><strong>D</strong> — The Vauxhall Motors example is automation: the online order goes directly into the production system without any further human input, which is a form of computer-controlled automation.</li></ul></div>"}, {"question": "Which of these statements is false? [1 mark]", "marks": 1, "hint": "Think carefully — TWO of these statements are false, but which one is the MOST clearly false and directly contradicts what you''ve learned?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Modern businesses do not use job production.</h5><p><strong>Why A is correct (i.e., A is FALSE):</strong> Many modern businesses use job production — from large construction projects like Crossrail, to hand-crafted furniture makers, to bespoke advertising campaigns. This statement is factually incorrect.</p><p><strong>Note on the other options:</strong></p><ul><li><strong>B</strong> is also false (flow production still requires workers to oversee machines), but A is the intended answer as it directly targets a common student misconception.</li><li><strong>C</strong> is TRUE — bakeries like Warburton''s and Crown Paints use batch production.</li><li><strong>D</strong> is TRUE — flow production benefits from economies of scale, giving lower unit costs than job production.</li></ul></div>"}, {"question": "What is meant by the term ''job production''? [1 mark]", "marks": 1, "hint": "Give the official definition. Use the key word ''individually''.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a)</h5><p>Award 1 mark for a correct definition:</p><ul><li>Is the process of production where products are made <strong>individually</strong></li><li>Each product is made one at a time / to the specific order of the customer</li><li>Products are unique / bespoke</li></ul></div>"}, {"question": "What is meant by the term ''batch production''? [1 mark]", "marks": 1, "hint": "Give the official definition. The key idea is that one type of product is made, then production switches to a different type.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a)</h5><p>Award 1 mark for a correct definition:</p><ul><li>Is the process of production where one type of product is made and then production is switched to make a different product</li><li>Groups of similar products are made together before switching to a different group</li></ul></div>"}, {"question": "Analyse one benefit of ''Delicious Cakes'' using job production. [3 marks]", "marks": 3, "hint": "Use the 3-step formula: (U) State a benefit of job production → (APP) Link it to something specific about Delicious Cakes in the case study → (AN) Explain the business impact this creates for Delicious Cakes.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b, AO2, AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> States a benefit of job production (e.g., high quality / bespoke / meets individual needs / worker satisfaction)</li><li><strong>Application (1 mark):</strong> Applies to Delicious Cakes specifically — e.g., their spectacular wedding cakes decorated with intricately designed flowers / minimum price of £700 / strong customer loyalty</li><li><strong>Analysis (1 mark):</strong> Explains the business impact — e.g., can charge premium prices / strong customer loyalty → repeat business → increased revenue</li></ul></div><div class=\"marks-section\"><h5>Exemplar Model Answer</h5><p>Job production allows Delicious Cakes to produce high-quality, unique products that are tailored to each customer''s exact requirements (U). Delicious Cakes makes spectacular wedding cakes decorated with intricately designed flowers, with a minimum price of £700 (APP). This allows the business to charge premium prices and build strong customer loyalty, generating high revenue per cake despite lower volumes of output (AN).</p></div>"}, {"question": "Analyse one drawback of ''Delicious Cakes'' using batch production. [3 marks]", "marks": 3, "hint": "Delicious Cakes currently uses job production to make unique cakes. If it SWITCHED to batch production, what would be the drawback? Think about what the business would LOSE by making cakes in batches rather than individually.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b, AO2, AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> States a drawback of batch production (e.g., switching time / stock costs / repetitive work / less unique products / less customer choice)</li><li><strong>Application (1 mark):</strong> Applies to Delicious Cakes specifically — e.g., their focus on unique, tailor-made cakes / intricately designed flowers / strong customer loyalty / minimum £700 price</li><li><strong>Analysis (1 mark):</strong> Explains the business impact — e.g., loss of bespoke nature → loss of premium pricing / loss of customer loyalty → reduced revenue</li></ul></div><div class=\"marks-section\"><h5>Exemplar Model Answer</h5><p>A drawback of batch production is that the products made would be less unique — each batch makes the same design (U). Delicious Cakes is renowned for its unique, tailor-made wedding cakes decorated with intricately designed flowers that meet specific customer needs (APP). If Delicious Cakes switched to batch production, it would lose this bespoke quality, meaning it could no longer justify its minimum £700 price point and would likely lose its strong customer loyalty and revenue (AN).</p></div>"}, {"question": "Analyse one benefit to Amazon from using robots in their warehouses. [3 marks]", "marks": 3, "hint": "Use U → APP → AN. Pick ONE benefit (productivity, speed, cost saving, worker motivation). Link it specifically to the Amazon case study — use the data (e.g., three times more packages, Prime delivery, 51% sales increase). End with a clear business impact.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b, AO2, AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Gives an example of a benefit of using robots, e.g.: speed up production / increase productivity of workers / save on wage costs / improve motivation (less walking) / faster delivery</li><li><strong>Application (1 mark):</strong> Relates to the Amazon case study specifically — cannot be gained without Understanding, e.g.: Workers at Amazon can handle over three times as many packages. Amazon can now deliver to customers within one day (Prime).</li><li><strong>Analysis (1 mark):</strong> Gives the effect/impact on Amazon, e.g.: Cost savings may allow Amazon to reduce prices, making it more competitive. Speedier Prime delivery will increase sales as customers want purchases quickly.</li></ul></div><div class=\"marks-section\"><h5>Exemplar Model Answers</h5><p><strong>Model Answer 1 (productivity):</strong> A benefit of using robots is that they increase the productivity of workers in the warehouse (U). The text states that each Amazon warehouse worker can now handle over three times more packages per shift than before (APP). This means Amazon can process and dispatch orders much faster, increasing sales and enabling the introduction of the Prime next-day delivery service, which is a major competitive advantage (AN).</p><p><strong>Model Answer 2 (cost):</strong> Robots help Amazon reduce its labour costs as fewer human pickers are needed (U). Previously, human ''pickers'' had to walk many miles each day — with robots doing this task, fewer workers are required for the same output (APP). The saving on wages means Amazon can afford to keep its prices competitive, helping it win sales from other online and high-street traders (AN).</p></div>"}, {"question": "Analyse one problem for Amazon from using robots in warehouses. [3 marks]", "marks": 3, "hint": "Use U → APP → AN. Pick ONE problem (injuries, breakdown risk, cost, worker morale). Link it specifically to the Amazon case study. End with a clear business impact on Amazon — not just on the workers.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b, AO2, AO3a)</h5><ul><li><strong>Understanding (1 mark):</strong> Gives an example of a problem with using robots, e.g.: could demotivate staff / robots cost money / robots replace workers / robots can break down / increased injury risk</li><li><strong>Application (1 mark):</strong> Relates to the Amazon case study specifically, e.g.: The number of injuries at Amazon has increased since robots were introduced. Each worker now handles three times more packages, creating physical strain.</li><li><strong>Analysis (1 mark):</strong> Gives the effect/impact on Amazon, e.g.: The rise in injuries may lead to increased compensation claims and costs. Amazon''s reputation may suffer, deterring job applicants. A robot breakdown could cause customers to cancel orders and order from competitors.</li></ul></div><div class=\"marks-section\"><h5>Exemplar Model Answer</h5><p>A problem with using robots is that they can increase the risk of injury to workers (U). The text states that since Amazon introduced robots, there has been an increase in the number of worker injuries — as each worker now handles over three times more packages, placing greater physical demands on them (APP). This may lead to an increase in compensation claims, adding to Amazon''s costs, and could damage Amazon''s reputation as an employer, making it harder to recruit workers in the future (AN).</p></div>"}, {"question": "Evaluate whether or not Amazon should continue to use robots in their warehouses. [3 marks]", "marks": 3, "hint": "This is an AO3b EVALUATE question — do NOT repeat analysis points. Make a JUDGEMENT (yes or no), JUSTIFY it with a reason, and SUPPORT it with specific data from the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b)</h5><ul><li><strong>Judgement (1 mark):</strong> Makes a clear statement about whether Amazon should or should not continue to use robots (either is acceptable)</li><li><strong>Justification (up to 2 marks):</strong> Justifies the judgement using information from the case study</li></ul><p>Both \"should continue\" and \"should not continue\" are perfectly valid answers — marks depend on the quality of justification, not the direction of the argument.</p></div><div class=\"marks-section\"><h5>Exemplar Model Answers</h5><p><strong>Option 1 (should continue):</strong> The use of robots has been very important for Amazon (Judgement). Amazon''s UK sales increased by 51% to £19.4 billion and employment grew by 3,000 workers, suggesting that the use of robots has been good for the business overall (Justification + Context). The robots have given Amazon a major competitive advantage through Prime next-day delivery, which is a key reason customers choose Amazon over other retailers.</p><p><strong>Option 2 (depends / qualified yes):</strong> The overall impact of robots depends on whether the additional revenue from increased sales outweighs the additional costs (Judgement). Sales have risen by 51% suggesting revenues have increased significantly (Context). However, if compensation claims for the increased worker injuries are very high, and if a robot breakdown caused major disruption, the net benefit might be lower than it appears (Justification).</p></div>"}]}}'::jsonb),
('business', '4-2-quality-of-goods-services', '4.2 Quality of Goods & Services', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>These are the essential terms you <strong>must</strong> know for this topic. Examiners award no credit for vague or imprecise definitions — learn these word-for-word.</p>\n<ul>\n  <li><strong>Quality:</strong> A product or service that is <strong>fit for purpose</strong> — it does what it is supposed to do, meets legislative rules (e.g. design and safety regulations), and meets <strong>customer expectations</strong>.</li>\n  <li><strong>Quality Control:</strong> A system for <strong>inspecting</strong> the quality of goods or services produced to ensure they are of a good standard. Checking is typically carried out by specialist inspectors at the end of, or during, production.</li>\n  <li><strong>Quality Assurance:</strong> An approach that involves the <strong>whole business</strong> focusing on quality, aiming to <strong>prevent</strong> quality problems from arising. Every employee at every stage of production is responsible for quality.</li>\n  <li><strong>Returns:</strong> Goods which customers take back to the shop because there are problems with the quality of them.</li>\n  <li><strong>Recalls:</strong> When a fault occurs with a product and the business asks for the product to be brought back so it can be repaired or replaced (e.g. Whirlpool washing machines in 2019).</li>\n  <li><strong>Mystery Shopper:</strong> A person who pretends to be a normal customer but secretly evaluates whether the service provided meets the required standard.</li>\n  <li><strong>Fit for Purpose:</strong> A product or service that fulfils its intended function and meets the reasonable expectations of the customer at the price they paid.</li>\n</ul>", "check": {"question": "According to the official definition, quality assurance is best described as...?", "options": ["A process only used to identify recalls after sale", "Every employee preventing quality problems at every stage", "Specialist inspectors checking finished goods at the end", "A promise that a product is the most expensive"], "answer": 1, "explain": "Quality assurance is a whole-business approach where every employee is responsible for quality at every stage, aiming to prevent problems rather than just catch them."}}, {"title": "The Concept of Quality", "html": "<p>Quality does <strong>not</strong> mean the most expensive or the best product on the market. A product or service is considered quality when it meets <strong>three criteria</strong>:</p>\n<ul>\n  <li><strong>Fit for purpose</strong> — it does what it is supposed to do</li>\n  <li><strong>Meets legislative rules</strong> — complies with design and safety regulations</li>\n  <li><strong>Meets customer expectations</strong> — even a cheap product can be quality if it does what the customer expected when buying it at that price point</li>\n</ul>\n<p>⚠️ <strong>Key Examiner Insight:</strong> Quality is about <em>meeting expectations</em>, not luxury. A budget supermarket own-brand tin of beans is quality if it tastes acceptable and the tin seals correctly. A £500 designer handbag that falls apart is <em>not</em> quality. This distinction comes up constantly in exam questions.</p>\n<p>The saying <strong>\"It costs five times more to gain a customer than to keep a customer\"</strong> highlights why quality matters strategically. Losing a customer through poor quality is easy — winning them back (or finding new ones) requires costly marketing campaigns.</p>\n<div class=\"case-study-box\">\n  <h4>Case Study: The Holiday Park (Tripadvisor)</h4>\n  <p>Online review platforms like Tripadvisor allow customers to share experiences publicly. A negative review describing a dirty caravan, broken TV, and rude staff can be read by thousands of potential customers — devastating a business''s bookings overnight. This illustrates how a failure to meet customer quality expectations directly translates into lost revenue and lasting reputational damage.</p>\n</div>", "check": {"question": "Which of these best illustrates the key examiner insight about quality described in this card?", "options": ["A product that is manufactured using the most advanced automated machinery", "A product that costs the business the most money to manufacture", "A budget tin of beans that tastes acceptable and seals correctly for its price", "Only premium products that are bought by customers at a high price"], "answer": 2, "explain": "The card stresses that quality is about meeting expectations at the price paid, not about luxury — a cheap product can be quality, and an expensive one can fail to be."}}, {"title": "The Importance of Quality", "html": "<p>There are four key consequences of <strong>poor quality</strong> that a business must avoid:</p>\n<ul>\n  <li><strong>Avoids Waste:</strong> Poor-quality goods cannot be sold at full price (or must be sold cheaply as ''seconds''). The business has already spent money on materials and labour — those resources are wasted. Customer returns also cost money to process and replace.</li>\n  <li><strong>Avoids Recalls:</strong> If a safety fault is discovered after products are already sold, the business must recall them. This is hugely expensive — involving engineer visits, repair costs, compensation payments, and severe reputational damage.</li>\n  <li><strong>Reputation and Sales:</strong> Customers who receive poor-quality goods or services may buy from a competitor in future, tell friends and family, or post negative reviews online. A poor reputation is extremely difficult and expensive to reverse — the business loses both existing and potential new customers.</li>\n  <li><strong>Disrupted Production:</strong> If components produced early in the production process are faulty, they cannot be used in later stages — shutting down or slowing the entire production line and increasing unit costs.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Whirlpool Recalls (2019–2020)</h4>\n  <p>In 2019, Whirlpool identified 519,000 Indesit and Hotpoint washing machines at risk of fire due to a door lock fault (machines made 2014–2018). Engineers had to visit every affected customer''s home for free. In 2020, a further 55,000 machines were recalled. Earlier, 5 million tumble dryers had also been recalled — some caused actual fires. In 2016, 50 residents at Shepherds Court, London, needed alternative accommodation after a fire caused by a Whirlpool tumble dryer. The company paid compensation to all affected residents. This case illustrates the catastrophic financial and reputational cost of quality failure on a large scale.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Customer Service Research (Opinium, 2020)</h4>\n  <p>A survey of 2,000 UK consumers found 79% had experienced bad customer service. Of these, 54% said they would not return to a business after poor service — costing the UK economy an estimated £2.5 billion in lost sales annually. The top-rated businesses during the pandemic were Tesco, Asda, and M&S — all of which adapted quickly to meet changed customer needs.</p>\n</div>", "check": {"question": "How many Indesit and Hotpoint washing machines did Whirlpool identify as at risk of fire in its 2019 recall?", "options": ["519,000", "55,000", "2,000", "5 million"], "answer": 0, "explain": "The case study states Whirlpool identified 519,000 washing machines made 2014–2018 as at risk of fire due to a door lock fault."}}, {"title": "Quality Control — How It Works", "html": "<p><strong>Quality control</strong> is about <em>checking</em> that a product or service meets required standards. It catches defects but does <strong>not prevent them from happening</strong> in the first place — that is the key distinction from quality assurance.</p>\n<p>Methods used in quality control:</p>\n<ul>\n  <li><strong>Physical inspection:</strong> Specialist inspectors sample raw materials, goods during manufacture, or finished products. Some items are tested in a laboratory (e.g. pharmaceutical drugs, food products).</li>\n  <li><strong>Automated machine checks:</strong> Machinery programmed to detect faults automatically ejects items that fail to meet standards — no human inspector required for that stage.</li>\n  <li><strong>Mystery shopper:</strong> A paid individual poses as a normal customer and covertly scores the service on categories such as staff helpfulness, facilities, speed, and product quality. A written report is sent to management for action.</li>\n  <li><strong>Customer satisfaction surveys:</strong> Customers rate their experience after purchase. The business uses the data to identify recurring problems and make targeted improvements.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Heinz Beanz — Automated Quality Control</h4>\n  <p>The Heinz Beanz factory in Wigan produces approximately 3 million cans every day using a highly automated process. Machinery is programmed to detect faults in cans or labels. If a can is the wrong weight or has not been properly sealed, it is automatically ejected from the production line before it can be sold to customers. This is a textbook example of quality control using technology — faults are caught at the end of production rather than prevented at source.</p>\n</div>", "check": {"question": "In the Heinz Beanz case study, approximately how many cans does the Wigan factory produce each day?", "options": ["10 million", "50,000", "3 million", "500,000"], "answer": 2, "explain": "The Heinz Beanz factory in Wigan produces approximately 3 million cans every day using a highly automated quality control process."}}, {"title": "Quality Control — Advantages & Disadvantages", "html": "<p>Use this two-column layout to evaluate quality control in exam answers:</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Prevents faulty goods reaching customers:</strong> Inspection catches defects before products leave the factory, reducing the number of returns and recalls.</div>\n    <div class=\"pro-item\"><strong>Non-disruptive to production:</strong> Workers continue producing while specialist inspectors do the checking — the production line does not need to stop, keeping output levels high.</div>\n    <div class=\"pro-item\"><strong>Improved reputation:</strong> Consistently meeting quality standards builds consumer confidence, which can increase repeat purchases and attract new customers.</div>\n    <div class=\"pro-item\"><strong>Suitable for technical products:</strong> Products like pharmaceutical drugs or chemicals require specialist laboratory testing that workers could not carry out themselves — quality control is the only viable approach here.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>Does not prevent waste:</strong> Faulty goods are only discovered after they have already been made — the materials and labour used to produce them are wasted, increasing costs.</div>\n    <div class=\"con-item\"><strong>Costly inspection process:</strong> The business must pay inspectors'' wages and fund the cost of testing equipment or laboratory analysis, adding to total production costs.</div>\n    <div class=\"con-item\"><strong>Workers not responsible for quality:</strong> Because inspectors do the checking, ordinary workers have no personal ownership of quality standards — this can reduce care and vigilance on the production line.</div>\n    <div class=\"con-item\"><strong>May miss faults:</strong> If only a sample of products are inspected, some faulty items may pass through undetected and reach customers.</div>\n  </div>\n</div>", "check": {"question": "Which of these is listed as a disadvantage of quality control?", "options": ["Workers have less personal responsibility for quality", "Production stops while workers check their own work", "It builds a culture of continuous improvement", "It needs extensive training for every employee"], "answer": 0, "explain": "Because inspectors do the checking under quality control, ordinary workers have no personal ownership of quality standards, which can reduce care and vigilance."}}, {"title": "Quality Assurance — How It Works", "html": "<p><strong>Quality assurance</strong> is about <em>preventing</em> quality problems before they arise. It creates a <strong>culture of quality</strong> throughout the whole organisation — not just in a dedicated inspection department.</p>\n<p>Key features of quality assurance:</p>\n<ul>\n  <li><strong>Every employee is involved</strong> at every stage of the production process — this is sometimes called Total Quality Management (TQM).</li>\n  <li>Each worker treats the <strong>next person in the production process as their internal customer</strong> — they must be satisfied with the quality of what has been passed to them.</li>\n  <li>Employees are <strong>encouraged to suggest improvements</strong> — regular meetings at all levels focus on continuous improvement.</li>\n  <li>Quality is <strong>built into the process</strong> from the start, rather than checked at the end.</li>\n  <li>Products and services are designed with consumer needs at the centre from the outset.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Toyota Motors — Quality Assurance in Manufacturing</h4>\n  <p>Toyota is perhaps the company most closely associated with quality assurance. Its system stresses <em>continuous improvement</em> (''kaizen'') and requires every employee to suggest improvements and take personal responsibility for the quality of their own work. Toyota aims to reduce waste at every stage and produce cars that precisely meet customer needs. Its two core principles are ''customer first'' and ''respect for people''.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Disney World, Florida — Quality Assurance in Services</h4>\n  <p>Disney World applies quality assurance to a service business. All employees — from actors in parades to street cleaners — are called ''cast members''. The entire visitor experience is treated as a ''show'' that every worker contributes to. Each cast member is personally responsible for delivering high-quality service at all times, ensuring every customer has a great experience. This shows that quality assurance is just as relevant to service industries as it is to manufacturing.</p>\n</div>", "check": {"question": "What are Toyota''s two core principles, according to the case study in this card?", "options": ["Cost reduction and automation", "Customer first and respect for people", "Innovation and profit maximisation", "Speed and efficiency"], "answer": 1, "explain": "The case study states Toyota''s two core principles are ''customer first'' and ''respect for people'', which underpin its continuous-improvement (''kaizen'') approach to quality assurance."}}, {"title": "Quality Assurance — Advantages & Disadvantages", "html": "<p>Use this two-column layout when evaluating quality assurance in exam answers:</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages</div>\n    <div class=\"pro-item\"><strong>Reduces wastage and costs:</strong> Because quality is checked at every stage, faults are caught early before more resources are invested in a defective product — reducing production costs.</div>\n    <div class=\"pro-item\"><strong>Motivates workers:</strong> Employees feel valued and trusted when given personal responsibility for quality. This can increase effort, engagement, and output quality.</div>\n    <div class=\"pro-item\"><strong>Improved reputation:</strong> A whole-business focus on quality builds a consistent, strong reputation over time, which attracts and retains customers and may allow the business to charge higher prices.</div>\n    <div class=\"pro-item\"><strong>Fewer returns and recalls:</strong> Catching problems during production means fewer defective products ever reach customers — saving the cost of returns, recalls, and compensation payments.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages</div>\n    <div class=\"con-item\"><strong>May disrupt production:</strong> Workers stopping to check their own work slows down the production line, potentially reducing output per hour and raising the cost per unit.</div>\n    <div class=\"con-item\"><strong>High training costs:</strong> Workers need extensive training to assess and take responsibility for quality standards — this requires significant investment in time and HR resources.</div>\n    <div class=\"con-item\"><strong>Worker resistance:</strong> Some employees may be uncomfortable with the added pressure of responsibility for quality and may resist the introduction of QA methods — potentially causing conflict or lower morale.</div>\n    <div class=\"con-item\"><strong>Not suitable for all products:</strong> Highly technical products such as pharmaceutical drugs still require specialist laboratory testing that ordinary production workers cannot perform, regardless of QA procedures.</div>\n  </div>\n</div>", "check": {"question": "According to this card, which type of product still requires specialist laboratory testing even under quality assurance?", "options": ["Pharmaceutical drugs", "Bicycles", "Own-brand tinned beans", "Washing machines"], "answer": 0, "explain": "The card notes that highly technical products such as pharmaceutical drugs still require specialist laboratory testing that ordinary production workers cannot perform, regardless of QA procedures."}}, {"title": "Quality Control vs Quality Assurance — Evaluation", "html": "<p>When a question asks you to evaluate or recommend a quality method, always consider the <strong>context</strong> — the type of product, the business''s size, and the specific problem being faced.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">Use Quality Control when...</div>\n    <div class=\"pro-item\">The product is highly technical and requires specialist lab testing (e.g. drugs, chemicals, food safety checks)</div>\n    <div class=\"pro-item\">The business needs production to run without interruption — workers focus on output, inspectors on quality</div>\n    <div class=\"pro-item\">Automated machinery can perform checks efficiently at high speed (e.g. Heinz Beanz production line)</div>\n  </div>\n  <div>\n    <div class=\"col-head\">Use Quality Assurance when...</div>\n    <div class=\"pro-item\">The workforce is skilled enough to judge and take responsibility for their own work (e.g. car manufacturing at Toyota)</div>\n    <div class=\"pro-item\">The business wants to reduce waste at source rather than discover it at the end of production</div>\n    <div class=\"pro-item\">The business operates in the service sector and wants all staff personally invested in customer experience (e.g. Disney World)</div>\n  </div>\n</div>\n<p><strong>Key evaluation point for high-mark answers:</strong> Building a reputation for quality takes a <em>long time</em>. Losing it can happen <em>very quickly</em>. A business that invests in either quality method protects itself from the costs of waste, returns, recalls, and customer loss. However, the method must match the business context — there is no single ''right'' answer.</p>\n<p><strong>The ''It depends on...'' rule:</strong> In a 6–9 mark evaluation, always qualify your recommendation. For example: \"Quality assurance would be more beneficial for ABC Bicycles because it reduces waste, but this depends on whether the business can afford the significant training costs involved.\"</p>", "check": {"question": "According to this evaluation card, when should a business use quality assurance rather than quality control?", "options": ["When the product requires specialist lab testing, such as drugs or chemicals", "When automated machinery can perform checks at high speed and scale", "When production must run continuously without any interruption at all", "When the workforce is skilled enough to take responsibility for quality"], "answer": 3, "explain": "The card states quality assurance suits businesses where the workforce is skilled enough to judge and take responsibility for their own work, using Toyota as the example."}}]}, "terms": {"enabled": true, "pairs": [{"term": "Quality", "definition": "A product or service that is fit for purpose, meets legislative rules, and meets customer expectations."}, {"term": "Quality Control", "definition": "Inspecting goods or services using specialist inspectors to ensure they meet the required standard — checking happens at or near the end of production."}, {"term": "Quality Assurance", "definition": "A whole-business approach to quality where every employee is responsible for preventing quality problems at every stage of production."}, {"term": "Returns", "definition": "Goods taken back to a shop by customers because of quality problems."}, {"term": "Recalls", "definition": "When a business asks customers to return a product after a fault is identified, so it can be repaired or replaced."}, {"term": "Mystery Shopper", "definition": "A person who secretly poses as a customer to evaluate whether a business''s service meets the required standard."}, {"term": "Fit for Purpose", "definition": "A product that does what it is supposed to do and meets the reasonable expectations of the customer for the price paid."}, {"term": "Waste (quality)", "definition": "Resources used to produce faulty goods that cannot be sold at full price — a key cost of poor quality production."}, {"term": "Advantage of QC over QA", "definition": "Quality control does not disrupt production — workers keep producing while specialists do the checking."}, {"term": "Advantage of QA over QC", "definition": "Quality assurance reduces waste because faults are caught early in production before more resources are spent on defective goods."}, {"term": "Disadvantage of Quality Control", "definition": "It does not prevent waste — the materials and labour are already used before the inspector discovers a fault."}, {"term": "Disadvantage of Quality Assurance", "definition": "It may disrupt production and requires expensive training for all workers."}, {"term": "Toyota (quality)", "definition": "A business associated with quality assurance — uses continuous improvement (kaizen) and makes all employees responsible for quality."}, {"term": "Heinz Beanz (quality)", "definition": "A business using quality control — automated machinery ejects cans that are wrong weight or improperly sealed before they can be sold."}, {"term": "Why quality matters", "definition": "Avoids waste, avoids recalls, protects reputation, prevents disrupted production, and retains customers."}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of the following best describes the concept of ''quality'' for a business?", "options": ["Producing goods that are more expensive than those of competitors", "Producing goods or services that are fit for purpose and meet customer expectations", "Using only the highest-grade raw materials regardless of cost", "Ensuring all products outperform the market leader"], "answer": 1, "explain": "Correct answer: Quality means a product or service is fit for purpose, meets legal requirements, and meets customer expectations — not about being the most expensive or most luxurious. Option A confuses quality with premium pricing. Options C and D describe standards that exceed what quality requires."}, {"question": "Which of the following statements best describes quality assurance?", "options": ["Inspectors are used to check the quality of goods being produced", "Only finished goods are checked so no faulty products are sold", "All workers are involved in and responsible for the quality of their work", "Quality is only checked once production is finished so it does not disrupt output"], "answer": 2, "explain": "Correct answer: Quality assurance involves the whole business in maintaining quality — every worker takes personal responsibility at every stage of production. Option A describes quality control (specialist inspectors). Option B describes end-of-line quality control. Option D is false — QA can slow production because workers stop to check their own work."}, {"question": "Which of the following is a disadvantage of using quality control?", "options": ["Inspectors do not need to be paid because workers check their own quality", "Inspectors are better at checking the quality of goods than workers", "Workers do not have to disrupt production to check quality", "Inspectors have to be paid for their work, adding to the cost of production"], "answer": 3, "explain": "Correct answer: Quality control requires specialist inspectors who must be paid a wage, and laboratory testing equipment also has a cost — both add to total production costs. Option A is false (inspectors do need to be paid). Option B is not a disadvantage. Option C is actually an advantage of quality control (production is not disrupted)."}, {"question": "A manufacturer makes chocolate bars. All bars are passed through a machine to check for production mistakes before being boxed. This is an example of:", "options": ["Product development", "Product recall", "Quality assurance", "Quality control"], "answer": 3, "explain": "Correct answer: This is quality control — a system where finished goods are inspected (by a machine acting as the inspector) before reaching the customer. It is end-of-production checking, not prevention at every stage, so it is NOT quality assurance. Option A (product development) means creating new products. Option B (product recall) means bringing products back after they have been sold."}, {"question": "Which of the following would be an example of a quality assurance activity for a car manufacturer?", "options": ["Driving every tenth car to test that the brakes are working correctly", "Holding a meeting with production operatives on how to improve the manufacturing process", "Increasing the amount of money that the operations function can spend", "Visually inspecting two cars of each colour for defects in the paintwork"], "answer": 1, "explain": "Correct answer: Quality assurance involves all workers contributing to improving quality — holding a meeting with production workers to suggest improvements is a classic QA activity (whole-business involvement). Options A and D are quality control examples (sampling and inspection). Option C is a financial/budget decision with no direct link to quality methods."}, {"question": "The concept of ''quality'' refers to making products:", "options": ["By hand", "Of a satisfactory standard", "That are better than the leading brand", "To the highest possible specification"], "answer": 1, "explain": "Correct answer: Quality means producing goods or services to a satisfactory standard — fit for purpose and meeting customer expectations at the price paid. Option A is wrong (quality can apply to machine-made products). Option C is wrong (quality does not mean being better than competitors). Option D is wrong (the highest possible specification may exceed what customers expect or are willing to pay for)."}, {"question": "Zayn owns a business making heated gloves. The business has recently experienced an increase in product returns. Which of the following would best help Zayn deal with this problem?", "options": ["Giving a bonus to the employee who sews the most gloves each month", "Improving quality checks to ensure every glove heats up correctly", "Researching other types of heated clothing the business could make", "Segmenting the market by age, gender and lifestyle"], "answer": 1, "explain": "Correct answer: Product returns indicate a quality problem — gloves are not meeting customer expectations. Improving quality checks (quality control) would catch faulty gloves before they are sold. Option A rewards speed, which may actually make the quality problem worse. Options C and D are unrelated to the quality/returns issue."}, {"question": "QT Homeware Ltd manufactures small kitchen appliances and has received complaints that its kettles leak. Which action would best help deal with this problem?", "options": ["Include a cloth to wipe up any leaks in the box of all new kettles", "Launch a promotional campaign in a housekeeping magazine", "Meet with production workers to discuss how to reduce costs", "Physically test every hundredth kettle to ensure it is watertight"], "answer": 3, "explain": "Correct answer: Physically testing kettles to ensure they are watertight is a quality control measure that directly addresses the root cause of the complaints. Option A treats the symptom (leaks) rather than solving the underlying quality fault. Option B is a marketing activity that does not fix the product. Option C focuses on cost reduction, not quality improvement."}, {"question": "Sabena works for a small business that makes computers. Her main task is to test every computer before it leaves the factory. What key business function does Sabena perform?", "options": ["After sales service", "Quality control", "Setting production levels", "Supply chain management"], "answer": 1, "explain": "Correct answer: Sabena inspects every finished computer before it reaches the customer — this is quality control (checking finished goods to ensure they meet the required standard). After-sales service (A) happens after the product is sold and delivered. Setting production levels (C) is an operations management decision. Supply chain management (D) involves managing suppliers and logistics."}, {"question": "The concept of quality requires a business to:", "options": ["Charge low prices for its services", "Produce the best goods on the market", "Provide services to required standards", "Source its raw materials from ethical suppliers"], "answer": 2, "explain": "Correct answer: Quality requires a business to produce goods or services that meet required standards — fit for purpose and meeting customer expectations. Option A (low prices) is about pricing strategy, not quality. Option B (best goods) exceeds what quality requires — being satisfactory is enough. Option D (ethical suppliers) relates to CSR, not the definition of quality."}, {"question": "Which of these statements is TRUE about the importance of quality?", "options": ["It is easy to gain a reputation for quality", "It is easy to lose a reputation for quality", "Producing high-quality goods always increases sales", "Producing high quality is always cheaper than producing low quality"], "answer": 1, "explain": "Correct answer: It is easy to lose a reputation for quality — one product failure or poor customer experience can damage a reputation built over many years. Option A is false: gaining a reputation for quality takes significant time and investment. Option C is false: other factors like price and marketing affect sales. Option D is false: quality production (e.g. better materials, QA training) usually costs more, not less."}, {"question": "A pottery business produces 200 vases per week. Each item costs £45. On average, 2 out of every 50 are faulty and must be scrapped. What is the total cost of this wastage in an average week?", "options": ["£9,000", "£180", "£360", "£720"], "answer": 2, "explain": "Correct answer: Step 1 — find the number of faulty vases: 200 ÷ 50 = 4 batches of 50, each with 2 faulty = 4 × 2 = 8 faulty vases. Step 2 — calculate the cost: 8 × £45 = £360. Option A (£9,000) is the total weekly production cost (200 × £45), not the waste cost. Option B (£180) uses the wrong faulty rate. Option D (£720) doubles the correct answer."}]}, "fib": {"enabled": true, "questions": [{"text": "Quality means a product or service is [fit] for [purpose], meets legislative rules, and meets customer expectations."}, {"text": "Quality [control] involves specialist inspectors checking goods, whereas quality [assurance] involves every worker being responsible for quality."}, {"text": "When a fault occurs with a product after it has been sold, the business may issue a [recall] asking customers to return the product for repair or replacement."}, {"text": "Goods taken back to a shop by dissatisfied customers due to quality problems are called [returns]."}, {"text": "A [mystery] shopper is a person who pretends to be a normal customer but secretly evaluates the quality of the service provided."}, {"text": "An advantage of quality control is that it does not [disrupt] production because workers continue producing while inspectors do the checking."}, {"text": "A disadvantage of quality assurance is that it may [disrupt] production because workers stop to check the quality of their own work."}, {"text": "Toyota is associated with quality [assurance] because it encourages every employee to suggest improvements and take responsibility for their part in production."}, {"text": "Quality control is particularly suitable for [technical] products such as pharmaceutical drugs, where specialist laboratory testing is required."}, {"text": "A disadvantage of quality control is that it does not prevent [waste] of resources when products are found to be faulty."}, {"text": "A [reputation] of quality takes a long time to build, but can be lost very quickly if goods or services fail to meet customer expectations."}, {"text": "In quality assurance, each employee is expected to treat the next person in the production process as an internal [customer], who must be satisfied with the quality of work passed to them."}]}, "tf": {"enabled": true, "questions": [{"statement": "Quality means a product or service must be the most expensive or best on the market.", "answer": false, "explain": "FALSE. Quality means a product or service is fit for purpose and meets customer expectations at the price paid — not that it must be the most expensive or best available."}, {"statement": "In quality assurance, every employee at every stage of production is responsible for quality.", "answer": true, "explain": "TRUE. Quality assurance creates a culture of quality throughout the whole business — it is not just the job of specialist inspectors. This is what distinguishes it from quality control."}, {"statement": "Quality control prevents waste because faults are caught before resources are used to make defective goods.", "answer": false, "explain": "FALSE. Quality control does NOT prevent waste — it only catches faults after the goods have already been made. The materials and labour used to produce defective items are already wasted by the time they are inspected."}, {"statement": "A recall occurs when a business asks customers to return a faulty product so it can be repaired or replaced.", "answer": true, "explain": "TRUE. A recall is when a fault is identified in a product that has already been sold, and the business contacts customers to return it for repair or replacement — as Whirlpool did with its washing machines in 2019."}, {"statement": "Quality assurance is non-disruptive to production because workers continue producing while inspectors do the checking.", "answer": false, "explain": "FALSE. This describes quality CONTROL, not quality assurance. Quality assurance can actually disrupt production because workers stop to check the quality of their own work at each stage."}, {"statement": "It is easier to lose a reputation for quality than it is to build one.", "answer": true, "explain": "TRUE. Building a reputation for quality takes a long time and requires consistent investment. Losing it can happen very quickly — a single product failure, recall, or viral negative review can damage years of hard-earned reputation."}, {"statement": "Toyota Motors is an example of a business that uses quality control because inspectors check every car at the end of the production line.", "answer": false, "explain": "FALSE. Toyota is associated with quality ASSURANCE — its system involves all employees being responsible for quality at every stage of production and continuously suggesting improvements. This is the opposite of relying solely on end-of-line inspectors."}, {"statement": "A mystery shopper is an example of a quality control method used in service businesses.", "answer": true, "explain": "TRUE. A mystery shopper is a quality control method — a person posing as a customer who checks the service against required standards and reports findings to management, allowing the business to take corrective action."}, {"statement": "One disadvantage of quality assurance is that it may cost a business a lot of money to train workers to assess the quality of their own work.", "answer": true, "explain": "TRUE. Quality assurance requires all workers to be trained to understand quality standards and assess their own work. This training takes time and money — it is a significant cost, particularly for larger businesses with many employees."}, {"statement": "Quality control is a better method than quality assurance in all situations.", "answer": false, "explain": "FALSE. Neither method is universally better — it depends on the context. Quality control is better suited to highly technical products needing specialist laboratory testing. Quality assurance is better when workers can judge quality themselves and the business wants to build a quality culture and reduce waste."}, {"statement": "Poor quality can lead to disrupted production if faulty materials from an early stage cannot be used in a later stage.", "answer": true, "explain": "TRUE. If materials produced at an early stage in the production process are of insufficient quality, they cannot be passed to the next stage — halting or slowing the entire production line and increasing costs."}, {"statement": "One advantage of quality control is that it motivates workers by giving them responsibility for quality.", "answer": false, "explain": "FALSE. This is an advantage of quality ASSURANCE, not quality control. In quality control, workers simply produce goods — inspectors do the checking. It is quality assurance that motivates workers by giving them personal responsibility and making them feel valued."}]}, "misc": {"enabled": true, "items": [{"myth": "Quality means a product is expensive, luxurious, or the best on the market.", "truth": "Quality means a product or service is fit for purpose and meets customer expectations at the price paid. A cheap product can be ''quality'' if it does what the customer expected. An expensive product that fails is not quality.", "check": {"question": "What does ''quality'' actually mean in this topic, according to the correct explanation?", "options": ["Packaged in the most luxurious box available on the market", "Priced higher than every rival product currently on the market", "Manufactured and sold under a well-known, trusted brand name", "Fit for purpose, meeting customer expectations at the price paid"], "answer": 3, "explain": "The card corrects the misconception that quality means expensive or luxurious — quality actually means fit for purpose and meeting customer expectations at the price paid."}}, {"myth": "Quality control and quality assurance are the same thing — both involve checking goods.", "truth": "They are fundamentally different. Quality CONTROL uses specialist inspectors to check products, usually at the end of production. Quality ASSURANCE involves ALL workers being responsible for quality throughout the entire production process, aiming to PREVENT faults rather than just catch them.", "check": {"question": "What is the key difference between quality control and quality assurance, according to this card?", "options": ["Quality control and quality assurance are simply two different names for the same process", "Quality assurance only checks finished goods once, right at the very end of production", "Quality control involves every single worker checking their own work at every stage", "Quality control uses inspectors to check goods, while quality assurance involves all workers"], "answer": 3, "explain": "Quality control relies on specialist inspectors checking products, usually at the end of production, while quality assurance makes all workers responsible for preventing faults throughout production."}}, {"myth": "Quality assurance does not disrupt production because quality is only checked once production is finished.", "truth": "The opposite is true. Quality ASSURANCE can disrupt production because workers stop to check their own work at each stage. It is quality CONTROL that does NOT disrupt production, because workers continue producing while inspectors check.", "check": {"question": "Which quality method actually disrupts production, according to this card?", "options": ["Both methods disrupt production by roughly the same amount", "Quality assurance, since workers pause to check their own work", "Neither method causes any real disruption to production at all", "Quality control, because inspectors slow down the entire production line"], "answer": 1, "explain": "It is quality assurance that can disrupt production, since workers stop to check their own work at each stage — quality control does not disrupt production because inspectors check while workers keep producing."}}, {"myth": "Quality control prevents waste because it catches faulty goods.", "truth": "Quality control does NOT prevent waste — the materials and labour to make a faulty product have already been used up before the inspector finds the fault. Quality ASSURANCE reduces waste because faults are caught early, before more resources are spent on a defective item.", "check": {"question": "Why does quality control NOT prevent waste, according to this card?", "options": ["Because quality control checks products only before they are manufactured", "Because materials and labour are already used up before a fault is found", "Because inspectors are simply too slow to catch every single fault", "Because quality control is only ever used within service industries"], "answer": 1, "explain": "Quality control only catches faults after production, so the materials and labour used to make a faulty product have already been wasted by the time an inspector finds the fault."}}, {"myth": "For a 1-mark ''identify'' question about quality, writing ''suppliers'' is enough for a mark.", "truth": "Examiners require a specific, precise answer. ''Suppliers'' alone is too vague. The correct answer would be ''the quality of raw materials / supplies used.'' Always be specific about WHAT about suppliers affects quality.", "check": {"question": "For a 1-mark identify question on factors affecting quality, why would writing just ''suppliers'' score 0 marks?", "options": ["It should have been written out as a full paragraph instead", "The examiner only accepts answers that mention staff training", "It is too vague — it doesn''t state what about suppliers affects quality", "Suppliers are never considered a relevant factor affecting product quality"], "answer": 2, "explain": "Examiners require a specific, precise answer such as ''the quality of raw materials/supplies used'' — simply writing ''suppliers'' is too vague to earn the mark."}}, {"myth": "For a 3-mark analyse question, writing everything you know about quality control will get full marks.", "truth": "This is ''knowledge dumping'' and will score 0 for analysis. You MUST follow the U → APP → AN structure: explain the concept (U), link it specifically to the business in the case study (APP), then explain the financial or operational impact on that business (AN).", "check": {"question": "Why would ''writing everything you know about quality control'' fail to score marks on a 3-mark analyse question?", "options": ["Because 3-mark questions only ever accept bullet-point style answers", "Because it is knowledge dumping, which scores 0 for analysis marks", "Because analyse questions never actually require any real understanding", "Because analyse questions are marked purely on handwriting neatness"], "answer": 1, "explain": "Knowledge dumping without following the U → APP → AN structure (explain, apply to the case study business, then analyse impact) scores 0 for analysis."}}, {"myth": "A product recall is the same as a product return.", "truth": "These are different. A RETURN is when an individual customer brings back a faulty product to the shop. A RECALL is when the business itself identifies a serious fault and proactively contacts all affected customers to return the product for repair or replacement.", "check": {"question": "What is the difference between a ''return'' and a ''recall'', according to this card?", "options": ["A return and a recall are the same process", "A recall always costs less than a return", "A return is customer-led; a recall is business-led", "A recall only ever happens to service businesses"], "answer": 2, "explain": "A return is when an individual customer brings a faulty product back; a recall is when the business itself identifies a fault and proactively contacts affected customers."}}, {"myth": "Quality assurance only applies to manufacturing businesses.", "truth": "Quality assurance applies equally to service businesses. Disney World is a classic example — all ''cast members'' (staff) take personal responsibility for delivering a high-quality customer experience, which is quality assurance applied to a service.", "check": {"question": "Which case study is used to show that quality assurance applies to service businesses too?", "options": ["Whirlpool, where faulty washing machines were recalled from customers'' homes", "Disney World, where ''cast members'' take responsibility for customer experience", "ABC Bicycles, where specialist inspectors check the quality of each bike", "Heinz Beanz, where automated machines eject cans that fail inspection"], "answer": 1, "explain": "Disney World is used as the example of quality assurance in a service business, where all ''cast members'' take personal responsibility for delivering high-quality customer experience."}}]}, "tips": {"enabled": true, "items": [{"title": "One Specific Point. That Is All.", "html": "\n      <p>A 1-mark <strong>''Identify'' or ''State''</strong> question needs exactly one correct, specific point. Nothing more. Do not write a paragraph, do not define the term, do not give an example unless asked.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific point = 1 mark ✅</li>\n        <li>A vague, general point = 0 marks ❌</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"Suppliers.\"</em><br/>\n      Too vague — it doesn''t say WHAT about suppliers affects quality.</p>\n\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"The quality of raw materials / supplies used.\"</em><br/>\n      Specific and directly answers the question.</p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> Many candidates lost marks on this question by writing about the <em>cost</em> of raw materials rather than the <em>quality</em> of them. Always re-read the exact wording before writing your answer.</p>\n\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write a definition of quality (e.g. \"fit for purpose\") when asked for a <em>factor that affects</em> quality. These are different things — read the question carefully.</p>\n    ", "check": {"question": "What is the key lesson from the ''Bad Answer'' example, writing just ''Suppliers''?", "options": ["It is far too long for a 1-mark question answer", "It doesn''t say WHAT about suppliers affects quality", "It fails to mention Heinz Beanz by name", "It claims suppliers are never a valid factor"], "answer": 1, "explain": "The card explains that ''Suppliers'' alone is too vague — a 1-mark answer must be specific, such as ''the quality of raw materials/supplies used.''"}}, {"title": "Name It, Then Explain It", "html": "\n      <p>A 2-mark <strong>''Explain''</strong> question needs two distinct steps: <strong>identify</strong> the point and then <strong>explain</strong> how or why it works. You will not get both marks for just naming something twice.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Identify (K):</strong> Name the concept clearly (e.g. \"quality control\")</li>\n        <li><strong>Step 2 — Explain (U):</strong> Explain what it involves or why it matters</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n      <em>\"Quality control is important because it makes goods better.\"</em><br/>\n      This only gets 1 mark — it names quality control but the explanation is too vague.</p>\n\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"Quality control (1) involves specialist inspectors checking finished goods to ensure they meet the required standard before reaching customers (1).\"</em></p>\n\n      <p><strong>⚠️ Examiner Warning:</strong> Many candidates explained the right concept but named it incorrectly (e.g. describing quality control but calling it quality assurance). You must name AND correctly explain the same method. Less than half of candidates gained both marks on this type of question in recent papers.</p>\n    ", "check": {"question": "According to this card, what is the most common reason candidates lost marks on 2-mark explain questions?", "options": ["They only wrote a single vague sentence with no real detail", "They explained the concept but never linked it to a case study", "They explained the right concept but gave it the wrong name", "They included far too many examples instead of one clear explanation"], "answer": 2, "explain": "The examiner warning notes that many candidates explained the right concept but named it incorrectly, mixing up quality control and quality assurance."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n      <p>A 3-mark <strong>''Analyse''</strong> question is worth 3 marks split across Understanding, Application, and Analysis. You <strong>cannot score the analysis mark without first showing understanding</strong>. And you will score <strong>ZERO for analysis</strong> if you do not link to the specific business in the case study.</p>\n\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> Explain the concept or benefit clearly</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link it directly to the specific business using evidence from the text (quote it, name the product, or reference a detail)</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the financial or operational impact on that business</li>\n      </ul>\n\n      <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n      <em>\"Quality is important because it helps the business sell more.\"</em><br/>\n      This gets U only — no application to the business, no analysis of impact.</p>\n\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"Maintaining quality helps M&S protect its reputation (U). M&S is committed to high quality own-brand food, clothing and home products (APP). If quality slips, customers may switch to competitors, directly reducing M&S''s revenue and profits (AN).\"</em></p>\n\n      <p><strong>The ''So What?'' Rule for Analysis:</strong> Keep asking yourself ''So what?'' until you reach a bottom-line business impact.</p>\n      <ul>\n        <li>\"Quality builds reputation\" → So what?</li>\n        <li>\"Customers are more likely to return\" → So what?</li>\n        <li>\"This increases repeat sales and reduces the marketing cost of acquiring new customers\" ✅ NOW that''s analysis.</li>\n      </ul>\n    ", "check": {"question": "In the 3-mark ''Analyse'' formula, what happens if a candidate does not link their answer to the specific business in the case study?", "options": ["They score ZERO for analysis", "They still get full marks if the understanding is strong", "They lose only the application mark but keep the analysis mark", "They automatically get 2 out of 3 marks"], "answer": 0, "explain": "The card states you will score ZERO for analysis if you do not link to the specific business in the case study, since analysis must build on application."}}, {"title": "Two 3-Mark Answers. No Conclusion Needed.", "html": "\n      <p>A 6-mark question is simply <strong>a 3-mark question done twice</strong>. Write two separate, fully developed points, each following the U → APP → AN structure. Do <strong>not</strong> waste time writing a conclusion — there are zero marks available for evaluation here.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Point 1:</strong> U (1 mark) + APP (1 mark) + AN (1 mark) = 3 marks</li>\n        <li><strong>Point 2:</strong> U (1 mark) + APP (1 mark) + AN (1 mark) = 3 marks</li>\n      </ul>\n\n      <p><strong>Example Structure for Sainsbury''s quality question:</strong></p>\n      <ul>\n        <li><strong>Point 1 (U):</strong> Improving food quality can help Sainsbury''s improve its reputation...</li>\n        <li><strong>Point 1 (APP):</strong> ...as its Taste the Difference burgers and dishwasher tablets recently won a Which? Best Buy rating...</li>\n        <li><strong>Point 1 (AN):</strong> ...which may attract new customers and increase market share over competitors like Tesco and Morrisons.</li>\n        <li><strong>Point 2 (U):</strong> Improving quality can also reduce waste...</li>\n        <li><strong>Point 2 (APP):</strong> ...as Sainsbury''s is improving the quality of 3,000 own-brand products...</li>\n        <li><strong>Point 2 (AN):</strong> ...meaning less unsold food is thrown away each day, directly reducing costs and improving profit margins.</li>\n      </ul>\n\n      <p><strong>🚫 Do NOT write a conclusion.</strong> A 6-mark question does not reward evaluation — save the \"it depends on...\" language for 7–9 mark questions only.</p>\n    ", "check": {"question": "According to this card, should a 6-mark ''analyse two benefits'' answer include a conclusion?", "options": ["Yes, but only if both points are about the same benefit", "No — because conclusions are banned across every GCSE Business question", "Yes — a conclusion is worth 2 of the 6 marks", "No — there are zero marks available for evaluation on this question type"], "answer": 3, "explain": "The card explicitly says not to waste time writing a conclusion, as a 6-mark question does not reward evaluation — that language is saved for 7–9 mark questions."}}, {"title": "Two Points, Each with U + APP", "html": "\n      <p>A 4-mark <strong>''Explain two reasons''</strong> question awards 1 mark for understanding each reason plus 1 mark for applying it to the specific business in the case study. Write two separate, clearly structured points.</p>\n\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Reason 1 (U):</strong> State the reason clearly → <strong>(APP):</strong> Link to the specific business</li>\n        <li><strong>Reason 2 (U):</strong> State a different reason → <strong>(APP):</strong> Link to the specific business</li>\n      </ul>\n\n      <p><strong>Example for JLR (Jaguar Land Rover):</strong></p>\n      <ul>\n        <li><em>\"Quality helps JLR maintain its reputation for luxury vehicles (U), which is especially important as it competes directly with premium German brands BMW and Mercedes (APP).\"</em></li>\n        <li><em>\"Quality helps JLR reduce the risk of costly product recalls (U), which would be extremely damaging for a company that sells expensive, complex cars where safety faults could be life-threatening (APP).\"</em></li>\n      </ul>\n\n      <p><strong>⚠️ Examiner Warning:</strong> Do not just list reasons without linking them to JLR. The application mark requires you to use a specific detail from the case study — mention the luxury segment, the competitors, the international markets, or the car manufacturing context.</p>\n    ", "check": {"question": "In the JLR example, what does the application mark require for each reason?", "options": ["A comparison between JLR''s methods and Toyota''s kaizen system", "A statistic taken from a UK customer service satisfaction survey", "A general dictionary-style definition of what quality assurance actually means", "A specific detail from the case study, such as the luxury car segment"], "answer": 3, "explain": "The examiner warning states the application mark requires a specific detail from the case study, such as the luxury segment, competitors, international markets, or manufacturing context."}}, {"title": "The Most Common Mix-Up in This Topic", "html": "\n      <p>Examiners repeatedly report that students confuse quality control and quality assurance. This mix-up alone costs thousands of marks across every exam series. Learn this distinction perfectly.</p>\n\n      <p><strong>The Key Difference in One Sentence:</strong><br/>\n      Quality control = <em>CHECKING</em> by specialists (after or during production). Quality assurance = <em>PREVENTING</em> by all workers (throughout production).</p>\n\n      <p><strong>Quick Reference Table:</strong></p>\n      <ul>\n        <li><strong>Who checks quality?</strong> QC = specialist inspectors only | QA = every single worker</li>\n        <li><strong>When is quality checked?</strong> QC = end of production or sampling | QA = at every stage continuously</li>\n        <li><strong>Does it disrupt production?</strong> QC = No | QA = Yes (workers stop to check)</li>\n        <li><strong>Does it prevent waste?</strong> QC = No (faults already made) | QA = Yes (caught early)</li>\n        <li><strong>Does it motivate workers?</strong> QC = No (workers have no responsibility) | QA = Yes (workers feel valued)</li>\n      </ul>\n\n      <p><strong>Real-World Memory Aid:</strong></p>\n      <ul>\n        <li><strong>Quality Control:</strong> Heinz Beanz machine ejecting wrong-weight cans ✅</li>\n        <li><strong>Quality Assurance:</strong> Toyota workers suggesting improvements in team meetings ✅</li>\n      </ul>\n\n      <p><strong>⚠️ AfL Note from Examiners:</strong> Creating key term lists, flashcards and mini tests is the most effective way to prevent this mix-up before an exam.</p>\n    ", "check": {"question": "According to the ''Real-World Memory Aid'', which example represents quality assurance?", "options": ["ABC Bicycles employees wearing white inspection gloves", "Heinz Beanz machines automatically ejecting faulty cans", "Whirlpool recalling faulty washing machines from customers", "Toyota workers suggesting quality improvements in meetings"], "answer": 3, "explain": "The card''s memory aid pairs quality control with the Heinz Beanz machine ejecting faulty cans, and quality assurance with Toyota workers suggesting improvements in team meetings."}}]}, "exam": {"enabled": true, "questions": [{"question": "Identify one factor which can affect the quality of a business'' products. [1 mark]", "marks": 1, "hint": "Think about what goes INTO making a product — materials, people, processes. Give a specific answer, not a vague one.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><ul><li><strong>1 mark</strong> for any one correct, specific factor. Accept any reasonable factor including:</li></ul><ul><li>Quality of supplies / raw materials used</li><li>Employees'' experience / skill / motivation / training</li><li>Production method used</li><li>Use of technology</li><li>Use of quality control methods</li><li>Legislation</li></ul><p><strong>Do NOT award</strong> a mark for:</p><ul><li>A definition of quality (e.g. \"fit for purpose\") — that defines quality, it doesn''t identify a factor that affects it</li><li>\"Low cost\" as meaning low quality — cost and quality are not the same thing</li><li>Vague answers like \"suppliers\" — must specify it is the <em>quality</em> of supplies</li></ul><p><strong>Examiner''s Comment:</strong> Nearly two thirds of candidates answered correctly. Those who did not gain the mark gave vague answers such as ''suppliers'' rather than ''the quality of the supplies used''. Many incorrectly wrote about the <em>cost</em> of raw materials rather than the <em>quality</em> of them — a surprising error given the Primark context.</p></div>"}, {"question": "Which of the following would help Zayn deal with this problem?", "marks": 1, "hint": "Product returns = a quality problem. Which option directly addresses why the gloves are being returned?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark</h5><p><strong>Correct Answer: B — Improving quality checks to ensure every glove heats up correctly</strong></p><p>An increase in returns means the product is failing to meet customer expectations. Improving quality checks addresses the root cause of the problem.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Bonus for most gloves sewn:</strong> Incentivising speed may actually worsen quality, as workers rush production to earn more. Does not address the heating fault.</li><li><strong>C — Researching other heated clothing:</strong> This is a product development strategy, not a solution to the current quality problem with the gloves.</li><li><strong>D — Market segmentation:</strong> This is a marketing activity. Segmenting the market does not fix the fault that is causing gloves to be returned.</li></ul></div>"}, {"question": "Explain one production process a business may use when making its products. [2 marks]", "marks": 2, "hint": "You need to name a specific production process AND explain what it involves. Don''t just describe it without naming it — you must do both.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a 1 + AO1b 1)</h5><ul><li><strong>1 mark (AO1a)</strong> for identifying a production process</li><li><strong>1 further mark (AO1b)</strong> for explaining the process</li></ul><p>Answers do not need to relate to Zara.</p><p><strong>Acceptable production processes:</strong></p><ul><li><strong>Batch production</strong> — groups of a similar product are made together before moving to the next batch</li><li><strong>Flow / Mass production</strong> — continuous production, products move along a production line without stopping</li><li><strong>Job production</strong> — one item is made individually at a time to specific customer requirements</li></ul><p><strong>Exemplar response:</strong><br/>Batch production (1) is when a group of similar products are made together at the same time before the production process moves on to a different product (1).</p><p><strong>Examiner''s Comment:</strong> Most candidates named one of the three production methods correctly. Some explained the process without naming it and gained no credit. Flow and job production were explained more accurately than batch production.</p></div>"}, {"question": "Explain one method that a business could use to ensure the quality of its products. [2 marks]", "marks": 2, "hint": "Name a specific quality method (quality control OR quality assurance) — don''t mix them up. Then explain what that method involves.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a 1 + AO1b 1)</h5><ul><li><strong>1 mark (AO1a)</strong> for identifying a method to ensure quality</li><li><strong>1 further mark (AO1b)</strong> for explaining the method</li></ul><p>Answers do not need to relate to Zara.</p><p><strong>Acceptable methods:</strong></p><ul><li><strong>Quality control</strong> — end of the production process / inspection / before being sold to customers</li><li><strong>Quality assurance</strong> — during the production process / carried out by production workers / involves the whole business</li></ul><p><strong>Exemplar response:</strong><br/>Quality control (1) is where a specialist inspector checks a sample of finished goods before they are sold to ensure they meet the required standard (1).</p><p><strong>⚠️ Examiner''s Comment (Misconception):</strong> Many candidates continue to mix up quality assurance and quality control, or give the explanation for the wrong term. This meant less than half of candidates gained both marks. Some answers did not name a specific method at all, which prevented any marks from being awarded. Key term revision is essential for this topic.</p></div>"}, {"question": "State two reasons why quality in the production of goods is important to a business. [2 marks]", "marks": 2, "hint": "Give two separate, distinct reasons. These can be stated briefly — no explanation required. Think about reputation, customers, and costs.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a 2)</h5><p><strong>1 mark for each correct reason, up to a maximum of 2 marks.</strong></p><p>Answers do not need to relate to any specific business. Acceptable answers include:</p><ul><li>Reputation / brand image</li><li>Competitiveness</li><li>To satisfy customer needs / sell more</li><li>Repeat purchasing</li><li>Able to set a higher price</li><li>Making products desirable</li><li>No need to recall / return / waste products</li><li>To satisfy any legal requirement</li></ul><p><strong>Do NOT award</strong> marks for references to profit alone (must link profit to a quality-related reason).</p><p><strong>Examiner''s Comment:</strong> This question was well answered, with most candidates gaining full marks for both reasons.</p></div>"}, {"question": "Which of the following actions would help QT Homeware Ltd deal with this problem?", "marks": 1, "hint": "The problem is that kettles are leaking — a quality problem. Which option actually fixes the quality of the product?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO2 Problem Solving)</h5><p><strong>Correct Answer: D — Physically test every hundredth kettle to ensure it is watertight</strong></p><p>This is a quality control measure that directly addresses the manufacturing fault.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Include a cloth:</strong> This accepts the fault and asks customers to deal with it — it does not solve the quality problem.</li><li><strong>B — Promotional campaign:</strong> Marketing does not fix a manufacturing defect. It may actually damage the brand further if new customers receive leaking kettles.</li><li><strong>C — Meeting to reduce costs:</strong> Cost reduction is unrelated to solving the leaking kettle problem and may make quality worse if it means cutting corners.</li></ul></div>"}, {"question": "The concept of ''quality'' requires a business to:", "marks": 1, "hint": "What is the official definition of quality? Think about what ''quality'' actually means in a business context.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p><strong>Correct Answer: C — Provide services that are fit for purpose</strong></p><p>\"Fit for purpose\" is the core definition of quality — a product or service meets its intended function and the expectations of the customer.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Better than competition:</strong> Quality does not require being better than competitors — just meeting customer expectations at the required standard.</li><li><strong>B — Reasonably priced:</strong> Price is not part of the definition of quality. A cheap product can be quality; an expensive one can fail to be quality.</li><li><strong>D — Value for money:</strong> Value for money is a pricing/marketing concept. Quality means fit for purpose, not necessarily that the customer paid a fair price.</li></ul></div>"}, {"question": "Which of the following would be an example of a quality assurance activity for a car manufacturer?", "marks": 1, "hint": "Quality assurance involves all workers improving quality together — it is not about inspecting finished products.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1b)</h5><p><strong>Correct Answer: B — Holding a meeting with production operatives on how to improve the manufacturing process</strong></p><p>Quality assurance involves all workers in a whole-business approach to quality. Meetings where production workers suggest improvements is a classic QA activity.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Driving every tenth car:</strong> This is quality CONTROL — sampling finished goods to inspect them.</li><li><strong>C — Increasing budget:</strong> This is a financial/resource decision, not a quality method.</li><li><strong>D — Visually inspecting two cars:</strong> This is quality CONTROL — inspecting a sample of finished goods for defects.</li></ul></div>"}, {"question": "Explain one reason why quality is important to a business in the production of goods. [2 marks]", "marks": 2, "hint": "Name a specific reason (not just ''it''s important'') and then explain HOW or WHY that reason matters to the business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a 1 + AO1b 1)</h5><ul><li><strong>1 mark (AO1a)</strong> for knowledge of a reason why quality is important</li><li><strong>1 further mark (AO1b)</strong> for further exemplification/explanation of that reason</li></ul><p>Answers do not need to relate to JLP. Acceptable reasons include:</p><ul><li>Reputation of the business</li><li>To gain new customers</li><li>To satisfy customer needs</li><li>Retain existing customers</li><li>Reduce product returns and recalls</li><li>Avoids waste</li><li>Avoids disruption to production</li><li>Allows a higher price to be charged</li></ul><p><strong>Exemplar response:</strong><br/>To maintain a good reputation (1) as consumers expect quality to be high and will switch to competitors if it is not met (1).</p></div>"}, {"question": "JLP''s electrical department staff have good product knowledge. Analyse one positive impact of this on the quality of JLP''s customer service. [3 marks]", "marks": 3, "hint": "Follow the U → APP → AN structure. Use specific details from the JLP case study in your application step.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1b 1 + AO2 1 + AO3a 1)</h5><ul><li><strong>1 mark (U)</strong> for understanding of a benefit of having knowledgeable employees — no further marks can be gained without this</li><li><strong>1 further mark (APP)</strong> for application to JLP, using evidence from the text</li><li><strong>1 further mark (AN)</strong> for analysis of one positive impact on JLP''s business</li></ul><p>The answer should focus on the <em>selling/customer service</em> part of JLP''s business — not on manufacturing products or identifying suppliers.</p><p><strong>Understanding may include:</strong></p><ul><li>Able to provide help, advice, and suggestions to customers</li><li>Customer is more confident in their purchase</li><li>Customer more likely to ask for help and make a decision</li><li>Increased trust from consumers</li><li>The business will get better reviews</li></ul><p><strong>Application (using the text) may include:</strong></p><ul><li>JLP is a chain of department stores</li><li>Wide range of products including computers, TVs and washing machines</li><li>Staff use face-to-face selling</li></ul><p><strong>Analysis may include:</strong></p><ul><li>More sales / higher conversion rate</li><li>Customer more likely to return or recommend to others</li><li>Improved reputation / increased customer satisfaction</li></ul><p><strong>Exemplar response:</strong><br/>Employees are able to confidently advise customers on product choices (U). This is especially important for JLP''s electrical department as customers buying computers or washing machines may lack technical knowledge and need guidance (APP). As a result, customers are more likely to trust JLP''s recommendations and make a purchase, increasing sales and encouraging repeat visits (AN).</p></div>"}, {"question": "The concept of ''quality'' refers to making products:", "marks": 1, "hint": "What does the official definition of quality say? Think about fit for purpose and meeting customer expectations.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1a)</h5><p><strong>Correct Answer: B — Of a satisfactory standard</strong></p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — By hand:</strong> The method of production (hand-made vs machine-made) does not determine quality. A machine-made product can absolutely be quality if it is fit for purpose.</li><li><strong>C — Better than the leading brand:</strong> Quality means meeting expectations, not surpassing the market leader.</li><li><strong>D — Highest possible specification:</strong> Quality does not require the highest specification — only a satisfactory one that meets what the customer expected for that product and price.</li></ul></div>"}, {"question": "The concept of quality requires a business to:", "marks": 1, "hint": "Focus on the official definition of quality — it is about standards and meeting expectations, not about price or ethics.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1b)</h5><p><strong>Correct Answer: C — Provide services to required standards</strong></p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Charge low prices:</strong> Price strategy has nothing to do with the definition of quality.</li><li><strong>B — Produce the best goods:</strong> Quality requires meeting required standards, not necessarily being the best on the market.</li><li><strong>D — Ethical suppliers:</strong> Ethical sourcing is a CSR/sustainability decision. It is not part of the core definition of quality.</li></ul></div>"}, {"question": "State two methods of ensuring quality. [2 marks]", "marks": 2, "hint": "Name two specific methods — you do not need to explain them, just state them clearly.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1a 2)</h5><p><strong>1 mark for each correct method identified, up to a maximum of 2 marks.</strong></p><p>Acceptable answers include:</p><ul><li>Quality control — accept specific examples such as inspection of samples, use of a mystery shopper for retail services</li><li>Quality assurance — accept specific examples such as continual checking on a production line, or training staff to look for errors</li></ul></div>"}, {"question": "Analyse one advantage to Tesco plc of selling using e-commerce. [3 marks]", "marks": 3, "hint": "Follow the U → APP → AN structure. The application step must use a specific detail about Tesco from the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1b 1 + AO2 1 + AO3 1)</h5><ul><li><strong>1 mark (U)</strong> for understanding of an advantage of e-commerce</li><li><strong>1 further mark (APP)</strong> for application to Tesco plc specifically, using evidence from the text</li><li><strong>1 further mark (AN)</strong> for analysis of one advantage to Tesco plc of selling through e-commerce</li></ul><p><strong>Advantages of e-commerce may include:</strong></p><ul><li>Open 24/7 — customers can buy at any time</li><li>Reduced overheads compared to physical stores</li><li>Wider market reach — sell to customers across the UK and potentially globally</li><li>Customer data and intelligence to target marketing</li><li>Can handle increased demand without the constraint of physical store space</li></ul><p><strong>Exemplar response:</strong><br/>E-commerce allows customers to make purchases at any time of day or night (U). This is important to Tesco plc as many of its physical stores have limited opening hours (APP). This can lead to more sales which may mean more profit and provide funds for further expansion (AN).</p></div>"}, {"question": "What key business function does Sabena perform?", "marks": 1, "hint": "Sabena tests products BEFORE they reach the customer. Which business function describes checking product quality at the end of production?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1b)</h5><p><strong>Correct Answer: B — Quality control</strong></p><p>Sabena tests every finished computer before it leaves the factory — this is quality control (inspecting finished goods to ensure they meet the required standard before reaching the customer).</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — After sales service:</strong> This would involve helping customers after they have already bought and received the product (e.g. repairs, customer complaints).</li><li><strong>C — Setting production levels:</strong> This is an operations management decision about output volume — unrelated to quality testing.</li><li><strong>D — Supply chain management:</strong> This involves managing suppliers and the flow of materials — nothing to do with testing finished products.</li></ul></div>"}, {"question": "Explain two reasons why quality is important to JLR. [4 marks]", "marks": 4, "hint": "Two separate reasons, each with a named reason (U) and a link to JLR specifically (APP). Use details from the case study.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO1b 2 + AO2 2)</h5><ul><li><strong>1 mark (U)</strong> for understanding of a reason why quality is important — up to a maximum of 2 marks for understanding</li><li><strong>1 further mark (APP)</strong> for application of that reason to JLR specifically — up to a maximum of 2 marks for application</li></ul><p><strong>Reasons may include:</strong></p><ul><li>To maintain reputation</li><li>To sell more cars</li><li>To reduce recalls</li><li>To reduce production errors / waste</li><li>To meet the needs of the luxury / executive market segment</li><li>To compete with BMW and Mercedes</li></ul><p><strong>Exemplar response:</strong><br/>Quality can help JLR maintain its reputation for producing luxury cars (U) which is vital as it directly competes with premium German brands BMW and Mercedes — if quality slips, customers may choose a competitor (APP).</p><br/><p>Quality also helps JLR reduce the cost of product recalls (U). Given JLR produces complex luxury vehicles, any safety fault could be extremely costly to recall and repair, damaging both profits and the premium brand image (APP).</p></div>"}, {"question": "Analyse one reason why quality is important to M&S. [3 marks]", "marks": 3, "hint": "Follow the U → APP → AN structure. For application, use a specific detail from the M&S case study — mentioning food, the 283 factories, Plan A, or its positioning as a premium retailer.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1b 1 + AO2 1 + AO3a 1)</h5><ul><li><strong>1 mark (U)</strong> for understanding of the importance of quality — no further marks can be gained without this</li><li><strong>1 further mark (APP)</strong> for application to M&S specifically, using evidence from the text</li><li><strong>1 further mark (AN)</strong> for analysis of a reason why quality is important to M&S</li></ul><p><strong>Understanding may include:</strong></p><ul><li>To maintain reputation</li><li>To sell more products</li><li>To reduce returns</li><li>To create brand loyalty</li><li>To comply with food safety legislation</li></ul><p><strong>Application (using the text) may include:</strong></p><ul><li>M&S is committed to high quality own-brand food, clothing & home products</li><li>Food must be of a minimum legal quality standard</li><li>60% of M&S revenue comes from food sales across 1025 stores</li><li>283 food factories must maintain consistent standards</li><li>Ethical programme — poor quality increases waste</li></ul><p><strong>Analysis may include:</strong></p><ul><li>Increased costs from products that do not meet standards</li><li>Lost sales from unhappy customers / poor reputation</li><li>Increased costs from legal disputes (food safety law)</li></ul><p><strong>Exemplar response:</strong><br/>Ensuring quality is vital to M&S as it maintains reputation (U) because M&S is committed to high quality own-brand products and food (APP) which directly links to customer demand, sales, and company profits (AN).</p><p><strong>⚠️ Examiner''s Comment:</strong> Candidates struggled to apply the case study data to this question, often giving generic answers about reputation without linking to M&S. Students who knew quality meant ''fit for purpose'' found more context — M&S selling food means there is also a legal dimension to quality compliance. Those who mentioned M&S''s food factories or its 60% food revenue earned the application mark.</p></div>"}, {"question": "A manufacturer makes chocolate bars. All of the chocolate bars are passed through a machine to check for production mistakes before being boxed. This is an example of:", "marks": 1, "hint": "Is this preventing mistakes or checking for them after they''ve been made? Which quality method involves inspection at the end of production?", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1b)</h5><p><strong>Correct Answer: D — Quality control</strong></p><p>All finished chocolate bars are inspected by a machine before being boxed — this is a classic quality control system (checking finished goods to ensure they meet the required standard before reaching the customer).</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Product development:</strong> This refers to creating or improving products, not to checking their quality.</li><li><strong>B — Product recall:</strong> A recall happens after products have been sold and a fault is found. This inspection happens before the product leaves the factory.</li><li><strong>C — Quality assurance:</strong> QA would involve ALL workers taking responsibility for preventing mistakes throughout production — not just a machine inspecting at the end. The key distinction: QA prevents, QC checks.</li></ul><p><strong>⚠️ Examiner''s Comment:</strong> There was a clear misunderstanding between quality control and quality assurance. These are technical terms that must be understood precisely. Key term revision — lists, flashcards, and mini tests — can prevent these errors.</p></div>"}, {"question": "Explain one method that Sainsbury''s could use to judge if the quality of the service provided by shop workers has improved. [2 marks]", "marks": 2, "hint": "Name a specific quality checking method suitable for a service/retail context, then explain how Sainsbury''s would actually use it.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 2 marks (AO1b 1 + AO2 1)</h5><ul><li><strong>1 mark (U)</strong> for identifying one quality control / quality assurance method appropriate to a shop environment</li><li><strong>1 further mark (APP)</strong> for explaining how Sainsbury''s would use this method — must relate to the case study</li></ul><p><strong>Acceptable methods include:</strong></p><ul><li>Mystery shopper</li><li>Customer satisfaction survey</li></ul><p><strong>Exemplar responses:</strong></p><ul><li><em>\"Use a mystery shopper (U) who would grade the way in which the shop assistants serve customers at the checkout and could score staff on how politely and helpfully they assist with queries (APP).\"</em></li><li><em>\"Complete a survey of customers (U) who have visited a Sainsbury''s store, asking them to rate the helpfulness of staff on the checkout or those stacking shelves (APP).\"</em></li></ul></div>"}, {"question": "Analyse two benefits to Sainsbury''s of improving the quality of the food it sells. [6 marks]", "marks": 6, "hint": "Two separate points, each following U → APP → AN. Use specific evidence from the Sainsbury''s case study for both application marks — mention the 3,000 own-brand products, the Which? rating, Taste the Difference range, or competition with Tesco and Morrisons.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 6 marks (AO1b 2 + AO2 2 + AO3a 2)</h5><ul><li><strong>Up to 2 marks (U)</strong> for two benefits of improving food quality</li><li><strong>Up to 2 marks (APP)</strong> for applying understanding to Sainsbury''s, using evidence from the case study</li><li><strong>Up to 2 marks (AN)</strong> for explaining the effects or impacts on the business</li></ul><p><strong>Understanding may include:</strong></p><ul><li>Improve reputation for quality</li><li>Gain new customers</li><li>Increase customer satisfaction / loyalty</li><li>May be able to charge a higher price</li><li>Reduce returns / waste</li><li>Avoid legal action (food safety legislation)</li></ul><p><strong>Application (using the case study) may include:</strong></p><ul><li>Reputation improving through word of mouth when customers try improved products</li><li>Sainsbury''s gaining awards such as the Which? Best Buy rating</li><li>Reduced waste from less unsold food each day</li><li>Improvement in manufacturing processes / better-quality ingredients in 3,000 own-brand products</li><li>Legal requirements for food quality that Sainsbury''s must meet</li></ul><p><strong>Analysis may include:</strong></p><ul><li>Increased sales / market share over Tesco and Morrisons</li><li>Reduced costs (less waste) increasing profits</li><li>Avoid bad publicity / fines from legal action</li><li>Costs of developing high-quality products will increase production costs (negative impact)</li></ul></div>"}, {"question": "What is meant by the term ''quality control''? [1 mark]", "marks": 1, "hint": "Give the official definition. Focus on who does the checking and when.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1b)</h5><p><strong>1 mark</strong> for a correct definition such as:</p><ul><li>A system where specialist inspectors check the quality of goods or services produced to ensure they are of a good standard</li><li>Checking goods at the end of, or during, production to ensure they meet required standards</li></ul></div>"}, {"question": "What is meant by the term ''quality assurance''? [1 mark]", "marks": 1, "hint": "Give the official definition. Focus on who is responsible and what the aim is.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 1 mark (AO1b)</h5><p><strong>1 mark</strong> for a correct definition such as:</p><ul><li>An approach that involves the whole business focusing on quality at every stage of production</li><li>A system where every employee is responsible for quality, aiming to prevent quality problems from arising</li></ul></div>"}, {"question": "Explain two possible reasons why ABC Bicycles Ltd uses quality control. [4 marks]", "marks": 4, "hint": "Two separate reasons (U), each applied to ABC Bicycles using details from the case study (APP). Mention the machines, the faulty bikes, or the white gloves.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 4 marks (AO1b 2 + AO2 2)</h5><ul><li><strong>1 mark (U)</strong> per reason, up to 2 marks for understanding</li><li><strong>1 mark (APP)</strong> per reason, up to 2 marks for applying to ABC Bicycles</li></ul><p><strong>Acceptable reasons include:</strong></p><ul><li>To prevent faulty bikes from reaching customers</li><li>To ensure all parts are correctly fitted</li><li>To protect the reputation of the business</li><li>To reduce returns from customers</li><li>To meet required production standards</li></ul><p><strong>Application must link to the case study</strong> — e.g. mention the machines checking parts are fitted accurately, the white gloves, the fact waste was too high under the previous QC-only system, or that they have been producing bikes for over 20 years.</p></div>"}, {"question": "Analyse one benefit of ABC Bicycles Ltd using quality assurance. [3 marks]", "marks": 3, "hint": "Follow U → APP → AN. For application, use specific evidence from the ABC Bicycles case study (white gloves, each employee checking at each stage). For analysis, explain the financial or operational impact.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1b 1 + AO2 1 + AO3 1)</h5><ul><li><strong>1 mark (U)</strong> for understanding of a benefit of quality assurance</li><li><strong>1 further mark (APP)</strong> for application to ABC Bicycles using evidence from the case study</li><li><strong>1 further mark (AN)</strong> for analysis of the impact on the business</li></ul><p><strong>Benefits may include:</strong></p><ul><li>Reduces waste as faults are caught at each stage rather than only at the end</li><li>Motivates workers by giving them personal responsibility for quality</li><li>Reduces returns and recalls, protecting reputation</li></ul></div>"}, {"question": "Analyse one drawback of ABC Bicycles Ltd using quality control. [3 marks]", "marks": 3, "hint": "Follow U → APP → AN. Use evidence from the ABC Bicycles case study to earn the application mark. The case study tells you what happened when they relied mainly on quality control.", "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme — 3 marks (AO1b 1 + AO2 1 + AO3 1)</h5><ul><li><strong>1 mark (U)</strong> for understanding of a drawback of quality control</li><li><strong>1 further mark (APP)</strong> for application to ABC Bicycles using evidence from the text</li><li><strong>1 further mark (AN)</strong> for analysis of the impact on the business</li></ul><p><strong>Drawbacks may include:</strong></p><ul><li>Does not prevent waste — faults are only caught after the bike has been fully or partially assembled</li><li>Workers are not responsible for quality — reduces motivation and care</li><li>Costly — requires specialist inspectors to be paid</li></ul></div>"}]}}'::jsonb),
('business', '4-3-sales-process-customer-service', '4.3 The Sales Process', '{"learn": {"enabled": true, "items": [{"title": "Key Terms & Official Definitions", "html": "<p>These are the essential terms you must know for 4.3. Learn them precisely — examiners reward specific, accurate definitions.</p>\n<ul>\n<li><strong>E-commerce:</strong> The bringing together of buying and selling electronically (online sales).</li>\n<li><strong>Customer service:</strong> The name given to an area of business that deals with customer enquiries.</li>\n<li><strong>Customer engagement:</strong> The contact between the business and customer.</li>\n<li><strong>Click and collect:</strong> Ordering online and collecting goods from store at a later time.</li>\n<li><strong>Face to face selling:</strong> Usually completed in a shop where there is direct contact between buyer and seller.</li>\n<li><strong>Telesales:</strong> Sales completed over the telephone.</li>\n<li><strong>After-sales service:</strong> Advice and help given to a customer after they have bought a product or service.</li>\n<li><strong>Product knowledge:</strong> The detailed knowledge of a product or service that staff within a business use to help persuade a customer to buy.</li>\n</ul>", "check": {"question": "According to the key terms, what is ''customer engagement''?", "options": ["Direct contact between buyer and seller in a shop", "The contact between the business and customer", "The area of business dealing with customer enquiries", "Advice given to a customer after a purchase"], "answer": 1, "explain": "Customer engagement is defined precisely as ''the contact between the business and customer'' — distinct from customer service (enquiries) or after-sales service (post-purchase advice)."}}, {"title": "Methods of Selling", "html": "<p>Businesses can use a range of selling methods depending on the product, target market, and business size. The three main methods are:</p>\n<ul>\n<li><strong>E-commerce:</strong> Bringing a buyer and seller together electronically. Involves physical delivery after an online sale.</li>\n<li><strong>Face to face:</strong> Direct contact between buyer and seller, typically in a shop, bank, or travel agent. Allows advice and interaction.</li>\n<li><strong>Telesales:</strong> Sales completed over the telephone. Acts as a bridge between e-commerce and face to face, especially useful for customers less comfortable with the internet.</li>\n</ul>\n<p>Not all businesses are suited to every method. The best method depends on the <strong>product type</strong>, the <strong>target market</strong>, and the level of <strong>service</strong> required.</p>\n<div class=\"case-study-box\">\n<h4>Case Study: John Lewis & Partners</h4>\n<p>John Lewis uses all three methods. Its department stores use face-to-face selling with trained staff who have excellent product knowledge, particularly in electronics. It also has a fast-growing e-commerce operation and uses phone lines for customer queries. JLP''s strategy shows how a business can combine multiple selling methods to serve different customers effectively.</p>\n</div>", "check": {"question": "Which company, according to the case study, uses all three selling methods (face-to-face, e-commerce, and telesales)?", "options": ["Marks & Spencer", "JC Motors Ltd", "Amazon UK Ltd", "John Lewis Partners"], "answer": 3, "explain": "The case study states John Lewis uses face-to-face selling in stores, a fast-growing e-commerce operation, and phone lines for customer queries."}}, {"title": "The Influence of E-commerce on Business Activity", "html": "<p>The growth of e-commerce — accelerated dramatically during the COVID-19 pandemic of 2020–21 — has changed business activity in several key ways:</p>\n<ul>\n<li><strong>Location:</strong> Businesses can locate almost anywhere. A telephone/internet connection handles the \"front end\" (orders), while warehouses can be separately sited near motorway networks for fast delivery.</li>\n<li><strong>New skill development:</strong> Staff need new skills — website maintenance, email responses, warehouse packing. Extra training may be required at all levels.</li>\n<li><strong>Levels of employment:</strong> E-commerce may increase OR decrease employment. Existing businesses may need fewer branch staff (e.g. banks), but new e-commerce startups must recruit website, logistics, and customer service staff.</li>\n<li><strong>Creation of specific departments:</strong> Large businesses like M&S, Next, and John Lewis have set up dedicated online departments to manage e-commerce sales and avoid losing business to competitors.</li>\n<li><strong>Click and collect:</strong> Customers order online and collect in-store later, solving the \"not home for delivery\" problem. Stores must dedicate space for click and collect areas.</li>\n<li><strong>Delivery options:</strong> Speed of delivery is a key competitive area. Amazon Prime offers next-day and same-day delivery. Drone delivery is a future possibility but faces security and safety hurdles.</li>\n</ul>", "check": {"question": "What historic event is identified as dramatically accelerating e-commerce growth?", "options": ["The COVID-19 pandemic of 2020–21", "The launch of Amazon Prime", "The 2008 financial crisis", "The invention of the smartphone"], "answer": 0, "explain": "The card states the growth of e-commerce was ''accelerated dramatically during the COVID-19 pandemic of 2020–21''."}}, {"title": "Advantages & Disadvantages of E-commerce for Businesses", "html": "<p>When evaluating e-commerce, always check whether the question asks for the <strong>business''s</strong> perspective or the <strong>customer''s</strong> perspective. Mixing these up is one of the most common reasons students lose marks.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages for Businesses</div>\n<div class=\"pro-item\"><strong>Sell worldwide:</strong> Even the smallest business can reach a global market, significantly increasing the potential customer base, sales, and profit.</div>\n<div class=\"pro-item\"><strong>Open all the time:</strong> No restriction on opening hours — the business can generate sales 24 hours a day, 7 days a week.</div>\n<div class=\"pro-item\"><strong>Professional look at little cost:</strong> A well-designed website creates a strong brand image, attracting customers without the need for expensive premises.</div>\n<div class=\"pro-item\"><strong>Lower operating costs:</strong> No need to pay expensive city-centre rents. The business can operate from anywhere with an internet connection, keeping profits high.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages for Businesses</div>\n<div class=\"con-item\"><strong>Worldwide competition:</strong> All e-commerce businesses face global competitors. Customers can easily compare prices, putting downward pressure on margins.</div>\n<div class=\"con-item\"><strong>Problems of delivering goods and accepting returns:</strong> Reliance on third-party logistics adds cost. High return rates increase expenses further.</div>\n<div class=\"con-item\"><strong>Online security:</strong> Businesses must maintain a secure website and keep customer data safe. A breach destroys customer trust and adds significant costs.</div>\n<div class=\"con-item\"><strong>Advances in technology:</strong> Businesses must constantly update their technology (e.g. mobile-optimised sites) to keep up with customer buying habits. This is ongoing and costly.</div>\n</div>\n</div>", "check": {"question": "Which of these is listed as a disadvantage of e-commerce FOR BUSINESSES (not customers)?", "options": ["Restricted shop opening hours", "Customers cannot touch or try products before buying", "Payment is geared towards card/debit only", "Worldwide competition puts downward pressure on margins"], "answer": 3, "explain": "The business disadvantages list worldwide competition and easy price comparison putting downward pressure on margins; the other options are customer-side issues."}}, {"title": "Advantages & Disadvantages of E-commerce for Customers", "html": "<p>Customers experience both benefits and drawbacks from e-commerce. Remember — some exam questions specifically ask about the <strong>customer''s</strong> perspective, not the business''s.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages for Customers</div>\n<div class=\"pro-item\"><strong>Price comparison:</strong> Customers can easily compare prices across multiple sites, getting the best deal and saving money.</div>\n<div class=\"pro-item\"><strong>Seven-day availability:</strong> Customers can buy at any time convenient to them — not restricted to shop opening hours.</div>\n<div class=\"pro-item\"><strong>Wide range of products:</strong> The internet provides worldwide access, giving customers far greater choice than any single physical store could offer.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages for Customers</div>\n<div class=\"con-item\"><strong>Lack of personal contact:</strong> No person to talk to directly, which may deter some customers — especially for complex or expensive purchases.</div>\n<div class=\"con-item\"><strong>Security risk:</strong> Customers worry about credit card and personal data being stolen, even with encryption available.</div>\n<div class=\"con-item\"><strong>Methods of payment:</strong> Customers who prefer cash cannot use e-commerce, as payment is geared towards credit/debit cards.</div>\n<div class=\"con-item\"><strong>Technology barriers:</strong> Some customers (especially older groups) lack internet access or confidence with technology.</div>\n<div class=\"con-item\"><strong>Only images seen:</strong> Cannot touch, feel, or try products before buying. This is less of a problem for familiar products (e.g. a known DVD) but significant for clothing or furniture.</div>\n</div>\n</div>", "check": {"question": "Which is listed as a disadvantage of e-commerce FOR CUSTOMERS?", "options": ["Businesses must constantly update their technology to stay competitive", "Businesses face worldwide competition from other online sellers", "Businesses must maintain secure websites to protect customer data", "They cannot touch, feel, or try products before buying"], "answer": 3, "explain": "''Only images seen'' — being unable to touch, feel, or try products — is listed as a customer disadvantage; the other options are business-side disadvantages."}}, {"title": "Face to Face Selling & Telesales", "html": "<p><strong>Face to face selling</strong> is typically done in a shop, bank, or travel agent. Key features:</p>\n<ul>\n<li>Direct interaction allows advice, demonstrations, questions, and answers</li>\n<li>Customers can see and handle products before buying</li>\n<li>Builds trust and personal relationships, encouraging return visits</li>\n<li>However, shops are <strong>expensive to operate</strong> — staff wages, rent, local taxes, cleaning and maintenance all apply</li>\n<li>Poor weather or inconvenience may push customers to shop online instead</li>\n</ul>\n<p><strong>Telesales</strong> bridges e-commerce and face to face. Key features:</p>\n<ul>\n<li>Useful for customers not comfortable with online shopping but happy to talk by phone</li>\n<li>Allows the customer to negotiate — e.g. renewing a mobile phone contract by phone lets them bargain for a better deal</li>\n<li>Larger businesses have dedicated telesales departments; smaller businesses may lack staff</li>\n<li><strong>Cold calling</strong> — unsolicited calls at inconvenient times — is seen as a nuisance by many customers</li>\n</ul>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Best for Face to Face</div>\n<div class=\"pro-item\">High-value or complex products (e.g. cars, wedding dresses, electronics)</div>\n<div class=\"pro-item\">When service and advice are central to the buying decision</div>\n<div class=\"pro-item\">When customers want to touch or try the product before buying</div>\n</div>\n<div>\n<div class=\"col-head\">✓ Best for Telesales</div>\n<div class=\"con-item\">Renewing subscriptions or contracts (e.g. insurance, phone, utilities)</div>\n<div class=\"con-item\">Reaching customers who are not tech-savvy</div>\n<div class=\"con-item\">When customers want to negotiate terms or receive personalised guidance by phone</div>\n</div>\n</div>", "check": {"question": "Which selling method is most useful for a customer who wants to negotiate a better deal, e.g. renewing a mobile phone contract?", "options": ["E-commerce", "Face to face selling", "Click and collect", "Telesales"], "answer": 3, "explain": "The card states telesales allows the customer to negotiate — e.g. renewing a mobile phone contract by phone lets them bargain for a better deal."}}, {"title": "The Importance of Customer Service & After-Sales Service", "html": "<p><strong>Customer service</strong> is vital to maintaining and increasing sales. A business must retain existing customers and attract new ones — losing customers to competitors is extremely costly.</p>\n<p>Good customer service is especially important where the product requires a high level of service — compare buying a book online (low service needed) with buying a wedding dress (high service, face-to-face essential).</p>\n<p><strong>After-sales service</strong> is what happens when things go wrong after a purchase. It might include:</p>\n<ul>\n<li>Offering refunds or exchanges (even where not legally required)</li>\n<li>Organising speedy repairs</li>\n<li>Keeping the customer informed about a problem being resolved</li>\n</ul>\n<p>The goal is to leave the customer satisfied, so they return and spend more in the future. Competitors are always ready to take customers from any business seen to be falling short on service.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Why After-Sales Service Matters</div>\n<div class=\"pro-item\">Ensures customers are satisfied after purchase, encouraging repeat business and loyalty.</div>\n<div class=\"pro-item\">Builds trust — customers who experience good problem resolution are more likely to return.</div>\n<div class=\"pro-item\">Positive word-of-mouth — satisfied customers recommend the business, attracting new customers at no extra marketing cost.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Risks of Poor After-Sales Service</div>\n<div class=\"con-item\">Customers switch to competitors after a bad post-purchase experience.</div>\n<div class=\"con-item\">Negative online reviews can rapidly damage brand reputation in the e-commerce age.</div>\n<div class=\"con-item\">Lost sales and reduced market share in the long run.</div>\n</div>\n</div>", "check": {"question": "Which purchase is used as the example of a product needing HIGH customer service, where face-to-face is essential?", "options": ["A wedding dress", "A DVD", "A phone contract renewal", "A book"], "answer": 0, "explain": "The card contrasts buying a book online (low service needed) with buying a wedding dress (high service, face-to-face essential)."}}, {"title": "Product Knowledge & Customer Engagement", "html": "<p><strong>Product knowledge</strong> is the detailed understanding staff have about what they sell. Its importance varies by business type:</p>\n<ul>\n<li>In a <strong>garden centre</strong>, staff need to advise on plants for specific conditions.</li>\n<li>In an <strong>electronics store</strong>, staff need to explain the latest TV or laptop technology to less-informed customers.</li>\n<li>In a <strong>newsagent</strong>, product knowledge is relatively less critical.</li>\n</ul>\n<p>Training costs time and money, but better product knowledge &rarr; better customer service &rarr; more sales &rarr; profits cover the cost of training.</p>\n<p><strong>Customer engagement</strong> is the contact between a customer and the business. Good engagement means:</p>\n<ul>\n<li>Well-trained, polite, knowledgeable staff in face-to-face settings</li>\n<li>A friendly, helpful voice in telesales</li>\n<li>Carefully worded emails and texts in e-commerce (replicating the feeling of face-to-face engagement)</li>\n</ul>\n<p>⚠️ There is a fine line between being helpful and being too \"pushy.\" Car salespeople have a reputation for over-engagement — too much information or pressure can drive customers away.</p>\n<div class=\"case-study-box\">\n<h4>Case Study: Amazon vs John Lewis</h4>\n<p>Amazon competes on <strong>price, choice, and speed of delivery</strong> — using Prime''s next-day and same-day delivery to stay ahead. John Lewis, by contrast, focuses on <strong>product knowledge and face-to-face customer engagement</strong>, especially important for complex electronics purchases where customers need explanation. Both approaches show that excellent customer service can take very different forms depending on the business model.</p>\n</div>", "check": {"question": "In which type of business does the guide say product knowledge is ''relatively less critical''?", "options": ["A car dealership", "An electronics store", "A newsagent", "A garden centre"], "answer": 2, "explain": "The guide states that in a newsagent, product knowledge is relatively less critical, unlike a garden centre or electronics store."}}, {"title": "Real-World Application: Amazon & E-commerce Growth", "html": "<div class=\"case-study-box\">\n<h4>Case Study: Amazon</h4>\n<p>Amazon was started by Jeff Bezos in 1994, initially selling books online. It later expanded into electronics, video games, and through Amazon Marketplace, an enormous range of products. It is now one of the world''s leading e-commerce businesses.</p>\n<p>Amazon has always responded to competitors by focusing on speed and enhanced service. In 2007 it launched its <strong>Prime service</strong> in the UK, promising next-day delivery. When competitors matched this, Amazon added \"extras\" — free music and video streaming, same-day food delivery through Morrisons, and exclusive \"Prime Day\" deals for subscribers.</p>\n<p>Prime is a subscription service, and consumers are willing to pay for this enhanced level of service. Amazon places great emphasis on <strong>pricing, choice, and speed of delivery</strong> rather than face-to-face customer engagement.</p>\n</div>\n<p><strong>Key takeaways for the exam:</strong></p>\n<ul>\n<li>Amazon is an e-commerce business because it brings buyers and sellers together digitally, with physical delivery following the online sale</li>\n<li>It competes through speed and choice rather than in-person customer engagement</li>\n<li>Its success is closely tied to the logistics industry (warehouses, delivery networks)</li>\n<li>The coronavirus pandemic of 2020–21 accelerated e-commerce growth, forcing many traditional retailers to adapt or close (e.g. Debenhams and Top Shop left the high street)</li>\n</ul>", "check": {"question": "In what year did Amazon launch its Prime service in the UK?", "options": ["2015", "2020", "2007", "1994"], "answer": 2, "explain": "The case study states ''In 2007 it launched its Prime service in the UK, promising next-day delivery.''"}}]}, "terms": {"enabled": true, "pairs": [{"term": "E-commerce", "definition": "The bringing together of buying and selling electronically."}, {"term": "Customer service", "definition": "The area of a business that deals with customer enquiries."}, {"term": "Customer engagement", "definition": "The contact between the business and customer."}, {"term": "After-sales service", "definition": "Advice and help given to a customer after they have bought a product or service."}, {"term": "Product knowledge", "definition": "Detailed knowledge of a product/service that staff use to help persuade customers to buy."}, {"term": "Telesales", "definition": "Sales completed over the telephone."}, {"term": "Face to face selling", "definition": "Direct contact between buyer and seller, usually completed in a shop."}, {"term": "Click and collect", "definition": "Ordering online and collecting goods from a store at a later time."}, {"term": "Advantage of e-commerce (business)", "definition": "Lower operating costs — no need for expensive city-centre premises or rent."}, {"term": "Disadvantage of e-commerce (business)", "definition": "Worldwide competition — customers can easily compare prices online against global competitors."}, {"term": "Advantage of e-commerce (customer)", "definition": "Price comparison — can find the best deal easily across multiple sellers at any time."}, {"term": "Disadvantage of e-commerce (customer)", "definition": "Only images of goods seen — cannot touch or inspect the product before buying."}, {"term": "Why customer service matters", "definition": "It helps maintain or increase sales by retaining existing customers and attracting new ones."}, {"term": "Why product knowledge matters", "definition": "It encourages customers to make a purchase by providing clear, confident, helpful advice."}, {"term": "Impact of e-commerce on location", "definition": "Businesses can locate almost anywhere — only an internet connection is needed for orders; warehouse sited near motorway for deliveries."}, {"term": "Amazon Prime", "definition": "Amazon''s subscription service offering next-day/same-day delivery and streaming extras, used to stay ahead of competitors."}]}, "mcq": {"enabled": true, "questions": [{"question": "Which of the following is the correct definition of e-commerce?", "options": ["The buying and selling of goods in a physical shop", "The bringing together of buying and selling electronically", "Selling goods over the telephone", "The delivery of goods using drones"], "answer": 1, "explain": "Correct answer: E-commerce is specifically defined as the bringing together of buying and selling electronically (online sales). It always involves some form of physical delivery after the online sale — unlike digital distribution where the product itself is delivered digitally."}, {"question": "Which of the following is an advantage to a BUSINESS of using e-commerce?", "options": ["Customers can compare prices easily across multiple websites", "Customers can shop at any time of day or night", "Lower operating costs as no expensive shop premises are needed", "Customers can touch and examine products before buying"], "answer": 2, "explain": "Correct answer: Lower operating costs is an advantage to the BUSINESS — no need to pay expensive city-centre rents. Options A, B, and D are advantages to CUSTOMERS, not businesses. Always check whose perspective the question is asking about."}, {"question": "Customer engagement refers to:", "options": ["Allowing customers to try products before they buy", "The contact between the business and customer", "Improving the product knowledge of employees", "Shortening the supply chain"], "answer": 1, "explain": "Correct answer: Customer engagement is defined as the contact between the business and customer. This includes face-to-face interaction in stores, friendly voices in telesales, and carefully worded emails/texts in e-commerce."}, {"question": "A business finds it easy to gain customers but has difficulty retaining them. Which aspect of the business most likely needs improving?", "options": ["After-sales service", "E-commerce", "Marketing", "Procurement"], "answer": 0, "explain": "Correct answer: After-sales service. Marketing (C) is clearly working — it is attracting customers. The problem is what happens AFTER the sale. After-sales service keeps customers satisfied and coming back."}, {"question": "Face to face selling will help a business most when:", "options": ["The goods being sold are cheap and simple", "Service and advice are important to the customer", "The customer has a computer and internet access", "The goods are small and easily transported"], "answer": 1, "explain": "Correct answer: Face to face selling is most valuable when service matters — for example, buying a wedding dress, complex electronics, or financial products. The physical presence of staff allows advice, demonstrations, and relationship-building that e-commerce cannot fully replicate."}, {"question": "Which of the following is a disadvantage to CUSTOMERS of using e-commerce?", "options": ["Having to pay expensive city-centre rents", "Increased worldwide competition from other businesses", "Difficulty keeping up with advances in technology costs", "Inability to touch or inspect products before purchasing"], "answer": 3, "explain": "Correct answer: Only being able to see images of goods (not touch or inspect them) is a disadvantage to the CUSTOMER. Options A (rents), B (competition), and C (technology update costs) are all disadvantages to BUSINESSES using e-commerce."}, {"question": "Why is good product knowledge important to a business?", "options": ["It helps recruit better staff to the business", "It will help a business in the sales process", "It will develop better working conditions for staff", "It will mean that training costs are lower"], "answer": 1, "explain": "Correct answer: Good product knowledge helps staff in the sales process by allowing them to advise customers confidently, increasing the chance of a purchase. It does NOT reduce training costs (D) — in fact, gaining product knowledge requires investment in training."}, {"question": "Click and collect is best described as:", "options": ["Buying goods in a shop and having them delivered to your home", "Ordering goods online and collecting them from a store at a later time", "Using a phone to order goods from a telesales department", "Returning faulty goods to a warehouse after an online purchase"], "answer": 1, "explain": "Correct answer: Click and collect means ordering online and collecting goods from a store later. It solves the problem of customers not being home for delivery, while ensuring the product is in stock before the customer makes the journey."}, {"question": "Which of the following businesses is most likely to use telesales as a primary method of selling?", "options": ["A burger van", "A petrol station", "A school", "An insurance company"], "answer": 3, "explain": "Correct answer: An insurance company commonly uses telesales — customers call to get quotes, renew policies, or negotiate better deals. Burger vans (A) and petrol stations (B) use face-to-face selling, and schools (C) do not sell products in the conventional sense."}, {"question": "A manufacturer of diamond rings employs staff to visit jewellery stores. Which is an advantage to the manufacturer of selling face to face?", "options": ["The cut and colour of the diamonds can be clearly demonstrated", "The jewellery stores have the opportunity to negotiate very low prices", "The risk of the rings being stolen is kept as low as possible", "The sales staff can give out lots of free samples"], "answer": 0, "explain": "Correct answer: Face-to-face selling allows the physical product to be demonstrated and examined — crucial for diamond rings where cut, colour, and quality must be seen in person. Option B (negotiating low prices) is a benefit to the BUYER, not the manufacturer."}, {"question": "Which of the following will NOT improve customer engagement for an e-commerce business?", "options": ["Training staff on the benefits of the product range", "Only selling products that have been certified as organic", "Sending carefully worded personalised emails to interested customers", "Sending text messages to previous customers about new products"], "answer": 1, "explain": "Correct answer: Only selling certified organic products is a product/sourcing decision — it does not directly improve the CONTACT between the business and customer. Options A, C, and D all directly improve how the business communicates and connects with its customers."}, {"question": "Which of the following would help a sole trader whose shop has difficulty RETAINING customers?", "options": ["Advertise other competing shops in the local area", "Close the shop early on weekdays in the school holidays", "Improve customer service by being friendly and polite", "Offer a free item to new customers who spend over a threshold"], "answer": 2, "explain": "Correct answer: If the shop is advertised and prices are reasonable, the problem is RETENTION. Customer service (being friendly and polite) improves customer engagement and gives customers a reason to return. Option D attracts NEW customers, not retains existing ones."}]}, "fib": {"enabled": true, "questions": [{"text": "E-commerce is the bringing together of [buying] and selling [electronically]."}, {"text": "Customer [engagement] is the contact between the business and customer, while customer [service] deals with enquiries."}, {"text": "After-sales service is advice and help given to a customer [after] they have bought a product."}, {"text": "Face to face selling is usually completed in a [shop] where there is direct contact between buyer and [seller]."}, {"text": "A disadvantage of e-commerce for businesses is [worldwide] competition, as customers can easily compare prices online."}, {"text": "[Click] and collect allows customers to order online and then pick up their goods from a [store] at a later time."}, {"text": "Good [product] knowledge helps staff to persuade customers to buy and increases the chance of making a [sale]."}, {"text": "One advantage of e-commerce to businesses is [lower] operating costs, as they do not need to pay expensive city-centre [rents]."}, {"text": "Telesales can be used as a bridge between e-commerce and [face] to [face] selling."}, {"text": "The growth of e-commerce has led to the creation of [specific] departments and new [skill] development requirements."}, {"text": "Amazon launched its [Prime] service in the UK in 2007, promising [next-day] delivery on a wide range of products."}, {"text": "A disadvantage of e-commerce for customers is that only [images] of goods can be seen, unlike in a shop where they can [touch] the product."}]}, "tf": {"enabled": true, "questions": [{"statement": "E-commerce involves some form of physical delivery after an online sale.", "answer": true, "explain": "TRUE. This is what distinguishes e-commerce from digital distribution — with e-commerce, the product is still physically delivered to the customer after being purchased online."}, {"statement": "A business using e-commerce must always be located near a city centre.", "answer": false, "explain": "FALSE. E-commerce businesses can locate almost anywhere. The ''front end'' (order taking) only requires an internet connection, and the warehouse simply needs to be near good transport links like a motorway network for efficient delivery."}, {"statement": "After-sales service is only important if a product is legally required to come with a guarantee.", "answer": false, "explain": "FALSE. After-sales service is important regardless of legal requirements. Businesses that offer refunds or resolve problems (even when not legally required to) build customer loyalty and encourage repeat purchases."}, {"statement": "Telesales can be a useful method of selling to older customers who are less comfortable with online shopping.", "answer": true, "explain": "TRUE. Telesales bridges the gap between e-commerce and face-to-face selling. Customers who are not comfortable using the internet may be very happy to talk to someone on the phone and be guided through the buying process."}, {"statement": "A business with a well-designed website will always provide better customer engagement than a physical shop.", "answer": false, "explain": "FALSE. A website creates a professional image, but customer engagement — the contact between business and customer — is often stronger in face-to-face settings where staff can directly answer questions, demonstrate products, and build personal relationships."}, {"statement": "Click and collect has meant that businesses need to dedicate more in-store space for collection points.", "answer": true, "explain": "TRUE. The success of click and collect has led businesses to allocate dedicated floor space for collection customers inside their stores, affecting how the available space is used overall."}, {"statement": "E-commerce always reduces the number of employees a business needs.", "answer": false, "explain": "FALSE. The effect on employment depends on the situation. An existing business switching to e-commerce may reduce staff in branches. But a new e-commerce business must recruit warehouse staff, website managers, and customer service representatives."}, {"statement": "Online security is only a concern for customers, not for businesses using e-commerce.", "answer": false, "explain": "FALSE. Security is a concern for BOTH customers AND businesses. Businesses must operate a secure website and keep customer data safe. A security breach damages customer trust and can result in significant financial costs and reputational harm."}, {"statement": "Product knowledge is equally important in all types of businesses.", "answer": false, "explain": "FALSE. The importance of product knowledge varies by context. It is highly important in electronics stores or garden centres where customers need expert advice. It is relatively less critical in, for example, a newsagent."}, {"statement": "Amazon focuses more on pricing, choice, and speed of delivery than on face-to-face customer engagement.", "answer": true, "explain": "TRUE. Amazon competes primarily through price, product range, and delivery speed (Amazon Prime). John Lewis, by contrast, relies on face-to-face customer engagement and product knowledge in its stores."}, {"statement": "Cold calling (unsolicited telesales) is generally viewed positively by customers.", "answer": false, "explain": "FALSE. Cold calling is widely seen as a nuisance by many customers, particularly when calls arrive at inconvenient times. This is a growing issue with telesales as a selling method."}, {"statement": "E-commerce can help a small business compete with much larger firms on a global scale.", "answer": true, "explain": "TRUE. E-commerce allows even the smallest business to reach a worldwide market with a professional-looking website at relatively low cost — competing on a scale that would not have been possible through traditional retail."}]}, "misc": {"enabled": true, "items": [{"myth": "Having a website means a business is doing e-commerce.", "truth": "E-commerce means the business actually SELLS products online — not just advertises them. A business with only a promotional website that does not take online orders is NOT an e-commerce business.", "check": {"question": "A business has a website that only advertises its products, with no way to buy online. Is this e-commerce?", "options": ["Yes – any business website automatically counts as e-commerce", "No – e-commerce requires actually selling online, not advertising", "Only if it''s a well-known brand with a large customer base", "Yes, as long as the website clearly lists prices and products"], "answer": 1, "explain": "E-commerce means the business actually sells online — a promotional-only website with no orders taken is not e-commerce."}}, {"myth": "E-commerce is only suitable for large businesses like Amazon.", "truth": "E-commerce is accessible to businesses of all sizes. A small business can set up a website for relatively little cost and reach a worldwide market, competing with larger firms in ways that were not possible before the internet.", "check": {"question": "Which statement about e-commerce and business size is correct?", "options": ["E-commerce requires a large marketing budget to work at all", "Small businesses can use e-commerce to reach a worldwide market", "Only businesses with physical stores can succeed online", "E-commerce is only suitable for large businesses like Amazon"], "answer": 1, "explain": "E-commerce is accessible to businesses of all sizes — a small business can set up a website cheaply and reach a worldwide market."}}, {"myth": "Customer service only means being polite to customers in a shop.", "truth": "Customer service covers the FULL customer journey: before, during, AND after the sale. After-sales service (handling returns, repairs, complaints) is a critical and separately examinable component of good customer service.", "check": {"question": "What does ''customer service'' actually cover, according to the guide?", "options": ["Only advertising and promotion before the sale is made", "Only handling complaints and returns after the sale is made", "Only being polite to customers face-to-face in a shop", "The full journey — before, during, and after the sale"], "answer": 3, "explain": "Customer service covers the full customer journey, including after-sales service, not just politeness in a shop."}}, {"myth": "E-commerce always reduces costs for a business.", "truth": "While e-commerce can lower operating costs (no shop rent), it also creates NEW costs: website security, delivery logistics, returns handling, and keeping up with technology. The net financial effect depends on the specific business.", "check": {"question": "Does e-commerce always reduce a business''s costs?", "options": ["No – it lowers some costs but adds new ones like security and logistics", "No – e-commerce always increases a business''s total operating costs", "Yes – it always reduces costs because there is no shop rent to pay", "Yes – because online businesses no longer need to employ any staff"], "answer": 0, "explain": "E-commerce can lower operating costs but also creates new costs such as website security, delivery logistics, and returns handling."}}, {"myth": "A disadvantage of e-commerce to the customer is that it costs the business more money.", "truth": "When a question asks for a disadvantage to the CUSTOMER, you must write about how the customer is negatively affected — not how the business is affected. Mixing up perspectives is one of the most common ways students lose marks.", "check": {"question": "If a question asks for a disadvantage of e-commerce TO THE CUSTOMER, what must the answer focus on?", "options": ["How the customer is negatively affected", "How the business loses market share", "How the business''s costs increase", "How delivery companies are affected"], "answer": 0, "explain": "Mixing up perspectives is a common error — an answer about a ''disadvantage to the customer'' must focus on the customer, not the business."}}, {"myth": "Good customer engagement means being as helpful and informative as possible at all times.", "truth": "There is a fine line between being helpful and being ''pushy.'' Too much information or pressure can drive customers away. Good engagement means reading the customer''s needs and responding appropriately — not overwhelming them.", "check": {"question": "According to the guide, what is the risk of ''too much'' customer engagement?", "options": ["It only affects online customers, not face-to-face ones", "It always increases sales no matter how it''s done", "It has no downsides at all for the business", "It can feel pushy and drive customers away"], "answer": 3, "explain": "There is a fine line between being helpful and being pushy — too much information or pressure can drive customers away."}}, {"myth": "Product knowledge is only important for face-to-face selling.", "truth": "Product knowledge is also important in telesales (staff must advise customers over the phone) and e-commerce (website descriptions, FAQs, and live chat all require accurate, detailed product information).", "check": {"question": "Is product knowledge only important for face-to-face selling?", "options": ["No – it also matters in telesales and in e-commerce websites", "No – it only matters for e-commerce, not telesales", "Yes – it is completely irrelevant to telesales and e-commerce", "Yes – only face-to-face shop staff need product knowledge"], "answer": 0, "explain": "Product knowledge also matters in telesales (advising by phone) and e-commerce (accurate website descriptions and live chat)."}}, {"myth": "Click and collect is the same as home delivery.", "truth": "Click and collect means the customer orders online but COLLECTS from a store — there is NO home delivery. It is specifically designed to solve the problem of customers not being home when a delivery arrives.", "check": {"question": "What is the key difference between click and collect and home delivery?", "options": ["Click and collect only works for food and grocery shopping", "They are exactly the same thing with no real difference", "Click and collect is always faster than home delivery", "Click and collect means collecting from a store, not delivery"], "answer": 3, "explain": "Click and collect means ordering online but collecting from a store — there is no home delivery involved."}}, {"myth": "E-commerce and digital distribution mean the same thing.", "truth": "E-commerce involves an online sale followed by PHYSICAL delivery. Digital distribution means the product itself is delivered digitally (e.g. a downloaded game or e-book) with no physical delivery required.", "check": {"question": "What is the key difference between e-commerce and digital distribution?", "options": ["Digital distribution always involves a physical shop instead", "E-commerce involves physical delivery, unlike digital", "They mean exactly the same thing in every situation", "E-commerce never involves any kind of delivery at all"], "answer": 1, "explain": "E-commerce involves an online sale followed by physical delivery, while digital distribution delivers the product itself digitally, e.g. a downloaded game or e-book."}}, {"myth": "Telesales is becoming irrelevant because of e-commerce.", "truth": "Telesales remains important as a bridge between e-commerce and face-to-face selling, particularly for older customers, subscription renewals (insurance, utilities, phone contracts), and situations where customers want to negotiate directly.", "check": {"question": "Is telesales becoming irrelevant because of e-commerce?", "options": ["Yes – no businesses run telesales departments anymore at all", "No – it remains important as a bridge for older customers", "Yes – it has been entirely replaced by e-commerce websites", "No – it is now more popular than face-to-face selling"], "answer": 1, "explain": "Telesales remains important, particularly for older customers, subscription renewals, and customers who want to negotiate directly."}}]}, "tips": {"enabled": true, "items": [{"title": "One Point. Full Stop. Move On.", "html": "\n      <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct point. No explanation. No case study. No paragraphs.</p>\n      <p><strong>The Formula:</strong> One specific, correct point = 1 mark ✅</p>\n      <ul>\n        <li><strong>❌ Bad Answer (0 marks):</strong> <em>\"Promotion.\"</em> — This is a marketing concept, not a method of selling.</li>\n        <li><strong>✅ Good Answer (1 mark):</strong> <em>\"E-commerce / telesales / face to face selling.\"</em></li>\n      </ul>\n      <p><strong>⚠️ Examiner Warning:</strong> Many students lost marks by writing promotional methods (price skimming, advertising) when asked for a <em>method of selling</em>. Read the exact question wording before writing.</p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write a definition when asked to ''identify''. Just name the thing.</p>\n    ", "check": {"question": "For a 1-mark ''State'' or ''Identify'' question, what should your answer contain?", "options": ["A full paragraph with U, APP and AN chains", "One specific point, no explanation needed", "Two safety points, one per mark", "A dictionary-style term definition"], "answer": 1, "explain": "The tip states a 1-mark identify/state question needs exactly one correct point — no explanation, no case study."}}, {"title": "Point + Explain = 2 Marks", "html": "\n      <p>For a 2-mark <strong>''Explain''</strong> question, you need a point AND an explanation of how it works. Two sentences — two marks.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Sentence 1 — State the point (K/U):</strong> Name the advantage, disadvantage, or concept.</li>\n        <li><strong>Sentence 2 — Explain it (U):</strong> Say WHY or HOW it works.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark max):</strong><br/><em>\"E-commerce means the business can sell more.\"</em><br/>Too vague — doesn''t explain the mechanism.</p>\n      <p><strong>✅ Good Answer (2 marks):</strong><br/><em>\"A business using e-commerce has lower operating costs (1) because it does not need to pay expensive city-centre rents for a physical shop (1).\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Some students answered from the customer''s perspective when asked about a business advantage. Re-read: who does the question say the advantage is FOR?</p>\n    ", "check": {"question": "What error did the guide flag as a common mistake on this 2-mark ''explain'' question about a business advantage?", "options": ["Answering from the customer''s view, not the firm''s", "Forgetting to name the business anywhere at all", "Using bullet points, not full written sentences", "Writing far too much content for the marks given"], "answer": 0, "explain": "The examiner warning notes some students answered from the customer''s perspective when the question asked about a business advantage."}}, {"title": "The Holy Trinity: U → APP → AN", "html": "\n      <p>A 3-mark analyse question requires all three elements. You will score <strong>ZERO for analysis</strong> if you don''t apply your answer to the specific business in the case study.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the theory or benefit clearly.</li>\n        <li><strong>Step 2 — Application (APP):</strong> Directly reference the case study business with specific text evidence.</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the financial or operational IMPACT on the business.</li>\n      </ul>\n      <p><strong>Sentence Starters:</strong></p>\n      <ul>\n        <li><em>U: \"Good product knowledge means staff can advise customers on...\"</em></li>\n        <li><em>APP: \"In the case of [Business Name], the text states that...\"</em></li>\n        <li><em>AN: \"This will lead to more sales, meaning...\" / \"As a result, the business will...\"</em></li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/><em>\"Product knowledge helps employees advise customers so they buy more.\"</em><br/>No application to the specific business = maximum 1 mark.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/><em>\"Call centre employees need to be able to advise customers on what is best to buy (U). AZ''s products are sold to qualified medical professionals, hospitals and governments (APP), so if employees cannot answer technical questions, sales and profits may fall (AN).\"</em></p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do not write everything you know about the topic. Answer the specific question with reference to the specific business.</p>\n    ", "check": {"question": "In the U → APP → AN structure for a 3-mark analyse question, what does ''APP'' require?", "options": ["A general definition of the relevant business theory", "A concluding evaluation using the ''it depends'' rule", "A clear judgement or final recommendation on the issue", "Direct reference to the case study business with evidence"], "answer": 3, "explain": "Application (APP) means directly referencing the case study business with specific text evidence — without it, you score zero for analysis."}}, {"title": "Two 3-Mark Chains. No Conclusion Needed.", "html": "\n      <p>A 6-mark question is simply a <strong>3-mark question done twice</strong>. You must analyse TWO separate impacts, each with its own U → APP → AN chain.</p>\n      <p><strong>⚠️ Critical Warning:</strong> There are <strong>ZERO marks</strong> available for a conclusion or evaluation here. Do NOT write \"Overall, I think...\" — it wastes time and scores nothing.</p>\n      <p><strong>Structure:</strong></p>\n      <ul>\n        <li><strong>Impact 1 (3 marks):</strong> U → APP → AN</li>\n        <li><strong>Impact 2 (3 marks):</strong> U → APP → AN</li>\n      </ul>\n      <p><strong>Sentence Starters for each paragraph:</strong></p>\n      <ul>\n        <li><em>\"One advantage/disadvantage is that... (U)\"</em></li>\n        <li><em>\"In the case of [Business], the text tells us that... (APP)\"</em></li>\n        <li><em>\"This means that... resulting in... (AN)\"</em></li>\n      </ul>\n      <p><strong>⚠️ Examiner Warning (Primark question):</strong> Many students wrote from the CUSTOMER''S point of view when the question asked about Primark Ltd. If the question says \"to Primark Ltd,\" every point must show how PRIMARK is affected — not how customers feel about it.</p>\n    ", "check": {"question": "How many marks are available for a conclusion or evaluation in a 6-mark ''analyse two impacts'' question?", "options": ["Six", "Zero", "One", "Three"], "answer": 1, "explain": "The guide is explicit that there are zero marks for a conclusion in a 6-mark ''two impacts'' analyse question — writing ''Overall, I think...'' wastes time and scores nothing."}}, {"title": "Decision + Contextual Justification", "html": "\n      <p>A 3-mark recommend question is NOT just a repeat of advantages and disadvantages. It needs a <strong>clear decision</strong> supported by a <strong>contextual justification</strong>.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>1 mark — Judgement:</strong> Make a clear recommendation (should / should not).</li>\n        <li><strong>2 marks — Contextual justification:</strong> Use EVIDENCE from the case study text to support your decision. The evidence must be USED (not just repeated).</li>\n        <li><strong>OR 1 mark — Non-contextual justification:</strong> A reason without specific text reference.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/><em>\"Primark should continue click and collect because it is good for customers.\"</em><br/>Wrong perspective, no context used.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/><em>\"Primark should continue (JUDGEMENT). If it stops, it may lose customers who have already changed their buying habits and got used to ordering online, as the text states buying habits have already changed (CONTEXT). This would reduce Primark''s revenue and market share. (+2 MARKS)\"</em></p>\n      <p><strong>⚠️ Examiner Comment:</strong> Less than a quarter of students got full marks on this type of question. Most could make a recommendation but could not justify it using the context — they repeated the text rather than using it to support their argument.</p>\n    ", "check": {"question": "What does a full 3-mark ''recommend'' answer require beyond a simple advantage/disadvantage list?", "options": ["An evaluation paragraph using the ''it depends'' rule", "A clear judgement supported by contextual justification", "A list of three separate recommendations for the business", "Only a simple yes or no decision with no reasoning"], "answer": 1, "explain": "A 3-mark recommend answer needs 1 mark for judgement and 2 marks for contextual justification, using case study evidence that is actually used, not just repeated."}}, {"title": "Four-Paragraph Structure for Full Marks", "html": "\n      <p>A 9-mark evaluate question tests your ability to argue both sides and make a justified judgement. Structure your answer in <strong>four paragraphs</strong>:</p>\n      <ul>\n        <li><strong>Paragraph 1 — Knowledge & Understanding (K + U):</strong> Define key concepts relevant to the question (e.g. what customer service is, what growth means as a business objective).</li>\n        <li><strong>Paragraph 2 — First side with analysis (AN + APP):</strong> Argue FOR the importance of customer service, with a full chain of reasoning linked to the specific business.</li>\n        <li><strong>Paragraph 3 — Counterargument with analysis (AN + APP):</strong> Argue against or present a counter-view (e.g. other factors affecting growth such as price or competition from no-frills rivals).</li>\n        <li><strong>Paragraph 4 — Evaluation (EVAL — 3 marks):</strong> Write a justified conclusion using the \"It depends on...\" rule. Decision + Context + Impact/Reasoning.</li>\n      </ul>\n      <p><strong>Evaluation Sentence Starters:</strong></p>\n      <ul>\n        <li><em>\"Overall, good customer service is important to Virgin Atlantic achieving growth because...\"</em></li>\n        <li><em>\"However, this depends on whether Virgin Atlantic is targeting price-conscious customers or premium travellers...\"</em></li>\n        <li><em>\"In conclusion, I recommend... because... but this depends on...\"</em></li>\n      </ul>\n      <p><strong>⚠️ Evaluation Warning:</strong> A conclusion that only repeats what you already wrote scores ZERO for evaluation. The \"It depends on...\" must introduce a NEW condition or consideration not already covered.</p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT list every fact you know about customer service. Every sentence must be specifically linked to the business''s objective in the question.</p>\n    ", "check": {"question": "According to the guide, what makes a concluding ''it depends on...'' statement score zero for evaluation?", "options": ["Failing to mention the business by name", "Repeating earlier points instead of a new condition", "Placing it in paragraph four, not paragraph one", "Writing fewer than two full sentences"], "answer": 1, "explain": "The evaluation warning states a conclusion that only repeats what was already written scores zero — the ''it depends'' must introduce a new condition not already covered."}}, {"title": "Business vs Customer: Never Mix These Up", "html": "\n      <p>One of the most common ways students lose marks in 4.3 is answering from the <strong>wrong perspective</strong>.</p>\n      <p><strong>Always identify WHO the question is asking about before you write:</strong></p>\n      <ul>\n        <li>If the question says \"advantage to the BUSINESS\" — every point must show how the BUSINESS benefits.</li>\n        <li>If the question says \"disadvantage to the CUSTOMER\" — every point must show how the CUSTOMER is negatively affected.</li>\n      </ul>\n      <p><strong>Examples of the perspective trap:</strong></p>\n      <ul>\n        <li><strong>❌ Wrong (0 marks):</strong> Answering \"customers can''t touch the product\" when asked about a disadvantage to M&S of selling food via e-commerce. That is a customer disadvantage.</li>\n        <li><strong>✅ Right (1 mark):</strong> \"M&S may suffer reputational damage if its website crashes, leading to a loss of customers and reduced revenue.\" — This is a business disadvantage.</li>\n      </ul>\n      <p><strong>⚠️ Direct Examiner Quote:</strong> On the Primark question, many students wrote advantages and disadvantages from the customer''s point of view even when the question clearly asked about Primark Ltd. This was one of the main reasons students scored 0 marks on that question.</p>\n    ", "check": {"question": "On the Primark question referenced in the guide, what was the main reason many students scored 0 marks?", "options": ["They wrote points from the customer''s view, not Primark''s", "They ran out of exam time before finishing the answer", "They used bullet points instead of full written paragraphs", "They forgot to mention click and collect at all"], "answer": 0, "explain": "The direct examiner quote notes many students wrote from the customer''s point of view even though the question asked about Primark Ltd, causing them to score 0."}}]}, "exam": {"enabled": true, "questions": [{"question": "Analyse one advantage and one disadvantage to Primark Ltd of offering an online click and collect service for shoppers. [6 marks]", "marks": 6, "hint": "This question is asking about the impact on PRIMARK — not on customers. For each point, use the U → APP → AN chain. Make sure your application uses details from the case study (e.g. Primark only started online selling in 2022, changes in buying habits, fashion retailer with low prices).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 6 marks (AO1b + AO2 + AO3a)</h5>\n<p><strong>Advantage (3 marks):</strong></p>\n<ul>\n<li><strong>Understanding (1 mark):</strong> Identify an advantage of offering click and collect (e.g. open 24/7 for orders; reach more people; professional website adds to brand image; save money on home deliveries).</li>\n<li><strong>Application (1 mark):</strong> Apply to Primark using text evidence (e.g. only started online selling in 2022; pressure from customers; changes in buying habits; fashion retailer with low-cost suppliers).</li>\n<li><strong>Analysis (1 mark):</strong> State the business impact (e.g. may boost revenue; increase/maintain market share; more brand awareness). Note: \"make more profit\" alone is insufficient — must link to higher revenue or competitiveness.</li>\n</ul>\n<p><strong>Disadvantage (3 marks):</strong></p>\n<ul>\n<li><strong>Understanding (1 mark):</strong> Identify a disadvantage (e.g. increased costs for staffing or website; increased returns/refunds; reduced impulse purchases; more online competition; keeping data safe; keeping up with technology; still requires a collection service — no home delivery).</li>\n<li><strong>Application (1 mark):</strong> Apply to Primark using text evidence.</li>\n<li><strong>Analysis (1 mark):</strong> State the business impact (e.g. competitors can now see and react to Primark''s strategy; may reduce profit margins; fines if data not kept safely; still needs expensive high street stores).</li>\n</ul>\n<p><strong>NB:</strong> Analysis must be business-facing. Both points must be for Primark Ltd — NOT for customers. \"Customers may not want to buy online\" scores no marks — they can still go to the retail store.</p>\n<p><strong>Examiner''s Comment:</strong> Less than a quarter of candidates gained 4 or more marks. Many wrote from the customer''s perspective rather than Primark''s. A significant number also incorrectly discussed home delivery — the service Primark offers is click and collect (in-store collection), not home delivery.</p></div>"}, {"question": "Recommend whether Primark Ltd should continue to offer an online click and collect service for shoppers. [3 marks]", "marks": 3, "hint": "Make a clear decision first (1 mark). Then justify your decision using CONTEXT from the case study — not just general points about click and collect. The context must be USED to support your argument, not just repeated.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO3b)</h5>\n<ul>\n<li><strong>Judgement (1 mark):</strong> Clear recommendation — should continue OR should stop offering click and collect.</li>\n<li><strong>Contextual justification (2 marks):</strong> A reason using evidence from the case study TEXT — the context must be USED (not just repeated) to support the decision.</li>\n<li><strong>OR Non-contextual justification (1 mark):</strong> A valid reason without specific case study reference.</li>\n</ul>\n<p><strong>Exemplar response (full marks):</strong><br>\"Primark should continue (1). If it stops, it may lose customers who have already got used to ordering online, as the text confirms that buying habits have already changed (CONTEXT). This would reduce Primark''s revenue and market share. (+2)\"</p>\n<p><strong>Examiner''s Comment:</strong> Most candidates could make a recommendation but could not justify it adequately — often writing from the customer''s point of view. Less than a quarter gained full marks. Examiners look for the context to be USED, not simply repeated.</p></div>"}, {"question": "Which of the following is an advantage to the manufacturer of selling face to face to jewellery stores?", "marks": 1, "hint": "Think about what face-to-face selling uniquely allows that e-commerce or telesales cannot — particularly for a high-value, visual product like diamond rings.", "markScheme": "<div class=\"marks-section\"><h5>Answer: A</h5>\n<p><strong>A — The cut and colour of the diamonds can be clearly demonstrated.</strong></p>\n<p><strong>Why A is correct:</strong> Face-to-face selling allows the physical product to be examined in person. For diamond rings, where cut, colour, clarity, and craftsmanship are key selling points, a live demonstration is far more effective than an image or telephone description.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>B — Negotiating very low prices</strong> is a benefit to the BUYER (jewellery stores), not the manufacturer/seller.</li>\n<li><strong>C — Reducing theft risk</strong> is not a specific or notable advantage of face-to-face selling over other methods.</li>\n<li><strong>D — Free samples</strong> are not realistic for diamond rings, and giving away samples is not a defining feature of face-to-face selling.</li>\n</ul></div>"}, {"question": "Calculate the percentage decrease in Zara''s sales revenue between 2019 and 2020. Show your workings. [2 marks]", "marks": 2, "hint": "First calculate the change in revenue (2019 minus 2020). Then divide by the ORIGINAL (2019) figure and multiply by 100. No need to include a negative sign — the question already states it is a decrease.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2)</h5>\n<ul>\n<li><strong>Step 1 (1 mark):</strong> €19,954m − €14,129m = €5,825m</li>\n<li><strong>Step 2 (1 mark):</strong> (€5,825m ÷ €19,954m) × 100 = 29.2% (accept 29% or any other reasonable level of accuracy)</li>\n</ul>\n<p>Two marks for a correct final answer, with or without workings shown. If the final answer is wrong but working clearly shows €5,825m, award 1 mark (own figure rule).</p>\n<p>Negative sign not required. Percentage sign not required.</p>\n<p><strong>Examiner''s Comment:</strong> Generally well answered. Common errors: using the 2020 figure as the denominator instead of the 2019 figure, or inverting the formula entirely.</p></div>"}, {"question": "Explain one possible advantage to a business of selling its products via e-commerce. [2 marks]", "marks": 2, "hint": "Make sure your advantage is clearly linked to e-commerce (not just ''selling more products'' without explanation) and is from the BUSINESS''S perspective, not the customer''s.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b)</h5>\n<ul>\n<li><strong>1 mark:</strong> Identify an advantage of selling via e-commerce (e.g. sell worldwide; open all the time; professional look at little cost; lower operating costs).</li>\n<li><strong>1 further mark:</strong> Explain the advantage — say how or why it benefits the business.</li>\n</ul>\n<p>Answers do not need to relate to Zara. \"Selling more products\" without any link to e-commerce scores 0.</p>\n<p><strong>Examiner''s Comment:</strong> Generally well answered. Most students focused on 24/7 availability or wider audience. Some answered from the customer''s perspective — the question asks about a BUSINESS advantage. Read the question carefully.</p></div>"}, {"question": "Analyse one reason why it is important to AZ that its call centre employees have good product knowledge. [3 marks]", "marks": 3, "hint": "Use U → APP → AN. Your application MUST use specific evidence from the AZ case study — simply naming the product (medicines) is NOT enough for the application mark.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5>\n<ul>\n<li><strong>Understanding (1 mark):</strong> Identify a reason why product knowledge matters for call centre staff (e.g. can offer correct advice; deal with customer queries; increase customer satisfaction; customer trusts the business/product).</li>\n<li><strong>Application (1 mark):</strong> Apply to AZ using TEXT EVIDENCE (e.g. operates in 100+ countries; sells to qualified medical professionals, hospitals and governments; switched from sales visits to a call centre; high quality products/code of ethics).</li>\n<li><strong>Analysis (1 mark):</strong> State the business impact (e.g. if employees cannot answer questions, sales/profits will decrease; could affect reputation; may reduce money available for R&D of new medicines).</li>\n</ul>\n<p><strong>NB:</strong> A basic reference to the product (medicines and vaccines) is NOT sufficient for the application mark — must use specific text evidence about AZ''s operations or customers.</p>\n<p><strong>Examiner''s Comment:</strong> Generally well answered, but many answers used no text evidence beyond naming the product, limiting those responses to 2 marks maximum.</p></div>"}, {"question": "Identify one method of selling products to customers. [1 mark]", "marks": 1, "hint": "There are three main selling methods covered in this topic. Name just one — no explanation needed.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a)</h5>\n<ul>\n<li><strong>1 mark</strong> for any correct method: e-commerce / online / websites / digitally; shops / retail / face to face; telesales; mail order / catalogues.</li>\n</ul>\n<p><strong>Examiner''s Comment:</strong> Most candidates gained this mark, but some wrote promotional methods (price skimming, advertising) instead of methods of selling. Read the question carefully.</p></div>"}, {"question": "Customer engagement:", "marks": 1, "hint": "Think about the official definition of customer engagement — what does it directly contribute to in a business?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5>\n<p><strong>B — Contributes to good customer service.</strong></p>\n<p><strong>Why B is correct:</strong> Customer engagement (the contact between business and customer) is one of the key ways a business delivers good customer service — well-trained, engaged staff build loyalty and improve customer satisfaction.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Trying before buying</strong> is a feature of face-to-face retail, not customer engagement per se.</li>\n<li><strong>C — Improving product knowledge of employees</strong> is about staff training, not customer engagement.</li>\n<li><strong>D — Shortening the supply chain</strong> is a logistics and procurement concept, unrelated to customer engagement.</li>\n</ul>\n<p><strong>Examiner''s Comment:</strong> Some students showed misunderstanding of ''customer engagement''. Always take time to read what the question is actually asking.</p></div>"}, {"question": "Calculate, using the figures shown in Fig. 1, the number of Barclays plc''s UK personal banking customers who are likely to have used online banking in 2020. Show your workings. [2 marks]", "marks": 2, "hint": "From the bar chart, 75% of UK banking customers used online banking in 2020. Barclays had 24 million UK personal banking customers. Calculate 75% of 24 million.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO2)</h5>\n<ul>\n<li><strong>Step 1 (1 mark):</strong> Identifies 75% of customers used online banking in 2020.</li>\n<li><strong>Step 2 (1 mark):</strong> 24m × 0.75 = 18 million.</li>\n</ul>\n<p>Two marks for the correct final answer (18m or 18,000,000), with or without workings shown.</p></div>"}, {"question": "Identify two impacts that e-commerce might have on business activity. [2 marks]", "marks": 2, "hint": "Think about what changes INSIDE a business when it adopts e-commerce — departments, employment levels, location decisions, skills requirements, delivery costs, etc.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1b)</h5>\n<ul>\n<li><strong>1 mark each</strong> for two different, correct impacts.</li>\n</ul>\n<p>Acceptable answers include: need to set up specific departments; recruit dedicated website/technical staff; invest in staff training; increased delivery costs; more online marketing needed; ability to sell 24/7 increasing customer numbers; fewer physical customers visiting a store; access to new international markets.</p>\n<p>No reward for general IT failure or general expansion answers without an e-commerce link. Both answers must be clearly different from each other.</p></div>"}, {"question": "Which of the following would help Geoff deal with this problem?", "marks": 1, "hint": "Geoff can gain customers (advertising is working and prices are good) but cannot KEEP them. Which option directly addresses the post-purchase experience and encourages customers to return?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5>\n<p><strong>C — Improve customer service by being friendly and polite.</strong></p>\n<p><strong>Why C is correct:</strong> The shop is advertised and prices are reasonable — marketing and pricing are not the issue. The problem is RETENTION. Friendly, polite customer service improves the experience and gives customers a reason to return.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Advertising other book shops</strong> would actively help competitors and drive customers away from Geoff''s shop.</li>\n<li><strong>B — Closing early</strong> reduces accessibility and would make retention worse, not better.</li>\n<li><strong>D — Free book for new customers</strong> targets gaining NEW customers, but the problem stated is retaining EXISTING ones.</li>\n</ul></div>"}, {"question": "This is an example of:", "marks": 1, "hint": "The customer physically enters a building and is served in person. Which method of selling involves direct contact between buyer and seller in a physical location?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5>\n<p><strong>C — Face to face selling.</strong></p>\n<p><strong>Why C is correct:</strong> The customer visits a physical location (post office) and is served directly by an assistant — direct contact between buyer and seller defines face-to-face selling.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — After-sales service</strong> is advice or help AFTER a purchase has already been made, not at the point of sale.</li>\n<li><strong>B — E-commerce</strong> involves buying and selling electronically — there is no online element here.</li>\n<li><strong>D — Telesales</strong> is completed over the telephone — the customer is physically present, not calling.</li>\n</ul></div>"}, {"question": "Explain one reason why quality is important to a business in the production of goods. [2 marks]", "marks": 2, "hint": "Give a reason WHY quality matters (K), then explain HOW that reason benefits the business (U). Answers do not need to refer to JLP.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a + AO1b)</h5>\n<ul>\n<li><strong>1 mark (Knowledge):</strong> State a reason why quality is important (e.g. reputation; gaining new customers; satisfying customer needs; retaining existing customers; reducing product returns and recalls; avoiding waste; avoiding disruption to production; allows a higher price to be charged).</li>\n<li><strong>1 further mark (Understanding):</strong> Explain or exemplify that reason.</li>\n</ul>\n<p>Answers do not need to relate to JLP.</p></div>"}, {"question": "JLP''s electrical department staff have good product knowledge. Analyse one positive impact of this on the quality of JLP''s customer service. [3 marks]", "marks": 3, "hint": "Use U → APP → AN. For the application mark, use specific details from the JLP case study (e.g. the wide range of computers, TVs and washing machines; face-to-face selling; chain of department stores).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5>\n<ul>\n<li><strong>Understanding (1 mark):</strong> State a benefit of knowledgeable staff (e.g. able to provide help/advice/suggestions; customer more confident; increased trust; business gets good reviews).</li>\n<li><strong>Application (1 mark):</strong> Apply to JLP using text evidence (e.g. chain of department stores; wide range including computers, TVs and washing machines; uses face-to-face selling; recent growth from e-commerce).</li>\n<li><strong>Analysis (1 mark):</strong> State the business impact (e.g. more sales; customer more likely to return or recommend to others; improved reputation).</li>\n</ul>\n<p>Focus on the selling aspect of the business, not manufacturing or supplier selection.</p></div>"}, {"question": "Explain two possible advantages to JLP of using e-commerce. [4 marks]", "marks": 4, "hint": "For each advantage: (1) State the advantage clearly (U), then (2) apply it specifically to JLP using details from the text (APP). Make sure both advantages are DIFFERENT from each other and are advantages to JLP — not to customers.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 4 marks (AO1b × 2 + AO2 × 2)</h5>\n<ul>\n<li><strong>1 mark each</strong> for each advantage stated (max 2), and <strong>1 further mark each</strong> for applying to JLP using text evidence (max 2).</li>\n</ul>\n<p>Advantages may include: reduces costs/more profit; wider market; increased sales; wider product range sold; reduces need for physical stores; reduces need to hold large inventory; less staff needed.</p>\n<p>Application evidence: chain of department stores; wide range of products (clothing, home furnishings, computers, TVs, washing machines); face-to-face selling currently used; recent growth from e-commerce.</p>\n<p>Both advantages must be different. Must be advantages to the BUSINESS, not the customer.</p></div>"}, {"question": "Which aspect of the business is most likely to need improving?", "marks": 1, "hint": "The business gains customers easily — so what is already working? The problem is keeping customers AFTER their first purchase. Which aspect deals with the post-purchase experience?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A</h5>\n<p><strong>A — After-sales service.</strong></p>\n<p><strong>Why A is correct:</strong> Marketing (C) is clearly working — the business gains customers easily. The problem is RETENTION. After-sales service determines how customers are treated after a purchase — poor after-sales service leads to customers not returning.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>B — E-commerce</strong> relates to the selling method, not to why customers stop returning.</li>\n<li><strong>C — Marketing</strong> is what gains customers — the question confirms this is already working well.</li>\n<li><strong>D — Procurement</strong> relates to buying supplies and inputs, not customer retention.</li>\n</ul></div>"}, {"question": "* Evaluate the importance of good customer service to Virgin Atlantic''s objective of growth. [9 marks]", "marks": 9, "hint": "This 9-mark evaluate question needs 4 paragraphs: (1) Define key terms (customer service + growth), (2) argue FOR customer service helping growth with Virgin Atlantic context, (3) argue AGAINST or present a counterpoint (e.g. price, no-frills competition), (4) write a justified ''it depends on...'' conclusion — NOT just repeating what you already wrote.", "markScheme": "<div class=\"marks-section\"><h5>Level Descriptors — 9 marks (AO1a×1, AO1b×1, AO2×2, AO3a×2, AO3b×3)</h5>\n<p><strong>Level 3 (7–9 marks):</strong> Good knowledge and understanding of customer service and the growth objective. Good application to Virgin Atlantic using specific text evidence. Good analysis showing logical chains of reasoning about the impact on growth. Strong, fully justified evaluation using context — judgement is made and conclusions go beyond what has already been written.</p>\n<p><strong>Level 2 (4–6 marks):</strong> Good knowledge with some application. Limited analysis with cause-and-consequence reasoning. Limited evaluation with a basic judgement.</p>\n<p><strong>Level 1 (1–3 marks):</strong> Limited knowledge of customer service. Some use of the scenario. Some simple cause-and-effect reasoning. No evaluation.</p>\n<p><strong>0 marks:</strong> No response or nothing worthy of credit.</p>\n<p><strong>Indicative content — FOR customer service helping growth:</strong></p>\n<ul>\n<li>Good customer service → repeat passengers → more sales → growth in revenue/profit</li>\n<li>Builds brand loyalty → word-of-mouth → new customers at no marketing cost</li>\n<li>Virgin Atlantic''s aim: \"people love to fly\" — directly requires excellent in-flight and ground service</li>\n<li>Made highest profit in 5 years in 2016 — good service likely contributed</li>\n</ul>\n<p><strong>Indicative content — AGAINST:</strong></p>\n<ul>\n<li>No-frills airlines cut customer service but offer lower prices, attracting price-sensitive customers</li>\n<li>Higher service levels mean higher costs (staff, food, training) — reduces profit available for growth investment</li>\n<li>Growth might require new routes or aircraft — finance may be more important than service</li>\n</ul>\n<p><strong>Evaluation — must use \"It depends on...\" with new context:</strong></p>\n<ul>\n<li>\"It depends on whether Virgin Atlantic is targeting premium travellers (where service is crucial) or price-conscious customers\"</li>\n<li>\"It depends on whether VA needs to grow by adding new routes/aircraft — if so, controlling costs may matter more\"</li>\n</ul></div>"}, {"question": "Which one of the following will NOT improve the level of customer service the store offers?", "marks": 1, "hint": "Think about what customer service actually means — the quality of interaction, advice, and assistance provided. Which option is a promotional or pricing decision rather than a customer service improvement?", "markScheme": "<div class=\"marks-section\"><h5>Answer: C</h5>\n<p><strong>C — Offering a free phone case with every mobile phone purchased.</strong></p>\n<p><strong>Why C is correct:</strong> A free phone case is a sales promotion / pricing incentive. It may attract customers, but it does not improve the QUALITY of service, advice, or interaction customers receive in store.</p>\n<p><strong>Why the others are wrong (they DO improve customer service):</strong></p>\n<ul>\n<li><strong>A</strong> — Training staff to be attentive and polite directly improves customer engagement — a key part of customer service.</li>\n<li><strong>B</strong> — Giving staff product feature lists improves product knowledge, enabling better advice for customers.</li>\n<li><strong>D</strong> — Training the manager to handle technical queries improves after-sales service and the ability to resolve customer problems effectively.</li>\n</ul></div>"}, {"question": "State two methods of ensuring quality. [2 marks]", "marks": 2, "hint": "Think about the two main formal approaches businesses use to check and maintain quality — one checks at the end, one checks continuously throughout production.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a × 2)</h5>\n<ul>\n<li><strong>1 mark each</strong> for two correct methods of ensuring quality.</li>\n<li>Quality control (e.g. inspection of product samples; mystery shoppers in retail)</li>\n<li>Quality assurance (e.g. continuous checking at every stage of production; training staff to identify errors)</li>\n</ul></div>"}, {"question": "Analyse one advantage to Tesco plc of selling using e-commerce. [3 marks]", "marks": 3, "hint": "Use U → APP → AN. Your application must link to something specific about TESCO from the case study (e.g. one of the UK''s largest retailers, sells through shops AND online, affected by competition).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3)</h5>\n<ul>\n<li><strong>Understanding (1 mark):</strong> State an advantage of e-commerce (e.g. customers can buy 24/7; sell to wider market; lower operating costs).</li>\n<li><strong>Application (1 mark):</strong> Apply to Tesco using text evidence (e.g. one of the UK''s largest retailers; already uses both shops and e-commerce; affected by increasing competition).</li>\n<li><strong>Analysis (1 mark):</strong> State the impact on Tesco''s business (e.g. more sales; helps it compete against rivals; higher revenue).</li>\n</ul></div>"}, {"question": "State one example of good customer service that retailers may provide for their customers. [1 mark]", "marks": 1, "hint": "Good customer service includes specific actions taken before, during, or after a sale — think beyond just being polite.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO1a)</h5>\n<ul>\n<li><strong>1 mark</strong> for any correct example: giving advice/product knowledge; accepting returns; being friendly/polite/welcoming (customer engagement); prompt delivery; effective after-sales service.</li>\n</ul></div>"}, {"question": "What is e-commerce?", "marks": 1, "hint": "Think about the official definition — e-commerce involves buying and selling using internet technology.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D</h5>\n<p><strong>D — A way to sell goods on the Internet.</strong></p>\n<p><strong>Why D is correct:</strong> E-commerce is the bringing together of buying and selling electronically — commonly known as online sales via the internet.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A</strong> — Quality control and quality assurance are methods to ensure quality, not e-commerce.</li>\n<li><strong>B</strong> — Planning tools include cash flow forecasts and SWOT analysis, not e-commerce.</li>\n<li><strong>C</strong> — A bank loan is a source of finance, completely unrelated to e-commerce.</li>\n</ul></div>"}, {"question": "Which one of the following businesses is most likely to use telesales?", "marks": 1, "hint": "Think about which type of business primarily sells its products or services by phone — where customers call to get a quote, renew a policy, or make a purchase without needing to see anything in person.", "markScheme": "<div class=\"marks-section\"><h5>Answer: D</h5>\n<p><strong>D — An insurance company.</strong></p>\n<p><strong>Why D is correct:</strong> Insurance companies are classic users of telesales — customers call to get quotes, compare options, negotiate premiums, and renew policies over the phone. The product (insurance) is intangible and requires no physical demonstration, making telephone sales ideal.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A</strong> — A burger van sells face-to-face at a physical location to passing customers.</li>\n<li><strong>B</strong> — A petrol station sells face-to-face at a physical location.</li>\n<li><strong>C</strong> — A school provides education services rather than selling products through telesales.</li>\n</ul></div>"}, {"question": "Identify one disadvantage to M&S of selling its food using e-commerce. [1 mark]", "marks": 1, "hint": "The question asks for a disadvantage to M&S (the BUSINESS) — NOT to the customer. Think about what problems M&S as a company would specifically face when selling food online.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 1 mark (AO2)</h5>\n<ul>\n<li><strong>1 mark</strong> for a correct disadvantage linked to M&S the business.</li>\n</ul>\n<p>Acceptable answers (linked to food or M&S): cost of transporting and delivering food; food may become damaged in transit; reputational damage if website crashes; high cost of website security for a large business; cost of a cyberattack (M&S is a high-profile target); customer loss if food arrives damaged.</p>\n<p><strong>Do NOT reward</strong> disadvantages to the CUSTOMER (e.g. \"the food might not be fresh when it arrives\" is a customer issue, not a business issue).</p>\n<p><strong>Examiner''s Comment:</strong> Many students wrote customer disadvantages. The question asks about M&S. A disadvantage to M&S might be delivery costs, reputational risk, or the technical costs of running and securing a website for such a large business.</p></div>"}, {"question": "Which of the following is this an example of?", "marks": 1, "hint": "The customer physically visits a location and is served in person. Which method of selling is defined by direct physical contact between buyer and seller?", "markScheme": "<div class=\"marks-section\"><h5>Answer: A</h5>\n<p><strong>A — Face to face selling.</strong></p>\n<p><strong>Why A is correct:</strong> The customer physically enters the travel agency and is served directly by an assistant — direct contact between buyer and seller in a physical setting is the definition of face-to-face selling.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>B — International branding</strong> refers to developing a brand identity across countries, not a method of selling.</li>\n<li><strong>C — Sales promotion</strong> refers to short-term marketing incentives (discounts, offers), not the method of selling.</li>\n<li><strong>D — Telesales</strong> would require the customer to be on the phone, not physically present.</li>\n</ul></div>"}, {"question": "Which of the following will NOT improve customer engagement?", "marks": 1, "hint": "Customer engagement is about improving the CONTACT between the business and its customers. Which option is a product sourcing or quality decision rather than a communication or interaction improvement?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5>\n<p><strong>B — Only selling products that have been certified as organic.</strong></p>\n<p><strong>Why B is correct:</strong> This is a product sourcing or quality decision — it may influence what is sold, but it does NOT directly improve the CONTACT or interaction between Coconut Life and its customers. Customer engagement requires active communication and connection.</p>\n<p><strong>Why the others are wrong (they DO improve engagement):</strong></p>\n<ul>\n<li><strong>A</strong> — Training staff improves their ability to advise and connect with customers when interacting with them.</li>\n<li><strong>C</strong> — Personalised emails are a direct, thoughtful form of customer contact and engagement.</li>\n<li><strong>D</strong> — Text messages to previous customers are a form of ongoing contact and engagement.</li>\n</ul>\n<p><strong>Examiner''s Comment:</strong> Some students misunderstood ''customer engagement''. Also note this question asks what will NOT improve it — always check whether you are looking for the item that will or will not do something.</p></div>"}, {"question": "Explain why Amazon can be described as an e-commerce business. [2 marks]", "marks": 2, "hint": "This is a Knowledge + Application question. First define what e-commerce means (K), then give a specific example from the Amazon case study to show Amazon fits that definition (APP).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 2 marks (AO1a + AO2)</h5>\n<ul>\n<li><strong>Knowledge (1 mark):</strong> Show knowledge of e-commerce (e.g. an e-commerce business brings buyers and sellers together digitally / electronically).</li>\n<li><strong>Application (1 mark):</strong> Use specific case study evidence showing Amazon fits the definition (e.g. Amazon is an internet-based company; sells books, electronics and video games through its website; customers order online and goods are physically delivered).</li>\n</ul>\n<p>NB: Cannot score the application mark without scoring the knowledge mark first.</p></div>"}, {"question": "Analyse one way in which Amazon tries to stay ahead of its competitors. [3 marks]", "marks": 3, "hint": "Use U → APP → AN. The understanding mark shows you understand HOW Amazon competes. The application mark requires specific evidence from the Amazon text. The analysis mark needs you to explain the IMPACT on Amazon''s business.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5>\n<ul>\n<li><strong>Understanding (1 mark):</strong> Show appreciation of how Amazon stays competitive (e.g. using technology to improve operations; offering wider product choice; improving speed of delivery).</li>\n<li><strong>Application (1 mark):</strong> Use specific case study evidence (e.g. same-day delivery; Prime streaming/music extras; Amazon Marketplace range; exclusive ''Prime Days'').</li>\n<li><strong>Analysis (1 mark):</strong> Explain the impact on Amazon''s business (e.g. Prime customers feel exceptional value → more subscription revenue; higher customer loyalty → lower risk of losing customers to competitors).</li>\n</ul></div>"}, {"question": "Analyse one benefit to a business such as John Lewis of concentrating on customer engagement to promote good customer service. [3 marks]", "marks": 3, "hint": "Use U → APP → AN. Define customer engagement (U), then apply it to John Lewis using specific case study evidence (APP), then explain the business impact (AN).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5>\n<ul>\n<li><strong>Understanding (1 mark):</strong> Show appreciation of customer engagement (e.g. it is the contact between customer and business; it builds trust and helps make a sale).</li>\n<li><strong>Application (1 mark):</strong> Apply to John Lewis using case study evidence (e.g. face-to-face engagement in stores; explaining features of technology products; staff knowledge — especially for electronics).</li>\n<li><strong>Analysis (1 mark):</strong> Explain the impact on John Lewis (e.g. better experience → more likely to be satisfied → more likely to return → increased sales and income for John Lewis).</li>\n</ul></div>"}, {"question": "Face-to-face selling involves:", "marks": 1, "hint": "What is the one defining feature of face-to-face selling that makes it different from all other methods?", "markScheme": "<div class=\"marks-section\"><h5>Answer: B</h5>\n<p><strong>B — A buyer meeting with a seller.</strong></p>\n<p><strong>Why B is correct:</strong> Face-to-face selling requires direct physical contact between buyer and seller — they meet in person. This is what makes it distinctly different from all other selling methods.</p>\n<p><strong>Why the others are wrong:</strong></p>\n<ul>\n<li><strong>A — Advertising on a website</strong> is digital marketing, not a selling method involving personal contact.</li>\n<li><strong>C — Telephoning buyers</strong> describes telesales, not face-to-face selling.</li>\n<li><strong>D — Using a website to take orders</strong> describes e-commerce.</li>\n</ul></div>"}, {"question": "State three methods of selling. [3 marks]", "marks": 3, "hint": "There are exactly three main methods of selling covered in this topic. Name all three — no explanation is needed.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1a × 3)</h5>\n<ul>\n<li>1 mark each for three correct methods.</li>\n<li>E-commerce / online selling / selling via the internet</li>\n<li>Face to face selling / selling in a shop</li>\n<li>Telesales / telephone sales</li>\n</ul></div>"}, {"question": "Explain two possible ways JC Motors Ltd can provide good customer service. [4 marks]", "marks": 4, "hint": "For each way: (1) Name the customer service method (U), then (2) apply it to JC Motors using specific evidence from the case study (APP). There are 2 marks per way. Make sure both ways are different.", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 4 marks (AO1b × 2 + AO2 × 2)</h5>\n<ul>\n<li><strong>1 mark (U)</strong> for identifying each way of providing good customer service, and <strong>1 further mark (APP)</strong> for applying it to JC Motors using case study evidence.</li>\n</ul>\n<p>Acceptable ways include: excellent product knowledge (staff know each car); after-sales service (staff available after purchase); customer engagement (hot drinks, snacks, seating area, children''s entertainment); worldwide e-commerce with shipping. Each must be linked to specific JC Motors evidence from the text.</p></div>"}, {"question": "Analyse one benefit of JC Motors selling their cars online. [3 marks]", "marks": 3, "hint": "Use U → APP → AN. Give a clear benefit of e-commerce (U), apply it using specific JC Motors case study detail (APP), then explain the business impact on JC Motors (AN).", "markScheme": "<div class=\"marks-section\"><h5>Mark Allocation — 3 marks (AO1b + AO2 + AO3a)</h5>\n<ul>\n<li><strong>Understanding (1 mark):</strong> Identify a benefit of selling online (e.g. worldwide market reach; 24/7 availability; lower operating costs; professional image).</li>\n<li><strong>Application (1 mark):</strong> Apply using JC Motors case study detail (e.g. website offers to ship cars worldwide; has already sold to customers worldwide; cars start from £50,000).</li>\n<li><strong>Analysis (1 mark):</strong> Explain the business impact (e.g. more global customers increases sales revenue; JC Motors can expand beyond its local area to a worldwide audience of wealthy buyers).</li>\n</ul></div>"}]}}'::jsonb)
